class Strategy_COLLECTIVE_1(BaseStrategy):
    """
    Implements a Collective Risk Dilemma strategy based on reciprocity and threshold sensitivity.
    - Round 1: Cooperates if m/n < 0.5, else defects.
    - Subsequent Rounds:
        - Reciprocity: If threshold was met and the player defected, switch to C.
        - Threshold Sensitivity: If threshold failed, defect to conserve. If threshold met, maintain previous action.
        - Last Round: If cooperators == m-1, play C, else D.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_idx = history.round_number
        current_round = current_round_idx + 1
        if current_round == 1:
            if self.m / self.n < 0.5:
                return Action.C
            return Action.D
        last_my_action_val = 1 if history.my_actions[-1] else 0
        last_opp_coop_count = history.opponent_cooperators[-1]
        total_cooperators = last_opp_coop_count + last_my_action_val
        if current_round == self.r:
            if total_cooperators == self.m - 1:
                return Action.C
            return Action.D
        threshold_met = total_cooperators >= self.m
        if threshold_met and last_my_action_val == 0:
            return Action.C
        if threshold_met:
            return Action.C if last_my_action_val == 1 else Action.D
        else:
            return Action.D

class Strategy_COLLECTIVE_2(BaseStrategy):
    """
    Threshold-Triggered Tit-for-Tat (TTT):
    - Round 1: Cooperate.
    - Subsequent rounds:
        - If previous round met threshold (N_c >= m), cooperate.
        - If previous round failed (N_c < m), defect, UNLESS:
            - Recovery: If previous round was a success (N_c >= m), switch to C (overrides the defect).
            - Recovery: If defecting for k consecutive rounds where k % 3 == 0, switch to C.
    - Final round edge cases: Protect if previously failed, sustain if previously succeeded.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description
        self.consecutive_defections = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_my_action = 1 if history.my_actions[-1] else 0
        prev_opp_coops = history.opponent_cooperators[-1]
        prev_total_cooperators = prev_opp_coops + prev_my_action
        threshold_met = prev_total_cooperators >= self.game.m
        if not threshold_met:
            self.consecutive_defections += 1
        else:
            self.consecutive_defections = 0
        if history.round_number == self.game.n_rounds - 1:
            if not threshold_met:
                return Action.D
            else:
                return Action.C
        if threshold_met:
            return Action.C
        if self.consecutive_defections > 0 and self.consecutive_defections % 3 == 0:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_3(BaseStrategy):
    """
    Implements a Threshold Trigger strategy:
    - Rounds 1 to r-1:
        - Cooperates if previous round threshold met (C_prev >= m).
        - Attempts recovery if previous round was a near-miss (C_prev == m - 1).
        - Defects if previous round was a total failure (C_prev < m - 1).
    - Round r:
        - Cooperates if successful in the majority of previous rounds.
        - Defects otherwise.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_idx = history.round_number
        if current_round_idx == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        prev_opp_coops = history.opponent_cooperators[-1]
        prev_total_coops = prev_opp_coops + (1 if my_prev_action else 0)
        if current_round_idx == self.total_rounds - 1:
            successful_count = 0
            for i in range(len(history.my_actions)):
                opp_c = history.opponent_cooperators[i]
                my_c = 1 if history.my_actions[i] else 0
                if opp_c + my_c >= self.m:
                    successful_count += 1
            if successful_count > self.total_rounds / 2:
                return Action.C
            else:
                return Action.D
        if prev_total_coops >= self.m:
            return Action.C
        elif prev_total_coops == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_4(BaseStrategy):
    """
    A strategy that implements a trigger-threshold mechanism to foster cooperation.
    It initiates with cooperation, uses a safety buffer to distinguish between
    minor deviations and systemic defection, and adjusts its action based on
    aggregate cooperation levels from the previous round. In the final round,
    it acts based on long-term cooperation history.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.alpha = 0.25
        self.buffer = max(1, math.ceil(self.alpha * (self.game_description.m - 1)))

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        if current_round == 0:
            return Action.C
        if current_round == r - 1:
            total_cooperators_history = []
            for t in range(current_round):
                my_action = 1 if history.my_actions[t] else 0
                total_cooperators = history.opponent_cooperators[t] + my_action
                total_cooperators_history.append(total_cooperators)
            avg_coop_rate = sum(total_cooperators_history) / (len(total_cooperators_history) * n)
            return Action.C if avg_coop_rate >= m / n else Action.D
        last_t = current_round - 1
        my_last_action = 1 if history.my_actions[last_t] else 0
        last_total_coop = history.opponent_cooperators[last_t] + my_last_action
        if last_total_coop >= m - self.buffer:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_1(BaseStrategy):
    """
    Threshold-Dependent Conditional Cooperation (TDCC).
    
    A strategy that balances prosocial cooperation with reactive testing of group
    resilience. It prioritizes the threshold m, signals defection when the group 
    is barely meeting the threshold to test stability, and adjusts dynamically 
    to trends in cooperative behavior. Always cooperates in the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        t_index = history.round_number
        if t_index == 0:
            return Action.C
        if t_index == self.r - 1:
            return Action.C
        prev_my_action = int(history.my_actions[t_index - 1])
        prev_opp_coop = history.opponent_cooperators[t_index - 1]
        prev_total_coop = prev_opp_coop + prev_my_action
        trend_improving = False
        if t_index > 1:
            prev_prev_opp_coop = history.opponent_cooperators[t_index - 2]
            prev_prev_my_action = int(history.my_actions[t_index - 2])
            prev_prev_total_coop = prev_prev_opp_coop + prev_prev_my_action
            if prev_total_coop > prev_prev_total_coop:
                trend_improving = True
        failure_count = 0
        if t_index >= 3:
            for i in range(1, 4):
                opp_c = history.opponent_cooperators[t_index - i]
                my_c = int(history.my_actions[t_index - i])
                if opp_c + my_c < self.m:
                    failure_count += 1
            if failure_count >= 3 and (not trend_improving):
                return Action.D
        if prev_total_coop >= self.m:
            if prev_total_coop == self.m:
                return Action.D
            else:
                return Action.C
        elif trend_improving or prev_total_coop > self.m / 2:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_2(BaseStrategy):
    """
    Implements Conditional Threshold Reciprocity (CTR).
    
    Phase I: Conditional initiation based on n and m.
    Phase II: Iterative threshold tracking; punishing non-cooperation 
              if threshold not met, attempting boost if defecting.
    Phase III: Final round defection if collective threshold not previously met.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = self.game_description.n_players
        self.m = self.game_description.m
        self.r = self.game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            if self.m / self.n <= 0.5:
                return Action.C
            return Action.D
        my_prev_action = history.my_actions[-1]
        my_prev_c = 1 if my_prev_action else 0
        prev_opp_coop = history.opponent_cooperators[-1]
        total_prev_coop = prev_opp_coop + my_prev_c
        if current_round == self.r - 1:
            if total_prev_coop >= self.m:
                return Action.C
            return Action.D
        if total_prev_coop >= self.m:
            return Action.C
        if total_prev_coop > 0:
            if my_prev_action:
                return Action.D
            else:
                return Action.C
        return Action.D

class Strategy_PROSOCIAL_3(BaseStrategy):
    """
    Threshold-Sensitive Tit-for-Tat:
    - Round 1: Always Cooperate.
    - Rounds 1 < t < r:
        - Cooperate if group cooperation >= m (maintenance) OR 
          if group cooperation == m - 1 (critical swing).
        - Otherwise, Defect.
    - Last Round:
        - Cooperate if group cooperation >= m - 1.
        - Otherwise, Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        m = self.game_description.m
        if history.round_number == 0:
            return Action.C
        my_last_action = 1 if history.my_actions[-1] else 0
        prev_cooperators = history.opponent_cooperators[-1] + my_last_action
        if history.round_number == r - 1:
            if prev_cooperators >= m - 1:
                return Action.C
            else:
                return Action.D
        if prev_cooperators >= m:
            return Action.C
        elif prev_cooperators == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_4(BaseStrategy):
    """
    Threshold-Targeted Reciprocal Strategy (TTRS)
    
    This strategy focuses on conditional cooperation, tipping points, 
    and opportunistic defecting based on history.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0
        self.warning_round = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        t = history.round_number
        prev_c = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        c_i = 1 if my_prev_action else 0
        total_cooperators_prev = prev_c + c_i
        if total_cooperators_prev < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if t == r - 1:
            if total_cooperators_prev >= m:
                return Action.D
            elif total_cooperators_prev == m - 1:
                return Action.C
            else:
                return Action.D
        if t > 1:
            prev_prev_c = history.opponent_cooperators[-2] + (1 if history.my_actions[-2] else 0)
            if prev_prev_c >= m and total_cooperators_prev < m:
                self.warning_round = True
                return Action.D
            if self.warning_round:
                self.warning_round = False
                if total_cooperators_prev >= m:
                    return Action.C
                return Action.D
        if total_cooperators_prev == m - 1:
            return Action.C
        if self.consecutive_failures > 2 and t > r / 2:
            return Action.D
        if total_cooperators_prev >= m:
            if my_prev_action:
                return Action.C
            else:
                return Action.D
        if total_cooperators_prev < m:
            if my_prev_action:
                return Action.C
            else:
                remaining_rounds = r - t
                p = min(1.0, remaining_rounds / r * 1.5)
                return Action.C if random.random() < p else Action.D
        return Action.D

class Strategy_ALTRUISTIC_1(BaseStrategy):
    """
    A strategy that employs Conditional Threshold Reciprocity.
    It cooperates initially, then adapts based on historical participation rates and 
    the need to meet the threshold 'm', while incorporating safeguards against 
    exploitation and coordination failure.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.target_ratio = self.m / self.n
        self.last_action_was_c = False

    def __call__(self, history: PlayerHistory) -> Action:
        t_zero_indexed = history.round_number
        t = t_zero_indexed + 1
        if t_zero_indexed == 0:
            self.last_action_was_c = True
            return Action.C
        prev_my_action_int = 1 if self.last_action_was_c else 0
        prev_round_idx = t_zero_indexed - 1
        prev_nc = history.opponent_cooperators[prev_round_idx] + prev_my_action_int
        all_prev_my_actions = history.my_actions.astype(int)
        all_prev_nc = history.opponent_cooperators + all_prev_my_actions
        cumulative_nc = np.sum(all_prev_nc)
        T = t_zero_indexed
        avg_p = cumulative_nc / (T * self.n)
        decision = Action.C
        if t == self.r:
            if self.last_action_was_c:
                decision = Action.C
            elif avg_p > 0.5 * self.target_ratio:
                decision = Action.C
            else:
                decision = Action.D
        else:
            is_declining = prev_nc < self.m
            if prev_nc == self.m:
                decision = Action.C
            elif is_declining:
                prev_observed_others = history.opponent_cooperators[prev_round_idx]
                ntr = self.m - prev_observed_others
                if ntr <= 1:
                    decision = Action.C
                else:
                    decision = Action.D
            elif avg_p >= self.target_ratio:
                decision = Action.C
            else:
                decision = Action.C
        self.last_action_was_c = decision == Action.C
        return decision

class Strategy_ALTRUISTIC_2(BaseStrategy):
    """
    Implements a Conditional Threshold Reciprocity model.
    Phases:
    1. Initialization: C if threshold density <= 0.5, else 50/50 toss.
    2. Reciprocal Monitoring: Maintains C if successful, probabilistic D otherwise.
    3. Terminal Phase: C if average cooperation >= threshold, else D.
    Handles persistent failure, sudden drops, and altruistic buffers as edge cases.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0
        self.persistent_failure_mode = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        t = history.round_number
        if t >= 3 and (not self.persistent_failure_mode):
            recent_opponents = history.opponent_cooperators[-3:]
            recent_my_actions = history.my_actions[-3:]
            fail_count = 0
            for i in range(3):
                my_c = 1 if recent_my_actions[i] else 0
                if recent_opponents[i] + my_c < m:
                    fail_count += 1
            if fail_count == 3:
                self.persistent_failure_mode = True
        if self.persistent_failure_mode:
            return Action.D
        if t == 0:
            if m / n <= 0.5:
                return Action.C
            else:
                return Action.C if random.random() < 0.5 else Action.D
        prev_opps = history.opponent_cooperators[-1]
        prev_my_c = 1 if history.my_actions[-1] else 0
        prev_total_c = prev_opps + prev_my_c
        if prev_total_c == m:
            return Action.C
        if t > 1:
            prev_prev_opps = history.opponent_cooperators[-2]
            prev_prev_my_c = 1 if history.my_actions[-2] else 0
            prev_prev_total_c = prev_prev_opps + prev_prev_my_c
            if prev_prev_total_c > 0:
                drop_pct = (prev_prev_total_c - prev_total_c) / prev_prev_total_c
                if drop_pct > 0.5:
                    return Action.D
        if t == r - 1:
            total_c_history = 0
            for i in range(t):
                c = history.opponent_cooperators[i] + (1 if history.my_actions[i] else 0)
                total_c_history += c
            avg_c = total_c_history / t
            return Action.C if avg_c >= m else Action.D
        if prev_total_c >= m:
            return Action.C
        elif prev_total_c == 0:
            return Action.D
        else:
            pd = 1.0 - prev_total_c / m
            return Action.D if random.random() < pd else Action.C

class Strategy_ALTRUISTIC_3(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that employs a forgiveness-based adaptation.
    It cooperates to maintain stability when targets are met, makes efforts to correct
    shortfalls, and uses a probabilistic approach to bridge cooperation gaps,
    while optimizing for the terminal round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.forgiveness_index = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            total_cooperators_per_round = []
            for r in range(history.round_number):
                my_c = 1 if history.my_actions[r] else 0
                total_cooperators_per_round.append(history.opponent_cooperators[r] + my_c)
            avg_coop = np.mean(total_cooperators_per_round)
            if avg_coop >= self.game_description.m - 1:
                return Action.C
            return Action.D
        n = self.game_description.n_players
        m = self.game_description.m
        my_prev_action = 1 if history.my_actions[-1] else 0
        c_prev = history.opponent_cooperators[-1] + my_prev_action
        if c_prev >= m:
            self.forgiveness_index = min(5, self.forgiveness_index + 1)
        else:
            self.forgiveness_index = max(0, self.forgiveness_index - 2)
        if c_prev >= m:
            return Action.C
        if c_prev < m and self.forgiveness_index < 2:
            return Action.C
        gap = m - c_prev
        remaining = n - c_prev
        prob = max(0.0, gap / remaining) if remaining > 0 else 0.0
        if random.random() < prob:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_4(BaseStrategy):
    """
    Implements 'Conditional Threshold Cooperation'.
    
    1. Always C on round 0.
    2. If the group met the threshold (C_prev >= m), play C.
    3. If the group failed (C_prev < m):
       - If the player defected last round AND the group was close to the threshold (C_prev >= m - 1), play C (Restoration/Forgiveness).
       - Otherwise, play D.
    
    Note on interpretation: 
    The 'opponent_cooperators' array in the history represents the count of *other* players who cooperated.
    To get the total number of cooperators ($C_{t-1}$), we must add my own action from the previous round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_opp_coop = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        total_cooperators_prev = prev_opp_coop + (1 if my_prev_action else 0)
        played_D_last = not my_prev_action
        m = self.game_description.m
        if total_cooperators_prev >= m:
            return Action.C
        if played_D_last and total_cooperators_prev >= m - 1:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_1(BaseStrategy):
    """
    Implements a Conditional Threshold Coordination strategy for the Collective Risk Dilemma.
    Prioritizes threshold maintenance (m) while adapting to group reliability.
    Uses signaling in R1, adaptive threshold seeking in intermediate rounds,
    and a terminal phase logic to minimize losses.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.buffer = max(1, self.desc.n_players // 4)

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        r = self.desc.n_rounds
        m = self.desc.m
        my_prev_action = history.my_actions[-1]
        my_prev_contribution = 1 if my_prev_action else 0
        c_prev = history.opponent_cooperators[-1] + my_prev_contribution
        if history.round_number >= 2:
            c_prev_prev = history.opponent_cooperators[-2] + (1 if history.my_actions[-2] else 0)
            if c_prev < m and c_prev_prev < m:
                return Action.D
        if history.round_number == r - 1:
            if c_prev >= m - 1:
                return Action.C
            else:
                return Action.D
        if c_prev >= m + self.buffer:
            return Action.D
        if c_prev >= m:
            return Action.C
        elif c_prev == m - 1:
            return Action.C
        elif my_prev_action:
            return Action.D
        else:
            return Action.D

class Strategy_BENEVOLENT_2(BaseStrategy):
    """
    Implements a conditional cooperation strategy for the Collective Risk Dilemma.
    Starts with Cooperation, switches to conditional reciprocation based on 
    threshold adherence, and utilizes a memory of cooperative equilibrium.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.consecutive_coop_rounds = 0
        self.consecutive_defect_rounds = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        current_round = history.round_number
        last_round_idx = current_round - 1
        n = self.desc.n_players
        m = self.desc.m
        my_last_action = history.my_actions[last_round_idx]
        c_last = history.opponent_cooperators[last_round_idx] + (1 if my_last_action else 0)
        if c_last >= m:
            self.consecutive_coop_rounds += 1
            self.consecutive_defect_rounds = 0
        else:
            self.consecutive_coop_rounds = 0
            self.consecutive_defect_rounds += 1
        if self.consecutive_coop_rounds >= 2:
            return Action.C
        if self.consecutive_defect_rounds >= 2:
            return Action.D
        if current_round == self.desc.n_rounds - 1:
            if c_last >= m:
                return Action.C
            else:
                return Action.D
        if c_last >= m:
            return Action.C
        total_coop_count = np.sum(history.opponent_cooperators) + np.sum(history.my_actions)
        current_r_val = current_round + 1
        if total_coop_count < m * current_r_val:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_3(BaseStrategy):
    """
    Implements the Conditional Threshold-Trigger (CTT) strategy.
    
    This strategy prioritizes group success (the achievement of m cooperators).
    It starts cooperatively, adapts based on previous round outcomes, 
    tries to rescue the group when near the threshold, withdraws in 
    persistent failure, and re-evaluates cooperative history in the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == r - 1:
            my_prev_action = int(history.my_actions[-1])
            prev_total_cooperators = my_prev_action + history.opponent_cooperators[-1]
            success_count = 0
            for t in range(current_round):
                total_in_round_t = int(history.my_actions[t]) + history.opponent_cooperators[t]
                if total_in_round_t >= m:
                    success_count += 1
            if success_count >= current_round / 2.0:
                return Action.C
            else:
                return Action.D
        prev_my_action = int(history.my_actions[-1])
        prev_opp_coops = history.opponent_cooperators[-1]
        prev_total_cooperators = prev_my_action + prev_opp_coops
        previous_round_success = prev_total_cooperators >= m
        if previous_round_success:
            return Action.C
        elif prev_total_cooperators >= m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_4(BaseStrategy):
    """
    Implements Threshold-Adaptive Reciprocity for the Collective Risk Dilemma.
    
    Strategy Logic:
    - Round 1: Cooperates to signal intent.
    - Final Round: Defects to maximize private payoff.
    - If previous round reached the cooperation threshold (m): Cooperates.
    - If previous round failed (0 cooperators): Defects.
    - If previous round failed but had some cooperation (< m and > 0): 
      Probabilistically cooperates to attempt recovery.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        prev_my_action = 1 if history.my_actions[-1] else 0
        prev_opponent_coop = history.opponent_cooperators[-1]
        c_prev = prev_my_action + prev_opponent_coop
        if c_prev == 0:
            return Action.D
        if c_prev >= self.game_description.m:
            return Action.C
        p = c_prev / (self.game_description.n_players - 1)
        if random.random() < p:
            return Action.C
        return Action.D

class Strategy_SELFISH_1(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that prioritizes threshold exploitation.
    It cooperates in the first round to test the group. In subsequent rounds, it
    defects if the threshold was reached (free-riding) and cooperates if the
    threshold was failed, unless the group shows signs of persistent uncooperativeness
    (failing 3 consecutive times), in which case it switches to permanent defection.
    It always defects in the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        m = self.game_description.m
        my_last_action = history.my_actions[-1]
        prev_opp_c = history.opponent_cooperators[-1]
        total_prev_c = prev_opp_c + (1 if my_last_action else 0)
        if total_prev_c >= m:
            return Action.D
        if total_prev_c < m:
            if my_last_action:
                if history.round_number >= 3:
                    recent_history_failed = True
                    for i in range(1, 4):
                        opp_c = history.opponent_cooperators[-i]
                        my_c = 1 if history.my_actions[-i] else 0
                        if opp_c + my_c >= m:
                            recent_history_failed = False
                            break
                    if recent_history_failed:
                        return Action.D
            return Action.C
        return Action.D

class Strategy_SELFISH_2(BaseStrategy):
    """
    Implements a Threshold-Conditional Reciprocity strategy:
    - Starts with C.
    - If last round threshold (m) met: Defect (D) to maximize gain.
    - If last round threshold not met: 
        - If close (cooperators >= m - 2): Cooperate (C).
        - If far (cooperators < m - 2): Defect (D).
    - Final round: Always Defect (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        last_my_action = history.my_actions[-1]
        last_opponent_coops = history.opponent_cooperators[-1]
        my_contribution = 1 if last_my_action else 0
        total_cooperators = last_opponent_coops + my_contribution
        if total_cooperators >= self.game_description.m:
            return Action.D
        if total_cooperators >= self.game_description.m - 2:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_3(BaseStrategy):
    """
    Threshold-Responsive Tit-for-Tat with Defection-in-the-End.
    Maximizes payoff by free-riding when possible, acting as a pivotal cooperator
    when necessary, and defecting in the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.uncooperative_group = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if self.game_description.k <= 0:
            return Action.D
        if current_round == r - 1:
            return Action.D
        if current_round == 0:
            if m <= n / 2:
                return Action.C
            else:
                return Action.D
        last_round_idx = current_round - 1
        c_prev = history.opponent_cooperators[last_round_idx] + (1 if history.my_actions[last_round_idx] else 0)
        my_prev_action = 1 if history.my_actions[last_round_idx] else 0
        c_others = c_prev - my_prev_action
        if c_others < m - 1:
            if current_round > 1:
                prev_c_prev = history.opponent_cooperators[last_round_idx - 1] + (1 if history.my_actions[last_round_idx - 1] else 0)
                prev_c_others = prev_c_prev - (1 if history.my_actions[last_round_idx - 1] else 0)
                if prev_c_others < m - 1:
                    self.uncooperative_group = True
        if self.uncooperative_group:
            return Action.D
        if c_others >= m:
            return Action.D
        elif c_others == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_4(BaseStrategy):
    """
    Implements a Threshold-Sensitive Tit-for-Tat strategy for the Collective Risk Dilemma.
    
    This strategy aims to maximize cumulative payoff by balancing the cost of cooperation 
    against the necessity of reaching the threshold 'm'. It initiates cooperation to 
    signal intent, free-rides when the threshold is met, and retracts cooperation upon 
    failure to reach the threshold to avoid exploitation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.is_punishing = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        n = self.game_description.n_players
        m = self.game_description.m
        last_my_action = int(history.my_actions[-1])
        last_opponent_coops = history.opponent_cooperators[-1]
        c_prev = last_opponent_coops + last_my_action
        if last_my_action == 1 and c_prev < m:
            self.is_punishing = True
        if self.is_punishing:
            if c_prev > 0:
                self.is_punishing = False
            else:
                return Action.D
        if c_prev >= m:
            return Action.D
        return Action.C

class Strategy_SELFINTERESTED_1(BaseStrategy):
    """
    Conditional Threshold Trigger (CTT):
    - Round 1: Cooperate.
    - If threshold (m) met last round:
        - If I played C and C_total == m: Try defecting (test necessity).
        - If C_total > m: Defect (surplus).
        - If I played D: Continue to defect.
    - If threshold (m) not met last round:
        - If I played D: Switch to Cooperate.
        - If I played C: Continue to Cooperate.
    - Endgame (last round):
        - If prev_threshold_met: Defect.
        - If prev_threshold_failed: Cooperate only if necessary to hit m, else Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.n = game_description.n_players
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        is_last_round = current_round == self.r - 1
        if current_round == 0:
            return Action.C
        prev_my_action = history.my_actions[-1]
        prev_my_c = 1 if prev_my_action else 0
        prev_opp_c = history.opponent_cooperators[-1]
        prev_total_c = prev_opp_c + prev_my_c
        prev_threshold_met = prev_total_c >= self.m
        if is_last_round:
            if prev_threshold_met:
                return Action.D
            else:
                if prev_opp_c == self.m - 1:
                    return Action.C
                return Action.D
        if prev_threshold_met:
            return Action.D
        else:
            return Action.C

class Strategy_SELFINTERESTED_2(BaseStrategy):
    """
    Adaptive Threshold Tit-for-Tat strategy.
    
    1. Initialises by cooperating.
    2. In final round, always defects.
    3. In standard rounds:
       - If previous threshold was met (C_{t-1} >= m), cooperates.
       - If previous threshold failed (C_{t-1} < m), tracks consecutive failures.
       - After 2 consecutive failures, attempts one-time 'reset' (cooperation).
       - If reset fails, persists in defection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures_count = 0
        self.reset_attempted = False

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round_idx == total_rounds - 1:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        prev_my_action = Action.C if history.my_actions[-1] else Action.D
        prev_total_cooperators = history.opponent_cooperators[-1] + (1 if prev_my_action == Action.C else 0)
        if prev_total_cooperators >= m:
            self.consecutive_failures_count = 0
            self.reset_attempted = False
            return Action.C
        else:
            self.consecutive_failures_count += 1
            if self.consecutive_failures_count >= 2 and (not self.reset_attempted):
                self.reset_attempted = True
                self.consecutive_failures_count = 0
                return Action.C
            return Action.D

class Strategy_SELFINTERESTED_3(BaseStrategy):
    """
    Implements a Conditional Threshold Tracker strategy.
    
    Logic:
    1.  Initialization (Round 1): Defect.
    2.  Adaptive Phase (Rounds 2 to r-1):
        - If previous cooperators >= m and I played Defect, continue Defect.
        - If previous cooperators == m - 1, Cooperate to trigger threshold.
        - If previous cooperators < m - 1, Defect (insufficient for threshold).
    3.  Terminal Phase (Round r): Defect.
    
    Reversion Rule: If k <= 1 or my previous contributions failed to trigger the 
    threshold when attempted, revert to permanent Defection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.revert_to_defect = False

    def __call__(self, history: PlayerHistory) -> Action:
        if self.game_description.k <= 1.0:
            return Action.D
        if self.revert_to_defect:
            return Action.D
        round_idx = history.round_number
        if round_idx == 0:
            return Action.D
        if round_idx == self.game_description.n_rounds - 1:
            return Action.D
        my_prev_action = history.my_actions[-1]
        opp_prev_coop = history.opponent_cooperators[-1]
        total_prev_coop = opp_prev_coop + (1 if my_prev_action else 0)
        if my_prev_action and total_prev_coop < self.game_description.m:
            self.revert_to_defect = True
            return Action.D
        if opp_prev_coop >= self.game_description.m:
            return Action.D
        if opp_prev_coop == self.game_description.m - 1:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_4(BaseStrategy):
    """
    A strategy that balances free-riding and contribution to hit the threshold 'm'.
    - Round 1: Always Defect (D).
    - Rounds 2 to r-1: 
        - If threshold met in prev round: Maintain Cooperation only if my contribution was pivotal (C_{t-1} == m). Otherwise, Defect.
        - If threshold not met in prev round: Cooperate only if my contribution makes the difference (others_cooperated == m - 1). Otherwise, Defect.
    - Final Round: Always Defect (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        r_curr = history.round_number + 1
        if r_curr == 1:
            return Action.D
        if r_curr == self.game_description.n_rounds:
            return Action.D
        prev_idx = -1
        last_action_bool = history.my_actions[prev_idx]
        last_action = Action.C if last_action_bool else Action.D
        my_last_contrib = 1 if last_action == Action.C else 0
        total_cooperators_prev = my_last_contrib + history.opponent_cooperators[prev_idx]
        m = self.game_description.m
        if total_cooperators_prev >= m:
            if last_action == Action.C and total_cooperators_prev == m:
                return Action.C
            return Action.D
        else:
            if history.opponent_cooperators[prev_idx] == m - 1:
                return Action.C
            return Action.D

class Strategy_OPPORTUNISTIC_1(BaseStrategy):
    """
    Conditional Tit-for-Tat with a Threshold Constraint.
    
    Strategy:
    1. Always Defect in the first round (round_number == 0).
    2. Always Defect in the final round (round_number == r - 1).
    3. If reward k <= 1, permanently defect as contribution is irrational.
    4. Otherwise:
       - If the group met the threshold m in the previous round, defect to free-ride.
       - If the group failed the threshold, check if cooperation nudge helps (i.e., if cooperators >= m - 1).
         If so, cooperate.
       - Otherwise, defect to minimize loss.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if self.k <= 1.0:
            return Action.D
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round == self.r - 1:
            return Action.D
        last_opponent_cooperators = history.opponent_cooperators[-1]
        last_my_action = history.my_actions[-1]
        my_prev_contribution = 1 if last_my_action else 0
        total_cooperators_last_round = last_opponent_cooperators + my_prev_contribution
        gained_reward_last_round = total_cooperators_last_round >= self.m
        if gained_reward_last_round:
            return Action.D
        elif total_cooperators_last_round >= self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_2(BaseStrategy):
    """
    A threshold-trigger conditional cooperation strategy.
    
    Logic:
    - Round 1: Always Cooperate.
    - Rounds 2 to r-1: 
        - Calculate rolling mean of cooperators (window=3).
        - If avg_cooperators >= m: Defect (exploit).
        - If avg_cooperators < m and >= m-2: Probabilistic 50/50 Cooperate/Defect.
        - If avg_cooperators < m-2: Cooperate (recovery).
        - Edge Case: If group consistently fails to meet threshold (avg < m) for 3 rounds 
          while I cooperated, switch to pure Defection (uncooperative group detection).
    - Round r (Last): Always Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.w = 3
        self.consecutive_failed_threshold_attempts = 0

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_round >= self.w:
            recent_coops = history.opponent_cooperators[-self.w:]
            my_recent_actions = history.my_actions[-self.w:]
            group_failed_streak = True
            for i in range(self.w):
                total_c = recent_coops[-(i + 1)] + (1 if my_recent_actions[-(i + 1)] else 0)
                if total_c >= m:
                    group_failed_streak = False
                    break
            if group_failed_streak and all(my_recent_actions):
                return Action.D
        lookback = min(current_round, self.w)
        recent_opponents = history.opponent_cooperators[-lookback:]
        recent_mine = history.my_actions[-lookback:]
        total_coop_per_round = [recent_opponents[i] + (1 if recent_mine[i] else 0) for i in range(lookback)]
        avg_cooperators = sum(total_coop_per_round) / lookback
        if avg_cooperators >= m:
            return Action.D
        if avg_cooperators >= m - 2:
            return Action.C if random.random() < 0.5 else Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_3(BaseStrategy):
    """
    Implements a Threshold-Sensitive Tit-for-Tat strategy.
    
    Operates on conditional cooperation: cooperates if necessary to meet the 
    threshold m, defects if the threshold is met by others or unreachable, 
    and incorporates history-based trends and termination logic.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k
        self.consecutive_low_cooperation = 0

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        prev_c_total = history.opponent_cooperators[-1]
        prev_my_action = history.my_actions[-1]
        s_i = 1 if prev_my_action else 0
        if s_i == 1:
            E = prev_c_total - 1
        else:
            E = prev_c_total
        if prev_c_total < self.m - 1:
            self.consecutive_low_cooperation += 1
        else:
            self.consecutive_low_cooperation = 0
        if self.consecutive_low_cooperation > 2:
            return Action.D
        if t == self.r - 1:
            if prev_c_total >= self.m:
                return Action.D
            if self.m - E == 1:
                return Action.C
            return Action.D
        if t > 1:
            prev_prev_c_total = history.opponent_cooperators[-2]
            if prev_c_total < self.m and prev_c_total > prev_prev_c_total:
                return Action.C
        if E >= self.m:
            return Action.D
        needed = self.m - E
        if needed == 1:
            return Action.C
        elif needed > 1:
            return Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_4(BaseStrategy):
    """
    Threshold-Monitoring Tit-for-Tat (TMTT):
    A strategy that prioritizes reaching the cooperation threshold 'm' 
    by cooperating, but exploits the group by defecting whenever the 
    threshold is safely exceeded (or met exactly, unless in the final round).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        last_round_idx = current_round - 1
        my_last_action = int(history.my_actions[last_round_idx])
        last_round_opponents = int(history.opponent_cooperators[last_round_idx])
        total_cooperators = last_round_opponents + my_last_action
        threshold_met = total_cooperators >= m
        if threshold_met:
            if current_round == r - 1:
                return Action.C
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_1(BaseStrategy):
    """
    Implements the Conditional Threshold Tit-for-Tat strategy.
    
    This strategy focuses on maintaining the cooperation threshold 'm' 
    by punishing defection when the threshold is not met, rewarding 
    collective stability, and occasionally testing the threshold 
    when it is met exactly.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        m = self.game_description.m
        t = history.round_number + 1
        if t == 1:
            return Action.C if m / n <= 0.5 else Action.D
        if t == r:
            if m < n:
                return Action.D
            last_round_idx = t - 2
            i_cooperated = bool(history.my_actions[last_round_idx])
            others_cooperated = history.opponent_cooperators[last_round_idx]
            total_cooperators = others_cooperated + (1 if i_cooperated else 0)
            return Action.C if total_cooperators == n else Action.D
        last_round_idx = t - 2
        N_c_prev = history.opponent_cooperators[last_round_idx] + (1 if history.my_actions[last_round_idx] else 0)
        c_self_prev = Action.C if history.my_actions[last_round_idx] else Action.D
        if N_c_prev < m:
            return Action.D
        if N_c_prev >= m:
            if c_self_prev == Action.D:
                if N_c_prev > m:
                    return Action.C
                return Action.D
            if c_self_prev == Action.C:
                if N_c_prev > m:
                    return Action.C
                if N_c_prev == m:
                    if random.random() < 1.0 / n:
                        return Action.D
                    return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_2(BaseStrategy):
    """
    Implements a conditional tit-for-tat strategy for the Collective Risk Dilemma.
    1. Probing: Cooperate in round 1.
    2. Adaptive: Cooperate if previous round reached threshold m, defect if not.
    3. Recovery: If defecting due to past failure, occasionally test cooperation (prob 0.5).
    4. Robustness: If failures persist for > 25% of rounds, default to permanent defection.
    5. Final Round: Defect unconditionally.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.max_coop_threshold = game_description.m
        self.total_rounds = game_description.n_rounds
        self.probe_prob = 0.5
        self.robustness_cutoff = self.total_rounds // 4
        self.permanent_defect = False

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == self.total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        recent_failures = 0
        for val in history.opponent_cooperators:
            if val < self.max_coop_threshold:
                recent_failures += 1
            else:
                recent_failures = 0
        if recent_failures >= self.robustness_cutoff:
            self.permanent_defect = True
            return Action.D
        if self.permanent_defect:
            return Action.D
        prev_cooperators = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        if prev_cooperators >= self.max_coop_threshold:
            return Action.C
        if my_prev_action:
            return Action.D
        elif random.random() < self.probe_prob:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_3(BaseStrategy):
    """
    Implements a Conditional Threshold Optimization strategy for the Collective Risk Dilemma.
    
    The strategy aims to maintain a cooperative state where exactly m players cooperate 
    to trigger the reward k. It uses a signal in round 0, monitors cooperation levels, 
    and applies specific adjustments for the final round and long-term population 
    deficiencies (The Defection Trap).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0

    def __call__(self, history: PlayerHistory) -> Action:
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        my_prev_action = 1 if history.my_actions[-1] else 0
        n_prev_cooperators = history.opponent_cooperators[-1] + my_prev_action
        if n_prev_cooperators < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 2:
            return Action.D
        if current_round == r - 1:
            if n_prev_cooperators >= m:
                return Action.D
        if n_prev_cooperators >= m:
            return Action.D
        if n_prev_cooperators == m - 1:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_4(BaseStrategy):
    """
    Implements a Conditional Threshold-Triggered Tit-for-Tat strategy.
    
    Logic:
    1. Round 1: Defect.
    2. Subsequent rounds (not final):
       - If N_c(t-1) >= m: Cooperate (maintain equilibrium).
       - If N_c(t-1) < m and self(t-1) == C: Defect (punish).
       - If N_c(t-1) < m and self(t-1) == D: Test protocol (every 4 rounds, cooperate; else defect).
    3. Final round:
       - If historically (r-1 rounds) N_c >= m consistently: Cooperate.
       - Else: Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.test_interval = 4

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            all_rounds_succeeded = True
            for i in range(history.round_number):
                if history.opponent_cooperators[i] < self.game_description.m:
                    all_rounds_succeeded = False
                    break
            if all_rounds_succeeded:
                return Action.C
            return Action.D
        prev_round_idx = history.round_number - 1
        num_cooperators = history.opponent_cooperators[prev_round_idx]
        my_prev_action_val = 1 if history.my_actions[prev_round_idx] else 0
        total_cooperators = num_cooperators + my_prev_action_val
        if total_cooperators >= self.game_description.m:
            return Action.C
        if my_prev_action_val == 1:
            return Action.D
        if history.round_number % self.test_interval == 0:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_5(BaseStrategy):
    """
    Threshold-Triggered Tit-for-Tat Strategy with a Grace Period and Buffer Logic.

    Implements a cooperative-first approach that:
    1. Always cooperates in round 1.
    2. Maintains cooperation if the threshold m was met in the previous round.
    3. Switches to defection if the threshold was missed, treating it as punishment/avoidance.
    4. Features a 'Threshold Buffer' adaptation: if the group has exceeded m for 3 consecutive rounds,
       the agent tests the threshold by defecting once.
    5. Includes a 'Persistent Defection' clause: if coordination fails (C < m) for 3 consecutive
       rounds, it ceases cooperation entirely for the rest of the game.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_exceeds = 0
        self.consecutive_fails = 0
        self.is_testing = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_prev_action_int = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + my_prev_action_int
        m = self.game_description.m
        if self.consecutive_fails >= 3:
            return Action.D
        if total_cooperators_prev >= m:
            self.consecutive_fails = 0
            if total_cooperators_prev > m:
                self.consecutive_exceeds += 1
            else:
                self.consecutive_exceeds = 0
        else:
            self.consecutive_fails += 1
            self.consecutive_exceeds = 0
            self.is_testing = False
        if self.is_testing:
            self.is_testing = False
            if total_cooperators_prev >= m:
                return Action.D
            else:
                return Action.C
        if self.consecutive_exceeds >= 3:
            self.is_testing = True
            self.consecutive_exceeds = 0
            return Action.D
        if total_cooperators_prev >= m:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_6(BaseStrategy):
    """
    Implements a conditional cooperation strategy for the Collective Risk Dilemma:
    - Starts with C.
    - If C_prev >= T, maintains C.
    - If C_prev < T, switches to D, but checks for recovery triggers (C_prev == T - 1 while self was D).
    - If persistent failure (C < T - 1 for 2 consecutive rounds), switches to D permanently.
    - Final round: Cooperates if threshold met previously, else defects.
    - Threshold dynamics: Tests fragility if C_prev > T by occasionally defecting.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.threshold = game_description.m
        self.persistent_failure_count = 0
        self.is_permanently_defected = False
        self.last_action = None

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            self.last_action = Action.C
            return Action.C
        if self.is_permanently_defected:
            self.last_action = Action.D
            return Action.D
        prev_round = history.round_number - 1
        others_cooperated = history.opponent_cooperators[prev_round]
        my_prev_cooperated = 1 if self.last_action == Action.C else 0
        total_cooperators_prev = others_cooperated + my_prev_cooperated
        if total_cooperators_prev < self.threshold - 1:
            self.persistent_failure_count += 1
        else:
            self.persistent_failure_count = 0
        if self.persistent_failure_count >= 2:
            self.is_permanently_defected = True
            self.last_action = Action.D
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            if total_cooperators_prev >= self.threshold:
                self.last_action = Action.C
                return Action.C
            else:
                self.last_action = Action.D
                return Action.D
        if total_cooperators_prev >= self.threshold:
            if total_cooperators_prev > self.threshold and random.random() < 0.1:
                self.last_action = Action.D
            else:
                self.last_action = Action.C
            return self.last_action
        if total_cooperators_prev == self.threshold - 1 and self.last_action == Action.D:
            self.last_action = Action.C
            return Action.C
        self.last_action = Action.D
        return Action.D

class Strategy_COLLECTIVE_7(BaseStrategy):
    """
    Threshold-Tit-for-Tat (TTFT) strategy.
    
    Prioritizes reaching threshold 'm' in a collective risk dilemma.
    - Round 0: Cooperates.
    - If threshold met in previous round: 
        - Cooperates if exact threshold reached.
        - Defects with 50% probability if excess cooperators present.
    - If threshold not met:
        - If previously defected, switch to Cooperate (repent).
        - If previously cooperated and were close to threshold, stay Cooperate (persistence).
        - Otherwise, Defect (punish/conserve).
    - End-game heuristic applied for final 3 rounds.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = self.game_description.n_players
        self.m = self.game_description.m
        self.r = self.game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number >= self.r - 2:
            lookback = 3
            recent_rounds = history.opponent_cooperators[-min(lookback, history.round_number):]
            met_count = sum((1 for c in recent_rounds if c >= self.m))
            if met_count == len(recent_rounds):
                return Action.D
            if np.mean(recent_rounds) / self.n > 0.5:
                return Action.C
            else:
                return Action.D
        prev_total = int(history.opponent_cooperators[-1])
        prev_my_action = Action.C if history.my_actions[-1] else Action.D
        threshold_met = prev_total >= self.m
        if threshold_met:
            if prev_total > self.m:
                return Action.D if random.random() < 0.5 else Action.C
            else:
                return Action.C
        elif prev_my_action == Action.D:
            return Action.C
        elif prev_total >= self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_8(BaseStrategy):
    """
    Threshold-Responsive Tit-for-Tat (TR-TFT)
    
    This strategy maximizes collective payoff by maintaining the cooperation threshold 'm'.
    - Round 1: Always Cooperate.
    - If C_prev >= m: Defect (free-ride).
    - If C_prev < m:
        - If I was D previously: Cooperate.
        - If I was C previously and C_prev == m-1: Cooperate.
        - If I was C previously and C_prev < m-1: Defect (cut losses).
    - Last Round Exception: If C_prev < m, always Defect (no future incentives).
    - Recovery: If threshold was met two rounds ago but missed last round, treat as a reset (Cooperate).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_round_idx = history.round_number - 1
        my_prev_action = history.my_actions[prev_round_idx]
        c_prev = history.opponent_cooperators[prev_round_idx] + (1 if my_prev_action else 0)
        if history.round_number == self.n_rounds:
            if c_prev < self.m:
                return Action.D
        if history.round_number >= 2:
            prev_prev_round_idx = history.round_number - 2
            my_prev_prev_action = history.my_actions[prev_prev_round_idx]
            c_prev_prev = history.opponent_cooperators[prev_prev_round_idx] + (1 if my_prev_prev_action else 0)
            if c_prev < self.m and c_prev_prev >= self.m:
                return Action.C
        if c_prev >= self.m:
            return Action.D
        elif not my_prev_action:
            return Action.C
        elif c_prev == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_9(BaseStrategy):
    """
    Implements a responsive strategy for the Collective Risk Dilemma:
    - Initial round: Cooperate if reward k > 1.
    - Subsequent rounds: Dynamic thresholds based on previous round cooperators 
      (m, m-1) and own action.
    - Edge cases: Handles last round pivot logic and persistence checks 
      (3-round failure detection).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        k = self.game_description.k
        rounds_total = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C if k > 1 else Action.D
        c_prev = history.opponent_cooperators[-1]
        my_action_prev = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = c_prev + my_action_prev
        if total_cooperators_prev < m - 1:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 3:
            return Action.D
        if current_round == rounds_total - 1:
            if total_cooperators_prev >= m:
                return Action.C if my_action_prev == 1 else Action.D
            elif total_cooperators_prev == m - 1:
                return Action.C
            else:
                return Action.D
        if my_action_prev == 1:
            if total_cooperators_prev >= m:
                return Action.C
            else:
                return Action.D
        elif total_cooperators_prev >= m:
            return Action.D
        elif total_cooperators_prev == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_10(BaseStrategy):
    """
    Threshold-Conditional Reciprocity (TCR) Strategy.
    Implements a conditional cooperation strategy aimed at maintaining a cooperation
    threshold m while punishing defection and employing an exit strategy for
    persistent failure.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.exit_mode_active = False
        self.failed_consecutive_rounds = 0
        self.always_cooperate = self.desc.n_players == self.desc.m

    def __call__(self, history: PlayerHistory) -> Action:
        if self.always_cooperate:
            return Action.C
        if history.round_number == 0:
            return Action.C
        last_self_action = int(history.my_actions[-1])
        last_opp_coop = history.opponent_cooperators[-1]
        last_total_coop = last_opp_coop + last_self_action
        if last_total_coop < self.desc.m:
            self.failed_consecutive_rounds += 1
        else:
            self.failed_consecutive_rounds = 0
        if self.failed_consecutive_rounds >= 3:
            self.exit_mode_active = True
        if self.exit_mode_active:
            return Action.D
        if history.round_number == self.desc.n_rounds - 1:
            if last_total_coop < self.desc.m:
                return Action.D
            else:
                return Action.C
        c_prev = last_total_coop
        c_self_prev = last_self_action
        if c_prev >= self.desc.m:
            return Action.C
        if c_self_prev == 0:
            if c_prev >= self.desc.m - 1:
                return Action.C
            else:
                return Action.D
        elif c_prev < self.desc.m - 1:
            return Action.D
        else:
            return Action.C

class Strategy_COLLECTIVE_11(BaseStrategy):
    """
    Threshold Reciprocity (TR) strategy.
    Implements conditional cooperation to maintain the minimum threshold m,
    punishing defection, and attempting to coordinate group success.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.consecutive_failures = 0
        self.reset_mode_active = False
        self.persistent_failure_reset_triggered = False
        self.permanent_defect_triggered = False

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        n = self.desc.n_players
        m = self.desc.m
        if t >= self.desc.n_rounds - 3:
            if t > 0:
                past_results = history.opponent_cooperators + history.my_actions.astype(int)
                success_count = np.sum(past_results >= m)
                if success_count > t / 2:
                    return Action.C
                else:
                    return Action.D
            return Action.C if m / n >= 0.5 else Action.D
        if t == 0:
            if m / n >= 0.5:
                return Action.C
            return Action.D
        if self.permanent_defect_triggered:
            return Action.D
        prev_cooperators = history.opponent_cooperators[-1] + (1 if history.my_actions[-1] else 0)
        if prev_cooperators < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
            self.reset_mode_active = False
        if self.consecutive_failures >= 3 and (not self.reset_mode_active):
            self.reset_mode_active = True
            if self.persistent_failure_reset_triggered:
                self.permanent_defect_triggered = True
                return Action.D
            self.persistent_failure_reset_triggered = True
            return Action.C
        prev_c_total = prev_cooperators
        last_action = history.my_actions[-1]
        if prev_c_total >= m:
            if last_action:
                if prev_c_total == m and t >= 3:
                    recent_cooperators = [history.opponent_cooperators[i] + (1 if history.my_actions[i] else 0) for i in range(t - 3, t)]
                    if recent_cooperators[0] > recent_cooperators[1] > recent_cooperators[2]:
                        return Action.D
                return Action.C
            else:
                return Action.C
        elif last_action:
            return Action.D
        else:
            if prev_c_total == m - 1:
                return Action.C
            return Action.D
        if t > 5:
            recent_avg = np.mean(history.opponent_cooperators[-5:] + history.my_actions[-5:].astype(int))
            if recent_avg > m + 1:
                return Action.C
        return Action.D

class Strategy_COLLECTIVE_12(BaseStrategy):
    """
    Threshold-Conditional Tit-for-Tat Strategy.
    
    Logic:
    1. First round: Always Cooperate (C).
    2. Last round: If threshold met in previous round, Cooperate (C). Otherwise, Defect (D).
    3. Intermediate rounds:
       - If previous round met the threshold (C_t-1 >= m): Cooperate (C).
       - If previous round failed (C_t-1 < m):
         - Periodic probe: Every 3 rounds, attempt to Cooperate (C).
         - Otherwise: Defect (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.probe_interval = 3

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        m = self.game_description.m
        total_rounds = self.game_description.n_rounds
        last_my_action = 1 if history.my_actions[-1] else 0
        last_total_cooperators = history.opponent_cooperators[-1] + last_my_action
        if current_round == total_rounds - 1:
            if last_total_cooperators >= m:
                return Action.C
            else:
                return Action.D
        if last_total_cooperators >= m:
            return Action.C
        if (current_round + 1) % self.probe_interval == 0:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_13(BaseStrategy):
    """
    Implements a Trigger-Threshold conditional cooperation strategy.
    
    The strategy maintains a cooperative state while the collective meets the 
    threshold `m` or misses it by at most one player (forgiveness buffer).
    If the threshold is missed by more than one player, it permanently switches
    to a defecting state to avoid exploitation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.status = True

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        if not self.status:
            return Action.D
        c_prev_others = history.opponent_cooperators[-1]
        c_prev_total = c_prev_others + 1
        m = self.game_description.m
        d = m - c_prev_total
        if d > 1:
            self.status = False
            return Action.D
        if t == self.game_description.n_rounds - 1:
            if self.status:
                return Action.C
            return Action.D
        return Action.C

class Strategy_COLLECTIVE_14(BaseStrategy):
    """
    Threshold-Dependent Reciprocity (TDR):
    A strategy that maintains cooperation while the group meets the threshold,
    defects when exploitation is detected (majority defecting),
    and attempts recovery based on group trends or specific boundary conditions.
    Includes persistent defection if the environment proves hostile.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description
        self.stagnant_defection_count = 0
        self.is_permanently_defecting = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if not self.is_permanently_defecting:
            if len(history.opponent_cooperators) >= 3:
                recent_failures = [c < self.game.m for c in history.opponent_cooperators[-3:]]
                if all(recent_failures):
                    self.is_permanently_defecting = True
        if self.is_permanently_defecting:
            return Action.D
        c_prev = history.opponent_cooperators[-1]
        if history.round_number == self.game.n_rounds - 1:
            avg_success = np.mean(history.opponent_cooperators >= self.game.m)
            if avg_success >= 0.5:
                return Action.C
            else:
                return Action.D
        if c_prev >= self.game.m:
            return Action.C
        if c_prev == self.game.m - 1:
            return Action.C
        d_r = (self.game.n_players - c_prev) / self.game.n_players
        if d_r > 0.5:
            if history.round_number > 1:
                c_prev_prev = history.opponent_cooperators[-2]
                if c_prev > c_prev_prev:
                    return Action.C
            return Action.D
        return Action.D

class Strategy_COLLECTIVE_15(BaseStrategy):
    """
    An adaptive threshold-trigger strategy for the Collective Risk Dilemma.
    Maintains a minimum viable contribution to secure k, employs rotating 
    cooperation, and tracks failure sequences to switch to permanent defection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0
        self.perm_defect = False
        self.was_cooperator = False

    def __call__(self, history: PlayerHistory) -> Action:
        if self.perm_defect:
            return Action.D
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            should_cooperate = random.random() < m / n
            self.was_cooperator = should_cooperate
            return Action.C if should_cooperate else Action.D
        if current_round == r - 1:
            c_prev = history.opponent_cooperators[-1]
            total_c = c_prev + (1 if self.was_cooperator else 0)
            if total_c >= m + 1:
                return Action.D
            start_idx = max(0, current_round - 3)
            recent_coops = history.opponent_cooperators[start_idx:current_round]
            my_actions = history.my_actions[start_idx:current_round].astype(int)
            total_history_c = np.sum(recent_coops) + np.sum(my_actions)
            avg_c = total_history_c / len(recent_coops) if len(recent_coops) > 0 else 0
            if total_c <= m and avg_c > m:
                self.was_cooperator = True
                return Action.C
            return Action.D
        c_prev_others = history.opponent_cooperators[-1]
        total_c_prev = c_prev_others + (1 if self.was_cooperator else 0)
        if total_c_prev < m:
            self.consecutive_failures += 1
            if self.consecutive_failures >= 2:
                self.perm_defect = True
                return Action.D
            self.was_cooperator = True
            return Action.C
        else:
            self.consecutive_failures = 0
            if total_c_prev == m:
                if self.was_cooperator:
                    self.was_cooperator = True
                    return Action.C
                else:
                    self.was_cooperator = False
                    return Action.D
            elif total_c_prev > m:
                prob_c = m / total_c_prev
                should_cooperate = random.random() < prob_c
                self.was_cooperator = should_cooperate
                return Action.C if should_cooperate else Action.D
        self.was_cooperator = False
        return Action.D

class Strategy_COLLECTIVE_16(BaseStrategy):
    """
    Implements a threshold-triggered, conditional cooperation strategy for the Collective Risk Dilemma.
    Uses history-based heuristics to balance cooperation against exploitation, including 
    pivotal moves and failure-trigger termination.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.k = game_description.k
        self.r = game_description.n_rounds
        self.consecutive_failures = 0
        self.permanently_defected = False

    def __call__(self, history: PlayerHistory) -> Action:
        if self.k < 1:
            return Action.D
        if self.permanently_defected:
            return Action.D
        if history.round_number == 0:
            if self.k * self.n > self.m:
                return Action.C
            return Action.D
        my_last_action = int(history.my_actions[-1])
        total_cooperators_prev = history.opponent_cooperators[-1] + my_last_action
        if total_cooperators_prev < self.m:
            self.consecutive_failures += 1
            if self.consecutive_failures >= 3:
                self.permanently_defected = True
                return Action.D
        else:
            self.consecutive_failures = 0
        if total_cooperators_prev == self.m - 1:
            return Action.C
        if history.round_number == self.r - 1:
            if total_cooperators_prev >= self.m:
                return Action.C
            return Action.D
        if total_cooperators_prev >= self.m:
            return Action.C
        if my_last_action == 1:
            return Action.D
        else:
            if random.random() < 1.0 / self.n:
                return Action.C
            return Action.D

class Strategy_COLLECTIVE_17(BaseStrategy):
    """
    Threshold-Tit-for-Tat with Conditional Escalation.
    Implements a sophisticated logic handling initialization, steady-state, end-game,
    initial failure detection, and exploitation testing.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.n = self.desc.n_players
        self.m = self.desc.m
        self.k = self.desc.k
        self.r = self.desc.n_rounds
        self.is_hostile = False
        self.in_reciprocity_check = False
        self.reciprocity_check_round = -1

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == 1 and history.opponent_cooperators[0] < self.m:
            self.is_hostile = True
        if self.is_hostile:
            if random.random() < 0.2:
                return Action.C
            return Action.D
        if history.round_number == self.r - 1:
            prev_threshold_met = history.opponent_cooperators[-1] >= self.m
            my_coops = history.my_actions.sum()
            my_defects = len(history.my_actions) - my_coops
            avg_c = history.my_payoffs[history.my_actions].mean() if my_coops > 0 else -1.0
            avg_d = history.my_payoffs[~history.my_actions].mean() if my_defects > 0 else -1.0
            if avg_c > avg_d:
                return Action.C
            if avg_d > avg_c:
                return Action.D
            return Action.C if prev_threshold_met else Action.D
        threshold_buffer = (self.n - self.m) / 2
        recent_coop_count = history.opponent_cooperators[-1]
        if not self.in_reciprocity_check and recent_coop_count > self.m + threshold_buffer:
            self.in_reciprocity_check = True
            self.reciprocity_check_round = history.round_number
            return Action.D
        if self.in_reciprocity_check:
            self.in_reciprocity_check = False
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        i_cooperated = history.my_actions[-1]
        if prev_cooperators >= self.m:
            if i_cooperated:
                return Action.C
            else:
                return Action.C if random.random() < self.m / self.n else Action.D
        else:
            deficit = self.m - prev_cooperators
            if deficit <= 0.2 * self.n:
                return Action.C
            else:
                return Action.D

class Strategy_COLLECTIVE_18(BaseStrategy):
    """
    Implements a reputation-based adaptation strategy for the Collective Risk Dilemma.
    It utilizes a reputation index R updated via optimistic or skeptical learning rates,
    reverting to a threshold-based Tit-for-Tat mechanism if cooperation levels remain
    consistently below the required threshold m.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.theta = self.m / self.n
        self.reputation = 0.5
        self.lambda_rate = 0.1
        self.mu_rate = 0.3
        self.consecutive_low_coop = 0
        self.tft_mode = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        c_i = 1 if my_prev_action else 0
        c_t = history.opponent_cooperators[-1] + c_i
        if history.round_number == self.r - 1:
            if c_t == self.n:
                return Action.C
            else:
                return Action.D
        if c_t < self.m:
            self.consecutive_low_coop += 1
        else:
            self.consecutive_low_coop = 0
            self.tft_mode = False
        if self.consecutive_low_coop >= 3:
            self.tft_mode = True
            self.reputation = 0.0
        if self.tft_mode:
            if c_t / self.n >= self.theta:
                return Action.C
            else:
                return Action.D
        alpha_t = c_t / self.n
        if my_prev_action:
            self.reputation = self.reputation + self.lambda_rate * (alpha_t - self.reputation)
        else:
            self.reputation = self.reputation + self.mu_rate * (alpha_t - self.reputation)
        if self.reputation >= self.theta:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_19(BaseStrategy):
    """
    Implements a Trigger-Threshold-Tit-for-Tat strategy for the Collective Risk Dilemma.
    
    Logic:
    1. Start with Cooperate.
    2. Maintain cooperation if threshold 'm' was met in the previous round.
    3. If threshold was missed but some cooperation existed, defect to protect, unless
       a 'Recovery Rule' triggers (forgiveness if near target, or permanent defection if collapsed).
    4. Explicit handling for final round and persistent failure.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0
        self.collapsed = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        my_prev_action = 1 if history.my_actions[-1] else 0
        c_prev = history.opponent_cooperators[-1] + my_prev_action
        if c_prev >= m and (not my_prev_action):
            self.consecutive_failures = 0
            return Action.C
        if self.collapsed:
            return Action.D
        if c_prev < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 3 and c_prev < m:
            self.collapsed = True
            return Action.D
        if history.round_number == r - 1:
            return Action.C if c_prev >= m else Action.D
        if c_prev >= m:
            return Action.C
        if c_prev == 0:
            self.collapsed = True
            return Action.D
        if 0 < c_prev < m:
            if c_prev == m - 1 and history.round_number < r - 2:
                if random.random() < 0.5:
                    return Action.C
            if my_prev_action == 1:
                return Action.D
            return Action.D
        return Action.D

class Strategy_COLLECTIVE_20(BaseStrategy):
    """
    Threshold-Adaptive Reciprocity (TAR):
    A conditional cooperation strategy balancing free-riding and threshold maintenance.
    - Signals cooperation in Round 1.
    - If threshold was met: switches to or stays at Defect to test free-riding limits.
    - If threshold failed: signals Cooperation (always if failure is large, probabilistically if close).
    - Includes safeguards: Persistent failure triggers forced cooperation; High-reward stability check
      detects over-defection cycles.
    - Always Defects in the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0
        self.consecutive_coops_while_d = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        m = self.game_description.m
        my_prev_action_bool = history.my_actions[-1]
        my_prev_contribution = 1 if my_prev_action_bool else 0
        c_prev = history.opponent_cooperators[-1] + my_prev_contribution
        if c_prev < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if c_prev >= m and (not my_prev_action_bool):
            self.consecutive_coops_while_d += 1
        else:
            self.consecutive_coops_while_d = 0
        if self.consecutive_failures >= 3:
            return Action.C
        if self.consecutive_coops_while_d >= 2:
            self.consecutive_coops_while_d = 0
            return Action.C
        if c_prev >= m:
            return Action.D
        elif c_prev < m - 1:
            return Action.C
        else:
            p = m / (m + 1)
            if random.random() < p:
                return Action.C
            else:
                return Action.D

class Strategy_COLLECTIVE_21(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that employs a recursive decision rule based on
    previous round outcomes (tit-for-tat style with threshold sensitivity) and incorporates
    an endgame heuristic to prioritize payoffs when the game concludes.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        r_total = self.game_description.n_rounds
        m = self.game_description.m
        t = history.round_number
        my_last_action = history.my_actions[-1]
        prev_opp_coop = history.opponent_cooperators[-1]
        prev_S = prev_opp_coop + (1 if my_last_action else 0)
        if t >= r_total - 1:
            all_S = history.opponent_cooperators + history.my_actions.astype(int)
            avg_S = np.mean(all_S)
            if avg_S < m:
                return Action.D
            else:
                return Action.C
        if prev_S >= m:
            if prev_S == m:
                return Action.C
            else:
                return Action.D
        elif m - prev_S == 1 and (not my_last_action):
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_22(BaseStrategy):
    """
    A threshold-adaptive strategy for the Collective Risk Dilemma.
    Implements a recursive decision rule based on threshold performance,
    punishment/recovery mechanisms, and last-round optimization.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.k = game_description.k
        self.r = game_description.n_rounds
        self.threshold_met = True
        self.consecutive_stable_rounds = 0
        self.contribution_reduction_factor = 0.0

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            prob_cooperate = self.m / self.n
            if random.random() < prob_cooperate:
                return Action.C
            return Action.D
        my_prev_action = int(history.my_actions[-1])
        c_prev = history.opponent_cooperators[-1] + my_prev_action
        if c_prev == 0:
            self.threshold_met = True
            self.consecutive_stable_rounds = 0
            self.contribution_reduction_factor = 0.0
        else:
            self.threshold_met = c_prev >= self.m
            if c_prev == self.m:
                self.consecutive_stable_rounds += 1
            else:
                self.consecutive_stable_rounds = 0
            if c_prev > self.m:
                self.contribution_reduction_factor = min(1.0, self.contribution_reduction_factor + 0.1)
            else:
                self.contribution_reduction_factor = max(0.0, self.contribution_reduction_factor - 0.1)
        if t == self.r - 1:
            return Action.C if self.k > 1 else Action.D
        if self.consecutive_stable_rounds >= 3:
            return Action.C
        if self.threshold_met:
            if c_prev <= self.m:
                action = Action.C
            else:
                action = Action.D
        elif c_prev >= self.m - 1:
            action = Action.C
        else:
            action = Action.D
        if action == Action.C and self.contribution_reduction_factor > 0:
            if random.random() < self.contribution_reduction_factor:
                return Action.D
        return action

class Strategy_COLLECTIVE_23(BaseStrategy):
    """
    A conditional 'Trigger-Based Tit-for-Tat' strategy for the Collective Risk Dilemma.
    It prioritizes maintaining the threshold 'm' through cooperative signaling and
    punishment/testing phases when the threshold is not met.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.testing_mode = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        c_prev_opponents = history.opponent_cooperators[-1]
        c_prev_total = c_prev_opponents + (1 if my_prev_action else 0)
        if current_round == r - 1:
            return Action.C if c_prev_total >= m else Action.D
        if self.testing_mode:
            if c_prev_total >= m:
                return Action.D
            else:
                self.testing_mode = False
                return Action.C
        if c_prev_total > m + 1:
            self.testing_mode = True
            return Action.D
        if c_prev_total >= m:
            return Action.C
        elif c_prev_total == m - 1:
            return Action.C if random.random() < 0.5 else Action.D
        else:
            return Action.D

class Strategy_COLLECTIVE_24(BaseStrategy):
    """
    Implements a Conditional Trigger-Threshold strategy for the Collective Risk Dilemma.
    
    Logic Summary:
    - Round 1: Cooperate (C).
    - Terminal Phase (Last 2 rounds): Defect (D).
    - Persistent Failure Detection: If the group fails to reach threshold 'm' for > 3 
      consecutive rounds, permanently Defect (D).
    - Cooperation Logic:
        - If previous round failed (< m), continue to Cooperate (C) to keep coordination open.
        - If previous round succeeded (>= m), use Rotational Cooperation:
          Cooperate if (round + personal_id) % n < m, else Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.personal_id = random.randint(0, self.game_description.n_players - 1)
        self.consecutive_failures = 0

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        n = self.game_description.n_players
        if current_round >= total_rounds - 2:
            return Action.D
        if current_round == 0:
            return Action.C
        prev_c_count = history.opponent_cooperators[-1]
        my_prev_c = 1 if history.my_actions[-1] else 0
        total_prev_cooperators = prev_c_count + my_prev_c
        if total_prev_cooperators < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures > 3:
            return Action.D
        if total_prev_cooperators >= m:
            if (current_round + self.personal_id) % n < m:
                return Action.C
            else:
                return Action.D
        return Action.C

class Strategy_COLLECTIVE_25(BaseStrategy):
    """
    Conditional Threshold Tit-for-Tat (CT-TFT).
    
    Strategy:
    - First round: Cooperate if k > 1.
    - Subsequent rounds (not last): Cooperate if prev_cooperators >= m-1. 
      Else, penalty phase (Defect).
    - Adaptive mechanism: If m > n/2, adjust threshold logic and include 
      a 'Defect-until-Threshold' signal if the collective fails to meet m for two consecutive rounds.
    - Last round: Cooperate if avg_previous_cooperators >= m-1, else Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.consecutive_fails = 0
        self.in_signaling_phase = False
        self.signaling_rounds_remaining = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.desc.n_players
        m = self.desc.m
        k = self.desc.k
        r = self.desc.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C if k > 1 else Action.D
        prev_my_act = int(history.my_actions[-1])
        prev_opp_coop = history.opponent_cooperators[-1]
        total_coop_prev = prev_opp_coop + prev_my_act
        if current_round == r - 1:
            total_coop_history = [int(history.my_actions[i]) + history.opponent_cooperators[i] for i in range(current_round)]
            avg_coop = np.mean(total_coop_history) if total_coop_history else 0
            return Action.C if avg_coop >= m - 1 else Action.D
        if m > n / 2:
            if total_coop_prev < m:
                self.consecutive_fails += 1
            else:
                self.consecutive_fails = 0
                self.in_signaling_phase = False
                self.signaling_rounds_remaining = 0
            if self.consecutive_fails >= 2:
                self.in_signaling_phase = True
                self.signaling_rounds_remaining = current_round % 3 + 1
                self.consecutive_fails = 0
            if self.in_signaling_phase:
                if self.signaling_rounds_remaining > 0:
                    self.signaling_rounds_remaining -= 1
                    return Action.D
                else:
                    self.in_signaling_phase = False
                    return Action.C
            threshold = m
        else:
            threshold = m - 1
        if total_coop_prev >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_26(BaseStrategy):
    """
    A Trigger-Tit-for-Tat strategy for the Collective Risk Dilemma.
    1. Rounds 1: Always Cooperate.
    2. Rounds 2 to r-1: Conditional cooperation based on previous round's success (T_t-1 >= m).
       - If group succeeded: Cooperate.
       - If group failed:
         - If I cooperated: Switch to Defect for one round.
         - If I defected: Continue to Defect.
         - If I was defecting but group succeeds: Switch back to Cooperate immediately.
    3. Final Round: Cooperate if success occurred > 50% of the time, else Defect.
    4. Robustness: If observed cooperators (excluding self) == 0 for two consecutive rounds, Defect forever.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.permanently_defected = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round >= 2:
            if history.opponent_cooperators[-1] == 0 and history.opponent_cooperators[-2] == 0:
                self.permanently_defected = True
        if self.permanently_defected:
            return Action.D
        if current_round == 0:
            return Action.C
        prev_my_action = int(history.my_actions[-1])
        prev_opp_coop = history.opponent_cooperators[-1]
        prev_total_coop = prev_opp_coop + prev_my_action
        prev_success = prev_total_coop >= m
        if current_round == r - 1:
            success_count = 0
            for i in range(current_round):
                total_c = int(history.my_actions[i]) + history.opponent_cooperators[i]
                if total_c >= m:
                    success_count += 1
            if success_count / current_round > 0.5:
                return Action.C
            else:
                return Action.D
        if prev_success:
            return Action.C
        elif prev_my_action == 1:
            return Action.D
        else:
            return Action.D

class Strategy_COLLECTIVE_27(BaseStrategy):
    """
    Tit-for-Tat with Threshold Sensitivity:
    - Round 1: Always Cooperate.
    - If m or more cooperators: 
        - Defect if cooperators > m+1 (Free-ride).
        - Cooperate if cooperators <= m+1 (Maintain threshold).
    - If fewer than m cooperators:
        - Cooperate if recovery is possible (failed less than 3 consecutive times).
        - Defect if group is deemed dysfunctional (3+ failures).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.failure_streak = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        m = self.game_description.m
        prev_my_action = int(history.my_actions[-1])
        prev_total_coop = history.opponent_cooperators[-1] + prev_my_action
        if prev_total_coop < m:
            self.failure_streak += 1
        else:
            self.failure_streak = 0
        if prev_total_coop >= m:
            if prev_total_coop > m + 1:
                return Action.D
            else:
                return Action.C
        elif self.failure_streak < 3:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_28(BaseStrategy):
    """
    A conditional strategy that cooperates if the previous round met the threshold 'm',
    defects otherwise, with a periodic recovery mechanism to restart cooperation.
    Specifically handles near-misses (m-1) by accelerating recovery.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.m = game_description.m
        self.k_interval = 3

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        my_prev_action = int(history.my_actions[-1])
        total_cooperators = prev_cooperators + my_prev_action
        current_round_1_based = history.round_number + 1
        if total_cooperators == self.m - 1:
            return Action.C
        if current_round_1_based % self.k_interval == 0:
            return Action.C
        if total_cooperators >= self.m:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_29(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that prioritizes threshold maintenance
    while using a threshold-based heuristic for adaptation and defecting in the 
    final round if historical cooperation has been erratic.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.n = game_description.n_players
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.m
        r = self.r
        current_round = history.round_number
        my_last_action_int = 1 if history.my_actions[-1] else 0
        c_obs = history.opponent_cooperators[-1] + my_last_action_int
        if c_obs >= m:
            return Action.C
        elif c_obs == m - 1:
            return Action.C
        elif current_round == r - 1:
            return Action.D
        else:
            return Action.D

class Strategy_COLLECTIVE_30(BaseStrategy):
    """
    Threshold-Responsive Tit-for-Tat (TR-TFT)
    
    This strategy enforces a cooperative equilibrium by conditioning contributions on 
    the collective success of previous rounds. It employs:
    1. Forgiving restart: Returns to cooperation after threshold success.
    2. Threshold-based response: Probabilistic rebound when partial cooperation occurs.
    3. Last-round defection: Exploits the finality of the game.
    4. Permanent defection: Abandons cooperation if the group repeatedly fails.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_total_defections = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        prev_my_action_val = history.my_actions[-1]
        c_i_prev = 1 if prev_my_action_val else 0
        C_prev = history.opponent_cooperators[-1] + c_i_prev
        if C_prev == 0:
            self.consecutive_total_defections += 1
        else:
            self.consecutive_total_defections = 0
        if self.consecutive_total_defections >= 2:
            return Action.D
        if current_round == r - 1:
            if C_prev < m:
                return Action.D
            return Action.D
        if C_prev >= m:
            if C_prev > m and c_i_prev == 1:
                return Action.D
            return Action.C
        else:
            if C_prev == 0:
                return Action.D
            denominator = n - C_prev
            if denominator <= 0:
                return Action.D
            p_rebound = (m - C_prev) / denominator
            if random.random() < p_rebound:
                return Action.C
            else:
                return Action.D

class Strategy_COLLECTIVE_31(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that balances conditional cooperation,
    punishment, and risk-aversion, with specific logic for threshold management and
    aggressive cooperation when the group size is large relative to the threshold.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.is_permanently_defecting = False
        self.is_currently_defecting = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        last_total_cooperators = history.opponent_cooperators[-1] + int(history.my_actions[-1])
        if self.is_permanently_defecting:
            return Action.D
        if last_total_cooperators == 0:
            self.is_permanently_defecting = True
            return Action.D
        if current_round == r - 1:
            if last_total_cooperators >= m:
                return Action.C
            else:
                return Action.D
        if last_total_cooperators >= m:
            self.is_currently_defecting = False
            return Action.C
        if m / n <= 0.25:
            return Action.C
        if last_total_cooperators < m:
            if self.is_currently_defecting:
                if last_total_cooperators >= m:
                    self.is_currently_defecting = False
                    return Action.C
                else:
                    if last_total_cooperators + 1 >= m:
                        self.is_currently_defecting = False
                        return Action.C
                    return Action.D
            if history.my_actions[-1] == True and last_total_cooperators == m - 1:
                self.is_currently_defecting = True
                return Action.D
            if history.my_actions[-1] == True and last_total_cooperators < m - 1:
                self.is_currently_defecting = True
                return Action.D
            if history.my_actions[-1] == False:
                self.is_currently_defecting = True
                return Action.D
        return Action.C

class Strategy_COLLECTIVE_32(BaseStrategy):
    """
    Implements a conditional trigger-cooperation strategy for Collective Risk Dilemmas.
    
    Logic:
    1. Round 1: Always cooperate (C).
    2. Intermediate rounds: 
       - If the threshold was met in the previous round, continue to cooperate.
       - If the threshold was not met, defect (D), with one exception: 
         if we defected previously and the group was exactly 1 short of the threshold (m-1),
         attempt a 'nudge' by cooperating (C).
    3. Final round: Defect (D) unless the threshold was met in the previous round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_idx = history.round_number
        current_round_num = current_round_idx + 1
        if current_round_idx == 0:
            return Action.C
        m = self.game_description.m
        r = self.game_description.n_rounds
        my_last_action = history.my_actions[-1]
        my_last_action_val = 1 if my_last_action == Action.C else 0
        total_prev_cooperators = history.opponent_cooperators[-1] + my_last_action_val
        if current_round_num == r:
            if total_prev_cooperators >= m:
                return Action.C
            return Action.D
        if total_prev_cooperators >= m:
            return Action.C
        if total_prev_cooperators == m - 1 and my_last_action == Action.D:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_5(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that employs a conditional
    probabilistic approach to cooperation. It starts by cooperating, then
    adjusts cooperation based on the previous round's outcome relative to
    the threshold m. It features a termination-sensitive adjustment in the
    final round based on historical cooperative success.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        current_round_idx = history.round_number
        last_round_idx = current_round_idx - 1
        my_last_action_val = 1 if history.my_actions[-1] else 0
        c_obs_total = my_last_action_val + history.opponent_cooperators[-1]
        if current_round_idx == self.r - 1:
            total_history = []
            for t in range(current_round_idx):
                my_act = 1 if history.my_actions[t] else 0
                opp_acts = history.opponent_cooperators[t]
                total_history.append(my_act + opp_acts)
            avg_cooperators = sum(total_history) / len(total_history)
            threshold_met_count = sum((1 for c in total_history if c >= self.m))
            if threshold_met_count / len(total_history) >= 0.5:
                return Action.C
            else:
                return Action.D
        if c_obs_total >= self.m:
            return Action.C
        if c_obs_total > 0:
            p = c_obs_total / self.m
            return Action.C if random.random() < p else Action.D
        else:
            return Action.D

class Strategy_PROSOCIAL_6(BaseStrategy):
    """
    Implements a Conditional Threshold Reciprocator policy for the Collective Risk Dilemma.
    
    Strategies:
    - Round 1: Always Cooperate.
    - Last Round: Cooperate only if 75%+ success rate in previous rounds.
    - Standard Rounds:
      - If threshold m == n: Uses "Tit-for-Tat-with-Forgiveness" (C if full cooperation, else D then C).
      - If threshold m < n:
        - If previously cooperated: Continue if threshold met; else probabilistic re-entry.
        - If previously defected: Return to C if threshold met; else remain D.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.must_forgive_next = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        r_total = self.game_description.n_rounds
        t = history.round_number + 1
        m = self.game_description.m
        if t == r_total:
            success_count = 0
            for i in range(history.round_number):
                opp_c = history.opponent_cooperators[i]
                my_c = 1 if history.my_actions[i] else 0
                if opp_c + my_c >= m:
                    success_count += 1
            success_rate = success_count / history.round_number
            return Action.C if success_rate >= 0.75 else Action.D
        prev_opp_c = history.opponent_cooperators[-1]
        prev_my_c = 1 if history.my_actions[-1] else 0
        total_prev_c = prev_opp_c + prev_my_c
        if m == self.game_description.n_players:
            if self.must_forgive_next:
                self.must_forgive_next = False
                return Action.C
            if total_prev_c == self.game_description.n_players:
                return Action.C
            else:
                self.must_forgive_next = True
                return Action.D
        if history.my_actions[-1]:
            if total_prev_c >= m:
                return Action.C
            else:
                if random.random() < total_prev_c / m:
                    return Action.C
                return Action.D
        elif total_prev_c >= m:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_7(BaseStrategy):
    """
    Implements a Collective Risk Dilemma strategy with three phases:
    1. Initial Phase (Rounds 0-1): Always cooperate to establish baseline.
    2. Main Phase (Rounds 2 to r-2): Conditional cooperation logic based on
       previous round performance relative to threshold m.
    3. Terminal Phase (Last Round): Cooperation based on historical average 
       performance compared to the m/n ratio.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        curr_round = history.round_number
        total_rounds = self.desc.n_rounds
        m = self.desc.m
        n = self.desc.n_players
        if curr_round < 2:
            return Action.C
        if curr_round == total_rounds - 1:
            total_coops = np.sum(history.opponent_cooperators + history.my_actions.astype(int))
            avg_cooperation_rate = total_coops / (curr_round * n)
            if avg_cooperation_rate >= m / n:
                return Action.C
            return Action.D
        prev_my_action = history.my_actions[-1]
        prev_opp_coops = history.opponent_cooperators[-1]
        N_prev = prev_opp_coops + (1 if prev_my_action else 0)
        if N_prev >= m:
            return Action.C
        elif N_prev == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_8(BaseStrategy):
    """
    Strategy: "Conditional Reciprocator with Debt Management"
    
    1. First round: Cooperate (C).
    2. Subsequent rounds (non-final):
       - If any opponent defected in a round where total cooperation equaled the threshold (m),
         switch to permanent Defection (D) due to exploitation.
       - Calculate total cooperators from previous round (C_prev).
       - If C_prev >= m: Cooperate (C).
       - If C_prev < m: Calculate cumulative deficit S. If S < n_players: Cooperate (C), else Defect (D).
    3. Final round (r):
       - If exploitation occurred or goal is unreachable/already met: Defect (D).
       - If goal potentially reachable and high consistency (>= 75% rounds with C >= m): Cooperate (C).
       - Otherwise: Defect (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.exploited = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        for t in range(current_round):
            my_prev_action = 1 if history.my_actions[t] else 0
            total_cooperators = history.opponent_cooperators[t] + my_prev_action
            if total_cooperators == m and total_cooperators < n:
                self.exploited = True
                break
        if self.exploited:
            return Action.D
        cooperator_counts = []
        for t in range(current_round):
            my_act = 1 if history.my_actions[t] else 0
            cooperator_counts.append(history.opponent_cooperators[t] + my_act)
        last_c = cooperator_counts[-1]
        if current_round == r - 1:
            past_successes = sum((1 for c in cooperator_counts if c >= m))
            consistency_ratio = past_successes / current_round
            if last_c >= m or consistency_ratio < 0.75:
                return Action.D
            return Action.C
        if last_c >= m:
            return Action.C
        s_val = sum((max(0, m - c) for c in cooperator_counts))
        if s_val < n:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_9(BaseStrategy):
    """
    A threshold-based conditional cooperation strategy.
    
    The strategy cycles through three states: 'Cooperative', 'Retaliatory', 
    and 'Testing'. It aims to maintain cooperation if the threshold m is met, 
    retaliates by defecting if the threshold is missed, and uses a final 
    round heuristic based on historical cooperation rates.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.state = 'Cooperative'

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_c = int(history.opponent_cooperators[-1])
        r = self.game_description.n_rounds
        m = self.game_description.m
        t = history.round_number
        if t == r - 1:
            coop_history = history.my_actions.astype(int)
            total_coop_rounds = np.sum(coop_history)
            if total_coop_rounds / t > 0.5:
                return Action.C
            else:
                return Action.D
        if prev_c == m - 1:
            return Action.C
        if self.state == 'Cooperative':
            if prev_c >= m:
                return Action.C
            else:
                self.state = 'Retaliatory'
                return Action.D
        elif self.state == 'Retaliatory':
            if prev_c >= m:
                self.state = 'Cooperative'
                return Action.C
            else:
                return Action.D
        elif self.state == 'Testing':
            if prev_c >= m:
                self.state = 'Cooperative'
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_PROSOCIAL_10(BaseStrategy):
    """
    A conditional cooperative strategy for the Collective Risk Dilemma.
    Operates by prioritizing the threshold m, punishing unilateral defection 
    when necessary, and utilizing a stochastic recovery mechanism.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.r - 1:
            total_coops = 0
            for t in range(history.round_number):
                c_mine = 1 if history.my_actions[t] else 0
                c_others = history.opponent_cooperators[t]
                total_coops += c_others + c_mine
            num_past_rounds = history.round_number
            avg_rate = total_coops / (self.n * num_past_rounds)
            if avg_rate >= self.m / self.n:
                return Action.C
            else:
                return Action.D
        last_round_idx = history.round_number - 1
        c_others = history.opponent_cooperators[last_round_idx]
        my_last_action = 1 if history.my_actions[last_round_idx] else 0
        total_coops_last = c_others + my_last_action
        if total_coops_last >= self.m:
            return Action.C
        if my_last_action == 1 and total_coops_last == self.m - 1:
            return Action.C
        prob_recovery = self.m / self.n
        if random.random() < prob_recovery:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_11(BaseStrategy):
    """
    Implements a reciprocal strategy for the Collective Risk Dilemma:
    - Round 1: Always Cooperate (C).
    - Rounds t > 1:
        - If previous total cooperators >= m: Cooperate (C).
        - If previous total cooperators < m: Defect (D), with a 10% chance to 'probe' (C).
    - Terminal round: Cooperate (C) unless previous cooperation was 0.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.unconditional_cooperation_mode = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        m = self.game_description.m
        current_round_idx = history.round_number
        prev_round_idx = current_round_idx - 1
        my_prev_action = history.my_actions[prev_round_idx]
        opponent_coop_count = history.opponent_cooperators[prev_round_idx]
        total_cooperators = opponent_coop_count + (1 if my_prev_action else 0)
        if current_round_idx == r - 1:
            if total_cooperators > 0:
                return Action.C
            else:
                return Action.D
        if self.unconditional_cooperation_mode:
            return Action.C
        if total_cooperators >= m:
            self.unconditional_cooperation_mode = True
            return Action.C
        if random.random() < 0.1:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_12(BaseStrategy):
    """
    Threshold-Conditional Tit-for-Tat (TCTT):
    - Round 1: Cooperate.
    - If total cooperators in previous round >= m: Cooperate.
    - If total cooperators in previous round == m - 1: Cooperate (Close miss recovery).
    - If total cooperators < m - 1: Defect (Punishment).
    - Exception: If strategy is in a state of sustained defection (previous round was < m - 1 and played D),
      it waits for O_{t-1} >= m - 1 (opponents ready to cooperate) before returning to C.
    - Final round: If currently cooperating, cooperate. If currently defecting, continue to defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.is_punishing = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            self.is_punishing = False
            return Action.C
        prev_round_idx = history.round_number - 1
        prev_opponents_C = history.opponent_cooperators[prev_round_idx]
        prev_self_C = 1 if history.my_actions[prev_round_idx] else 0
        total_C = prev_opponents_C + prev_self_C
        m = self.game_description.m
        r = self.game_description.n_rounds
        is_final_round = history.round_number == r - 1
        if self.is_punishing:
            if prev_opponents_C >= m - 1:
                self.is_punishing = False
            else:
                pass
        if not self.is_punishing:
            if total_C < m - 1:
                self.is_punishing = True
        if total_C >= m - 1:
            return Action.C
        if self.is_punishing:
            if is_final_round:
                return Action.D
            return Action.D
        return Action.C

class Strategy_PROSOCIAL_13(BaseStrategy):
    """
    A strategy that maintains cooperation based on a reputation score S,
    calculated from the group's ability to reach the threshold m. 
    It incorporates gradual forgiveness and threshold enforcement rules.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.s = 1.0
        self.consecutive_failures = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if self.desc.k < 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        last_round_idx = history.round_number - 1
        last_round_cooperators = history.opponent_cooperators[last_round_idx]
        my_last_action = history.my_actions[last_round_idx]
        total_cooperators = last_round_cooperators + (1 if my_last_action else 0)
        if total_cooperators < self.desc.m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 3:
            self.s = 0.0
        elif total_cooperators >= self.desc.m:
            self.s = min(1.0, self.s + 0.2)
        elif total_cooperators == self.desc.m - 1:
            self.s = max(0.0, self.s - 0.1)
        else:
            self.s = max(0.0, self.s - 0.4)
        if history.round_number == self.desc.n_rounds - 1:
            if self.s > 0.6:
                return Action.C
            else:
                return Action.D
        if random.random() < self.s:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_14(BaseStrategy):
    """
    Implements Conditional Reciprocal Thresholding.
    Initiates with cooperation. If the threshold 'm' is met, maintains cooperation.
    If 'm' is missed, enters a punishment phase by defecting and decrementing a state variable S.
    Uses a 'Recovery Rule' to reset and resume cooperation if the group shows consistent
    intent (N_c >= m-1 for two consecutive rounds) even during a punishment phase.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.S = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            self.S = 0
            return Action.C
        m = self.game_description.m
        last_round_idx = history.round_number - 1
        my_last_action = history.my_actions[last_round_idx]
        n_opp_c = history.opponent_cooperators[last_round_idx]
        total_c = n_opp_c + (1 if my_last_action else 0)
        if total_c >= m:
            self.S = 0
            return Action.C
        else:
            if my_last_action:
                self.S -= 1
            if history.round_number >= 2:
                prev_my_act = history.my_actions[last_round_idx - 1]
                prev_opp_c = history.opponent_cooperators[last_round_idx - 1]
                total_c_prev = prev_opp_c + (1 if prev_my_act else 0)
                if self.S < 0 and total_c >= m - 1 and (total_c_prev >= m - 1):
                    self.S = 0
                    return Action.C
            return Action.D

class Strategy_PROSOCIAL_15(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that employs a conditional
    Cooperative/Defect status based on the threshold m.
    
    1. Initial Round (t=1): Always Cooperate.
    2. Status 'Cooperative':
       - If previous round cooperators >= m: Maintain status 'Cooperative', choose Cooperate.
       - If previous round cooperators < m: Switch to 'Defect', choose Defect.
    3. Status 'Defect':
       - If previous round cooperators >= m: Switch to 'Cooperative', choose Cooperate.
       - If previous round cooperators < m: Maintain status 'Defect', choose Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.status = 'Cooperative'

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            self.status = 'Cooperative'
            return Action.C
        last_round_idx = history.round_number - 1
        opponents_cooperated = history.opponent_cooperators[last_round_idx]
        i_cooperated = 1 if history.my_actions[last_round_idx] == Action.C else 0
        total_cooperators = opponents_cooperated + i_cooperated
        threshold_met = total_cooperators >= self.game_description.m
        if self.status == 'Cooperative':
            if threshold_met:
                return Action.C
            else:
                self.status = 'Defect'
                return Action.D
        elif self.status == 'Defect':
            if threshold_met:
                self.status = 'Cooperative'
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_PROSOCIAL_16(BaseStrategy):
    """
    A conditional strategy for the Collective Risk Dilemma that tracks a 'status'
    (Cooperative/Defect), adapts to threshold fluctuations, and handles recovery
    and edge-case scenarios like the 'm-1' accident buffer.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.status = 1

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        m = self.game_description.m
        my_prev_action = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + my_prev_action
        if total_cooperators_prev == m - 1 or total_cooperators_prev == m:
            self.status = 1
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            if self.status == 1:
                return Action.C
            else:
                if total_cooperators_prev >= m:
                    return Action.C
                return Action.D
        if self.status == 1:
            if total_cooperators_prev < m:
                self.status = 0
                return Action.D
            else:
                return Action.C
        elif total_cooperators_prev >= m + 1:
            self.status = 1
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_17(BaseStrategy):
    """
    Implements a Conditional Reciprocal Thresholding strategy for the Collective Risk Dilemma.
    
    Phase 1 (Early/Mid Game): Trigger-based cooperation. If the threshold was met
    in the previous round, cooperate. If not, defect for one round as a signal,
    then attempt recovery.
    
    Phase 2 (Late Game, round r-1): Mean-based evaluation. If historical average
    cooperation >= m, cooperate; otherwise, defect.
    
    Phase 3 (Final Round r): Cultural success check. If threshold m was met in
    at least 50% of previous rounds, cooperate; otherwise, defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self._just_corrected = False

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = self.game_description.n_rounds
        m = self.game_description.m
        current_round_idx = history.round_number
        if current_round_idx == 0:
            self._just_corrected = False
            return Action.C

        def get_total_cooperators(round_idx: int) -> int:
            i_cooperated = int(history.my_actions[round_idx])
            opp_coops = int(history.opponent_cooperators[round_idx])
            return opp_coops + i_cooperated
        if current_round_idx < n_rounds - 2:
            prev_total_c = get_total_cooperators(current_round_idx - 1)
            if prev_total_c >= m:
                self._just_corrected = False
                return Action.C
            elif self._just_corrected:
                self._just_corrected = False
                return Action.C
            else:
                self._just_corrected = True
                return Action.D
        if current_round_idx == n_rounds - 2:
            all_past_total_c = [get_total_cooperators(i) for i in range(current_round_idx)]
            mean_c = np.mean(all_past_total_c) if all_past_total_c else 0.0
            if mean_c >= m:
                return Action.C
            return Action.D
        if current_round_idx == n_rounds - 1:
            all_past_total_c = np.array([get_total_cooperators(i) for i in range(current_round_idx)])
            successes = np.sum(all_past_total_c >= m)
            success_rate = successes / current_round_idx
            if success_rate >= 0.5:
                return Action.C
            return Action.D
        return Action.D

class Strategy_PROSOCIAL_18(BaseStrategy):
    """
    Threshold-Adaptive Reciprocity (TAR):
    A conditional cooperation strategy that attempts to hit the threshold 'm' 
    by reciprocating cooperative behavior and punishing free-riders. It maintains
    an internal state to track if it has permanently switched to defection due 
    to group failure.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.gave_up = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if self.gave_up:
            return Action.D
        last_others_cooperated = history.opponent_cooperators[-1]
        i_last_action = history.my_actions[-1]
        if history.round_number >= 3:
            recent_others = history.opponent_cooperators[-3:]
            if np.mean(recent_others) < self.m - 2:
                self.gave_up = True
                return Action.D
        if not i_last_action and last_others_cooperated >= self.m:
            return Action.D
        if not i_last_action and last_others_cooperated >= self.m - 1:
            return Action.C
        if last_others_cooperated >= self.m - 1:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_19(BaseStrategy):
    """
    Adaptive Threshold Tit-for-Tat (ATTT) strategy.
    
    Logic:
    - Round 0: Cooperate.
    - Final Round: Cooperate if cooperation was successful in >= 50% of previous rounds.
    - If group fails threshold for 3 consecutive rounds (where my contribution would have mattered), defect for remaining rounds.
    - Otherwise:
        - If previous total cooperators >= m, Cooperate.
        - If previous total cooperators == m-1, Cooperate.
        - Else, Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_coordination_failures = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        m = self.game_description.m
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        my_prev_actions = history.my_actions.astype(int)
        n_prev_cooperators = history.opponent_cooperators + my_prev_actions
        if current_round == r - 1:
            successful_rounds = np.sum(n_prev_cooperators >= m)
            if successful_rounds / current_round >= 0.5:
                return Action.C
            return Action.D
        if current_round >= 3:
            recent_N = n_prev_cooperators[-3:]
            if all((val < m for val in recent_N)) and all((val >= m - 1 for val in recent_N)):
                return Action.D
        last_N = n_prev_cooperators[-1]
        if last_N >= m:
            return Action.C
        elif last_N == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_20(BaseStrategy):
    """
    A strategy that alternates between cooperative and punitive phases based on historical group performance,
    while attempting to recover cooperation periodically.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.test_interval = 3
        self.m = game_description.m
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_round = history.round_number - 1
        my_prev_action = int(history.my_actions[-1])
        c_prev = history.opponent_cooperators[-1] + my_prev_action
        if history.round_number == self.n_rounds - 1:
            total_c = np.sum(history.opponent_cooperators) + np.sum(history.my_actions)
            avg_cooperation = total_c / history.round_number
            if avg_cooperation >= self.m:
                return Action.C
            return Action.D
        if c_prev >= self.m:
            return Action.C
        if history.round_number % self.test_interval == 0:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_21(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that maintains an active cooperation state, 
    adapts contribution probability based on group performance, triggers total defection 
    upon sustained failure, and attempts a final-round cooperative effort if viable.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.state = 'Active'
        self.consecutive_failures = 0
        self.failure_threshold = math.ceil(self.game_description.n_rounds / 4)

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        if current_round == 0:
            return Action.C
        my_prev_action_bool = history.my_actions[-1]
        my_prev_action = 1 if my_prev_action_bool else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + my_prev_action
        if total_cooperators_prev < m:
            self.consecutive_failures += 1
            if my_prev_action == 1 or self.consecutive_failures >= self.failure_threshold:
                self.state = 'Defection_Triggered'
        else:
            self.consecutive_failures = 0
        if self.state == 'Defection_Triggered':
            return Action.D
        if current_round == r - 1:
            if total_cooperators_prev >= m - 1:
                return Action.C
            else:
                return Action.D
        if total_cooperators_prev >= m:
            return Action.C
        deficit = m - total_cooperators_prev
        if deficit > n / 2:
            self.state = 'Defection_Triggered'
            return Action.D
        prob_cooperate = 1.0 - deficit / n
        if random.random() < prob_cooperate:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_22(BaseStrategy):
    """
    A conditional threshold-trigger strategy that prioritizes cooperation, uses
    Tit-for-Tat recovery when thresholds are missed but reachable, and defects
    when cooperation is clearly ineffective or non-reciprocal.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        my_prev_action = history.my_actions[-1]
        my_prev_contribution = 1 if my_prev_action == Action.C else 0
        total_cooperators = history.opponent_cooperators[-1] + my_prev_contribution
        round_idx = history.round_number
        is_final_round = round_idx == r - 1
        if is_final_round:
            if total_cooperators >= m - 1:
                return Action.C
            else:
                return Action.D
        if total_cooperators >= m:
            return Action.C
        can_tip_balance = total_cooperators + 1 >= m
        if my_prev_action == Action.D and can_tip_balance:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_23(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that signals cooperation early,
    uses conditional reciprocity based on the threshold m, pivots to punish
    failure or subsidize success, and applies a trend analysis in the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_round = history.round_number - 1
        prev_cooperators = history.opponent_cooperators[prev_round]
        my_prev_action = Action.C if history.my_actions[prev_round] else Action.D
        my_contribution = 1 if my_prev_action == Action.C else 0
        total_cooperators = prev_cooperators + my_contribution
        if history.round_number == self.r - 1:
            all_coop_counts = []
            for i in range(history.round_number):
                opp = history.opponent_cooperators[i]
                my = 1 if history.my_actions[i] else 0
                all_coop_counts.append(opp + my)
            successes = sum((1 for c in all_coop_counts if c >= self.m))
            failures = sum((1 for c in all_coop_counts if c < self.m))
            if successes >= failures:
                return Action.C
            else:
                return Action.D
        if prev_cooperators == self.m - 1:
            return Action.C
        if total_cooperators >= self.m:
            return Action.C
        if my_prev_action == Action.C:
            return Action.D
        return Action.D

class Strategy_PROSOCIAL_24(BaseStrategy):
    """
    A threshold-based adaptive reciprocity strategy for the Collective Risk Dilemma.
    Starts with cooperation and adjusts based on the previous round's outcome relative to the threshold (m).
    Specifically, it maintains cooperation if the threshold is met, punishes failures to reach the threshold
    by defecting, and attempts to resume cooperation if the group is close to reaching the threshold.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        my_last_action = Action.C if history.my_actions[-1] else Action.D
        current_round = history.round_number
        total_rounds = self.n_rounds
        if current_round == total_rounds - 1:
            if prev_cooperators >= self.m - 1:
                return Action.C
            else:
                return Action.D
        if my_last_action == Action.C:
            if prev_cooperators >= self.m:
                return Action.C
            else:
                return Action.D
        elif prev_cooperators >= self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_25(BaseStrategy):
    """
    Conditional Threshold Reciprocator:
    - Starts by cooperating.
    - If previous round success (total cooperation >= m), cooperates.
    - If previous round failure (total cooperation < m), defects with probability proportional to the deficit (m - C_t-1) / n.
    - In the final round, defects if the previous round was a failure.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_prev_action = int(history.my_actions[-1])
        others_prev_action_count = int(history.opponent_cooperators[-1])
        total_cooperators_prev = my_prev_action + others_prev_action_count
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round_idx = history.round_number
        if current_round_idx == r - 1:
            if total_cooperators_prev >= m:
                return Action.C
            else:
                return Action.D
        if total_cooperators_prev >= m:
            return Action.C
        else:
            deficit = m - total_cooperators_prev
            prob_defect = min(1.0, deficit / n)
            if random.random() < prob_defect:
                return Action.D
            else:
                return Action.C

class Strategy_PROSOCIAL_26(BaseStrategy):
    """
    A conditional threshold-based cooperation strategy. 
    It balances cooperative thresholds (m) by probabilistic entry, 
    adaptive signaling upon failure, and an opportunistic recoupment phase.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.consecutive_failures = 0
        self.in_recoupment = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.desc.n_players
        m = self.desc.m
        r = self.desc.n_rounds
        t = history.round_number
        if t == 0:
            return Action.C if random.random() < m / n else Action.D
        my_prev_c = int(history.my_actions[-1])
        my_prev_action = Action.C if my_prev_c == 1 else Action.D
        l_prev = history.opponent_cooperators[-1] + my_prev_c
        if l_prev < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
            self.in_recoupment = False
        if t == r - 1:
            if l_prev >= m:
                return my_prev_action
            else:
                if history.opponent_cooperators[-1] + 1 >= m:
                    return Action.C
                return Action.D
        if self.consecutive_failures >= 2:
            if not self.in_recoupment:
                self.in_recoupment = True
                return Action.C
            else:
                return Action.D
        if l_prev >= m:
            if my_prev_action == Action.D:
                return Action.D
            prob_c = m / n
            if l_prev > m:
                adjustment = (l_prev - m) / n
                prob_c = max(0.0, prob_c - adjustment)
            return Action.C if random.random() < prob_c else Action.D
        elif my_prev_action == Action.C:
            return Action.D
        else:
            return Action.C

class Strategy_PROSOCIAL_27(BaseStrategy):
    """
    A conditional cooperation strategy for the Collective Risk Dilemma.
    Implements a trigger-threshold mechanism: plays C on round 1.
    In subsequent rounds, rewards cooperation if the threshold was met,
    uses a repentance mechanism if previously defected and goal met,
    executes a "Rescue Move" if the threshold is within reach,
    and switches to a final-round terminal logic.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_last_move_bool = history.my_actions[-1]
        total_cooperators_prev = history.opponent_cooperators[-1] + (1 if my_last_move_bool else 0)
        if history.round_number == self.r - 1:
            prev_opp_actions = history.opponent_cooperators
            my_actions = history.my_actions
            success_count = 0
            for i in range(len(my_actions)):
                total = prev_opp_actions[i] + (1 if my_actions[i] else 0)
                if total >= self.m:
                    success_count += 1
            success_rate = success_count / len(my_actions)
            if total_cooperators_prev >= self.m - 1 or success_rate > 0.5:
                return Action.C
            else:
                return Action.D
        if total_cooperators_prev >= self.m:
            if my_last_move_bool:
                return Action.C
            else:
                p = 1.0 - total_cooperators_prev / self.n
                if random.random() < p:
                    return Action.C
                return Action.D
        elif total_cooperators_prev == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_28(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that uses threshold-based conditioning,
    cooperation streaks, and targeted defection to balance the risk of non-cooperation 
    with the need to avoid exploitation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.cooperation_streak = 0
        self.exploitation_cooldown = 0
        self.initial_failure_recovery = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r_total = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            self.cooperation_streak = 0
            self.exploitation_cooldown = 0
            self.initial_failure_recovery = False
            return Action.C
        prev_round = current_round - 1
        my_prev_action = history.my_actions[prev_round]
        total_cooperators_prev = history.opponent_cooperators[prev_round] + (1 if my_prev_action else 0)
        threshold_met = 1 if total_cooperators_prev >= m else 0
        if threshold_met == 1:
            self.cooperation_streak += 1
            self.initial_failure_recovery = False
        else:
            self.cooperation_streak = 0
        if current_round == r_total - 1:
            return Action.D
        if self.exploitation_cooldown > 0:
            self.exploitation_cooldown -= 1
            if total_cooperators_prev >= m:
                return Action.D
            else:
                self.exploitation_cooldown = 0
        if my_prev_action == True and total_cooperators_prev == m:
            if random.random() < 0.5:
                self.exploitation_cooldown = 1
                return Action.D
        if current_round == 1 and threshold_met == 0:
            self.initial_failure_recovery = True
            return Action.D
        if self.initial_failure_recovery:
            self.initial_failure_recovery = False
            return Action.C
        if threshold_met == 1:
            p = min(1.0, m / n + 0.1)
            if random.random() < p:
                return Action.C
            else:
                return Action.D
        elif total_cooperators_prev == 0 or total_cooperators_prev == 1:
            return Action.D
        elif total_cooperators_prev >= m - 1:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_29(BaseStrategy):
    """
    Threshold-Adaptive Reciprocity (TAR) Strategy.
    
    Plays C in the first round.
    Tracks historical cooperation levels.
    If the threshold (m) was met in the previous round, maintains C.
    If the threshold was not met, it calculates the historical success ratio (successful rounds / total rounds).
    If the ratio > 0.5 (indicating a generally cooperative history), it attempts a conditional reset (plays C).
    Otherwise, it defaults to D for the remainder of the game.
    In the final round, it plays C if the threshold was met previously, otherwise D.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_index = history.round_number
        n_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round_index == 0:
            return Action.C
        last_my_action = history.my_actions[-1]
        last_opponent_cooperators = history.opponent_cooperators[-1]
        total_cooperators_prev = int(last_opponent_cooperators) + (1 if last_my_action else 0)
        successful_rounds = 0
        for i in range(current_round_index):
            c_i = int(history.opponent_cooperators[i]) + (1 if history.my_actions[i] else 0)
            if c_i >= m:
                successful_rounds += 1
        if current_round_index == n_rounds - 1:
            return Action.C if total_cooperators_prev >= m else Action.D
        if total_cooperators_prev >= m:
            return Action.C
        else:
            success_ratio = successful_rounds / current_round_index
            if success_ratio > 0.5:
                return Action.C
            else:
                return Action.D

class Strategy_PROSOCIAL_30(BaseStrategy):
    """
    Conditional Threshold Tit-for-Tat (CT-TFT)
    Implements a strategy based on threshold monitoring, pivotal cooperation,
    and punishment cycles.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_coop_failures = 0
        self.is_punishing = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.game_description.m
        n_rounds = self.game_description.n_rounds
        my_last_action = int(history.my_actions[-1])
        others_last_coop = history.opponent_cooperators[-1]
        total_coop_last = others_last_coop + my_last_action
        all_my_actions = history.my_actions.astype(int)
        all_total_coop = history.opponent_cooperators + all_my_actions
        if history.round_number == n_rounds - 1:
            success_count = np.sum(all_total_coop >= m)
            success_rate = success_count / history.round_number
            if success_rate >= 0.75:
                return Action.C
            return Action.D
        if total_coop_last < m and my_last_action == 1:
            self.consecutive_coop_failures += 1
        elif total_coop_last >= m:
            self.consecutive_coop_failures = 0
            self.is_punishing = False
        if self.consecutive_coop_failures >= 2:
            self.is_punishing = True
            self.consecutive_coop_failures = 0
            return Action.D
        if self.is_punishing:
            self.is_punishing = False
            return Action.D
        if total_coop_last >= m:
            return Action.C
        avg_coop = np.mean(all_total_coop)
        is_majority_defected = avg_coop < m
        if others_last_coop == m - 1 and (not is_majority_defected):
            return Action.C
        if others_last_coop == m - 1:
            return Action.D
        return Action.D

class Strategy_PROSOCIAL_31(BaseStrategy):
    """
    Implements a conditional cooperation strategy for the Collective Risk Dilemma.
    Maintains a cooperative state unless the threshold isn't met, with specific 
    retaliation and recovery mechanisms.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.state = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        if history.round_number == 0:
            if m <= n / 2:
                return Action.C
            else:
                if 0.5 > (m - 1) / (n - 1):
                    return Action.C
                return Action.D
        last_round_idx = history.round_number - 1
        my_last_action = history.my_actions[last_round_idx]
        opponents_cooperated = history.opponent_cooperators[last_round_idx]
        total_cooperators = opponents_cooperated + (1 if my_last_action else 0)
        is_final_round = history.round_number == r - 1
        if self.state == 0:
            if total_cooperators >= m:
                action = Action.C
            elif total_cooperators >= m - 1 and my_last_action:
                action = Action.C
            else:
                self.state = 1
                action = Action.D
        else:
            action = Action.D
            if total_cooperators >= m:
                self.state = 0
                action = Action.C
        if is_final_round:
            if self.state == 1:
                return Action.D
            else:
                return Action.C
        return action

class Strategy_PROSOCIAL_32(BaseStrategy):
    """
    Implements the Adaptive Threshold Trigger (ATT) strategy.
    
    This strategy aims to maintain exactly m cooperators per round to maximize 
    collective benefit while minimizing individual contribution costs. It utilizes 
    a "Stability Buffer" when the threshold is met exactly to prevent 
    unstable oscillations.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        round_t = history.round_number
        if round_t == 0:
            prob_c = self.m / self.n
            return Action.C if random.random() < prob_c else Action.D
        last_coop_others = history.opponent_cooperators[-1]
        last_my_action_val = 1 if history.my_actions[-1] else 0
        h_coop = last_coop_others + last_my_action_val
        if h_coop >= self.m:
            if h_coop == self.m:
                return Action.C if random.random() < 0.2 else Action.D
            return Action.D
        else:
            return Action.C

class Strategy_ALTRUISTIC_5(BaseStrategy):
    """
    Implements a Conditional Tit-for-Tat with Threshold Sensitivity strategy.
    
    In the initial round, it cooperates to signal willingness to participate.
    In subsequent rounds, it observes the number of cooperators from the previous round (C_prev).
    - If C_prev >= m, it cooperates, reinforcing the successful collective outcome.
    - If C_prev < m, it defects, as the threshold for the reward (k) was not met.
    This approach optimizes for the collective reward while avoiding exploitation when the threshold is missed.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_last_action = history.my_actions[-1]
        others_cooperated = history.opponent_cooperators[-1]
        total_cooperators_prev = others_cooperated + (1 if my_last_action else 0)
        if total_cooperators_prev >= self.m:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_6(BaseStrategy):
    """
    A strategy that maintains cooperation based on a threshold-monitoring approach.
    It cooperates in the first round and then adjusts based on group performance:
    - If previous round performance >= m-1, cooperate.
    - If previous round performance < m-1, defect, but with a 're-ignition'
      attempt every 3rd round.
    - In the final round, it evaluates the total historical performance to decide
      between cooperation and defection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.n = game_description.n_players
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_idx = -1
        last_obs = history.opponent_cooperators[prev_idx]
        current_round = history.round_number + 1
        if current_round == self.r:
            if history.round_number == 0:
                return Action.C
            avg_cooperation = np.mean(history.opponent_cooperators)
            threshold = (self.m - 1) / self.n
            if avg_cooperation >= threshold:
                return Action.C
            else:
                return Action.D
        if last_obs >= self.m - 1:
            return Action.C
        elif current_round % 3 == 0:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_7(BaseStrategy):
    """
    Threshold-Tit-for-Tat (TTFT) Strategy.
    
    Cooperates in the first round. In subsequent rounds:
    1. If the previous round met the threshold (cooperators >= m), continue to cooperate.
    2. If the previous round failed, defect, but probe every 3rd round with cooperation 
       to check if the group is ready to return to a cooperative equilibrium.
    3. Handles final round edge case by defecting if the previous round failed.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.probe_interval = 3

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        my_last_action = history.my_actions[-1]
        opponents_cooperated = history.opponent_cooperators[-1]
        total_cooperators_last_round = int(my_last_action) + opponents_cooperated
        previous_success = total_cooperators_last_round >= m
        if current_round == r - 1:
            return Action.C if previous_success else Action.D
        if previous_success:
            return Action.C
        if (current_round + 1) % self.probe_interval == 0:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_8(BaseStrategy):
    """
    Implements a collective risk dilemma strategy that alternates between cooperative threshold maintenance
    and defensive defection. It prioritizes reaching the threshold 'm', but tracks consecutive failure
    streaks to minimize losses when the group is uncooperative.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.failed_streak = 0
        self.epsilon = 0.05

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        if current_round == 0:
            return Action.C
        last_idx = -1
        prev_opp_coop = history.opponent_cooperators[last_idx]
        my_prev_action = history.my_actions[last_idx]
        total_cooperators = int(prev_opp_coop) + (1 if my_prev_action else 0)
        if total_cooperators < m:
            self.failed_streak += 1
        else:
            self.failed_streak = 0
        if current_round == r - 1:
            if total_cooperators >= m:
                return Action.C
            else:
                return Action.D
        if total_cooperators >= m:
            if total_cooperators > m:
                return Action.C
            elif random.random() < 1.0 - self.epsilon:
                return Action.C
            else:
                return Action.D
        elif self.failed_streak >= 3:
            return Action.D
        else:
            return Action.C

class Strategy_ALTRUISTIC_9(BaseStrategy):
    """
    Implements a 'Conditional Reciprocity with Patience' strategy for the Collective Risk Dilemma.
    
    Logic:
    - Round 0: Always Cooperate (C) to signal intent.
    - Rounds 1 to r-2: 
        - If previous round threshold (m) met: Cooperate (C) regardless of previous action.
        - If threshold missed:
            - If missed by exactly 1 (N_c == m-1) AND I defected: Attempt recovery (C).
            - Else (significant miss or already defecting): Defect (D) to signal dissatisfaction or conserve.
    - Final Round (r-1): 
        - Check historical success rate of reaching threshold m over all previous rounds.
        - If success rate >= 50%: Cooperate (C).
        - Else: Defect (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.game_description.m
        n_rounds = self.game_description.n_rounds
        current_round = history.round_number
        last_idx = -1
        prev_my_action_int = 1 if history.my_actions[last_idx] else 0
        prev_n_c = history.opponent_cooperators[last_idx] + prev_my_action_int
        prev_my_action_c = history.my_actions[last_idx]
        if current_round == n_rounds - 1:
            total_past_rounds = current_round
            success_count = 0
            for r in range(total_past_rounds):
                my_c = 1 if history.my_actions[r] else 0
                opp_c = history.opponent_cooperators[r]
                if my_c + opp_c >= m:
                    success_count += 1
            success_rate = success_count / total_past_rounds
            return Action.C if success_rate >= 0.5 else Action.D
        if prev_n_c >= m:
            return Action.C
        if prev_n_c == m - 1 and (not prev_my_action_c):
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_10(BaseStrategy):
    """
    Strategy: Threshold-Responsive Tit-for-Tat with Conditional Altruism.
    
    Operates by balancing the burden of the threshold $m$. It is cautious in the 
    first round, adaptive based on the previous round's success, and enters a 
    cooperative termination phase if history suggests the community is viable.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C if self.m / self.n <= 0.5 else Action.D
        x = min(3, self.r // 4)
        if history.round_number >= self.r - x:
            total_cooperators_history = []
            for t in range(history.round_number):
                my_c = 1 if history.my_actions[t] else 0
                total_cooperators_history.append(history.opponent_cooperators[t] + my_c)
            avg_c = sum(total_cooperators_history) / len(total_cooperators_history)
            return Action.C if avg_c > self.m - 1 else Action.D
        my_c_prev = 1 if history.my_actions[-1] else 0
        C_prev = history.opponent_cooperators[-1] + my_c_prev
        if C_prev >= self.m:
            return Action.C if history.my_actions[-1] else Action.D
        G = self.m - C_prev
        if not history.my_actions[-1] and G == 1:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_11(BaseStrategy):
    """
    Implements a Collective Risk Dilemma strategy using Adaptive Reciprocity.
    - Phase 1: Initiates with Cooperation.
    - Phase 2: Adjusts cooperation based on threshold performance (S_t-1 vs m).
    - Phase 3: Switches to conditional cooperation based on past stability in the final round.
    - Includes Altruistic Adjustment: Prioritizes marginal contribution when S_t-1 = m-1.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.epsilon = 0.05
        self.trend_score = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        prev_opp_coop = history.opponent_cooperators[-1]
        s_prev = prev_opp_coop + (1 if my_prev_action else 0)
        if current_round > 1:
            prev_s_prev = history.opponent_cooperators[-2] + (1 if history.my_actions[-2] else 0)
            if s_prev > prev_s_prev:
                self.trend_score += 1
            elif s_prev < prev_s_prev:
                self.trend_score -= 1
        if current_round == r - 1:
            if s_prev >= m:
                return Action.C
            return Action.D
        if s_prev == m - 1:
            return Action.C
        if s_prev >= m:
            if my_prev_action:
                return Action.C
            elif s_prev > m:
                return Action.D
            else:
                if n == s_prev:
                    return Action.C
                prob = (m - s_prev) / (n - s_prev) + self.epsilon
                return Action.C if random.random() < prob else Action.D
        elif my_prev_action:
            if s_prev < m - 1:
                return Action.D
            else:
                return Action.C
        else:
            if self.trend_score > 0:
                return Action.C
            return Action.D

class Strategy_ALTRUISTIC_12(BaseStrategy):
    """
    Implements a Conditional Altruism strategy.
    
    Logic:
    - Round 1: Cooperate.
    - Subsequent rounds: Maintains a trust state (S) and a dynamic cooperation threshold (M).
    - If S=1 (Trusting): Cooperate if prev_cooperators >= m. If not, defect, S=0, M++.
    - If S=0 (Suspicious): Cooperate only if prev_cooperators >= M, then reset S=1.
    - Final round: If S=1 or prev_cooperators >= m, cooperate; else defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.threshold = game_description.m
        self.state = 1

    def __call__(self, history: PlayerHistory) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        is_final_round = round_idx == self.desc.n_rounds - 1
        if is_final_round:
            if self.state == 1 or prev_cooperators >= self.desc.m:
                return Action.C
            return Action.D
        if self.state == 1:
            if prev_cooperators < self.desc.m:
                self.state = 0
                self.threshold += 1
                return Action.D
            else:
                return Action.C
        elif prev_cooperators >= self.threshold:
            self.state = 1
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_13(BaseStrategy):
    """
    Implements the Conditional Reciprocal Contribution (CRC) strategy.
    
    This strategy behaves as follows:
    - Round 0: Cooperates to signal willingness.
    - Subsequent rounds:
        - If the threshold was met in the previous round, cooperates.
        - If the threshold was NOT met in the previous round, defects.
        - Adaptive Efficiency: If the threshold was exceeded by more than one 
          person (total cooperators > m), it probabilistically defects with 
          probability P = (cooperators - m) / cooperators to avoid 
          excessive contribution.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        last_round_idx = -1
        last_my_action = history.my_actions[last_round_idx]
        last_opp_coop = history.opponent_cooperators[last_round_idx]
        last_total_cooperators = int(last_my_action) + last_opp_coop
        m = self.game_description.m
        threshold_met = last_total_cooperators >= m
        if threshold_met:
            if last_total_cooperators > m:
                prob_defect = (last_total_cooperators - m) / last_total_cooperators
                if random.random() < prob_defect:
                    return Action.D
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_14(BaseStrategy):
    """
    Implements a threshold-responsive Tit-for-Tat strategy with periodic forgiveness.
    Cooperates as long as the threshold 'm' was met in the previous round. 
    If the threshold was not met, it switches to a Defect regime, but periodically 
    attempts to reconcile with an 'Olive Branch' (Cooperate) based on a reset interval.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        if self.game_description.k > 1.5:
            self.recovery_interval = 2
        else:
            self.recovery_interval = max(2, self.game_description.n_players)

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        last_my_action = history.my_actions[-1]
        last_opponents_coop = history.opponent_cooperators[-1]
        total_cooperators_last_round = int(last_opponents_coop) + (1 if last_my_action else 0)
        regime_violated = total_cooperators_last_round < self.game_description.m
        if history.round_number == self.game_description.n_rounds - 1:
            if not regime_violated:
                return Action.C
            return Action.D
        if not regime_violated:
            return Action.C
        else:
            current_round_num = history.round_number + 1
            if current_round_num % self.recovery_interval == 0:
                return Action.C
            return Action.D

class Strategy_ALTRUISTIC_15(BaseStrategy):
    """
    A conditional cooperation strategy for Collective Risk Dilemmas.
    Uses adaptive forgiveness based on temporal proximity to the game's end
    and historical population cooperation rates.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.n = self.desc.n_players
        self.r = self.desc.n_rounds
        self.m = self.desc.m
        self.k = self.desc.k
        self.m_ratio = self.m / self.n

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        my_prev_action = int(history.my_actions[-1])
        total_cooperators_prev = history.opponent_cooperators[-1] + my_prev_action
        s_prev = total_cooperators_prev / self.n
        current_round_index = t + 1
        if self.m_ratio > 0.75 and current_round_index < 0.2 * self.r:
            return Action.C
        if current_round_index == self.r:
            history_total_cooperators = history.opponent_cooperators + history.my_actions.astype(int)
            history_success_rates = history_total_cooperators / self.n
            success_rounds = np.sum(history_success_rates >= self.m_ratio)
            if success_rounds / t >= 0.75:
                return Action.C
            else:
                avg_coop = np.mean(history_success_rates)
                if avg_coop < self.m_ratio:
                    return Action.D
                else:
                    return Action.C
        if total_cooperators_prev >= self.m:
            return Action.C
        else:
            forgiveness_prob = 1.0 - (current_round_index / self.r) ** 2
            if random.random() < forgiveness_prob:
                return Action.C
            else:
                return Action.D

class Strategy_ALTRUISTIC_16(BaseStrategy):
    """
    Implements a Conditional Threshold-Trigger (CTT) strategy.
    
    Logic:
    1. Initial Round: Cooperate (C).
    2. Reset Rule: Every r_reset = min(ceil(sqrt(r)), 5) rounds, play C.
    3. Endgame Heuristic: In final 2 rounds, loosen cooperation threshold requirements.
    4. Adaptive Logic (Standard):
       - If previous threshold met (C_prev >= m), maintain or switch to C.
       - If missed by exactly 1 and I played C, continue C.
       - Else, defect (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.reset_interval = min(math.ceil(math.sqrt(game_description.n_rounds)), 5)

    def __call__(self, history: PlayerHistory) -> Action:
        r_total = self.game_description.n_rounds
        r_current = history.round_number
        if r_current == 0:
            return Action.C
        round_t = r_current + 1
        if round_t % self.reset_interval == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        my_prev_c = 1 if my_prev_action else 0
        opp_prev_c = history.opponent_cooperators[-1]
        c_prev_total = opp_prev_c + my_prev_c
        if r_current >= r_total - 2:
            distance_from_end = r_total - round_t
            threshold = self.game_description.m - (distance_from_end + 1)
            threshold = max(0, threshold)
            return Action.C if c_prev_total >= threshold else Action.D
        if c_prev_total >= self.game_description.m:
            return Action.C
        elif c_prev_total == self.game_description.m - 1 and my_prev_c == 1:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_17(BaseStrategy):
    """
    Implements Conditional Threshold Reciprocity:
    1. Signals cooperation in the first round.
    2. In intermediate rounds, matches group success (C if threshold met), 
       punishes exploitation (D if group failed and we contributed), 
       and attempts to rescue (C if group failed but is 1 away from threshold).
    3. Detects persistent failure (3+ consecutive rounds of failure) and switches 
       to permanent Defection.
    4. In the final round, cooperates only if the group historically met the threshold.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.game_description.m
        n_rounds = self.game_description.n_rounds

        def get_total_cooperators(idx: int) -> int:
            my_c = 1 if history.my_actions[idx] else 0
            return my_c + history.opponent_cooperators[idx]
        if history.round_number >= 3:
            fail1 = get_total_cooperators(-1) < m
            fail2 = get_total_cooperators(-2) < m
            fail3 = get_total_cooperators(-3) < m
            if fail1 and fail2 and fail3:
                return Action.D
        c_prev = get_total_cooperators(-1)
        my_last_action = 1 if history.my_actions[-1] else 0
        if history.round_number == n_rounds - 1:
            return Action.C if c_prev >= m else Action.D
        if c_prev >= m:
            return Action.C
        elif my_last_action == 1:
            return Action.D
        elif c_prev == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_18(BaseStrategy):
    """
    Threshold-Responsive Tit-for-Tat (TR-TFT).
    
    This strategy aims to establish and maintain a stable equilibrium where the group 
    threshold 'm' is met. 
    - Round 1: Always Cooperate.
    - Rounds 2 to r-1: 
        - Cooperate if the group successfully met the threshold in the previous round.
        - If the threshold was NOT met:
            - Defect if we cooperated in the last round (punishing the lack of collective action).
            - Cooperate if we defected in the last round (probing/restoring cooperation).
    - Final Round: Cooperate if the threshold was met previously; otherwise, Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == 0:
            return Action.C
        last_round_idx = -1
        prev_opp_cooperators = history.opponent_cooperators[last_round_idx]
        prev_my_action = history.my_actions[last_round_idx]
        prev_total_cooperators = prev_opp_cooperators + (1 if prev_my_action else 0)
        if current_round == n_rounds - 1:
            if prev_total_cooperators >= m:
                return Action.C
            else:
                return Action.D
        if prev_total_cooperators >= m:
            return Action.C
        elif prev_my_action == True:
            return Action.D
        else:
            return Action.C

class Strategy_ALTRUISTIC_19(BaseStrategy):
    """
    Trigger-Threshold Reciprocity Strategy:
    - Initiates with cooperation.
    - If the previous round met the threshold (m), continues cooperation.
    - If the previous round was just below threshold (m-1), provides the crucial contribution to reach it.
    - If the previous round was further below (less than m-1), defects to conserve resources.
    - Implements persistent defection detection: if the group fails to meet the threshold consistently 
      (defined here as multiple rounds of failure), it shifts to permanent defection.
    - The "Last-Mover" Exception handles the final round by avoiding wasted cooperation if previous efforts failed.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.persistent_failure = False
        self.failure_counter = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        my_prev_action = int(history.my_actions[-1])
        total_cooperators_prev = history.opponent_cooperators[-1] + my_prev_action
        if total_cooperators_prev < m:
            self.failure_counter += 1
        else:
            self.failure_counter = 0
        if self.failure_counter >= round_idx:
            self.persistent_failure = True
        if self.persistent_failure:
            return Action.D
        if round_idx == r - 1:
            if total_cooperators_prev == 0:
                return Action.D
            return Action.C
        if total_cooperators_prev >= m:
            return Action.C
        if total_cooperators_prev < m - 1:
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_20(BaseStrategy):
    """
    Threshold-Tit-for-Tat (TTFT) strategy for the Collective Risk Dilemma.
    
    This strategy prioritizes the collective reward threshold (m) by cooperating 
    when the threshold is threatened or missed, and only defecting when the 
    threshold is safely exceeded and the number of cooperators is stable or increasing.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description
        self.m = self.game.m
        self.n_total = self.game.n_players

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_last_action = int(history.my_actions[-1])
        c_prev = history.opponent_cooperators[-1] + my_last_action
        current_round = history.round_number
        is_last_round = current_round == self.game.n_rounds - 1
        if is_last_round:
            if c_prev <= self.m:
                return Action.C
            return Action.D
        if current_round >= 2:
            my_prev_prev_action = int(history.my_actions[-2])
            c_prev_prev = history.opponent_cooperators[-2] + my_prev_prev_action
        else:
            c_prev_prev = c_prev
        if c_prev < self.m:
            return Action.C
        elif c_prev == self.m:
            return Action.C
        elif c_prev > self.m and c_prev < c_prev_prev:
            return Action.C
        if c_prev > self.m and c_prev >= c_prev_prev:
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_21(BaseStrategy):
    """
    A strategy that balances altruistic contribution to meet a collective threshold 
    with periodic testing of group robustness. It maintains a streak of successful 
    rounds and attempts to exploit the system (Defect) if the group proves robust 
    enough to hit the threshold repeatedly.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.epsilon = 0.05
        self.last_action = None

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        t = history.round_number
        if t == 0:
            self.last_action = Action.C
            return Action.C
        prev_my_coop = 1 if self.last_action == Action.C else 0
        prev_opponents = history.opponent_cooperators[-1]
        total_prev_cooperators = prev_opponents + prev_my_coop
        was_success = total_prev_cooperators >= m
        streak_counter = 0
        for i in range(t - 1, -1, -1):
            opp_i = history.opponent_cooperators[i]
            my_i = 1 if history.my_actions[i] else 0
            if opp_i + my_i >= m:
                streak_counter += 1
            else:
                break
        if t == r - 1:
            if not was_success:
                self.last_action = Action.C
                return Action.C
            else:
                self.last_action = Action.D
                return Action.D
        if streak_counter >= 3:
            if self.last_action == Action.D:
                if not was_success:
                    self.last_action = Action.C
                    return Action.C
                else:
                    self.last_action = Action.D
                    return Action.D
            else:
                self.last_action = Action.D
                return Action.D
        if not was_success:
            self.last_action = Action.C
            return Action.C
        elif random.random() < 1.0 - self.epsilon:
            self.last_action = Action.C
            return Action.C
        else:
            self.last_action = Action.D
            return Action.D

class Strategy_ALTRUISTIC_22(BaseStrategy):
    """
    A threshold-based strategy that prioritizes collective welfare. 
    It cooperates in the first round to signal intent. In subsequent rounds,
    it continues to cooperate if the threshold was met, or if a single 
    additional contribution would have met the threshold. In the final round,
    it cooperates only if historical evidence suggests a stable cooperative 
    norm exists (mean cooperators >= m - 1). Otherwise, it defects to avoid exploitation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.m
        T = self.total_rounds
        current_round = history.round_number
        is_final_round = current_round == T - 1
        prev_cooperators = history.opponent_cooperators[-1]
        if not is_final_round:
            if prev_cooperators >= m:
                return Action.C
            elif m - prev_cooperators == 1:
                return Action.C
            else:
                return Action.D
        if len(history.opponent_cooperators) > 0:
            avg_cooperation = np.mean(history.opponent_cooperators)
        else:
            avg_cooperation = 0.0
        if avg_cooperation >= m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_23(BaseStrategy):
    """
    Implements a threshold-responsive strategy: Cooperates initially and in the final round.
    In intermediate rounds, it maintains cooperation if the threshold is met or if 
    it is contributing to a near-threshold (m-1) group attempt, otherwise defects 
    to signal conditional cooperation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.C
        my_prev_action = history.my_actions[-1]
        c_prev = history.opponent_cooperators[-1] + (1 if my_prev_action else 0)
        m = self.game_description.m
        if c_prev >= m:
            return Action.C
        if c_prev == m - 1 and my_prev_action:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_24(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma using a belief-based threshold approach.
    Maintains a Trust Index to track population behavior and adjusts contribution
    based on threshold requirements and exploitation protection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.alpha = 0.8
        self.trust_index = 1.0
        self.is_punishing = False
        self.last_punishment_round = -1

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        n_opp = n - 1
        m = self.game_description.m
        k = self.game_description.k
        r = self.game_description.n_rounds
        curr_round = history.round_number
        prev_my_c = 1 if history.my_actions[-1] else 0
        prev_opp_c = history.opponent_cooperators[-1]
        prev_total_c = prev_my_c + prev_opp_c
        self.trust_index = self.alpha * self.trust_index + (1 - self.alpha) * (prev_total_c / n_opp)
        if self.is_punishing:
            if prev_total_c >= m:
                self.is_punishing = False
            else:
                return Action.D
        if curr_round == r - 1:
            my_history_arr = history.my_actions.astype(int)
            total_history = my_history_arr + history.opponent_cooperators
            avg_c = np.mean(total_history)
            if avg_c >= m:
                return Action.C
            return Action.D
        decision_val = self.trust_index * n_opp
        threshold_needed = m - 1
        if abs(decision_val - threshold_needed) < 0.5:
            return Action.C
        if decision_val < threshold_needed:
            self.is_punishing = True
            self.last_punishment_round = curr_round
            return Action.D
        action = Action.C if decision_val >= threshold_needed else Action.D
        if prev_total_c == m and action == Action.C:
            if random.random() < 0.1:
                return Action.D
        return action

class Strategy_ALTRUISTIC_25(BaseStrategy):
    """
    Implements a Threshold-Targeting Conditional Cooperation strategy for the Collective Risk Dilemma.
    Prioritizes meeting the threshold 'm' while using tit-for-tat like mechanisms to punish
    defection. Includes adaptive adjustments based on moving averages and a terminal
    altruistic push phase.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.epsilon = 0.05

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        current_round_idx = history.round_number
        last_round_idx = current_round_idx - 1
        if current_round_idx > 0:
            tau = np.mean(history.opponent_cooperators / self.n)
        else:
            tau = 1.0
        last_cooperators = history.opponent_cooperators[last_round_idx]
        last_my_action = history.my_actions[last_round_idx]
        if current_round_idx == self.r - 1:
            if tau < 0.1:
                return Action.D
            return Action.C
        if current_round_idx >= 3 * self.r // 4:
            if tau > self.m / self.n * 0.5:
                return Action.C
        if last_cooperators >= self.m:
            if last_my_action == True:
                return Action.C if random.random() > self.epsilon else Action.D
            else:
                return Action.C
        elif last_my_action == True:
            return Action.D
        else:
            if tau > self.m / self.n or last_cooperators == self.m - 1:
                return Action.C
            return Action.D

class Strategy_ALTRUISTIC_26(BaseStrategy):
    """
    Tit-for-Threshold (TfT-Threshold) Strategy:
    Prioritizes the threshold (m) cooperation while defending against defection.
    - Round 1: Always Cooperate.
    - If threshold (m) met in previous round: Cooperate.
    - If threshold not met in previous round: Defect.
    - Exception (Recovery Kickstart): If threshold was missed by exactly 1 and 
      the player defected previously, flip a coin (50%) to attempt recovery.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        my_prev_coop = 1 if my_prev_action else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + my_prev_coop
        m = self.game_description.m
        if total_cooperators_prev >= m:
            return Action.C
        if total_cooperators_prev == m - 1 and (not my_prev_action):
            if random.random() < 0.5:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_ALTRUISTIC_27(BaseStrategy):
    """
    Implements a Tit-for-Tat with a Threshold strategy.
    
    Strategy logic:
    1. Always cooperates in the first round.
    2. Maintains cooperation if the group threshold was met in the previous round.
    3. If the group narrowly failed the threshold (m-1), remains cooperative to encourage success.
    4. If the group failed significantly, defaults to defection, while probing for cooperation every 3 rounds.
    5. In the final round, makes a terminal decision based on whether the game history suggests potential success.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        current_round = history.round_number
        if current_round == self.r - 1:
            total_history_coop = np.sum(history.opponent_cooperators)
            avg_coop = total_history_coop / current_round
            if avg_coop < self.m:
                return Action.D
            else:
                return Action.C
        c_prev = history.opponent_cooperators[-1]
        if c_prev >= self.m:
            return Action.C
        if c_prev >= self.m - 1:
            return Action.C
        if current_round % 3 == 0:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_28(BaseStrategy):
    """
    Implements a Conditional Tit-for-Tat with Threshold Maintenance strategy.
    
    Logic:
    - Round 1: Always Cooperate.
    - Rounds t in [2, r-1]: Cooperate if the previous round had at least (m-1) cooperators.
    - Final Round: Cooperate only if the group historically met the threshold (>=m cooperators) 
      in the majority of previous rounds. Otherwise, Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        is_final_round = history.round_number == self.total_rounds - 1
        prev_cooperators = history.opponent_cooperators[-1]
        if not is_final_round:
            if prev_cooperators >= self.m - 1:
                return Action.C
            else:
                return Action.D
        else:
            successes = np.sum(history.opponent_cooperators >= self.m)
            if successes > history.round_number / 2:
                return Action.C
            else:
                return Action.D

class Strategy_ALTRUISTIC_29(BaseStrategy):
    """
    Threshold-Triggered Tit-for-Tat (TTTT) strategy for Collective Risk Dilemma.
    
    Logic:
    - Round 1: Cooperative if m/n <= 0.5, else defaults to cooperation.
    - Adaptive Phase (Rounds 2 to r-1): 
        - Rewards cooperation if the threshold was met.
        - Protects resources if the threshold was missed.
        - Includes a probabilistic 'test' if the group missed the threshold by exactly one.
    - Terminal Phase (Round r): Focuses on meeting the threshold if reachable.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        last_my_action = int(history.my_actions[-1])
        last_opp_coop = history.opponent_cooperators[-1]
        last_C = last_opp_coop + last_my_action
        if t == self.r - 1:
            if last_C >= self.m - 1:
                return Action.C
            return Action.D
        threshold_target = self.m - last_my_action
        if last_C >= threshold_target:
            return Action.C
        else:
            if last_C == self.m - 1 and last_my_action == 1:
                return Action.C if random.random() < 0.5 else Action.D
            return Action.D

class Strategy_ALTRUISTIC_30(BaseStrategy):
    """
    Altruistic Threshold Strategy:
    - Round 1: Cooperate.
    - Rounds 2 to r-1: Conditional reciprocity based on threshold m.
        - If I cooperated in t-1: Cooperate if C_{t-1} >= m, else Defect.
        - If I defected in t-1: Cooperate if C_{t-1} >= m, else Defect.
    - Final Round: Cooperate if average cooperators in r-1 rounds >= m - 1, else Defect.
    - Leniency: Every 5 rounds, force Cooperate to break deadlocks.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.n = game_description.n_players

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if (current_round + 1) % 5 == 0:
            return Action.C
        if current_round == 0:
            return Action.C
        if current_round == self.r - 1:
            my_actions_int = history.my_actions.astype(int)
            total_cooperators_per_round = history.opponent_cooperators + my_actions_int
            avg_coop = np.mean(total_cooperators_per_round)
            if avg_coop >= self.m - 1:
                return Action.C
            return Action.D
        prev = current_round - 1
        my_prev_action = int(history.my_actions[prev])
        c_prev = history.opponent_cooperators[prev] + my_prev_action
        if my_prev_action == 1:
            if c_prev >= self.m:
                return Action.C
            else:
                return Action.D
        elif c_prev >= self.m:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_31(BaseStrategy):
    """
    A conditional threshold-trigger strategy for the Collective Risk Dilemma.
    It promotes mutual cooperation but reacts to non-cooperative groups by 
    calculating historical surplus, detecting persistent failure, and 
    adjusting behavior based on exploitation risk.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.is_permanently_defected = False

    def __call__(self, history: PlayerHistory) -> Action:
        if self.is_permanently_defected:
            return Action.D
        round_num = history.round_number
        if round_num == 0:
            return Action.C
        prev_idx = -1
        prev_coop_count = history.opponent_cooperators[prev_idx] + (1 if history.my_actions[prev_idx] else 0)
        prev_met_threshold = prev_coop_count >= self.desc.m
        if round_num >= 3:
            recent_coops = [history.opponent_cooperators[i] + (1 if history.my_actions[i] else 0) for i in range(-3, 0)]
            my_coops = [history.my_actions[i] for i in range(-3, 0)]
            if all((c < self.desc.m for c in recent_coops)) and all(my_coops):
                self.is_permanently_defected = True
                return Action.D
        if round_num >= 2:
            recent_coops = [history.opponent_cooperators[i] + (1 if history.my_actions[i] else 0) for i in range(-2, 0)]
            if all((c < self.desc.m - 1 for c in recent_coops)):
                self.is_permanently_defected = True
                return Action.D
        if prev_met_threshold:
            return Action.C
        else:
            if round_num == 1:
                return Action.C
            all_my_actions = history.my_actions
            total_coop_rounds = np.sum(all_my_actions)
            total_def_rounds = len(all_my_actions) - total_coop_rounds
            if total_coop_rounds > total_def_rounds:
                return Action.D
            else:
                if not history.my_actions[-1]:
                    return Action.C
                return Action.D
        if round_num == self.desc.n_rounds - 1:
            coop_indices = np.where(history.my_actions == True)[0]
            if len(coop_indices) == 0:
                return Action.C
            exploitation_events = 0
            for idx in coop_indices:
                total_c = history.opponent_cooperators[idx] + 1
                if total_c < self.desc.m:
                    exploitation_events += 1
            if exploitation_events / len(coop_indices) > 0.5:
                return Action.D
            else:
                return Action.C
        return Action.C

class Strategy_ALTRUISTIC_32(BaseStrategy):
    """
    Implements a Conditional Threshold Altruism strategy.
    
    Logic:
    - Round 1: Always Cooperate.
    - Intermediate Rounds:
        - If group successful (C_observed >= m), maintain cooperation.
        - If group failing, Defect to signal necessity for change (or preserve resources).
        - Tracks persistent failure (3 rounds < m) to switch to aggressive defecting.
    - Terminal Round: Altruistic push if success is mathematically plausible (C_observed >= m-1).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            self.consecutive_failures = 0
            return Action.C
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        my_last_action_bool = bool(history.my_actions[-1])
        my_last_contrib = 1 if my_last_action_bool else 0
        c_observed = history.opponent_cooperators[-1] + my_last_contrib
        if c_observed < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if current_round == r - 1:
            if c_observed >= m - 1:
                return Action.C
            else:
                return Action.D
        if self.consecutive_failures >= 3:
            return Action.D
        if c_observed >= m:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_5(BaseStrategy):
    """
    A conditional-cooperation strategy for the Collective Risk Dilemma.
    
    Logic:
    - Round 0: Always Cooperate (C) to establish baseline.
    - Final Round (r-1): Cooperate if previous round threshold was nearly met (>= m-1), otherwise Defect (D).
    - Intermediate Rounds:
        - If previous round met threshold (>= m): Cooperate (C).
        - If previous round failed (< m): Defect (D) to observe self-correction.
        - Exploitation check: If previous payoff was consistently lower than potential 
          defector payoff (approx. 1 + k), Defect (D) to force redistribution.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.k = game_description.k
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        current_r = history.round_number
        last_r = current_r - 1
        if current_r == self.r - 1:
            if history.opponent_cooperators[last_r] >= self.m - 1:
                return Action.C
            else:
                return Action.D
        n_c_last = history.opponent_cooperators[last_r]
        my_c_last = bool(history.my_actions[last_r])
        total_c_last = (1 if my_c_last else 0) + n_c_last
        if n_c_last >= self.m:
            if my_c_last and history.my_payoffs[last_r] < 1.0:
                return Action.D
            return Action.C
        if n_c_last < self.m:
            return Action.D
        return Action.C

class Strategy_BENEVOLENT_6(BaseStrategy):
    """
    Implements a Tit-for-Tat variant with conditional threshold target.
    
    Logic:
    1. First round: Always Cooperate.
    2. Subsequent rounds:
       - If the previous round's total cooperators (C_prev) >= m:
         - If C_prev > m, probabilistically play D or C to optimize contribution.
         - If C_prev == m, continue C.
       - If C_prev < m:
         - If gap is 1 (C_prev == m - 1), attempt to bridge the gap with C.
         - Otherwise, Defect (D).
    3. Terminal round:
       - If C_prev >= m, play C to ensure success.
       - Otherwise, play D.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_my_action = history.my_actions[-1]
        prev_opp_count = history.opponent_cooperators[-1]
        total_prev_cooperators = int(prev_my_action) + prev_opp_count
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == r - 1:
            if total_prev_cooperators >= m:
                return Action.C
            else:
                return Action.D
        if total_prev_cooperators >= m:
            if total_prev_cooperators > m:
                prob_defect = (total_prev_cooperators - m) / total_prev_cooperators
                if random.random() < prob_defect:
                    return Action.D
                return Action.C
            return Action.C
        elif total_prev_cooperators == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_7(BaseStrategy):
    """
    Conditional Threshold-Reciprocity (CTR)
    Prioritizes the achievement of threshold m by signaling commitment early and
    maintaining cooperation as long as there is evidence of collective effort.
    Resets to cooperation after a punishment phase.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k
        self.defection_threshold = 2
        self.consecutive_failures = 0
        self.last_action = Action.C

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            self.last_action = Action.C
            self.consecutive_failures = 0
            return Action.C
        my_prev_action = history.my_actions[-1]
        opp_prev_coop = history.opponent_cooperators[-1]
        total_cooperators_prev = opp_prev_coop + (1 if my_prev_action else 0)
        if total_cooperators_prev < self.m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if history.round_number == self.n_rounds - 1:
            self.last_action = Action.D
            return Action.D
        if total_cooperators_prev >= self.m:
            self.last_action = Action.C
            return Action.C
        if self.consecutive_failures >= self.defection_threshold:
            if self.last_action == Action.D:
                self.last_action = Action.C
                return Action.C
            else:
                self.last_action = Action.D
                return Action.D
        self.last_action = Action.C
        return Action.C

class Strategy_BENEVOLENT_8(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that initializes with cooperation 
    and maintains a threshold-based adaptive response. It attempts to lead 
    cooperation, uses a 'Benevolent Buffer' to verify group reliability, 
    and incorporates a cycle-reset mechanism if the group fails.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.threshold = float(self.game_description.m)

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        current_round = history.round_number + 1
        last_round_cooperators = int(history.opponent_cooperators[-1])
        my_last_action = Action.C if history.my_actions[-1] else Action.D
        total_cooperators = last_round_cooperators + (1 if my_last_action == Action.C else 0)
        if current_round == self.game_description.n_rounds:
            if total_cooperators >= self.game_description.m:
                return Action.C
            else:
                return Action.D
        if total_cooperators >= self.threshold:
            return Action.C
        elif total_cooperators < self.game_description.m:
            self.threshold = float(self.game_description.m)
            return Action.D
        else:
            self.threshold = float(self.game_description.m + 1)
            return Action.C

class Strategy_BENEVOLENT_9(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that initiates cooperation,
    maintains cooperation if the group threshold is met, defaults to defection
    if the threshold is missed to minimize loss, and attempts to recover or 
    signal coordination in the final round based on historical success.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        last_round_idx = history.round_number - 1
        my_last_action = history.my_actions[last_round_idx]
        total_prev_cooperators = history.opponent_cooperators[last_round_idx] + (1 if my_last_action else 0)
        if total_prev_cooperators >= self.m:
            return Action.C
        if history.round_number == self.r - 1:
            rounds_passed = history.round_number
            threshold_met_count = 0
            has_contributed_ever = False
            for t in range(rounds_passed):
                if history.my_actions[t]:
                    has_contributed_ever = True
                opp_c = history.opponent_cooperators[t]
                my_c = 1 if history.my_actions[t] else 0
                if opp_c + my_c >= self.m:
                    threshold_met_count += 1
            threshold_missed_count = rounds_passed - threshold_met_count
            is_unstable = threshold_missed_count / rounds_passed >= 0.5
            if is_unstable:
                return Action.D
            if has_contributed_ever:
                return Action.C
            return Action.D
        return Action.D

class Strategy_BENEVOLENT_10(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that balances threshold coordination,
    benevolence buffering, and adaptive Tit-for-Tat responses to exploitation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.exploitation_trend = 0

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round > 0:
            last_my_action = 1 if history.my_actions[-1] else 0
            h_prev = history.opponent_cooperators[-1] + last_my_action
            if h_prev >= self.m:
                defectors = self.n - h_prev
                if defectors > 0:
                    self.exploitation_trend += 1
                else:
                    self.exploitation_trend = max(0, self.exploitation_trend - 1)
        if current_round == 0:
            return Action.C
        if self.exploitation_trend > 3:
            if h_prev < self.m:
                return Action.D
            return Action.C
        if current_round == self.r - 1:
            all_h = []
            for i in range(current_round):
                my_act = 1 if history.my_actions[i] else 0
                all_h.append(history.opponent_cooperators[i] + my_act)
            avg_h = sum(all_h) / len(all_h) if all_h else 0
            if avg_h >= self.m:
                return Action.C
            current_total_payoff = np.sum(history.my_payoffs)
            if current_total_payoff < self.r * 0.5:
                return Action.C
            return Action.D
        if h_prev >= self.m:
            return Action.C
        else:
            b_buffer = (self.m - h_prev) / self.n
            if random.random() < 1.0 - b_buffer:
                return Action.C
            return Action.D

class Strategy_BENEVOLENT_11(BaseStrategy):
    """
    Threshold-Adaptive Reciprocity Strategy:
    - Round 0: Always cooperate (Action.C).
    - Rounds > 0: 
        - If previous round's total cooperation (including self) met threshold m, continue cooperating.
        - If previous round's cooperation failed (total < m), reassess:
            - If (prev_cooperators + 1) >= m: Re-engage (cooperate) to help reach threshold.
            - Otherwise: Abstain (defect) to save endowment.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_opponents_c = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        my_prev_c = 1 if my_prev_action else 0
        total_prev_c = prev_opponents_c + my_prev_c
        if total_prev_c >= self.m:
            return Action.C
        if prev_opponents_c + 1 >= self.m:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_12(BaseStrategy):
    """
    A conditional, threshold-based cooperation strategy designed for the Collective Risk Dilemma.
    It initiates with cooperation, adapts thresholds based on recent performance, employs a
    "forgiveness" mechanism for near-misses, and switches to defection if consistently exploited.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.S_t = self.m
        self.sucker_trap_activated = False
        self.consecutive_success = 0
        self.consecutive_failure = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        t = history.round_number
        prev_cooperators = history.opponent_cooperators[-1]
        if t == self.r - 1:
            if prev_cooperators >= self.m:
                return Action.C
            return Action.D
        if prev_cooperators >= self.m:
            self.consecutive_success += 1
            self.consecutive_failure = 0
        elif prev_cooperators < self.m - 1:
            self.consecutive_failure += 1
            self.consecutive_success = 0
        else:
            self.consecutive_success = 0
            self.consecutive_failure = 0
        if self.consecutive_success >= 2 and self.S_t > self.m:
            self.S_t -= 1
        elif self.consecutive_failure >= 2 and self.S_t < self.n:
            self.S_t += 1
        if t > 5:
            recent_performance = history.opponent_cooperators[-5:]
            if all((c < self.m for c in recent_performance)):
                self.sucker_trap_activated = True
        if self.sucker_trap_activated:
            if t % 3 == 0:
                return Action.C
            return Action.D
        if prev_cooperators >= self.S_t:
            return Action.C
        if prev_cooperators == self.S_t - 1:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_13(BaseStrategy):
    """
    Implements a Conditional Trigger-Threshold strategy for the Collective Risk Dilemma.
    Prioritizes reciprocity and target-attainment. 
    - Round 1: Cooperate.
    - Subsequent Rounds:
        - If previous count >= m: Repeat previous action (Stability).
        - If previous count == m-1: Cooperate (Pivot player logic).
        - If previous count < m-1: Defect (Conservation).
        - Last Round special case: If previous count >= m-1, Cooperate to secure reward.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_round_idx = history.round_number - 1
        my_prev_action_bool = history.my_actions[prev_round_idx]
        opponent_count = history.opponent_cooperators[prev_round_idx]
        prev_c_count = opponent_count + (1 if my_prev_action_bool else 0)
        if history.round_number == self.r - 1:
            if prev_c_count >= self.m - 1:
                return Action.C
            else:
                return Action.D
        if prev_c_count >= self.m:
            return Action.C if my_prev_action_bool else Action.D
        if prev_c_count == self.m - 1:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_14(BaseStrategy):
    """
    Implements a phase-based strategy for the Collective Risk Dilemma:
    - Phase 1 (First half): Tit-for-tat like behavior, establishing cooperation.
    - Phase 2 (Second half): "Critical nudge" strategy to ensure threshold compliance,
      with specific reset and benevolence triggers.
    - Phase 3 (Final round): Aggressive cooperation if the group is viable.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.failure_counter = 0
        self.success_counter = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.desc.n_players
        m = self.desc.m
        total_rounds = self.desc.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        my_prev_action = 1 if history.my_actions[-1] else 0
        n_c_prev = history.opponent_cooperators[-1] + my_prev_action
        if n_c_prev < m:
            self.failure_counter += 1
            self.success_counter = 0
        else:
            self.failure_counter = 0
            self.success_counter += 1
        if current_round == total_rounds - 1:
            return Action.C if n_c_prev >= m - 1 else Action.D
        if self.failure_counter > 2:
            return Action.D
        if self.success_counter >= 2:
            return Action.C
        if current_round < total_rounds // 2:
            return Action.C if n_c_prev >= m - 1 else Action.D
        if n_c_prev >= m:
            return Action.C
        if n_c_prev == m - 1:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_15(BaseStrategy):
    """
    Implements a sophisticated adaptive strategy for the Collective Risk Dilemma:
    - Round 1: Always Cooperate (C).
    - Rounds 2 to r-1:
        - If C_{t-1} >= m: Maintain current action, unless C_{t-1} == m, then C.
        - If C_{t-1} < m: If C in t-1, switch to D. If D in t-1, try rebound with prob P_rebound.
        - Adaptive Adjustment: If C_{t-1} > m, reduce C probability by factor m/C_{t-1}.
        - Reset mechanism: If C_{t-1} < m for 3 consecutive rounds, reset to C once.
    - Terminal Phase: C if moving avg of cooperators over last 3 rounds >= m-1, else D.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failure_count = 0
        self.force_cooperate_reset = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        prev_cooperators = history.opponent_cooperators[-1] + (1 if history.my_actions[-1] else 0)
        did_contribute_prev = history.my_actions[-1]
        if prev_cooperators < m:
            self.consecutive_failure_count += 1
        else:
            self.consecutive_failure_count = 0
        if current_round == r - 1:
            lookback = min(3, current_round)
            recent_coop_counts = []
            for i in range(1, lookback + 1):
                opps = history.opponent_cooperators[-i]
                me = 1 if history.my_actions[-i] else 0
                recent_coop_counts.append(opps + me)
            avg_coop = sum(recent_coop_counts) / len(recent_coop_counts)
            return Action.C if avg_coop >= m - 1 else Action.D
        if self.consecutive_failure_count >= 3:
            self.force_cooperate_reset = True
            self.consecutive_failure_count = 0
            return Action.C
        if self.force_cooperate_reset:
            self.force_cooperate_reset = False
            return Action.C
        action_to_take = Action.D
        if prev_cooperators >= m:
            if prev_cooperators == m:
                action_to_take = Action.C
            else:
                action_to_take = Action.C if did_contribute_prev else Action.D
            if prev_cooperators > m and action_to_take == Action.C:
                prob = m / prev_cooperators
                if random.random() > prob:
                    action_to_take = Action.D
        elif did_contribute_prev:
            action_to_take = Action.D
        else:
            denominator = n - prev_cooperators
            if denominator > 0:
                prob_rebound = (m - prev_cooperators) / denominator
                if random.random() < prob_rebound:
                    action_to_take = Action.C
                else:
                    action_to_take = Action.D
            else:
                action_to_take = Action.D
        return action_to_take

class Strategy_BENEVOLENT_16(BaseStrategy):
    """
    Implements a sophisticated strategy for the Collective Risk Dilemma:
    - Round 1: Cooperate.
    - Threshold Enforcement: If C_{t-1} < m, cooperate. If C_{t-1} >= m, defect to test stability (except in last round).
    - Adaptive Reciprocity: If previous round was a defect AND threshold was missed, immediately cooperate.
    - Last Round: If collective success prioritized, cooperate if C_{t-1} < m + 1. If individual return maximized, defect if C_{t-1} > m else cooperate.
    - Edge Case Recovery: If threshold missed in two consecutive rounds, cooperate until threshold met again.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_last_action_int = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + my_last_action_int
        if history.round_number >= 2:
            prev_opp_coop = history.opponent_cooperators[-2]
            prev_my_action = 1 if history.my_actions[-2] else 0
            total_cooperators_prev_prev = prev_opp_coop + prev_my_action
            if total_cooperators_prev < self.m and total_cooperators_prev_prev < self.m:
                return Action.C
        if not history.my_actions[-1] and total_cooperators_prev < self.m:
            return Action.C
        if history.round_number == self.r - 1:
            if total_cooperators_prev < self.m + 1:
                return Action.C
            else:
                return Action.D if total_cooperators_prev > self.m else Action.C
        if total_cooperators_prev < self.m:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_17(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that employs a trust-building phase,
    threshold enforcement, and conditional defection based on historical group cooperation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        last_round_idx = history.round_number - 1
        my_last_action = int(history.my_actions[last_round_idx])
        c_last = history.opponent_cooperators[last_round_idx] + my_last_action
        my_past_actions = history.my_actions.astype(int)
        all_past_c = history.opponent_cooperators + my_past_actions
        avg_c = np.mean(all_past_c)
        current_round = history.round_number + 1
        half_rounds = math.ceil(self.r / 2)
        m_minus_one = self.m - 1
        if current_round <= half_rounds:
            if avg_c >= m_minus_one:
                return Action.C
        if c_last >= m_minus_one:
            return Action.C
        if current_round == self.r:
            if avg_c >= m_minus_one:
                return Action.C
            else:
                return Action.D
        if avg_c < m_minus_one:
            return Action.D
        if current_round > half_rounds and c_last < m_minus_one:
            return Action.D
        return Action.D

class Strategy_BENEVOLENT_18(BaseStrategy):
    """
    Implements a Collective Risk Dilemma strategy with adaptive response based on threshold proximity
    and previous cooperation levels.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.p_switch = 0.5

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        m = self.game_description.m
        total_rounds = self.game_description.n_rounds
        current_round = history.round_number + 1
        prev_my_action = history.my_actions[-1]
        prev_opponent_coops = history.opponent_cooperators[-1]
        c_prev = prev_opponent_coops + (1 if prev_my_action else 0)
        if current_round == total_rounds:
            threshold_achieved_history = False
            for i in range(len(history.my_actions)):
                opp_c = history.opponent_cooperators[i]
                my_c = 1 if history.my_actions[i] else 0
                if opp_c + my_c >= m:
                    threshold_achieved_history = True
                    break
            return Action.C if threshold_achieved_history else Action.D
        if c_prev == m - 1:
            return Action.C
        if prev_my_action:
            if c_prev >= m:
                return Action.C
            elif random.random() < self.p_switch:
                return Action.D
            else:
                return Action.C
        elif c_prev >= m:
            return Action.D
        else:
            return Action.C

class Strategy_BENEVOLENT_19(BaseStrategy):
    """
    A strategy that maintains cooperation as long as the group is close to the threshold 'm'.
    - Round 1: Always Cooperate.
    - Subsequent rounds:
        - If the previous round had >= m cooperators: Cooperate.
        - If the previous round had >= m-1 cooperators: Cooperate (attempting to bridge the gap).
        - Otherwise: Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        opponents_cooperating = history.opponent_cooperators[-1]
        c_prev = opponents_cooperating + (1 if my_prev_action == Action.C else 0)
        if c_prev >= self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_20(BaseStrategy):
    """
    Implements a threshold-conditional trigger mechanism strategy for the Collective Risk Dilemma.
    - Round 1: Always Cooperate.
    - Subsequent rounds:
        - If previous round cooperation >= m, Cooperate.
        - If previous round cooperation == m - 1 (near-miss), Cooperate.
        - Terminal round (last round): If historical average cooperation >= m/n, Cooperate.
        - Default: Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.m
        my_prev_action = 1 if history.my_actions[-1] else 0
        total_prev_cooperators = history.opponent_cooperators[-1] + my_prev_action
        if total_prev_cooperators >= m:
            return Action.C
        if total_prev_cooperators >= m - 1:
            return Action.C
        if history.round_number == self.r - 1:
            all_opponents_coop = history.opponent_cooperators
            my_coop_actions = history.my_actions.astype(int)
            total_coop_per_round = all_opponents_coop + my_coop_actions
            avg_coop = np.mean(total_coop_per_round / self.n)
            if avg_coop >= m / self.n:
                return Action.C
        return Action.D

class Strategy_BENEVOLENT_21(BaseStrategy):
    """
    Implements Conditional Tit-for-Tat Thresholding for the Collective Risk Dilemma.
    
    Strategy:
    - Round 1: Always Cooperate.
    - Rounds 2 to r-1: 
        - Cooperate if the group threshold m was met in the previous round (N_{t-1} >= m).
        - Otherwise, Defect.
        - Adaptive Buffer: If 0 cooperators for 3 consecutive rounds, reset and Cooperate.
    - Terminal Round: Always Cooperate.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == 0:
            return Action.C
        if current_round == total_rounds - 1:
            return Action.C
        prev_cooperators = history.opponent_cooperators
        if current_round >= 3:
            last_three = prev_cooperators[-3:]
            if all((n == 0 for n in last_three)):
                return Action.C
        my_prev_action_int = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = prev_cooperators[-1] + my_prev_action_int
        if total_cooperators_prev >= m:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_22(BaseStrategy):
    """
    Conditional Reciprocal Threshold Cooperation:
    - Round 1: Cooperate.
    - Subsequent rounds:
        - If previous round total cooperators >= m: Cooperate (Secure reward k).
        - If previous round total cooperators < m: Defect (Avoid personal loss).
        - Test Mode: In the round immediately following a failure (< m), attempt C with probability 0.5 
          to probe for cooperative resurgence.
    - Final round: Always Cooperate (Maximize collective utility).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.in_test_mode = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        my_prev_coop = 1 if my_prev_action else 0
        total_cooperators = prev_cooperators + my_prev_coop
        if total_cooperators < self.game_description.m:
            self.in_test_mode = True
            if random.random() < 0.5:
                return Action.C
            else:
                return Action.D
        else:
            self.in_test_mode = False
            return Action.C

class Strategy_BENEVOLENT_23(BaseStrategy):
    """
    Implements a conditional cooperative strategy for the Collective Risk Dilemma.
    Focuses on maintaining the threshold m, exploiting D when safe, punishing 
    non-cooperation, and evaluating long-term trends for the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.consecutive_single_coop_rounds = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if self.desc.m == 1:
            return Action.D
        n = self.desc.n_players
        m = self.desc.m
        r_total = self.desc.n_rounds
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        prev_round = round_idx - 1
        my_prev_action = history.my_actions[prev_round]
        my_c = 1 if my_prev_action else 0
        total_c = my_c + history.opponent_cooperators[prev_round]
        if my_prev_action is True and total_c == 1:
            self.consecutive_single_coop_rounds += 1
        else:
            self.consecutive_single_coop_rounds = 0
        if self.consecutive_single_coop_rounds >= 3:
            return Action.D
        if round_idx == r_total - 1:
            if round_idx > 0:
                all_prev_coop_counts = []
                for i in range(round_idx):
                    c = (1 if history.my_actions[i] else 0) + history.opponent_cooperators[i]
                    all_prev_coop_counts.append(c)
                avg_rate = sum(all_prev_coop_counts) / (n * round_idx)
                if avg_rate >= m / n:
                    return Action.C
                failed_rounds = sum((1 for c in all_prev_coop_counts if c < m))
                if failed_rounds / round_idx > 0.5:
                    return Action.D
            return Action.C
        if total_c >= m:
            if my_prev_action is True and total_c == m:
                return Action.C
            if my_prev_action is False and total_c == m:
                return Action.D
            if total_c > m:
                return Action.D
            if total_c <= m - 1:
                return Action.C
        else:
            return Action.C
        return Action.C

class Strategy_BENEVOLENT_24(BaseStrategy):
    """
    A conditional probabilistic threshold strategy for the Collective Risk Dilemma.
    Adjusts cooperation based on previous round success (C_t-1) relative to threshold (m),
    with specific adjustments for the final two rounds.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C if random.random() < 0.8 else Action.D
        prev_cooperators = history.opponent_cooperators[-1]
        if history.round_number >= self.r - 2:
            lookback = max(1, self.r // 2)
            past_coops = history.opponent_cooperators[-lookback:]
            avg_coops = np.mean(past_coops)
            if avg_coops < self.m - 1:
                return Action.D
            return self._decide_with_prob(prev_cooperators, adjustment=-0.2)
        return self._decide_with_prob(prev_cooperators, adjustment=0.0)

    def _decide_with_prob(self, prev_cooperators: int, adjustment: float) -> Action:
        """Determines action based on threshold logic and provided probability adjustment."""
        if prev_cooperators >= self.m:
            prob = 0.9
        elif prev_cooperators == self.m - 1:
            prob = 1.0
        else:
            prob = 0.2
        final_prob = max(0.0, min(1.0, prob + adjustment))
        return Action.C if random.random() < final_prob else Action.D

class Strategy_BENEVOLENT_25(BaseStrategy):
    """
    Implements the 'Conditional Threshold Commitment' strategy.
    
    Logic:
    1. Phase 1 (First 2 rounds): Always Cooperate (C).
    2. Phase 2 (Rounds 3 to r-1): 
       - Check if the previous round met the threshold 'm'. If so, cooperate (Forgiveness).
       - Otherwise, calculate historical average participation of opponents.
       - Cooperate if avg participation >= (m/n), otherwise Defect.
    3. Phase 3 (Final round): Copy the action from round r-1.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.threshold_ratio = self.m / self.n

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round < 2:
            return Action.C
        if current_round == self.r - 1:
            last_action_was_c = bool(history.my_actions[-1])
            return Action.C if last_action_was_c else Action.D
        last_round_idx = current_round - 1
        opponents_cooped = history.opponent_cooperators[last_round_idx]
        my_last_action = bool(history.my_actions[last_round_idx])
        total_cooperators_last = opponents_cooped + (1 if my_last_action else 0)
        if total_cooperators_last >= self.m:
            return Action.C
        total_opponent_coops = np.sum(history.opponent_cooperators)
        num_opponents = self.n - 1
        avg_participation = total_opponent_coops / (num_opponents * current_round)
        if avg_participation >= self.threshold_ratio:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_26(BaseStrategy):
    """
    Implements Conditional Reciprocal Contribution:
    - Round 1: Cooperate.
    - Rounds 1 < t < r:
        - If previous cooperation (Nc) >= m: Cooperate.
        - If Nc < m:
            - If previously played C: Defect.
            - If previously played D: Cooperate with probability p = m/n.
        - Includes volatility buffer (threshold logic).
    - Terminal round logic (t >= r-3):
        - Strict "Tit-for-Tat": Cooperate if Nc >= m, else Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.desc.n_players
        m = self.desc.m
        r = self.desc.n_rounds
        t = history.round_number
        last_my_action = history.my_actions[-1]
        nc_others = history.opponent_cooperators[-1]
        nc_total = nc_others + (1 if last_my_action else 0)
        is_high_cooperation_stable = False
        if t >= 2:
            prev_nc_others = history.opponent_cooperators[-2]
            prev_my_action = history.my_actions[-2]
            prev_nc_total = prev_nc_others + (1 if prev_my_action else 0)
            if nc_total == n and prev_nc_total == n:
                is_high_cooperation_stable = True
        if t >= r - 3:
            if nc_total >= m:
                return Action.C
            return Action.D
        if is_high_cooperation_stable:
            return Action.C
        buffer = math.floor(n / m)
        if nc_total < m - buffer:
            pass
        if nc_total >= m:
            return Action.C
        elif last_my_action:
            return Action.D
        else:
            p = m / n
            if random.random() < p:
                return Action.C
            return Action.D

class Strategy_BENEVOLENT_27(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that prioritizes threshold maintenance (m)
    while implementing adaptive defection for monitoring, surplus exploitation avoidance,
    and threshold failure signaling.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0
        self.in_reset_mode = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        k = self.game_description.k
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C if k > 1 else Action.D
        last_my_action = 1 if history.my_actions[-1] else 0
        last_total_c = history.opponent_cooperators[-1] + last_my_action
        if current_round == r - 1:
            all_total_c = history.opponent_cooperators + history.my_actions.astype(int)
            avg_c = np.mean(all_total_c)
            if avg_c >= m:
                return Action.C
            else:
                return Action.D
        if last_total_c < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
            self.in_reset_mode = False
        if self.consecutive_failures >= 3:
            if not self.in_reset_mode:
                self.in_reset_mode = True
                return Action.D
            else:
                self.in_reset_mode = False
                self.consecutive_failures = 0
                return Action.C
        if last_total_c < m and last_my_action == 0:
            if history.round_number >= 2 and history.opponent_cooperators[-2] + (1 if history.my_actions[-2] else 0) == m:
                return Action.C
        if last_total_c >= m:
            if last_total_c > m + 1:
                return Action.D
            return Action.C
        else:
            return Action.C

class Strategy_BENEVOLENT_28(BaseStrategy):
    """
    Implements a Threshold-Triggered Tit-for-Tat strategy with Gradual Forgiveness.
    
    Logic:
    - Round 1: Always Cooperate.
    - End-Game (last 3 rounds): Cooperate if previous cooperators >= m-1, else Defect.
    - Standard Rounds (t > 1):
        - Cooperate if threshold m was met in previous round.
        - If threshold was NOT met, play Defect with probability (1 - prev_cooperators / m) 
          to punish free-riding while allowing gradual recovery.
        - Includes logic to check for "Forgiveness" (reverting to Cooperation if the
          group showed improvement).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self._last_observed_cooperators = None

    def __call__(self, history: PlayerHistory) -> Action:
        m = self.game_description.m
        total_rounds = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            self._last_observed_cooperators = 0
            return Action.C
        last_opponent_coops = history.opponent_cooperators[-1]
        my_last_action = int(history.my_actions[-1])
        total_prev_cooperators = last_opponent_coops + my_last_action
        previous_cooperators = self._last_observed_cooperators
        self._last_observed_cooperators = total_prev_cooperators
        if current_round >= total_rounds - 3:
            if total_prev_cooperators >= m - 1:
                return Action.C
            else:
                return Action.D
        if total_prev_cooperators >= m:
            return Action.C
        if total_prev_cooperators > previous_cooperators:
            return Action.C
        probability_to_defect = max(0.0, 1.0 - total_prev_cooperators / m)
        if random.random() < probability_to_defect:
            return Action.D
        return Action.C

class Strategy_BENEVOLENT_29(BaseStrategy):
    """
    Implements a Conditional Threshold Tit-for-Tat strategy.
    
    1. Always cooperates in the first round.
    2. In final round, cooperates only if the threshold was met in >= 50% of previous rounds.
    3. In intermediate rounds:
       - If threshold was met in the previous round, continues cooperating.
       - If threshold was not met, attempts to bridge the gap if contributing makes the difference.
       - Otherwise, defects to punish/conserve endowment.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        round_idx = history.round_number
        n_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if round_idx == 0:
            return Action.C
        if round_idx == n_rounds - 1:
            total_cooperators = history.opponent_cooperators + history.my_actions.astype(int)
            success_count = np.sum(total_cooperators >= m)
            if success_count >= n_rounds / 2.0:
                return Action.C
            return Action.D
        last_my_action = history.my_actions[-1]
        last_opponent_coops = history.opponent_cooperators[-1]
        total_cooperators_last = last_opponent_coops + (1 if last_my_action else 0)
        if total_cooperators_last >= m:
            return Action.C
        if last_opponent_coops + 1 >= m:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_30(BaseStrategy):
    """
    Implements Threshold Reciprocity with Opportunistic Safeguards.
    
    Strategy Rules:
    - Round 1: Always Cooperate.
    - Last Round: Always Cooperate.
    - Intermediate Rounds:
        - If total cooperators in previous round >= m: Cooperate.
        - If total cooperators < m:
            - If I cooperated in previous round: Defect (punishment/safeguard).
            - If I defected in previous round: Cooperate (probing).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == 0:
            return Action.C
        if current_round == n_rounds - 1:
            return Action.C
        my_last_action = history.my_actions[-1]
        my_last_contribution = 1 if my_last_action else 0
        total_cooperators = history.opponent_cooperators[-1] + my_last_contribution
        if total_cooperators >= m:
            return Action.C
        elif my_last_action:
            return Action.D
        else:
            return Action.C

class Strategy_BENEVOLENT_31(BaseStrategy):
    """
    Implements the Threshold-Conditional Reciprocity (TCR) strategy.
    
    It initializes cooperation and maintains a 'Trust Score' based on whether the 
    collective threshold 'm' was met in previous rounds. It oscillates between 
    cooperation (if trust is high) and defection (if trust is low or threshold 
    was missed), with specific logic for the terminal round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.trust_score = game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        last_n_cooperators = history.opponent_cooperators[-1]
        i_cooperated_prev = bool(history.my_actions[-1])
        total_cooperators_prev = last_n_cooperators + (1 if i_cooperated_prev else 0)
        if total_cooperators_prev >= self.game_description.m:
            self.trust_score = min(self.trust_score + 1, self.game_description.n_players)
        else:
            self.trust_score = max(self.trust_score - 1, 0)
        if history.round_number == self.game_description.n_rounds - 1:
            if total_cooperators_prev >= self.game_description.m:
                return Action.C
            else:
                return Action.D
        if self.trust_score >= self.game_description.m:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_32(BaseStrategy):
    """
    Implements a threshold-trigger tit-for-tat strategy.
    
    Logic:
    - Round 1: Always Cooperate.
    - Subsequent rounds:
        - If previous round threshold was met (C_prev >= m), Cooperate.
        - If previous round was missed but close (C_prev >= m-1), Cooperate.
        - Otherwise, Defect.
    - Endgame: 
        - If previous round was Cooperate, play Cooperate.
        - If previous round was Defect, play Defect.
        - Exception: If consistently failed to reach threshold in last ceil(r/4) rounds, play Defect.
    - Edge Cases:
        - If C_prev == 0 for two consecutive rounds, switch to permanent Defection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.state = 'Cooperate'
        self.systemic_failure = False

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        c_prev_total = history.opponent_cooperators[-1] + (1 if my_prev_action else 0)
        m = self.game_description.m
        r_total = self.game_description.n_rounds
        if t >= 2:
            prev_total_minus_1 = history.opponent_cooperators[-2] + (1 if history.my_actions[-2] else 0)
            if c_prev_total == 0 and prev_total_minus_1 == 0:
                self.systemic_failure = True
        if self.systemic_failure:
            return Action.D
        lookback_window = math.ceil(r_total / 4)
        if t >= lookback_window:
            recent_rounds = []
            for i in range(1, lookback_window + 1):
                opp_c = history.opponent_cooperators[-i]
                my_c = 1 if history.my_actions[-i] else 0
                recent_rounds.append(opp_c + my_c)
            if all((c < m for c in recent_rounds)):
                return Action.D
        if t == r_total - 1:
            if self.state == 'Cooperate':
                return Action.C
            else:
                return Action.D
        if c_prev_total >= m:
            self.state = 'Cooperate'
            return Action.C
        elif c_prev_total >= m - 1:
            self.state = 'Cooperate'
            return Action.C
        else:
            self.state = 'Defect'
            return Action.D

class Strategy_SELFISH_5(BaseStrategy):
    """
    Threshold-Sensitive Tit-for-Tat with Defection bias.
    
    Strategy Logic:
    1. First Round (t=1): Defect.
    2. Terminal Round (t=r): Defect.
    3. Intermediate Rounds:
        - If C_total >= m:
            - If C_total == m: Cooperate (maintain threshold).
            - If C_total > m: Defect (exploit).
        - If C_total < m:
            - Cooperate with probability P = (m - C_total) / (n - C_total).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round == self.r - 1:
            return Action.D
        my_prev_action = 1 if history.my_actions[-1] else 0
        c_total = history.opponent_cooperators[-1] + my_prev_action
        if c_total >= self.m:
            if c_total == self.m:
                return Action.C
            else:
                return Action.D
        else:
            denominator = self.n - c_total
            if denominator <= 0:
                return Action.D
            p = (self.m - c_total) / denominator
            if random.random() < p:
                return Action.C
            else:
                return Action.D

class Strategy_SELFISH_6(BaseStrategy):
    """
    Implements a strategic approach to the Collective Risk Dilemma.
    
    Round 1: Always Defect (D).
    
    Final Round (t=r): Always Defect (D).
    
    Intermediate Rounds:
    - If previous round threshold was met (C_{t-1} >= m):
        Always switch to/continue Defect (D).
    - If previous round threshold was not met (C_{t-1} < m):
        - If m_needed == 1 (marginal contribution makes a difference): Play Cooperate (C).
        - Otherwise (m_needed > 1): Play Defect (D).
    
    Edge Case: If k < 1, always Defect (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if self.game_description.k < 1.0:
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.D
        c_prev_total = history.opponent_cooperators[-1]
        my_prev_action = int(history.my_actions[-1])
        c_prev_total_including_me = c_prev_total + my_prev_action
        if c_prev_total_including_me >= self.game_description.m:
            return Action.D
        m_needed = self.game_description.m - c_prev_total
        if m_needed == 1:
            return Action.C
        return Action.D

class Strategy_SELFISH_7(BaseStrategy):
    """
    Implements a conditional Tit-for-Tat strategy for the Collective Risk Dilemma.
    The strategy prioritizes free-riding unless coordination is required to meet the 
    threshold (m), or unless it is the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        m = self.game_description.m
        r = self.game_description.n_rounds
        prev_C = history.opponent_cooperators[-1]
        my_prev_action = Action.C if history.my_actions[-1] else Action.D
        c_prev = 1 if my_prev_action == Action.C else 0
        total_coop_prev = prev_C + c_prev
        is_last_round = current_round == r - 1
        if is_last_round:
            if total_coop_prev >= m:
                return Action.D
            elif total_coop_prev == m - 1:
                return Action.C
            else:
                return Action.D
        if prev_C >= m:
            return Action.D
        if total_coop_prev == m:
            if c_prev == 1:
                return Action.C
            else:
                return Action.D
        if total_coop_prev == m - 1:
            if c_prev == 0:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_SELFISH_8(BaseStrategy):
    """
    Implements Threshold-Sensitive Conditional Reciprocity.
    
    Strategy Logic:
    1. Always Cooperate on the first round to test group responsiveness.
    2. In intermediate rounds:
       - If the threshold m was met in the previous round, Defect (try to free-ride).
       - If the threshold m was missed by exactly 1 in the previous round, Cooperate (bridge the gap).
       - If the threshold m was missed by more than 1, Defect (sunk cost).
    3. In the final round: Always Defect (maximize end-game payoff).
    4. Adaptive Safety (Edge Case): If the strategy identifies it is the sole 'bridge-builder' 
       (the threshold remains at m-1 for 3 consecutive rounds while it cooperates), 
       it ceases cooperation to avoid exploitation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_bridge_attempts = 0

    def __call__(self, history: PlayerHistory) -> Action:
        round_t = history.round_number
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if round_t == 0:
            return Action.C
        if round_t == total_rounds - 1:
            return Action.D
        last_round_i_cooperated = history.my_actions[-1]
        last_round_opponents_c = history.opponent_cooperators[-1]
        total_cooperators_last_round = last_round_opponents_c + (1 if last_round_i_cooperated else 0)
        if total_cooperators_last_round >= m:
            self.consecutive_bridge_attempts = 0
            return Action.D
        if total_cooperators_last_round == m - 1:
            if last_round_i_cooperated:
                self.consecutive_bridge_attempts += 1
            else:
                self.consecutive_bridge_attempts = 0
            if self.consecutive_bridge_attempts >= 3:
                return Action.D
            return Action.C
        self.consecutive_bridge_attempts = 0
        return Action.D

class Strategy_SELFISH_9(BaseStrategy):
    """
    Implements a conditional threshold-tracking strategy for the Collective Risk Dilemma.
    
    The strategy probes cooperation in the first round. In subsequent rounds, it acts
    as a conditional cooperator:
    - If the threshold m was met without self-contribution, it defects to maximize payoff.
    - If the self is the 'tipping point' needed to reach m, it cooperates.
    - If the threshold is unreachable, it defects, with a specific 'retry' logic to 
      re-probe cooperation levels if a previous attempt failed.
    - In the final round, it always defects.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if round_idx == self.desc.n_rounds - 1:
            return Action.D
        c_prev = history.opponent_cooperators[-1]
        m = self.desc.m
        my_last_action = 1 if history.my_actions[-1] else 0
        total_coop_prev = c_prev + my_last_action
        if c_prev >= m:
            return Action.D
        elif c_prev == m - 1:
            return Action.C
        else:
            if len(history.my_actions) > 1:
                prev_my_action = 1 if history.my_actions[-2] else 0
                prev_opp_coop = history.opponent_cooperators[-2]
                if prev_opp_coop == m - 1 and prev_my_action == 1 and (prev_opp_coop + prev_my_action < m):
                    return Action.C
            return Action.D

class Strategy_SELFISH_10(BaseStrategy):
    """
    A strategy that probes for cooperation, attempts to free-ride when the threshold is met,
    tries to rescue the threshold when cooperation is sparse, and defaults to defection
    in the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        my_prev_action = history.my_actions[-1]
        c_opponents = history.opponent_cooperators[-1]
        c_prev = c_opponents + (1 if my_prev_action else 0)
        if history.round_number == r - 1:
            return Action.D
        if c_prev >= m:
            return Action.D
        elif not my_prev_action:
            return Action.C
        elif c_prev == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_11(BaseStrategy):
    """
    Implements the Threshold Conditional Defection (TCD) strategy.
    
    Logic:
    - Initially defects (Round 1).
    - Tracks cooperation propensity (P) as the average number of cooperators observed.
    - If previous round met threshold (m): Defects to exploit.
    - If previous round failed threshold (m):
        - If possible to bridge gap (m - c_{t-1} <= 1) and not the final round, cooperates.
        - Otherwise, defects.
    - If uncooperative (P < 1 for 3 consecutive rounds), defects indefinitely.
    - If "Greedy Equilibrium" (c_{t-1} == m), defects to avoid over-contribution.
    - Always defects in the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_uncooperative_rounds = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        m = self.game_description.m
        t = history.round_number
        if t == 0:
            return Action.D
        my_prev_action = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + my_prev_action
        if total_cooperators_prev < m:
            self.consecutive_uncooperative_rounds += 1
        else:
            self.consecutive_uncooperative_rounds = 0
        if self.consecutive_uncooperative_rounds >= 3:
            return Action.D
        if t == r - 1:
            return Action.D
        project_sufficient = total_cooperators_prev >= m
        if project_sufficient:
            return Action.D
        else:
            nnc = m - total_cooperators_prev
            if nnc <= 1:
                return Action.C
            else:
                return Action.D

class Strategy_SELFISH_12(BaseStrategy):
    """
    Implements a Conditional Free-Rider strategy.
    
    1.  Starts with Trial-Defect (Round 0: D).
    2.  Uses previous round cooperation data (m - C_{t-1}) to pivot.
    3.  If pivot fails, enters 2-round 'Hard-Defect' cooldown.
    4.  Logic respects final round payoffs (only cooperate if k > 1).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.hard_defect_cooldown = 0
        self.last_action = None

    def __call__(self, history: PlayerHistory) -> Action:
        if self.game_description.m > self.game_description.n_players:
            return Action.D
        if history.round_number == 0:
            self.last_action = Action.D
            return Action.D
        last_round_idx = history.round_number - 1
        last_opponents_c = history.opponent_cooperators[last_round_idx]
        last_my_c = 1 if self.last_action == Action.C else 0
        total_cooperators = last_opponents_c + last_my_c
        if last_my_c == 1 and total_cooperators < self.game_description.m:
            self.hard_defect_cooldown = 2
        if self.hard_defect_cooldown > 0:
            self.hard_defect_cooldown -= 1
            self.last_action = Action.D
            return Action.D
        need = self.game_description.m - last_opponents_c
        if history.round_number == self.game_description.n_rounds - 1:
            if need == 1:
                if self.game_description.k > 1.0:
                    self.last_action = Action.C
                    return Action.C
            self.last_action = Action.D
            return Action.D
        if need <= 0:
            self.last_action = Action.D
            return Action.D
        elif need > 1:
            self.last_action = Action.D
            return Action.D
        else:
            self.last_action = Action.C
            return Action.C

class Strategy_SELFISH_13(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that prioritizes endowment preservation
    while strategically contributing to bridge critical gaps toward the threshold (m).
    
    Logic summary:
    - First round: Always defect (D).
    - Ongoing/Last-round:
        1. If previous round cooperators >= m: Defect (no need to pay).
        2. If previous round cooperators == m - 1: Cooperate (if k > 1).
        3. If previous round cooperators < m - 1: Defect (insufficient leverage).
    - Opponent Exploitation Handling: Monitors if the player is being free-ridden by
      others. If the strategy contributed in the last round but still resulted in 
      the threshold not being met (or the group failed to reciprocate), it triggers 
      a reset to defection to avoid exploitation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.last_action = None

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            self.last_action = Action.D
            return Action.D
        m = self.game_description.m
        k = self.game_description.k
        my_last_c = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + my_last_c
        if my_last_c == 1 and total_cooperators_prev < m:
            self.last_action = Action.D
            return Action.D
        if total_cooperators_prev >= m:
            self.last_action = Action.D
            return Action.D
        if total_cooperators_prev == m - 1 and k > 1:
            self.last_action = Action.C
            return Action.C
        self.last_action = Action.D
        return Action.D

class Strategy_SELFISH_14(BaseStrategy):
    """
    Implements a threshold-dependent conditional cooperation strategy.
    
    This strategy attempts to secure reward 'k' by coordinating contributions only when
    the threshold 'm' is reachable. It defaults to defection in the first round (unless m=1),
    and in subsequent rounds, dynamically decides between free-riding, maintaining the
    threshold, or acting as the swing voter to reach the threshold.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.k = game_description.k
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C if self.m == 1 else Action.D
        prev_cooperators_others = history.opponent_cooperators[-1]
        prev_my_action_int = 1 if history.my_actions[-1] else 0
        prev_total_c = prev_cooperators_others + prev_my_action_int
        if t == self.r - 1:
            threshold_ever_met = np.any(history.opponent_cooperators + history.my_actions.astype(int) >= self.m)
            if not threshold_ever_met:
                return Action.D
        if prev_total_c >= self.m + 1:
            return Action.D
        if prev_total_c == self.m:
            return Action.C
        if prev_total_c == self.m - 1:
            return Action.C
        return Action.D

class Strategy_SELFISH_15(BaseStrategy):
    """
    Conditional Threshold Thresholding (CTT):
    Maximizes private gain by defecting by default. Only cooperates (C) if it is 
    the only action preventing failure to meet the threshold (m), provided the 
    reward (k) justifies the cost (1).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        last_my_action = history.my_actions[-1]
        last_opp_count = history.opponent_cooperators[-1]
        last_total_cooperators = last_opp_count + (1 if last_my_action else 0)
        deficit = self.game_description.m - last_total_cooperators
        if deficit == 1 and self.game_description.k > 1:
            return Action.C
        return Action.D

class Strategy_SELFISH_16(BaseStrategy):
    """
    Strategy: Conditional Threshold Monitoring (CTM)
    Uses a weighted moving average of cooperation to determine when to free-ride
    vs. contribute to secure the collective threshold. Includes endgame
    logic and reactivity to declining cooperation trends.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.S = 0.0
        self.prev_opp_coops = []

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.desc.n_players
        m = self.desc.m
        k = self.desc.k
        r_total = self.desc.n_rounds
        if k <= 1:
            return Action.D
        if history.round_number == 0:
            self.S = m / n
            return Action.C if random.random() < m / n else Action.D
        prev_my_action = int(history.my_actions[-1])
        prev_opp_count = history.opponent_cooperators[-1]
        o_t_minus_1 = prev_opp_count + prev_my_action
        self.S = 0.7 * self.S + 0.3 * o_t_minus_1
        self.prev_opp_coops.append(o_t_minus_1)
        if n - m < 2 and len(self.prev_opp_coops) >= 2:
            if self.prev_opp_coops[-1] < self.prev_opp_coops[-2]:
                return Action.C
        if history.round_number == r_total - 1:
            if self.S >= m:
                return Action.D
            else:
                if k - 1 > 1:
                    return Action.C
                return Action.D
        if self.S >= m + 1:
            return Action.D
        elif m < self.S < m + 1:
            return Action.D
        elif m - self.S > 1:
            return Action.C
        else:
            prob_c = 1.0 - (m - self.S)
            if random.random() < prob_c:
                return Action.C
            return Action.D

class Strategy_SELFISH_17(BaseStrategy):
    """
    Implements a strategic approach for the Collective Risk Dilemma.
    Round 1: Initial assessment based on risk threshold and reward.
    Rounds 2 to r-1: Adaptive strategy based on previous total cooperation (C_total).
    Round r: Terminal strategy evaluating if the final reward justifies the cost.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.n = game_description.n_players
        self.k = game_description.k
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            if self.m / self.n > 0.5 and self.k > 1:
                return Action.C
            return Action.D
        my_prev_action = Action.C if history.my_actions[-1] else Action.D
        c_prev_int = 1 if my_prev_action == Action.C else 0
        c_total_prev = history.opponent_cooperators[-1] + c_prev_int
        if current_round == self.r - 1:
            if self.k > 1:
                if c_total_prev == self.m - 1:
                    return Action.C
            return Action.D
        if c_total_prev >= self.m:
            if my_prev_action == Action.C:
                if c_total_prev > self.m:
                    return Action.D
                else:
                    return Action.C
            else:
                return Action.D
        elif c_total_prev == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_18(BaseStrategy):
    """
    A conditional cooperation strategy for the Collective Risk Dilemma.
    
    Logic:
    - Always defects on the first round to observe baseline behavior.
    - Always defects on the final round as there is no future incentive.
    - In intermediate rounds:
        - Free-rides (Defects) if the previous round's threshold was met.
        - Calculates the deficit (m - cooperators) if the threshold was missed.
        - Cooperates only if exactly one more person is needed to reach the threshold (Deficit == 1).
        - Otherwise, defects.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == self.total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.D
        my_prev_action = history.my_actions[-1]
        my_prev_c = 1 if my_prev_action == Action.C else 0
        last_round_c = history.opponent_cooperators[-1] + my_prev_c
        if last_round_c >= self.m:
            return Action.D
        deficit = self.m - last_round_c
        if deficit == 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_19(BaseStrategy):
    """
    Threshold-Sensitive Tit-for-Tat with Defection Bias.
    Prioritizes the reward (k) when necessary, while freeriding (D) when possible.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.k = game_description.k
        self.r = game_description.n_rounds
        self.gave_up = False

    def __call__(self, history: PlayerHistory) -> Action:
        if self.k <= 1:
            return Action.D
        if history.round_number == self.r - 1:
            return Action.D
        if history.round_number > 0:
            last_my_c = 1 if history.my_actions[-1] else 0
            last_total_c = last_my_c + history.opponent_cooperators[-1]
            if last_total_c < self.m - 1:
                self.gave_up = True
        if self.gave_up:
            return Action.D
        if history.round_number == 0:
            return Action.C
        prev_my_c = 1 if history.my_actions[-1] else 0
        prev_opp_c = history.opponent_cooperators[-1]
        prev_coop = prev_my_c + prev_opp_c
        if prev_my_c == 1:
            if prev_coop >= self.m + 1:
                return Action.D
            elif prev_coop == self.m:
                return Action.C
            else:
                return Action.D
        elif prev_opp_c >= self.m:
            return Action.D
        elif prev_opp_c == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_20(BaseStrategy):
    """
    Implements a trigger-threshold strategy:
    1. If the group threshold was met in the previous round, defect (exploit).
    2. If the group was exactly one short of the threshold, cooperate (pivotal position).
    3. If the group was further from the threshold, defect (cost saving).
    4. Last round: maximize payoff based on the previous round's outcome.
    5. Systematic Failure: If cooperation fails 3 times while contributing, defect permanently.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.failed_cooperation_attempts = 0
        self.systemic_failure_triggered = False

    def __call__(self, history: PlayerHistory) -> Action:
        if self.systemic_failure_triggered:
            return Action.D
        round_idx = history.round_number
        if round_idx == 0:
            return Action.D
        last_my_action = 1 if history.my_actions[-1] else 0
        last_opp_coop = history.opponent_cooperators[-1]
        total_cooperators_prev = last_my_action + last_opp_coop
        if last_my_action == 1 and total_cooperators_prev < self.m:
            self.failed_cooperation_attempts += 1
            if self.failed_cooperation_attempts >= 3:
                self.systemic_failure_triggered = True
                return Action.D
        threshold_met = total_cooperators_prev >= self.m
        pivotal_position = total_cooperators_prev == self.m - 1
        if round_idx == self.r - 1:
            if pivotal_position:
                return Action.C
            return Action.D
        if threshold_met:
            return Action.D
        elif pivotal_position:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_21(BaseStrategy):
    """
    A strategic implementation for the Collective Risk Dilemma that prioritizes defecting
    to minimize losses, while cautiously contributing only at the "tipping point" (N_c = m-1)
    to trigger the reward k, provided the group's history is stable.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.consecutive_failures = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        if history.round_number == self.desc.n_rounds - 1:
            return Action.D
        m = self.desc.m
        n = self.desc.n_players
        k = self.desc.k
        prev_nc = history.opponent_cooperators[-1]
        if history.round_number >= 2:
            if history.opponent_cooperators[-1] < m and history.opponent_cooperators[-2] < m:
                return Action.D
        if m <= n / 2:
            return Action.D
        if history.round_number >= 3:
            h = history.opponent_cooperators[-3:]
            bounced = (h[0] < m) != (h[1] < m) or (h[1] < m) != (h[2] < m)
            if bounced:
                return Action.D
        if prev_nc < m:
            return Action.D
        if prev_nc >= m:
            if prev_nc > m:
                return Action.D
            return Action.D
        if k > 1 and prev_nc == m - 1:
            return Action.C
        return Action.D

class Strategy_SELFISH_22(BaseStrategy):
    """
    Implements the 'Conditional Threshold Optimization' strategy.
    
    Logic:
    - Round 1: Defect.
    - Subsequent Rounds (not last):
      - C_obs >= m: Defect (Free-ride).
      - C_obs == m - 1: Cooperate (Pivotal player).
      - C_obs < m - 1: Defect.
    - Last Round: Always Defect.
    - Volatility Handling: Use average of last 3 rounds if stable history exists.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.r - 1:
            return Action.D
        if history.round_number == 0:
            return Action.D
        if history.round_number >= 3:
            recent_opponent_coops = history.opponent_cooperators[-3:]
            recent_my_actions = history.my_actions[-3:]
            total_cooperators_list = []
            for i in range(3):
                my_contrib = 1 if recent_my_actions[i] else 0
                total_cooperators_list.append(recent_opponent_coops[i] + my_contrib)
            c_obs = math.floor(sum(total_cooperators_list) / 3)
        else:
            last_my_contrib = 1 if history.my_actions[-1] else 0
            c_obs = history.opponent_cooperators[-1] + last_my_contrib
        if c_obs >= self.m:
            return Action.D
        if c_obs == self.m - 1:
            return Action.C
        return Action.D

class Strategy_SELFISH_23(BaseStrategy):
    """
    Implements a threshold-triggering conditional cooperation strategy.
    
    The agent defaults to Defect (D) to maximize private endowment. 
    It dynamically adjusts only when it identifies itself as a 'pivotal' player 
    (where its contribution of C would hit the threshold m) and the net gain 
    (k-1) is positive. It also employs a 'probing' mechanism: after contributing 
    to a successful threshold, it reverts to D to test if the threshold can be 
    maintained without its contribution.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.last_action = Action.D

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            self.last_action = Action.D
            return Action.D
        m = self.desc.m
        k = self.desc.k
        prev_c_opp = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        my_prev_contribution = 1 if my_prev_action else 0
        total_c = prev_c_opp + my_prev_contribution
        action = Action.D
        if not my_prev_action:
            if prev_c_opp >= m:
                action = Action.D
            elif prev_c_opp == m - 1:
                if k > 1:
                    action = Action.C
                else:
                    action = Action.D
            else:
                action = Action.D
        elif total_c >= m:
            action = Action.D
        else:
            action = Action.D
        if history.round_number == self.desc.n_rounds - 1:
            if prev_c_opp == m - 1 and k > 1:
                action = Action.C
            elif k > 2:
                action = Action.C
            else:
                action = Action.D
        self.last_action = action
        return action

class Strategy_SELFISH_24(BaseStrategy):
    """
    Implements the Threshold-Conditional Greed strategy.
    
    In the first round, defects.
    In the final round, always defects.
    In intermediate rounds, plays Cooperate only if the player is the 'pivotal' cooperator
    required to meet the threshold (m) based on the previous round's performance of others.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.D
        others_cooperated_prev = int(history.opponent_cooperators[-1])
        needed = self.game_description.m - others_cooperated_prev
        if needed == 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_25(BaseStrategy):
    """
    Threshold-Responsive Tit-for-Tat with Defection-First Terminality.

    Strategy Rules:
    1. Initial Action (Round 0): Defect (D) to preserve endowment.
    2. Terminal Round (Last Round): Defect (D) to maximize payoff without risk of future retaliation.
    3. Intermediate Rounds (1 < t < r):
       - If k <= 1: Always Defect (D), as cooperation is not profitable.
       - If previous round's cooperation count (C_t-1) >= m: Cooperate (C) to maintain reward.
       - If previous round's cooperation count (C_t-1) < m: Defect (D) as threshold is not met.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if self.game_description.k <= 1.0:
            return Action.D
        current_round = history.round_number
        last_round_idx = self.game_description.n_rounds - 1
        if current_round == 0:
            return Action.D
        if current_round == last_round_idx:
            return Action.D
        prev_cooperators = history.opponent_cooperators[-1]
        my_last_action = 1 if history.my_actions[-1] else 0
        total_cooperators = prev_cooperators + my_last_action
        if total_cooperators >= self.game_description.m:
            return Action.C
        return Action.D

class Strategy_SELFISH_26(BaseStrategy):
    """
    A Threshold-Triggered Tit-for-Tat strategy for the Collective Risk Dilemma.
    
    Logic:
    - Round 0 (1st round): Plays Defect (D).
    - Round Last: Plays Defect (D) as there is no future incentive.
    - Intermediate Rounds:
        - If the previous round met the cooperation threshold m, plays Defect (D) to free-ride.
        - If the previous round missed the threshold by exactly one player (m-1), plays Cooperate (C) to attempt to trigger the reward.
        - Otherwise, plays Defect (D) to avoid wasted contributions.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == 0:
            return Action.D
        if current_round == n_rounds - 1:
            return Action.D
        prev_my_action = int(history.my_actions[-1])
        prev_opponent_cooperators = int(history.opponent_cooperators[-1])
        total_cooperators = prev_my_action + prev_opponent_cooperators
        if total_cooperators >= m:
            return Action.D
        if total_cooperators == m - 1:
            return Action.C
        return Action.D

class Strategy_SELFISH_27(BaseStrategy):
    """
    Implements Threshold-Conditional Tit-for-Tat (TCTT).
    
    Logic:
    - Terminal round: Always Defect.
    - Round 1: Cooperate if m <= n/2, else Defect.
    - Round t > 1:
        - If previous round threshold was met (last C_count >= m), Defect.
        - If previous round was exactly m-1 cooperators, Cooperate.
        - Otherwise, Defect.
    
    Note: The 'opponent_cooperators' provided in history is the count of *other* players.
    To determine the total cooperation count, we must account for our own previous action.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n = self.game_description.n_players
        m = self.game_description.m
        if current_round == self.game_description.n_rounds - 1:
            return Action.D
        if current_round == 0:
            if m <= n / 2:
                return Action.C
            else:
                return Action.D
        my_last_action = int(history.my_actions[-1])
        total_cooperators_last_round = history.opponent_cooperators[-1] + my_last_action
        if total_cooperators_last_round >= m:
            return Action.D
        elif total_cooperators_last_round == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_28(BaseStrategy):
    """
    A conditional cooperation strategy for the Collective Risk Dilemma.
    Tests the threshold m without contribution first, then free-rides if possible.
    If the threshold is narrowly missed (by 1 cooperator), it contributes to secure the reward k,
    provided that the reward outweighs the cost of cooperation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if self.k <= 1.0:
            return Action.D
        current_round_idx = history.round_number
        if current_round_idx == 0:
            return Action.D
        prev_opp_coop = history.opponent_cooperators[-1]
        prev_my_action = history.my_actions[-1]
        total_prev_coop = prev_opp_coop + (1 if prev_my_action else 0)
        if current_round_idx == self.r - 1:
            if total_prev_coop >= self.m:
                return Action.D
            missing = self.m - total_prev_coop
            if missing == 1:
                return Action.C
            return Action.D
        if total_prev_coop > self.m:
            return Action.D
        if total_prev_coop >= self.m:
            return Action.D
        else:
            missing = self.m - total_prev_coop
            if not prev_my_action:
                if missing == 1:
                    return Action.C
                return Action.D
            else:
                return Action.D

class Strategy_SELFISH_29(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that prioritizes selfish retention
    by default, defecting unless the player is the pivotal contributor required
    to meet the cooperation threshold m, and only when the reward k outweighs 
    the cost of cooperation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        my_prev_action = history.my_actions[-1]
        my_prev_coop = 1 if my_prev_action == Action.C else 0
        previous_cooperators = history.opponent_cooperators[-1] + my_prev_coop
        m = self.game_description.m
        k = self.game_description.k
        if previous_cooperators >= m:
            return Action.D
        if previous_cooperators == m - 1:
            if k > 1:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_SELFISH_30(BaseStrategy):
    """
    Implements a Conditional Threshold Strategy for the Collective Risk Dilemma.
    
    The strategy follows three phases:
    1. Phase 1: Test cooperation with Defection (Round 0).
    2. Phase 2: Adaptive Threshold Maintenance (Rounds 1 to n_rounds-2).
       - Free-ride if threshold is already met.
       - Contribute only if exactly one more cooperator is needed to reach m.
       - Defect if the effort is futile.
    3. Phase 3: Terminal Defection (Final Round).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.D
        last_opponents_cooperated = history.opponent_cooperators[-1]
        last_my_action = history.my_actions[-1]
        m = self.game_description.m
        my_contribution = 1 if last_my_action else 0
        total_cooperators_last_round = last_opponents_cooperated + my_contribution
        if total_cooperators_last_round >= m:
            return Action.D
        if last_opponents_cooperated == m - 1:
            return Action.C
        return Action.D

class Strategy_SELFISH_31(BaseStrategy):
    """
    Threshold-Conditional Tit-for-Tat (TCTT) Strategy.
    
    This strategy aims to maximize cumulative payoff by minimizing personal contributions.
    It treats the group as a single entity and only contributes if the player's own 
    contribution is strictly necessary to reach the cooperative threshold 'm'.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        last_my_action = history.my_actions[-1]
        last_total_cooperators = history.opponent_cooperators[-1] + (1 if last_my_action else 0)
        if last_total_cooperators >= self.m:
            return Action.D
        elif last_total_cooperators == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_32(BaseStrategy):
    """
    Strategy: Conditional Threshold Greed
    
    This strategy aims to maximize payoff by free-riding (playing D) whenever possible.
    It only contributes (plays C) if the player is the pivotal swing voter required 
    to reach the threshold 'm' and unlock the reward 'k'.
    
    Logic:
    - Round 0: Always Defect (D).
    - Last Round: Always Defect (D).
    - Other Rounds: 
        - Calculate how many others contributed in the previous round.
        - If the number of others who contributed is exactly m-1, play C 
          (to hit the threshold m).
        - Otherwise, play D.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        round_idx = history.round_number
        if round_idx == 0 or round_idx == self.game_description.n_rounds - 1:
            return Action.D
        prev_others_cooperated = history.opponent_cooperators[-1]
        if prev_others_cooperated == self.game_description.m - 1:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_5(BaseStrategy):
    """
    Threshold-Tit-for-Tat with Forgiveness and Decay.
    
    This strategy models the game as a coordination problem, aiming to reach the
    threshold m while managing free-rider incentives. It uses probabilistic initial
    moves, conditional reciprocity, and a sunset phase to handle finite horizon effects.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k
        self.is_in_free_rider_trap = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number >= self.r - math.floor(self.n / self.m):
            return Action.D
        if history.round_number == 0:
            if random.random() < self.m / self.n:
                return Action.C
            return Action.D
        prev_my_action = history.my_actions[-1]
        c_i_prev = 1 if prev_my_action else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + c_i_prev
        if total_cooperators_prev == self.m and (not prev_my_action):
            self.is_in_free_rider_trap = True
        if total_cooperators_prev < self.m:
            self.is_in_free_rider_trap = False
        if self.is_in_free_rider_trap:
            return Action.D
        threshold_met = total_cooperators_prev >= self.m
        if threshold_met:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_6(BaseStrategy):
    """
    Threshold-Conditional Reciprocity strategy for Collective Risk Dilemma.
    
    This strategy adapts to the group's collective behavior:
    1. Initial Round: Always cooperates to test group propensity.
    2. Adaptive Rounds:
       - If threshold met with surplus, free-ride (switch to Defect).
       - If threshold exactly met, maintain Cooperation.
       - If threshold missed narrowly, maintain Cooperation to signal.
       - If threshold missed badly, switch to Defect to conserve resources.
    3. Terminal Phase:
       - Uses trend analysis of recent rounds to decide between cost of Cooperation 
         vs. potential reward of threshold completion.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_prev_c = int(history.my_actions[-1])
        opp_prev_c = history.opponent_cooperators[-1]
        s_prev = opp_prev_c + my_prev_c
        if history.round_number == self.r - 1:
            recent_rounds = min(history.round_number, 3)
            recent_opp_c = history.opponent_cooperators[-recent_rounds:]
            avg_opp_c = np.mean(recent_opp_c)
            prob_success_with_c = 1.0 if avg_opp_c + 1 >= self.m else 0.0
            if prob_success_with_c > 0.5:
                return Action.C
            return Action.D
        if s_prev >= self.m:
            if s_prev > self.m:
                return Action.D
            else:
                return Action.C
        elif s_prev == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_7(BaseStrategy):
    """
    A strategy that acts as a conditional threshold trigger.
    
    Logic:
    - Round 0: Always cooperates to signal willingness.
    - Final Round: Always defects, as there is no future utility.
    - Intermediate Rounds:
        - If the previous round met the threshold (>= m), defect to capture private reward + k.
        - If the previous round was exactly one player short (m-1), cooperate to trigger the reward.
        - If the previous round failed significantly (< m-1), defect to avoid wasting investment.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.game.n_rounds - 1:
            return Action.D
        my_prev_action = history.my_actions[-1]
        last_round_cooperators = (1 if my_prev_action else 0) + history.opponent_cooperators[-1]
        m = self.game.m
        if last_round_cooperators >= m:
            return Action.D
        elif last_round_cooperators == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_8(BaseStrategy):
    """
    Threshold-Responsive Trigger (TRT) strategy:
    A conditional cooperation strategy that attempts to maintain the threshold
    cooperation level (m) to secure the collective reward (k), while exploiting
    (defecting) when possible or necessary.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k
        self.buffer = math.ceil(self.n / self.m)

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            prob_c = self.m / self.n
            return Action.C if random.random() < prob_c else Action.D
        round_t = current_round + 1
        prev_idx = current_round - 1
        my_last_action_val = 1 if history.my_actions[prev_idx] else 0
        total_cooperators_prev = history.opponent_cooperators[prev_idx] + my_last_action_val
        if round_t == self.r:
            return Action.D
        if round_t > self.r - self.buffer:
            return Action.D
        threshold_met = total_cooperators_prev >= self.m
        if threshold_met:
            if history.my_actions[prev_idx] == Action.C:
                return Action.C
            else:
                my_last_payoff = history.my_payoffs[prev_idx]
                if my_last_payoff > 1.0:
                    return Action.D
                else:
                    return Action.C
        else:
            return Action.C if round_t % 2 == 0 else Action.D

class Strategy_SELFINTERESTED_9(BaseStrategy):
    """
    Threshold-Adaptive Reciprocity (TAR):
    A conditional cooperation strategy that attempts to maintain the threshold (m)
    when possible, defects when the group fails, and includes a recovery protocol 
    to nudge the group back toward cooperation if they were close to the threshold.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description
        self.in_cooldown = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.game.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            self.in_cooldown = False
            return Action.C
        my_prev_action_val = 1 if history.my_actions[-1] else 0
        c_prev = history.opponent_cooperators[-1] + my_prev_action_val
        m = self.game.m
        if self.in_cooldown:
            self.in_cooldown = False
            return Action.C
        if c_prev >= m:
            return Action.C
        elif c_prev >= m - 1:
            return Action.C
        else:
            self.in_cooldown = True
            return Action.D

class Strategy_SELFINTERESTED_10(BaseStrategy):
    """
    Threshold-Responsive Tit-for-Tat (TR-TFT):
    - Round 1: Probability p=m/n to Cooperate.
    - Rounds 2 to r-2: 
        - If N_prev >= m: Maintain previous action (Tit-for-Tat logic).
        - If N_prev == m-1: Cooperate (Nudge).
        - If N_prev < m-1: Defect.
        - If N_prev > m: Defect (Over-cooperation avoidance).
        - Edge Case (Persistent Defection): If failed (N_prev < m) for 3 consecutive rounds, switch to Defect permanently.
    - Final 2 rounds: Always Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.consecutive_failures = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number >= self.r - 2:
            return Action.D
        if history.round_number == 0:
            return Action.C if random.random() < self.m / self.n else Action.D
        last_opponent_count = history.opponent_cooperators[-1]
        my_last_action_val = 1 if history.my_actions[-1] else 0
        total_cooperators = last_opponent_count + my_last_action_val
        if total_cooperators < self.m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 3:
            return Action.D
        if total_cooperators >= self.m:
            if total_cooperators > self.m:
                return Action.D
            return Action.C if history.my_actions[-1] else Action.D
        if total_cooperators == self.m - 1:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_11(BaseStrategy):
    """
    Implements a Conditional Threshold-Triggered Contribution strategy.
    
    Phases:
    1. Initial Phase: Cooperates for the first two rounds (rounds 0 and 1).
    2. Adaptive Phase: Calculates historical average cooperation of opponents.
       - If high or marginal (>= (m-1)/(n-1)), plays C.
       - If low (< (m-1)/(n-1)), plays D, unless triggering a periodic 3-round test.
    3. Final Round: Special "last-ditch" effort if the threshold is within 1 cooperator.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description
        self.n_opponents = self.game.n_players - 1

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        n = self.game.n_players
        m = self.game.m
        if t <= 1:
            return Action.C
        total_observed_cooperators = np.sum(history.opponent_cooperators)
        if t == 0:
            avg_opp_coop = 0.0
        else:
            avg_opp_coop = total_observed_cooperators / (self.n_opponents * t)
        threshold_high = m / self.n_opponents
        threshold_marginal = (m - 1) / self.n_opponents
        action = Action.D
        if avg_opp_coop >= threshold_high:
            action = Action.C
        elif avg_opp_coop > threshold_marginal:
            action = Action.C
        elif t % 3 == 0:
            action = Action.C
        else:
            action = Action.D
        if t == self.game.n_rounds - 1:
            last_round_opp_coop = history.opponent_cooperators[-1]
            if last_round_opp_coop == m - 1:
                return Action.C
        return action

class Strategy_SELFINTERESTED_12(BaseStrategy):
    """
    Threshold-Triggered Conditional Cooperation (TTCC) strategy.
    
    Operates by defecting in the first round. In subsequent rounds, it monitors the
    previous round's total cooperators. It only contributes if the previous round 
    had exactly m-1 cooperators, effectively acting as the "pivot" player to 
    secure the reward. Otherwise, it defects to minimize costs, assuming that if 
    the threshold is already met (>= m), it can free-ride, and if it's far below (< m-1),
    contributing is a wasted cost.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        last_round_idx = history.round_number - 1
        prev_my_action = int(history.my_actions[last_round_idx])
        prev_total_cooperators = history.opponent_cooperators[last_round_idx] + prev_my_action
        if history.round_number == self.r:
            if prev_total_cooperators == self.m - 1:
                return Action.C
            return Action.D
        if prev_total_cooperators >= self.m:
            return Action.D
        elif prev_total_cooperators == self.m - 1:
            denominator = max(1, self.n - 1)
            p = min(1.0, float(prev_total_cooperators) / denominator)
            if random.random() < p:
                return Action.C
            return Action.D
        else:
            return Action.D

class Strategy_SELFINTERESTED_13(BaseStrategy):
    """
    Implements a Conditional Threshold Strategy for the Collective Risk Dilemma.
    Prioritizes Defect (D) unless the player's single contribution is sufficient to 
    reach the cooperative threshold m, thereby triggering the reward k.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if self.k <= 1:
            return Action.D
        if history.round_number == 0:
            return Action.D
        if history.round_number == self.r - 1:
            return Action.D
        last_round_idx = history.round_number - 1
        opponents_cooperating_last = history.opponent_cooperators[last_round_idx]
        my_last_action_val = 1 if history.my_actions[last_round_idx] == Action.C else 0
        total_cooperators_last = opponents_cooperating_last + my_last_action_val
        if self.m - 1 <= opponents_cooperating_last < self.m:
            return Action.C
        if opponents_cooperating_last >= self.m:
            return Action.D
        if opponents_cooperating_last < self.m - 1:
            return Action.D
        return Action.D

class Strategy_SELFINTERESTED_14(BaseStrategy):
    """
    A strategy that implements conditional 'Win-Stay, Lose-Shift' logic based on the 
    collective cooperation threshold 'm'. It makes decisions by assessing whether 
    the player's contribution is necessary (pivotal) to achieve the reward 'k', 
    free-riding when the threshold is already met, and defecting when the 
    threshold is unreachable.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = self.game_description.n_players
        self.m = self.game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            if self.m / self.n <= 0.5:
                return Action.C
            return Action.D
        c_prev = int(history.opponent_cooperators[-1])
        my_last_action_val = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = c_prev + my_last_action_val
        if total_cooperators_prev >= self.m:
            return Action.D
        elif total_cooperators_prev == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_15(BaseStrategy):
    """
    Adaptive Threshold-Conditional Cooperation (ATCC):
    A strategy that aims to maintain the collective threshold (m) to unlock 
    the reward (k) while defecting (D) whenever it is safe to do so 
    (either the threshold is met without the player's contribution or 
    the player is redundant).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.game_description.n_rounds - 1:
            return Action.D
        prev_my_action_bool = history.my_actions[-1]
        prev_opp_coop = history.opponent_cooperators[-1]
        prev_my_contribution = 1 if prev_my_action_bool else 0
        prev_total_cooperators = prev_opp_coop + prev_my_contribution
        threshold_met = prev_total_cooperators >= self.game_description.m
        if threshold_met:
            if prev_my_contribution == 1:
                if prev_total_cooperators > self.game_description.m:
                    return Action.D
                else:
                    return Action.C
            else:
                return Action.D
        else:
            return Action.C

class Strategy_SELFINTERESTED_16(BaseStrategy):
    """
    Implements the Threshold-Conditional Reciprocity (TCR) strategy.
    
    TCR balances cooperation to reach a collective threshold (m) with protection 
    against free-riders and sunk costs, while maximizing individual payoffs 
    in terminal rounds.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.k = game_description.k
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            if self.k > 1:
                return Action.C
            return Action.D
        my_prev_action = history.my_actions[-1]
        c_prev_others = history.opponent_cooperators[-1]
        total_cooperators_prev = c_prev_others + (1 if my_prev_action else 0)
        s = 1 if total_cooperators_prev >= self.m else 0
        if current_round == self.r - 1:
            return Action.D
        if s == 1:
            return Action.C
        elif total_cooperators_prev >= self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_17(BaseStrategy):
    """
    Threshold-Conditional Tit-for-Tat with Defection-Risk Buffering:
    A strategy that adapts to the group's ability to reach the threshold m.
    It cooperates if the group meets the threshold or if the player's 
    cooperation can uniquely trigger the threshold reward k.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        m = self.game_description.m
        k = self.game_description.k
        if current_round == 0:
            return Action.C
        my_prev_action = int(history.my_actions[-1])
        opp_coop_prev = int(history.opponent_cooperators[-1])
        is_terminal = current_round == r - 1
        if is_terminal:
            if k > 1 and opp_coop_prev >= m - 1:
                return Action.C
            else:
                return Action.D
        effective_threshold = m if my_prev_action == 0 else m - 1
        if opp_coop_prev >= effective_threshold:
            return Action.C
        else:
            gap = effective_threshold - opp_coop_prev
            if gap == 1 and k > 1:
                return Action.C
            else:
                return Action.D

class Strategy_SELFINTERESTED_18(BaseStrategy):
    """
    Implements Adaptive Threshold-Triggered Cooperation for the Collective Risk Dilemma.
    
    Strategy:
    - Phase 1: Cooperate in round 0 to establish baseline.
    - Phase 2: Adaptive response logic based on the previous round's outcome.
      - If threshold was met, try Defecting to optimize payoff.
      - If threshold missed, try Cooperating to reach threshold.
    - Special Handling:
      - If reward factor k <= 1, always Defect.
      - If group is consistently non-cooperative (threshold not met for 3+ consecutive rounds),
        stop contributing to minimize losses.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.failed_streak = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if self.desc.k <= 1.0:
            return Action.D
        if history.round_number == 0:
            return Action.C
        my_last_action = history.my_actions[-1]
        others_coop = history.opponent_cooperators[-1]
        total_coop = others_coop + (1 if my_last_action else 0)
        if total_coop < self.desc.m:
            self.failed_streak += 1
        else:
            self.failed_streak = 0
        if self.failed_streak >= 3:
            return Action.D
        if history.round_number == self.desc.n_rounds - 1:
            if total_coop >= self.desc.m:
                return Action.D
            else:
                return Action.C if self.desc.k > 1 else Action.D
        if total_coop >= self.desc.m:
            return Action.D
        return Action.C

class Strategy_SELFINTERESTED_19(BaseStrategy):
    """
    Conditional Threshold Tit-for-Tat (CTT) Strategy.
    
    A strategy that balances the desire to meet the cooperative threshold 
    with the incentive to defect when the threshold is safe or when the 
    group is not cooperating sufficiently.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        m = self.game_description.m
        last_my_action = 1 if history.my_actions[-1] else 0
        last_c_total = history.opponent_cooperators[-1] + last_my_action
        if last_c_total > m:
            return Action.D
        if last_c_total == m:
            return Action.C
        all_my_actions = history.my_actions.astype(np.int_)
        all_c_totals = history.opponent_cooperators + all_my_actions
        avg_c = np.mean(all_c_totals)
        if avg_c >= m - 1:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_20(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that focuses on pivotal contribution.
    It defaults to Defection in the first round. In subsequent rounds, it monitors
    the previous round's cooperation count. It cooperates only when the player's 
    contribution is strictly necessary to reach the 'm' threshold (i.e., when
    the previous round's cooperators were exactly m-1), provided the reward 'k' 
    is sufficient to justify the cost.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        last_round_idx = history.round_number - 1
        i_cooperated_last = int(history.my_actions[last_round_idx])
        c_prev_others = history.opponent_cooperators[last_round_idx]
        total_c_prev = c_prev_others + i_cooperated_last
        if total_c_prev == self.m - 1 and self.k > 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_21(BaseStrategy):
    """
    Implements a Threshold-Contingent Trigger-Tit-for-Tat strategy.
    
    Logic:
    - Round 1: Cooperate.
    - Rounds 2 to r-1: 
        - If last action was C: Cooperate if threshold was met, else Defect.
        - If last action was D: Defect if threshold was met, else probabilistically Cooperate.
        - Always Cooperate if all players cooperated.
        - Always Defect if 0 players cooperated.
    - Final Round: Evaluate historical performance; cooperate under specific criteria.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_my_action = history.my_actions[-1]
        prev_opp_coop = history.opponent_cooperators[-1]
        prev_total_coop = prev_opp_coop + (1 if prev_my_action else 0)
        if prev_total_coop == self.n:
            return Action.C
        if prev_total_coop == 0:
            return Action.D
        if history.round_number == self.r - 1:
            if len(history.my_payoffs) > 1:
                avg_payoff = np.mean(history.my_payoffs[:-1])
            else:
                avg_payoff = history.my_payoffs[0]
            prev_coop_rounds = 0
            for i in range(history.round_number):
                my_c = 1 if history.my_actions[i] else 0
                total_c = history.opponent_cooperators[i] + my_c
                if total_c >= self.m:
                    prev_coop_rounds += 1
            is_consistent = prev_coop_rounds > history.round_number / 2
            if avg_payoff > 1.0:
                return Action.C if prev_total_coop >= self.m - 1 else Action.D
            elif is_consistent:
                return Action.C
            else:
                return Action.D
        if prev_my_action:
            if prev_total_coop >= self.m:
                return Action.C
            else:
                return Action.D
        elif prev_total_coop >= self.m:
            return Action.D
        else:
            p = 1.0 - prev_total_coop / self.m
            return Action.C if random.random() < p else Action.D

class Strategy_SELFINTERESTED_22(BaseStrategy):
    """
    Threshold-Adaptive Trigger (TAT):
    Adaptive strategy that switches between defection (to maximize utility when
    successful) and conditional cooperation (to save the group outcome when
    one player can tip the threshold).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            if self.m / self.n >= 0.5:
                return Action.C
            return Action.D
        my_prev_action = 1 if history.my_actions[-1] else 0
        total_prev_cooperators = history.opponent_cooperators[-1] + my_prev_action
        if t == self.r - 1:
            if total_prev_cooperators >= self.m - 1:
                return Action.C
            return Action.D
        if total_prev_cooperators >= self.m:
            return Action.D
        else:
            deficit_gap = self.m - total_prev_cooperators
            if deficit_gap == 1:
                return Action.C
            else:
                return Action.D

class Strategy_SELFINTERESTED_23(BaseStrategy):
    """
    A conditional threshold-trigger strategy for the Collective Risk Dilemma.
    Balances free-riding (D) against pivotal contribution (C) based on historical cooperation counts.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            if self.m <= self.n / 2:
                return Action.D
            else:
                return Action.C
        total_cooperators_per_round = [history.opponent_cooperators[i] + (1 if history.my_actions[i] else 0) for i in range(round_idx)]
        if round_idx == self.r - 1:
            last_total_coop = total_cooperators_per_round[-1]
            if last_total_coop >= self.m:
                return Action.D
            elif last_total_coop == self.m - 1:
                return Action.C
            else:
                return Action.D
        avg_c = sum(total_cooperators_per_round) / round_idx
        if avg_c >= self.m:
            return Action.D
        if avg_c < self.m - 1:
            return Action.D
        if avg_c >= self.m - 1 and avg_c < self.m:
            if round_idx > 1:
                last_total = total_cooperators_per_round[-1]
                last_my_action = history.my_actions[-1]
                if last_my_action and last_total < self.m:
                    return Action.D
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_24(BaseStrategy):
    """
    Threshold-Triggered Conditional Cooperation Strategy.
    
    Logic:
    - Round 1: Always Cooperate (C).
    - Rounds t > 1:
        - If previous cooperation count X >= m - 1, Cooperate (C).
        - If X < m - 1, Defect (D), subject to probe logic.
    - Probe Logic: Every N = ceil(r / ln(r)) rounds (or at least every 3), 
      attempt to Cooperate (C) even when in defect mode to test for cooperation recovery.
    - Last Round: Defect (D) if history has not been consistently cooperative, 
      otherwise maintain cooperation pattern.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description
        r = float(self.game.n_rounds)
        try:
            self.probe_interval = max(3, math.ceil(r / math.log(r)))
        except (ValueError, ZeroDivisionError):
            self.probe_interval = 3
        self.is_probing = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        round_idx = history.round_number
        prev_cooperators = history.opponent_cooperators[-1]
        is_last_round = round_idx == self.game.n_rounds - 1
        if round_idx % self.probe_interval == 0:
            return Action.C
        if is_last_round:
            recent_cooperation = history.opponent_cooperators[-3:]
            if all((c >= self.game.m - 1 for c in recent_cooperation)):
                return Action.C
            return Action.D
        if prev_cooperators >= self.game.m - 1:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_25(BaseStrategy):
    """
    A conditional cooperation strategy for the Collective Risk Dilemma.
    Round 1: Defect.
    Round t > 1:
        - If previous round threshold was met (C_{t-1} >= m): Defect.
        - If previous round threshold was not met (C_{t-1} < m):
            - If C_{t-1} == m - 1 and t < r: Cooperate.
            - Else: Defect.
    Last Round: Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round == self.r - 1:
            return Action.D
        last_my_action = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + last_my_action
        if total_cooperators_prev >= self.m:
            return Action.D
        if total_cooperators_prev == self.m - 1:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_26(BaseStrategy):
    """
    A strategy that tracks the number of cooperators against a threshold 'm'.
    It uses a state-based approach ("Testing", "Cooperative", "Exploitative")
    to decide whether to contribute or defect based on group success and
    the risk of free-riding.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.state = 'Testing'

    def __call__(self, history: PlayerHistory) -> Action:
        r = self.game_description.n_rounds
        t = history.round_number + 1
        m = self.game_description.m
        k = self.game_description.k
        if t == r:
            return Action.D
        if t == 1:
            return Action.C if random.random() < 0.5 else Action.D
        prev_cooperators = history.opponent_cooperators[-1]
        my_prev_action = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = prev_cooperators + my_prev_action
        if total_cooperators_prev >= m:
            self.state = 'Cooperative'
        else:
            self.state = 'Exploitative'
        if self.state == 'Cooperative':
            if total_cooperators_prev > m:
                return Action.C
            else:
                return Action.D
        elif self.state == 'Exploitative':
            action = Action.D
            if k > 1 and total_cooperators_prev == m - 1:
                action = Action.C
            elif t < r and t % 5 == 0:
                action = Action.C
            return action
        return Action.D

class Strategy_SELFINTERESTED_27(BaseStrategy):
    """
    A threshold-triggered conditional cooperation strategy for the Collective Risk Dilemma.
    
    This strategy implements reciprocity by conditioning cooperation on whether the previous
    round met the required threshold 'm'. It includes mechanisms for periodic testing
    after a failure and explicitly defects on the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == self.r - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        previous_my_action = history.my_actions[-1]
        previous_opponent_coops = history.opponent_cooperators[-1]
        s_prev = previous_opponent_coops + (1 if previous_my_action else 0)
        if self.m > self.n / 2 and s_prev < self.m:
            return Action.D
        if s_prev >= self.m:
            return Action.C
        else:
            if (current_round + 1) % 3 == 0:
                return Action.C
            if self.k <= 1.0:
                return Action.D
            return Action.D

class Strategy_SELFINTERESTED_28(BaseStrategy):
    """
    Threshold-Sensitive Tit-for-Tat with Conditional Defection.
    
    Logic:
    - Round 0 (Phase 1): Cooperate if the threshold is attainable (n <= 2m), else defect.
    - Intermediate Rounds (Phase 2):
        - If previous round met threshold (C_prev >= m): Repeat previous action (tit-for-tat on one's own success).
        - If previous round was one short of threshold (C_prev == m - 1): Cooperate to push over threshold.
        - Otherwise: Defect to minimize loss.
    - Final Round (Phase 3): Defect unconditionally.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            if n <= 2 * m:
                return Action.C
            else:
                return Action.D
        if current_round == r - 1:
            return Action.D
        my_prev_action = history.my_actions[-1]
        my_prev_coop = 1 if my_prev_action else 0
        opponents_prev_coop = history.opponent_cooperators[-1]
        total_cooperators_prev = my_prev_coop + opponents_prev_coop
        if total_cooperators_prev >= m:
            if my_prev_action:
                return Action.C
            else:
                return Action.D
        if total_cooperators_prev == m - 1:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_29(BaseStrategy):
    """
    Threshold-Adaptive Trigger (TAT)
    
    This strategy utilizes a dynamic threshold model to maximize the likelihood of 
    reaching the critical mass m while punishing free-riders. It operates based on 
    the total number of cooperators observed in the previous round, acting as a 
    conditional cooperator that prioritizes 'pivotal' contribution opportunities.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_prev_coop = 1 if history.my_actions[-1] else 0
        opp_prev_coop = int(history.opponent_cooperators[-1])
        total_last_round_cooperators = my_prev_coop + opp_prev_coop
        m = self.game_description.m
        is_last_round = history.round_number == self.game_description.n_rounds - 1
        if is_last_round:
            if total_last_round_cooperators == m - 1:
                return Action.C
            return Action.D
        if total_last_round_cooperators >= m:
            return Action.C
        elif total_last_round_cooperators == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_30(BaseStrategy):
    """
    Threshold-Triggered Conditional Cooperation:
    - Round 1: Play C to signal willingness.
    - Round t (1 < t <= r): If the previous round's number of cooperators was >= m, play C.
      Otherwise, play D.
    - Final Round: Always play D (no future reciprocity incentive).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        threshold = self.game_description.m
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        last_action = Action.C if history.my_actions[-1] else Action.D
        last_action_val = 1 if last_action == Action.C else 0
        previous_total_cooperators = history.opponent_cooperators[-1] + last_action_val
        if previous_total_cooperators >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_31(BaseStrategy):
    """
    A conditional strategy for the Collective Risk Dilemma.
    
    Logic:
    - Round 0: Always Defect (test baseline).
    - Round t > 0:
        - If threshold m was met last round: Defect (free-riding).
        - If threshold was m-1 last round: Cooperate (attempt to cross threshold).
        - Otherwise: Defect (save private endowment).
    - Final Round Adjustment: If the average cooperation rate over previous rounds 
      is low (indicating consistent failure to meet threshold), prioritize Defecting.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.k = game_description.k
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        last_my_action = 1 if history.my_actions[-1] else 0
        last_opp_coop = history.opponent_cooperators[-1]
        last_total_coop = last_opp_coop + last_my_action
        if history.round_number == self.r - 1:
            all_opp_coops = history.opponent_cooperators
            all_my_actions = history.my_actions.astype(int)
            total_coop_history = all_opp_coops + all_my_actions
            if np.all(total_coop_history < self.m):
                return Action.D
        if last_total_coop >= self.m:
            return Action.D
        if last_total_coop == self.m - 1:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_32(BaseStrategy):
    """
    A Trigger-Threshold strategy that biases initial participation based on probability,
    then switches to conditional cooperation based on group viability. It pivots to 
    cooperation when necessary to reach the threshold (m) and defaults to defection
    when the group fails to coordinate, with specific logic for the terminal round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.permanently_defected = False
        self.cooperation_cycle_history = []

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        round_idx = history.round_number
        if round_idx > 0:
            if history.opponent_cooperators[-1] < m - 1:
                if round_idx > 1 and history.opponent_cooperators[-2] < m - 1:
                    self.permanently_defected = True
        if self.permanently_defected:
            return Action.D
        if round_idx == 0:
            p = (m - 1) / (n - 1) if n - 1 > 0 else 0.0
            return Action.C if random.random() < p else Action.D
        my_prev_action = 1 if history.my_actions[-1] else 0
        others_prev = history.opponent_cooperators[-1]
        c_prev = others_prev + my_prev_action
        self.cooperation_cycle_history.append(c_prev >= m - 1)
        if len(self.cooperation_cycle_history) > 2:
            self.cooperation_cycle_history.pop(0)
        if round_idx == r - 1:
            if len(self.cooperation_cycle_history) == 2 and all(self.cooperation_cycle_history):
                return Action.C
            return Action.D
        if c_prev > m and my_prev_action == 0:
            return Action.D
        if c_prev >= m:
            return Action.C
        elif c_prev == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_5(BaseStrategy):
    """
    Implements Threshold-Targeting Opportunism:
    - Round 1: Cooperate.
    - Subsequent Rounds (2 to r-1):
        - If previously cooperated:
            - If threshold was met: Defect (exploit).
            - If threshold was missed: Cooperate (attempt again).
        - If previously defected:
            - If threshold met: Defect (free-ride).
            - If threshold nearly met (C_prev == m-1): Cooperate (pivot).
            - Otherwise: Defect.
    - Final Round: Cooperate if own action can trigger the threshold, else Defect.
    - Convergence: If consecutive rounds fail to meet the threshold, switch to Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_fails = 0

    def __call__(self, history: PlayerHistory) -> Action:
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        prev_C = history.opponent_cooperators[-1]
        prev_my_C = bool(history.my_actions[-1])
        total_prev_C = prev_C + (1 if prev_my_C else 0)
        if total_prev_C < m:
            self.consecutive_fails += 1
        else:
            self.consecutive_fails = 0
        if self.consecutive_fails >= 3:
            return Action.D
        if current_round == r - 1:
            if prev_C >= m - 1:
                return Action.C
            return Action.D
        if prev_my_C:
            if total_prev_C >= m:
                return Action.D
            else:
                return Action.C
        elif prev_C >= m:
            return Action.D
        elif prev_C == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_6(BaseStrategy):
    """
    Implements an Opportunistic Threshold-Based Strategy for the Collective Risk Dilemma.
    
    Logic:
    - Round 1: Always Cooperate (C).
    - Final Round: Always Defect (D).
    - Opportunistic Rule:
        - If previous round met threshold (>= m): Switch to/Maintain Defect.
        - If previous round failed (< m):
            - If we played C and failed, switch to Defect.
            - If we played D and were exactly 1 short of threshold (m-1), switch to Cooperate.
            - Otherwise maintain Defect.
        - Persistence Check: If threshold failure persists for two consecutive rounds, revert to Defect forever.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.n_rounds = game_description.n_rounds
        self.consecutive_failures = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        prev_round_idx = history.round_number - 1
        my_action_prev = history.my_actions[prev_round_idx]
        c_prev = 1 if my_action_prev else 0
        n_t_minus_1 = history.opponent_cooperators[prev_round_idx] + c_prev
        if n_t_minus_1 < self.m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 2:
            return Action.D
        if n_t_minus_1 >= self.m:
            return Action.D
        if my_action_prev:
            return Action.D
        if n_t_minus_1 == self.m - 1:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_7(BaseStrategy):
    """
    Implements Conditional Threshold-Triggered Opportunism for the Collective Risk Dilemma.
    
    The strategy balances between signaling, cooperative rescue, and opportunistic defection
    based on the state of the collective threshold m.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == self.game_description.n_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        last_opponents_c = history.opponent_cooperators[-1]
        self_last_acted_c = history.my_actions[-1]
        total_cooperators_last_round = last_opponents_c + (1 if self_last_acted_c else 0)
        m = self.game_description.m
        if total_cooperators_last_round == m - 1:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_8(BaseStrategy):
    """
    A strategy that balances cooperative signaling with calculated opportunism.
    - If the last round: Defect (D).
    - If round 1: Cooperate (C) with probability m/n.
    - If R_rem > 0:
        - If C_prev >= m: Defect (D).
        - If C_prev < m:
            - If C_prev >= m - 1: Cooperate (C) with prob (m - C_prev) / (n - C_prev + 1).
            - Else: Defect (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_idx = history.round_number
        rounds_remaining = self.r - current_round_idx
        if rounds_remaining == 1:
            return Action.D
        if current_round_idx == 0:
            p_start = self.m / self.n
            return Action.C if random.random() < p_start else Action.D
        c_prev = int(history.opponent_cooperators[-1])
        if c_prev >= self.m:
            return Action.D
        if c_prev >= self.m - 1:
            denominator = self.n - c_prev + 1
            if denominator <= 0:
                return Action.D
            p_adaptive = (self.m - c_prev) / denominator
            return Action.C if random.random() < p_adaptive else Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_9(BaseStrategy):
    """
    Threshold-Triggered Opportunistic Response (TTOR) strategy.
    
    Operates on a logic of minimal necessary contribution to secure the k reward:
    - Round 1: Always Cooperate.
    - Intermediate rounds:
        - If the group reaches threshold without me, Defect.
        - If the group is one short of threshold, Cooperate.
        - Otherwise Defect, with a special 'probing' maneuver at round (r-1).
    - Final round: Minimal contribution logic.
    - Adaptation: Tracks if the group is hopeless (fails to meet threshold 3 times despite contribution)
      and switches to permanent Defection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0
        self.is_hopeless = False

    def __call__(self, history: PlayerHistory) -> Action:
        if self.is_hopeless:
            return Action.D
        if history.round_number == 0:
            return Action.C
        prev_c_total = history.opponent_cooperators[-1]
        prev_my_action = Action.C if history.my_actions[-1] else Action.D
        if prev_my_action == Action.C:
            n_eff = prev_c_total - 1
        else:
            n_eff = prev_c_total
        if prev_my_action == Action.C and prev_c_total < self.game_description.m:
            self.consecutive_failures += 1
        elif prev_c_total >= self.game_description.m:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 3:
            self.is_hopeless = True
            return Action.D
        m = self.game_description.m
        t = history.round_number
        r = self.game_description.n_rounds
        if n_eff >= m:
            return Action.D
        if n_eff == m - 1:
            return Action.C
        if t == r - 1 and n_eff == m - 2:
            if random.random() < 0.5:
                return Action.C
            return Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_10(BaseStrategy):
    """
    Implements a 'Wait-and-Verify' protocol.
    - Round 1: Cooperates to signal intent.
    - Rounds 2 to r-1:
        - Defect if threshold was met (free-ride).
        - Cooperate if threshold was missed by exactly one (pivot player).
        - Defect if threshold is clearly unattainable (minimizes loss).
    - Final Round: Always defects (no future reciprocity).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if self.m > self.n or self.m <= 1:
            return Action.D
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.r - 1:
            return Action.D
        my_prev_action = history.my_actions[-1]
        c_prev = history.opponent_cooperators[-1] + (1 if my_prev_action else 0)
        if c_prev >= self.m:
            return Action.D
        elif c_prev == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_11(BaseStrategy):
    """
    Strategy: Conditional Reciprocity with Threshold Sensitivity.
    Prioritizes private gain while ensuring collective success by contributing
    only when the player is the marginal individual required to meet the 
    threshold (m), or on the very first round to initiate cooperation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.game_description.m
        total_rounds = self.game_description.n_rounds
        current_round = history.round_number
        prev_my_action = int(history.my_actions[-1])
        prev_opp_coop = int(history.opponent_cooperators[-1])
        cooperators_previous_round = prev_my_action + prev_opp_coop
        if current_round == total_rounds - 1:
            if cooperators_previous_round < m:
                return Action.C
            else:
                return Action.D
        if cooperators_previous_round >= m:
            return Action.D
        elif cooperators_previous_round == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_12(BaseStrategy):
    """
    Implements a 'Triggered Threshold' strategy for the Collective Risk Dilemma.
    1. Reward Inefficiency: Always defects if k <= 1.
    2. Cooperative Seeding: Always starts with C in round 0 (t=1).
    3. Reciprocal Adaptation:
       - If last round threshold met: Continue to cooperate (C).
       - If last round threshold missed: Defect (D).
       - Permanent Defection: If two consecutive rounds fail to meet the threshold, switch to D permanently.
       - Volatility Check: If success rate over last 3 rounds < 0.5, switch to D permanently.
    4. Opportunistic Exit: In the final round, only cooperate if the previous round met the threshold and k > 1.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.permanent_defection = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        k = self.game_description.k
        r = self.game_description.n_rounds
        t = history.round_number
        if k <= 1.0:
            return Action.D
        if t == 0:
            return Action.C
        if self.permanent_defection:
            return Action.D
        my_prev_action = history.my_actions[-1]
        prev_opp_coop = history.opponent_cooperators[-1]
        c_prev = 1 if my_prev_action else 0
        total_cooperators_prev = prev_opp_coop + c_prev
        threshold_met_prev = total_cooperators_prev >= m
        if t == r - 1:
            if threshold_met_prev and k > 1.0:
                return Action.C
            return Action.D
        if len(history.my_actions) >= 2:
            prev2_opp_coop = history.opponent_cooperators[-2]
            prev2_my_action = history.my_actions[-2]
            c_prev2 = 1 if prev2_my_action else 0
            threshold_met_prev2 = prev2_opp_coop + c_prev2 >= m
            if not threshold_met_prev and (not threshold_met_prev2):
                self.permanent_defection = True
                return Action.D
        if len(history.my_actions) >= 3:
            results = []
            for i in range(-3, 0):
                c = 1 if history.my_actions[i] else 0
                total = history.opponent_cooperators[i] + c
                results.append(1 if total >= m else 0)
            if sum(results) / 3 < 0.5:
                self.permanent_defection = True
                return Action.D
        if threshold_met_prev:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_13(BaseStrategy):
    """
    Implements a Conditional Tit-for-Tat with Threshold Sensitivity.
    
    Logic:
    - Round 1: Always Cooperate (C).
    - Final Round: Always Defect (D).
    - Intermediate Rounds:
        - If previous threshold met (C_total >= m):
            - If C_total > m: Defect (free-ride).
            - If C_total == m: Cooperate (maintain).
        - If previous threshold not met (C_total < m):
            - If my_action was D and C_total == m - 1: Cooperate (tip the scale).
            - Else: Defect.
            
    Note: 'C_total' (cooperators in group) = opponent_cooperators[t-1] + (1 if I played C else 0).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        if t == self.game_description.n_rounds - 1:
            return Action.D
        my_prev_action = history.my_actions[-1]
        prev_opponents_c = history.opponent_cooperators[-1]
        c_prev = prev_opponents_c + (1 if my_prev_action else 0)
        m = self.game_description.m
        if c_prev >= m:
            if c_prev > m:
                return Action.D
            else:
                return Action.C
        elif not my_prev_action:
            if c_prev == m - 1:
                return Action.C
            else:
                return Action.D
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_14(BaseStrategy):
    """
    Conditional Threshold Tit-for-Tat:
    - Round 0: Cooperate.
    - Final Round: Defect.
    - If previous round had surplus cooperators (>= m + 1): Defect.
    - If previous round had exactly m cooperators: 
      - If I cooperated, continue to cooperate (preserve threshold).
      - If I defected, continue to defect (free-ride).
    - If previous round failed (below m): Cooperate.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        m = self.game_description.m
        total_rounds = self.game_description.n_rounds
        current_round_index = history.round_number
        if current_round_index == total_rounds - 1:
            return Action.D
        if current_round_index == 0:
            return Action.C
        self_acted_c = bool(history.my_actions[-1])
        opp_cooperators = int(history.opponent_cooperators[-1])
        total_cooperators_prev = opp_cooperators + (1 if self_acted_c else 0)
        if total_cooperators_prev >= m + 1:
            return Action.D
        if total_cooperators_prev == m:
            if self_acted_c:
                return Action.C
            else:
                return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_15(BaseStrategy):
    """
    Implements the Threshold-Sensitive Opportunism strategy.
    
    This strategy behaves as follows:
    1. First Round: Always Cooperate (C).
    2. Final Round: Defects unless the threshold is nearly met (c_{t-1} >= m-1), 
       in which case it attempts a final pivotal contribution.
    3. Intermediate Rounds:
       - Over-performance (c_{t-1} > m): Defect to free-ride.
       - Threshold Met (c_{t-1} == m): Maintain previous action (Persistence).
       - Threshold Missed (c_{t-1} < m): Cooperate to restore the reward.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_idx = history.round_number
        if current_round_idx == 0:
            return Action.C
        last_action = history.my_actions[-1]
        last_round_opponents = history.opponent_cooperators[-1]
        total_cooperators_prev = last_round_opponents + (1 if last_action else 0)
        if current_round_idx == self.r - 1:
            if total_cooperators_prev >= self.m - 1:
                return Action.C
            else:
                return Action.D
        if total_cooperators_prev > self.m:
            return Action.D
        elif total_cooperators_prev >= self.m:
            return Action.C if last_action else Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_16(BaseStrategy):
    """
    Implements a Collective Risk Dilemma strategy utilizing phases:
    1. Cooperation init.
    2. Monitoring and Trust Score tracking.
    3. Opportunistic switching between defecting (when threshold met) and contributing (when needed).
    4. Terminal phase defection bias.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.trust_score = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        m = self.game_description.m
        last_idx = history.round_number - 1
        last_my_action = history.my_actions[last_idx]
        n_cooperators_total = history.opponent_cooperators[last_idx]
        s = n_cooperators_total - 1 if last_my_action else n_cooperators_total
        if s >= m:
            self.trust_score += 1
        elif s < m:
            self.trust_score = max(0, self.trust_score - 1)
        if history.round_number == r - 1:
            recent_threshold_met = True
            for i in range(1, 4):
                if history.round_number - i >= 0:
                    prev_idx = history.round_number - i
                    prev_my_action = history.my_actions[prev_idx]
                    prev_total = history.opponent_cooperators[prev_idx]
                    prev_s = prev_total - 1 if prev_my_action else prev_total
                    if prev_s < m:
                        recent_threshold_met = False
                        break
            if recent_threshold_met:
                return Action.D
            return Action.C if s < m - 1 else Action.D
        if s >= m:
            return Action.D
        elif s < m - 1:
            return Action.C
        elif self.trust_score > 0:
            return Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_17(BaseStrategy):
    """
    Implements the Threshold-Conditional Opportunism (TCO) strategy.
    
    TCO aims to maintain cooperation only when the collective threshold is at risk, 
    while defecting to maximize gains (free-riding) when the threshold is securely 
    met by other players. It reserves defection for the final round and reacts 
    dynamically to the robustness of the group's cooperation history.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = self.game_description.n_players
        self.m = self.game_description.m
        self.r = self.game_description.n_rounds
        self.is_high_risk_scenario = self.n - self.m <= 1

    def __call__(self, history: PlayerHistory) -> Action:
        round_idx = history.round_number
        if round_idx == self.r - 1:
            return Action.D
        if round_idx == 0:
            return Action.C
        if self.is_high_risk_scenario:
            return Action.C
        last_round_cooperators = int(history.opponent_cooperators[-1])
        last_total_cooperators = last_round_cooperators + (1 if history.my_actions[-1] else 0)
        last_my_action = history.my_actions[-1]
        if last_total_cooperators >= self.m + 1:
            return Action.D
        if last_total_cooperators == self.m:
            if last_my_action:
                return Action.D
            else:
                return Action.C
        return Action.C

class Strategy_OPPORTUNISTIC_18(BaseStrategy):
    """
    Implements a Collective Risk Dilemma strategy based on adaptive opportunism, 
    threshold sensitivity, and endgame defection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = self.game_description.n_players
        self.m = self.game_description.m
        self.k = self.game_description.k
        self.r = self.game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            if self.m / self.n <= 0.5:
                return Action.C
            else:
                return Action.D
        if history.round_number == self.r - 1:
            return Action.D
        my_prev_action = history.my_actions[-1]
        c_i_prev = 1 if my_prev_action else 0
        last_C_obs = history.opponent_cooperators[-1] + c_i_prev
        D_crit = self.m - last_C_obs
        if last_C_obs >= self.m + 1:
            return Action.D
        if last_C_obs == self.m:
            if history.round_number >= 2:
                prev_my_act = history.my_actions[-2]
                prev_c_i = 1 if prev_my_act else 0
                prev_prev_C_obs = history.opponent_cooperators[-2] + prev_c_i
                if prev_prev_C_obs == self.m:
                    return Action.C
                else:
                    return Action.D
            else:
                return Action.D
        if last_C_obs < self.m:
            if D_crit == 1:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_19(BaseStrategy):
    """
    Threshold-Conditional Opportunism:
    - Round 1: Cooperate.
    - Rounds 2 to r-1:
        - If previously Cooperated: Continue if threshold met, else Defect.
        - If previously Defected: Always Defect (unless probing).
    - Probe Mechanism: If defecting for N=2 consecutive rounds, attempt one Cooperator move.
    - Final Round: Always Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_defects = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if self.consecutive_defects >= 2:
            self.consecutive_defects = 0
            return Action.C
        last_action = history.my_actions[-1]
        last_opponents_coop = history.opponent_cooperators[-1]
        my_last_val = 1 if last_action else 0
        total_cooperators = last_opponents_coop + my_last_val
        threshold_met = total_cooperators >= self.game_description.m
        if last_action:
            if threshold_met:
                return Action.C
            else:
                self.consecutive_defects += 1
                return Action.D
        else:
            self.consecutive_defects += 1
            return Action.D

class Strategy_OPPORTUNISTIC_20(BaseStrategy):
    """
    Implements an Opportunistic Threshold Tracking strategy:
    - Round 1: Defaults to Defect (D) to observe initial population behavior.
    - Subsequent rounds:
        - If the threshold of m cooperators is already met by others (C_obs >= m), free-ride (D).
        - If the player is the 'pivotal' voter needed to reach the threshold (C_obs == m - 1), 
          contribute (C) only if the payoff incentive k > 1.
        - If the threshold is unreachable (C_obs < m - 1), do not waste the contribution (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        m = self.game_description.m
        k = self.game_description.k
        my_prev_action = history.my_actions[-1]
        c_i = 1 if my_prev_action == Action.C else 0
        c_obs = history.opponent_cooperators[-1] + c_i
        if c_obs >= m:
            return Action.D
        if c_obs == m - 1:
            return Action.C if k > 1 else Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_21(BaseStrategy):
    """
    Conditional Tit-for-Tat with Threshold Sensitivity.
    
    Probes in round 1. In intermediate rounds, it balances cooperation to reach threshold 
    m with free-riding when m is exceeded. It abandons cooperation after sustained 
    failures (failure_streak >= 2). In the final round, it plays D if m was met 
    previously, or C/D based on whether recovery is mathematically possible.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.failure_streak = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        last_my_action = 1 if history.my_actions[-1] else 0
        last_N_c = history.opponent_cooperators[-1] + last_my_action
        if last_N_c < m:
            self.failure_streak += 1
        else:
            self.failure_streak = 0
        if history.round_number == r - 1:
            if last_N_c >= m:
                return Action.D
            return Action.C if last_N_c >= m - 1 else Action.D
        if self.failure_streak >= 2:
            return Action.D
        if last_N_c >= m + 1:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_22(BaseStrategy):
    """
    A conditional cooperator strategy with a bias toward defection (free-riding).
    It aims to hit the contribution threshold exactly when necessary, while
    occasionally attempting to recover systemic failures with tit-for-tat signals.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.recovery_mode_counter = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        t = history.round_number + 1
        if t == 1:
            return Action.C if m / n > 0.5 else Action.D
        prev_idx = history.round_number - 1
        last_cooperators = history.opponent_cooperators[prev_idx]
        last_my_action = history.my_actions[prev_idx]
        total_coop = last_cooperators + int(last_my_action)
        if self.recovery_mode_counter > 0:
            self.recovery_mode_counter -= 1
            return Action.C if last_cooperators >= m - 1 else Action.D
        if t > 3:
            hist_indices = [-1, -2, -3]
            failures = 0
            for idx in hist_indices:
                opp_c = history.opponent_cooperators[idx]
                my_c = int(history.my_actions[idx])
                if opp_c + my_c < m:
                    failures += 1
            if failures >= 3:
                self.recovery_mode_counter = 2
                return Action.C
        if t == r:
            return Action.C if total_coop >= m - 1 else Action.D
        if total_coop >= m:
            return Action.D
        elif total_coop == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_23(BaseStrategy):
    """
    Threshold-Triggered Opportunism:
    - Phase 1: Cooperates in round 1 to test cooperation.
    - Phase 2: Adaptive Opportunism (Rounds 2 to r-1).
        - If previous round >= m cooperators:
            - Cooperate if exactly m (maintain threshold).
            - Defect if > m (free-ride).
        - If previous round < m cooperators:
            - Attempt to recover threshold by cooperating.
            - If stagnation detected (3+ consecutive rounds < m), switch to pure Defect.
            - Implements a retry counter for consecutive attempted cooperation during threshold failure.
    - Phase 3: Defect in the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_under_m = 0
        self.consecutive_coop_attempts = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if m <= 0 or m > n:
            return Action.D
        if current_round > 0 and history.opponent_cooperators[-1] < m:
            self.consecutive_under_m += 1
        else:
            self.consecutive_under_m = 0
        if self.consecutive_under_m > 3:
            return Action.D
        if current_round == r - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        if prev_cooperators >= m:
            self.consecutive_coop_attempts = 0
            if prev_cooperators == m:
                return Action.C
            else:
                return Action.D
        else:
            self.consecutive_coop_attempts += 1
            if self.consecutive_coop_attempts > 2:
                self.consecutive_coop_attempts = 0
                return Action.D
            return Action.C

class Strategy_OPPORTUNISTIC_24(BaseStrategy):
    """
    Threshold-Targeting Opportunism:
    A strategy that acts as a conditional cooperator. 
    - Round 1: Always cooperates to signal.
    - Subsequent rounds:
        - If previous round cooperators S >= m: Free-ride (Defect).
        - If S == m - 1: Cooperate (provide marginal contribution).
        - If S < m - 1: Defect (ignore unreachable threshold).
    - Systemic Defection Edge Case: If the group fails to reach the threshold for two 
      consecutive rounds (S < m), switch to unconditional defection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0
        self.is_systemic_defection_mode = False

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round >= 2:
            prev_s = history.opponent_cooperators[-1]
            prev_prev_s = history.opponent_cooperators[-2]
            if prev_s < self.game_description.m and prev_prev_s < self.game_description.m:
                self.is_systemic_defection_mode = True
        if self.is_systemic_defection_mode:
            return Action.D
        my_prev_action = history.my_actions[-1]
        my_c_val = 1 if my_prev_action else 0
        s_total = history.opponent_cooperators[-1] + my_c_val
        m = self.game_description.m
        if s_total >= m:
            return Action.D
        elif s_total == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_25(BaseStrategy):
    """
    Implements a Threshold-Targeting Tit-for-Tat strategy.
    
    This strategy prioritizes immediate payoff maximization while maintaining the collective
    cooperative threshold. It dynamically adjusts contributions based on whether the
    group successfully triggered the collective reward in the previous round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.k = game_description.k
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if self.k <= 1.0:
            return Action.D
        if history.round_number == self.r - 1:
            return Action.D
        if self.m == self.n:
            return Action.C
        if history.round_number == 0:
            if self.n - 1 >= self.m:
                return Action.C
            return Action.D
        last_round_idx = history.round_number - 1
        my_last_action = history.my_actions[last_round_idx]
        opp_coop_count = history.opponent_cooperators[last_round_idx]
        total_cooperators = opp_coop_count + (1 if my_last_action else 0)
        if total_cooperators >= self.m:
            if not my_last_action and total_cooperators == self.m:
                return Action.C
            return Action.D
        else:
            if total_cooperators == self.m - 1:
                return Action.C
            return Action.D

class Strategy_OPPORTUNISTIC_26(BaseStrategy):
    """
    Threshold-Sensitive Tit-for-Tat (TSTFT) Strategy:
    - Starts by cooperating to signal willingness to participate.
    - If the previous round met the threshold (m cooperators), it pivots to defection to maximize payoff.
    - If the threshold was not met, it contributes (Cooperate) to help reach it.
    - In the final round, it always defects, as the marginal benefit of contributing is zero
      relative to future payoffs (since there are no future payoffs).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        threshold = self.game_description.m
        if current_round == 0:
            return Action.C
        if current_round == total_rounds - 1:
            return Action.D
        my_prev_action = history.my_actions[-1]
        opp_prev_coop_count = history.opponent_cooperators[-1]
        my_prev_val = 1 if my_prev_action else 0
        total_prev_cooperators = my_prev_val + opp_prev_coop_count
        if total_prev_cooperators >= threshold:
            return Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_27(BaseStrategy):
    """
    Implements a conditional tit-for-tat strategy with opportunistic thresholding.
    Prioritizes cooperation to reach the threshold 'm', but defects when the threshold 
    is safely exceeded or when the game is in its final round. Includes an 
    adaptive mechanism to kickstart cooperation if the recent trend drops below threshold.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k
        self.kickstart_active = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.r - 1:
            return Action.D
        if self.r < 3:
            return Action.C
        if self.n == self.m:
            return Action.C
        my_prev_action = history.my_actions[-1]
        opp_coop_prev = history.opponent_cooperators[-1]
        s_prev = (1 if my_prev_action else 0) + opp_coop_prev
        s_all = []
        for i in range(history.round_number):
            s_val = (1 if history.my_actions[i] else 0) + history.opponent_cooperators[i]
            s_all.append(s_val)
        c_trend = np.mean(s_all[-3:]) if len(s_all) >= 1 else 0
        if len(s_all) >= 2:
            if s_all[-1] < self.m - 1 and s_all[-2] < self.m - 1:
                self.kickstart_active = True
        if self.kickstart_active:
            self.kickstart_active = False
            return Action.C
        if s_prev < self.m:
            p = min(1.0, self.m / (s_prev + 1))
            if random.random() < p:
                return Action.C
            return Action.D
        if s_prev >= self.m:
            if s_prev > self.m:
                return Action.D
            if s_prev == self.m:
                if my_prev_action:
                    return Action.D
                return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_28(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that dynamically adjusts cooperation 
    based on previous rounds' turnout, aiming to meet the threshold 'm' efficiently 
    while exploiting the group once 'm' is secured, and punishing non-responsive 
    behavior.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.consecutive_zeros = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_my_action = int(history.my_actions[-1])
        prev_others_cooperated = history.opponent_cooperators[-1]
        prev_total_cooperators = prev_others_cooperated + prev_my_action
        if prev_total_cooperators == 0:
            self.consecutive_zeros += 1
        else:
            self.consecutive_zeros = 0
        if history.round_number >= 3 and self.consecutive_zeros >= 3:
            return Action.D
        if prev_total_cooperators >= self.m:
            return Action.D
        needed = self.m - prev_total_cooperators
        denom = self.n - prev_total_cooperators
        if denom <= 0:
            return Action.D
        probability_c = max(0.0, min(1.0, needed / denom))
        if random.random() < probability_c:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_29(BaseStrategy):
    """
    Implements the Conditional Threshold-Opportunist strategy.
    
    This strategy aims to maximize payoffs by contributing just enough to reach 
    the threshold when necessary, free-riding when the threshold is safe, 
    and conserving resources when the group is uncooperative.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_underperformance = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        k = self.game_description.k
        r = self.game_description.n_rounds
        t = history.round_number
        if k <= 1.0:
            return Action.D
        if t == 0:
            if random.random() < m / n:
                return Action.C
            return Action.D
        last_my_action = history.my_actions[-1]
        last_my_contrib = 1 if last_my_action else 0
        last_total_cooperators = history.opponent_cooperators[-1] + last_my_contrib
        if last_total_cooperators < m - 1:
            self.consecutive_underperformance += 1
        else:
            self.consecutive_underperformance = 0
        if self.consecutive_underperformance >= 3:
            return Action.D
        if t == r - 1:
            return Action.D
        threshold_met = last_total_cooperators >= m
        if threshold_met:
            return Action.D
        else:
            if last_total_cooperators == m - 1:
                return Action.C
            return Action.D

class Strategy_OPPORTUNISTIC_30(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that employs Tit-for-Tat with Threshold Sensitivity.
    It cooperates in the first round, defects in the last round, and dynamically adjusts
    cooperation based on whether the collective threshold (m) was met in the previous round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.n_rounds - 1:
            return Action.D
        last_round_idx = -1
        last_opponent_c_count = history.opponent_cooperators[last_round_idx]
        last_my_action = history.my_actions[last_round_idx]
        total_cooperators_last_round = last_opponent_c_count + (1 if last_my_action else 0)
        if total_cooperators_last_round >= self.m:
            return Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_31(BaseStrategy):
    """
    A strategy that defects in the first round. In subsequent rounds, it monitors the
    total number of cooperators. It only cooperates if doing so is both necessary
    and sufficient to reach the cooperation threshold (m) and secure the reward (k).
    Otherwise, it defects to free-ride or conserve resources.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        my_last_action = 1 if history.my_actions[-1] else 0
        opponents_last_coop = history.opponent_cooperators[-1]
        total_cooperators_last_round = my_last_action + opponents_last_coop
        m = self.game_description.m
        if opponents_last_coop >= m:
            return Action.D
        elif opponents_last_coop == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_32(BaseStrategy):
    """
    Implements Threshold-Conditional Opportunism:
    - Round 1: Cooperate (C) to establish baseline.
    - Final Round: Always Defect (D) to maximize terminal payoff.
    - Intermediate Rounds:
        - If previous round failed (C < m): Defect (D).
        - If previous round succeeded (C >= m):
            - If C > m (surplus): Defect (D).
            - If C == m (critical): Cooperate (C) to maintain threshold.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == 0:
            return Action.C
        if current_round == total_rounds - 1:
            return Action.D
        last_action_c = bool(history.my_actions[-1])
        last_opponent_coops = int(history.opponent_cooperators[-1])
        total_cooperators_prev = last_opponent_coops + (1 if last_action_c else 0)
        if total_cooperators_prev < m:
            return Action.D
        elif total_cooperators_prev > m:
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_5(BaseStrategy):
    """
    A conditional cooperation strategy for the Collective Risk Dilemma.
    
    Logic Summary:
    - Round 1: Calculate probability P(M_1 >= m-1) assuming uniform 0.5 cooperation prior.
      Contribute if k * P > 1.
    - Subsequent Rounds (t < r):
      - If threshold was met in previous round: Contribute (to sustain).
      - Otherwise: Defect (to save endowment).
      - Special Case (Threshold Vulnerability): If exactly m-1 others cooperated in the previous 
        round, contribute regardless of history to secure the collective threshold.
    - Final Round (t = r): Always Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description

    def _nCr(self, n, r):
        if r < 0 or r > n:
            return 0
        return math.factorial(n) // (math.factorial(r) * math.factorial(n - r))

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game.n_players
        m = self.game.m
        k = self.game.k
        r = self.game.n_rounds
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        if current_round == 0:
            n_opponents = n - 1
            needed = m - 1
            sum_combos = 0
            for i in range(needed, n_opponents + 1):
                sum_combos += self._nCr(n_opponents, i)
            prob_success = sum_combos * 0.5 ** n_opponents
            return Action.C if k * prob_success > 1.0 else Action.D
        last_total_opponents_coop = history.opponent_cooperators[-1]
        last_my_action = 1 if history.my_actions[-1] else 0
        last_total_coop = last_total_opponents_coop + last_my_action
        if last_total_opponents_coop == m - 1:
            return Action.C
        threshold_met = last_total_coop >= m
        if threshold_met:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_6(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that employs a conditional
    cooperation model:
    - Phase 1: Always Cooperate (C) in the first round to test the environment.
    - Phase 2: Adapt based on the previous round's outcome to optimize payoff
      by balancing the threshold requirement 'm' against personal gain.
    - Phase 3: Defect (D) in the final round as there are no future consequences.
    - Safety check: If the threshold is mathematically impossible to reach given
      the number of active cooperators, default to Defect (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description
        self.n = self.game.n_players
        self.m = self.game.m
        self.r = self.game.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == self.r - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        prev_my_c = history.my_actions[-1]
        prev_opp_c = history.opponent_cooperators[-1]
        my_prev_val = 1 if prev_my_c else 0
        total_cooperators = prev_opp_c + my_prev_val
        if prev_opp_c < self.m - 1:
            return Action.D
        if total_cooperators >= self.m:
            if prev_my_c:
                if prev_opp_c >= self.m:
                    return Action.D
                else:
                    return Action.C
            else:
                return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_7(BaseStrategy):
    """
    Implements a Threshold-Targeted Tit-for-Tat strategy with probe 
    mechanisms and near-miss recovery for the Collective Risk Dilemma.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = self.game_description.n_players
        self.m = self.game_description.m
        self.r = self.game_description.n_rounds
        self.probe_interval = math.ceil(self.r / 4)

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_idx = history.round_number
        if current_round_idx == 0:
            return Action.D
        if current_round_idx == self.r - 1:
            return Action.D
        my_prev_action = history.my_actions[-1]
        my_prev_c = 1 if my_prev_action == Action.C else 0
        s_prev = history.opponent_cooperators[-1] + my_prev_c
        if current_round_idx > 0 and current_round_idx % self.probe_interval == 0:
            return Action.C
        if s_prev == self.m - 1 and my_prev_action == Action.D:
            return Action.C
        if s_prev >= self.m:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_8(BaseStrategy):
    """
    Conditional Threshold Thresholding (CTT) Strategy.
    
    Logic:
    - Initialization: Cooperate if the expected utility of cooperation is positive
      based on a uniform distribution assumption.
    - Iterative Rounds: Adjusts between exploiting the threshold (if m-buffer exists)
      or testing the group if the failure rate is high.
    - Terminal Phase: Always defects to extract maximum remaining payoff.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        n = self.game_description.n_players
        m = self.game_description.m
        k = self.game_description.k
        self.init_action = Action.C if k - 1 > (n - m) / n else Action.D

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return self.init_action
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        c_last = history.opponent_cooperators[-1]
        m = self.game_description.m
        my_last_action = 1 if history.my_actions[-1] else 0
        if c_last >= m:
            if c_last > m:
                return Action.C
            else:
                return Action.D
        elif my_last_action == 1:
            return Action.D
        else:
            recent_window = 3
            start_index = max(0, history.round_number - recent_window)
            relevant_history = history.opponent_cooperators[start_index:]
            failures = 0
            for count in relevant_history:
                if count < m:
                    failures += 1
            if failures >= 2:
                return Action.C
            else:
                return Action.D

class Strategy_INDIVIDUALISTIC_9(BaseStrategy):
    """
    A strategy that maximizes utility in a Collective Risk Dilemma by adjusting 
    contributions based on the threshold (m) and the previous round's outcome.
    It balances conditional cooperation with free-riding when the reward is 
    secured or unattainable.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C if m / n <= 0.5 else Action.D
        prev_C = history.opponent_cooperators[-1] + (1 if history.my_actions[-1] else 0)
        prev_my_action = Action.C if history.my_actions[-1] else Action.D
        if current_round == r - 1:
            if prev_C >= m - 1:
                return Action.C
            else:
                return Action.D
        if prev_my_action == Action.C:
            if prev_C >= m - 1:
                return Action.C
            else:
                return Action.D
        elif prev_C == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_10(BaseStrategy):
    """
    Implements Threshold-Responsive Tit-for-Tat with Discounted Forgiveness.
    
    Prioritizes securing the threshold reward m while minimizing individual contribution costs,
    adjusting cooperation based on the collective behavior observed in the previous round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number + 1
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        n = self.game_description.n_players
        if current_round == 1:
            return Action.C
        last_action_c = bool(history.my_actions[-1])
        prev_nc = history.opponent_cooperators[-1] + (1 if last_action_c else 0)
        if current_round == total_rounds:
            if prev_nc >= m - 1:
                return Action.C
            else:
                return Action.D
        if prev_nc >= m:
            if last_action_c:
                return Action.D
            else:
                if random.random() < m / n:
                    return Action.C
                return Action.D
        if prev_nc == m - 1:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_11(BaseStrategy):
    """
    Adaptive Threshold Monitoring Strategy:
    Monitors the previous round's cooperation count (O_{t-1}).
    - If O_{t-1} >= m, defect to exploit the threshold being met.
    - If O_{t-1} == m - 1, cooperate to pivot the group over the threshold.
    - Otherwise, defect to minimize losses.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if self.k - 1 <= 1e-09:
            return Action.D
        if history.round_number == 0:
            if self.n - 1 >= self.m:
                return Action.C
            return Action.D
        last_round_idx = history.round_number - 1
        others_cooperated = history.opponent_cooperators[last_round_idx]
        i_cooperated = 1 if history.my_actions[last_round_idx] else 0
        total_cooperators = others_cooperated + i_cooperated
        if total_cooperators >= self.m:
            return Action.D
        elif total_cooperators == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_12(BaseStrategy):
    """
    Implements a responsive adaptive coordination strategy for the Collective Risk Dilemma.
    Tests the group in round 1, then dynamically adjusts contributions based on whether 
    the cooperation threshold (m) was met in the previous round, with an end-game 
    trigger to capture rewards if pivotal.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.T = game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_round_idx = history.round_number - 1
        num_prev_cooperators = history.opponent_cooperators[prev_round_idx]
        my_prev_action_is_c = bool(history.my_actions[prev_round_idx])
        n_c = num_prev_cooperators + (1 if my_prev_action_is_c else 0)
        action = Action.D
        if n_c >= self.T:
            action = Action.C if my_prev_action_is_c else Action.D
        else:
            deficit = self.T - n_c
            if deficit == 1:
                action = Action.C
            else:
                action = Action.D
        if history.round_number == self.game_description.n_rounds:
            if action == Action.D and n_c == self.T - 1:
                return Action.C
        return action

class Strategy_INDIVIDUALISTIC_13(BaseStrategy):
    """
    Adaptive Threshold-Trigger (ATT) Strategy:
    - Initially cooperates.
    - Tracks aggregate cooperation (S) from the previous round.
    - If S >= m:
        - If S > m: Defect (exploit surplus).
        - If S == m: Cooperate (maintain stability).
    - If S < m:
        - If S == m - 1: Cooperate (try to rescue).
        - If S < m - 1: Defect (sunk cost).
    - Terminal Phase (t=r): Always Defect.
    - Edge Case 1: If threshold fails, signal intolerance by Defecting for one round.
    - Edge Case 2: If π_i > 1 + k (i.e., others defected while threshold was met), Defect for one round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.punishing = False
        self.was_punishing = False

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n = self.game_description.n_players
        m = self.game_description.m
        k = self.game_description.k
        if current_round == 0:
            return Action.C
        if current_round == self.game_description.n_rounds - 1:
            return Action.D
        prev_my_action = 1 if history.my_actions[-1] else 0
        prev_payoff = history.my_payoffs[-1]
        prev_S = history.opponent_cooperators[-1] + prev_my_action
        if prev_S >= m and prev_my_action == 0 and (prev_payoff > 1):
            self.punishing = True
        if prev_S < m and (not self.was_punishing):
            self.punishing = True
        else:
            self.was_punishing = False
        if self.punishing:
            self.punishing = False
            self.was_punishing = True
            return Action.D
        if prev_S >= m:
            if prev_S > m:
                return Action.D
            else:
                return Action.C
        elif prev_S == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_14(BaseStrategy):
    """
    Implements a conditional threshold strategy for the Collective Risk Dilemma.
    - Round 1: Defect.
    - Final Round: Defect.
    - Intermediate Rounds: If the threshold m was met by the group in the previous 
      round (including own contribution), cooperate if necessary or sustainable.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        round_t = history.round_number
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        if round_t == r - 1:
            return Action.D
        if round_t == 0:
            return Action.D
        prev_opp_c = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        my_c = 1 if my_prev_action else 0
        total_prev_coop = prev_opp_c + my_c
        if total_prev_coop >= m:
            if my_c == 1:
                return Action.C
            elif total_prev_coop > m:
                return Action.C
            else:
                return Action.D
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_15(BaseStrategy):
    """
    Implements a strategy based on threshold-conditional reciprocity:
    - Round 1: Defect.
    - Rounds 2 to r-1:
        - If previous round threshold met (C >= m): Cooperate (if previously defected, switch; if cooperated, repeat).
        - If previous round threshold failed (C < m):
            - If C == m - 1: Cooperate (to hit threshold).
            - Otherwise: Defect.
    - Terminal Round r:
        - If previous round threshold met: Cooperate.
        - If previous round threshold failed: Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        prev_idx = history.round_number - 1
        my_prev_action = history.my_actions[prev_idx]
        my_c_prev = 1 if my_prev_action else 0
        total_c_prev = history.opponent_cooperators[prev_idx] + my_c_prev
        if history.round_number == self.r - 1:
            if total_c_prev >= self.m:
                return Action.C
            else:
                return Action.D
        if total_c_prev >= self.m:
            return Action.C
        elif total_c_prev == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_16(BaseStrategy):
    """
    Implements a strategy for the Collective Risk Dilemma that alternates 
    based on the observed cooperation threshold m. It prioritizes defection
    in early rounds, attempts to signal cooperation when the threshold is 
    not met, and exploits the system by defecting when the threshold is met.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.T = game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.D
        last_my_action = history.my_actions[-1]
        last_opponent_coops = history.opponent_cooperators[-1]
        last_total_coops = last_opponent_coops + (1 if last_my_action else 0)
        if t == self.game_description.n_rounds - 1:
            if last_total_coops < self.T and self.game_description.k > 1:
                return Action.C
            return Action.D
        if last_total_coops == self.T:
            return Action.D
        if last_total_coops == self.T - 1:
            if last_my_action:
                return Action.D
            else:
                return Action.C
        if last_total_coops >= self.T:
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_17(BaseStrategy):
    """
    Threshold-Responsive Trigger (TRT):
    A dynamic strategy that cooperates initially, then adapts based on the previous round's 
    cooperation levels relative to the threshold 'm'. It attempts to act as the marginal
    contributor only when necessary, tests for free-riding potential when the threshold 
    is met, and resets cooperation when thresholds are missed to encourage group coordination.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.is_indifferent = game_description.k <= 1

    def __call__(self, history: PlayerHistory) -> Action:
        if self.is_indifferent:
            return Action.D
        current_round = history.round_number
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        if current_round == 0:
            return Action.C
        prev_my_action_int = 1 if history.my_actions[-1] else 0
        prev_cooperators = history.opponent_cooperators[-1] + prev_my_action_int
        c_prev = prev_cooperators
        s_prev = prev_my_action_int
        if current_round == r - 1:
            if c_prev >= m - 1:
                return Action.C
            else:
                return Action.D
        if c_prev >= m:
            return Action.D
        if c_prev == m - 1 and s_prev == 0:
            return Action.C
        return Action.C

class Strategy_INDIVIDUALISTIC_18(BaseStrategy):
    """
    A Trigger-Threshold strategy for Collective Risk Dilemmas. 
    Defects in round 1 and the final round. Uses a binomial probability model 
    based on historical cooperation rates to determine if marginal cooperation 
    is utility-maximizing in intermediate rounds, with specific adjustments 
    for past outcomes.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.stagnation_counter = 0

    def _binom_pmf(self, n: int, k: int, p: float) -> float:
        """Calculate Binomial PMF: P(X = k) = (n choose k) * p^k * (1-p)^(n-k)."""
        if k < 0 or k > n:
            return 0.0
        comb = math.factorial(n) / (math.factorial(k) * math.factorial(n - k))
        return comb * p ** k * (1 - p) ** (n - k)

    def _binom_cdf_ge(self, n: int, m: int, p: float) -> float:
        """Calculate P(X >= m) = sum from k=m to n of Binomial PMF."""
        if p == 0:
            return 1.0 if m == 0 else 0.0
        if p == 1:
            return 1.0 if m <= n else 0.0
        return sum((self._binom_pmf(n, i, p) for i in range(m, n + 1)))

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.desc.n_players
        m = self.desc.m
        r = self.desc.n_rounds
        k = self.desc.k
        current_round = history.round_number
        if k <= 1:
            return Action.D
        if current_round == r - 1:
            return Action.D
        if current_round == 0:
            return Action.D
        total_cooperators_sum = sum((history.opponent_cooperators[i] + (1 if history.my_actions[i] else 0) for i in range(current_round)))
        total_slots = n * current_round
        rho = total_cooperators_sum / total_slots if total_slots > 0 else 0.0
        if history.opponent_cooperators[-1] + (1 if history.my_actions[-1] else 0) < m:
            self.stagnation_counter += 1
        else:
            self.stagnation_counter = 0
        if self.stagnation_counter >= n:
            return Action.D
        last_coop_others = history.opponent_cooperators[-1]
        last_i_coop = history.my_actions[-1]
        total_last = last_coop_others + (1 if last_i_coop else 0)
        if total_last >= m and last_i_coop:
            return Action.C
        if total_last == m - 1 and last_i_coop:
            return Action.D
        if total_last >= m and (not last_i_coop):
            return Action.D
        p_threshold_if_c = self._binom_cdf_ge(n - 1, m - 1, rho)
        p_threshold_if_d = self._binom_cdf_ge(n - 1, m, rho)
        lhs = (k - 1) * p_threshold_if_c
        rhs = 1 - k * p_threshold_if_d
        if lhs > rhs:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_19(BaseStrategy):
    """
    A conditional-threshold strategy for the Collective Risk Dilemma.
    
    The strategy aims to maximize individual payoff by:
    1. Playing 'C' in the first round.
    2. Playing 'D' if the previous round's cooperation count (N_c) met or exceeded the threshold 'm'.
    3. Playing 'C' if the previous round's cooperation count was exactly 'm - 1'.
    4. Playing 'D' if the previous round's cooperation count was less than 'm - 1' (conserving endowment).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        last_my_action = history.my_actions[-1]
        last_opponent_coop_count = history.opponent_cooperators[-1]
        my_c_last = 1 if last_my_action else 0
        n_c = last_opponent_coop_count + my_c_last
        m = self.game_description.m
        if n_c >= m:
            return Action.D
        elif n_c == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_20(BaseStrategy):
    """
    Implements a Tit-for-Tat variant with a threshold-monitoring mechanism.
    It attempts to secure the collective reward (k) by cooperating when the 
    threshold (m) is not met, and attempts to free-ride (defect) when the 
    threshold is safely met, while adjusting based on its own previous action 
    to maintain a cooperative baseline.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        m = self.game_description.m
        k = self.game_description.k
        total_rounds = self.game_description.n_rounds
        my_prev_action_bool = history.my_actions[-1]
        my_prev_action_val = 1 if my_prev_action_bool else 0
        c_observed_prev_round = history.opponent_cooperators[-1] + my_prev_action_val
        current_round_idx = history.round_number
        last_round_idx = total_rounds - 1
        if current_round_idx == last_round_idx:
            if c_observed_prev_round >= m:
                return Action.D
            else:
                if k > 1:
                    return Action.C
                return Action.D
        if c_observed_prev_round >= m:
            if my_prev_action_bool:
                return Action.D
            else:
                return Action.C
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_21(BaseStrategy):
    """
    A strategic agent for the Collective Risk Dilemma that balances cooperation
    based on immediate past results, a rolling 3-round window of performance,
    and a global threshold condition.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if self.m / self.n > 0.75:
            return Action.D
        if current_round >= 3:
            recent_cooperators = history.opponent_cooperators[-3:]
            my_last_3 = [int(a) for a in history.my_actions[-3:]]
            total_last_3 = [c + m_act for c, m_act in zip(recent_cooperators[-len(my_last_3):], my_last_3)]
            avg_cooperators = sum(total_last_3) / len(total_last_3)
            if avg_cooperators < self.m - 1:
                return Action.D
        if current_round == 0:
            return Action.C
        prev_my_action = int(history.my_actions[-1])
        prev_num_c = history.opponent_cooperators[-1] + prev_my_action
        if current_round == self.r - 1:
            if prev_num_c >= self.m + 1:
                return Action.D
            elif prev_num_c == self.m:
                return Action.D
            else:
                if prev_num_c >= self.m - 1:
                    return Action.C
                return Action.D
        if prev_num_c >= self.m:
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_22(BaseStrategy):
    """
    Threshold-Optimization Tit-for-Tat strategy.
    Plays Defect in the first round to establish a baseline of cooperation.
    In subsequent rounds, if the previous total cooperation count was exactly m-1,
    it contributes to trigger the reward. Otherwise, it defects to minimize costs.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        prev_my_action = history.my_actions[-1]
        prev_opp_coop = history.opponent_cooperators[-1]
        total_cooperators_prev = (1 if prev_my_action else 0) + prev_opp_coop
        m = self.game_description.m
        if total_cooperators_prev >= m:
            return Action.D
        elif total_cooperators_prev == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_23(BaseStrategy):
    """
    A strategy that initiates cooperation and then pivots between cooperating and 
    defecting based on the minimum necessary contributions to reach the collective threshold.
    
    Logic:
    1. Always Cooperate on the first round.
    2. In subsequent rounds, determine if the threshold (m) is achievable based on 
       previous round performance:
       - If previous contribution by others >= threshold adjusted for my last action, 
         defect (free ride).
       - If others are close to threshold (within 2 of m), cooperate (pivotal role).
       - Otherwise, defect (threshold is too far to reach).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.m = game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_n_coop = history.opponent_cooperators[-1]
        prev_my_action = history.my_actions[-1]
        mnc = self.m - 1 if prev_my_action else self.m
        if prev_n_coop >= mnc:
            return Action.D
        elif prev_n_coop >= self.m - 2:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_24(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that employs a conditional
    cooperation model. It starts by defecting to observe the group, then 
    conditionally cooperates only if it can act as the pivotal player 
    to reach the threshold m. It abandons cooperation if the group 
    fails to coordinate.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k
        self.cooperation_threshold = self.m
        self.last_action_was_cooperation = False
        self.given_up = False

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            self.last_action_was_cooperation = False
            return Action.D
        if self.given_up:
            self.last_action_was_cooperation = False
            return Action.D
        if current_round == self.r - 1:
            c_obs = int(history.opponent_cooperators[-1])
            last_action_c = self.last_action_was_cooperation
            prev_group_c = c_obs + (1 if last_action_c else 0)
            if prev_group_c == self.m - 1:
                self.last_action_was_cooperation = True
                return Action.C
            self.last_action_was_cooperation = False
            return Action.D
        c_obs = int(history.opponent_cooperators[-1])
        last_action_c = self.last_action_was_cooperation
        prev_total_c = c_obs + (1 if last_action_c else 0)
        if prev_total_c >= self.m:
            action = Action.D
        elif self.m - prev_total_c == 1:
            action = Action.C
        else:
            action = Action.D
        if last_action_c:
            if c_obs >= self.m - 1:
                action = Action.D
            elif prev_total_c < self.m:
                self.given_up = True
                action = Action.D
        self.last_action_was_cooperation = action == Action.C
        return action

class Strategy_INDIVIDUALISTIC_25(BaseStrategy):
    """
    A threshold-tracking strategy for the Collective Risk Dilemma.
    
    The strategy adopts a conditional cooperation approach. It initially defects to
    gather information. In subsequent rounds, it tracks the history of cooperation.
    It calculates the moving average of cooperators and cooperates if the group
    has historically demonstrated the capacity to reach the threshold `m`.
    
    Edge cases handled:
    - Failure to Coordinate: If the threshold is not met for 3 consecutive rounds 
      despite some cooperation, the strategy triggers an observation reset (2 rounds of defection).
    - Threshold Saliency: If k is high (k > n - 1), it implements a "Trigger Period" 
      cooperating for 2 rounds to attempt to seed cooperation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.failure_counter = 0
        self.reset_rounds_remaining = 0
        self.trigger_rounds_remaining = 0

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.D
        c_i_history = history.my_actions.astype(int)
        c_opp_history = history.opponent_cooperators
        c_total_history = c_i_history + c_opp_history
        last_total = c_total_history[-1]
        if last_total < self.game_description.m:
            self.failure_counter += 1
        else:
            self.failure_counter = 0
        if self.failure_counter >= 3:
            self.reset_rounds_remaining = 2
            self.failure_counter = 0
        if self.reset_rounds_remaining > 0:
            self.reset_rounds_remaining -= 1
            return Action.D
        if self.game_description.k > self.game_description.n_players - 1:
            if self.trigger_rounds_remaining > 0:
                self.trigger_rounds_remaining -= 1
                return Action.C
            if t < 3:
                self.trigger_rounds_remaining = 1
                return Action.C
        avg_cooperation = np.mean(c_total_history)
        if avg_cooperation >= self.game_description.m:
            if t == self.game_description.n_rounds - 1:
                return Action.C if avg_cooperation >= self.game_description.m else Action.D
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_26(BaseStrategy):
    """
    Implements the 'Threshold-Guard' strategy for a Collective Risk Dilemma.
    
    Strategy Logic:
    1. t=1 (Round 0): Always Cooperate (C).
    2. t=r (Final Round): Always Defect (D).
    3. t=1 < t < r:
       - If previous round (C_{t-1}) >= T (m): Defect (D).
       - If previous round (C_{t-1}) < T (m): 
         - If deficit (T - C_{t-1}) == 1: Cooperate (C).
         - If deficit (T - C_{t-1}) > 1: Defect (D).
         
    Note on terminology: 
    - history.round_number: number of completed rounds.
    - If history.round_number == 0, we are at t=1.
    - If history.round_number == r-1, we are at the final round.
    - opponent_cooperators count includes only opponents. 
      Total cooperators = opponent_cooperators[-1] + (1 if I played C else 0).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.n = game_description.n_players
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.r - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        opp_prev_coop = history.opponent_cooperators[-1]
        total_prev_c = opp_prev_coop + (1 if my_prev_action else 0)
        if total_prev_c >= self.m:
            return Action.D
        deficit = self.m - total_prev_c
        if deficit == 1:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_27(BaseStrategy):
    """
    Threshold-Sensitive Tit-for-Tat with Defection Dampening.
    
    This strategy focuses on conditional cooperation. It initializes by cooperating,
    then evaluates the previous round's outcome to determine if cooperation is 
    "necessary" (threshold pivot point), "superfluous" (reward secured), or 
    "futile" (threshold unreachable). It incorporates adaptive mechanisms:
    permanent defection if the group shows insufficient coordination, and
    reduced cooperation if the reward is consistently achieved without 
    this player's contribution.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.permanent_defection = False
        self.cooperation_deficit_count = 0
        self.surplus_cooperation_count = 0
        self.times_cooperated = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if self.permanent_defection:
            return Action.D
        if history.round_number == 0:
            self.times_cooperated += 1
            return Action.C
        prev_round = history.round_number - 1
        my_prev_action = int(history.my_actions[prev_round])
        other_coop = history.opponent_cooperators[prev_round]
        total_coop = other_coop + my_prev_action
        eff_coop = other_coop
        if my_prev_action == 1:
            if total_coop < self.game_description.m:
                self.cooperation_deficit_count += 1
            else:
                self.cooperation_deficit_count = 0
            if total_coop > self.game_description.m:
                self.surplus_cooperation_count += 1
        if self.cooperation_deficit_count >= 2:
            self.permanent_defection = True
            return Action.D
        if my_prev_action == 1 and other_coop == 0 and (total_coop < self.game_description.m):
            self.permanent_defection = True
            return Action.D
        if eff_coop >= self.game_description.m:
            if self.times_cooperated > 0 and self.surplus_cooperation_count / self.times_cooperated > 0.5:
                return Action.D
            return Action.D
        if eff_coop == self.game_description.m - 1:
            self.times_cooperated += 1
            return Action.C
        if eff_coop < self.game_description.m - 1:
            remaining_rounds = self.game_description.n_rounds - history.round_number
            if remaining_rounds < 2:
                return Action.D
            return Action.D
        return Action.D

class Strategy_INDIVIDUALISTIC_28(BaseStrategy):
    """
    Threshold-Responsive Tit-for-Tat with Defection-on-Failure (TRT-DoF).
    
    Strategy:
    1. Always cooperate in the first round.
    2. In intermediate rounds:
       - If previous round succeeded (C >= m), cooperate.
       - If previous round failed but self-cooperation would have succeeded (X >= m-1), cooperate.
       - If previous round failed and was hopeless (X < m-1), defect.
       - If previous round failed despite capability (X >= m-1 but group failed), defect once to punish/test.
    3. In final round: Cooperate if previous round succeeded, otherwise defect.
    4. Reward Threshold Sensitivity: If k < 1, always defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.punishing = False

    def __call__(self, history: PlayerHistory) -> Action:
        if self.game_description.k < 1:
            return Action.D
        round_num = history.round_number
        if round_num == 0:
            return Action.C
        if self.punishing:
            self.punishing = False
            return Action.D
        m = self.game_description.m
        n = self.game_description.n_players
        last_x = history.opponent_cooperators[-1]
        last_s = int(history.my_actions[-1])
        last_c = last_x + last_s
        if round_num == self.game_description.n_rounds - 1:
            if last_c >= m:
                return Action.C
            else:
                return Action.D
        if last_c >= m:
            return Action.C
        if last_x >= m - 1:
            self.punishing = True
            return Action.D
        if last_x < m - 1:
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_29(BaseStrategy):
    """
    Implements a conditional trigger mechanism for the Collective Risk Dilemma.
    
    Strategy:
    1. Calibration (Round 1): Defect (D).
    2. Adaptive Response (Rounds 2 to r-1): 
       - If previous round cooperators >= m: Defect (D) to save endowment.
       - If previous round cooperators == m-1: Cooperate (C) to trigger reward k.
       - Else (cooperators < m-1): Defect (D) to minimize loss.
    3. Terminal Round: Defect (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == self.game_description.n_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.D
        prev_my_action = history.my_actions[-1]
        prev_opponents = history.opponent_cooperators[-1]
        total_cooperators_prev = prev_opponents + (1 if prev_my_action else 0)
        m = self.game_description.m
        if total_cooperators_prev >= m:
            return Action.D
        elif total_cooperators_prev == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_30(BaseStrategy):
    """
    Implements a Threshold-Contingent Conditional Reciprocity strategy.
    Prioritizes cooperation only when the collective threshold is reachable or being met,
    while defecting when the reward-to-cost ratio is unfavorable, in the final round,
    or after sustained failure to meet the threshold.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if self.desc.k < 1:
            return Action.D
        current_round = history.round_number
        total_rounds = self.desc.n_rounds
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            prob = self.desc.m / self.desc.n_players
            return Action.C if random.random() < prob else Action.D
        c_prev = history.opponent_cooperators[-1]
        m = self.desc.m
        if c_prev >= m:
            return Action.C
        if c_prev == m - 1:
            return Action.C
        if len(history.opponent_cooperators) >= 3:
            recent_failures = [history.opponent_cooperators[-1], history.opponent_cooperators[-2], history.opponent_cooperators[-3]]
            if all((c < m for c in recent_failures)):
                return Action.D
        return Action.D

class Strategy_INDIVIDUALISTIC_31(BaseStrategy):
    """
    Implements a Threshold-Sensitive Tit-for-Tat strategy for the Collective Risk Dilemma.
    - Round 1: Always Cooperate.
    - Rounds 2 to r-1: 
        - Cooperate if threshold m was met in previous round.
        - Defect if threshold not met.
        - Trigger permanent defection if the group fails to meet the threshold for two consecutive rounds.
        - If k is high enough, override conditional logic to always cooperate.
    - Final Round: Always Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0
        self.always_cooperate_mode = self.game_description.k > 2.0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if self.always_cooperate_mode:
            return Action.C
        prev_my_action = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + prev_my_action
        m = self.game_description.m
        if total_cooperators_prev < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 2:
            return Action.D
        if total_cooperators_prev >= m:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_32(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that employs a conditional cooperation heuristic.
    
    The strategy follows these rules:
    - Round 0: Always Defect (D) to observe baseline cooperation.
    - Final Round: Always Defect (D) as there is no future incentive.
    - Intermediate Rounds:
        - If the previous round met or exceeded the threshold (m), Defect (D) to free-ride.
        - If the previous round fell exactly 1 short of the threshold (m-1), Cooperate (C) to trigger the reward.
        - If the previous round fell short by more than 1, Defect (D) as cooperation is unlikely to be sufficient.
    - Edge Case: If the group consistently fails to reach the threshold despite prior attempts, switch to Defect (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.giving_up = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.D
        m = self.game_description.m
        prev_opp_coop = history.opponent_cooperators[-1]
        my_prev_action = int(history.my_actions[-1])
        total_cooperators = prev_opp_coop + my_prev_action
        if my_prev_action == 1 and total_cooperators < m:
            self.giving_up = True
        if self.giving_up:
            return Action.D
        if prev_opp_coop >= m:
            return Action.D
        if prev_opp_coop == m - 1:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_33(BaseStrategy):
    """
    A strategy that prioritizes reaching the cooperation threshold 'm'.
    It starts by cooperating, then adjusts based on the previous round's outcome:
    - If successful (>= m), continues cooperating.
    - If near-miss (== m-1), cooperates to attempt a recovery.
    - If total failure (< m-1), defects to preserve payoff.
    In the final round, it cooperates if the historical success rate >= 50%.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number + 1
        my_last_action = int(history.my_actions[-1])
        last_total_cooperators = history.opponent_cooperators[-1] + my_last_action
        if current_round < r:
            if last_total_cooperators >= m:
                return Action.C
            elif last_total_cooperators >= m - 1:
                return Action.C
            else:
                return Action.D
        if current_round == r:
            all_my_actions = history.my_actions.astype(int)
            all_opponent_cooperators = history.opponent_cooperators
            all_total_cooperators = all_my_actions + all_opponent_cooperators
            successes = np.sum(all_total_cooperators >= m)
            total_past_rounds = len(all_total_cooperators)
            success_rate = successes / total_past_rounds if total_past_rounds > 0 else 0.0
            if success_rate >= 0.5:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_COLLECTIVE_34(BaseStrategy):
    """
    Implements a recursive decision rule strategy for the Collective Risk Dilemma.
    - Round 1: Always Cooperate.
    - Subsequent Rounds (t > 1):
        - If previous cooperation count (c_prev) >= m:
            - If c_prev > m: Defect (Free-ride).
            - If c_prev == m: Cooperate (Maintain threshold).
        - If c_prev < m:
            - If last round: Cooperate only if k > 1 (based on simple payoff heuristic).
            - Else: Cooperate (Signal coordination).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.k = game_description.k
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        last_round_idx = history.round_number - 1
        my_last_action = history.my_actions[last_round_idx]
        total_cooperators_prev = history.opponent_cooperators[last_round_idx] + (1 if my_last_action else 0)
        if total_cooperators_prev >= self.m:
            if total_cooperators_prev > self.m:
                return Action.D
            else:
                return Action.C
        if history.round_number == self.r:
            return Action.C if self.k > 1 else Action.D
        return Action.C

class Strategy_COLLECTIVE_35(BaseStrategy):
    """
    Implements a Conditional Trigger with Threshold Tracking strategy for the Collective Risk Dilemma.
    It evaluates group performance history, detects near-misses for potential recovery,
    and defends against sustained exploitation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.has_given_up = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            if m / n >= 0.5:
                return Action.C
            return Action.D
        last_action = history.my_actions[-1]
        last_opponents = history.opponent_cooperators[-1]
        prev_total_cooperators = last_opponents + (1 if last_action else 0)
        if self.has_given_up:
            return Action.D
        if current_round >= 3:
            recent_counts = []
            for i in range(1, 4):
                opps = history.opponent_cooperators[-i]
                my_act = history.my_actions[-i]
                recent_counts.append(opps + (1 if my_act else 0))
            if all((count < m for count in recent_counts)):
                self.has_given_up = True
                return Action.D
        if current_round == r - 1:
            total_history_count = 0
            for i in range(current_round):
                total_history_count += history.opponent_cooperators[i] + (1 if history.my_actions[i] else 0)
            avg_success = total_history_count / current_round >= m
            if avg_success:
                return Action.C
            else:
                return Action.D
        if prev_total_cooperators >= m:
            return Action.C
        if prev_total_cooperators == m - 1:
            t_one_based = current_round + 1
            if random.random() < 1.0 - t_one_based / r:
                return Action.C
        return Action.D

class Strategy_COLLECTIVE_36(BaseStrategy):
    """
    Implements a Conditional Threshold Commitment strategy.
    
    This strategy behaves as a Tit-for-Tat variant adjusted for the threshold m.
    It prioritizes collective success, attempts to rescue threshold failures via
    critical mass contributions, and utilizes signals and permanent defection
    to manage non-cooperative groups.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.stagnation_counter = 0
        self.failed_c_counter = 0
        self.permanent_defect = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        prev_my_action_bool = history.my_actions[-1]
        prev_opp_c = history.opponent_cooperators[-1]
        total_c_prev = prev_opp_c + (1 if prev_my_action_bool else 0)
        if total_c_prev < self.game_description.m:
            self.stagnation_counter += 1
        else:
            self.stagnation_counter = 0
        if prev_my_action_bool and total_c_prev < self.game_description.m:
            self.failed_c_counter += 1
        else:
            self.failed_c_counter = 0
        if self.stagnation_counter >= 3:
            self.permanent_defect = True
        if self.permanent_defect:
            return Action.D
        if self.failed_c_counter == 2:
            return Action.D
        if total_c_prev >= self.game_description.m:
            return Action.C
        elif total_c_prev == self.game_description.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_37(BaseStrategy):
    """
    Implements a 'Conditional Threshold Commitment' strategy.
    
    Round 1: Always Cooperate.
    Rounds 1 < t < r:
    - If previous round cooperation count C_{t-1} >= m: Cooperate.
    - If C_{t-1} < m: Switch to Defect for one round.
    - If C_{t+1} >= m after a Defect test: Revert to Cooperate.
    - If C_{t+1} < m after a Defect test: Maintain Defection for remainder.
    - Large n/m adjustment: If m/n > 0.75, test if threshold is sustained with one fewer.
    Final Round: Cooperate if consistently reaching threshold, else Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.has_defect_tested = False
        self.permanently_defecting = False
        self.waiting_for_test_result = False
        self.previous_round_action = None

    def __call__(self, history: PlayerHistory) -> Action:
        if self.game_description.k <= 1:
            return Action.D
        if history.round_number == 0:
            self.previous_round_action = Action.C
            return Action.C
        if self.permanently_defecting:
            self.previous_round_action = Action.D
            return Action.D
        n = self.game_description.n_players
        m = self.game_description.m
        my_prev_action = self.previous_round_action
        total_cooperators_prev = history.opponent_cooperators[-1] + (1 if my_prev_action == Action.C else 0)
        if history.round_number == self.game_description.n_rounds - 1:
            all_rounds_met = True
            for r_idx in range(history.round_number):
                if int(history.my_actions[r_idx]) + history.opponent_cooperators[r_idx] < m:
                    all_rounds_met = False
                    break
            if all_rounds_met:
                self.previous_round_action = Action.C
                return Action.C
            else:
                self.permanently_defecting = True
                self.previous_round_action = Action.D
                return Action.D
        if m / n > 0.75:
            if total_cooperators_prev == m:
                self.previous_round_action = Action.C
                return Action.C
            elif total_cooperators_prev == m + 1:
                self.previous_round_action = Action.D
                return Action.D
        if self.waiting_for_test_result:
            if total_cooperators_prev >= m:
                self.waiting_for_test_result = False
                self.previous_round_action = Action.C
                return Action.C
            else:
                self.permanently_defecting = True
                self.previous_round_action = Action.D
                return Action.D
        if total_cooperators_prev < m:
            self.waiting_for_test_result = True
            self.previous_round_action = Action.D
            return Action.D
        self.previous_round_action = Action.C
        return Action.C

class Strategy_COLLECTIVE_38(BaseStrategy):
    """
    Implements a Triggered Threshold strategy for the Collective Risk Dilemma.
    
    This strategy utilizes a state-machine approach:
    1. Initially cooperates (Round 0).
    2. Monitors the threshold (m) based on the previous round's outcome.
    3. If the threshold was met, it maintains cooperation.
    4. If the threshold was not met, it switches to defection for a single round to punish/signal.
    5. Following a defection, it probes for cooperation by switching back to C.
    6. Terminal round (Last round) logic overrides state machine based on near-miss proximity.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.state = 'C'
        self.was_defecting = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        threshold = self.game_description.m
        total_rounds = self.game_description.n_rounds
        current_round = history.round_number
        last_round_cooperators = history.opponent_cooperators[-1]
        is_near_miss = last_round_cooperators >= threshold - 1
        if current_round == total_rounds - 1:
            if is_near_miss:
                return Action.C
            return Action.C if self.state == 'C' else Action.D
        met_threshold = last_round_cooperators >= threshold
        if self.state == 'C':
            if met_threshold:
                self.state = 'C'
                self.was_defecting = False
                return Action.C
            else:
                self.state = 'D'
                self.was_defecting = True
                return Action.D
        else:
            self.state = 'C'
            self.was_defecting = False
            return Action.C

class Strategy_COLLECTIVE_39(BaseStrategy):
    """
    Threshold-Responsive Tit-for-Tat (TR-TFT):
    An adaptive strategy that adjusts cooperativeness based on the collective 
    contribution rate of the previous round to minimize defection while 
    maximizing the probability of meeting the threshold m.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_idx = history.round_number
        n = self.desc.n_players
        m = self.desc.m
        r = self.desc.n_rounds
        if current_round_idx == 0:
            return Action.C if m / n <= 0.5 else Action.D
        if current_round_idx == r - 1:
            prev_total_cooperators = history.opponent_cooperators[-1] + int(history.my_actions[-1])
            return Action.C if prev_total_cooperators >= m else Action.D
        prev_my_action = int(history.my_actions[-1])
        prev_total_cooperators = history.opponent_cooperators[-1] + prev_my_action
        if prev_total_cooperators >= m:
            return Action.C
        else:
            p_penalty = (m - prev_total_cooperators) / n
            if random.random() < 1.0 - p_penalty:
                return Action.C
            else:
                return Action.D

class Strategy_COLLECTIVE_40(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that attempts to maintain the
    cooperative threshold 'm'. It cooperates initially, maintains cooperation 
    if the threshold is met exactly (as an essential contributor), and probes
    for free-riding opportunities if the threshold is exceeded by more than 
    one cooperator, while resetting to cooperate if the threshold collapses.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.last_action = Action.C

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            self.last_action = Action.C
            return Action.C
        i_cooperated = 1 if self.last_action == Action.C else 0
        n_c_last = history.opponent_cooperators[-1] + i_cooperated
        if history.round_number == self.desc.n_rounds - 1:
            self.last_action = Action.D
            return Action.D
        if n_c_last < self.desc.m:
            self.last_action = Action.C
            return Action.C
        if n_c_last == self.desc.m:
            if self.last_action == Action.C:
                self.last_action = Action.C
                return Action.C
            else:
                self.last_action = Action.D
                return Action.D
        if n_c_last > self.desc.m:
            self.last_action = Action.D
            return Action.D
        self.last_action = Action.C
        return Action.C

class Strategy_COLLECTIVE_41(BaseStrategy):
    """
    A Conditional Tit-for-Tat strategy with Threshold Signaling.
    
    1. Signals cooperation in the first round.
    2. Reciprocates based on the threshold (m):
       - If the collective succeeded (>= m cooperators), cooperate.
       - If the collective failed but was close (m-1), attempt recovery (cooperate).
       - Otherwise, defect to punish/preserve resources.
    3. Handles persistent failure by switching to unconditional defection.
    4. Final round prioritizes individual return based on previous success.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.game_description.m
        total_rounds = self.game_description.n_rounds
        current_round = history.round_number
        last_action_was_c = history.my_actions[-1]
        last_total_cooperators = (1 if last_action_was_c else 0) + history.opponent_cooperators[-1]
        if last_total_cooperators < m - 1:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures > 3:
            return Action.D
        if current_round == total_rounds - 1:
            if last_total_cooperators >= m:
                return Action.C
            else:
                return Action.D
        if last_total_cooperators >= m:
            return Action.C
        if last_total_cooperators == m - 1:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_42(BaseStrategy):
    """
    Threshold-Conditional Tit-for-Tat with Forgiveness.
    
    Operates by conditionally cooperating to reach threshold m. 
    Maintains cooperation as long as the threshold is met, defects otherwise,
    but retains the ability to forgive and resume cooperation if the group 
    returns to the threshold. In the final round, it performs a heuristic check
    on average historical performance to decide between altruism and self-preservation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description
        self.target_strategy = True

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_last_action = history.my_actions[-1]
        n_others_cooperated = history.opponent_cooperators[-1]
        n_prev = n_others_cooperated + (1 if my_last_action else 0)
        if n_prev < self.game.m:
            self.target_strategy = False
        elif n_prev >= self.game.m:
            self.target_strategy = True
        if history.round_number == self.game.n_rounds - 1:
            total_cooperators_history = np.sum(history.opponent_cooperators) + np.sum(history.my_actions)
            avg_cooperation_rate = total_cooperators_history / (history.round_number + 1)
            threshold_ratio = self.game.m / self.game.n_players
            if avg_cooperation_rate < threshold_ratio:
                return Action.D
            else:
                return Action.C
        return Action.C if self.target_strategy else Action.D

class Strategy_COLLECTIVE_43(BaseStrategy):
    """
    Implements a Threshold-Stabilizing Tit-for-Tat strategy.
    
    This strategy seeks to achieve a specific threshold of cooperators (m) to maximize 
    collective utility. It uses a probabilistic approach to rotate the burden of 
    cooperation when the threshold is met, punishes under-contribution, signals 
    over-contribution, and exits uncooperative game scenarios.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.total_rounds = game_description.n_rounds
        self.n = game_description.n_players
        self.m = game_description.m
        self.k = game_description.k
        self.is_giving_up = False

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_idx = history.round_number
        t = current_round_idx + 1
        if self.is_giving_up:
            return Action.D
        if t > 2:
            prev_1 = history.opponent_cooperators[-1]
            prev_2 = history.opponent_cooperators[-2]
            my_last_action = 1 if history.my_actions[-1] else 0
            my_second_last_action = 1 if history.my_actions[-2] else 0
            total_coop_last = prev_1 + my_last_action
            total_coop_2nd_last = prev_2 + my_second_last_action
            if total_coop_last == 0 and total_coop_2nd_last == 0:
                self.is_giving_up = True
                return Action.D
        if t == 1:
            return Action.C
        if t == self.total_rounds:
            last_total_coop = history.opponent_cooperators[-1] + (1 if history.my_actions[-1] else 0)
            if last_total_coop >= self.m:
                return Action.D
            else:
                return Action.C if self.k > 1 else Action.D
        prev_total_coop = history.opponent_cooperators[-1] + (1 if history.my_actions[-1] else 0)
        if prev_total_coop < self.m:
            return Action.C
        if prev_total_coop > self.m:
            return Action.D
        if random.random() < self.m / self.n:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_44(BaseStrategy):
    """
    Implements a Threshold-Targeting Reciprocity strategy:
    - Round 1: Probabilistic cooperation based on m/n ratio.
    - Subsequent Rounds: Cooperative if threshold was met, Punishing phase (D) if failed.
    - Last-Round/End-Game logic to exploit final opportunities.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.punishment_rounds_remaining = 0
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.r - 1:
            return Action.D
        if history.round_number == 0:
            if self.n <= 3:
                return Action.C
            prob = self.m / self.n
            return Action.C if random.random() < prob else Action.D
        last_was_coop = bool(history.my_actions[-1])
        total_cooperators_prev = history.opponent_cooperators[-1] + (1 if last_was_coop else 0)
        if history.round_number >= self.r - 2:
            if total_cooperators_prev < self.m - 1:
                return Action.D
        if total_cooperators_prev == self.m - 1:
            return Action.C
        if self.punishment_rounds_remaining > 0:
            self.punishment_rounds_remaining -= 1
            return Action.D
        if total_cooperators_prev >= self.m - 1:
            return Action.C
        else:
            self.punishment_rounds_remaining = math.floor(self.n / self.m)
            return Action.D

class Strategy_COLLECTIVE_45(BaseStrategy):
    """
    Threshold-Tit-for-Tat with Conditional Escalation strategy.
    
    Logic:
    1. Initial Round (t=0): Cooperate if threshold ratio m/n <= 0.5, else Defect.
    2. Terminal Phase (t=r-1): Always Defect.
    3. Subsequent Rounds (0 < t < r-1):
       - If previous threshold met (C_prev >= m):
         Maintain status quo (repeat previous action).
         BUT: If C_prev < C_prev_prev (dropping), Defect for one round as a warning.
       - If previous threshold not met (C_prev < m):
         If gap (m - C_prev) == 1: Pivot to Cooperate.
         If gap > 1: Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n = self.desc.n_players
        m = self.desc.m
        r = self.desc.n_rounds
        if current_round == r - 1:
            return Action.D
        if current_round == 0:
            return Action.C if m / n <= 0.5 else Action.D
        my_prev_action = history.my_actions[-1]
        my_prev_int = 1 if my_prev_action else 0
        c_prev = history.opponent_cooperators[-1] + my_prev_int
        if current_round >= 2:
            prev_opp_coop = history.opponent_cooperators[-2]
            prev_my_int = 1 if history.my_actions[-2] else 0
            c_prev_prev = prev_opp_coop + prev_my_int
            if c_prev >= m and c_prev < c_prev_prev:
                return Action.D
        gap = m - c_prev
        if gap <= 0:
            return Action.C if my_prev_action else Action.D
        if gap == 1:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_46(BaseStrategy):
    """
    Implements the Adaptive Threshold Tit-for-Tat (ATTT) strategy.
    
    This strategy balances cooperation to trigger threshold rewards with 
    calculated defection to signal insufficient participation or to 
    exploit the group in the final stages.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.in_permanent_failure_mode = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        t = history.round_number
        r = self.desc.n_rounds
        m = self.desc.m
        my_last_action = history.my_actions[-1]
        opponents_cooperated = history.opponent_cooperators[-1]
        c_prev = opponents_cooperated + (1 if my_last_action else 0)
        if self.in_permanent_failure_mode:
            if c_prev >= m + 1:
                self.in_permanent_failure_mode = False
                return Action.C
            return Action.D
        if c_prev < m:
            if len(history.my_actions) >= 2:
                prev_opp = history.opponent_cooperators[-2]
                prev_self = 1 if history.my_actions[-2] else 0
                if prev_opp + prev_self < m:
                    self.in_permanent_failure_mode = True
                    return Action.D
            return Action.D
        if t >= r - 2:
            lookback = min(3, len(history.my_actions))
            last_n_coop_counts = []
            for i in range(1, lookback + 1):
                opp = history.opponent_cooperators[-i]
                self_c = 1 if history.my_actions[-i] else 0
                last_n_coop_counts.append(opp + self_c)
            avg_coop = sum(last_n_coop_counts) / lookback
            if avg_coop < m:
                return Action.D
            return Action.C
        prob_defect = 1.0 / r
        if random.random() < prob_defect:
            return Action.D
        return Action.C

class Strategy_COLLECTIVE_47(BaseStrategy):
    """
    Implements a trigger-cooperation strategy for the Collective Risk Dilemma.
    It targets the threshold m, balancing the need to reach the collective reward
    against individual payoff maximization.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        m = self.game_description.m
        if history.round_number == 0:
            return Action.C if random.random() < m / n else Action.D
        current_round = history.round_number
        my_prev_action = history.my_actions[-1]
        opp_coop_count = history.opponent_cooperators[-1]
        total_cooperators_prev = opp_coop_count + (1 if my_prev_action else 0)
        if current_round == r - 1:
            if total_cooperators_prev >= m:
                return Action.D
            else:
                return Action.C
        if total_cooperators_prev < m:
            if my_prev_action:
                return Action.C
            else:
                return Action.C if random.random() < m / n else Action.D
        elif my_prev_action:
            excess_cooperators = total_cooperators_prev - m
            if excess_cooperators > 0:
                return Action.D
            else:
                return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_48(BaseStrategy):
    """
    Implements a Conditional Threshold Tit-for-Tat strategy.
    
    Aims to sustain exactly m cooperators to secure the reward k while minimizing 
    costs. Utilizes surplus-testing, failure-recovery, and an exit condition 
    for persistent failure.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.consecutive_near_misses = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            threshold_ratio = self.desc.m / self.desc.n_players
            if threshold_ratio >= 0.5:
                return Action.C
            return Action.D
        my_prev_action = history.my_actions[-1]
        my_prev_coop = 1 if my_prev_action == Action.C else 0
        n_c_prev = history.opponent_cooperators[-1] + my_prev_coop
        s_success = n_c_prev >= self.desc.m
        is_near_miss = not s_success and n_c_prev >= self.desc.m - 1
        if is_near_miss:
            self.consecutive_near_misses += 1
        else:
            self.consecutive_near_misses = 0
        if self.consecutive_near_misses >= 3:
            return Action.D
        if history.round_number == self.desc.n_rounds - 1:
            if n_c_prev >= self.desc.m - 1:
                return Action.C
            return Action.D
        if s_success:
            surplus = n_c_prev - self.desc.m
            if surplus >= 1:
                return Action.D
            else:
                return Action.C
        elif n_c_prev >= self.desc.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_49(BaseStrategy):
    """
    Implements Conditional Reciprocal Contribution (CRC):
    A strategy that maintains a 'Cooperative' or 'Defensive' status.
    It monitors the threshold 'm' to decide whether to cooperate or defect,
    balancing the group goal with individual payoff maximization.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.status = 'Cooperative'
        self.exploit_counter = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            self.status = 'Cooperative'
            self.exploit_counter = 0
            return Action.C
        m = self.desc.m
        total_rounds = self.desc.n_rounds
        current_round = history.round_number
        last_c = history.opponent_cooperators[-1]
        i_cooperated_last = history.my_actions[-1]
        if i_cooperated_last and last_c < m:
            self.exploit_counter = 2
            self.status = 'Defensive'
        if self.exploit_counter > 0:
            self.exploit_counter -= 1
            if self.exploit_counter == 0:
                pass
        if self.status == 'Defensive':
            if current_round >= 2 and history.opponent_cooperators[-1] >= m and (history.opponent_cooperators[-2] >= m):
                self.status = 'Cooperative'
                return Action.C
            return Action.D
        if last_c < m:
            self.status = 'Defensive'
            return Action.D
        elif last_c == m:
            return Action.C
        elif last_c - 1 >= m:
            if current_round == total_rounds - 1:
                return Action.D
            return Action.D
        else:
            return Action.C

class Strategy_COLLECTIVE_50(BaseStrategy):
    """
    Implements Threshold-Conditional Reciprocity.
    Maintains exactly m cooperators by observing recent history and adjusting actions.
    Includes protocols for persistent failure and last-round constraints.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.persistent_failure = False
        self.sudden_drop_test = False

    def __call__(self, history: PlayerHistory) -> Action:
        desc = self.game_description
        r = history.round_number
        n = desc.n_players
        m = desc.m
        if r == 0:
            if random.random() < m / n:
                return Action.C
            return Action.D
        my_action = history.my_actions[-1]
        total_cooperators = history.opponent_cooperators[-1] + (1 if my_action else 0)
        if r >= 3 and (not self.persistent_failure):
            if all((history.opponent_cooperators[i] + (1 if history.my_actions[i] else 0) < m for i in range(r - 3, r))):
                self.persistent_failure = True
        if self.persistent_failure:
            return Action.D
        if r == desc.n_rounds - 1:
            prev_total = history.opponent_cooperators[-1] + (1 if history.my_actions[-1] else 0)
            if prev_total >= m:
                return Action.C
            return Action.D
        if r >= 2:
            prev_total_prev = history.opponent_cooperators[-2] + (1 if history.my_actions[-2] else 0)
            if prev_total_prev >= m and total_cooperators < m:
                self.sudden_drop_test = True
                return Action.C
            elif self.sudden_drop_test:
                self.sudden_drop_test = False
        if total_cooperators == m:
            return Action.C if my_action else Action.D
        if total_cooperators < m:
            return Action.C
        if total_cooperators > m:
            return Action.D if my_action else Action.C
        return Action.D

class Strategy_COLLECTIVE_51(BaseStrategy):
    """
    Implements a Threshold-Conditional Reciprocation strategy for the Collective Risk Dilemma.
    It manages a trust_score to balance conditional cooperation with punishment of defection,
    utilizing a state-based approach to decide between contributing (C) or keeping (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.trust_score = game_description.m
        self.consecutive_failures = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        prev_my_action = 1 if history.my_actions[-1] else 0
        prev_opp_c = history.opponent_cooperators[-1]
        prev_total_c = prev_opp_c + prev_my_action
        if prev_total_c < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 3:
            self.trust_score = 0
            self.consecutive_failures = 0
        if current_round == r - 1:
            if prev_total_c >= m:
                return Action.C
            if current_round >= 1:
                prev_prev_c = history.opponent_cooperators[-2] + (1 if history.my_actions[-2] else 0) if current_round >= 2 else m + 1
                if prev_total_c < m and prev_prev_c < m:
                    return Action.D
            return Action.C if prev_total_c >= m else Action.D
        if prev_total_c == m:
            self.trust_score += 1
            return Action.C
        if prev_total_c >= m:
            self.trust_score += 1
            return Action.C
        else:
            self.trust_score -= 2
            if self.trust_score <= 0:
                self.trust_score = m
                return Action.C
            if prev_total_c >= math.ceil(m / 2):
                return Action.C
            else:
                return Action.D

class Strategy_COLLECTIVE_52(BaseStrategy):
    """
    Implements a Collective Risk Dilemma strategy balancing probability-based 
    entry with responsive adaptation to collective outcomes.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.k = game_description.k
        self.epsilon = 0.1

    def __call__(self, history: PlayerHistory) -> Action:
        if self.k <= 1:
            return Action.D
        round_idx = history.round_number
        if round_idx == 0:
            prob = min(1.0, self.m / self.n + self.epsilon)
            return Action.C if random.random() < prob else Action.D
        prev_round = round_idx - 1
        my_prev_action = history.my_actions[prev_round]
        c_prev = history.opponent_cooperators[prev_round]
        total_cooperators_prev = c_prev + (1 if my_prev_action else 0)
        if total_cooperators_prev == 0:
            return Action.D
        if round_idx == self.r - 1:
            if total_cooperators_prev >= self.m - 1:
                return Action.C
            else:
                return Action.D
        if total_cooperators_prev >= self.m:
            if total_cooperators_prev > self.m:
                return Action.D
            else:
                return Action.C
        if total_cooperators_prev < self.m:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_53(BaseStrategy):
    """
    Implements a Threshold-Responsive Tit-for-Tat strategy for the Collective Risk Dilemma.
    
    Logic:
    - Initialization: Cooperates if m/n <= 0.5, else defects.
    - Reciprocity: Conditional cooperation based on whether the collective target 'm'
      was met in the previous round.
    - Recovery: Specifically checks the 'cooperation gap' (m - N_C) to decide 
      when to attempt to bridge the gap and trigger rewards.
    - Last Round: Aggressive defecting if previous results do not support cooperation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.oscillation_counter = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            if self.m / self.n <= 0.5:
                return Action.C
            return Action.D
        prev_n_c = history.opponent_cooperators[-1] + (1 if history.my_actions[-1] else 0)
        prev_my_action = history.my_actions[-1]
        target_met = prev_n_c >= self.m
        if history.round_number >= 2:
            prev_prev_n_c = history.opponent_cooperators[-2] + (1 if history.my_actions[-2] else 0)
            if abs(prev_n_c - prev_prev_n_c) >= self.n / 2:
                self.oscillation_counter += 1
            else:
                self.oscillation_counter = 0
            if self.oscillation_counter >= 2:
                self.oscillation_counter = 0
                return Action.D
        if history.round_number == self.r - 1:
            if target_met:
                return Action.C
            return Action.D
        if target_met:
            if prev_my_action:
                return Action.C
            else:
                return Action.D
        elif prev_my_action:
            return Action.D
        else:
            gap = self.m - history.opponent_cooperators[-1]
            if gap == 1:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_COLLECTIVE_54(BaseStrategy):
    """
    Implements Conditional Threshold Cooperation.
    
    Strategy Logic:
    - Initiates with cooperation (Round 0).
    - Tracks "Failure Streak" (consecutive rounds where m was not reached).
    - If m is not reached for 3 consecutive rounds despite cooperation, 
      triggers a 2-round penalty (Defect).
    - Uses adaptive logic: If threshold met, safe to Defect (if excess cooperators exist).
      If threshold not met, switches to Cooperate to attempt coordination.
    - Last-round optimization: Defect if safe, Cooperate only if it can reach the threshold.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.failure_streak = 0
        self.penalty_rounds_remaining = 0

    def _threshold_reached(self, prev_coop_opponents: int, prev_my_action: Action) -> bool:
        my_c = 1 if prev_my_action == Action.C else 0
        return prev_coop_opponents + my_c >= self.desc.m

    def __call__(self, history: PlayerHistory) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        last_opp_coop = int(history.opponent_cooperators[-1])
        last_my_action = Action.C if history.my_actions[-1] else Action.D
        reached = self._threshold_reached(last_opp_coop, last_my_action)
        if self.penalty_rounds_remaining > 0:
            self.penalty_rounds_remaining -= 1
        if not reached and last_my_action == Action.C:
            self.failure_streak += 1
        else:
            self.failure_streak = 0
        if self.failure_streak >= 3:
            self.failure_streak = 0
            self.penalty_rounds_remaining = 2
        if round_idx == self.desc.n_rounds - 1:
            total_cooperators = last_opp_coop + (1 if last_my_action == Action.C else 0)
            if total_cooperators >= self.desc.m:
                return Action.D
            elif last_opp_coop == self.desc.m - 1:
                return Action.C
            else:
                return Action.D
        if self.penalty_rounds_remaining > 0:
            return Action.D
        if last_my_action == Action.C:
            if last_opp_coop + 1 > self.desc.m:
                return Action.D
            return Action.C
        else:
            if last_opp_coop >= self.desc.m:
                return Action.D
            return Action.C

class Strategy_COLLECTIVE_55(BaseStrategy):
    """
    Threshold-Conditional Reciprocity (TCR):
    A Trigger-Tit-for-Tat variant for Collective Risk Dilemmas.
    Cooperate initially. In subsequent rounds, maintain cooperation if the threshold m is met.
    If the threshold is missed, defect to punish/protect.
    Includes a decay-based recovery mechanism and a limit on exploitation tolerance.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self._consecutive_failures = 0
        self._max_exploitation_tolerance = 3

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        m = self.game_description.m
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        prev_opp_coop = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        total_prev_coop = prev_opp_coop + (1 if my_prev_action else 0)
        if total_prev_coop >= m:
            self._consecutive_failures = 0
            return Action.C
        if my_prev_action == Action.C:
            self._consecutive_failures += 1
        if self._consecutive_failures >= self._max_exploitation_tolerance:
            return Action.D
        if total_prev_coop == 0:
            p = max(0.01, 0.1 * (1 - current_round / r))
            if random.random() < p:
                return Action.C
        return Action.D

class Strategy_COLLECTIVE_56(BaseStrategy):
    """
    Implements a 'Tit-for-Tat with a Buffer' strategy.
    
    Logic:
    1. Always Cooperate in the first round.
    2. In subsequent rounds, if the previous total cooperators (opponent_cooperators + self) 
       was >= m, we Cooperate.
    3. If the threshold was not met, we Defect.
    4. Self-Correction: If we previously Defected but the threshold was met 
       (e.g., reached exactly m without our help), we return to Cooperation 
       to secure future rewards.
    5. In the final round, Defect if the previous threshold was not met, otherwise Cooperate.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        last_my_action = 1 if history.my_actions[-1] else 0
        last_opponent_coops = history.opponent_cooperators[-1]
        total_cooperators_last_round = last_opponent_coops + last_my_action
        is_final_round = history.round_number == self.desc.n_rounds - 1
        if total_cooperators_last_round >= self.desc.m:
            return Action.C
        if is_final_round:
            return Action.D
        if last_opponent_coops >= self.desc.m:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_57(BaseStrategy):
    """
    Implements the Conditional Threshold Trigger (CTT) strategy.
    
    CTT maintains cooperation if the threshold `m` was met in the previous round.
    If the threshold was not met, it tracks consecutive failures (up to a limit `L`) 
    before permanently switching to defection. It also includes an 'Exploitation 
    Protection' mechanism: if the player defected in the previous round but the 
    threshold was still met, they resume cooperation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.failure_limit = 2
        self.failure_count = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_round_idx = history.round_number - 1
        cooperators_prev = history.opponent_cooperators[prev_round_idx]
        my_prev_action = history.my_actions[prev_round_idx]
        total_cooperators_prev = cooperators_prev + (1 if my_prev_action else 0)
        threshold_met = total_cooperators_prev >= self.game_description.m
        if not my_prev_action and threshold_met:
            self.failure_count = 0
            return Action.C
        if threshold_met:
            self.failure_count = 0
            return Action.C
        else:
            self.failure_count += 1
            if self.failure_count >= self.failure_limit:
                return Action.D
            else:
                return Action.D

class Strategy_COLLECTIVE_58(BaseStrategy):
    """
    Implements a Trigger-Threshold Reciprocity strategy for Collective Risk Dilemmas.
    
    Strategy Logic:
    - Round 0: Always Cooperate.
    - If group threshold m met:
        - If I played C: Continue C.
        - If I played D: Switch to C with prob m/n.
    - If group threshold m not met:
        - If I played C and failure is large (> n/3): Switch to D.
        - If I played D: Stay D.
    - Edge Cases:
        - Marginal failure (m-1): Always C.
        - Consistent Exploitation (C for 3 rounds while m not met): Permanent D.
    - Terminal round (r-1): Cooperate if threshold was met, else Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.consecutive_coop_failures = 0

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        n = self.desc.n_players
        m = self.desc.m
        r = self.desc.n_rounds
        prev_round = t - 1
        my_prev_action = history.my_actions[prev_round]
        total_prev_cooperators = history.opponent_cooperators[prev_round]
        if my_prev_action == Action.C and total_prev_cooperators < m:
            self.consecutive_coop_failures += 1
        else:
            self.consecutive_coop_failures = 0
        if self.consecutive_coop_failures >= 3:
            return Action.D
        if t == r - 1:
            if total_prev_cooperators >= m:
                return Action.C
            else:
                return Action.D
        if total_prev_cooperators == m - 1:
            return Action.C
        if total_prev_cooperators >= m:
            if my_prev_action == Action.C:
                return Action.C
            else:
                prob = m / n
                return Action.C if random.random() < prob else Action.D
        elif my_prev_action == Action.C:
            if m - total_prev_cooperators > n // 3:
                return Action.D
            else:
                return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_59(BaseStrategy):
    """
    Threshold-Conditional Reciprocity (TCR):
    A strategy that signals cooperation in round 1, reciprocates group behavior
    in middle rounds, and makes a calculated bet on the final round.
    Includes memory for persistent defection detection to mitigate losses.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description
        self.consecutive_failures = 0

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n_rounds = self.game.n_rounds
        m = self.game.m
        if current_round == 0:
            return Action.C
        last_action = int(history.my_actions[-1])
        coop_prev = int(history.opponent_cooperators[-1])
        if coop_prev < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 3:
            return Action.D
        if current_round == n_rounds - 1:
            if coop_prev >= m - 1:
                return Action.C
            else:
                return Action.D
        if coop_prev >= m:
            return Action.C if last_action == 1 else Action.D
        elif last_action == 1:
            return Action.D
        else:
            prob_test = 1.0 - coop_prev / m
            if random.random() < prob_test:
                return Action.C
            else:
                return Action.D

class Strategy_COLLECTIVE_60(BaseStrategy):
    """
    Threshold-Conditional Reciprocity (TCR):
    A strategy that maintains cooperation based on the collective threshold 'm'.
    - Round 1: Always Cooperate (C).
    - Rounds 2 to r-1:
        - If previous round met/exceeded threshold (C_t-1 >= m):
            - If I cooperated and we exceeded threshold, switch to Defect (D) to save cost.
            - If we were exactly at the threshold, maintain Co-operation (C).
            - If I defected, stay Defect (D).
        - If previous round failed (C_t-1 < m):
            - If we were one shy (m-1), Cooperate (C) to 'rescue'.
            - If far from threshold, Defect (D).
    - Round r: Pure payoff maximization, except for a final 'rescue' if m-1 was achieved.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.n = game_description.n_players

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_round_idx = history.round_number - 1
        my_last_action = Action.C if history.my_actions[prev_round_idx] else Action.D
        prev_cooperators = history.opponent_cooperators[prev_round_idx] + (1 if my_last_action == Action.C else 0)
        is_final_round = history.round_number == self.r - 1
        if is_final_round:
            if prev_cooperators == self.m - 1:
                return Action.C
            return Action.D
        threshold_met = prev_cooperators >= self.m
        if threshold_met:
            if my_last_action == Action.C and prev_cooperators > self.m:
                return Action.D
            if my_last_action == Action.D:
                return Action.D
            return Action.C
        else:
            if prev_cooperators == self.m - 1:
                return Action.C
            return Action.D

class Strategy_COLLECTIVE_61(BaseStrategy):
    """
    Threshold-Targeted Reciprocal Tit-for-Tat:
    Maintains the collective goal of reaching m cooperators while minimizing 
    exploitation via a phase-based logic:
    1. Initial Phase (Round 0): Always Cooperate.
    2. Monitoring Phase:
       - If previous round met threshold (>= m): Cooperate.
       - If previous round failed (< m) but the round before that succeeded (>= m): Forgive/Restart with Cooperate.
       - Otherwise: Defect.
    3. Terminal Phase (Last Round):
       - If previous round met threshold (>= m): Cooperate.
       - Otherwise: Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_idx = history.round_number
        if current_round_idx == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        if current_round_idx == self.n_rounds - 1:
            if prev_cooperators >= self.m:
                return Action.C
            return Action.D
        if prev_cooperators >= self.m:
            return Action.C
        if current_round_idx > 1:
            prev_prev_cooperators = history.opponent_cooperators[-2]
            if prev_prev_cooperators >= self.m:
                return Action.C
        return Action.D

class Strategy_COLLECTIVE_62(BaseStrategy):
    """
    Threshold Reciprocal Cooperation strategy for Collective Risk Dilemma.
    Attempts to achieve exactly m cooperators by probing in round 1,
    then dynamically switching between C and D based on previous round's outcome
    to maintain the threshold while maximizing payoff.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.k = game_description.k
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_idx = history.round_number
        if current_round_idx == 0:
            probability_c = self.m / self.n
            return Action.C if random.random() < probability_c else Action.D
        c_prev = history.opponent_cooperators[-1]
        i_cooperated = bool(history.my_actions[-1])
        total_c_prev = c_prev + (1 if i_cooperated else 0)
        if current_round_idx == self.r - 1:
            if total_c_prev >= self.m:
                return Action.D
            else:
                return Action.C if self.k > 1 else Action.D
        if total_c_prev >= self.m:
            if i_cooperated and total_c_prev == self.m:
                return Action.D
            elif total_c_prev > self.m:
                return Action.D
            else:
                return Action.D
        else:
            return Action.C

class Strategy_COLLECTIVE_63(BaseStrategy):
    """
    A complex strategic agent for the Collective Risk Dilemma that balances 
    threshold enforcement, conditional cooperation, and risk-aversion.
    
    Strategy Highlights:
    - Round 1: Default to Cooperation.
    - Threshold Maintenance: Always plays C if the threshold m is met.
    - Failure Tracking: Shifts to D if the group fails to meet m for two consecutive rounds.
    - Swing Vote Logic: If the group is at m-1 (one short), always plays C.
    - Low-Contribution Exit: If cooperation is consistently < m/2, defects permanently.
    - Final Round: Shifts to D if historical failure is the norm, otherwise cooperates.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0
        self.consistent_defection_flag = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        m = self.game_description.m
        last_c = int(history.opponent_cooperators[-1])
        my_last_action = int(history.my_actions[-1])
        total_c_prev = last_c + my_last_action
        if total_c_prev < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if np.mean(history.opponent_cooperators) < m / 2:
            self.consistent_defection_flag = True
        if self.consistent_defection_flag:
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            success_rate = np.mean(np.array(history.opponent_cooperators + history.my_actions.astype(int)) >= m)
            if success_rate > 0.5:
                return Action.C
            return Action.D
        if total_c_prev == m - 1:
            return Action.C
        if total_c_prev >= m:
            return Action.C
        else:
            if self.consecutive_failures >= 2:
                return Action.D
            if total_c_prev >= m / 2:
                p_coop = 1.0 - m / n
                if random.random() < p_coop:
                    return Action.C
                return Action.D
            return Action.C

class Strategy_COLLECTIVE_64(BaseStrategy):
    """
    Implements Conditional Threshold-Trigger Tit-for-Tat.
    
    Cooperates initially. In subsequent rounds (excluding the final round), it 
    responds to whether the threshold 'm' was met in the previous round. 
    It punishes failure to meet the threshold by defecting, but periodically 
    'probes' by cooperating every 4th round of defection to test for group recovery. 
    In the final round, it cooperates only if the threshold was met in the previous round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_defects = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.game_description.m
        r_total = self.game_description.n_rounds
        current_round = history.round_number
        prev_cooperators = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        total_cooperators = prev_cooperators + (1 if my_prev_action else 0)
        if current_round == r_total - 1:
            if total_cooperators >= m:
                return Action.C
            else:
                return Action.D
        if self.consecutive_defects >= 4:
            self.consecutive_defects = 0
            return Action.C
        if total_cooperators >= m:
            self.consecutive_defects = 0
            return Action.C
        else:
            self.consecutive_defects += 1
            return Action.D

class Strategy_COLLECTIVE_65(BaseStrategy):
    """
    Implements the Threshold-Adaptive Trigger (TAT) strategy for the Collective Risk Dilemma.
    TAT coordinates towards a threshold 'm' and adapts based on group performance.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.consecutive_cooperative_rounds = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if self.desc.k <= 1:
            return Action.D
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        others_prev = history.opponent_cooperators[-1]
        total_prev = others_prev + (1 if my_prev_action else 0)
        if round_idx > 1:
            prev_others = history.opponent_cooperators[-2]
            prev_total = prev_others + (1 if history.my_actions[-2] else 0)
            if prev_total - total_prev > 2:
                return Action.D
        if total_prev >= self.desc.m:
            self.consecutive_cooperative_rounds += 1
        else:
            self.consecutive_cooperative_rounds = 0
        if self.consecutive_cooperative_rounds >= 2:
            return Action.C
        if round_idx == self.desc.n_rounds - 1:
            avg_c = np.mean(history.opponent_cooperators + history.my_actions.astype(int))
            if avg_c >= self.desc.m:
                return Action.C
            return Action.D
        if total_prev >= self.desc.m and my_prev_action == Action.C:
            if total_prev > self.desc.m:
                return Action.D
            else:
                return Action.C
        if total_prev >= self.desc.m:
            return Action.D
        if total_prev == self.desc.m - 1:
            if my_prev_action == Action.D:
                return Action.C
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_66(BaseStrategy):
    """
    Threshold-Conditional Tit-for-Tat (TCTFT):
    Cooperates in the first round to signal intent. In subsequent rounds, it
    cooperates only if the previous round's total cooperation fell below the
    required threshold (m), attempting to drive the group to reach the goal.
    If the threshold was met or exceeded in the previous round, it defects
    to save on the cost of cooperation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_last_action = history.my_actions[-1]
        my_last_contribution = 1 if my_last_action else 0
        total_cooperators_last_round = my_last_contribution + history.opponent_cooperators[-1]
        if total_cooperators_last_round < self.m:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_67(BaseStrategy):
    """
    Implements a Threshold-Conditional Tit-for-Tat strategy for the Collective Risk Dilemma.
    Adjusts contribution based on previous round's collective success relative to the 
    threshold (m), attempting to maintain a cooperative equilibrium or testing the group's 
    resilience.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.k = game_description.k
        self.is_testing_threshold = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.m
        last_my_action = history.my_actions[-1]
        last_coop_count_opponents = history.opponent_cooperators[-1]
        last_total_cooperators = last_coop_count_opponents + (1 if last_my_action else 0)
        if history.round_number == self.r - 1:
            all_opp_counts = history.opponent_cooperators + history.my_actions.astype(int)
            if np.all(all_opp_counts >= m):
                return Action.C
            else:
                return Action.D
        if last_total_cooperators >= m:
            if last_my_action:
                if last_total_cooperators == m and (not self.is_testing_threshold):
                    self.is_testing_threshold = True
                    return Action.D
                return Action.C
            else:
                if self.is_testing_threshold:
                    self.is_testing_threshold = False
                    return Action.C
                return Action.D
        else:
            if self.is_testing_threshold:
                self.is_testing_threshold = False
                return Action.C
            if last_total_cooperators >= m - 1:
                return Action.C
            return Action.D

class Strategy_COLLECTIVE_68(BaseStrategy):
    """
    A strategy that coordinates on a cooperative threshold `m`.
    It cooperates to initiate and maintain cooperation, defects when the threshold 
    is not met to avoid exploitation, and performs 'probes' (cooperating) when 
    the group is just one short of the threshold (m-1).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number + 1
        if current_round == 1:
            return Action.C
        i_cooperated_prev = bool(history.my_actions[-1])
        opponents_coop_prev = history.opponent_cooperators[-1]
        total_cooperators_prev = opponents_coop_prev + (1 if i_cooperated_prev else 0)
        m = self.game_description.m
        n_rounds = self.game_description.n_rounds
        if current_round == n_rounds:
            return Action.C if total_cooperators_prev >= m else Action.D
        if total_cooperators_prev == m - 1:
            return Action.C
        if total_cooperators_prev >= m:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_69(BaseStrategy):
    """
    Implements a Conditional Threshold Trigger strategy.
    
    This strategy maintains cooperation as long as a minimum threshold (m) 
    of cooperators is met. It punishes defection, employs a probabilistic 
    recovery mechanism after failed cooperation, and switches to defection 
    in the final round unless a perfect history of cooperation exists.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.target_count = game_description.m
        self.total_rounds = game_description.n_rounds
        self.recovery_probability = 0.3

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_idx = history.round_number
        if current_round_idx == 0:
            return Action.C
        previous_my_action = history.my_actions[-1]
        prev_opp_coop = history.opponent_cooperators[-1]
        total_prev_coop = (1 if previous_my_action else 0) + prev_opp_coop
        is_last_round = current_round_idx == self.total_rounds - 1
        if is_last_round:
            perfect_cooperation = True
            for r in range(current_round_idx):
                r_opp = history.opponent_cooperators[r]
                r_me = 1 if history.my_actions[r] else 0
                if r_opp + r_me < self.target_count:
                    perfect_cooperation = False
                    break
            if perfect_cooperation:
                return Action.C
            else:
                return Action.D
        if total_prev_coop >= self.target_count:
            return Action.C
        else:
            if not previous_my_action:
                if random.random() < self.recovery_probability:
                    return Action.C
            return Action.D

class Strategy_COLLECTIVE_70(BaseStrategy):
    """
    Implements a Threshold-Conditional Reciprocator strategy for the Collective Risk Dilemma.
    Focuses on maintaining the cooperative threshold 'm' while using probabilistic
    dampening to discourage free-riding and adaptive endgame logic.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.desc.n_players
        m = self.desc.m
        r = self.desc.n_rounds
        current_round = history.round_number
        prev_idx = -1
        my_prev_action_bool = history.my_actions[prev_idx]
        opp_prev_coop = history.opponent_cooperators[prev_idx]
        total_prev_coop = opp_prev_coop + (1 if my_prev_action_bool else 0)
        if current_round >= r - 1:
            lookback = min(5, history.round_number)
            recent_coop_counts = []
            for i in range(1, lookback + 1):
                opp_c = history.opponent_cooperators[-i]
                my_c = 1 if history.my_actions[-i] else 0
                recent_coop_counts.append(opp_c + my_c)
            avg_recent = sum(recent_coop_counts) / len(recent_coop_counts)
            if avg_recent >= m:
                return Action.C
            else:
                return Action.D
        if total_prev_coop == m:
            return Action.C
        if total_prev_coop >= m:
            probability = m / total_prev_coop
            if random.random() < probability:
                return Action.C
            else:
                return Action.D
        if total_prev_coop == 0:
            return Action.C
        else:
            return Action.C

class Strategy_COLLECTIVE_71(BaseStrategy):
    """
    A Tit-for-Tat-style threshold strategy for the Collective Risk Dilemma.
    Starts by cooperating. Subsequent actions depend on the threshold m and the 
    previous round's observed number of cooperators. 
    It incorporates conditional pivot-detection and terminal phase logic.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        current_round = history.round_number
        prev_my_action = int(history.my_actions[-1])
        N_c = history.opponent_cooperators[-1] + prev_my_action
        if current_round == self.r - 1:
            if N_c >= self.m - 1:
                return Action.C
            else:
                return Action.D
        if N_c == self.m - 1:
            return Action.C
        if N_c >= self.m:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_72(BaseStrategy):
    """
    A strategy that adapts based on the success of collective cooperation:
    - Round 1: Always Cooperate (C).
    - Middle rounds (2 to r-1): If previous round cooperators >= m, play C; else play D.
    - Final round (r): If previous round cooperators >= m, play C; else play D.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        my_previous_action = history.my_actions[-1]
        total_cooperators_prev = history.opponent_cooperators[-1] + (1 if my_previous_action else 0)
        m = self.game_description.m
        if total_cooperators_prev >= m:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_73(BaseStrategy):
    """
    A Conditional Threshold Reciprocity strategy for Collective Risk Dilemma.
    
    Logic summary:
    - Round 1: Cooperate.
    - Round t > 1:
        1. If previous round cooperators >= m: Cooperate (Steady State).
        2. If previous round cooperators == m-1: Cooperate (Near Miss).
        3. If previous round cooperators < m-1:
            - If t == r: Defect.
            - Else: Probabilistic re-engagement (p = 1/n) to cooperate, else Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.re_engagement_prob = 1.0 / self.n

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_prev_action = int(history.my_actions[-1])
        other_cooperators = int(history.opponent_cooperators[-1])
        total_cooperators_prev = my_prev_action + other_cooperators
        current_round = history.round_number
        if total_cooperators_prev >= self.m:
            return Action.C
        if total_cooperators_prev == self.m - 1:
            return Action.C
        if current_round == self.r - 1:
            return Action.D
        if random.random() < self.re_engagement_prob:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_74(BaseStrategy):
    """
    Threshold-Responsive Tit-for-Tat (TR-TFT):
    Prioritizes cooperation to reach the collective threshold 'm'.
    - Round 0: Always Cooperate.
    - If threshold (m) met last round: Continue Cooperating.
    - If threshold missed by 1 (m-1): Cooperate to push for success.
    - If threshold missed significantly (< m-1): Defect to minimize loss.
    - Final Round: If threshold was missed in the previous round, Defect; otherwise Cooperate.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        r = self.game_description.n_rounds
        m = self.game_description.m
        if t == 0:
            return Action.C
        my_prev_action = Action.C if history.my_actions[-1] else Action.D
        opp_prev_coop = history.opponent_cooperators[-1]
        c_prev = opp_prev_coop + (1 if my_prev_action == Action.C else 0)
        if t == r - 1:
            if c_prev < m:
                return Action.D
            else:
                return Action.C
        if c_prev >= m:
            return Action.C
        elif c_prev == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_75(BaseStrategy):
    """
    Implements a Conditional Tit-for-Tat with Threshold Sensitivity.
    
    Logic:
    - Round 0: 50/50 probability to probe.
    - Subsequent rounds:
        - If previous threshold met (C_t >= m): Maintain C.
        - If threshold failed (C_t < m): 
            - If I played C, switch to D to punish.
            - If I played D, stay D unless "near-miss" (C_t >= m-1) triggers re-initiation.
    - Near-Threshold Optimization: If observed count is consistently m-1, play C if not exploited in the last 2 rounds.
    - Final Round: If last round failed, defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description
        self.m = game_description.m
        self.n = game_description.n_players
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.r - 1:
            if history.round_number > 0 and history.opponent_cooperators[-1] < self.m:
                return Action.D
        if history.round_number == 0:
            return Action.C if random.random() < 0.5 else Action.D
        prev_round = history.round_number - 1
        c_prev = history.opponent_cooperators[prev_round]
        my_prev_action = history.my_actions[prev_round]
        if c_prev >= self.m:
            return Action.C
        if my_prev_action:
            return Action.D
        if c_prev >= self.m - 1:
            return Action.C
        if history.round_number >= 2:
            prev_2_cooperators = history.opponent_cooperators[prev_round - 1]
            if c_prev == self.m - 1 and prev_2_cooperators == self.m - 1:
                return Action.C
        return Action.D

class Strategy_COLLECTIVE_76(BaseStrategy):
    """
    Implements a Threshold-Triggered Conditional Cooperation strategy.
    
    This strategy acts as a modified Grim Trigger, calibrated to the minimum number of cooperators (m) 
    required to trigger the collective reward (k). It initiates with cooperation and adapts based 
    on the previous round's outcome:
    - If m or more cooperators were present, it continues to cooperate.
    - If fewer than m were present, it defects, assuming the group failed to coordinate.
    - If it was defecting, it will switch back to cooperating if the group manages to hit the 
      threshold (showing the group is capable of coordination despite the player's previous absence).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_my_action_is_c = bool(history.my_actions[-1])
        prev_c_count = int(history.opponent_cooperators[-1])
        if prev_my_action_is_c:
            if prev_c_count >= self.m:
                return Action.C
            else:
                return Action.D
        elif prev_c_count >= self.m:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_77(BaseStrategy):
    """
    Threshold-Responsive Tit-for-Tat (TR-TFT):
    - Round 1: Always Cooperate.
    - Rounds 2 to r-1: 
        - If previous round met threshold (>= m): Cooperate.
        - If previous round failed threshold (< m): Calculate shortfall and play Defect for a penalty period 
          (1 or 2 rounds), then test again with Cooperate.
    - Final Round: If previous round met threshold (>= m), play C, else D.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.penalty_rounds_left = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if self.penalty_rounds_left > 0:
            self.penalty_rounds_left -= 1
            return Action.D
        last_round_idx = history.round_number - 1
        n_c_last = history.opponent_cooperators[last_round_idx]
        threshold_met = n_c_last >= self.desc.m
        if history.round_number == self.desc.n_rounds - 1:
            if threshold_met:
                return Action.C
            else:
                return Action.D
        if threshold_met:
            return Action.C
        else:
            shortfall = self.desc.m - n_c_last
            if shortfall >= self.desc.m / 2:
                self.penalty_rounds_left = 1
            else:
                self.penalty_rounds_left = 0
            return Action.D

class Strategy_COLLECTIVE_78(BaseStrategy):
    """
    Threshold-Responsive Tit-for-Tat (TR-TFT):
    Starts by cooperating. In subsequent rounds, it maintains cooperation if the threshold 
    was met in the previous round. If the threshold was missed, it defects to avoid 
    exploitation. After 2 consecutive failures to meet the threshold, it attempts 
    a 're-cooperation' signal to test for renewed group cooperation. In the final round, 
    it plays C if the threshold was met or if the recovery trigger was successful 
    in the previous round; otherwise, it plays D.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == 0:
            return Action.C
        last_my_action = history.my_actions[-1]
        last_total_cooperators = history.opponent_cooperators[-1] + (1 if last_my_action else 0)
        threshold_met_last_round = last_total_cooperators >= m
        if threshold_met_last_round:
            self.consecutive_failures = 0
        else:
            self.consecutive_failures += 1
        if current_round == n_rounds - 1:
            if threshold_met_last_round or self.consecutive_failures == 0:
                return Action.C
            else:
                return Action.D
        if threshold_met_last_round:
            return Action.C
        elif self.consecutive_failures >= 2:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_79(BaseStrategy):
    """
    A strategy that cooperates initially to test the threshold, maintains cooperation 
    while the collective threshold is met, defects if the threshold is failed, 
    and always defects in the final round. It includes a start-up delay mechanism 
    to distinguish between temporary coordination failure and a lack of cooperation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.wait_count = 0

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == r - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        prev_cooperators = history.opponent_cooperators[-1] + (1 if my_prev_action else 0)
        threshold_met = prev_cooperators >= m
        if threshold_met:
            self.wait_count = 0
            return Action.C
        elif self.wait_count < 1:
            self.wait_count += 1
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_80(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that balances cooperation with adaptive
    recalibration and trend analysis, while accounting for edge cases like small
    margins or insufficient rewards.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.k = game_description.k
        self.r = game_description.n_rounds
        self.consecutive_misses = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if self.k <= 1.0:
            return Action.D
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if self.m >= self.n - 1 and self.n <= 5:
            if history.opponent_cooperators[-1] < self.m:
                my_last_action = history.my_actions[-1]
                total_coops = history.opponent_cooperators[-1] + (1 if my_last_action else 0)
                if total_coops < self.m:
                    self.consecutive_misses += 1
                else:
                    self.consecutive_misses = 0
            else:
                self.consecutive_misses = 0
            if self.consecutive_misses >= 2:
                return Action.D
            return Action.C
        if current_round == self.r - 1:
            avg_coops = np.mean(history.opponent_cooperators + history.my_actions.astype(int))
            return Action.C if avg_coops >= self.m else Action.D
        last_my_action = int(history.my_actions[-1])
        last_opp_coops = history.opponent_cooperators[-1]
        prev_total = last_opp_coops + last_my_action
        if prev_total < self.m:
            return Action.D
        if prev_total >= self.m:
            if prev_total == self.m:
                return Action.C
            if prev_total > self.m:
                return Action.D
            if random.random() < self.m / self.n:
                return Action.C if last_my_action else Action.D
            return Action.D
        if current_round >= 3:
            recent_coops = history.opponent_cooperators[-3:] + history.my_actions[-3:].astype(int)
            if recent_coops[2] > recent_coops[1] > recent_coops[0]:
                return Action.C
        return Action.D

class Strategy_COLLECTIVE_81(BaseStrategy):
    """
    Threshold-Responsive Trigger (TRT) Strategy:
    - Maintains cooperation threshold m by tracking history.
    - Uses probabilistic defection for 'Greed Control' when surplus cooperation is present.
    - Penalizes defectors unless the player's own cooperation is vital for reaching the threshold.
    - Uses historical cooperation averages to decide final round behavior.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = self.game_description.n_players
        self.m = self.game_description.m
        self.r = self.game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_prev_action = bool(history.my_actions[-1])
        my_contribution = 1 if my_prev_action else 0
        n_c_t = history.opponent_cooperators[-1] + my_contribution
        current_round = history.round_number + 1
        downward_trend = False
        if history.round_number >= 3:
            recent_rounds = history.opponent_cooperators[-3:] + np.array([1 if a else 0 for a in history.my_actions[-3:]])
            if recent_rounds[0] > recent_rounds[1] > recent_rounds[2]:
                downward_trend = True
        if n_c_t < self.m:
            if downward_trend:
                return Action.D
            if my_prev_action and n_c_t == self.m - 1:
                return Action.C
            return Action.D
        if current_round == self.r:
            total_cooperators_history = history.opponent_cooperators + np.array([1 if a else 0 for a in history.my_actions])
            running_avg_cooperation = np.mean(total_cooperators_history / self.n)
            if running_avg_cooperation >= self.m / self.n:
                return Action.C
            else:
                return Action.D
        surplus = n_c_t - self.m
        if surplus > 0:
            denom = self.n - self.m
            prob = min(1.0, surplus / denom) if denom > 0 else 1.0
            if random.random() < prob:
                return Action.D
        return Action.C

class Strategy_COLLECTIVE_82(BaseStrategy):
    """
    A Conditional Threshold Strategy for the Collective Risk Dilemma.
    Implements a Tit-for-Tat based logic with periodic probing and a terminal push.
    
    Strategy Logic:
    - Round 1: Always Cooperate (C).
    - Rounds 2 to r-1:
        - If previous cooperation met threshold (C_prev >= m): Play C.
        - If threshold not met (C_prev < m): 
            - Every X rounds (where X = max(5, ceil(r/4))), force a 'probe' C.
            - Otherwise: Play D.
    - Round r (Terminal Phase):
        - If threshold was nearly met (C_prev >= m - 1): Play C.
        - Otherwise: Play D.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.X = max(5, math.ceil(self.game_description.n_rounds / 4))

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        total_prev_coop = prev_cooperators + (1 if my_prev_action else 0)
        if current_round == total_rounds - 1:
            if total_prev_coop >= m - 1:
                return Action.C
            return Action.D
        if (current_round + 1) % self.X == 0 and total_prev_coop < m:
            return Action.C
        if total_prev_coop >= m:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_83(BaseStrategy):
    """
    Implements a decision-theoretic strategy for the Collective Risk Dilemma based on 
    Bayesian estimation of opponent cooperation probability. 
    
    Decision Logic:
    - Round 1: Cooperate if n/k > 1, else Defect.
    - Rounds > 1: Estimate opponent probability p based on historical frequency.
      Calculate the probability that our contribution is pivotal (exactly m-1 opponents cooperate).
      Contribute (C) if k * P(pivotal) > 1, otherwise Defect (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C if self.n / self.k > 1 else Action.D
        t = history.round_number
        total_observed_cooperators = np.sum(history.opponent_cooperators) + np.sum(history.my_actions)
        total_slots = self.n * t
        p = total_observed_cooperators / total_slots if total_slots > 0 else 0.5
        n_choose_k = math.comb(self.n - 1, self.m - 1)
        p_pivotal = n_choose_k * math.pow(p, self.m - 1) * math.pow(1 - p, self.n - self.m)
        if self.k * p_pivotal > 1:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_84(BaseStrategy):
    """
    A strategy that acts as a 'Conditional Trigger-Threshold' agent.
    It cooperates to reach the threshold 'm', punishes defection, but attempts
    to act as the 'stabilizer' when the group is exactly one person short
    of the threshold, and periodically probes for recovery after prolonged defection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.desc.m
        my_last_action = Action.C if history.my_actions[-1] else Action.D
        my_last_c = 1 if my_last_action == Action.C else 0
        total_prev_c = history.opponent_cooperators[-1] + my_last_c
        if total_prev_c >= m:
            return Action.C
        if total_prev_c == m - 1 and my_last_action == Action.D:
            return Action.C
        if history.round_number >= 2:
            prev_total_c = history.opponent_cooperators[-1] + (1 if history.my_actions[-1] else 0)
            prev_prev_total_c = history.opponent_cooperators[-2] + (1 if history.my_actions[-2] else 0)
            if prev_total_c == 0 and prev_prev_total_c == 0:
                return Action.C
        return Action.D

class Strategy_COLLECTIVE_85(BaseStrategy):
    """
    Threshold-Tit-for-Tat with Gradual Forgiveness.
    
    Logic Summary:
    1. Always start with C.
    2. Maintain cooperation if the previous round's threshold (m) was met.
    3. If threshold failed (C_prev < m), Defect (D) to avoid exploitation.
    4. Sucker Trap detection: If C_prev == m and I cooperated for 3 consecutive rounds 
       receiving only reward 'k' while others got 'k+1', switch to D to signal.
    5. End-Game logic: If aggregate cooperation < m, Defect.
    6. Initialization handling: If early rounds fail, attempt a 'probe' after short punishment.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.n = game_description.n_players
        self.sucker_trap_counter = 0
        self.consecutive_defect_rounds = 0
        self.probing = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        c_i = 1 if my_prev_action else 0
        total_cooperators = history.opponent_cooperators[-1] + c_i
        threshold_met = total_cooperators >= self.m
        if history.round_number == self.r - 1:
            total_coop_all_past = np.sum(history.opponent_cooperators) + np.sum(history.my_actions)
            avg_coop = total_coop_all_past / history.round_number
            if avg_coop < self.m:
                return Action.D
            return Action.C
        if my_prev_action == Action.C and total_cooperators == self.m:
            self.sucker_trap_counter += 1
        else:
            self.sucker_trap_counter = 0
        if self.sucker_trap_counter >= 3:
            self.sucker_trap_counter = 0
            return Action.D
        if threshold_met:
            self.consecutive_defect_rounds = 0
            self.probing = False
            return Action.C
        elif my_prev_action == Action.C:
            self.consecutive_defect_rounds = 1
            return Action.D
        else:
            self.consecutive_defect_rounds += 1
            if history.round_number < 4 and self.consecutive_defect_rounds >= 2:
                self.probing = True
                return Action.C
            return Action.D

class Strategy_COLLECTIVE_86(BaseStrategy):
    """
    A strategy that implements Threshold-Conditional Cooperation.
    - Round 1: Always Cooperate.
    - Subsequent rounds:
        - If the group successfully met the threshold (or could with my help), cooperate.
        - Otherwise, defect to avoid exploitation when cooperation is futile.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = self.game_description.m
        self.n_rounds = self.game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_prev_action_bool = history.my_actions[-1]
        prev_my_c = 1 if my_prev_action_bool else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + prev_my_c
        if total_cooperators_prev >= self.m:
            return Action.C
        if history.opponent_cooperators[-1] + 1 >= self.m:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_87(BaseStrategy):
    """
    Implements a Conditional Threshold Reciprocity strategy for a Collective Risk Dilemma.
    1. First round (t=0): Always cooperate.
    2. Subsequent rounds: Cooperate if the previous round met the threshold (N_C >= m) 
       or if the long-term average cooperation >= m.
    3. Edge cases:
       - If threshold missed, defect unless long-term average >= m.
       - "Probe" mechanism: If after a failure we switch to D, attempt C every 3 rounds.
       - Last round (t=r-1): Cooperate if the group has successfully hit the 
         threshold m in at least 75% of rounds 0 to r-2, otherwise Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.n = game_description.n_players
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        my_contribution = 1 if my_prev_action else 0
        n_c_prev = prev_cooperators + my_contribution
        total_prev_c = np.sum(history.opponent_cooperators) + np.sum(history.my_actions)
        avg_cooperation = total_prev_c / current_round
        if current_round == self.r - 1:
            all_n_c = history.opponent_cooperators + history.my_actions.astype(int)
            successful_rounds = np.sum(all_n_c >= self.m)
            success_rate = successful_rounds / current_round
            if success_rate >= 0.75:
                return Action.C
            return Action.D
        if n_c_prev >= self.m:
            return Action.C
        else:
            if avg_cooperation >= self.m:
                return Action.C
            if current_round % 3 == 0:
                return Action.C
            return Action.D

class Strategy_COLLECTIVE_88(BaseStrategy):
    """
    A conditional strategy for the Collective Risk Dilemma that balances cooperation 
    for threshold achievement, punishment for non-cooperation, and efficiency optimization 
    for excessive cooperation. It incorporates adaptive threshold adjustment based on 
    performance trends and specific logic for the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.n = game_description.n_players

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        my_prev_c = 1 if my_prev_action else 0
        n_prev_opponents = history.opponent_cooperators[-1]
        n_prev_total = n_prev_opponents + my_prev_c
        lookback_window = math.ceil(self.r / 10)
        if t >= lookback_window:
            all_opponents = history.opponent_cooperators
            all_my_actions = history.my_actions.astype(int)
            total_coop_per_round = all_opponents + all_my_actions
            recent_rounds = total_coop_per_round[-lookback_window:]
            success_count = np.sum(recent_rounds >= self.m)
            success_rate = success_count / lookback_window
            if success_rate < 0.5:
                return Action.D
        if t == self.r - 1:
            total_coop_per_round = history.opponent_cooperators + history.my_actions.astype(int)
            successes = np.sum(total_coop_per_round >= self.m)
            if successes / t >= 0.5:
                return Action.C
            else:
                return Action.D
        if n_prev_total < self.m:
            if my_prev_action == Action.C:
                return Action.D
            else:
                return Action.C
        if n_prev_total > self.m + 1:
            return Action.D
        return Action.C

class Strategy_COLLECTIVE_89(BaseStrategy):
    """
    Implements a threshold-seeking strategy for the Collective Risk Dilemma.
    Starts with Cooperation, then adapts based on the previous round's outcome
    to either maintain, initiate, or withdraw support based on whether the
    minimum cooperators threshold (m) was met. Includes end-game logic to 
    maximize payoff when the threshold is consistently achievable.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.n = game_description.n_players

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_last_action = Action.C if history.my_actions[-1] else Action.D
        my_last_val = 1 if my_last_action == Action.C else 0
        total_cooperators_last_round = my_last_val + history.opponent_cooperators[-1]
        if history.round_number == self.r - 1:
            historical_successes = 0
            for i in range(len(history.my_actions)):
                my_val = 1 if history.my_actions[i] else 0
                if my_val + history.opponent_cooperators[i] >= self.m:
                    historical_successes += 1
            if historical_successes / history.round_number > 0.5:
                return Action.C
            return Action.D
        if total_cooperators_last_round >= self.m:
            return Action.D
        if total_cooperators_last_round < self.m:
            if my_last_action == Action.D:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_COLLECTIVE_90(BaseStrategy):
    """
    A conditional cooperation strategy based on "Threshold Tit-for-Tat".
    
    Logic:
    1. Initial Round: Always cooperate (C).
    2. Threshold Enforcement: If the previous round's total cooperation count (C_{t-1})
       was >= m, continue to cooperate.
    3. Punishment: If C_{t-1} < m, switch to defect (D) for the current round.
    4. Resumption: If in a 'Defect' state, observe current round's cooperation. 
       If C_{t} >= m, reset to cooperate in the following round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.is_punishing = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        previous_my_action = history.my_actions[-1]
        previous_opponent_coop_count = history.opponent_cooperators[-1]
        total_cooperators_prev = int(previous_opponent_coop_count) + (1 if previous_my_action else 0)
        m = self.game_description.m
        if self.is_punishing:
            if total_cooperators_prev >= m:
                self.is_punishing = False
                return Action.C
            else:
                return Action.D
        elif total_cooperators_prev < m:
            self.is_punishing = True
            return Action.D
        else:
            return Action.C

class Strategy_COLLECTIVE_91(BaseStrategy):
    """
    Implements a threshold-conditional trigger strategy for the Collective Risk Dilemma.
    
    Round 1: Cooperate.
    Rounds 2 to r-1: 
        - Cooperate if the previous round met or exceeded the threshold m.
        - Defect if the previous round failed to meet the threshold.
        - Includes automatic recovery (resumes cooperation if the threshold is met).
    Final Round (r):
        - Cooperate if the game has been consistently successful (m met in all previous rounds).
        - Defect otherwise (frequent failure or recent failure).
    Edge cases like "near miss" (m-1) result in defection as they fail the threshold condition.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_index = history.round_number
        n_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round_index == 0:
            return Action.C
        my_prev_action = int(history.my_actions[-1])
        prev_round_total_cooperators = history.opponent_cooperators[-1] + my_prev_action
        prev_round_success = prev_round_total_cooperators >= m
        if current_round_index < n_rounds - 1:
            if prev_round_success:
                return Action.C
            else:
                return Action.D
        if current_round_index == n_rounds - 1:
            all_successful = True
            for i in range(current_round_index):
                prev_c_count = history.opponent_cooperators[i] + int(history.my_actions[i])
                if prev_c_count < m:
                    all_successful = False
                    break
            if all_successful and prev_round_success:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_COLLECTIVE_92(BaseStrategy):
    """
    Threshold-Sensitive Tit-for-Tat (TSTFT):
    A strategy that uses conditional cooperation to meet the threshold m.
    It contributes only when necessary if the threshold is met, rotates
    contribution when the threshold is not met, and abandons cooperation
    if failures persist.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number < 2:
            return Action.C
        my_last_action = int(history.my_actions[-1])
        opponents_last_count = history.opponent_cooperators[-1]
        prev_round_total = my_last_action + opponents_last_count
        m = self.game_description.m
        if prev_round_total < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 2:
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if prev_round_total >= m:
            if prev_round_total == m:
                return Action.C
            else:
                return Action.D
        elif my_last_action == 1:
            return Action.D
        else:
            return Action.C

class Strategy_COLLECTIVE_93(BaseStrategy):
    """
    Threshold-Responsive Trigger (TRT) Strategy.
    
    Operates on a conditional cooperative basis:
    - Round 1: Always Cooperate (C) to signal.
    - Rounds 2 to r-1: 
        - Reciprocity: If previous round cooperation count >= m, Cooperate (C).
        - Retaliation: If previous round cooperation count < m, Defect (D).
    - Round r (Terminal): Repeat the action performed in the previous round (r-1).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self._last_action = None

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            self._last_action = Action.C
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return self._last_action
        my_prev_action = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + my_prev_action
        m = self.game_description.m
        if total_cooperators_prev >= m:
            self._last_action = Action.C
            return Action.C
        else:
            self._last_action = Action.D
            return Action.D

class Strategy_COLLECTIVE_94(BaseStrategy):
    """
    Tit-for-Tat with a Threshold Trigger:
    A strategy that cooperates if the collective threshold (m) is met,
    punishes by defecting if the threshold is missed, and employs a
    probing cycle if the population remains stuck in a non-cooperative
    state for too long.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0
        self.probing_state = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.game_description.m
        last_round_idx = history.round_number - 1
        my_last_action = int(history.my_actions[last_round_idx])
        nc_last = history.opponent_cooperators[last_round_idx] + my_last_action
        if nc_last < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
            self.probing_state = 0
        if self.consecutive_failures >= 3:
            self.probing_state = self.probing_state % 3 + 1
            if self.probing_state == 3:
                return Action.C
            else:
                return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            if nc_last >= m:
                return Action.C
            return Action.D
        if nc_last >= m:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_95(BaseStrategy):
    """
    A conditional cooperation strategy for the Collective Risk Dilemma.
    
    Operates on a principle of conditional cooperation:
    1. First round: Always Cooperate (C) to signal intent.
    2. Subsequent rounds:
       - If the threshold m was met in the previous round, continue to Cooperate (C).
       - If a 'near-miss' occurred (m-1 cooperators), switch to or continue to Cooperate (C).
       - Otherwise, Defect (D) to protect endowment.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        total_cooperators_last_round = history.opponent_cooperators[-1] + (1 if my_prev_action else 0)
        if total_cooperators_last_round >= self.game.m:
            return Action.C
        elif total_cooperators_last_round == self.game.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_96(BaseStrategy):
    """
    Implements a conditional 'tit-for-tat with threshold-triggered altruism' strategy
    for the Collective Risk Dilemma, balancing the costs of contribution against
    threshold attainment probabilities.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.k = game_description.k
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if self.k <= 1:
            return Action.D
        is_hard_threshold = self.m > self.n - 1
        if history.round_number == 0:
            if self.m / self.n > 0.5:
                return Action.C
            return Action.D
        last_round_idx = history.round_number - 1
        last_my_action = int(history.my_actions[last_round_idx])
        c_prev = history.opponent_cooperators[last_round_idx] + last_my_action
        if history.round_number == self.r - 1:
            if c_prev >= self.m - 1:
                return Action.C
            return Action.D
        if is_hard_threshold:
            if c_prev >= self.m:
                return Action.C
            return Action.D
        if c_prev >= self.m:
            return Action.C
        g = self.m - c_prev
        if g == 1:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_97(BaseStrategy):
    """
    Implements a threshold-targeted conditional cooperation strategy.
    
    Strategy:
    1. First round: Always Cooperate (C).
    2. Rounds 2 to r-1: 
       - If previous round cooperators < m: Play C.
       - If previous round cooperators >= m: Play D.
    3. Last round (r): Same logic as rounds 2 to r-1.
    4. Adaptive Refinement: If history shows consistent excess (m+1 or m+2 cooperators), 
       transition to a probabilistic contribution with p = m/n.
    5. Edge Case Handling: 
       - Total Defection (< m/2): Reset by playing C for two rounds.
       - Free-Rider Response: If we were C, hit m, moved to D, and the threshold 
         immediately fails, return to C.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.reset_counter = 0
        self.last_action_was_c = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            self.last_action_was_c = True
            return Action.C
        my_prev_action = history.my_actions[-1]
        c_prev_others = history.opponent_cooperators[-1]
        c_prev_total = c_prev_others + (1 if my_prev_action else 0)
        if c_prev_total < m / 2:
            self.reset_counter = 2
        if self.reset_counter > 0:
            self.reset_counter -= 1
            self.last_action_was_c = True
            return Action.C
        if not my_prev_action and self.last_action_was_c and (c_prev_total < m):
            self.last_action_was_c = True
            return Action.C
        if current_round >= 3:
            recent_total_coop = history.opponent_cooperators[-3:] + history.my_actions[-3:]
            if np.all(recent_total_coop >= m + 1):
                if random.random() < m / n:
                    self.last_action_was_c = True
                    return Action.C
                else:
                    self.last_action_was_c = False
                    return Action.D
        if c_prev_total < m:
            self.last_action_was_c = True
            return Action.C
        else:
            self.last_action_was_c = False
            return Action.D

class Strategy_COLLECTIVE_98(BaseStrategy):
    """
    A sophisticated Collective Risk Dilemma strategy implementing threshold-based 
    cooperation, adaptive history analysis, and endgame exploitation logic.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.prior_alpha = 1.0
        self.prior_beta = 1.0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        t = history.round_number
        if t == 0:
            return Action.C
        prev_nc = int(history.opponent_cooperators[-1])
        if history.my_actions[-1]:
            prev_nc += 1
        self.prior_alpha += prev_nc
        self.prior_beta += n - prev_nc
        if t >= 2 and history.opponent_cooperators[-1] == 0 and (history.opponent_cooperators[-2] == 0):
            prev_total = history.opponent_cooperators[-1] + (1 if history.my_actions[-1] else 0)
            prev_prev_total = history.opponent_cooperators[-2] + (1 if history.my_actions[-2] else 0)
            if prev_total == 0 and prev_prev_total == 0:
                return Action.D
        if t >= 3:
            full_coop_count = 0
            for i in range(1, 4):
                total_c = history.opponent_cooperators[-i] + (1 if history.my_actions[-i] else 0)
                if total_c == n:
                    full_coop_count += 1
            if full_coop_count == 3:
                return Action.C
        if t == r - 1:
            recent_avg = np.mean(history.opponent_cooperators[-min(5, t):])
            if recent_avg >= m - 1:
                return Action.C
            return Action.D
        if t > 0.9 * r:
            recent_avg = np.mean(history.opponent_cooperators[-min(5, t):])
            if recent_avg < m:
                return Action.D
            return Action.C
        if prev_nc >= m:
            return Action.C
        gap = m - prev_nc
        if gap == 1:
            return Action.C
        if gap > 1:
            window = min(3, t)
            recent_history = history.opponent_cooperators[-window:]
            total_history = [recent_history[i] + (1 if history.my_actions[-(window - i)] else 0) for i in range(window)]
            avg_nc = np.mean(total_history)
            if avg_nc > 0.5 * m:
                return Action.C
            if avg_nc < 0.3 * n:
                return Action.D
        threshold_pct = 0.2
        if m > prev_nc > m - threshold_pct * n:
            prob = prev_nc / m
            if random.random() < prob:
                return Action.C
        return Action.D

class Strategy_COLLECTIVE_99(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that utilizes cooperative signaling,
    threshold-testing for efficiency, and risk-adjusted decision making in the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.cooperation_count = 0
        self.total_rounds_succeeded = 0
        self.testing_slack = False
        self.defect_mode = False

    def __call__(self, history: PlayerHistory) -> Action:
        m = self.game_description.m
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            self.cooperation_count = 1
            return Action.C
        prev_my_action = history.my_actions[-1]
        prev_my_c = 1 if prev_my_action else 0
        prev_opp_c = int(history.opponent_cooperators[-1])
        total_prev_c = prev_my_c + prev_opp_c
        prev_success = total_prev_c >= m
        if prev_success:
            self.total_rounds_succeeded += 1
        if current_round >= 3:
            c_history = [int(a) + int(o) for a, o in zip(history.my_actions[-3:], history.opponent_cooperators[-3:])]
            if all((c_history[i] > c_history[i + 1] for i in range(len(c_history) - 1))):
                self.defect_mode = True
        if current_round == r - 1:
            success_rate = self.total_rounds_succeeded / current_round
            if success_rate < 0.5:
                return Action.D
            return Action.C
        if self.defect_mode:
            return Action.D
        if not prev_success:
            self.testing_slack = False
            return Action.D
        if total_prev_c == m:
            self.testing_slack = False
            self.cooperation_count += 1
            return Action.C
        if total_prev_c > m:
            if self.testing_slack:
                return Action.D
            self.testing_slack = True
            return Action.D
        return Action.C

class Strategy_COLLECTIVE_100(BaseStrategy):
    """
    Cooperate until the final round (t=r), defecting at the final round.
    For intermediate rounds, cooperate if the collective threshold (m) 
    was met in the previous round, otherwise defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        my_previous_action = 1 if history.my_actions[-1] else 0
        total_cooperators = history.opponent_cooperators[-1] + my_previous_action
        if total_cooperators >= self.game_description.m:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_101(BaseStrategy):
    """
    Implements a Trigger-Based Conditional Contribution strategy for the Collective Risk Dilemma.
    
    The strategy maintains an internal state ('target_reached').
    - Starts by cooperating.
    - If cooperative: If the threshold (m) was met in the previous round, continues cooperating.
      If the threshold was not met, it attempts recovery by cooperating again (hoping others follow).
    - If in a punitive state (target_reached=False): If the threshold was met in the previous round,
      it resets to cooperative state and plays C. If threshold not met, it continues to punish (D).
    - In the final round, it acts based on the current state (C if cooperative, D if punitive).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.target_reached = True

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        m = self.game_description.m
        total_rounds = self.game_description.n_rounds
        if current_round == 0:
            return Action.C
        my_prev_action = int(history.my_actions[-1])
        others_prev_count = history.opponent_cooperators[-1]
        n_c = others_prev_count + my_prev_action
        if current_round < total_rounds:
            if self.target_reached:
                if n_c >= m:
                    return Action.C
                else:
                    self.target_reached = False
                    return Action.C
            elif n_c >= m:
                self.target_reached = True
                return Action.C
            else:
                return Action.D
        elif self.target_reached:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_102(BaseStrategy):
    """
    Implements a conditional cooperation strategy for the Collective Risk Dilemma.
    Maintains threshold 'm' via tit-for-tat logic with probabilistic recovery 
    and exponential decay for persistent defection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0
        self.shock_recovery = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        prev_cooperators = history.opponent_cooperators[-1]
        my_prev_action = 1 if history.my_actions[-1] else 0
        total_cooperators = prev_cooperators + my_prev_action
        if total_cooperators < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
            self.shock_recovery = False
        if history.round_number == r - 1:
            return Action.C if total_cooperators >= m else Action.D
        if total_cooperators >= m:
            self.shock_recovery = False
            return Action.C
        if history.round_number > 1:
            prev_total = history.opponent_cooperators[-2] + (1 if history.my_actions[-2] else 0)
            if prev_total >= m and total_cooperators < m:
                self.shock_recovery = True
                return Action.D
        if self.consecutive_failures > 1:
            base_prob = (m - total_cooperators) / (n - total_cooperators) if n > total_cooperators else 0
            prob_cooperate = base_prob * 0.5 ** (self.consecutive_failures - 1)
        else:
            prob_cooperate = (m - total_cooperators) / (n - total_cooperators) if n > total_cooperators else 0
        if random.random() < prob_cooperate:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_103(BaseStrategy):
    """
    Threshold-Sensitive Tit-for-Tat (TSTFT):
    Starts by cooperating. In subsequent rounds, it acts based on the previous round's outcome relative to the threshold m.
    If the threshold was met, it cooperates.
    If the threshold was missed by exactly 1, it attempts cooperation to bridge the gap.
    If the threshold was missed by > 1, it defects.
    Includes a defensive switch: if the group consistently fails to reach the threshold for 1/4 of total rounds, switches to permanent defection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.consecutive_failures = 0

    def __call__(self, history: PlayerHistory) -> Action:
        m = self.desc.m
        n = self.desc.n_players
        if history.round_number == 0:
            return Action.C
        my_prev_action = int(history.my_actions[-1])
        c_prev = history.opponent_cooperators[-1] + my_prev_action
        if c_prev < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures > self.desc.n_rounds / 4:
            return Action.D
        if c_prev >= m:
            return Action.C
        if c_prev == m - 1:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_104(BaseStrategy):
    """
    Conditional Reciprocal Thresholding (CRT):
    Maintains a cooperative state to hit threshold m, while adjusting
    participation based on previous round outcomes to minimize cost.
    Uses defection damping for repeated failures and special logic for
    the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            if self.m <= self.n / 2:
                return Action.C
            else:
                return Action.C if random.random() < self.m / self.n else Action.D
        prev_my_action = history.my_actions[-1]
        prev_opp_count = history.opponent_cooperators[-1]
        prev_total_c = prev_opp_count + (1 if prev_my_action else 0)
        if history.round_number >= 3:
            recent_my_actions = history.my_actions[-3:]
            recent_opp_counts = history.opponent_cooperators[-3:]
            if all(recent_my_actions) and all((c + 1 < self.m for c in recent_opp_counts)):
                return Action.D
        if history.round_number == self.r - 1:
            if history.round_number >= 3:
                recent_total_c = [history.opponent_cooperators[i] + (1 if history.my_actions[i] else 0) for i in range(-3, 0)]
                if all((c >= self.m for c in recent_total_c)):
                    if prev_my_action:
                        return Action.D
            if history.round_number >= 3:
                if all((c + (1 if a else 0) < self.m for c, a in zip(history.opponent_cooperators[-3:], history.my_actions[-3:]))):
                    return Action.D
        if prev_total_c == self.m:
            return Action.C if prev_my_action else Action.D
        elif prev_total_c < self.m:
            return Action.C
        else:
            return Action.D
        return Action.D

class Strategy_COLLECTIVE_105(BaseStrategy):
    """
    Conditional Threshold Reciprocity (CTR): A strategy that maintains threshold
    cooperation, punishes defection, and attempts to restart after total collapse.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.restart_prob = 0.1
        self.my_id = random.randint(1, game_description.n_players)

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        n = self.game_description.n_players
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            if self.my_id <= m:
                return Action.C
            else:
                return Action.D
        last_round_my_action = history.my_actions[-1]
        last_round_opp_c = history.opponent_cooperators[-1]
        total_cooperators_prev = last_round_opp_c + (1 if last_round_my_action else 0)
        if total_cooperators_prev >= m:
            return Action.C
        elif total_cooperators_prev == 0:
            if random.random() < self.restart_prob:
                return Action.C
            else:
                return Action.D
        else:
            return Action.D

class Strategy_COLLECTIVE_106(BaseStrategy):
    """
    Implements a Threshold-Targeted Conditional Reciprocation strategy for the Collective Risk Dilemma.
    
    Logic:
    - Round 1: Cooperate.
    - Rounds 2 to r:
        - If previous round met threshold (or logic says yes): Cooperate.
        - If previous round missed threshold but was close (gap of 1): Cooperate.
        - If previous round failed significantly: Defect.
    - Tracks 'Target_Met' status and 'Persistent Failure' count (three consecutive failures after 
      attempting to bridge).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.target_met = True
        self.consecutive_failed_attempts = 0

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        c_prev_total = history.opponent_cooperators[-1] + (1 if my_prev_action else 0)
        self.target_met = c_prev_total >= self.game_description.m
        if not self.target_met and c_prev_total >= self.game_description.m - 1:
            self.consecutive_failed_attempts += 1
        else:
            self.consecutive_failed_attempts = 0
        if self.consecutive_failed_attempts >= 3:
            return Action.D
        if self.target_met:
            return Action.C
        if c_prev_total >= self.game_description.m - 1:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_107(BaseStrategy):
    """
    Threshold-Contingent Conditional Reciprocity (TCCR).
    
    This strategy aims to maintain the minimum threshold 'm' needed to trigger 
    the reward 'k' while minimizing individual contribution costs. It uses 
    reciprocal signals and opportunistic "free-rider" testing.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.testing_free_ride = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        m = self.game_description.m
        if history.round_number == 0:
            return Action.C
        prev_round_idx = history.round_number - 1
        my_prev_action_val = 1 if history.my_actions[prev_round_idx] else 0
        total_cooperators_prev = history.opponent_cooperators[prev_round_idx] + my_prev_action_val
        if history.round_number == r - 1:
            if total_cooperators_prev >= m:
                return Action.C
            else:
                return Action.D
        if self.testing_free_ride:
            if total_cooperators_prev >= m:
                return Action.D
            else:
                self.testing_free_ride = False
                return Action.C
        if total_cooperators_prev < m:
            if total_cooperators_prev == m - 1:
                return Action.C
            return Action.D
        if total_cooperators_prev >= m:
            if total_cooperators_prev > m:
                self.testing_free_ride = True
                return Action.D
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_108(BaseStrategy):
    """
    Implements a threshold-triggered conditional reciprocity strategy.
    
    Logic:
    1. Round 1: Cooperate.
    2. Subsequent rounds:
        - If previous count >= m: Cooperate.
        - Threshold Correction: If previously D and count == m-1, Cooperate.
        - One-Short Testing: If count == m-1 repeatedly, attempt Cooperate for 2 rounds.
        - Total Failure: If count == 0 for two consecutive rounds, Defect permanently.
    3. Final Round: 
        - If success rate >= 0.5, Cooperate; else Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_total_defections = 0
        self.one_short_consecutive_count = 0
        self.one_short_test_active_until = -1

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        m = self.game_description.m
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        my_prev_action = Action.C if history.my_actions[-1] else Action.D
        total_cooperators_prev = prev_cooperators + (1 if my_prev_action == Action.C else 0)
        if current_round >= 2:
            prev_prev_coop = history.opponent_cooperators[-2]
            prev_prev_my_action = Action.C if history.my_actions[-2] else Action.D
            total_cooperators_prev_prev = prev_prev_coop + (1 if prev_prev_my_action == Action.C else 0)
            if total_cooperators_prev == 0 and total_cooperators_prev_prev == 0:
                self.consecutive_total_defections = 2
        if self.consecutive_total_defections >= 2:
            return Action.D
        if current_round == r - 1:
            total_successes = 0
            for i in range(current_round):
                c = history.opponent_cooperators[i] + (1 if history.my_actions[i] else 0)
                if c >= m:
                    total_successes += 1
            success_rate = total_successes / current_round if current_round > 0 else 0
            return Action.C if success_rate >= 0.5 else Action.D
        if current_round <= self.one_short_test_active_until:
            return Action.C
        if total_cooperators_prev == m - 1:
            self.one_short_consecutive_count += 1
        else:
            self.one_short_consecutive_count = 0
        if self.one_short_consecutive_count >= 2:
            self.one_short_test_active_until = current_round + 1
            self.one_short_consecutive_count = 0
            return Action.C
        if my_prev_action == Action.D and total_cooperators_prev == m - 1:
            return Action.C
        if total_cooperators_prev >= m:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_109(BaseStrategy):
    """
    A Tit-for-Tat variant for Collective Risk Dilemmas.
    Plays C in the first round. In subsequent rounds, it acts based on the previous round's 
    cooperation count relative to the threshold m. It includes a recovery mechanism to 
    periodically test for cooperation if the collective is stuck in a failure loop.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.is_testing = False
        self.last_test_round = -2

    def __call__(self, history: PlayerHistory) -> Action:
        m = self.game_description.m
        if history.round_number == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        c_i = 1 if my_prev_action else 0
        c_prev_others = history.opponent_cooperators[-1]
        c_prev_total = c_prev_others + c_i
        if self.is_testing:
            self.is_testing = False
            if c_prev_total >= m - 1:
                pass
            else:
                return Action.D
        if c_prev_total >= m:
            return Action.C
        elif c_prev_total == m - 1:
            return Action.C
        else:
            current_round = history.round_number
            if current_round - self.last_test_round > 2:
                self.is_testing = True
                self.last_test_round = current_round
                return Action.C
            return Action.D

class Strategy_COLLECTIVE_110(BaseStrategy):
    """
    Threshold-Responsive Tit-for-Tat (TR-TFT).
    Cooperates if the threshold was met, punishes if it failed,
    and probes with a probability proportional to m/n if the last action was defection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if self.desc.k <= 1.0:
            return Action.D
        if history.round_number == 0:
            return Action.C
        prev_round_idx = history.round_number - 1
        my_prev_action = history.my_actions[prev_round_idx]
        prev_S = history.opponent_cooperators[prev_round_idx] + (1 if my_prev_action else 0)
        n = self.desc.n_players
        m = self.desc.m
        r = self.desc.n_rounds
        current_round = history.round_number + 1
        if current_round == r:
            if prev_S >= m:
                return Action.C
            elif prev_S == m - 1:
                return Action.C
            else:
                return Action.D
        if prev_S >= m:
            return Action.C
        if not my_prev_action:
            prob = m / n if n > 0 else 0
            if random.random() < prob:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_COLLECTIVE_111(BaseStrategy):
    """
    A Triggered Tit-for-Tat strategy with Threshold Scaling for Collective Risk Dilemmas.
    
    Logic:
    1. Always start with C.
    2. Maintain C if the threshold m is met.
    3. If threshold not met, switch to D (unless special recovery/exploitation clauses override).
    4. Adaptive Scaling: If threshold is barely met (== m), check recent 3-round trend to decide
       stability.
    5. Exploitation Clause: If threshold is consistently exceeded (>= m+1) but cooperators
       are systematically exploited, signal dissatisfaction by defecting for one round.
    6. Recovery Protocol: If the group fails to meet the threshold for 2 consecutive rounds,
       permanently switch to D.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0
        self.exploitation_cooldown = 0
        self.exploitation_triggered = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        m = self.game_description.m
        my_last_action = int(history.my_actions[-1])
        c_prev_others = history.opponent_cooperators[-1]
        c_prev_total = c_prev_others + my_last_action
        if c_prev_total < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 2:
            return Action.D
        if self.exploitation_cooldown > 0:
            self.exploitation_cooldown -= 1
            if c_prev_total > m:
                self.exploitation_triggered = False
                return Action.C
            return Action.D
        if history.round_number >= 2:
            prev_others_2 = history.opponent_cooperators[-2]
            prev_total_2 = prev_others_2 + int(history.my_actions[-2])
            if prev_total_2 >= m + 1 and c_prev_total >= m + 1:
                self.exploitation_triggered = True
                self.exploitation_cooldown = 1
                return Action.D
        if c_prev_total > m:
            return Action.C
        elif c_prev_total < m:
            return Action.D
        elif history.round_number >= 3:
            recent_others = history.opponent_cooperators[-3:]
            recent_mine = [int(x) for x in history.my_actions[-3:]]
            recent_totals = np.add(recent_others, recent_mine)
            trend = np.mean(recent_totals)
            if trend < m:
                return Action.D
            else:
                return Action.C
        else:
            return Action.C

class Strategy_COLLECTIVE_112(BaseStrategy):
    """
    Implements a 'Threshold-Trigger' strategy for Collective Risk Dilemma.
    It uses a probabilistic start, Tit-for-Tat adaptation based on threshold m,
    and specific endgame/failure-resilience heuristics.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0
        self.last_action = None

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        if history.round_number == 0:
            p = m / n
            action = Action.C if random.random() < p else Action.D
            self.last_action = action
            return action
        prev_my_c = 1 if self.last_action == Action.C else 0
        prev_total_c = history.opponent_cooperators[-1] + prev_my_c
        prev_round = history.round_number - 1
        if prev_total_c < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if history.round_number >= self.game_description.n_rounds - 1:
            total_rounds = history.round_number
            success_count = 0
            for r in range(total_rounds):
                c_count = history.opponent_cooperators[r] + (1 if history.my_actions[r] else 0)
                if c_count >= m:
                    success_count += 1
            if success_count / total_rounds < 0.5:
                self.last_action = Action.D
                return Action.D
        if self.consecutive_failures >= 3:
            self.last_action = Action.D
            return Action.D
        action: Action
        if prev_total_c >= m:
            action = Action.C
        elif prev_total_c == m - 1:
            action = Action.C
        else:
            action = Action.D
        self.last_action = action
        return action

class Strategy_COLLECTIVE_113(BaseStrategy):
    """
    A strategy that pursues a collective contribution quota.
    It initiates cooperation, then modulates contribution based on the previous round's outcome
    to optimize individual payoffs, while retaining an adaptive 'give up' threshold if the 
    group proves uncooperative.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0
        self.giving_up = False

    def __call__(self, history: PlayerHistory) -> Action:
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if self.giving_up:
            return Action.D
        if current_round > 0:
            my_last_action = int(history.my_actions[-1])
            total_cooperators = history.opponent_cooperators[-1] + my_last_action
            if total_cooperators < m:
                self.consecutive_failures += 1
            else:
                self.consecutive_failures = 0
            if self.consecutive_failures >= 3:
                self.giving_up = True
                return Action.D
        if current_round == 0:
            return Action.C
        if current_round == r - 1:
            return Action.D
        prev_opp_coop = history.opponent_cooperators[-1]
        my_last_action = int(history.my_actions[-1])
        c_obs = prev_opp_coop + my_last_action
        if c_obs >= m:
            return Action.D
        else:
            return Action.C

class Strategy_COLLECTIVE_114(BaseStrategy):
    """
    Threshold-Adaptive Reciprocity (TAR) strategy.
    Maintains the threshold m while minimizing individual exploitation using
    conditional cooperation based on system health (previous round's cooperation).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_zero_cooperation = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        my_last_action = history.my_actions[-1]
        last_others_coop = history.opponent_cooperators[-1]
        c_prev = int(last_others_coop) + (1 if my_last_action else 0)
        if c_prev == 0:
            self.consecutive_zero_cooperation += 1
        else:
            self.consecutive_zero_cooperation = 0
        if self.consecutive_zero_cooperation >= 2:
            return Action.D
        if current_round == r - 1:
            if c_prev >= m - 1:
                return Action.C
            else:
                return Action.D
        if m == n:
            if c_prev >= m - 1:
                return Action.C
            else:
                return Action.D
        if c_prev >= m:
            if c_prev > m:
                return Action.C
            else:
                p = 1.0 - m / n
                return Action.D if random.random() < p else Action.C
        elif c_prev == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_115(BaseStrategy):
    """
    Implements a Threshold-Triggered Reciprocity strategy for the Collective Risk Dilemma.
    It manages quorum maintenance, punishment of free-riders, and periodic reset attempts
    when the group fails to meet the threshold.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.reset_counter = -1

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        if history.round_number == 0:
            return Action.C if random.random() < m / n else Action.D
        r_current = history.round_number - 1
        c_prev_total = history.opponent_cooperators[r_current]
        my_prev_action = history.my_actions[r_current]
        total_cooperators = c_prev_total + (1 if my_prev_action else 0)
        if self.reset_counter > 0:
            self.reset_counter -= 1
        if self.reset_counter == 0:
            self.reset_counter = -1
            return Action.C
        if self.reset_counter == -1 and total_cooperators < m:
            if not my_prev_action:
                self.reset_counter = random.randint(2, 4)
        if history.round_number == self.game_description.n_rounds:
            return Action.C if total_cooperators >= m else Action.D
        if total_cooperators == m - 1:
            return Action.C
        if total_cooperators >= m:
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_116(BaseStrategy):
    """
    Implements a Threshold-Constrained Tit-for-Tat strategy with forgiveness.
    Prioritizes maintaining collective thresholds (m) and provides buffers 
    against minor failures (m-1), while using periodic probing to recover 
    from necessary defecting phases.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.defect_counter = 0
        self.in_defect_mode = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            self.defect_counter = 0
            self.in_defect_mode = False
            return Action.C
        m = self.game_description.m
        last_my_action = history.my_actions[-1]
        last_n_c = history.opponent_cooperators[-1] + (1 if last_my_action else 0)
        if history.round_number == self.game_description.n_rounds - 1:
            if last_n_c >= m - 1:
                return Action.C
            return Action.D
        if self.in_defect_mode:
            self.defect_counter += 1
            if self.defect_counter % 3 == 0:
                return Action.C
            else:
                return Action.D
        if last_n_c >= m - 1:
            return Action.C
        else:
            self.in_defect_mode = True
            self.defect_counter = 0
            return Action.D

    def update_state(self, last_round_n_c: int):
        """
        Helper to check recovery condition. 
        This is implicitly handled in __call__ logic flow, 
        but if a probe round succeeds, exit defect mode.
        """
        if self.in_defect_mode and last_round_n_c >= self.game_description.m:
            self.in_defect_mode = False
            self.defect_counter = 0

class Strategy_COLLECTIVE_117(BaseStrategy):
    """
    Implements a Threshold-Tit-for-Tat strategy for the Collective Risk Dilemma.
    
    Strategy Logic:
    - Round 1: Always Cooperate.
    - Rounds 2 to r-1: 
        - If threshold m met in previous round: Cooperate.
        - If threshold not met: 
            - If we cooperated previously: Defect (punish).
            - If we defected previously: Cooperate (attempt restart) if trend is not negative.
    - Round r: 
        - If threshold m met in r-1: Cooperate.
        - If not: Defect.
    - Termination condition: If cooperation is trending downward (declining over 3 rounds), defect permanently.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.last_action = Action.C

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            self.last_action = Action.C
            return Action.C
        last_coop_count = history.opponent_cooperators[-1]
        is_trending_down = False
        if current_round >= 3:
            c1 = history.opponent_cooperators[-1]
            c2 = history.opponent_cooperators[-2]
            c3 = history.opponent_cooperators[-3]
            if c3 > c2 > c1:
                is_trending_down = True
        if is_trending_down:
            self.last_action = Action.D
            return Action.D
        if current_round == r - 1:
            if last_coop_count >= m:
                self.last_action = Action.C
                return Action.C
            else:
                self.last_action = Action.D
                return Action.D
        if last_coop_count >= m:
            self.last_action = Action.C
            return Action.C
        elif self.last_action == Action.C:
            self.last_action = Action.D
            return Action.D
        else:
            self.last_action = Action.C
            return Action.C

class Strategy_COLLECTIVE_118(BaseStrategy):
    """
    Implements a Trigger-Threshold coordination strategy:
    - Round 0 (1st round): Cooperate.
    - Rounds 1 to r-2: 
        - If last round reached threshold (m cooperators): Cooperate.
        - If last round missed threshold by one (m-1 cooperators): Cooperate (Bridge attempt).
        - Otherwise: Defect.
    - Final round: 
        - If historical success rate >= 75%: Cooperate.
        - Otherwise: Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_index = history.round_number
        n_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round_index == 0:
            return Action.C
        if current_round_index == n_rounds - 1:
            total_successes = 0
            for t in range(current_round_index):
                total_c = history.opponent_cooperators[t] + (1 if history.my_actions[t] else 0)
                if total_c >= m:
                    total_successes += 1
            success_rate = total_successes / current_round_index
            return Action.C if success_rate >= 0.75 else Action.D
        prev_round_idx = -1
        last_total_c = history.opponent_cooperators[prev_round_idx] + (1 if history.my_actions[prev_round_idx] else 0)
        if last_total_c >= m:
            return Action.C
        elif last_total_c == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_119(BaseStrategy):
    """
    Implements the 'Adaptive Threshold Reciprocity' strategy.
    
    This strategy focuses on maintaining the minimum threshold (m) required for the reward (k).
    It employs conditional cooperation: starting with C, rescuing the threshold when close (m-1),
    and exploiting surplus (S > m) with D, while adjusting based on previous outcomes.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        last_my_action = history.my_actions[-1]
        last_opponent_coops = history.opponent_cooperators[-1]
        last_s = (1 if last_my_action else 0) + last_opponent_coops
        current_round = history.round_number
        is_final_round = current_round == self.r - 1
        if is_final_round:
            if last_s < self.m:
                return Action.D
            if last_s >= self.m:
                if last_my_action:
                    return Action.C
                if last_s == self.m:
                    return Action.C
                return Action.D
            return Action.D
        if last_s == self.m - 1:
            return Action.C
        if last_s >= self.m:
            if last_s > self.m:
                return Action.D
            if last_my_action:
                return Action.C
            return Action.C
        return Action.D

class Strategy_COLLECTIVE_120(BaseStrategy):
    """
    A conditional cooperation strategy for the Collective Risk Dilemma.
    
    Logic:
    - Round 0: Always Cooperate to test the group.
    - Final Round (Round r-1): If previous round cooperators >= m-1, Cooperate; otherwise Defect.
    - Intermediate Rounds:
        - If previous cooperators >= m: Copy own previous action (Tit-for-Tat).
        - If previous cooperators == m-1: Cooperate (Rescue move).
        - If previous cooperators < m-1: Defect (Conservation).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        n_rounds = self.game_description.n_rounds
        m = self.game_description.m
        prev_idx = -1
        prev_cooperators = history.opponent_cooperators[prev_idx]
        my_prev_action_bool = history.my_actions[prev_idx]
        total_cooperators = prev_cooperators + (1 if my_prev_action_bool else 0)
        if history.round_number == n_rounds - 1:
            if total_cooperators >= m - 1:
                return Action.C
            else:
                return Action.D
        if total_cooperators >= m:
            return Action.C if my_prev_action_bool else Action.D
        elif total_cooperators == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_121(BaseStrategy):
    """
    Implements a threshold-responsive strategy:
    - Starts with cooperation.
    - Uses logic based on the collective threshold 'm'.
    - Implements reciprocity, probing after failure, and permanent defection detection.
    - Defects on the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.consecutive_failed_attempts = 0
        self.permanent_defection = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.desc.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if self.permanent_defection:
            return Action.D
        n_prev_coop = history.opponent_cooperators[-1]
        my_prev_action = int(history.my_actions[-1])
        total_coop_prev = n_prev_coop + my_prev_action
        if total_coop_prev < self.desc.m:
            self.consecutive_failed_attempts += 1
        else:
            self.consecutive_failed_attempts = 0
        if self.consecutive_failed_attempts >= 3:
            self.permanent_defection = True
            return Action.D
        if total_coop_prev >= self.desc.m:
            return Action.C
        if total_coop_prev == self.desc.m - 1:
            return Action.C
        if history.round_number > 1:
            n_prev_prev_coop = history.opponent_cooperators[-2]
            my_prev_prev_action = int(history.my_actions[-2])
            total_coop_prev_prev = n_prev_prev_coop + my_prev_prev_action
            if total_coop_prev_prev < self.desc.m:
                return Action.C
        return Action.D

class Strategy_COLLECTIVE_122(BaseStrategy):
    """
    Threshold-Conditional Tit-for-Tat with Exploitation Defense.
    
    This strategy attempts to coordinate at the threshold m by rewarding cooperation 
    while protecting endowment against repeated failure. It uses a probabilistic 
    probe when the group is just below the threshold and defaults to defection 
    when the threshold is unreachable.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.n = self.desc.n_players
        self.m = self.desc.m
        self.r = self.desc.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_last_action = history.my_actions[-1]
        cooperators_from_others = history.opponent_cooperators[-1]
        total_cooperators_last_round = cooperators_from_others + (1 if my_last_action else 0)
        if history.round_number == self.r - 1:
            if total_cooperators_last_round >= self.m:
                return Action.C
            else:
                return Action.D
        if total_cooperators_last_round >= self.m:
            return Action.C
        if total_cooperators_last_round == self.m - 1:
            prob_cooperate = self.m / self.n if self.n > 0 else 0.0
            if random.random() < prob_cooperate:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_COLLECTIVE_123(BaseStrategy):
    """
    Adaptive strategy for Collective Risk Dilemma.
    Manages cooperation based on dynamic trust levels, previous round success,
    trend monitoring, and equilibrium locking.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k
        self.trust_level = 0.5
        self.consecutive_successes = 0

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C if random.random() < self.m / self.n else Action.D
        my_last_action_int = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + my_last_action_int
        if total_cooperators_prev >= self.m:
            self.consecutive_successes += 1
        else:
            self.consecutive_successes = 0
            reduction = 1.0 / (self.r - current_round + 1)
            self.trust_level = max(0.0, self.trust_level - reduction)
        if total_cooperators_prev >= self.m:
            self.consecutive_successes += 1
            if self.consecutive_successes >= 2:
                self.trust_level = min(1.0, self.trust_level + 0.1)
        else:
            self.consecutive_successes = 0
        if current_round == self.r - 1:
            if total_cooperators_prev < self.m:
                return Action.D
        if self.m <= total_cooperators_prev <= self.m + 1:
            return Action.C
        if total_cooperators_prev > 0.8 * self.n:
            return Action.D
        return Action.C if random.random() < self.trust_level else Action.D

class Strategy_COLLECTIVE_124(BaseStrategy):
    """
    Implements a Tit-for-Tat variant with threshold adjustment for the Collective Risk Dilemma.
    Strategy prioritizes cooperation while using probabilistic adjustments and statistical 
    threshold checking to avoid exploitation and wasted investment.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.giving_up = False

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        n = self.game_description.n_players
        m = self.game_description.m
        total_rounds = self.game_description.n_rounds
        if t == 0:
            return Action.C
        if self.giving_up:
            return Action.D
        prev_my_action = 1 if history.my_actions[-1] else 0
        prev_C_total = prev_my_action + history.opponent_cooperators[-1]
        all_coop_counts = [(1 if act else 0) + opp_c for act, opp_c in zip(history.my_actions, history.opponent_cooperators)]
        if np.mean(all_coop_counts) < m:
            self.giving_up = True
            return Action.D
        if t == total_rounds - 1:
            if prev_C_total >= m:
                return Action.C
            else:
                return Action.D
        if prev_C_total >= m:
            return Action.C
        else:
            g = m - prev_C_total
            p = 1.0 / (g + 1)
            if prev_my_action == 0:
                return Action.C if random.random() < p else Action.D
            else:
                return Action.D if random.random() < 1 - p else Action.C
        return Action.C if history.my_actions[-1] else Action.D

class Strategy_COLLECTIVE_125(BaseStrategy):
    """
    Implements a Conditional Threshold-Trigger Tit-for-Tat strategy.
    
    Strategy logic:
    - Round 1: Always Cooperate.
    - If Nearing End (r < 5): Use pure Tit-for-Tat based on threshold.
    - Otherwise (Standard Rounds):
        - If threshold met in previous round, maintain cooperation.
        - If threshold failed, probabilistically defect to punish/signal.
        - Incorporates a 'leniency buffer' based on recent history to prevent death spirals.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        c_prev = history.opponent_cooperators[-1]
        if self.r < 5:
            return Action.C if c_prev >= self.m else Action.D
        if current_round == self.r - 1:
            return Action.C if c_prev >= self.m else Action.D
        if current_round >= 3:
            recent_avg = np.mean(history.opponent_cooperators[-3:])
            if recent_avg >= self.m - 1:
                return Action.C
        if c_prev >= self.m:
            return Action.C
        elif self.n > 0 and random.random() < self.m / self.n:
            return Action.D
        else:
            return Action.C

class Strategy_COLLECTIVE_126(BaseStrategy):
    """
    A strategy that follows a 'Triggered Conditional Cooperation' approach:
    - First round: Always Cooperate.
    - Subsequent rounds:
        - If the previous round met the threshold (N_C >= m), maintain Cooperation.
        - If the previous round failed (N_C < m), Defect, with a 25% probability 
          of attempting a 'test' Cooperate move to try and recover the equilibrium.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        last_round_idx = history.round_number - 1
        last_n_cooperators = history.opponent_cooperators[last_round_idx]
        my_last_action = Action.C if history.my_actions[last_round_idx] else Action.D
        total_cooperators = last_n_cooperators + (1 if my_last_action == Action.C else 0)
        if total_cooperators >= self.m:
            return Action.C
        if my_last_action == Action.C:
            return Action.D
        elif random.random() < 0.25:
            return Action.C
        else:
            return Action.D

class Strategy_COLLECTIVE_127(BaseStrategy):
    """
    Implements a 'trigger-and-adjust' mechanism.
    
    Logic Summary:
    - Round 0 (t=1): Always Cooperate.
    - If successful previous round (>= m):
      - If I cooperated: Cooperate again.
      - If I defected: Free-ride (Defect) if slack > 0, else Contribute (Cooperate) if threshold was just met.
    - If failed previous round (< m):
      - If I cooperated: Defect to enforce a cooling-off period.
      - If I defected: Attempt to restart by Cooperating.
    - Final round (t=r): Always Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        last_cooperators_total = history.opponent_cooperators[-1]
        my_last_action = Action.C if history.my_actions[-1] else Action.D
        my_contribution = 1 if my_last_action == Action.C else 0
        total_c_last_round = last_cooperators_total + my_contribution
        if total_c_last_round >= m:
            if my_last_action == Action.C:
                return Action.C
            else:
                slack = total_c_last_round - m
                return Action.D if slack > 0 else Action.C
        elif my_last_action == Action.C:
            return Action.D
        else:
            return Action.C

class Strategy_COLLECTIVE_128(BaseStrategy):
    """
    Implements a Collective Risk Dilemma strategy based on threshold monitoring,
    probabilistic resets upon failure, and prioritized cooperation in terminal rounds.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.k = game_description.k
        self.r = game_description.n_rounds
        self.n = game_description.n_players

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            if self.k > 1:
                return Action.C
            return Action.D
        prev_cooperators = history.opponent_cooperators[-1]
        is_terminal = current_round >= self.r - 2
        if is_terminal:
            total_cooperators_per_round = np.add(history.opponent_cooperators, history.my_actions.astype(int))
            successes = np.sum(total_cooperators_per_round >= self.m)
            success_rate = successes / current_round
            if success_rate > 0.5 and self.k > 1:
                return Action.C
        if current_round >= 2:
            last_round_total = history.opponent_cooperators[-1] + int(history.my_actions[-1])
            prev_round_total = history.opponent_cooperators[-2] + int(history.my_actions[-2])
            last_two_rounds_failed = last_round_total < self.m and prev_round_total < self.m
        else:
            last_two_rounds_failed = False
        if last_two_rounds_failed:
            if random.random() < 0.5:
                return Action.C
            return Action.D
        if prev_cooperators >= self.m:
            return Action.C
        elif prev_cooperators == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_33(BaseStrategy):
    """
    A conditional threshold-tracking strategy.
    
    Logic:
    1. Round 0 (Start): Always cooperate (C).
    2. Rounds 1 to r-2: 
       - If last action was C: Cooperate if threshold was met, else Defect.
       - If last action was D: If group was close to threshold (m-1), rejoin (C), else stay Defect.
    3. Failure Resilience: If D for 3+ rounds and group never met m-1, maintain D until last round.
    4. Reward Exploitation: If group exceeded threshold (m+1), play D to test sustainability.
    5. Final Round: Cooperate if threshold was met, else Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_defections = 0
        self.is_testing_threshold = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        r = self.game_description.n_rounds
        t = history.round_number
        m = self.game_description.m
        my_last_action = history.my_actions[-1]
        my_prev_c = 1 if my_last_action else 0
        s_prev = history.opponent_cooperators[-1] + my_prev_c
        if t == r - 1:
            return Action.C if s_prev >= m else Action.D
        if my_last_action == Action.C:
            self.is_testing_threshold = False
            self.consecutive_defections = 0
        else:
            self.consecutive_defections += 1
        if s_prev >= m + 1 and (not self.is_testing_threshold):
            self.is_testing_threshold = True
            return Action.D
        if self.is_testing_threshold:
            if s_prev < m:
                self.is_testing_threshold = False
                return Action.C
            else:
                return Action.D
        if self.consecutive_defections >= 3 and s_prev < m - 1:
            return Action.D
        if my_last_action == Action.C:
            if s_prev >= m:
                return Action.C
            else:
                return Action.D
        elif s_prev >= m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_34(BaseStrategy):
    """
    A conditional strategy for the Collective Risk Dilemma that incentivizes
    collective cooperation while punishing non-cooperators.
    
    Logic:
    - Round 1: Always Cooperate.
    - Subsequent rounds:
        - Endgame (remaining rounds < 3): Defect to avoid exploitation.
        - If threshold m was met in the previous round: Continue to Cooperate.
        - If threshold m was missed but we are the vital pivot (C_prev == m - 1): Cooperate.
        - If threshold m was missed and we cooperated previously: Punish with Defect.
        - If threshold m was missed and we defected previously: Attempt reconciliation 
          (50% probability to Cooperate).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round_idx = history.round_number
        remaining_rounds = r - current_round_idx
        others_cooperated = history.opponent_cooperators[-1]
        i_cooperated = history.my_actions[-1]
        c_prev = others_cooperated + (1 if i_cooperated else 0)
        if remaining_rounds < 3:
            return Action.D
        if c_prev >= m:
            return Action.C
        if c_prev == m - 1:
            return Action.C
        if i_cooperated:
            return Action.D
        if random.random() > 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_35(BaseStrategy):
    """
    Implements Adaptive Threshold-Reciprocity strategy for the Collective Risk Dilemma.
    
    This strategy relies on conditional cooperation based on the observed collective threshold.
    - Start with Cooperate.
    - If m or more players cooperated in the previous round, continue to Cooperate.
    - If the threshold (m) was not met, switch to or stay in Defect mode.
    - Exception: If the observed cooperators were exactly m-1, act as a "bridge" 
      to Cooperate to attempt to nudge the group toward the threshold.
    - Endgame: In the final round, cooperate only if the group was close (>= m-1) 
      in the previous round, otherwise defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        n_rounds = self.game_description.n_rounds
        m = self.game_description.m
        current_round = history.round_number
        last_opponent_coops = history.opponent_cooperators[-1]
        my_last_action_val = 1 if history.my_actions[-1] else 0
        c_obs_prev = last_opponent_coops + my_last_action_val
        if current_round == n_rounds - 1:
            if c_obs_prev >= m - 1:
                return Action.C
            else:
                return Action.D
        if c_obs_prev >= m:
            return Action.C
        elif c_obs_prev == m - 1 and (not history.my_actions[-1]):
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_36(BaseStrategy):
    """
    Threshold-Adaptive Reciprocity Strategy for the Collective Risk Dilemma.
    Implements adaptive responses based on previous round's cooperation threshold performance.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game.n_players
        m = self.game.m
        r = self.game.n_rounds
        current_round = history.round_number + 1
        prev_idx = -1
        my_prev_action = 1 if history.my_actions[prev_idx] else 0
        n_prev_coop = history.opponent_cooperators[prev_idx] + my_prev_action
        failed_rounds = 0
        for i in range(history.round_number):
            opp_coop = history.opponent_cooperators[i]
            my_coop = 1 if history.my_actions[i] else 0
            if opp_coop + my_coop < m:
                failed_rounds += 1
        majority_failed = failed_rounds > history.round_number / 2
        if current_round == r:
            if n_prev_coop >= m and (not majority_failed):
                return Action.C
            else:
                return Action.D
        if n_prev_coop >= m:
            if history.my_actions[prev_idx]:
                return Action.C
            else:
                p = m / n_prev_coop
                if random.random() < p:
                    return Action.C
                else:
                    return Action.D
        else:
            r_ratio = n_prev_coop / m
            if r_ratio < 0.5:
                return Action.D
            elif current_round < r:
                return Action.C
            else:
                return Action.D

class Strategy_PROSOCIAL_37(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that adapts cooperation based on 
    group success, punishment mechanisms, and proximity to the game's end.
    
    State:
    - contribution_threshold: Int (m)
    - cooperation_status: Boolean (True = Prosocial mode, False = Defect mode)
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.contribution_threshold = game_description.m
        self.cooperation_status = True

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.contribution_threshold
        r = self.game_description.n_rounds
        if history.round_number == 0:
            self.cooperation_status = True
            return Action.C
        cooperators_last_round_others = history.opponent_cooperators[-1]
        my_last_action = history.my_actions[-1]
        my_c_last = 1 if my_last_action else 0
        total_cooperators_last = cooperators_last_round_others + my_c_last
        if r <= 5:
            if cooperators_last_round_others + 1 < m:
                return Action.D
            return Action.C
        if self.game_description.k > 10.0:
            return Action.C
        if history.round_number == r - 1:
            if self.cooperation_status:
                return Action.C
            prev_opp_c = history.opponent_cooperators[-2] if history.round_number > 1 else 0
            prev_my_c = 1 if history.my_actions[-2] else 0
            if prev_opp_c + prev_my_c == m - 1:
                return Action.C
            return Action.D
        if self.cooperation_status:
            if total_cooperators_last >= m:
                return Action.C
            if total_cooperators_last < m and my_c_last == 1:
                self.cooperation_status = False
                return Action.D
            if total_cooperators_last >= m - 1 and my_c_last == 0:
                self.cooperation_status = True
                return Action.C
            return Action.C
        else:
            if cooperators_last_round_others >= m:
                self.cooperation_status = True
                return Action.C
            return Action.D

class Strategy_PROSOCIAL_38(BaseStrategy):
    """
    A conditional threshold-based cooperation strategy for the Collective Risk Dilemma.
    Adjusts cooperation threshold dynamically based on observed group behavior, 
    starting with the minimum viable cooperation required and attempting to scale 
    upwards if successful, or falling back if failed.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.tau = game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            if m <= n - 1:
                return Action.C
            return Action.D
        if current_round == r - 1:
            total_coop_counts = []
            for t in range(current_round):
                my_c = 1 if history.my_actions[t] else 0
                total_c = history.opponent_cooperators[t] + my_c
                total_coop_counts.append(total_c)
            avg_coop = sum(total_coop_counts) / current_round
            if avg_coop >= m:
                return Action.C
            else:
                return Action.D
        prev_my_c = 1 if history.my_actions[-1] else 0
        prev_total_c = history.opponent_cooperators[-1] + prev_my_c
        if prev_total_c >= self.tau:
            self.tau = min(n - 1, self.tau + 1)
            return Action.C
        else:
            self.tau = max(m, self.tau - 1)
            return Action.D

class Strategy_PROSOCIAL_39(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that employs adaptive cooperation,
    punishment for collapse, and threshold-based final round decision making.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.cooperators_history = []
        self.just_tested_collapse = False

    def __call__(self, history: PlayerHistory) -> Action:
        if self.game_description.k <= 1:
            return Action.D
        if history.round_number > 0:
            last_round_idx = history.round_number - 1
            last_opponents = history.opponent_cooperators[last_round_idx]
            last_my_action = 1 if history.my_actions[last_round_idx] else 0
            total_c = last_opponents + last_my_action
            self.cooperators_history.append(total_c)
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            if not self.cooperators_history:
                return Action.C
            successful_rounds = sum((1 for c in self.cooperators_history if c >= self.game_description.m))
            success_rate = successful_rounds / len(self.cooperators_history)
            return Action.C if success_rate >= 0.5 else Action.D
        c_prev = self.cooperators_history[-1]
        n = self.game_description.n_players
        m = self.game_description.m
        if c_prev == n or n - c_prev == 1:
            self.just_tested_collapse = False
            return Action.C
        if self.just_tested_collapse:
            self.just_tested_collapse = False
            return Action.C
        if c_prev >= m:
            return Action.C
        elif c_prev >= m - 1:
            return Action.C
        else:
            self.just_tested_collapse = True
            return Action.D

class Strategy_PROSOCIAL_40(BaseStrategy):
    """
    Conditional Threshold Tit-for-Tat (CT-TFT) strategy for the Collective Risk Dilemma.
    Implements a combination of reciprocal cooperation, probabilistic forgiveness, 
    and history-dependent adaptation (equilibrium locking and quit thresholds).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_cooperation_threshold_hits = 0
        self.consecutive_failure_to_meet_threshold = 0
        self.gave_up = False

    def __call__(self, history: PlayerHistory) -> Action:
        if self.gave_up:
            return Action.D
        current_round = history.round_number
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        m = self.game_description.m
        k = self.game_description.k
        if current_round == 0:
            return Action.C
        prev_opponents_c = history.opponent_cooperators[-1]
        my_prev_c = int(history.my_actions[-1])
        T = m - my_prev_c
        total_c = prev_opponents_c + my_prev_c
        if total_c >= m:
            self.consecutive_cooperation_threshold_hits += 1
            self.consecutive_failure_to_meet_threshold = 0
        else:
            self.consecutive_cooperation_threshold_hits = 0
            self.consecutive_failure_to_meet_threshold += 1
        if prev_opponents_c < m - 1 and self.consecutive_failure_to_meet_threshold >= 3:
            self.gave_up = True
            return Action.D
        if current_round == r - 1:
            if k <= 1:
                return Action.D
            if prev_opponents_c == m - 1:
                return Action.C
            return Action.D
        if prev_opponents_c >= m and self.consecutive_cooperation_threshold_hits >= 3:
            return Action.C
        if prev_opponents_c >= T:
            return Action.C
        elif prev_opponents_c == T - 1:
            t_val = current_round + 1
            p = 1.0 - t_val / r
            if random.random() < p:
                return Action.C
            return Action.D
        return Action.D

class Strategy_PROSOCIAL_41(BaseStrategy):
    """
    Implements a strategy based on Conditional Threshold Reciprocity.
    
    Principles:
    1. Prosocial Initialization: Always starts by cooperating.
    2. Adaptive Reciprocity: If the collective threshold m is met, maintains cooperation
       to stabilize the reward.
    3. Targeted Pivot: If the group fails to meet the threshold, defects unless 
       it could have flipped the outcome (group_c == m - 1).
    4. Endgame Conservation: Defects in the final round if the goal was not met, 
       avoiding wasted investment.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.game_description.m
        total_rounds = self.game_description.n_rounds
        rounds_left = total_rounds - history.round_number
        my_previous_action = int(history.my_actions[-1])
        group_c = history.opponent_cooperators[-1] + my_previous_action
        if group_c >= m:
            return Action.C
        else:
            if rounds_left == 0:
                return Action.D
            if group_c == m - 1:
                return Action.C
            return Action.D

class Strategy_PROSOCIAL_42(BaseStrategy):
    """
    Implements a Conditional Threshold Reciprocity strategy for the Collective Risk Dilemma.
    It attempts to reach the threshold m by conditionally cooperating, stabilizing,
    and adapting to failures or excesses in cooperation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.persistent_defection_counter = 0
        self.defection_cooldown = 0
        self.over_contribution_counter = 0
        self.testing_after_defection = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        m = self.game_description.m
        prev_my_action = int(history.my_actions[-1])
        prev_opponents = int(history.opponent_cooperators[-1])
        n_c_prev = prev_opponents + prev_my_action
        if n_c_prev < m and prev_my_action == 1:
            self.persistent_defection_counter += 1
        else:
            self.persistent_defection_counter = 0
        if self.defection_cooldown > 0:
            self.defection_cooldown -= 1
            if self.defection_cooldown == 0:
                self.testing_after_defection = True
                return Action.C
        if n_c_prev > m + 1:
            self.over_contribution_counter += 1
        else:
            self.over_contribution_counter = 0
        if self.persistent_defection_counter >= 3:
            self.defection_cooldown = 2
            self.persistent_defection_counter = 0
            return Action.D
        if self.over_contribution_counter >= 2:
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            if n_c_prev >= m - 1:
                return Action.C
            return Action.D
        if n_c_prev >= m:
            if prev_my_action == 1:
                if self.testing_after_defection:
                    self.testing_after_defection = False
                    return Action.C
                return Action.C
            else:
                return Action.D
        elif n_c_prev == m - 1:
            return Action.C
        else:
            prob = (m - n_c_prev) / max(1, n - n_c_prev)
            if random.random() < prob:
                return Action.C
            else:
                return Action.D

class Strategy_PROSOCIAL_43(BaseStrategy):
    """
    Implements a conditional cooperation strategy for the Collective Risk Dilemma.
    Cooperate initially. In subsequent rounds, cooperate if the collective 
    threshold (m) was met in the previous round. If the threshold was not met, 
    defect for exactly one round to signal dissatisfaction, unless it is the 
    final round (where cooperation is prioritized to maximize potential).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self._punishing = False

    def __call__(self, history: PlayerHistory) -> Action:
        round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if round_idx == 0:
            return Action.C
        if round_idx == total_rounds - 1:
            return Action.C
        my_prev_action = history.my_actions[-1]
        coop_count_opponents = history.opponent_cooperators[-1]
        total_cooperators_prev = coop_count_opponents + (1 if my_prev_action else 0)
        threshold_met = total_cooperators_prev >= m
        if self._punishing:
            self._punishing = False
            return Action.C
        if threshold_met:
            return Action.C
        else:
            self._punishing = True
            return Action.D

class Strategy_PROSOCIAL_44(BaseStrategy):
    """
    A conditional 'Win-Stay, Lose-Shift' strategy for the Collective Risk Dilemma.
    It initiates cooperation to test the group, then adapts based on the 
    threshold success (m) in previous rounds, balancing group goals with 
    individual utility preservation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = self.game_description.n_players
        self.r = self.game_description.n_rounds
        self.m = self.game_description.m
        self.k = self.game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        last_action = Action.C if history.my_actions[-1] else Action.D
        current_total_cooperators = history.opponent_cooperators[-1] + (1 if last_action == Action.C else 0)
        current_round_1based = history.round_number + 1
        if current_round_1based == self.r:
            if current_total_cooperators >= self.m - 1:
                return Action.C
            else:
                return Action.D
        prev_success = current_total_cooperators >= self.m
        if prev_success:
            if last_action == Action.C:
                return Action.C
            elif current_total_cooperators == self.m:
                return Action.C
            else:
                return Action.D
        elif current_total_cooperators >= self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_45(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that employs a tit-for-tat variant adapted 
    for threshold-based coordination: it cooperates in the first round, rewards 
    successful collective action, attempts to rescue near-misses, and defects in the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == n_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        prev_my_action = history.my_actions[-1]
        prev_opp_coop = history.opponent_cooperators[-1]
        c_prev = prev_opp_coop + (1 if prev_my_action else 0)
        if c_prev >= m:
            return Action.C
        if c_prev == m - 1:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_46(BaseStrategy):
    """
    A strategy that pursues collective thresholds by balancing reciprocity and individual utility.
    
    Logic:
    - Round 0: Always Cooperate.
    - Subsequent Rounds (t < r):
        - If previous round met threshold (S >= m): Cooperate.
        - If previous round missed by 1 (S == m-1) and I defected: Cooperate (Swing-vote pivot).
        - Otherwise: Defect to minimize loss, unless triggered by Sucker Protection or Consecutive Failure.
    - Sucker Protection: If personal cooperation rate > group cooperation rate over last 3 rounds, Defect.
    - Consecutive Failure: If failed to meet threshold for 2 rounds while cooperating, Defect for 1 round.
    - Final Round: If historical trend is successful, Cooperate; else, Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failed_rounds = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.game_description.m
        r = self.game_description.n_rounds
        n = self.game_description.n_players
        last_round_idx = history.round_number - 1
        my_last_action = history.my_actions[last_round_idx]
        opponents_cooperating = history.opponent_cooperators[last_round_idx]
        s_prev = opponents_cooperating + (1 if my_last_action else 0)
        if s_prev < m:
            self.consecutive_failed_rounds += 1
        else:
            self.consecutive_failed_rounds = 0
        if history.round_number == r - 1:
            if s_prev >= m:
                return Action.C
            return Action.D
        if history.round_number >= 3:
            recent_my_actions = history.my_actions[-3:].astype(int)
            recent_opp_coops = history.opponent_cooperators[-3:]
            recent_total_coops = recent_opp_coops + recent_my_actions
            avg_group_contribution = np.mean(recent_total_coops) / n
            my_contribution_rate = np.mean(recent_my_actions)
            if my_contribution_rate > avg_group_contribution:
                return Action.D
        if self.consecutive_failed_rounds >= 2 and my_last_action:
            return Action.D
        if s_prev >= m:
            return Action.C
        elif s_prev == m - 1 and (not my_last_action):
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_47(BaseStrategy):
    """
    Implements a contingent cooperation strategy for the Collective Risk Dilemma.
    Cooperates in the first round. In subsequent rounds, maintains cooperation if
    the collective threshold (m) was met. If the threshold was not met, it attempts
    a probabilistic nudge. In the final round, it defects if the history of
    success has been consistently poor (threshold never met), otherwise cooperates.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.epsilon = 0.1

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.game_description.m
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        last_my_action = history.my_actions[-1]
        last_opp_cooperators = history.opponent_cooperators[-1]
        total_cooperators_last_round = int(last_my_action) + last_opp_cooperators
        if total_cooperators_last_round >= m:
            return Action.C
        if history.round_number == r - 1:
            all_my_actions = history.my_actions.astype(int)
            all_opp_cooperators = history.opponent_cooperators
            total_history = all_my_actions + all_opp_cooperators
            successes = np.sum(total_history >= m)
            success_rate = successes / history.round_number
            if success_rate < 0.5:
                return Action.D
            else:
                return Action.C
        threshold_prob = min(1.0, m / n + self.epsilon)
        if random.random() < threshold_prob:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_48(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that employs reciprocal thresholding.
    It initiates with cooperation, maintains cooperation if the threshold is met,
    and attempts to incentivize participation if it is not, with specific logic
    for the final round and a Pavlovian fallback for coordination failures.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0
        self.last_action_was_pavlov_shift = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round_idx = history.round_number
        my_last_action = Action.C if history.my_actions[-1] else Action.D
        opp_cooperators_last = history.opponent_cooperators[-1]
        total_cooperators_last = opp_cooperators_last + (1 if my_last_action == Action.C else 0)
        if total_cooperators_last < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if current_round_idx == r - 1:
            if total_cooperators_last >= m:
                return Action.D
            if total_cooperators_last == m - 1 and my_last_action == Action.D:
                return Action.C
            return Action.D
        if self.consecutive_failures > 2 and (not self.last_action_was_pavlov_shift):
            if my_last_action == Action.C:
                self.last_action_was_pavlov_shift = True
                return Action.D
            else:
                self.last_action_was_pavlov_shift = True
                return Action.C
        self.last_action_was_pavlov_shift = False
        if total_cooperators_last >= m:
            return my_last_action
        if my_last_action == Action.C:
            return Action.C
        return Action.C

class Strategy_PROSOCIAL_49(BaseStrategy):
    """
    Implements a Conditional Threshold Cooperation strategy.
    
    This strategy aims to ensure the collective threshold m is met to secure
    the reward k, while avoiding unnecessary cooperation when the threshold 
    is already satisfied. It acts as a backup when the threshold is exactly met 
    and prioritizes cooperation when the threshold is missed.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = self.game_description.n_players
        self.m = self.game_description.m
        self.r = self.game_description.n_rounds
        self.prob_backup = 1.0 / (self.n - self.m + 1) if self.n - self.m + 1 > 0 else 0.0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            if self.m / self.n >= 0.5:
                return Action.C
            else:
                return Action.C if random.random() < self.m / self.n else Action.D
        t = history.round_number + 1
        c_prev = history.opponent_cooperators[-1]
        my_prev_action = int(history.my_actions[-1])
        c_total_prev = c_prev + my_prev_action
        if t == self.r:
            if c_total_prev >= self.m - 1:
                return Action.C
            else:
                if np.mean(history.opponent_cooperators) >= self.m - 1:
                    return Action.C
                return Action.D
        if c_total_prev >= self.m:
            if c_total_prev == self.m:
                return Action.C if random.random() < self.prob_backup else Action.D
            else:
                return Action.D
        if c_total_prev < self.m:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_50(BaseStrategy):
    """
    A conditional cooperation strategy that tracks group success thresholds.
    - Round 1: Always Cooperate.
    - Subsequent Rounds (not final): Cooperate if previous round >= m. If failed, defect for exactly one round, then attempt to return to cooperation.
    - If group fails to reach threshold for 3 consecutive rounds: Defect for all remaining rounds.
    - Final Round: Cooperate if average past success suggests threshold >= m, otherwise Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description
        self.consecutive_failures = 0
        self.testing_defection = False

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        r = self.game.n_rounds
        m = self.game.m
        if t == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        my_prev_action = 1 if history.my_actions[-1] else 0
        total_prev_cooperators = prev_cooperators + my_prev_action
        if total_prev_cooperators < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
            self.testing_defection = False
        if self.consecutive_failures >= 3:
            return Action.D
        if t == r - 1:
            avg_prev_success = np.mean(history.opponent_cooperators + history.my_actions.astype(int))
            if avg_prev_success >= m - 0.5:
                return Action.C
            else:
                return Action.D
        if self.testing_defection:
            self.testing_defection = False
            return Action.C
        if total_prev_cooperators >= m:
            return Action.C
        else:
            self.testing_defection = True
            return Action.D

class Strategy_PROSOCIAL_51(BaseStrategy):
    """
    Implements a Collective Risk Dilemma strategy:
    - Rounds 1-2: Always Cooperate (C) to build trust.
    - Rounds 3 to r-1: If the group met or narrowly missed (m-1) the threshold in the
      previous round, Cooperate (C). Otherwise, Defect (D) as a punishment trigger.
    - Final Round: If previous round was successful, Cooperate (C), otherwise Defect (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        if current_round == 0:
            return Action.C
        if current_round == 1:
            return Action.C
        prev_my_action = int(history.my_actions[-1])
        prev_opponent_coops = int(history.opponent_cooperators[-1])
        total_prev_coops = prev_opponent_coops + prev_my_action
        if current_round == r - 1:
            if total_prev_coops >= m:
                return Action.C
            else:
                return Action.D
        if total_prev_coops >= m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_52(BaseStrategy):
    """
    Threshold-Sensitive Tit-for-Tat with Forgiveness.
    
    This strategy balances cooperation to hit a threshold m with opportunistic 
    defection to maximize payoffs, while including mechanisms to detect free-riders 
    and 'probing' rounds to assess opponent behavior.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.in_cooldown = False
        self.consecutive_failures = 0
        self.is_probing = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        total_c = prev_cooperators + (1 if my_prev_action else 0)
        threshold_met = total_c >= self.desc.m
        if not threshold_met:
            self.consecutive_failures += 1
            self.in_cooldown = True
        else:
            self.consecutive_failures = 0
            self.in_cooldown = False
            self.is_probing = False
        if history.round_number == self.desc.n_rounds - 1:
            if self.consecutive_failures >= 2:
                return Action.D
            if total_c >= self.desc.m - 1:
                return Action.C
            return Action.D
        if total_c >= self.desc.m + self.desc.n_players // 3:
            return Action.D
        if self.in_cooldown and (not self.is_probing):
            self.is_probing = True
            return Action.D
        if threshold_met:
            if total_c > self.desc.m:
                return Action.D
            return Action.C
        else:
            if my_prev_action:
                return Action.C
            if total_c >= self.desc.m - 1:
                return Action.C
            return Action.D

class Strategy_PROSOCIAL_53(BaseStrategy):
    """
    A Threshold Tit-for-Tat strategy that cooperates as long as the group meets
    the cooperation threshold. If the threshold is missed, it switches to 
    defecting to prevent exploitation but probes occasionally for recovery.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k
        self.target = True
        self.p_probe = 0.1

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            self.target = True
            return Action.C
        prev_round_idx = current_round - 1
        prev_cooperators = history.opponent_cooperators[prev_round_idx] + int(history.my_actions[prev_round_idx])
        prev_action = Action.C if history.my_actions[prev_round_idx] else Action.D
        if current_round == self.r - 1:
            if self.target:
                return Action.C
            elif prev_cooperators == self.m - 1:
                return Action.C
            else:
                return Action.D
        if not self.target and prev_cooperators >= self.m:
            self.target = True
            return Action.C
        if prev_cooperators >= self.m:
            self.target = True
            return Action.C
        elif prev_action == Action.C:
            self.target = False
            return Action.D
        elif random.random() < self.p_probe:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_54(BaseStrategy):
    """
    A threshold-based conditionally cooperative strategy.
    
    Logic:
    - Round 1: Plays C to signal cooperation.
    - Rounds 2 to r-1: 
        - If the previous round's cooperation count >= m, it plays C.
        - If the previous round's cooperation count < m, it plays D.
        - Special Case: If the group was failing (count < m) but then recovers (count >= m),
          it attempts to re-join the coalition by playing C.
    - Final Round (r): Plays D to avoid end-game exploitation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        prev_round_idx = history.round_number - 1
        last_round_coop_count = history.opponent_cooperators[prev_round_idx]
        my_prev_action = history.my_actions[prev_round_idx]
        total_cooperators_prev = last_round_coop_count + (1 if my_prev_action else 0)
        threshold_met = total_cooperators_prev >= self.game_description.m
        if threshold_met:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_55(BaseStrategy):
    """
    Implements a Threshold-Triggered Reciprocity strategy for the Collective Risk Dilemma.
    
    The strategy follows these rules:
    1. Round 1: Always Cooperate.
    2. Final Round: Cooperate if the previous round met the threshold (m), else Defect.
    3. Intermediate Rounds:
       - If previous round met threshold (m): Cooperate.
       - If previous round failed:
         - If we cooperated previously: Defect (to avoid exploitation).
         - If we defected previously: Cooperate if historical success rate >= 50%, else Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        m_threshold = self.game_description.m
        if current_round_idx == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        my_last_action = Action.C if history.my_actions[-1] else Action.D
        if current_round_idx == total_rounds - 1:
            if prev_cooperators >= m_threshold:
                return Action.C
            else:
                return Action.D
        if prev_cooperators >= m_threshold:
            return Action.C
        if my_last_action == Action.C:
            return Action.D
        history_counts = history.opponent_cooperators
        success_rounds = 0
        for count in history_counts:
            if count >= m_threshold:
                success_rounds += 1
        hist_len = len(history_counts)
        if hist_len > 0:
            success_rate = success_rounds / hist_len
            if success_rate >= 0.5:
                return Action.C
        return Action.D

class Strategy_PROSOCIAL_56(BaseStrategy):
    """
    Conditional Threshold Tit-for-Tat (CTTFT).
    Strategically adjusts contributions based on group performance, 
    threshold requirements, and historical cooperation trends.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_free_rider_count = 0
        self.cautious_strategy_counter = 0
        self.is_using_cautious_strategy = False
        self.last_defect_round_was_test = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        if history.round_number == 0:
            return Action.C
        prev_my_action = int(history.my_actions[-1])
        prev_total_coop = history.opponent_cooperators[-1] + prev_my_action
        if history.round_number == 1 and prev_total_coop < m:
            self.is_using_cautious_strategy = True
        if self.is_using_cautious_strategy:
            self.cautious_strategy_counter = (self.cautious_strategy_counter + 1) % 3
            if self.cautious_strategy_counter < 2:
                if prev_total_coop >= m:
                    self.is_using_cautious_strategy = False
                else:
                    return Action.D
            return Action.C
        if history.round_number == r - 1:
            avg_coop_rate = np.mean(history.opponent_cooperators + history.my_actions) / n
            if avg_coop_rate >= m / n:
                return Action.C
            return Action.D
        if prev_total_coop > m:
            self.consecutive_free_rider_count += 1
        else:
            self.consecutive_free_rider_count = 0
        if self.last_defect_round_was_test:
            self.last_defect_round_was_test = False
            return Action.C
        if self.consecutive_free_rider_count >= 3:
            if prev_my_action == 1 and prev_total_coop - 1 >= m:
                self.consecutive_free_rider_count = 0
                self.last_defect_round_was_test = True
                return Action.D
            self.consecutive_free_rider_count = 0
        if prev_total_coop >= m:
            if prev_my_action == 0 and prev_total_coop >= m:
                self.last_defect_round_was_test = True
                return Action.D
            return Action.C
        if prev_total_coop == m - 1:
            return Action.C
        if prev_total_coop < m - 1:
            if history.round_number > 1:
                prev_prev_total_coop = history.opponent_cooperators[-2] + int(history.my_actions[-2])
                if prev_total_coop > prev_prev_total_coop:
                    return Action.C
            return Action.D
        return Action.C

class Strategy_PROSOCIAL_57(BaseStrategy):
    """
    Implements Adaptive Threshold-Reciprocity strategy for Collective Risk Dilemma.
    Focuses on stabilizing group cooperation at threshold m, utilizing history 
    to punish non-compliance and conserve resources when the group is stable.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.failed_coop_streak = 0
        self.punishment_rounds_left = 0
        self.just_tested_stability = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        my_prev_action = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + my_prev_action
        if my_prev_action == 1 and total_cooperators_prev < m:
            self.failed_coop_streak += 1
        else:
            self.failed_coop_streak = 0
        if self.punishment_rounds_left > 0:
            self.punishment_rounds_left -= 1
            return Action.D
        if self.failed_coop_streak >= 3:
            self.failed_coop_streak = 0
            self.punishment_rounds_left = 2
            return Action.D
        if current_round == r - 1:
            others_cooperated = history.opponent_cooperators[-1]
            return Action.C if others_cooperated >= m - 1 else Action.D
        others_cooperated = history.opponent_cooperators[-1]
        if total_cooperators_prev >= m:
            if self.just_tested_stability:
                self.just_tested_stability = False
                return Action.D
            if total_cooperators_prev > m:
                prob_switch = (total_cooperators_prev - m) / total_cooperators_prev
                if random.random() < prob_switch:
                    self.just_tested_stability = True
                    return Action.D
            return Action.C
        else:
            if self.just_tested_stability:
                self.just_tested_stability = False
                return Action.C
            if others_cooperated >= m - 1:
                return Action.C
            return Action.D

class Strategy_PROSOCIAL_58(BaseStrategy):
    """
    Implements a Threshold-Responsive Tit-for-Tat strategy.
    
    Logic:
    1. First Round: Cooperate if m/n <= 0.5, else Defect.
    2. Subsequent Rounds (excluding final): Cooperate if previous round threshold met,
       or if this player was a pivot (or one away from pivot) in the previous round.
       Otherwise, Defect to penalize.
    3. Final Round: Cooperate if at least 50% of previous rounds met the threshold, 
       otherwise Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_idx = history.round_number
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        if current_round_idx == 0:
            if m / n <= 0.5:
                return Action.C
            else:
                return Action.D
        if current_round_idx == r - 1:
            total_cooperators_history = history.opponent_cooperators + history.my_actions.astype(int)
            threshold_met_mask = total_cooperators_history >= m
            success_count = np.sum(threshold_met_mask)
            if success_count / (r - 1) >= 0.5:
                return Action.C
            else:
                return Action.D
        prev_idx = current_round_idx - 1
        prev_my_action_int = 1 if history.my_actions[prev_idx] else 0
        prev_total_c = history.opponent_cooperators[prev_idx] + prev_my_action_int
        prev_was_cooperator = history.my_actions[prev_idx]
        if prev_total_c >= m:
            return Action.C
        is_pivot = prev_was_cooperator and prev_total_c == m or (not prev_was_cooperator and prev_total_c == m - 1)
        if is_pivot:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_59(BaseStrategy):
    """
    A Collective Risk Dilemma strategy that alternates between 'Trust-Building' 
    and 'Defensive-Correction' states to manage cooperation based on the threshold (m).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.state = 'Trust-Building'
        self.m = game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            self.state = 'Trust-Building'
            return Action.C
        my_prev_action = history.my_actions[-1]
        opp_prev_coop = history.opponent_cooperators[-1]
        prev_total_coop = opp_prev_coop + (1 if my_prev_action else 0)
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.C if prev_total_coop >= self.m else Action.D
        if self.state == 'Trust-Building':
            if prev_total_coop >= self.m:
                return Action.C
            elif self.m - prev_total_coop <= 1:
                return Action.C
            else:
                self.state = 'Defensive-Correction'
                return Action.D
        elif self.state == 'Defensive-Correction':
            if prev_total_coop >= self.m:
                self.state = 'Trust-Building'
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_PROSOCIAL_60(BaseStrategy):
    """
    A strategy that maintains a cooperation state which adapts based on the 
    collective threshold performance, monitors for group viability, and 
    attempts to signal re-engagement.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.is_cooperating = True
        self.consecutive_failed_rounds = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        if history.round_number == 0:
            self.is_cooperating = True
            return Action.C
        prev_round_idx = history.round_number - 1
        my_prev_action = history.my_actions[prev_round_idx]
        my_prev_coop = 1 if my_prev_action else 0
        c_prev_total = history.opponent_cooperators[prev_round_idx] + my_prev_coop
        if c_prev_total < m:
            self.consecutive_failed_rounds += 1
        else:
            self.consecutive_failed_rounds = 0
        if self.consecutive_failed_rounds >= 3:
            self.is_cooperating = False
        if not my_prev_action:
            if prev_round_idx > 0:
                prev_c_prev_total = history.opponent_cooperators[prev_round_idx - 1] + (1 if history.my_actions[prev_round_idx - 1] else 0)
                if c_prev_total > prev_c_prev_total:
                    self.is_cooperating = True
        if c_prev_total >= m + 1:
            self.is_cooperating = True
        elif c_prev_total == m:
            self.is_cooperating = True
        elif c_prev_total < m:
            self.is_cooperating = False
        if history.round_number == r - 1:
            if c_prev_total >= m:
                return Action.D
            else:
                total_rounds = history.round_number
                all_c_counts = []
                for t in range(total_rounds):
                    op_c = history.opponent_cooperators[t]
                    my_c = 1 if history.my_actions[t] else 0
                    all_c_counts.append(op_c + my_c)
                avg_coop = sum(all_c_counts) / (total_rounds * n)
                if avg_coop > 0.5:
                    return Action.C
                return Action.D
        return Action.C if self.is_cooperating else Action.D

class Strategy_PROSOCIAL_61(BaseStrategy):
    """
    Implements a Threshold-Conditional Reciprocity strategy for the Collective Risk Dilemma.
    It adaptively cooperates or defects based on threshold proximity, past group performance,
    and historical stability to balance personal utility against collective success.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.zero_coop_streak = 0
        self.consistent_threshold_met = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            if self.m / self.n <= 0.5:
                return Action.C
            return Action.D
        t = history.round_number
        last_c = history.opponent_cooperators[-1]
        my_last_action = Action.C if history.my_actions[-1] else Action.D
        total_c_last = last_c + (1 if my_last_action == Action.C else 0)
        if total_c_last == 0:
            self.zero_coop_streak += 1
        else:
            self.zero_coop_streak = 0
        if total_c_last >= self.m:
            self.consistent_threshold_met = True
        if self.zero_coop_streak >= 2:
            return Action.D
        if t == self.r - 1:
            if self.consistent_threshold_met:
                return Action.C
            return Action.D
        if total_c_last >= self.m:
            if my_last_action == Action.C:
                return Action.C
            if total_c_last > self.m:
                return Action.C
            if total_c_last == self.m:
                return Action.D
        elif total_c_last >= self.m - 1:
            return Action.C
        else:
            return Action.D
        return Action.D

class Strategy_PROSOCIAL_62(BaseStrategy):
    """
    Modified Tit-for-Tat with Forgiving Thresholds.
    
    Strategy Logic:
    - Round 1: Cooperate.
    - Last Round: Always Defect.
    - Intermediate Rounds:
        - Cooperate if previous cooperators >= m - 1.
        - Defect if previous cooperators < m - 1.
    - Persistent Defection Rule: If the group fails to meet the threshold (C < m) for 
      two consecutive rounds, switch to Defect permanently.
    - Sudden Drop Rule: If C drops significantly below m-1, defect for one round 
      to signal breakdown, then attempt to resume if C recovers.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.persistent_defection = False
        self.signal_breakdown = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if history.round_number >= 2:
            last_round_c = history.opponent_cooperators[-1]
            prev_round_c = history.opponent_cooperators[-2]
            my_last_action = 1 if history.my_actions[-1] else 0
            my_prev_action = 1 if history.my_actions[-2] else 0
            total_last = last_round_c + my_last_action
            total_prev = prev_round_c + my_prev_action
            if total_last < self.game_description.m and total_prev < self.game_description.m:
                self.persistent_defection = True
        if self.persistent_defection:
            return Action.D
        c_prev = history.opponent_cooperators[-1] + (1 if history.my_actions[-1] else 0)
        if self.signal_breakdown:
            self.signal_breakdown = False
            if c_prev >= self.game_description.m - 1:
                return Action.C
            return Action.D
        if c_prev < self.game_description.m - 1:
            self.signal_breakdown = True
            return Action.D
        if c_prev >= self.game_description.m - 1:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_63(BaseStrategy):
    """
    A Tit-for-Tat adaptive strategy for the Collective Risk Dilemma.
    Starts with cooperation and maintains reputation based on threshold success.
    Turns to defection if history suggests persistent failure.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.reputation = 0.0

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        r = self.game_description.n_rounds
        m = self.game_description.m
        if t == 0:
            self.reputation = 0.0
            return Action.C
        prev_cooperators = history.opponent_cooperators[t - 1]
        if t == r - 1:
            if prev_cooperators >= m:
                return Action.C
            else:
                return Action.D
        if prev_cooperators >= m:
            self.reputation = min(1.0, self.reputation + 0.1)
            return Action.C
        else:
            self.reputation = max(-1.0, self.reputation - 0.2)
            if self.reputation > -0.5:
                return Action.C
            else:
                return Action.D

class Strategy_PROSOCIAL_64(BaseStrategy):
    """
    Implements a Conditional Trigger-Threshold strategy. 
    Aims to meet the threshold 'm' cooperators, punishing free-riding, 
    and minimizing wasted contributions by alternating between contributing 
    and defecting when the threshold is comfortably met.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_index = history.round_number
        last_round_index = current_round_index - 1
        if current_round_index == 0:
            return Action.C
        my_last_action = history.my_actions[last_round_index]
        last_opp_c = history.opponent_cooperators[last_round_index]
        total_c_last = last_opp_c + (1 if my_last_action else 0)
        m = self.desc.m
        r = self.desc.n_rounds
        threshold_met = total_c_last >= m
        if current_round_index == r - 1:
            if threshold_met:
                return Action.D
            elif total_c_last == m - 1:
                return Action.C
            else:
                return Action.D
        if threshold_met:
            if my_last_action and total_c_last == m:
                return Action.C
            return Action.D
        else:
            return Action.C

class Strategy_PROSOCIAL_65(BaseStrategy):
    """
    Implements a Threshold-Conditional Reciprocity strategy for the Collective Risk Dilemma.
    
    This strategy monitors the group's cooperation threshold (m) and adjusts its 
    behavior based on the total number of cooperators observed in the previous round.
    It attempts to facilitate cooperation when the threshold is met, punishes 
    non-cooperation, and employs a probabilistic recovery mechanism.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def _get_total_cooperators_in_round(self, history: PlayerHistory, round_idx: int) -> int:
        """Helper to compute total cooperators (my + opponents) for a given round."""
        my_c = 1 if history.my_actions[round_idx] else 0
        return history.opponent_cooperators[round_idx] + my_c

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        t = history.round_number
        if t == r - 1:
            total_past_cooperators = sum((self._get_total_cooperators_in_round(history, i) for i in range(t)))
            if t == 0:
                return Action.C
            avg_coop_rate = total_past_cooperators / (t * n)
            return Action.C if avg_coop_rate > m / n else Action.D
        prev_m = self._get_total_cooperators_in_round(history, t - 1)
        my_prev_action = history.my_actions[t - 1]
        if prev_m >= m:
            if my_prev_action == Action.C:
                return Action.C
            else:
                return Action.C if random.random() < 0.5 else Action.D
        if prev_m == m - 1:
            if t >= 2:
                prev_prev_m = self._get_total_cooperators_in_round(history, t - 2)
                if prev_prev_m < m:
                    return Action.D
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_66(BaseStrategy):
    """
    Threshold-Triggered Conditional Reciprocity strategy for Collective Risk Dilemma.
    
    Logic:
    1. Always Cooperate (C) in the first round to signal intent.
    2. Always Cooperate (C) in the final round to attempt to secure the reward.
    3. In intermediate rounds, if the previous round's total cooperative count met the threshold (m), 
       continue to Cooperate (C). If the threshold was missed, Defect (D) to conserve resources.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.C
        prev_round_index = history.round_number - 1
        my_prev_action = 1 if history.my_actions[prev_round_index] else 0
        total_cooperators_prev = history.opponent_cooperators[prev_round_index] + my_prev_action
        if total_cooperators_prev >= self.game_description.m:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_67(BaseStrategy):
    """
    A Tit-for-Tat inspired strategy for the Collective Risk Dilemma.
    It prioritizes establishing a quorum by cooperating in the first and last rounds.
    It aggressively enforces threshold requirements but includes a "pivotal" override 
    to facilitate recovery when the group is exactly one cooperator shy of the threshold.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.C
        my_prev_action_bool = history.my_actions[-1]
        prev_round_cooperators = history.opponent_cooperators[-1] + (1 if my_prev_action_bool else 0)
        m = self.game_description.m
        if prev_round_cooperators == m - 1:
            return Action.C
        if prev_round_cooperators >= m:
            return Action.C
        if my_prev_action_bool:
            return Action.D
        return Action.D

class Strategy_PROSOCIAL_68(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that balances cooperative threshold 
    maintenance with individual payoff optimization, adapting to historical 
    cooperation levels.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.k = game_description.k
        self.defect_mode = False

    def __call__(self, history: PlayerHistory) -> Action:
        if self.defect_mode:
            return Action.D
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        my_prev_c = 1 if my_prev_action else 0
        opp_cooperators = history.opponent_cooperators[-1]
        total_cooperators = opp_cooperators + my_prev_c
        threshold_met = total_cooperators >= self.m
        if opp_cooperators + 1 < self.m:
            self.defect_mode = True
            return Action.D
        if round_idx == self.r - 1:
            if threshold_met:
                return Action.D
            else:
                return Action.C
        if threshold_met:
            if total_cooperators == self.m:
                return Action.C
            elif total_cooperators > self.m:
                return Action.D
            else:
                return Action.C
        elif total_cooperators >= self.m - 2:
            return Action.C
        else:
            if round_idx > 2:
                self.defect_mode = True
                return Action.D
            return Action.C

class Strategy_PROSOCIAL_69(BaseStrategy):
    """
    Implements Threshold-Conditional Reciprocity:
    1. Rounds 1: Cooperate.
    2. t > 1: If threshold (m) met, optimize cost (pivot to Defect). If threshold missed, help (Cooperate).
    3. Handles persistent defection by initiating a penalty phase.
    4. Ensures final round cooperation if history has been unsuccessful.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0
        self.penalty_mode = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.game_description.m
        n_rounds = self.game_description.n_rounds
        prev_idx = history.round_number - 1
        my_prev_action_val = 1 if history.my_actions[prev_idx] else 0
        total_c = history.opponent_cooperators[prev_idx] + my_prev_action_val
        if my_prev_action_val == 1 and total_c < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
            self.penalty_mode = False
        if self.consecutive_failures >= 3:
            self.penalty_mode = True
            self.consecutive_failures = 0
        if self.penalty_mode:
            self.penalty_mode = False
            return Action.D
        if history.round_number == n_rounds - 1:
            all_my_actions = history.my_actions.astype(int)
            all_total_c = history.opponent_cooperators + all_my_actions
            if np.any(all_total_c < m):
                return Action.C
        threshold_met = total_c >= m
        if not threshold_met:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_70(BaseStrategy):
    """
    Conditional cooperation strategy that balances trust, punishment, and resource protection.
    Follows a tit-for-tat variant adapted for group thresholds, with probabilistic re-entry.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.previous_c_count = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if self.r < 3:
            return Action.C
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        prev_my_action = 1 if history.my_actions[-1] else 0
        prev_opponent_c = history.opponent_cooperators[-1]
        c_prev = prev_opponent_c + prev_my_action
        if current_round == self.r - 1:
            total_cooperators = np.array([history.opponent_cooperators[i] + (1 if history.my_actions[i] else 0) for i in range(current_round)])
            success_count = np.sum(total_cooperators >= self.m)
            success_rate = success_count / current_round
            return Action.C if success_rate >= 0.5 else Action.D
        if current_round > 1:
            prev_prev_c = history.opponent_cooperators[-2] + (1 if history.my_actions[-2] else 0)
            if prev_prev_c >= self.m and c_prev < 0.5 * prev_prev_c:
                return Action.D
        if c_prev == self.m:
            return Action.D
        if c_prev >= self.m:
            if prev_my_action == 1:
                return Action.C
            elif prev_opponent_c >= self.m:
                return Action.C
            else:
                return Action.D
        elif prev_my_action == 1:
            return Action.D
        else:
            p = max(0.0, 1.0 - c_prev / self.m)
            if random.random() < p:
                return Action.D
            else:
                return Action.C

class Strategy_PROSOCIAL_71(BaseStrategy):
    """
    Conditional Threshold Defender:
    Plays C in the first round. In subsequent rounds, it acts based on the 
    previous round's cooperation levels:
    - If cooperators >= m + 1: Cooperate (C)
    - If cooperators == m: Cooperate (C) with probability 1 - (1/n)
    - If cooperators < m: Cooperate (C)
    In the final round: Cooperate (C) if historical success rate >= 0.5, else Defect (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        my_last_action = int(history.my_actions[-1])
        c_prev = history.opponent_cooperators[-1] + my_last_action
        if history.round_number == r - 1:
            all_opponents_actions = history.opponent_cooperators
            all_my_actions = history.my_actions.astype(int)
            total_cooperators_history = all_opponents_actions + all_my_actions
            success_count = np.sum(total_cooperators_history >= m)
            success_rate = success_count / history.round_number
            if success_rate >= 0.5:
                return Action.C
            else:
                return Action.D
        if c_prev >= m + 1:
            return Action.C
        elif c_prev == m:
            probability = 1.0 - 1.0 / n
            if random.random() < probability:
                return Action.C
            else:
                return Action.D
        else:
            return Action.C

class Strategy_PROSOCIAL_72(BaseStrategy):
    """
    A strategy that adapts cooperation based on observed group success, using a 
    probabilistic reputation threshold that adjusts based on collective performance, 
    with a terminal round defection buffer to prevent exploitation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.reputation_threshold = 1.0
        self.critical_round_buffer = max(1, math.ceil(self.game_description.n_rounds * 0.1))

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_idx = history.round_number
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        if current_round_idx == 0:
            return Action.C
        if current_round_idx > r - self.critical_round_buffer - 1:
            return Action.D
        last_action = history.my_actions[-1]
        observed_other_coops = history.opponent_cooperators[-1]
        total_cooperators = observed_other_coops + (1 if last_action else 0)
        ratio_prev = total_cooperators / n
        self.reputation_threshold = (self.reputation_threshold + ratio_prev) / 2
        if total_cooperators >= m and self.reputation_threshold < m / n:
            self.reputation_threshold = m / n
        if total_cooperators == 0:
            self.reputation_threshold *= 0.5
        if random.random() < self.reputation_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_73(BaseStrategy):
    """
    Implements a conditional threshold-based strategy for the Collective Risk Dilemma.
    Prioritizes achieving the cooperation threshold (m) while reacting to group dynamics:
    - Round 1: Cooperate.
    - Rounds 1 < t < r: Cooperate if the threshold was met, if we are exactly 1 shy of the threshold, 
      or to 'test' the waters if the previous round was a failed cooperation attempt. Defect if 
      the previous round was a successful cooperation but we were the ones defecting.
    - Final Round: Cooperate only if the group achieved the threshold in the penultimate round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == 0:
            return Action.C
        my_last_action = Action.C if history.my_actions[-1] else Action.D
        c_prev = history.opponent_cooperators[-1] + (1 if my_last_action == Action.C else 0)
        if current_round == n_rounds - 1:
            if c_prev >= m:
                return Action.C
            else:
                return Action.D
        if c_prev >= m:
            return Action.C
        if c_prev == m - 1:
            return Action.C
        if my_last_action == Action.C:
            return Action.D
        else:
            return Action.C

class Strategy_PROSOCIAL_74(BaseStrategy):
    """
    Implements a conditional contribution strategy for the Collective Risk Dilemma.
    
    Logic:
    1. Initial Round: Always Cooperate (C) to establish trust.
    2. Terminal Round: Always Defect (D) as it is the dominant strategy.
    3. Intermediate Rounds: 
       - If the group met the minimum cooperators threshold (m) in the previous round, 
         continue to Cooperate (C).
       - If the group failed to meet the threshold, switch to Defect (D) to avoid exploitation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        last_round_idx = current_round - 1
        my_last_action = history.my_actions[last_round_idx]
        opponents_cooperating = history.opponent_cooperators[last_round_idx]
        total_cooperators_last_round = opponents_cooperating + (1 if my_last_action else 0)
        if total_cooperators_last_round >= m:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_75(BaseStrategy):
    """
    Implements a phase-based strategy for the Collective Risk Dilemma:
    - Initial Phase (Rounds 0-2): Unconditional cooperation to signal intent.
    - Active Phase (Rounds 3 to r-2): Conditional strategy based on threshold performance.
    - Final Phase (Round r-1): Defection-focused if historical cooperation was erratic/low,
      cooperation-focused if stable equilibrium exists.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.last_action_was_defect = False

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        if current_round < 3:
            self.last_action_was_defect = False
            return Action.C
        if current_round == r - 1:
            prev_others = history.opponent_cooperators[-1]
            prev_mine = 1 if not self.last_action_was_defect else 0
            all_coop_counts = np.array([history.opponent_cooperators[i] + (1 if history.my_actions[i] else 0) for i in range(current_round)])
            avg_coop_rate = np.mean(all_coop_counts) / n
            if avg_coop_rate > m / n:
                self.last_action_was_defect = False
                return Action.C
            else:
                self.last_action_was_defect = True
                return Action.D
        if self.last_action_was_defect:
            self.last_action_was_defect = False
            return Action.C
        prev_others = history.opponent_cooperators[-1]
        prev_mine = 1 if history.my_actions[-1] else 0
        total_prev_coop = prev_others + prev_mine
        if total_prev_coop >= m:
            self.last_action_was_defect = False
            return Action.C
        else:
            deficit = m - total_prev_coop
            if deficit <= 1:
                if random.random() > 0.5:
                    self.last_action_was_defect = False
                    return Action.C
                else:
                    self.last_action_was_defect = True
                    return Action.D
            else:
                self.last_action_was_defect = True
                return Action.D

class Strategy_PROSOCIAL_76(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that employs a mix of conditional 
    reciprocity, threshold recovery attempts, and final-round cooperation based on 
    historical performance.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.n = game_description.n_players
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        if current_round == self.r - 1:
            total_coop = np.sum(history.opponent_cooperators)
            my_total_coop = np.sum(history.my_actions.astype(int))
            avg_rate = (total_coop + my_total_coop) / (current_round * self.n)
            if avg_rate >= self.m / self.n:
                return Action.C
            else:
                return Action.D
        if prev_cooperators >= self.m:
            return Action.C
        if prev_cooperators >= math.floor(self.m / 2):
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_77(BaseStrategy):
    """
    Threshold-Conditional Tit-for-Tat strategy.
    Cooperates in the first round. 
    In subsequent rounds:
    - If previously Cooperated:
        - If threshold met, continue Cooperating.
        - If threshold not met, probabilistically Defect based on performance gap.
    - If previously Defected:
        - If threshold met, forgive and Cooperate.
        - If threshold not met, continue Defecting.
    - Final round logic optimizes for potential success.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        current_round = history.round_number
        last_idx = -1
        last_cooperators = int(history.opponent_cooperators[last_idx])
        my_last_action = history.my_actions[last_idx]
        total_cooperators = last_cooperators + (1 if my_last_action else 0)
        if history.round_number == self.r - 1:
            if total_cooperators >= self.m - 1:
                return Action.C
            return Action.D
        if my_last_action:
            if total_cooperators >= self.m:
                return Action.C
            else:
                prob_defect = (self.m - total_cooperators) / self.m
                if random.random() < prob_defect:
                    return Action.D
                else:
                    return Action.C
        elif total_cooperators >= self.m:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_78(BaseStrategy):
    """
    A conditional cooperative strategy for the Collective Risk Dilemma.
    Implements a threshold-aware mechanism that:
    1. Starts with cooperation.
    2. Continues cooperation if the threshold is met.
    3. Punishes unilateral defection after threshold failure.
    4. Attempts to rebuild cooperation if participation is moderate.
    5. Detects and stops contributing if the population is uncooperative (persistence of defection).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_zeros = 0
        self.persistent_defection_threshold = 3

    def __call__(self, history: PlayerHistory) -> Action:
        m = self.game_description.m
        r_total = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        last_action_c = bool(history.my_actions[-1])
        opp_c = history.opponent_cooperators[-1]
        total_c = opp_c + (1 if last_action_c else 0)
        if total_c == 0:
            self.consecutive_zeros += 1
        else:
            self.consecutive_zeros = 0
        if self.consecutive_zeros >= self.persistent_defection_threshold:
            return Action.D
        if current_round == r_total - 1:
            historical_success_rate = np.mean(history.opponent_cooperators + history.my_actions.astype(int)) >= m
            if historical_success_rate:
                return Action.C
            else:
                return Action.D
        if total_c >= m:
            return Action.C
        if last_action_c:
            if total_c == m - 1:
                return Action.C
            return Action.D
        elif opp_c >= m / 2.0:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_79(BaseStrategy):
    """
    A strategy that maintains cooperation while the group threshold (m) is met.
    Punishes defectors by withholding contribution (Defect) if the threshold was missed 
    in the previous round. Attempts to recover cooperation if the group self-corrects 
    while the agent is currently defecting. Logic adjusts for the final round to 
    mitigate exploitation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == 0:
            return Action.C
        last_opponent_count = history.opponent_cooperators[-1]
        my_last_action = Action.C if history.my_actions[-1] else Action.D
        last_my_count = 1 if my_last_action == Action.C else 0
        total_last_c = last_opponent_count + last_my_count
        if current_round == n_rounds - 1:
            if total_last_c >= m:
                return Action.C
            else:
                return Action.D
        if total_last_c >= m:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_80(BaseStrategy):
    """
    Implements a risk-aware, threshold-maintaining strategy for the Collective Risk Dilemma.
    Prioritizes meeting the cooperative threshold 'm', switches to defection only when safe,
    and incorporates a stability check to ensure consistent cooperation before defecting.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description
        self.consecutive_cooperative_rounds = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_last_action = int(history.my_actions[-1])
        c_others = history.opponent_cooperators[-1]
        c_total = c_others + my_last_action
        if c_total >= self.game.m:
            self.consecutive_cooperative_rounds += 1
        else:
            self.consecutive_cooperative_rounds = 0
        if history.round_number == self.game.n_rounds - 1:
            if self.consecutive_cooperative_rounds >= 3:
                return Action.D
            return Action.C
        if c_total < self.game.m:
            return Action.C
        if c_total == self.game.m:
            return Action.C
        if c_total > self.game.m:
            if c_total - 1 >= self.game.m:
                prob = (c_total - self.game.m) / c_total
                if random.random() < prob:
                    return Action.D
            if self.consecutive_cooperative_rounds < 3:
                return Action.C
        return Action.C

class Strategy_PROSOCIAL_81(BaseStrategy):
    """
    Implements a mixed-strategy, reputation-based approach for the Collective Risk Dilemma.
    Uses adaptive threshold tracking and conditional cooperation based on observed group dynamics.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k
        self.cooperation_threshold = self.m
        self.reputation = 1.0

    def __call__(self, history: PlayerHistory) -> Action:
        round_t = history.round_number + 1
        if round_t == 1:
            if random.random() < self.m / self.n:
                return Action.C
            return Action.D
        prev_opp_coop = history.opponent_cooperators[-1]
        self_played_c = int(history.my_actions[-1])
        total_coop_prev = prev_opp_coop + self_played_c
        if total_coop_prev == self.n:
            return Action.D
        if total_coop_prev == 0:
            if round_t == 2:
                return Action.C
            return Action.D
        if round_t == self.r:
            avg_coop = np.mean(history.opponent_cooperators + history.my_actions.astype(int))
            if avg_coop < self.m:
                return Action.D
            else:
                return Action.C
        self.reputation = 0.7 * self.reputation + 0.3 * (total_coop_prev / self.n)
        threshold_ratio = self.m / self.n
        if self.reputation >= threshold_ratio:
            if total_coop_prev == self.m - 1 or total_coop_prev == self.m:
                return Action.C
            return Action.D
        else:
            if total_coop_prev < self.m:
                return Action.C
            return Action.D

class Strategy_PROSOCIAL_82(BaseStrategy):
    """
    Implements a Collective Risk Dilemma strategy utilizing rolling averages,
    probabilistic assessment of impact, and threshold monitoring to adapt
    cooperation levels.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description
        self.n = self.game.n_players
        self.r = self.game.n_rounds
        self.m = self.game.m
        self.k = self.game.k
        self.n_opponents = self.n - 1
        self.consecutive_low_coop_count = 0
        self.switched_to_permanent_defect = False

    def _get_binomial_prob(self, n, k, p):
        if k < 0 or k > n:
            return 0.0
        comb = math.comb(n, k)
        return comb * p ** k * (1 - p) ** (n - k)

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number > 0:
            past_coop_rates = []
            for j in range(history.round_number):
                past_coop_rates.append(history.opponent_cooperators[j] / self.n_opponents)
            avg_p = sum(past_coop_rates) / len(past_coop_rates)
            if avg_p < 0.2:
                self.switched_to_permanent_defect = True
        if self.switched_to_permanent_defect:
            return Action.D
        if history.round_number >= 2:
            last_round_coop = history.opponent_cooperators[-1]
            second_last_round_coop = history.opponent_cooperators[-2]
            if last_round_coop < self.m - 2 and second_last_round_coop < self.m - 2:
                self.switched_to_permanent_defect = True
                return Action.D
        if history.round_number == 0:
            return Action.C
        all_p = [history.opponent_cooperators[j] / self.n_opponents for j in range(history.round_number)]
        avg_p_t_minus_1 = sum(all_p) / len(all_p)
        t = history.round_number + 1
        if t == self.r:
            if avg_p_t_minus_1 >= (self.m - 1) / self.n_opponents:
                return Action.C
            return Action.D
        if t < math.ceil(self.r / 4):
            return Action.C
        prob_impact = self._get_binomial_prob(self.n_opponents, self.m - 1, avg_p_t_minus_1)
        prob_x_ge_m = sum((self._get_binomial_prob(self.n_opponents, i, avg_p_t_minus_1) for i in range(self.m, self.n_opponents + 1)))
        prob_x_ge_m_minus_1 = prob_impact + prob_x_ge_m
        e_u_c = prob_x_ge_m_minus_1 * self.k
        e_u_d = prob_x_ge_m * self.k + 1
        if e_u_c >= e_u_d:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_83(BaseStrategy):
    """
    A strategy that maintains a moving average of group cooperation (trust_level),
    adapting to collective dynamics and threshold requirements. It employs conditional 
    cooperation, reciprocity, and terminal-phase optimization.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.trust_level = 0.5
        self.consecutive_zero_obs = 0
        self.is_recovering = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r_total = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        prev_round_idx = -1
        last_opponent_coops = history.opponent_cooperators[prev_round_idx]
        last_my_action = history.my_actions[prev_round_idx]
        did_i_cooperate = 1 if last_my_action else 0
        obs_rate = last_opponent_coops / (n - 1)
        if obs_rate == 0:
            self.consecutive_zero_obs += 1
            if self.consecutive_zero_obs >= 2:
                self.trust_level = 0.1
                self.is_recovering = True
                return Action.D
        else:
            self.consecutive_zero_obs = 0
            if self.is_recovering:
                if last_opponent_coops + did_i_cooperate >= m:
                    self.trust_level = 0.5
                    self.is_recovering = False
                else:
                    return Action.D
        total_cooperators = last_opponent_coops + did_i_cooperate
        excess_margin = total_cooperators - m
        weight = 0.3
        if excess_margin >= 2:
            weight = 0.15
        self.trust_level = 0.7 * self.trust_level + weight * obs_rate
        if current_round == r_total - 1:
            return Action.C if self.trust_level >= 0.5 else Action.D
        if excess_margin >= n - m:
            return Action.D
        cond_threshold = self.trust_level * (n - 1) >= m - 1
        reciprocity = self.trust_level > 0.4
        if cond_threshold or reciprocity:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_84(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that balances prosocial contribution with 
    threshold sensitivity. 
    
    Round 1: Always Cooperate (C) to signal intent.
    Subsequent Rounds:
    - If threshold (m) met last round: Maintain cooperation if critical (c == m), 
      otherwise test free-riding stability (D) if there's a buffer (c > m).
    - If threshold (m) missed last round: Default to defect (D) to save endowment, 
      unless recent trend shows progress (>= 75% of m), then Cooperate (C).
    - Last Round (r): Cooperate if historical success rate implies threshold reachability 
      or if consistent cooperation has been maintained; otherwise Defect (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        recent_c = int(history.opponent_cooperators[-1])
        my_last_action = bool(history.my_actions[-1])
        total_cooperators = recent_c + (1 if my_last_action else 0)
        if current_round == self.r - 1:
            total_history_c = history.opponent_cooperators + history.my_actions.astype(int)
            success_count = np.sum(total_history_c >= self.m)
            if success_count > self.r / 2 or np.mean(history.my_actions) > 0.5:
                return Action.C
            else:
                return Action.D
        if total_cooperators >= self.m:
            if total_cooperators == self.m:
                return Action.C
            else:
                return Action.D
        else:
            is_upward_trend = False
            if current_round >= 2:
                prev_c = int(history.opponent_cooperators[-2]) + (1 if history.my_actions[-2] else 0)
                if total_cooperators > prev_c and total_cooperators >= self.m * 0.75:
                    is_upward_trend = True
            if total_cooperators >= self.m * 0.75 or is_upward_trend:
                return Action.C
            else:
                return Action.D

class Strategy_PROSOCIAL_85(BaseStrategy):
    """
    A Threshold Tit-for-Tat strategy designed for the Collective Risk Dilemma.
    
    Logic:
    - Round 1: Always Cooperate.
    - Final Round: Cooperate if the group history suggests the threshold is achievable, else Defect.
    - Standard Rounds:
        - If threshold met in previous round: Cooperate.
        - If threshold not met: Cooperate with probability m/n.
        - Edge Case: If systemic defection (3 consecutive failures), switch to Defect, 
          but retry Cooperation every 5th round.
        - Edge Case: If threshold over-shooting (C > m), continue to Cooperate.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.consecutive_failures = 0

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.desc.n_rounds - 1:
            if np.mean(history.opponent_cooperators) >= self.desc.m - 1:
                return Action.C
            else:
                return Action.D
        last_round_idx = current_round - 1
        last_c = history.opponent_cooperators[last_round_idx]
        if last_c < self.desc.m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 3:
            if (current_round + 1) % 5 == 0:
                return Action.C
            else:
                return Action.D
        if last_c >= self.desc.m:
            return Action.C
        elif random.random() < self.desc.m / self.desc.n_players:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_86(BaseStrategy):
    """
    Threshold-Targeted Conditional Cooperation strategy for the Collective Risk Dilemma.
    
    Round 1: Always Cooperate.
    Rounds 2 to r-1: Cooperate if previous round cooperators >= m-1. Otherwise, Defect, 
    with a 'probe' mechanism every 3 rounds to check for population shifts.
    Final Round r: Cooperate if previous round cooperators >= m-1. Otherwise, Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.defect_streak = 0
        self.probing = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.game_description.m
        r = self.game_description.n_rounds
        my_prev_action = history.my_actions[-1]
        prev_opp_count = history.opponent_cooperators[-1]
        total_prev_coop = prev_opp_count + (1 if my_prev_action else 0)
        current_round = history.round_number
        is_final_round = current_round == r - 1
        if not is_final_round:
            if total_prev_coop < m - 1:
                self.defect_streak += 1
                if self.defect_streak % 3 == 0:
                    return Action.C
                return Action.D
            else:
                self.defect_streak = 0
                if total_prev_coop >= m - 1:
                    return Action.C
                return Action.D
        elif total_prev_coop >= m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_87(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that employs a mix of cooperative baseline,
    conditional monitoring (reciprocity), and probing behavior when cooperation fails.
    
    Logic:
    - Round 0: Always Cooperate (C).
    - Round 1 to r-1: 
        - If previous round threshold (m) met: Cooperate (C).
        - If previous round threshold (m) not met:
            - If last action was Defect (D): Probabilistically probe (50% chance C).
            - Else: Defect (D).
    - Round r: 
        - If previous round threshold (m) met: Cooperate (C).
        - If previous round threshold (m) not met: Defect (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round_idx = history.round_number
        last_round_idx = current_round_idx - 1
        my_prev_action = history.my_actions[last_round_idx]
        total_cooperators = history.opponent_cooperators[last_round_idx] + (1 if my_prev_action else 0)
        last_round_success = total_cooperators >= m
        if current_round_idx == r - 1:
            return Action.C if last_round_success else Action.D
        if last_round_success:
            return Action.C
        if not my_prev_action:
            if random.random() < 0.5:
                return Action.C
            return Action.D
        return Action.D

class Strategy_PROSOCIAL_88(BaseStrategy):
    """
    A strategy that maintains cooperation if the threshold 'm' is met, switches to
    defensive defection if the threshold fails (triggered by previous own cooperation),
    and resets to cooperation once the group meets the threshold again.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.state = 'Cooperative'

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == self.game_description.n_rounds - 1:
            last_opp_coop = history.opponent_cooperators[-1]
            last_my_coop = int(history.my_actions[-1])
            total_c_prev = last_opp_coop + last_my_coop
            if total_c_prev >= self.game_description.m - 1:
                return Action.C
            else:
                return Action.D
        if t == 0:
            self.state = 'Cooperative'
            return Action.C
        last_opp_coop = history.opponent_cooperators[-1]
        last_my_coop = int(history.my_actions[-1])
        C_prev = last_opp_coop + last_my_coop
        if C_prev == self.game_description.m - 1 and last_my_coop == 1:
            return Action.C
        if self.state == 'Cooperative':
            if C_prev >= self.game_description.m:
                return Action.C
            elif last_my_coop == 1:
                self.state = 'Defensive'
                return Action.D
            else:
                return Action.C
        elif self.state == 'Defensive':
            if C_prev >= self.game_description.m:
                self.state = 'Cooperative'
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_PROSOCIAL_89(BaseStrategy):
    """
    Implements a Collective Risk Dilemma strategy that balances conditional cooperation,
    an alternating reset mechanism upon failure, and a final-round threshold check.
    
    Includes a "Persistent Failure" check (3 strikes rule) to prevent unilateral exploitation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        i_cooperated_last = bool(history.my_actions[-1])
        opp_cooperated_last = int(history.opponent_cooperators[-1])
        c_total_last = opp_cooperated_last + (1 if i_cooperated_last else 0)
        if c_total_last < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 3:
            return Action.D
        if current_round == r - 1:
            if c_total_last >= m - 1:
                return Action.C
            else:
                return Action.D
        if c_total_last >= m:
            return Action.C
        if i_cooperated_last:
            return Action.D
        else:
            return Action.C

class Strategy_PROSOCIAL_90(BaseStrategy):
    """
    Implements Conditional Threshold Reciprocity.
    
    Phases:
    1. Initialization: Always cooperate in Round 1.
    2. Assessment/Reciprocation: 
       - If collective met threshold (C_prev >= m), continue cooperating.
       - If collective failed (C_prev < m), retaliate with D, unless it's a "near miss" (C_prev = m-1), 
         in which case cooperate to encourage growth.
       - If a 'Retaliation' D was played, return to C to restart.
    3. Termination: Cooperate if last round succeeded, Defect otherwise.
    
    Edge Case Handling:
    - Persistent Failure (3 consecutive rounds of failure): Switch to permanent Defection.
    - Near-Threshold: If C_prev == m - 1, ignore failure and cooperate.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.failure_counter = 0

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        prev_round_idx = t - 1
        opponents_cooperating_prev = history.opponent_cooperators[prev_round_idx]
        my_action_prev_bool = history.my_actions[prev_round_idx]
        my_c_prev = 1 if my_action_prev_bool else 0
        total_cooperators_prev = my_c_prev + opponents_cooperating_prev
        if total_cooperators_prev < self.m:
            self.failure_counter += 1
        else:
            self.failure_counter = 0
        if self.failure_counter >= 3:
            return Action.D
        if t == self.r - 1:
            if total_cooperators_prev >= self.m:
                return Action.C
            else:
                return Action.D
        if total_cooperators_prev == self.m - 1:
            return Action.C
        if total_cooperators_prev >= self.m:
            return Action.C
        if my_action_prev_bool:
            return Action.D
        else:
            return Action.C

class Strategy_PROSOCIAL_91(BaseStrategy):
    """
    Threshold-Sensitive Tit-for-Tat (TSTFT):
    A strategy that maintains cooperation if the community project is viable.
    It attempts to signal cooperation when the threshold is narrowly missed,
    but switches to defection if coordination failures are persistent,
    with an end-game heuristic to maximize payoffs.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        last_idx = -1
        my_prev_action = history.my_actions[last_idx]
        opp_prev_coop = history.opponent_cooperators[last_idx]
        prev_total_coop = opp_prev_coop + (1 if my_prev_action else 0)
        current_round = history.round_number
        rounds_left = self.r - current_round
        if prev_total_coop >= self.m:
            return Action.C
        if prev_total_coop == self.m - 1:
            return Action.C
        if rounds_left <= 2:
            recent_history = history.opponent_cooperators[max(0, len(history.opponent_cooperators) - 3):]
            cooperation_viable = False
            for i, opp_count in enumerate(recent_history):
                idx_in_history = len(history.opponent_cooperators) - len(recent_history) + i
                total = opp_count + (1 if history.my_actions[idx_in_history] else 0)
                if total >= self.m:
                    cooperation_viable = True
                    break
            if not cooperation_viable:
                return Action.D
        return Action.D

class Strategy_PROSOCIAL_92(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that employs conditional cooperation.
    
    Logic:
    - Round 1: Always Cooperate (C).
    - Rounds 2 to r-1: 
        - Cooperate if the group met the threshold (C_{t-1} >= m).
        - Cooperate if the group is exactly one short (C_{t-1} == m-1) as a 'conditional invitation'.
        - Otherwise, Defect (D).
    - Last Round: 
        - Cooperate if C_{r-1} >= m - 1.
        - Otherwise, Defect.
    - Re-entry mechanism: Implicitly handled by the logic above (if the group cooperates 
      well enough in round t-1, we switch back to C in round t).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        r = self.game_description.n_rounds
        m = self.game_description.m
        current_round_idx = history.round_number
        if current_round_idx == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        my_prev_val = 1 if my_prev_action == Action.C else 0
        total_cooperators_prev = prev_cooperators + my_prev_val
        if current_round_idx == r - 1:
            if total_cooperators_prev >= m - 1:
                return Action.C
            else:
                return Action.D
        if total_cooperators_prev >= m:
            return Action.C
        elif total_cooperators_prev == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_93(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that employs a conditional
    cooperation logic based on whether the previous round met the threshold `m`.
    - Always cooperates in the first round.
    - If the previous round's cooperation count (by all players) met or exceeded `m`, 
      it continues/switches to cooperating.
    - If the previous round's cooperation count fell below `m`, it defects to preserve
      the endowment.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_last_action_val = 1 if history.my_actions[-1] == Action.C else 0
        total_cooperators_last_round = history.opponent_cooperators[-1] + my_last_action_val
        threshold_met = total_cooperators_last_round >= self.m
        if threshold_met:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_94(BaseStrategy):
    """
    A strategic implementation for the Collective Risk Dilemma.
    Implements a recursive threshold-based cooperative strategy with 
    punishment mechanisms, test-cooperation resets, and final-round 
    optimization.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0
        self.last_round_defect_and_failed = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        k = self.game_description.k
        if k <= 1.0:
            if history.round_number == 0:
                return Action.C
            last_round_total_cooperators = history.opponent_cooperators[-1] + (1 if history.my_actions[-1] else 0)
            return Action.C if last_round_total_cooperators >= m else Action.D
        if history.round_number == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        prev_total_cooperators = history.opponent_cooperators[-1] + (1 if my_prev_action else 0)
        if prev_total_cooperators < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if history.round_number == r - 1:
            all_prev_total_cooperators = []
            for i in range(history.round_number):
                c_i = 1 if history.my_actions[i] else 0
                all_prev_total_cooperators.append(history.opponent_cooperators[i] + c_i)
            avg_c = np.mean(all_prev_total_cooperators) if all_prev_total_cooperators else 0.0
            if avg_c >= m:
                return Action.C
            return Action.D
        if self.consecutive_failures >= 2:
            return Action.D
        if prev_total_cooperators >= m:
            self.last_round_defect_and_failed = False
            return Action.C
        elif not my_prev_action and self.last_round_defect_and_failed == False:
            self.last_round_defect_and_failed = True
            return Action.C
        else:
            self.last_round_defect_and_failed = False
            return Action.D

class Strategy_PROSOCIAL_95(BaseStrategy):
    """
    Adaptive Threshold-Conditional Tit-for-Tat:
    - Round 1: Always Cooperate.
    - Subsequent rounds:
        - Sustained: If threshold m met, cooperate.
        - Failure: If m not met, evaluate deficit:
            - If deficit > half of other players, defect (anti-exploit).
            - Otherwise, cooperate (coordination signal).
        - Exploitation Filter: If threshold is hit consistently but only exactly at m, 
          probabilistically test group reliance.
    - Final round: Cooperate if threshold met > 50% of history, else Defect.
    - Small-n exception: Always cooperate if n is close to m.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_exact_threshold_rounds = 0
        self.consecutive_exceeded_threshold_rounds = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r_total = self.game_description.n_rounds
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if n <= m + 2:
            return Action.C
        if round_idx == r_total - 1:
            threshold_met_count = 0
            for r in range(round_idx):
                my_action_prev = 1 if history.my_actions[r] else 0
                total_c = history.opponent_cooperators[r] + my_action_prev
                if total_c >= m:
                    threshold_met_count += 1
            if threshold_met_count / round_idx >= 0.5:
                return Action.C
            return Action.D
        prev_opp_c = history.opponent_cooperators[-1]
        my_prev_action = 1 if history.my_actions[-1] else 0
        total_c_prev = prev_opp_c + my_prev_action
        if total_c_prev >= m:
            self.consecutive_exact_threshold_rounds = self.consecutive_exact_threshold_rounds + 1 if total_c_prev == m else 0
            self.consecutive_exceeded_threshold_rounds = self.consecutive_exceeded_threshold_rounds + 1 if total_c_prev > m else 0
            if self.consecutive_exceeded_threshold_rounds >= 3:
                return Action.C
            if self.consecutive_exact_threshold_rounds > 0:
                if random.random() < 1.0 - m / n:
                    return Action.D
            return Action.C
        else:
            self.consecutive_exact_threshold_rounds = 0
            self.consecutive_exceeded_threshold_rounds = 0
            if my_prev_action == 0 and total_c_prev + 1 >= m:
                return Action.C
            deficit = m - total_c_prev
            n_opponents = n - 1
            if deficit > n_opponents / 2:
                return Action.D
            else:
                return Action.C

class Strategy_PROSOCIAL_96(BaseStrategy):
    """
    A strategy that follows a multi-phase approach:
    1. Initial Phase: Cooperate for the first 2 rounds.
    2. Monitoring Phase: Adaptive strategy based on the 'Cooperation Deficit'.
       - Maintain C if previous N_c >= m.
       - Apply 'Rescue': Cooperate if N_c was exactly m - 1.
       - Defect if the group fails to meet the rescue threshold twice consecutively.
       - Revert to cooperation if N_c returns to >= m.
    3. Terminal Phase: Cooperate if the aggregate historical cooperation rate meets the threshold.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = self.game_description.n_players
        self.m = self.game_description.m
        self.r = self.game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        round_idx = history.round_number
        current_round = round_idx + 1
        if round_idx < 2:
            return Action.C
        my_prev_action = int(history.my_actions[-1])
        prev_n_c = history.opponent_cooperators[-1] + my_prev_action
        if current_round == self.r:
            total_n_c = 0
            for i in range(round_idx):
                total_n_c += history.opponent_cooperators[i] + int(history.my_actions[i])
            avg_coop_rate = total_n_c / ((self.r - 1) * self.n)
            threshold_rate = self.m / self.n
            return Action.C if avg_coop_rate >= threshold_rate else Action.D
        if prev_n_c == self.m - 1:
            return Action.C
        if prev_n_c >= self.m:
            return Action.C
        if round_idx >= 2:
            prev_prev_n_c = history.opponent_cooperators[-2] + int(history.my_actions[-2])
            if prev_n_c < self.m - 1 and prev_prev_n_c < self.m - 1:
                return Action.D
        return Action.D

class Strategy_PROSOCIAL_97(BaseStrategy):
    """
    Adaptive Threshold-Conditional Cooperation:
    1. Always cooperates in the first round (t=0).
    2. In the final round, cooperates only if the group has historically met the threshold.
    3. In intermediate rounds:
       - If the previous round met the threshold (C_obs >= m), cooperate.
       - If the previous round failed (C_obs < m), defect to avoid subsidizing failure.
       - "Re-entry" probe: If previously defecting and the count was exactly m-1, 
         switch to cooperate to attempt to trigger success.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        m = self.game_description.m
        n_rounds = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == n_rounds - 1:
            all_rounds_met = True
            for i in range(current_round):
                if history.opponent_cooperators[i] < m:
                    all_rounds_met = False
                    break
            if all_rounds_met:
                return Action.C
            return Action.D
        c_obs_prev = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        if not my_prev_action and c_obs_prev == m - 1:
            return Action.C
        if c_obs_prev >= m:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_98(BaseStrategy):
    """
    A conditional cooperation strategy for the Collective Risk Dilemma.
    
    Logic:
    - Round 1: Cooperate (C).
    - Rounds 2 to r-1: 
        - If previous round met threshold (C >= m), maintain C.
        - If previous round missed threshold by a small margin (deficit <= 1), signal C.
        - If previous round missed threshold by a large margin, play D for one round to minimize losses.
    - Final Round (r): 
        - Cooperate if threshold was met in the previous round OR missed by only one player.
        - Otherwise, Defect to prevent exploitation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        opp_coop_count = history.opponent_cooperators[-1]
        total_cooperators = int(opp_coop_count) + (1 if my_prev_action else 0)
        deficit = self.m - total_cooperators
        current_round_idx = history.round_number + 1
        if current_round_idx < self.r:
            if total_cooperators >= self.m:
                return Action.C
            elif deficit <= 1:
                return Action.C
            else:
                return Action.D
        elif total_cooperators >= self.m or deficit <= 1:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_99(BaseStrategy):
    """
    Threshold-Responsive Reciprocation:
    A strategy for the Collective Risk Dilemma that manages cooperation based on 
    the observed threshold of others. It attempts to maintain cooperation if 
    the threshold is met (Phase 1), offers a recovery attempt if the threshold 
    was slightly missed (Phase 2), and optimizes for the final round (Phase 3).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        last_round_cooperators = history.opponent_cooperators[-1]
        if round_idx == r - 1:
            if last_round_cooperators >= m - 1:
                return Action.C
            else:
                return Action.D
        if last_round_cooperators >= m - 1:
            return Action.C
        elif last_round_cooperators >= m - 2:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_100(BaseStrategy):
    """
    Implements a Tit-for-Tat-with-Forgiveness strategy for the Collective Risk Dilemma.
    
    Logic summary:
    - Round 0: Always Cooperate.
    - Intermediate Rounds (0 < t < r-1):
        - If previous threshold met (C >= m), Cooperate.
        - If previous result was close (C == m-1), Cooperate (Forgiveness/Retry).
        - Otherwise, Defect with probability based on how far the group was from the goal,
          punishing significant under-contribution.
    - Final Round (t = r-1):
        - Cooperate if previous round was m-1 or greater.
        - Defect otherwise.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        last_c = history.opponent_cooperators[-1]
        if current_round == self.r - 1:
            if last_c >= self.m - 1:
                return Action.C
            else:
                return Action.D
        if last_c >= self.m:
            return Action.C
        if last_c >= self.m - 1:
            return Action.C
        p_defect = 1.0 - last_c / self.m
        if random.random() < p_defect:
            return Action.D
        else:
            return Action.C

class Strategy_PROSOCIAL_101(BaseStrategy):
    """
    Threshold-Responsive Tit-for-Tat (TR-TFT):
    A strategy that adapts cooperation based on whether the collective threshold (m)
    was met in the previous round. It includes a recovery mechanism for past defections
    and a probabilistic noise component to test cooperation levels. It tracks
    consecutive failures to reach the threshold to implement a periodic punishment.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.n = game_description.n_players
        self.m = game_description.m
        self.k = game_description.k
        self.punishment_counter = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_round = history.round_number - 1
        c_prev_total = history.opponent_cooperators[prev_round] + int(history.my_actions[prev_round])
        others_c_prev = history.opponent_cooperators[prev_round]
        my_prev_action = history.my_actions[prev_round]
        if c_prev_total < self.m:
            self.punishment_counter += 1
        else:
            self.punishment_counter = 0
        if self.punishment_counter >= 3:
            if self.punishment_counter <= 4:
                return Action.D
            else:
                self.punishment_counter = 0
                return Action.C
        if c_prev_total >= self.m:
            return Action.C
        if my_prev_action:
            if others_c_prev == self.m - 1:
                return Action.D
            else:
                prob = 1.0 - c_prev_total / self.m
                if random.random() < prob:
                    return Action.C
                else:
                    return Action.D
        else:
            return Action.C

class Strategy_PROSOCIAL_102(BaseStrategy):
    """
    Adaptive Threshold Tit-for-Tat (AT-TFT).
    A conditional cooperation strategy that maintains cooperation if the threshold 
    (m) is met, attempts to bridge the gap if at least half of the threshold is met, 
    and defects if the collective performance is critically low.
    Always defects in the final round to maximize terminal payoff.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.recovery_threshold = math.floor(self.game_description.m / 2)

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        if prev_cooperators >= self.game_description.m:
            return Action.C
        if prev_cooperators >= self.recovery_threshold:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_103(BaseStrategy):
    """
    A conditional, threshold-adaptive strategy for the Collective Risk Dilemma.
    It prioritizes early momentum for low thresholds and cautious observation for high thresholds.
    It utilizes a 'tipping point' heuristic to break deadlocks when the group is one cooperator shy of the threshold
    and unconditionally cooperates in the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.desc.n_rounds - 1:
            return Action.C
        if history.round_number == 0:
            if self.desc.m / self.desc.n_players <= 0.5:
                return Action.C
            return Action.D
        my_last_action = history.my_actions[-1]
        total_cooperators_prev = history.opponent_cooperators[-1] + (1 if my_last_action else 0)
        if total_cooperators_prev >= self.desc.m:
            return Action.C
        if total_cooperators_prev == self.desc.m - 1:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_104(BaseStrategy):
    """
    A conditional cooperation strategy for the Collective Risk Dilemma.
    Implements threshold maintenance, retaliatory exclusion, and specific 
    handling for "free-rider" detection and small-group vulnerabilities.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.is_probing = False
        self.failure_count = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.desc.m
        n = self.desc.n_players
        prev_coop_total = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        total_cooperators_prev = prev_coop_total + (1 if my_prev_action else 0)
        if total_cooperators_prev < m:
            self.failure_count += 1
        if history.round_number == self.desc.n_rounds - 1:
            if self.failure_count / self.desc.n_rounds > 0.5:
                return Action.D
            return Action.C
        if total_cooperators_prev >= m:
            self.is_probing = False
            if total_cooperators_prev == m and my_prev_action:
                return Action.D
            return Action.C
        if m > n / 1.5:
            return Action.C
        if my_prev_action:
            self.is_probing = True
            return Action.D
        else:
            self.is_probing = True
            return Action.D

class Strategy_PROSOCIAL_105(BaseStrategy):
    """
    Implements a Threshold-Targeted Conditional Reciprocator.
    Strategies:
    - Round 1: Cooperate if m/n >= 0.5, else Defect.
    - Success (C_prev >= m):
        - C_prev > m and A_prev=C -> D
        - C_prev == m and A_prev=C -> C
        - C_prev > m and A_prev=D -> D
        - C_prev == m and A_prev=D -> C
    - Failure (C_prev < m):
        - A_prev=C -> C
        - A_prev=D -> C
    - Edge Cases:
        - Last round: If threshold met last 2 rounds -> D, else Failure logic.
        - Vulnerability: If C_prev == m - 1 -> C.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            if self.m / self.n >= 0.5:
                return Action.C
            return Action.D
        c_i_prev = 1 if history.my_actions[-1] else 0
        opp_c_prev = history.opponent_cooperators[-1]
        c_prev_total = opp_c_prev + c_i_prev
        if current_round == self.r - 1:
            if current_round >= 2:
                prev_1_total = history.opponent_cooperators[-1] + (1 if history.my_actions[-1] else 0)
                prev_2_total = history.opponent_cooperators[-2] + (1 if history.my_actions[-2] else 0)
                if prev_1_total >= self.m and prev_2_total >= self.m:
                    return Action.D
        if c_prev_total == self.m - 1:
            return Action.C
        if c_prev_total >= self.m:
            if c_i_prev == 1:
                if c_prev_total > self.m:
                    return Action.D
                else:
                    return Action.C
            elif c_prev_total > self.m:
                return Action.D
            else:
                return Action.C
        else:
            return Action.C

class Strategy_PROSOCIAL_106(BaseStrategy):
    """
    Implements a Threshold-Targeted Conditional Reciprocity strategy for the
    Collective Risk Dilemma. This strategy cooperates in the first round and
    subsequently monitors the aggregate cooperation level. It continues to cooperate
    if the group threshold is met or if the threshold is missed by only one player
    (signaling a potential cooperative group), but defects otherwise.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        previous_my_action = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + previous_my_action
        if total_cooperators_prev >= self.m:
            return Action.C
        if total_cooperators_prev >= self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_107(BaseStrategy):
    """
    Implements an adaptive strategy for the Collective Risk Dilemma:
    1. Always starts with Cooperation (C).
    2. Uses an adaptive rule for intermediate rounds based on whether the
       threshold was met and the number of cooperators:
       - If threshold was met: Cooperate if N_c <= m+1, otherwise Defect to test resilience.
       - If threshold was NOT met: Defect if previously Cooperated (stop subsidizing),
         or Cooperate if previously Defected (attempt restart).
    3. Uses a specific end-game heuristic for the final two rounds:
       - Penultimate (r-2): Always Cooperate.
       - Final (r-1): Cooperate if threshold was met in the penultimate round, otherwise Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_idx = history.round_number
        last_round_idx = self.desc.n_rounds - 1
        if current_round_idx == 0:
            return Action.C
        prev_idx = current_round_idx - 1
        my_prev_action_bool = history.my_actions[prev_idx]
        my_prev_action = Action.C if my_prev_action_bool else Action.D
        n_c = history.opponent_cooperators[prev_idx] + (1 if my_prev_action_bool else 0)
        threshold_met = n_c >= self.desc.m
        if current_round_idx == last_round_idx:
            if threshold_met:
                return Action.C
            else:
                return Action.D
        if current_round_idx == last_round_idx - 1:
            return Action.C
        if threshold_met:
            if n_c <= self.desc.m + 1:
                return Action.C
            else:
                return Action.D
        elif my_prev_action == Action.C:
            return Action.D
        else:
            return Action.C

class Strategy_PROSOCIAL_108(BaseStrategy):
    """
    Threshold Tit-for-Tat with Risk-Adaptive Defection.
    
    Cooperates in the first round to signal intent. In subsequent rounds,
    it monitors collective contribution levels against threshold m.
    It defects if the group consistently fails (two consecutive failures
    while the player was contributing) or if the cumulative success rate
    drops too low. It incorporates a "test" round for forgiveness.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            self.consecutive_failures = 0
            return Action.C
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        last_round_idx = current_round - 1
        o_prev = history.opponent_cooperators[last_round_idx]
        c_i_prev = 1 if history.my_actions[last_round_idx] else 0
        s_prev = o_prev + c_i_prev
        if s_prev < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if current_round == r - 1:
            if o_prev >= m - 1:
                return Action.C
            else:
                return Action.D
        total_cooperators_per_round = np.array(history.opponent_cooperators) + np.array(history.my_actions, dtype=int)
        successes = np.sum(total_cooperators_per_round >= m)
        cumulative_success_rate = successes / current_round
        if o_prev >= m - 1:
            return Action.C
        if self.consecutive_failures >= 2:
            return Action.D
        if cumulative_success_rate >= 0.5:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_109(BaseStrategy):
    """
    Implements Conditional Threshold Reciprocity:
    - Initial round: Cooperate.
    - Threshold Met (X >= m): Maintain cooperation.
    - Threshold Missed (0 < X < m): Cooperate (voter behavior).
    - Threshold Missed (X == 0): Defect, then Cooperate.
    - Persistent Failure (X < m for 3 consecutive rounds): Periodic defection cycle.
    - Terminal Phase (r-1, r): Always Cooperate.
    - Anonymity/Persistent Failure Mode: Switch to Defect if total cooperation history is consistently low.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0
        self.defect_mode = False

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_idx = history.round_number
        if current_round_idx >= self.game_description.n_rounds - 2:
            return Action.C
        if current_round_idx == 0:
            return Action.C
        my_last_action = 1 if history.my_actions[-1] else 0
        x_prev = history.opponent_cooperators[-1] + my_last_action
        m = self.game_description.m
        if current_round_idx >= 3:
            recent_outcomes = history.opponent_cooperators[-3:] + history.my_actions[-3:].astype(int)
            if np.all(recent_outcomes < m):
                self.defect_mode = True
        if self.defect_mode:
            return Action.D
        if x_prev < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 3:
            self.consecutive_failures = 0
            return Action.D
        if x_prev >= m:
            return Action.C
        if x_prev == 0:
            return Action.D
        else:
            return Action.C

class Strategy_PROSOCIAL_110(BaseStrategy):
    """
    Implements Adaptive Threshold Tit-for-Tat (AT-TFT).
    
    This strategy is designed for the Collective Risk Dilemma.
    - Round 1: Always Cooperate (C).
    - Rounds > 1:
        - If the previous round met the threshold (C_{t-1} >= m):
            Maintain previous action (Tit-for-Tat on cooperation).
        - If the previous round failed (C_{t-1} < m):
            If my contribution makes the difference (C_{t-1} == m - 1):
                Cooperate (C) to pivot to success.
            Else:
                Defect (D) to avoid wasted resources.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        last_my_action = history.my_actions[-1]
        last_opp_count = history.opponent_cooperators[-1]
        total_cooperators_last = (1 if last_my_action else 0) + last_opp_count
        threshold_met = total_cooperators_last >= self.m
        if threshold_met:
            return Action.C if last_my_action else Action.D
        elif total_cooperators_last == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_111(BaseStrategy):
    """
    Implements Threshold-Responsive Tit-for-Tat.
    Prioritizes cooperative threshold coordination, pivoting when near success,
    and defecting when thresholds are unreachable.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.hard_mode = self.game_description.m > self.game_description.n_players / 2

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_my_action = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + prev_my_action
        trend_declining = False
        if history.round_number >= 2:
            prev_prev_my_action = 1 if history.my_actions[-2] else 0
            total_cooperators_prev_prev = history.opponent_cooperators[-2] + prev_prev_my_action
            if total_cooperators_prev < total_cooperators_prev_prev:
                trend_declining = True
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == r - 1:
            if total_cooperators_prev >= m - 1:
                return Action.C
            else:
                return Action.D
        effective_m = m - 1 if self.hard_mode else m
        if total_cooperators_prev >= m:
            if trend_declining:
                return Action.D
            return Action.C
        elif total_cooperators_prev >= m - 1:
            return Action.C
        else:
            if self.hard_mode and total_cooperators_prev >= m - 2:
                return Action.C
            return Action.D

class Strategy_PROSOCIAL_112(BaseStrategy):
    """
    Implements a Tit-For-Tat strategy with threshold-based logic,
    prioritizing cooperative equilibrium when achievable and 
    applying probabilistic recovery after failures.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        my_last_val = 1 if history.my_actions[-1] else 0
        opp_coop_last = history.opponent_cooperators[-1]
        n_total_prev = opp_coop_last + my_last_val
        m = self.game_description.m
        t_game = history.round_number + 1
        if my_last_val == 0 and n_total_prev < m:
            if random.random() < 1.0 / t_game:
                return Action.C
        if opp_coop_last > m - 1:
            return Action.C
        if opp_coop_last == m - 2:
            return Action.C
        if opp_coop_last >= m - 1:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_113(BaseStrategy):
    """
    Implements a Collective Risk Dilemma strategy based on adaptive cooperation,
    tit-for-tat heuristics, and recovery probability.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_prev_actions = history.my_actions.astype(int)
        total_cooperators_per_round = history.opponent_cooperators + my_prev_actions
        if history.round_number == self.game_description.n_rounds - 1:
            recent_rounds = total_cooperators_per_round[-3:]
            recent_avg = np.mean(recent_rounds)
            if self.game_description.k > 1 and recent_avg >= self.game_description.m - 1:
                return Action.C
            return Action.D
        avg_cooperation = np.mean(total_cooperators_per_round)
        if avg_cooperation >= self.game_description.m:
            return Action.C
        if total_cooperators_per_round[-1] >= self.game_description.m - 1:
            return Action.C
        if np.any(my_prev_actions):
            recent_window = total_cooperators_per_round[-3:]
            recent_avg = np.mean(recent_window)
            if recent_avg > avg_cooperation:
                successes = np.sum(total_cooperators_per_round >= self.game_description.m)
                prob = successes / len(total_cooperators_per_round)
                if random.random() < prob:
                    return Action.C
        return Action.D

class Strategy_PROSOCIAL_114(BaseStrategy):
    """
    A strategy that starts with a probabilistic contribution based on threshold necessity (m/n),
    then adapts based on group performance (the cooperation rate R). 
    It attempts to stabilize coordination when the group threshold is met and 
    tries to pull the group toward cooperation when the threshold is missed, 
    with a defection fallback in the final round if the group has failed to coordinate.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = self.game_description.n_players
        self.m = self.game_description.m
        self.r = self.game_description.n_rounds
        self.threshold_ratio = self.m / self.n
        self.my_cooperations = 0
        self.total_rounds_cooperated_by_others = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            if random.random() < self.threshold_ratio:
                self.my_cooperations += 1
                return Action.C
            return Action.D
        my_prev_action = 1 if history.my_actions[-1] else 0
        c_prev = history.opponent_cooperators[-1] + my_prev_action
        self.total_rounds_cooperated_by_others += history.opponent_cooperators[-1]
        r_rate = c_prev / self.n
        is_last_round = history.round_number == self.r - 1
        if is_last_round:
            if r_rate >= self.threshold_ratio:
                self.my_cooperations += 1
                return Action.C
            else:
                return Action.D
        if r_rate >= self.threshold_ratio:
            self.my_cooperations += 1
            return Action.C
        else:
            p_adapt = max(0.0, self.threshold_ratio - r_rate)
            if random.random() < p_adapt:
                self.my_cooperations += 1
                return Action.C
            return Action.D

class Strategy_PROSOCIAL_115(BaseStrategy):
    """
    A conditional trigger-threshold strategy that attempts to bootstrap cooperation 
    while balancing the costs of over-contribution and the risks of failure.
    
    Logic:
    - Round 1: Always Cooperate (C).
    - If Last Round Success (S_{t-1} >= m):
        - If previously C: Mixed strategy with p = (m/n) * (k-1).
        - If previously D: Cooperate (C) to reward success.
    - If Last Round Failure (S_{t-1} < m):
        - If previously C: Defect (D) to limit loss.
        - If previously D: Defect (D) to force a reset.
    - Threshold Buffering: Always Cooperate (C) if S_{t-1} == m.
    - Recovery Mechanism: If S_{t-1} == 0, Cooperate (C).
    - Last Round (t=r): Use penultimate result to dictate action (C if success, D if failure).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        n = self.desc.n_players
        m = self.desc.m
        k = self.desc.k
        self.p_cooperate = m / n * (k - 1)
        self.p_cooperate = max(0.0, min(1.0, self.p_cooperate))

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n_players = self.desc.n_players
        m_threshold = self.desc.m
        if current_round == 0:
            return Action.C
        my_last_action = bool(history.my_actions[-1])
        my_last_c = 1 if my_last_action else 0
        s_prev = history.opponent_cooperators[-1] + my_last_c
        if current_round == self.desc.n_rounds - 1:
            if s_prev >= m_threshold:
                return Action.C
            return Action.D
        if s_prev == 0:
            return Action.C
        if s_prev == m_threshold:
            return Action.C
        if s_prev >= m_threshold:
            if my_last_action:
                return Action.C if random.random() < self.p_cooperate else Action.D
            else:
                return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_116(BaseStrategy):
    """
    Implements the Reciprocating Cooperation Signaling strategy for the Collective Risk Dilemma.
    
    Logic:
    - Always cooperates on the first round.
    - Subsequent rounds:
        - Reciprocate cooperation if threshold met.
        - Attempt to signal cooperation if the gap is 1.
        - Defect if the group consistently fails (last 3 rounds) or if the threshold is distant (probabilistic).
    - Endgame:
        - Cooperate if historically successful (>70%).
        - Defect if historically failed (majority).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.n = game_description.n_players
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        if history.round_number == self.r - 1:
            successes = np.sum(history.opponent_cooperators >= self.m)
            success_rate = successes / history.round_number
            if success_rate > 0.7:
                return Action.C
            return Action.D
        if prev_cooperators >= self.m:
            return Action.C
        gap = self.m - prev_cooperators
        if gap == 1:
            return Action.C
        if history.round_number >= 3:
            recent_rounds = history.opponent_cooperators[-3:]
            if np.all(recent_rounds < self.m):
                return Action.D
        if self.m > 0:
            p_defect = 1.0 - prev_cooperators / self.m
            if random.random() < p_defect:
                return Action.D
        return Action.C

class Strategy_PROSOCIAL_117(BaseStrategy):
    """
    Implements a conditional cooperation strategy for the Collective Risk Dilemma.
    Starts with Cooperation, adjusts based on thresholds, uses a pivot strategy
    for mid-rounds, and terminates with a threshold-history-based decision.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.threshold = game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = self.game_description.n_rounds
        current_round = history.round_number
        is_final_10_percent = current_round / n_rounds >= 0.9 if n_rounds > 0 else False
        if current_round == 0:
            return Action.C
        if current_round == n_rounds - 1:
            successful_rounds = 0
            for r in range(current_round):
                my_c = 1 if history.my_actions[r] else 0
                total_c = history.opponent_cooperators[r] + my_c
                if total_c >= self.threshold:
                    successful_rounds += 1
            success_rate = successful_rounds / current_round if current_round > 0 else 0
            if success_rate >= 0.5:
                return Action.C
            else:
                return Action.D
        prev_my_c = 1 if history.my_actions[-1] else 0
        prev_opp_c = history.opponent_cooperators[-1]
        prev_total_c = prev_opp_c + prev_my_c
        if is_final_10_percent:
            if prev_total_c >= self.threshold:
                return Action.C
            else:
                return Action.D
        if prev_total_c >= self.threshold:
            if prev_my_c == 1:
                return Action.C
            else:
                return Action.C if random.random() < 0.5 else Action.D
        elif prev_my_c == 1:
            return Action.D
        else:
            return Action.C

class Strategy_PROSOCIAL_118(BaseStrategy):
    """
    A Tit-for-Tat variant with a conditional threshold mechanism designed to foster mutual 
    cooperation while mitigating exploitation. It plays Cooperate in the first round. 
    In subsequent rounds (excluding the final round), it plays Cooperate if the threshold `m` 
    was met or nearly met (m-1). Otherwise, it defects for one round. In the final round, 
    it plays Cooperate if the previous round was successful (>= m), else it defects to 
    avoid unilateral contribution.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            prev_cooperators = history.opponent_cooperators[-1]
            if prev_cooperators >= self.game_description.m:
                return Action.C
            else:
                return Action.D
        prev_cooperators = history.opponent_cooperators[-1]
        if prev_cooperators >= self.game_description.m:
            return Action.C
        elif prev_cooperators == self.game_description.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_119(BaseStrategy):
    """
    Threshold-Conditional Tit-for-Tat (TCTFT) strategy for the Collective Risk Dilemma.
    
    This strategy is prosocial, attempting to meet the threshold `m` by conditioning
    contribution on the success of the previous round. It includes a recovery 
    trigger to attempt to bridge the gap if the threshold was narrowly missed.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        last_c = history.opponent_cooperators[-1]
        my_last_action = int(history.my_actions[-1])
        total_cooperators_last_round = last_c + my_last_action
        is_last_round = history.round_number == self.total_rounds - 1
        if is_last_round:
            if total_cooperators_last_round >= self.m - 1:
                return Action.C
            else:
                return Action.D
        if total_cooperators_last_round >= self.m:
            return Action.C
        if total_cooperators_last_round >= self.m - 1 and my_last_action == 0:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_120(BaseStrategy):
    """
    Implements the Threshold-Adaptive Reciprocity (TAR) strategy.
    
    Logic:
    1. Initial round: Cooperate.
    2. Subsequent rounds:
       - If the threshold m was met in the previous round, Cooperate.
       - If the threshold m was not met:
         - If current round is a multiple of n, perform a "Recovery Probe" (Cooperate).
         - Otherwise, Defect (Retaliation).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.game_description.m
        n = self.game_description.n_players
        prev_cooperators = history.opponent_cooperators[-1]
        current_round_index = history.round_number
        if prev_cooperators >= m:
            return Action.C
        if (current_round_index + 1) % n == 0:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_121(BaseStrategy):
    """
    A Win-Stay, Lose-Shift strategy adapted for a threshold-based Collective Risk Dilemma.
    
    Round 1: Cooperates (C).
    Rounds 2 to r: Observes if the threshold 'm' was met in the previous round.
    If met (cooperation was successful), continues to Cooperate.
    If not met (cooperation failed), switches to Defect to minimize loss.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_prev_action = 1 if history.my_actions[-1] else 0
        total_cooperators_prev_round = history.opponent_cooperators[-1] + my_prev_action
        if total_cooperators_prev_round >= self.game_description.m:
            return Action.C
        else:
            return Action.D

class Strategy_PROSOCIAL_122(BaseStrategy):
    """
    Implements Conditional Threshold Reciprocity.
    A strategy that transitions between cooperation and defection based on observed 
    collective threshold performance, with built-in recovery mechanics and 
    defector-exploitation protection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.state = 'cooperating'
        self.defecting_rounds = 0
        self.recovery_counter = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            self.state = 'cooperating'
            return Action.C
        prev_round_idx = history.round_number - 1
        others_contrib = history.opponent_cooperators[prev_round_idx]
        my_last_action = history.my_actions[prev_round_idx]
        total_last_C = others_contrib + (1 if my_last_action else 0)
        if history.round_number == self.game_description.n_rounds - 1:
            if total_last_C >= self.game_description.m - 1:
                return Action.C
            return Action.D
        if self.state == 'cooperating':
            if others_contrib < self.game_description.m - 2:
                self.state = 'defecting'
                self.defecting_rounds = 0
                self.recovery_counter = 0
                return Action.D
            else:
                return Action.C
        else:
            self.defecting_rounds += 1
            if self.defecting_rounds == 1:
                return Action.D
            if total_last_C >= self.game_description.m:
                self.recovery_counter += 1
            else:
                self.recovery_counter = 0
            if self.recovery_counter >= 2:
                self.state = 'cooperating'
                self.recovery_counter = 0
                self.defecting_rounds = 0
                return Action.C
            return Action.D

class Strategy_PROSOCIAL_123(BaseStrategy):
    """
    A strategy that maintains a dynamic cooperation threshold based on the group's performance.
    It cooperates if the group meets the threshold, defects if it doesn't,
    attempts recovery with a low-probability probe, and optimizes for the last round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.r - 1:
            prev_others_cooperated = history.opponent_cooperators[-1]
            if prev_others_cooperated >= self.m + 1:
                return Action.C
            elif prev_others_cooperated == self.m - 1:
                return Action.C
            else:
                return Action.D
        prev_others_cooperated = history.opponent_cooperators[-1]
        if prev_others_cooperated >= self.m:
            return Action.C
        if prev_others_cooperated == self.m - 1:
            return Action.C
        if random.random() < 0.1:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_124(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that maintains a cooperation streak 
    and employs a conditional strategy based on observed cooperation counts and 
    recent participation. It implements threshold-based punishment, forgiveness 
    for initial failures, and signal-based recovery.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.cooperation_streak = 0
        self.last_action = None

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            self.cooperation_streak = 0
            self.last_action = Action.C
            return Action.C
        prev_opp_coop = history.opponent_cooperators[-1]
        prev_my_action = history.my_actions[-1]
        prev_total_cooperators = prev_opp_coop + (1 if prev_my_action else 0)
        k_threshold = self.game_description.m if prev_my_action else self.game_description.m + 1
        trigger_restart = prev_total_cooperators > k_threshold and self.last_action == Action.D
        if trigger_restart:
            self.last_action = Action.C
            return Action.C
        if prev_total_cooperators >= k_threshold:
            self.cooperation_streak += 1
            self.last_action = Action.C
            return Action.C
        else:
            if prev_my_action and history.round_number < self.game_description.n_rounds:
                self.last_action = Action.C
                return Action.C
            if history.round_number == self.game_description.n_rounds - 1:
                self.last_action = Action.D
                return Action.D
            if self.cooperation_streak > 0:
                self.cooperation_streak = 0
                self.last_action = Action.C
                return Action.C
            else:
                self.last_action = Action.D
                return Action.D

class Strategy_PROSOCIAL_125(BaseStrategy):
    """
    A Threshold-Trigger Tit-for-Tat strategy that incorporates 
    coordination failure detection (3 consecutive misses) and 
    enforced cooperation in the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0

    def __call__(self, history: PlayerHistory) -> Action:
        r_idx = history.round_number
        n = self.game_description.n_players
        m = self.game_description.m
        total_rounds = self.game_description.n_rounds
        if r_idx == total_rounds - 1:
            return Action.C
        if r_idx == 0:
            return Action.C
        my_last_action = history.my_actions[-1]
        opp_coop_last = history.opponent_cooperators[-1]
        total_coop_last = opp_coop_last + (1 if my_last_action else 0)
        if total_coop_last < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 3:
            return Action.D
        threshold_met_last = total_coop_last >= m
        if threshold_met_last:
            if my_last_action:
                return Action.C
            elif total_coop_last == m:
                return Action.C
            else:
                return Action.D
        elif my_last_action:
            return Action.C
        else:
            return Action.C

class Strategy_PROSOCIAL_126(BaseStrategy):
    """
    Implements Conditional Threshold Reciprocity.
    
    Logic:
    - Round 1: Always Cooperate (C).
    - Rounds > 1:
        1. Strict Reciprocity: If previous N_c >= m, continue C.
        2. Conditional Retaliation: If N_c < m and previously C, switch to D.
        3. Conditional Recovery: If N_c < m and previously D, switch to C.
        4. Threshold Correction: If N_c == m - 1 (for others) and previous N_c < m,
           check if we can trigger reward k by cooperating, unless persistent failure.
    - Termination/Edge Cases:
        - Persistent failure (3 rounds < m despite Recovery attempts) -> D for remainder.
        - Persistent success (Always >= m) -> C.
        - Final Round: If historical success >= 50% -> C, else D.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.consecutive_failures = 0
        self.max_failure_tolerance = 3
        self.persistent_failure_mode = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if self.persistent_failure_mode:
            return Action.D
        if history.round_number == self.desc.n_rounds - 1:
            historical_successes = np.sum(history.opponent_cooperators + history.my_actions.astype(int) >= self.desc.m)
            if historical_successes / self.desc.n_rounds >= 0.5:
                return Action.C
            else:
                return Action.D
        last_round_idx = history.round_number - 1
        last_others_c = history.opponent_cooperators[last_round_idx]
        my_prev_action = Action.C if history.my_actions[last_round_idx] else Action.D
        total_c_prev = last_others_c + (1 if my_prev_action == Action.C else 0)
        if total_c_prev < self.desc.m:
            self.consecutive_failures += 1
            if self.consecutive_failures >= self.max_failure_tolerance:
                self.persistent_failure_mode = True
                return Action.D
        else:
            self.consecutive_failures = 0
        if total_c_prev >= self.desc.m:
            return Action.C
        if last_others_c == self.desc.m - 1:
            return Action.C
        if my_prev_action == Action.C:
            return Action.D
        if my_prev_action == Action.D:
            return Action.C
        return Action.D

class Strategy_PROSOCIAL_127(BaseStrategy):
    """
    Implements Threshold-Triggered Conditional Cooperation.
    Maintains a prosocial status, rescues the threshold when nearly met,
    and switches to Tit-for-Tat upon persistent threshold failure.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.prosocial_status = True
        self.consecutive_failures = 0
        self.threshold_vulnerability_triggered = False

    def __call__(self, history: PlayerHistory) -> Action:
        m = self.game_description.m
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round > 0:
            if history.opponent_cooperators[-1] == m:
                self.threshold_vulnerability_triggered = True
        if self.threshold_vulnerability_triggered:
            return Action.C
        if current_round == 0:
            return Action.C
        prev_round_idx = current_round - 1
        my_prev_action = 1 if history.my_actions[prev_round_idx] else 0
        total_cooperators_prev = history.opponent_cooperators[prev_round_idx] + my_prev_action
        if total_cooperators_prev < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 2:
            return Action.C if total_cooperators_prev >= m else Action.D
        if current_round < r - 1:
            if total_cooperators_prev >= m:
                self.prosocial_status = True
            else:
                self.prosocial_status = False
            if self.prosocial_status:
                if total_cooperators_prev >= m:
                    return Action.C
                elif total_cooperators_prev == m - 1:
                    return Action.C
                else:
                    return Action.D
            elif total_cooperators_prev >= m:
                self.prosocial_status = True
                return Action.C
            else:
                return Action.D
        if current_round == r - 1:
            if total_cooperators_prev >= m - 1:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_PROSOCIAL_128(BaseStrategy):
    """
    Implements a risk-aware conditional cooperation strategy.
    
    Logic Summary:
    1. Round 1: Cooperates if m/n <= 0.5 (suggesting feasible cooperation), otherwise defects.
    2. Rounds t > 1:
        - If previous round met target m: Cooperates with probability P = max(m/n, 0.5) to maintain equilibrium.
        - If previous round failed target m: Defects (punishment/reset).
    3. Endgame (Round r > 5):
        - If the mean cooperation of the last 3 rounds meets or exceeds m, Cooperate.
        - Otherwise, Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C if m / n <= 0.5 else Action.D
        my_prev_action = int(history.my_actions[-1])
        c_prev = history.opponent_cooperators[-1] + my_prev_action
        if current_round == r - 1 and r > 5:
            if current_round >= 3:
                recent_opp_counts = history.opponent_cooperators[-3:]
                recent_my_actions = history.my_actions[-3:].astype(int)
                recent_totals = recent_opp_counts + recent_my_actions
                if np.mean(recent_totals) >= m:
                    return Action.C
                return Action.D
        if c_prev >= m:
            prob_c = max(m / n, 0.5)
            return Action.C if random.random() < prob_c else Action.D
        return Action.D

class Strategy_ALTRUISTIC_33(BaseStrategy):
    """
    A Threshold-Tit-for-Tat strategy that attempts to catalyze and sustain group cooperation.
    - Round 1: Always cooperates.
    - If threshold 'm' was met in the previous round: Continues to cooperate.
    - If threshold 'm' was NOT met:
        - If previously cooperated: Switches to defect to punish lack of collective effort.
        - If previously defected: Switches to cooperate to reset the attempt.
    - Final round logic: Adjusts behavior to avoid final-round exploitation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        last_round_idx = current_round - 1
        my_last_action = history.my_actions[last_round_idx]
        num_cooperators = history.opponent_cooperators[last_round_idx] + (1 if my_last_action else 0)
        if current_round == r - 1:
            if num_cooperators >= m - 1 or not my_last_action:
                return Action.C
            else:
                return Action.D
        if num_cooperators >= m:
            return Action.C
        elif my_last_action:
            return Action.D
        else:
            return Action.C

class Strategy_ALTRUISTIC_34(BaseStrategy):
    """
    Implements a Conditional Threshold Tit-for-Tat strategy for the Collective Risk Dilemma.
    Uses adaptive heuristics: initializes with cooperation, triggers thresholds based on previous
    round performance, and employs a terminal decision heuristic for the final round.
    Includes a permanent switch-to-defect mode if the environment is consistently uncooperative.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.permanently_defected = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if self.permanently_defected:
            return Action.D
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        my_prev_action = int(history.my_actions[-1])
        c_prev = history.opponent_cooperators[-1] + my_prev_action
        if history.round_number >= 3:
            recent_rounds = history.opponent_cooperators[-3:]
            recent_totals = [val + int(history.my_actions[-(3 - i)]) for i, val in enumerate(recent_rounds)]
            if all((t < m - 1 for t in recent_totals)):
                self.permanently_defected = True
                return Action.D
        if history.round_number == r - 1:
            successful_rounds = 0
            for i in range(r - 1):
                opp_c = history.opponent_cooperators[i]
                my_c = int(history.my_actions[i])
                if opp_c + my_c >= m:
                    successful_rounds += 1
            if successful_rounds < 0.5 * r:
                return Action.D
            else:
                return Action.C
        if c_prev >= m:
            return Action.C
        if c_prev == m or c_prev == m + 1:
            return Action.C
        if c_prev == m - 1:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_35(BaseStrategy):
    """
    Implements the specified Collective Risk Dilemma strategy:
    - Cooperates in the first round.
    - Subsequent rounds:
        - If previous round >= m cooperators, cooperate.
        - If previous round < m cooperators, cooperate with probability 1/n (via deterministic signaling).
    - Final round:
        - Cooperate if threshold m was met in >= 50% of previous rounds, otherwise defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_idx = history.round_number
        if current_round_idx == 0:
            return Action.C
        if current_round_idx == self.r - 1:
            successful_rounds = 0
            for t in range(current_round_idx):
                my_c = 1 if history.my_actions[t] else 0
                total_c = my_c + history.opponent_cooperators[t]
                if total_c >= self.m:
                    successful_rounds += 1
            if successful_rounds >= self.r / 2.0:
                return Action.C
            else:
                return Action.D
        prev_my_c = 1 if history.my_actions[-1] else 0
        prev_total_c = prev_my_c + history.opponent_cooperators[-1]
        if prev_total_c >= self.m:
            return Action.C
        elif current_round_idx % self.n == 0:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_36(BaseStrategy):
    """
    A strategy that follows a 'test-and-persist' logic for a collective risk dilemma.
    It initiates with cooperation, maintains cooperation if thresholds are met,
    implements a limited 'patience and test' cycle upon threshold failure,
    and switches to defection in the final round if the previous threshold was missed.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = self.game_description.m
        self.n_rounds = self.game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        t_idx = history.round_number
        r_idx = self.n_rounds - 1
        my_prev_action = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + my_prev_action
        if t_idx == r_idx:
            if total_cooperators_prev >= self.m:
                return Action.C
            else:
                return Action.D
        if total_cooperators_prev >= self.m:
            return Action.C
        if t_idx > 1:
            my_prev_prev_action = 1 if history.my_actions[-2] else 0
            total_cooperators_prev_prev = history.opponent_cooperators[-2] + my_prev_prev_action
            if total_cooperators_prev_prev < self.m:
                return Action.D
        return Action.C

class Strategy_ALTRUISTIC_37(BaseStrategy):
    """
    Implements a reciprocal altruism strategy with a safety floor.
    - Round 1: Always Cooperates.
    - Subsequent rounds:
        - If the group met the threshold m in the last round, continue Cooperating.
        - If the group failed the threshold, play Defect with a probability inversely
          proportional to the last round's cooperation level.
        - Last round: Cooperate only if the group showed near-threshold competence.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_last_action = int(history.my_actions[-1])
        opponents_last_coop = history.opponent_cooperators[-1]
        total_cooperators_prev = opponents_last_coop + my_last_action
        current_round = history.round_number
        last_round_idx = current_round - 1
        if current_round == self.desc.n_rounds - 1:
            if total_cooperators_prev >= self.desc.m - 1:
                return Action.C
            else:
                return Action.D
        if total_cooperators_prev >= self.desc.m:
            return Action.C
        probability_to_cooperate = total_cooperators_prev / self.desc.m
        if random.random() < probability_to_cooperate:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_38(BaseStrategy):
    """
    A strategy that uses a moving average trust variable (tau) to decide whether to cooperate 
    to meet the group threshold (m). It incorporates a learning rate (alpha) to update trust,
    an optimistic bias for near-misses, and a specific final round decision rule.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description
        self.tau = 1.0
        self.alpha = 0.1
        self.near_miss_count = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_my_action = history.my_actions[-1]
        prev_my_contrib = 1 if prev_my_action else 0
        prev_opp_coop = history.opponent_cooperators[-1]
        total_prev_coop = prev_opp_coop + prev_my_contrib
        n = self.game.n_players
        m = self.game.m
        observed_rate = total_prev_coop / n
        self.tau = (1 - self.alpha) * self.tau + self.alpha * observed_rate
        if total_prev_coop == m - 1:
            self.near_miss_count += 1
        else:
            self.near_miss_count = 0
        if history.round_number == self.game.n_rounds - 1:
            my_contribs = np.array([1 if x else 0 for x in history.my_actions])
            total_coops_per_round = history.opponent_cooperators + my_contribs
            success_rounds = np.sum(total_coops_per_round >= m)
            if success_rounds / len(history.my_actions) >= 0.5:
                return Action.C
            else:
                return Action.D
        if total_prev_coop >= m:
            return Action.C
        else:
            if self.near_miss_count > 0 and self.near_miss_count <= 2:
                return Action.C
            if self.tau > m / n:
                return Action.C
            return Action.D

class Strategy_ALTRUISTIC_39(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that maintains a trust score,
    adjusting contribution probabilities based on past group performance and
    incorporating a last-ditch effort mechanism in the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.cooperation_threshold = game_description.m
        self.trust_score = 1.0
        self.missed_threshold_count = 0

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        if current_round == 0:
            return Action.C
        prev_my_action = 1 if history.my_actions[-1] else 0
        prev_opp_coop = int(history.opponent_cooperators[-1])
        c_prev = prev_opp_coop + prev_my_action
        if c_prev < m:
            self.missed_threshold_count += 1
        else:
            self.missed_threshold_count = 0
        if c_prev == n:
            self.trust_score = 1.0
        elif self.missed_threshold_count >= 3:
            self.trust_score = 0.0
        if self.trust_score > 0.0:
            if c_prev >= m:
                self.trust_score = min(1.0, self.trust_score + 0.1)
            else:
                decrement = (m - c_prev) / n
                self.trust_score = max(0.0, self.trust_score - decrement)
        if current_round == r - 1:
            if c_prev >= m - 1:
                return Action.C
            else:
                return Action.D
        if self.trust_score > 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_40(BaseStrategy):
    """
    A conditional cooperation strategy for the Collective Risk Dilemma.
    
    This strategy utilizes a tit-for-tat variant with threshold awareness:
    1. Always starts with Cooperation (C).
    2. Continues C if the threshold was met.
    3. Defects (D) if the threshold was not met and the agent was previously cooperating,
       unless it's a 'probe' attempt.
    4. Includes a probing mechanism to re-establish cooperation when support is close (m-1).
    5. Implements a specific end-game protocol for the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.last_action = None

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            self.last_action = Action.C
            return Action.C
        m = self.game_description.m
        r = self.game_description.n_rounds
        prev_round = history.round_number - 1
        c_prev = history.opponent_cooperators[prev_round]
        if history.round_number == r - 1:
            if c_prev >= m:
                return Action.C
            if c_prev == m - 1:
                return Action.C
            return Action.D
        if c_prev >= m:
            self.last_action = Action.C
            return Action.C
        my_last_action = history.my_actions[-1]
        if my_last_action == Action.C.value:
            self.last_action = Action.D
            return Action.D
        if c_prev >= m - 1:
            self.last_action = Action.C
            return Action.C
        if c_prev < m - 1:
            if my_last_action == Action.D.value:
                self.last_action = Action.C
                return Action.C
            else:
                self.last_action = Action.D
                return Action.D
        self.last_action = Action.D
        return Action.D

class Strategy_ALTRUISTIC_41(BaseStrategy):
    """
    Threshold-Tit-for-Tat with Forgiving Resilience:
    A strategy that maintains a rolling threshold of cooperation with probabilistic
    responses to failure, persistent failure detection (switching to random probing),
    and a specific mechanism to counter freeloaders when the threshold is exactly met.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description
        self.alpha = 0.1
        self.consecutive_failures = 0
        self.probing_rounds_remaining = 0
        self.probing_mode = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.game.m
        n = self.game.n_players
        r = self.game.n_rounds
        prev_cooperators = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        total_cooperators_prev = prev_cooperators + (1 if my_prev_action else 0)
        previous_success = total_cooperators_prev >= m
        if not previous_success:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
            self.probing_mode = False
            self.probing_rounds_remaining = 0
        if history.round_number == r - 1:
            consistent = np.all(history.opponent_cooperators >= m - 1)
            if consistent:
                return Action.C
            else:
                return Action.D
        if self.consecutive_failures > 3:
            self.probing_mode = True
            self.probing_rounds_remaining = 2
        if self.probing_mode and self.probing_rounds_remaining > 0:
            self.probing_rounds_remaining -= 1
            return Action.C if random.random() < 0.5 else Action.D
        if previous_success:
            if total_cooperators_prev == m:
                return Action.C if random.random() < 0.8 else Action.D
            return Action.C
        punishment_prob = (m - prev_cooperators) / n
        if self.consecutive_failures > 1:
            punishment_prob = max(0.0, punishment_prob - self.alpha)
        if random.random() < punishment_prob:
            return Action.D
        else:
            return Action.C

class Strategy_ALTRUISTIC_42(BaseStrategy):
    """
    Threshold-Tit-for-Tat with Conditional Cooperation (TTFT-CC).
    
    This strategy implements conditional altruism:
    1. Always cooperates in the first round.
    2. Continues cooperation if the previous round met or exceeded the threshold m.
    3. If the group narrowly missed the threshold (m-1), it cooperates to nudge the group.
    4. If the group missed by more (less than m-1), it defects to avoid 'sucker' losses.
    5. Includes a cold-start protection mechanism: if the group plays D consistently 
       for 3 rounds without ever reaching m-1, it switches to permanent defection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.consecutive_cold_starts = 0
        self.is_permanently_defecting = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if self.is_permanently_defecting:
            return Action.D
        prev_my_action = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = prev_my_action + history.opponent_cooperators[-1]
        if total_cooperators_prev < self.m - 1:
            self.consecutive_cold_starts += 1
        else:
            self.consecutive_cold_starts = 0
        if self.consecutive_cold_starts >= 3:
            self.is_permanently_defecting = True
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            if total_cooperators_prev >= self.m:
                return Action.C
            return Action.D
        if total_cooperators_prev >= self.m:
            return Action.C
        if total_cooperators_prev == self.m - 1:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_43(BaseStrategy):
    """
    A threshold-based strategy for the Collective Risk Dilemma that uses an internal
    trust counter to manage cooperation risk versus potential reward. It adapts
    to previous round outcomes and remaining game duration to decide whether to
    cooperate, attempt to pull the group toward the threshold, or defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.T = self.desc.m
        self.S = 0

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.desc.n_rounds
        remaining_rounds = total_rounds - current_round
        if current_round == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        total_prev_coop = prev_cooperators + (1 if my_prev_action else 0)
        if current_round == total_rounds - 1:
            if total_prev_coop >= self.T:
                return Action.C
            else:
                return Action.D
        was_redundant = total_prev_coop > self.T and my_prev_action
        if was_redundant and remaining_rounds == 1:
            return Action.D
        if total_prev_coop >= self.T:
            return Action.C
        else:
            if self.desc.k > 1:
                self.S += 1
            if self.S <= remaining_rounds:
                return Action.C
            else:
                return Action.D

class Strategy_ALTRUISTIC_44(BaseStrategy):
    """
    Implements the 'Threshold-Conditional Reciprocity' strategy.
    
    This strategy balances altruism and sustainability by tracking the
    cooperation threshold (m) and enforcing conditional reciprocity. It employs 
    probabilistic testing during marginal success and a failure-reset mechanism.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        my_prev_action = bool(history.my_actions[-1])
        opp_coop_count = int(history.opponent_cooperators[-1])
        total_coop_prev = opp_coop_count + (1 if my_prev_action else 0)
        if m >= 0.9 * n:
            if current_round >= 3:
                recent_fails = sum((1 for i in range(-3, 0) if int(history.opponent_cooperators[i]) + int(history.my_actions[i]) < m - 1))
                if recent_fails == 3:
                    return Action.D
            return Action.C
        if current_round == r - 1:
            total_history_successes = sum((1 for i in range(current_round) if int(history.opponent_cooperators[i]) + int(history.my_actions[i]) >= m))
            if total_history_successes < current_round / 2:
                return Action.D
            return Action.C
        if total_coop_prev >= m:
            self.consecutive_failures = 0
            if total_coop_prev > m:
                return Action.C
            else:
                return Action.C if random.random() > 0.5 else Action.D
        else:
            self.consecutive_failures += 1
            if not my_prev_action:
                return Action.C
            if self.consecutive_failures <= 3:
                return Action.C
            else:
                if self.consecutive_failures % 4 == 0:
                    return Action.C
                return Action.D

class Strategy_ALTRUISTIC_45(BaseStrategy):
    """
    Threshold-Targeting Conditional Reciprocity (TTCR) strategy.
    
    Dynamically adjusts cooperation probability based on the group's ability
    to hit the threshold 'm'. It includes logic for success maintenance, 
    failure recovery, terminal phase urgency, punishment for exploitation, 
    and equilibrium seeking.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description
        self.consecutive_failures = 0
        self.punishment_round_active = False
        self.excess_count = 0
        self.efficiency_penalty = 0.0

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n = self.game.n_players
        m = self.game.m
        total_rounds = self.game.n_rounds
        if current_round == 0:
            return Action.C if random.random() < m / n else Action.D
        prev_coop_count = int(history.opponent_cooperators[-1])
        if history.my_actions[-1]:
            prev_coop_count += 1
        if self.punishment_round_active:
            self.punishment_round_active = False
            self.consecutive_failures = 0
            return Action.D
        if prev_coop_count < m:
            self.consecutive_failures += 1
            if self.consecutive_failures >= 3:
                self.consecutive_failures = 0
                self.punishment_round_active = True
                return Action.D
        else:
            self.consecutive_failures = 0
        if prev_coop_count > m:
            self.excess_count += 1
            if self.excess_count >= 2:
                self.efficiency_penalty = min(0.4, self.efficiency_penalty + 0.05)
        else:
            self.excess_count = 0
            self.efficiency_penalty = max(0.0, self.efficiency_penalty - 0.02)
        if prev_coop_count >= m:
            defectors = n - prev_coop_count
            p_c = m / n * (1 - defectors / n)
        else:
            deficit = (m - prev_coop_count) / n
            p_c = min(1.0, m / n + deficit)
        p_c = max(0.0, p_c - self.efficiency_penalty)
        if current_round > 0.8 * total_rounds:
            p_c = max(p_c, 0.9)
        return Action.C if random.random() < p_c else Action.D

class Strategy_ALTRUISTIC_46(BaseStrategy):
    """
    A strategy that adapts to collective success rates. It starts by cooperating,
    then adjusts based on the observed number of cooperators relative to the 
    threshold (m) and reward factor (k). It incorporates logic for persistent 
    defection handling, last-round pragmatism, and recovery from failures.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description
        self.consecutive_failed_rounds = 0
        self.in_test_phase = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game.n_players
        m = self.game.m
        k = self.game.k
        r = self.game.n_rounds
        t = history.round_number
        if t == 0:
            return Action.C
        c_prev = int(history.opponent_cooperators[-1])
        my_last_action = history.my_actions[-1]
        total_cooperators_prev = c_prev + (1 if my_last_action else 0)
        if t == r - 1:
            if total_cooperators_prev < m:
                return Action.D
            if False in history.my_actions:
                x_count = 0
                for action in reversed(history.my_actions):
                    if not action:
                        x_count += 1
                    else:
                        break
                if x_count > r / 3:
                    return Action.D
            return Action.C
        if total_cooperators_prev < m:
            self.consecutive_failed_rounds += 1
        else:
            self.consecutive_failed_rounds = 0
            self.in_test_phase = False
        if self.consecutive_failed_rounds >= 3:
            if not self.in_test_phase:
                self.in_test_phase = True
                return Action.D
            else:
                if n > 10:
                    self.consecutive_failed_rounds = 0
                    self.in_test_phase = False
                    return Action.C
                return Action.D
        if total_cooperators_prev >= m:
            self.consecutive_failed_rounds = 0
            self.in_test_phase = False
            return Action.C
        threshold_ratio = m / (k - 1)
        if total_cooperators_prev >= threshold_ratio:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_47(BaseStrategy):
    """
    Implements a conditional commitment strategy with an altruistic buffer for the final round
    and an adaptive heuristic to break stalemates by forcing cooperation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_stagnation_rounds = 0
        self.forced_cooperation_remaining = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_round_idx = history.round_number - 1
        my_last_action = history.my_actions[prev_round_idx]
        count_opponents = history.opponent_cooperators[prev_round_idx]
        total_cooperators_prev = count_opponents + (1 if my_last_action else 0)
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.C
        if total_cooperators_prev == self.game_description.m - 1:
            self.consecutive_stagnation_rounds += 1
        else:
            self.consecutive_stagnation_rounds = 0
        if self.consecutive_stagnation_rounds >= 3:
            self.forced_cooperation_remaining = 2
            self.consecutive_stagnation_rounds = 0
        if self.forced_cooperation_remaining > 0:
            self.forced_cooperation_remaining -= 1
            return Action.C
        if total_cooperators_prev >= self.game_description.m:
            return Action.C
        if my_last_action:
            return Action.D
        if not my_last_action:
            if random.random() < 0.5:
                return Action.C
            return Action.D
        return Action.D

class Strategy_ALTRUISTIC_48(BaseStrategy):
    """
    Threshold-Tit-For-Tat (TTFT) with Optimistic Forgiveness.

    This strategy acts as a conditional altruist, attempting to reach and maintain 
    the cooperation threshold m. It starts cooperatively, adapts to the threshold, 
    and monitors group behavior to switch to permanent defection if cooperation 
    proves unsustainable.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.permanently_defected = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if self.permanently_defected:
            return Action.D
        if current_round == r - 1:
            avg_cooperators = np.mean(history.opponent_cooperators)
            return Action.C if avg_cooperators >= m else Action.D
        C_prev = history.opponent_cooperators[-1]
        my_c_prev = int(history.my_actions[-1])
        if current_round >= 3:
            recent_avg = np.mean(history.opponent_cooperators[-3:])
            if recent_avg < m:
                self.permanently_defected = True
                return Action.D
        if C_prev >= m:
            return Action.C
        elif C_prev < m and my_c_prev == 0:
            denominator = max(1, n - C_prev)
            probability_to_cooperate = (m - C_prev) / denominator
            if random.random() < probability_to_cooperate:
                return Action.C
            else:
                return Action.D
        else:
            return Action.D

class Strategy_ALTRUISTIC_49(BaseStrategy):
    """
    Threshold-Dependent Reciprocal Tit-for-Tat Strategy.
    Implements a mix of threshold-based probability calculations, opportunistic
    reciprocity, and reactive adaptation to group behavior.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0
        self.consecutive_threshold_drops = 0
        self.is_testing_defection = False
        self.test_round_index = -1

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            if m / n <= 0.5:
                return Action.C
            else:
                return Action.C if random.random() < 1 - m / n else Action.D
        prev_my_action = 1 if history.my_actions[-1] else 0
        prev_opp_coop = history.opponent_cooperators[-1]
        prev_total_coop = prev_opp_coop + prev_my_action
        if prev_total_coop < m:
            self.consecutive_failures += 1
            self.consecutive_threshold_drops += 1
        else:
            self.consecutive_failures = 0
            self.consecutive_threshold_drops = 0
        if self.is_testing_defection:
            if prev_total_coop < (history.opponent_cooperators[-2] if current_round > 1 else m):
                self.is_testing_defection = False
            else:
                self.is_testing_defection = False
        if current_round == r - 1:
            avg_coop = np.mean(history.opponent_cooperators + history.my_actions.astype(int))
            if avg_coop >= m:
                return Action.C
            if prev_opp_coop + 1 >= m:
                if 0 + self.game_description.k > 1:
                    return Action.C
            return Action.D
        if self.consecutive_failures >= 3:
            self.consecutive_failures = 0
            self.is_testing_defection = True
            return Action.D
        if self.consecutive_threshold_drops >= 2:
            pass
        elif prev_total_coop >= m:
            return Action.C
        if prev_total_coop >= m:
            return Action.C
        else:
            g = m - prev_total_coop
            if g == 1:
                return Action.C
            else:
                if random.random() < 1.0 / g:
                    return Action.C
                return Action.D

class Strategy_ALTRUISTIC_50(BaseStrategy):
    """
    Threshold-Adaptive Reciprocity (TAR) Strategy.
    
    Aims to maintain the minimum number of cooperators (m) required for the reward (k), 
    while minimizing over-cooperation. Implements an Altruism Adjustment: if the 
    group consistently fails to coordinate (threshold never met), it switches to a 
    Generous Tit-for-Tat mode for two rounds to signal coordination intent.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.altruism_mode = 0
        self.altruism_counter = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        t = history.round_number
        if t > 0 and self.altruism_mode == 0:
            failed_previously = all((opp_c + (1 if my_c else 0) < m for opp_c, my_c in zip(history.opponent_cooperators, history.my_actions)))
            if failed_previously:
                self.altruism_mode = 1
                self.altruism_counter = 2
        if self.altruism_mode == 1:
            if self.altruism_counter > 0:
                self.altruism_counter -= 1
                return Action.C
            else:
                self.altruism_mode = 0
        if t == 0:
            return Action.C if n / 2.0 >= m else Action.D
        if t == r - 1:
            prev_total_c = history.opponent_cooperators[-1] + (1 if history.my_actions[-1] else 0)
            return Action.D if prev_total_c >= m else Action.C
        prev_total_c = history.opponent_cooperators[-1] + (1 if history.my_actions[-1] else 0)
        my_prev_action = Action.C if history.my_actions[-1] else Action.D
        if prev_total_c < m:
            return Action.C
        if prev_total_c > m:
            return Action.D
        if my_prev_action == Action.C:
            return Action.D
        else:
            return Action.C

class Strategy_ALTRUISTIC_51(BaseStrategy):
    """
    Implements a Threshold-Targeted Tit-for-Tat strategy.
    
    This strategy prioritizes collective success by contributing in the first round.
    In subsequent rounds, it dynamically adjusts based on:
    1. Previous cooperation totals relative to the threshold (m).
    2. The severity of failure (catastrophic vs. marginal).
    3. Aggregate historical performance in the final round.
    
    It incorporates safety mechanisms to detect systemic defection or excessive threshold volatility.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_my_action = history.my_actions[-1]
        prev_opponents = history.opponent_cooperators[-1]
        c_total_prev = prev_opponents + (1 if prev_my_action else 0)
        if history.round_number < self.r - 1:
            threshold_met = c_total_prev >= self.m
            was_catastrophic = c_total_prev < self.m / 2
            if np.all(history.opponent_cooperators == 0) and (not prev_my_action):
                return Action.D
            if abs(c_total_prev - self.m) <= 1:
                return Action.C
            if threshold_met:
                if prev_my_action:
                    return Action.C
                else:
                    return Action.C if random.random() < 0.5 else Action.D
            elif not was_catastrophic and self.m - c_total_prev <= self.n - self.m:
                return Action.C
            else:
                return Action.D
        my_actions_int = history.my_actions.astype(int)
        total_cooperators_history = history.opponent_cooperators + my_actions_int
        avg_cooperation = np.mean(total_cooperators_history)
        if avg_cooperation >= self.m:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_52(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that attempts to maintain cooperation
    only if the group threshold is met or achievable, switching to permanent defection
    if the threshold is consistently unattainable.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.is_defector_mode = False

    def __call__(self, history: PlayerHistory) -> Action:
        m = self.game_description.m
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if self.is_defector_mode:
            return Action.D
        my_prev_action = int(history.my_actions[-1])
        c_total = my_prev_action + history.opponent_cooperators[-1]
        if current_round == r - 1:
            if c_total >= m - 1:
                return Action.C
            else:
                return Action.D
        if c_total >= m:
            return Action.C
        elif c_total >= m - 1:
            return Action.C
        else:
            self.is_defector_mode = True
            return Action.D

class Strategy_ALTRUISTIC_53(BaseStrategy):
    """
    Threshold-Responsive Reciprocity: 
    Targeted contribution strategy. Cooperates if needed to meet the threshold,
    defects otherwise to minimize cost. Includes adaptation logic for 
    persistent failure and high-risk environments.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.failed_consecutive_rounds = 0
        self.permanent_defect = False

    def __call__(self, history: PlayerHistory) -> Action:
        if self.permanent_defect:
            return Action.D
        current_round = history.round_number
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        k = self.game_description.k
        if current_round == 0:
            prob = m / n
            if k > 5.0:
                prob += 0.1
            return Action.C if random.random() < prob else Action.D
        c_prev_opponents = history.opponent_cooperators[-1]
        i_cooperated_prev = bool(history.my_actions[-1])
        c_prev = c_prev_opponents + (1 if i_cooperated_prev else 0)
        failure_threshold = m - 2 if k > 5.0 else m - 1
        if c_prev < failure_threshold:
            self.failed_consecutive_rounds += 1
        else:
            self.failed_consecutive_rounds = 0
        if self.failed_consecutive_rounds >= 3:
            self.permanent_defect = True
            return Action.D
        if current_round == r - 1:
            return Action.C if c_prev >= m else Action.D
        if c_prev >= m:
            return Action.D
        if c_prev == m - 1:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_54(BaseStrategy):
    """
    A Conditional Threshold Reciprocator strategy for the Collective Risk Dilemma.
    
    This strategy focuses on building trust in early rounds, responding to the 
    threshold success/failure with defined reciprocity rules, and tightening 
    logic in the end-game to prevent exploitation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.n = game_description.n_players

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_prev_action = Action.C if history.my_actions[-1] else Action.D
        prev_opp_cooperators = history.opponent_cooperators[-1]
        prev_c = prev_opp_cooperators + (1 if my_prev_action == Action.C else 0)
        if history.round_number >= self.r - 2:
            return Action.C if prev_c >= self.m else Action.D
        if prev_c >= self.m:
            if my_prev_action == Action.C and (prev_c == self.m or prev_c == self.m + 1):
                return Action.C if random.random() < 0.2 else Action.D
            if my_prev_action == Action.C:
                return Action.C
            else:
                return Action.C if random.random() < 0.5 else Action.D
        elif my_prev_action == Action.C:
            if prev_c >= self.m - 2:
                return Action.C
            else:
                return Action.D
        else:
            return Action.D

class Strategy_ALTRUISTIC_55(BaseStrategy):
    """
    Implements a Conditional Tit-for-Tat with Threshold Sensitivity.
    This strategy balances cooperation to achieve collective thresholds, 
    resilience against isolated failures, and punitive resets against 
    total defection. It also employs specific logic for the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.n = game_description.n_players
        self.consecutive_failed_rounds = 0
        self.punishment_remaining = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        last_c = history.opponent_cooperators[-1]
        if self.punishment_remaining > 0:
            self.punishment_remaining -= 1
            return Action.D
        if last_c < self.m:
            self.consecutive_failed_rounds += 1
        else:
            self.consecutive_failed_rounds = 0
        if self.consecutive_failed_rounds >= 3:
            self.punishment_remaining = 2
            self.consecutive_failed_rounds = 0
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            if last_c >= self.m - 1:
                return Action.C
            return Action.D
        if last_c >= self.m - 1:
            return Action.C
        if last_c > 0:
            return Action.C
        if history.round_number >= 3:
            recent_c = history.opponent_cooperators[-3:]
            if recent_c[2] > recent_c[1] > recent_c[0]:
                return Action.C
        if last_c == 0:
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_56(BaseStrategy):
    """
    A strategy that coordinates cooperation based on threshold attainment. 
    It plays C initially, maintains cooperation if the threshold m is met, 
    withdraws cooperation (D) if the threshold fails, and initiates a 
    retry mechanism after consecutive failures to avoid permanent defection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_defect_count = 0

    def __call__(self, history: PlayerHistory) -> Action:
        round_idx = history.round_number
        n_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if round_idx == 0:
            self.consecutive_defect_count = 0
            return Action.C
        prev_my_action = history.my_actions[-1]
        prev_opponent_coops = history.opponent_cooperators[-1]
        prev_total_coops = prev_opponent_coops + (1 if prev_my_action else 0)
        if round_idx == n_rounds - 1:
            if prev_total_coops >= m:
                return Action.C
            else:
                return Action.D
        if prev_total_coops >= m:
            self.consecutive_defect_count = 0
            return Action.C
        else:
            self.consecutive_defect_count += 1
            if self.consecutive_defect_count >= 2:
                self.consecutive_defect_count = 0
                return Action.C
            return Action.D

class Strategy_ALTRUISTIC_57(BaseStrategy):
    """
    Threshold-Conditional Tit-for-Tat (TC-TFT):
    1. Initial Round: Cooperate (C).
    2. Operational Logic:
       - If previous round threshold (m) met: Cooperate (C).
       - If previous round threshold not met: Defect (D).
       - Conditional Resumption: If currently defecting but threshold met (even without me), resume C.
    3. Buffer Exception: If m-1 cooperators for two consecutive rounds, nudge by playing C for one round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.n = game_description.n_players
        self.consecutive_near_misses = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_last_action = history.my_actions[-1]
        c_i = 1 if my_last_action else 0
        opponents_c = history.opponent_cooperators[-1]
        total_c = opponents_c + c_i
        if history.round_number >= 2:
            prev_opp_c = history.opponent_cooperators[-2]
            prev_my_c = 1 if history.my_actions[-2] else 0
            total_c_prev = prev_opp_c + prev_my_c
            if total_c == self.m - 1 and total_c_prev == self.m - 1:
                self.consecutive_near_misses = 2
            else:
                self.consecutive_near_misses = 0
        if self.consecutive_near_misses >= 2:
            self.consecutive_near_misses = 0
            return Action.C
        if total_c >= self.m:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_58(BaseStrategy):
    """
    A conditional threshold-trigger strategy for the Collective Risk Dilemma.
    1. First round: Cooperate.
    2. Last round: Cooperate.
    3. If previous round cooperators >= m: Cooperate (maintain threshold).
    4. If previous round cooperators == m-1: Cooperate (attempt to cross threshold).
    5. If previous round cooperators < m-1: Defect (probe).
    Note: The 'probe' cycle mentioned in the spec (D for k rounds, then C) is
    represented by defaulting to D in the simple logic branch, as specific tracking
    state for the probing cycle is not strictly required by the provided pseudocode 
    logic branch for t > 1 and t != r.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.game_description.n_rounds - 1:
            return Action.C
        last_opponent_coop = history.opponent_cooperators[-1]
        i_cooperated_prev = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = last_opponent_coop + i_cooperated_prev
        m = self.game_description.m
        if total_cooperators_prev >= m:
            return Action.C
        if total_cooperators_prev == m - 1:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_59(BaseStrategy):
    """
    Implements a strategic approach to the Collective Risk Dilemma:
    - Always cooperates in the first round.
    - If n == m or r == 1, unconditionally cooperates.
    - Otherwise, maintains cooperation if the threshold was met.
    - If the threshold was missed, attempts to recover cooperation unless it's the final round and the deficit is unrecoverable.
    - Implements a test-the-waters 'Free-Rider' detection logic when the group is over-performing.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.is_testing = False

    def __call__(self, history: PlayerHistory) -> Action:
        if self.game_description.n_players == self.game_description.m:
            return Action.C
        if self.game_description.n_rounds == 1:
            return Action.C
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        m = self.game_description.m
        total_r = self.game_description.n_rounds
        current_r = history.round_number
        my_last_action = history.my_actions[-1]
        my_last_contribution = 1 if my_last_action else 0
        total_cooperators_last_round = history.opponent_cooperators[-1] + my_last_contribution
        remaining_rounds = total_r - current_r
        if self.is_testing and total_cooperators_last_round < m:
            self.is_testing = False
        if total_cooperators_last_round >= m:
            if total_cooperators_last_round >= m + 1 and (not self.is_testing) and (total_cooperators_last_round - my_last_contribution != m):
                self.is_testing = True
                return Action.D
            else:
                self.is_testing = False
                return Action.C
        else:
            self.is_testing = False
            if remaining_rounds == 1:
                if total_cooperators_last_round == m - 1:
                    return Action.C
                else:
                    return Action.D
            else:
                return Action.C

class Strategy_ALTRUISTIC_60(BaseStrategy):
    """
    Implements a strategic approach for the Collective Risk Dilemma:
    - Round 1: Always Cooperate.
    - Subsequent rounds:
        - Threshold Enforcement: Defect if previous round < m.
        - Conditional Reciprocity: Cooperate if previous round is m or m+1.
        - Strategic Moderation: Defect if previous round >= m+2.
    - Last Round (if r > 1): Cooperate if historically successful (majority of rounds >= m), else Defect.
    - Permanent Failure Trigger: If any round result == m-1, revert to permanent Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.permanently_failed = False

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        for r_idx in range(current_round):
            my_action = 1 if history.my_actions[r_idx] else 0
            total_coop = history.opponent_cooperators[r_idx] + my_action
            if total_coop == self.m - 1:
                self.permanently_failed = True
                break
        if self.permanently_failed:
            return Action.D
        if current_round == self.r - 1:
            successful_rounds = 0
            for r_idx in range(current_round):
                my_action = 1 if history.my_actions[r_idx] else 0
                total_coop = history.opponent_cooperators[r_idx] + my_action
                if total_coop >= self.m:
                    successful_rounds += 1
            if successful_rounds >= current_round / 2:
                return Action.C
            else:
                return Action.D
        prev_my_action = 1 if history.my_actions[-1] else 0
        prev_total_coop = history.opponent_cooperators[-1] + prev_my_action
        if prev_total_coop < self.m:
            return Action.D
        elif prev_total_coop == self.m or prev_total_coop == self.m + 1:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_61(BaseStrategy):
    """
    A Tit-for-Tat-based threshold strategy. 
    Plays Cooperate in the first round to signal intent. 
    In subsequent rounds, if the threshold m was met in the previous round, it cooperates. 
    If the group narrowly failed (m-1), it uses a 50% probability buffer. 
    Otherwise, it defects.
    In the final round, it makes a last-ditch effort if previous history suggests 
    collective goal attainment is still statistically viable.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        current_round_t = history.round_number + 1
        m = self.game_description.m
        r = self.game_description.n_rounds
        if current_round_t == r:
            if len(history.opponent_cooperators) > 0:
                avg_coop = np.mean(history.opponent_cooperators)
                if avg_coop >= m - 1:
                    return Action.C
        prev_opp_coop = history.opponent_cooperators[-1]
        prev_my_action = history.my_actions[-1]
        total_prev_c = prev_opp_coop + (1 if prev_my_action else 0)
        if total_prev_c >= m:
            return Action.C
        if total_prev_c == m - 1:
            return Action.C if random.random() < 0.5 else Action.D
        return Action.D

class Strategy_ALTRUISTIC_62(BaseStrategy):
    """
    A tit-for-tat influenced strategy for the Collective Risk Dilemma.
    It manages trust dynamically, reacts to threshold outcomes, and attempts
    to signal cooperation while protecting against exploitation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.trust_level = 0.5
        self.last_coop_rate_val = 0.0
        self.threshold = self.game_description.m / self.game_description.n_players

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        total_rounds = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            prob_c = min(1.0, m / n + 0.1)
            return Action.C if random.random() < prob_c else Action.D
        last_my_action = history.my_actions[-1]
        last_opp_coops = history.opponent_cooperators[-1]
        last_total_coops = last_opp_coops + (1 if last_my_action else 0)
        if last_my_action:
            others_who_cooperated = last_total_coops - 1
        else:
            others_who_cooperated = last_total_coops
        coop_rate_prev = others_who_cooperated / (n - 1) if n - 1 > 0 else 0.0
        if last_my_action and self.last_coop_rate_val - coop_rate_prev > 0.5:
            self.trust_level = 0.0
            action = Action.D
        else:
            self.trust_level = 0.9 * self.trust_level + 0.1 * coop_rate_prev
            if not last_my_action and last_total_coops >= m:
                action = Action.C
            elif current_round / total_rounds > 0.8:
                if self.trust_level > 0.8:
                    action = Action.C
                else:
                    action = Action.D
            elif self.trust_level > self.threshold:
                action = Action.C
            else:
                prob = min(1.0, self.trust_level * (n / m))
                action = Action.C if random.random() < prob else Action.D
        self.last_coop_rate_val = coop_rate_prev
        return action

class Strategy_ALTRUISTIC_63(BaseStrategy):
    """
    Implements a Conditional Threshold Cooperation strategy.
    
    Logic:
    - Round 1: Play C.
    - Standard Rounds:
        - If previous total cooperators >= m: Play C (Success).
        - If previous total cooperators == m - 1: Play C (Pivot).
        - Otherwise: Play D (Failure).
    - Terminal Round:
        - If aggregate cooperation history suggests a probability of success > 0.5 (approximated 
          by total cooperators >= m - 1), Play C. Otherwise, Play D.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        prev_my_action = 1 if history.my_actions[-1] else 0
        prev_total_cooperators = history.opponent_cooperators[-1] + prev_my_action
        if history.round_number == r - 1:
            if prev_total_cooperators >= m - 1:
                return Action.C
            return Action.D
        if prev_total_cooperators >= m:
            return Action.C
        elif prev_total_cooperators == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_64(BaseStrategy):
    """
    Implements an Adaptive Conditional Cooperation strategy for the Collective Risk Dilemma.
    
    Logic:
    - Round 0: Always Cooperate (C).
    - Rounds 1 to (r-2):
        - If previous cooperator count >= m:
            - If previously played C, maintain C.
            - If previously played D, play C with probability m/n.
        - If previous cooperator count == m-1: Always C (Pivotal contribution).
        - If previous cooperator count < m-1: Always D.
    - Final Round (r-1):
        - If previous cooperator count >= m-1: Always C.
        - Otherwise: Always D.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        if current_round == 0:
            return Action.C
        my_prev_action = Action.C if history.my_actions[-1] else Action.D
        s_prev = history.opponent_cooperators[-1] + (1 if my_prev_action == Action.C else 0)
        if current_round == r - 1:
            if s_prev >= m - 1:
                return Action.C
            else:
                return Action.D
        if s_prev >= m:
            if my_prev_action == Action.C:
                return Action.C
            else:
                if random.random() < m / n:
                    return Action.C
                return Action.D
        elif s_prev == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_65(BaseStrategy):
    """
    A strategy that aims to stabilize cooperation at the threshold m.
    It cooperates in the first round, and subsequently adapts based on whether
    the threshold was met in the previous round, incorporating a 'pivotal' logic
    and a 'saturation' check.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.failed_consecutive_rounds = 0

    def __call__(self, history: PlayerHistory) -> Action:
        m = self.game_description.m
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        last_my_action = history.my_actions[-1]
        last_opp_c = history.opponent_cooperators[-1]
        last_my_c = 1 if last_my_action else 0
        total_C_prev = last_opp_c + last_my_c
        if total_C_prev < m:
            self.failed_consecutive_rounds += 1
        else:
            self.failed_consecutive_rounds = 0
        if self.failed_consecutive_rounds >= 3:
            return Action.D
        if current_round == r - 1:
            if total_C_prev >= m - 1:
                return Action.C
            return Action.D
        if total_C_prev >= m:
            if total_C_prev > m:
                return Action.D
            else:
                return Action.C if last_my_action else Action.D
        elif total_C_prev == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_66(BaseStrategy):
    """
    Implements a Tit-for-Tat variant designed for collective thresholds.
    Prioritizes cooperation (C) to meet the minimum threshold (m). 
    If the threshold fails for two consecutive rounds, defects (D) for one round
    as a protective measure, then returns to cooperation (C) in the next round
    to offer an 'olive branch'.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        last_my_action = 1 if history.my_actions[-1] else 0
        total_cooperators_last = last_my_action + history.opponent_cooperators[-1]
        m = self.game_description.m
        if total_cooperators_last < m:
            if history.round_number > 1:
                prev_my_action = 1 if history.my_actions[-2] else 0
                total_cooperators_prev = prev_my_action + history.opponent_cooperators[-2]
                if total_cooperators_prev < m:
                    return Action.D
            return Action.C
        return Action.C

class Strategy_ALTRUISTIC_67(BaseStrategy):
    """
    Conditional Altruistic Trigger (CAT):
    A threshold-based conditional cooperator strategy. It initializes with
    cooperation, cooperates if the previous round met the threshold (or was a near-miss),
    and utilizes a punishment/recovery cycle if the threshold is failed.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.desc.m
        my_last_action = Action.C if history.my_actions[-1] else Action.D
        my_last_contribution = 1 if my_last_action == Action.C else 0
        total_cooperators_last_round = history.opponent_cooperators[-1] + my_last_contribution
        if total_cooperators_last_round >= m:
            return Action.C
        if total_cooperators_last_round == m - 1:
            return Action.C
        if total_cooperators_last_round < m:
            if my_last_action == Action.D:
                if total_cooperators_last_round > 0:
                    return Action.C
                else:
                    return Action.D
            else:
                return Action.D
        return Action.D

class Strategy_ALTRUISTIC_68(BaseStrategy):
    """
    Threshold-Targeting Reciprocity (TTR): A strategy that promotes collective
    cooperation by punishing defectors when thresholds are missed, while 
    maintaining probing behavior to re-establish cooperation. Includes specific
    provisions for initial rounds, near-threshold successes, and the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description
        self.m = game_description.m
        self.n = game_description.n_players
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        my_last_action = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + my_last_action
        if current_round == self.r - 1:
            return Action.C
        if total_cooperators_prev == self.m - 1:
            return Action.C
        if current_round == 1:
            if total_cooperators_prev < self.m:
                return Action.C
        d_t = self.m - total_cooperators_prev
        if d_t <= 0:
            return Action.C
        else:
            i_defected_last = not history.my_actions[-1]
            if i_defected_last:
                if total_cooperators_prev >= self.m - 1:
                    return Action.C
                else:
                    return Action.D
            else:
                return Action.D

class Strategy_ALTRUISTIC_69(BaseStrategy):
    """
    Implements a Conditional Tit-for-Tat strategy with Threshold Sensitivity.
    Prioritizes cooperative equilibria while punishing persistent defection,
    featuring proactive recovery (forgiveness/signaling) when the group is
    near the threshold.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.last_action = None

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            self.last_action = Action.C
            return Action.C
        c_prev = history.opponent_cooperators[-1]
        my_prev_action = Action.C if history.my_actions[-1] else Action.D
        m = self.game_description.m
        r_total = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == r_total - 1:
            threshold_met_count = np.sum(history.opponent_cooperators >= m)
            if threshold_met_count / current_round >= 0.75:
                return Action.C
            else:
                return Action.D
        if c_prev == m - 1:
            self.last_action = Action.C
            return Action.C
        if c_prev >= m:
            self.last_action = Action.C
            return Action.C
        elif my_prev_action == Action.C:
            self.last_action = Action.D
            return Action.D
        else:
            self.last_action = Action.D
            return Action.D

class Strategy_ALTRUISTIC_70(BaseStrategy):
    """
    Implements Threshold-Adaptive Reciprocity (TAR). 
    TAR anchors cooperation to the threshold m, using forgiveness for minor 
    coordination failures while punishing systemic defection. It ensures 
    altruism in the final round and attempts to reset following total silence.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.alpha = max(1, math.floor(self.game_description.n_players / self.game_description.m))
        self.is_easy_threshold = self.game_description.n_players - self.game_description.m < self.game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        n = self.game_description.n_players
        if current_round == total_rounds - 1:
            return Action.C
        if current_round == 0:
            return Action.C
        my_last_action = history.my_actions[-1]
        c_prev = history.opponent_cooperators[-1] + (1 if my_last_action else 0)
        if c_prev == 0:
            return Action.C
        if c_prev >= m:
            return Action.C
        if self.is_easy_threshold:
            return Action.D
        d_prev = n - c_prev
        if d_prev <= self.alpha:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_71(BaseStrategy):
    """
    Implements a conditional threshold reciprocity strategy.
    
    The strategy attempts to maintain exactly m cooperators by:
    - Initiating with cooperation.
    - If T >= m: 
        - If I cooperated, defect if surplus (T > m), otherwise cooperate.
        - If I defected, continue to defect if T > m, otherwise cooperate.
    - If T < m: Always cooperate to attempt to meet the threshold.
    - Last round: Defect if T >= m, otherwise contribute only if it tips the scale to m.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_last_action = history.my_actions[-1]
        opponents_cooperating = history.opponent_cooperators[-1]
        my_contribution = 1 if my_last_action else 0
        T_prev = opponents_cooperating + my_contribution
        if history.round_number == self.total_rounds - 1:
            if T_prev >= self.m:
                return Action.D
            else:
                if T_prev == self.m - 1:
                    return Action.C
                return Action.D
        if T_prev >= self.m:
            if my_last_action:
                return Action.D if T_prev > self.m else Action.C
            else:
                return Action.D
        else:
            return Action.C

class Strategy_ALTRUISTIC_72(BaseStrategy):
    """
    Implements a conditional cooperative strategy for the Collective Risk Dilemma.
    Starts by cooperating. Subsequent actions depend on the threshold m and 
    the number of remaining rounds, using probabilistic signals or altruistic 
    final-round checks.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        last_round_idx = -1
        my_last_action = int(history.my_actions[last_round_idx])
        c_prev = history.opponent_cooperators[last_round_idx] + my_last_action
        if c_prev >= self.m:
            return Action.C
        current_round = history.round_number
        remaining_rounds = self.r - current_round
        if remaining_rounds > 1:
            p_c = min(max(self.m / self.n, 0.0), 1.0)
            return Action.C if random.random() < p_c else Action.D
        all_my_actions = history.my_actions.astype(int)
        all_total_cooperators = history.opponent_cooperators + all_my_actions
        avg_cooperators = np.mean(all_total_cooperators)
        if avg_cooperators >= self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_73(BaseStrategy):
    """
    Implements Conditional Threshold Reciprocity with a Tit-for-Tat baseline.
    
    Strategy logic:
    1. First Round: Cooperate if threshold ratio m/n <= 0.5, else Defect.
    2. Subsequent Rounds: 
       - If previous threshold met, Cooperate.
       - If previous threshold failed:
         - If self cooperated, Defect (punish).
         - If self defected, Cooperate with probability p = (m - C_prev) / n.
    3. Endgame (last 2 rounds): Revert to strict Tit-for-Tat (C if threshold met, else D).
    4. Edge cases: m=1 always C; high-threshold tolerance handled by logic.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if self.m == 1:
            return Action.C
        if current_round == 0:
            if self.m / self.n <= 0.5:
                return Action.C
            return Action.D
        c_prev = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        if current_round >= self.r - 2:
            return Action.C if c_prev >= self.m else Action.D
        if self.n - self.m > self.n / 2:
            if current_round >= 2:
                failed_last_2 = history.opponent_cooperators[-1] < self.m and history.opponent_cooperators[-2] < self.m
                if failed_last_2:
                    return Action.D
        if c_prev >= self.m:
            return Action.C
        elif my_prev_action:
            return Action.D
        else:
            p = (self.m - c_prev) / self.n
            if random.random() < p:
                return Action.C
            else:
                return Action.D

class Strategy_ALTRUISTIC_74(BaseStrategy):
    """
    Threshold-Targeted Conditional Cooperation:
    A strategy that prioritizes the collective threshold (m) while employing 
    probabilistic adjustments and failure recovery mechanisms to balance 
    group success with individual risk.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0
        self.recovery_countdown = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.game_description.m
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        prev_my_action = int(history.my_actions[-1])
        prev_opp_coop = int(history.opponent_cooperators[-1])
        prev_total_coop = prev_opp_coop + prev_my_action
        if prev_total_coop < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if history.round_number == r - 1:
            total_past_successes = sum((1 for c in history.opponent_cooperators + history.my_actions.astype(int) if c >= m))
            if total_past_successes / r < 0.2:
                return Action.D
            return Action.C
        if self.recovery_countdown > 0:
            self.recovery_countdown -= 1
            if self.recovery_countdown == 0:
                return Action.C
            return Action.D
        if self.consecutive_failures >= 3:
            self.consecutive_failures = 0
            self.recovery_countdown = 2
            return Action.D
        if prev_total_coop >= m:
            if prev_my_action == 1 and prev_total_coop == m:
                prob = max(0.5, 1.0 / m)
                if random.random() < prob:
                    return Action.D
                return Action.C
            if prev_my_action == 0 and prev_total_coop > m:
                return Action.D
            if prev_my_action == 0 and prev_total_coop == m:
                return Action.C
            return Action.C
        else:
            deficit = m - prev_total_coop
            if prev_my_action == 0:
                if deficit == 1:
                    return Action.C
                else:
                    p = max(0.0, 1.0 - deficit / n)
                    if random.random() < p:
                        return Action.C
                    return Action.D
            return Action.C

class Strategy_ALTRUISTIC_75(BaseStrategy):
    """
    Threshold-Targeting Trigger (TTT) Strategy.
    
    Implements a conditional-cooperation mechanism:
    1. Always starts by cooperating to signal intent.
    2. Continues cooperation if the collective threshold (m) was met.
    3. If threshold not met, switches to Conditional Reciprocity (probabilistic 
       cooperation based on remaining needs).
    4. Includes Sucker Mitigation (random defection if surplus cooperation exists).
    5. Includes Re-ignition (handshake) logic after persistent failure.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0
        self.conditional_reciprocity_counter = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        m = self.game_description.m
        prev_opp_c = history.opponent_cooperators[-1]
        prev_my_action = history.my_actions[-1]
        my_prev_coop = 1 if prev_my_action else 0
        prev_total_c = prev_opp_c + my_prev_coop
        if prev_total_c < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.C
        if prev_total_c >= m:
            self.conditional_reciprocity_counter = 0
            if prev_total_c > m and random.random() < 0.1:
                return Action.D
            return Action.C
        if self.consecutive_failures > 3:
            self.consecutive_failures = 0
            return Action.C
        if prev_total_c < m:
            if my_prev_coop == 1:
                return Action.C
            needed = m - prev_total_c
            available = n - prev_total_c
            prob = needed / available if available > 0 else 0
            if random.random() < prob:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_ALTRUISTIC_76(BaseStrategy):
    """
    A reputation-based strategy for the Collective Risk Dilemma.
    Maintains a reputation score S, adjusting based on collective performance,
    with specific triggers for sudden drops and persistent defection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description
        self.reputation = 0
        self.consecutive_fails = 0
        self.permanent_defection = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game.n_players
        m = self.game.m
        r = self.game.n_rounds
        t = history.round_number
        if t == 0:
            if m / n <= 0.5:
                return Action.C
            return Action.D
        prev_opp_coop = int(history.opponent_cooperators[-1])
        my_prev_action = bool(history.my_actions[-1])
        c_total = prev_opp_coop + (1 if my_prev_action else 0)
        if t > 1:
            prev_prev_opp_coop = int(history.opponent_cooperators[-2])
            prev_prev_my_action = bool(history.my_actions[-2])
            prev_c_total = prev_prev_opp_coop + (1 if prev_prev_my_action else 0)
            if prev_c_total - c_total > n / 2:
                self.reputation = -1
                return Action.D
        if c_total >= m:
            self.reputation += 1
            if c_total == n:
                self.reputation += 1
            self.consecutive_fails = 0
        else:
            self.reputation -= 1
            self.consecutive_fails += 1
        if self.consecutive_fails >= 3:
            self.reputation = -n
            self.permanent_defection = True
            return Action.D
        if self.permanent_defection:
            return Action.D
        if t == r - 1:
            past_coop_counts = np.array(history.opponent_cooperators) + history.my_actions.astype(int)
            avg_coop_rate = np.mean(past_coop_counts) / n
            if avg_coop_rate < m / n:
                return Action.D
            return Action.C
        if self.reputation >= 0:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_77(BaseStrategy):
    """
    Implements a Conditional Cooperation strategy.
    Prioritizes group success by ensuring the collective contribution meets the threshold m.
    Utilizes historical success rates and redundant contribution checks to optimize individual payoffs.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.d = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.d.m
        r_total = self.d.n_rounds
        current_round_idx = history.round_number
        my_prev_action = 1 if history.my_actions[-1] else 0
        opp_prev_c = history.opponent_cooperators[-1]
        total_prev_c = my_prev_action + opp_prev_c
        if current_round_idx == r_total - 1:
            total_successes = 0
            for i in range(current_round_idx):
                i_c = 1 if history.my_actions[i] else 0
                i_opp = history.opponent_cooperators[i]
                if i_c + i_opp >= m:
                    total_successes += 1
            if total_successes / current_round_idx < 0.5:
                return Action.D
            return Action.C
        if total_prev_c >= m:
            if total_prev_c - 1 >= m:
                return Action.D
            return Action.C
        return Action.C

class Strategy_ALTRUISTIC_78(BaseStrategy):
    """
    Adaptive Threshold-Reciprocity Strategy.
    
    This strategy balances altruism and defense. It defaults to cooperation to signal 
    goodwill. It monitors the group's cooperation rate to reach threshold 'm'.
    - If the threshold was met, it continues to cooperate.
    - If the threshold failed, it calculates the 'contribution gap'.
      - If the gap is small (1), suggesting one defection prevented success, it punishes with 'D'.
      - If the gap is large, it persists with 'C' to act as a catalyst for future coordination.
    - In the final round, it rewards historical cooperation with 'C', otherwise 'D'.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        n = self.game_description.n_players
        if current_round == 0:
            return Action.C
        if current_round == total_rounds - 1:
            total_coop_over_rounds = 0.0
            for r in range(current_round):
                my_action_val = 1 if history.my_actions[r] else 0
                total_coop_over_rounds += my_action_val + history.opponent_cooperators[r]
            avg_coop_rate = total_coop_over_rounds / (current_round * n)
            if avg_coop_rate >= m / n:
                return Action.C
            return Action.D
        prev_opp_coop = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        my_prev_val = 1 if my_prev_action else 0
        total_cooperators = my_prev_val + prev_opp_coop
        if total_cooperators >= m:
            return Action.C
        gap = m - total_cooperators
        condition_val = 1 if my_prev_action else 0
        if condition_val == 1 and gap <= 1:
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_79(BaseStrategy):
    """
    Implements a Conditional Reciprocity Threshold strategy for the Collective Risk Dilemma.
    Aims for exactly m cooperators to optimize payoff, with logic for resetting dynamics 
    during persistent failure and discouraging over-contribution.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.failed_streak = 0
        self.override_cooldown = 0

    def __call__(self, history: PlayerHistory) -> Action:
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        my_prev_c = bool(history.my_actions[-1])
        c_prev = history.opponent_cooperators[-1] + (1 if my_prev_c else 0)
        if c_prev < m:
            self.failed_streak += 1
        else:
            self.failed_streak = 0
        if self.override_cooldown > 0:
            self.override_cooldown -= 1
            return Action.D
        if self.failed_streak >= 3:
            self.failed_streak = 0
            self.override_cooldown = 2
            return Action.D
        if c_prev > m + 1:
            return Action.D
        if current_round == r - 1:
            if c_prev < m:
                return Action.C
            else:
                return Action.D
        if c_prev < m:
            if my_prev_c:
                return Action.D
            else:
                return Action.C
        elif c_prev > m:
            return Action.D
        elif my_prev_c:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_80(BaseStrategy):
    """
    Implements Threshold-Conditioned Reciprocity.
    
    1. First round: Always Cooperate (C).
    2. Final round: Always Cooperate (C).
    3. Intermediate rounds (2 to r):
       - If previous round threshold (m) met: Cooperate (C).
       - If previous round threshold not met:
         - If gap is exactly 1 (c_prev == m - 1): Cooperate (C) to bridge the gap.
         - Otherwise: Defect (D) to protect private endowment.
    
    Strategy notes:
    - Assumes the 'm' parameter refers to the absolute number of cooperators required across all players (including self).
    - The history tracks opponent_cooperators, which implies we need to be careful with the counts provided.
    - Since opponent_cooperators usually excludes 'self', the logic adjusts:
      - If I cooperated: Total = opponent_cooperators + 1
      - If I defected: Total = opponent_cooperators
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.C
        m = self.game_description.m
        prev_opp_coop = history.opponent_cooperators[-1]
        my_prev_action = Action.C if history.my_actions[-1] else Action.D
        total_cooperators_prev = prev_opp_coop + (1 if my_prev_action == Action.C else 0)
        if total_cooperators_prev >= m:
            return Action.C
        elif total_cooperators_prev == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_81(BaseStrategy):
    """
    Implements a Conditional Threshold Tit-for-Tat strategy. 
    Cooperates initially, then adapts based on whether the previous round 
    met the cooperation threshold 'm'. It enforces the threshold by 
    defecting if the group fails, but offers an 'olive branch' if the 
    threshold was nearly met (m-1), attempting to recover cooperation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.persistent_defection_threshold = 2

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        total_cooperators_prev = prev_cooperators + (1 if my_prev_action else 0)
        if current_round >= self.persistent_defection_threshold:
            recent_history = history.opponent_cooperators[-self.persistent_defection_threshold:]
            if all((c + (1 if a else 0) < m for c, a in zip(recent_history, history.my_actions[-self.persistent_defection_threshold:]))):
                return Action.D
        if current_round == r - 1:
            if total_cooperators_prev >= m:
                return Action.C
            else:
                return Action.D
        if total_cooperators_prev >= m:
            return Action.C
        elif total_cooperators_prev >= m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_82(BaseStrategy):
    """
    Threshold-Tit-for-Tat with Conditional Altruism.
    
    Uses reciprocity to enforce threshold compliance. Upon a failed threshold, 
    the strategy enters a retaliatory state (playing D) until the group proves 
    stability through two consecutive successful rounds, at which point it 
    resets to altruistic behavior (C).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.is_retaliating = False
        self.success_streak = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            self.is_retaliating = False
            self.success_streak = 0
            return Action.C
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        my_last_action = bool(history.my_actions[-1])
        opp_coop = history.opponent_cooperators[-1]
        total_coop = opp_coop + (1 if my_last_action else 0)
        if history.round_number == r - 1:
            if my_last_action:
                return Action.C
            return Action.C if opp_coop + 1 >= m else Action.D
        if total_coop >= m:
            self.success_streak += 1
        else:
            self.success_streak = 0
            self.is_retaliating = True
        if self.is_retaliating:
            if self.success_streak >= 2:
                self.is_retaliating = False
                return Action.C
            return Action.D
        if total_coop >= m:
            if my_last_action:
                return Action.C
            else:
                return Action.C if random.random() < m / n else Action.D
        else:
            return Action.D

class Strategy_ALTRUISTIC_83(BaseStrategy):
    """
    Implements a Threshold-Triggered Conditional Reciprocity strategy.
    It prioritizes initial cooperation, attempts recovery if the threshold is just missed,
    tracks long-term reliability for the terminal phase, and abandons cooperation 
    in response to persistent failure or unreliability.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.consecutive_failures = 0
        self.is_fragile = self.desc.m >= self.desc.n_players - 1

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_round = history.round_number - 1
        n_cooperators = history.opponent_cooperators[prev_round]
        my_c = 1 if history.my_actions[prev_round] else 0
        total_cooperators = n_cooperators + my_c
        threshold_met = total_cooperators >= self.desc.m
        if not threshold_met:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 2:
            return Action.D
        if history.round_number == self.desc.n_rounds - 1:
            success_count = 0
            for r in range(history.round_number):
                opp_c = history.opponent_cooperators[r]
                my_c_r = 1 if history.my_actions[r] else 0
                if opp_c + my_c_r >= self.desc.m:
                    success_count += 1
            success_rate = success_count / history.round_number
            if success_rate > 0.5:
                return Action.C
            return Action.D
        if threshold_met:
            return Action.C
        if total_cooperators == self.desc.m - 1:
            return Action.C
        if self.is_fragile and total_cooperators == self.desc.m - 2 and (self.consecutive_failures < 2):
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_84(BaseStrategy):
    """
    Conditional Threshold-Trigger (CTT): A strategy that enforces a social contract 
    of cooperation (m threshold) through adaptive punishment and reconciliation phases.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.punishment_counter = 0
        self.reconciliation_mode = False
        self.consecutive_failed_windows = 0
        self.last_action = Action.C
        base_f = max(1, math.floor(self.game_description.n_rounds / 10))
        self.base_punishment_length = base_f

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            self.last_action = Action.C
            return Action.C
        my_prev_action = history.my_actions[-1]
        my_prev_coop = 1 if my_prev_action == Action.C else 0
        total_coop_prev = history.opponent_cooperators[-1] + my_prev_coop
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == r - 1:
            if total_coop_prev >= m:
                return Action.C
            else:
                return Action.D
        if self.punishment_counter > 0:
            self.punishment_counter -= 1
            if self.punishment_counter == 0:
                self.reconciliation_mode = True
                return Action.C
            else:
                return Action.D
        if self.reconciliation_mode:
            self.reconciliation_mode = False
            if total_coop_prev >= m:
                self.consecutive_failed_windows = 0
                return Action.C
            else:
                self.consecutive_failed_windows += 1
                self._trigger_punishment(total_coop_prev < m)
                return Action.D
        if total_coop_prev == m - 1:
            self.last_action = Action.C
            return Action.C
        if total_coop_prev < m:
            self.consecutive_failed_windows += 1
            self._trigger_punishment(True)
            return Action.D
        else:
            self.consecutive_failed_windows = 0
            return self.last_action

    def _trigger_punishment(self, failed: bool):
        if failed:
            multiplier = 1
            if self.consecutive_failed_windows > 3:
                multiplier = 2
            self.punishment_counter = self.base_punishment_length * multiplier
        else:
            self.punishment_counter = 0

class Strategy_ALTRUISTIC_85(BaseStrategy):
    """
    A conditional threshold-trigger strategy for the Collective Risk Dilemma.
    Starts with Cooperation, maintains it if the group threshold is met,
    defects upon collective failure, and periodically probes for recovery.
    Always defects in the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.cooperation_active = True

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        prev_round = history.round_number - 1
        my_prev_action = history.my_actions[prev_round]
        opp_c = history.opponent_cooperators[prev_round]
        total_c = opp_c + (1 if my_prev_action else 0)
        m = self.game_description.m
        if total_c >= m:
            self.cooperation_active = True
            return Action.C
        else:
            my_played_c = bool(my_prev_action)
            if total_c == m - 1 and my_played_c:
                self.cooperation_active = False
            elif total_c < m - 1:
                self.cooperation_active = False
            if not self.cooperation_active:
                if history.round_number % 3 == 0:
                    return Action.C
                else:
                    return Action.D
            return Action.D

class Strategy_ALTRUISTIC_86(BaseStrategy):
    """
    Implements an Altruistic Threshold-Triggered Tit-for-Tat strategy.
    
    Prioritizes group success (reaching threshold m). Uses conditional cooperation:
    - If threshold is met, cooperates (with occasional testing).
    - If threshold is missed, signals for change by defecting (unless being the
      swing vote, in which case it attempts to correct).
    - In the final round, makes a best-effort judgment to reach the threshold.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description
        self.last_action = Action.C

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            self.last_action = Action.C
            return Action.C
        n_prev_coop_others = history.opponent_cooperators[-1]
        i_cooperated = int(history.my_actions[-1])
        total_cooperators = n_prev_coop_others + i_cooperated
        m = self.game.m
        r = self.game.n_rounds
        if history.round_number < r - 1:
            current_action = Action.D
            if total_cooperators >= m:
                current_action = Action.C
                if total_cooperators > m + 1:
                    current_action = Action.D
            elif total_cooperators < m:
                if total_cooperators == m - 1 and self.last_action == Action.D:
                    current_action = Action.C
                else:
                    current_action = Action.D
            self.last_action = current_action
            return current_action
        if total_cooperators >= m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_87(BaseStrategy):
    """
    Implements the Tit-for-Tat Threshold Strategy (TFTS).
    
    Logic:
    1. Round 1: Cooperate.
    2. Rounds t > 1:
       - If previous round had >= 1 cooperators, cooperate.
       - If previous round had 0 cooperators, defect, UNLESS 
         probing condition (current round index is multiple of 3) triggers cooperation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_prev_action = 1 if history.my_actions[-1] else 0
        prev_total_cooperators = history.opponent_cooperators[-1] + my_prev_action
        t = history.round_number + 1
        if prev_total_cooperators == 0 and t % 3 == 0:
            return Action.C
        if prev_total_cooperators >= 1:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_88(BaseStrategy):
    """
    Conditional Altruistic Trigger (CAT):
    A strategy that initiates cooperation and maintains it as long as the threshold 
    is met. If the threshold is not met, it employs defensive defection but 
    re-attempts cooperation after a brief cooldown, balancing altruism with 
    resource protection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_defections = 0
        self.was_cooperating_streak = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            self.consecutive_defections = 0
            self.was_cooperating_streak = False
            return Action.C
        m = self.game_description.m
        r = self.game_description.n_rounds
        prev_round = history.round_number - 1
        prev_c_count = history.opponent_cooperators[prev_round]
        my_prev_action = history.my_actions[prev_round]
        total_nc = prev_c_count + (1 if my_prev_action else 0)
        if history.round_number == r - 1:
            if total_nc >= m * 0.8 or self.was_cooperating_streak:
                return Action.C
            return Action.D
        if total_nc >= m:
            self.consecutive_defections = 0
            self.was_cooperating_streak = True
            return Action.C
        if my_prev_action == Action.C:
            self.consecutive_defections = 1
            self.was_cooperating_streak = False
            return Action.D
        self.consecutive_defections += 1
        if self.consecutive_defections >= 2:
            self.consecutive_defections = 0
            self.was_cooperating_streak = False
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_89(BaseStrategy):
    """
    Implements a Cooperative Threshold Strategy that manages contributions based on
    reciprocity, historical success rates, and a cyclical testing mechanism to
    mitigate exploitation in a collective risk dilemma.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.last_my_action = 0
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.threshold_ratio = self.m / self.n

    def __call__(self, history: PlayerHistory) -> Action:
        t_0_based = history.round_number
        t_1_based = t_0_based + 1
        if t_0_based == 0:
            action = Action.C if self.threshold_ratio <= 0.5 else Action.D
            self.last_my_action = action.value
            return action
        if t_1_based == self.r:
            success_count = sum((1 for obs in history.opponent_cooperators if obs + self.last_my_action >= self.m))
            if success_count >= self.r / 2:
                action = Action.C
            else:
                action = Action.D
            self.last_my_action = action.value
            return action
        total_cooperators_per_round = history.opponent_cooperators + history.my_actions.astype(int)
        avg_coop_rate = sum(total_cooperators_per_round) / (t_0_based * self.n)
        if avg_coop_rate >= self.threshold_ratio:
            action = Action.C
        elif t_1_based % 2 == 0:
            action = Action.C
        else:
            action = Action.D
        self.last_my_action = action.value
        return action

class Strategy_ALTRUISTIC_90(BaseStrategy):
    """
    Implements a Conditional Tit-for-Tat strategy with threshold sensitivity.
    
    Logic:
    1. Initial Round: Cooperate if m < n, else Defect.
    2. Maintenance Phase: 
       - Cooperate if prev_c >= m OR prev_c == m - 1.
       - Defect if prev_c < m - 1 OR persistent defection (m-1 or less for > 2 consecutive rounds) detected.
    3. Terminal Round: Cooperate if average cooperators >= m over the last 3 rounds, else Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n = self.desc.n_players
        m = self.desc.m
        r = self.desc.n_rounds
        if current_round == 0:
            return Action.C if m < n else Action.D
        prev_c = history.opponent_cooperators[-1]
        my_prev_action = int(history.my_actions[-1])
        total_prev_c = prev_c + my_prev_action
        if current_round == r - 1:
            recent_rounds_total = []
            limit = min(3, current_round)
            for i in range(1, limit + 1):
                c_count = history.opponent_cooperators[-i] + int(history.my_actions[-i])
                recent_rounds_total.append(c_count)
            if len(recent_rounds_total) > 0 and all((c >= m for c in recent_rounds_total)):
                return Action.C
            return Action.D
        history_len = len(history.my_actions)
        if history_len >= 3:
            is_persistent = True
            for i in range(1, 4):
                c_val = history.opponent_cooperators[-i] + int(history.my_actions[-i])
                if c_val > m - 1:
                    is_persistent = False
                    break
            if is_persistent:
                return Action.D
        if total_prev_c >= m:
            return Action.C
        if total_prev_c == m - 1:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_91(BaseStrategy):
    """
    Threshold-Adaptive Reciprocity (TAR):
    A strategy that facilitates collective success by signaling commitment to the threshold 
    while preventing exploitation. It prioritizes the 'm' threshold, contributing if necessary, 
    but defecting when the threshold is safe or the collective is hopeless.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.n = game_description.n_players

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        s_prev = int(history.opponent_cooperators[-1])
        my_last_action = history.my_actions[-1]
        my_last_contribution = 1 if my_last_action == Action.C else 0
        t = history.round_number
        total_cooperators_prev = s_prev + my_last_contribution
        threshold_was_met = total_cooperators_prev >= self.m
        if t == self.r - 1:
            if s_prev + 1 >= self.m:
                return Action.C
            if t >= 2:
                coop_prev_1 = int(history.opponent_cooperators[-1]) + (1 if history.my_actions[-1] else 0)
                coop_prev_2 = int(history.opponent_cooperators[-2]) + (1 if history.my_actions[-2] else 0)
                if coop_prev_1 >= self.m and coop_prev_2 >= self.m:
                    return Action.C
            return Action.D
        if s_prev == 0:
            return Action.D
        if threshold_was_met:
            if s_prev >= self.m:
                return Action.D
            else:
                return Action.C
        else:
            return Action.C

class Strategy_ALTRUISTIC_92(BaseStrategy):
    """
    Implements a Conditional Reciprocity with Threshold Sensitivity strategy.
    
    The strategy coordinates to meet the threshold 'm' while punishing defectors 
    using a grim-trigger variation. It tracks consecutive full-defection rounds 
    to handle the 'Persistent Defection' edge case and considers remaining 
    rounds vs the reward 'k' to prioritize payoff efficiency.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_defection_count = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        m = self.game_description.m
        k = self.game_description.k
        if history.round_number == 0:
            return Action.C
        my_prev_action = int(history.my_actions[-1])
        c_prev = history.opponent_cooperators[-1] + my_prev_action
        if c_prev == 0:
            self.consecutive_defection_count += 1
        else:
            self.consecutive_defection_count = 0
        r_current = history.round_number
        r_rem = r - r_current
        if r_current == r - 1:
            return Action.C
        if self.consecutive_defection_count >= n:
            return Action.D
        if r_rem * k < 1:
            all_rounds_successful = True
            for i in range(r_current):
                prev_c_total = history.opponent_cooperators[i] + int(history.my_actions[i])
                if prev_c_total < m:
                    all_rounds_successful = False
                    break
            if not all_rounds_successful:
                return Action.D
        if c_prev >= m - 1:
            return Action.C
        if c_prev == 0:
            return Action.D
        return Action.C

class Strategy_ALTRUISTIC_93(BaseStrategy):
    """
    A strategy that seeks to meet the collective threshold 'm'.
    It starts by cooperating, defects if the threshold is missed,
    attempts recovery if the group cooperates without its help,
    and plays cooperatively in the final round if there is potential.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.current_state = Action.C

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            self.current_state = Action.C
            return Action.C
        m = self.game_description.m
        r = self.game_description.n_rounds
        my_prev_action = history.my_actions[-1]
        c_prev = history.opponent_cooperators[-1] + (1 if my_prev_action == Action.C else 0)
        if history.round_number == r - 1:
            if c_prev >= m - 1:
                return Action.C
            else:
                return Action.D
        if self.current_state == Action.D:
            if c_prev >= m:
                self.current_state = Action.C
        if c_prev < m:
            self.current_state = Action.D
        if c_prev >= m:
            self.current_state = Action.C
        return self.current_state

class Strategy_ALTRUISTIC_94(BaseStrategy):
    """
    The Altruistic Threshold Reciprocator:
    A conditional cooperator that prioritizes collective success while using punishment to
    mitigate free-riding. It cooperates if the threshold was met in the previous round,
    defects if not, but attempts to recover coordination via a probabilistic reset
    proportional to the threshold difficulty (m/n). In the final round, it forces
    cooperation if the threshold is within reach.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description
        self.recovery_prob = self.game.m / self.game.n_players

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_last_action = history.my_actions[-1]
        c_prev = history.opponent_cooperators[-1] + (1 if my_last_action else 0)
        if history.round_number == self.game.n_rounds - 1:
            if c_prev == self.game.m - 1:
                return Action.C
            else:
                return Action.D
        if c_prev >= self.game.m:
            return Action.C
        if random.random() < self.recovery_prob:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_95(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that balances cooperation signaling,
    reciprocity, and loss minimization based on threshold performance.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        round_index = history.round_number
        if round_index == 0:
            return Action.C
        my_prev_action_int = 1 if history.my_actions[-1] else 0
        c_prev = history.opponent_cooperators[-1] + my_prev_action_int
        if round_index == self.r - 1:
            if c_prev >= self.m:
                return Action.C
            else:
                return Action.D
        if c_prev >= self.m:
            return Action.C
        elif c_prev > 0 and (not history.my_actions[-1]):
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_96(BaseStrategy):
    """
    Implements a Conditional Cooperation strategy for the Collective Risk Dilemma.
    Starts with optimism (C). In subsequent rounds, cooperates if the previous round 
    succeeded (>=m) or was a 'near-miss' (m-1). If the game history shows persistent 
    failure (>75% failure rate), switches to defection. In the final round, makes a 
    decision based on the long-term success rate (>50% success leads to cooperation).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        n_players = self.game_description.n_players
        m = self.game_description.m
        total_rounds = self.game_description.n_rounds
        last_my_action = 1 if history.my_actions[-1] else 0
        prev_round_cooperators = history.opponent_cooperators[-1] + last_my_action
        if history.round_number == total_rounds - 1:
            total_rounds_played = history.round_number
            success_count = 0
            for r in range(total_rounds_played):
                total_c = history.opponent_cooperators[r] + (1 if history.my_actions[r] else 0)
                if total_c >= m:
                    success_count += 1
            success_rate = success_count / total_rounds_played if total_rounds_played > 0 else 0
            return Action.C if success_rate > 0.5 else Action.D
        if prev_round_cooperators >= m:
            return Action.C
        elif prev_round_cooperators == m - 1:
            return Action.C
        else:
            total_rounds_played = history.round_number
            failure_count = 0
            for r in range(total_rounds_played):
                total_c = history.opponent_cooperators[r] + (1 if history.my_actions[r] else 0)
                if total_c < m:
                    failure_count += 1
            failure_rate = failure_count / total_rounds_played if total_rounds_played > 0 else 0
            if failure_rate > 0.75:
                return Action.D
            return Action.D

class Strategy_ALTRUISTIC_97(BaseStrategy):
    """
    Implements an Adaptive Aspiration-based strategy for the Collective Risk Dilemma.
    Uses a moving average estimator for opponents' cooperation probability, with
    conditional altruistic corrections and final-round heuristic adjustments.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.k = game_description.k
        self.r = game_description.n_rounds
        self.alpha = 0.2
        self.p_hat = self.m / self.n

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        t = history.round_number
        n = self.n
        m = self.m
        last_my_action = int(history.my_actions[-1])
        last_opp_coop = history.opponent_cooperators[-1]
        c_prev = last_opp_coop + last_my_action
        self.p_hat = (1 - self.alpha) * self.p_hat + self.alpha * (c_prev / n)
        decision = Action.D
        if self.p_hat >= (m - 1) / n:
            decision = Action.C
        if t >= 2:
            prev_opp_coop = history.opponent_cooperators[-2]
            prev_my_action = int(history.my_actions[-2])
            c_prev_2 = prev_opp_coop + prev_my_action
            if c_prev < m and c_prev_2 < m:
                decision = Action.C
        if t == self.r - 1:
            if c_prev >= m - 1:
                decision = Action.C
        return decision

class Strategy_ALTRUISTIC_98(BaseStrategy):
    """
    Implements a Triggered Reciprocity strategy for the Collective Risk Dilemma.
    
    The strategy maintains a 'trust index' (h) that tracks group cooperation history.
    It initiates with cooperation, maintains cooperation if the previous round succeeded
    or if trust is sufficiently high, and defects if the group consistently fails
    to meet the cooperation threshold (m). In the final round, it cooperates
    unconditionally to maximize collective potential.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.h = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = self.game_description.n_rounds
        m = self.game_description.m
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        prev_my_action = history.my_actions[-1]
        prev_opp_coops = history.opponent_cooperators[-1]
        total_coops = prev_opp_coops + (1 if prev_my_action else 0)
        if total_coops >= m:
            self.h = min(self.h + 1, 5)
        else:
            self.h = self.h - 2
        if current_round == n_rounds - 1:
            return Action.C
        if total_coops >= m:
            return Action.C
        if self.h >= 0:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_99(BaseStrategy):
    """
    Altruistic Threshold Reciprocity (ATR) Strategy.
    
    Operates on conditional threshold facilitation:
    - Always cooperates on the first and last rounds.
    - If the collective meets the threshold, reinforces with cooperation.
    - If below threshold, calculates a 'bridge' attempt (cooperate if deficit is small).
    - Includes a 'Persistent Failure' mechanism: shifts to permanent defection after 
      3 consecutive rounds of failure to meet the threshold.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.failure_counter = 0
        self.max_failure_tolerance = 3
        self.persistent_defection = False

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == 0:
            return Action.C
        if current_round == total_rounds - 1:
            return Action.C
        if self.persistent_defection:
            return Action.D
        last_round_idx = current_round - 1
        my_last_action = history.my_actions[last_round_idx]
        total_cooperators_last_round = history.opponent_cooperators[last_round_idx] + (1 if my_last_action else 0)
        if total_cooperators_last_round < m:
            self.failure_counter += 1
        else:
            self.failure_counter = 0
        if self.failure_counter >= self.max_failure_tolerance:
            self.persistent_defection = True
            return Action.D
        if total_cooperators_last_round >= m:
            return Action.C
        needed = m - (total_cooperators_last_round + 1)
        if needed <= 2:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_100(BaseStrategy):
    """
    A strategy that utilizes conditional cooperation to hit the threshold 'm'.
    It contributes if the threshold is potentially reachable and requires the player's 
    participation (pivotal), or if the threshold is exactly met (maintenance). 
    It defects if the threshold is safely exceeded or if the collective effort 
    is futile.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = self.game_description.n_players
        self.m = self.game_description.m
        self.r = self.game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        my_actions_int = history.my_actions.astype(int)
        total_cooperators_history = history.opponent_cooperators + my_actions_int
        historical_avg = np.mean(total_cooperators_history)
        if current_round == self.r - 1:
            if historical_avg >= (self.m - 1) / self.n:
                return Action.C
            else:
                return Action.D
        last_round_idx = -1
        prev_opponents_c = history.opponent_cooperators[last_round_idx]
        prev_my_c = int(history.my_actions[last_round_idx])
        c_prev = prev_opponents_c + prev_my_c
        if c_prev >= self.m:
            if c_prev > self.m:
                return Action.D
            else:
                return Action.C
        elif c_prev == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_101(BaseStrategy):
    """
    Threshold-Responsive Reciprocity:
    Prioritizes collective success by conditioning actions on the previous round's outcome relative to m.
    - First round: Cooperate.
    - If successful (prev_cooperators >= m): Cooperate with probability m/n to maintain threshold.
    - If failure (prev_cooperators < m): Toggle action (if C -> D, if D -> C).
    - Last round: Cooperate if previous success, otherwise Defect.
    - Default: After three consecutive failures, default to Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.failure_counter = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        prev_my_action = Action.C if history.my_actions[-1] else Action.D
        prev_opponents = history.opponent_cooperators[-1]
        total_prev_cooperators = prev_opponents + (1 if prev_my_action == Action.C else 0)
        if total_prev_cooperators < m:
            self.failure_counter += 1
        else:
            self.failure_counter = 0
        if self.failure_counter >= 3:
            return Action.D
        if current_round == r - 1:
            if total_prev_cooperators >= m:
                return Action.C
            else:
                return Action.D
        if total_prev_cooperators >= m:
            if random.random() < m / n:
                return Action.C
            return Action.D
        elif prev_my_action == Action.C:
            return Action.D
        else:
            return Action.C

class Strategy_ALTRUISTIC_102(BaseStrategy):
    """
    Implements a Threshold-Targeted Reciprocal Altruism strategy.
    
    This strategy focuses on achieving the group threshold 'm' to secure the collective reward.
    - Rounds 1 and terminal round: Always cooperate.
    - Success (C_t-1 >= m): Cooperate with probability 0.9 to sustain success while minimizing exploitation.
    - Near-Failure (C_t-1 == m-1): Cooperate with probability 1.0 to attempt to bridge the gap.
    - Failure (C_t-1 < m-1): Defect for one round to signal dissatisfaction, then revert to C in subsequent rounds.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.in_reset_phase = False

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == 0:
            self.in_reset_phase = False
            return Action.C
        if current_round == total_rounds - 1:
            return Action.C
        my_last_action = int(history.my_actions[-1])
        total_cooperators_prev = history.opponent_cooperators[-1] + my_last_action
        if self.in_reset_phase:
            self.in_reset_phase = False
            return Action.C
        if total_cooperators_prev >= m:
            return Action.C if random.random() < 0.9 else Action.D
        elif total_cooperators_prev == m - 1:
            return Action.C
        else:
            self.in_reset_phase = True
            return Action.D

class Strategy_ALTRUISTIC_103(BaseStrategy):
    """
    Implements a conditional cooperation strategy for the Collective Risk Dilemma.
    
    Logic:
    1. First round (round_number == 0): Always Cooperate (C).
    2. Subsequent rounds: Cooperate (C) if the total number of cooperators 
       (including self) in the previous round was >= m.
       Otherwise, Defect (D).
    
    Note: The 'opponent_cooperators' field gives the number of other players who 
    cooperated. To get the total number of cooperators, we must add 1 if 'we' 
    cooperated in the previous round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_opp_coops = history.opponent_cooperators[-1]
        i_cooperated = 1 if history.my_actions[-1] else 0
        total_cooperators = prev_opp_coops + i_cooperated
        if total_cooperators >= self.game_description.m:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_104(BaseStrategy):
    """
    Implements Adaptive Threshold-Reciprocal Altruism.
    Strategies:
    - Always C in Round 1.
    - If any round had zero cooperators, switches permanently to D (Collapse Clause).
    - If previous round failed (C_prev < m), plays C to recover.
    - If previous round was stable (C_prev == m), plays C to maintain threshold.
    - If previous round was surplus (C_prev > m), plays D to free-ride (or alternates).
    - In Terminal Round, plays C if majority of previous rounds succeeded, else D.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.has_collapsed = False
        self.alternating_buffer_toggle = False

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        last_my_action = history.my_actions[-1]
        last_total_cooperators = history.opponent_cooperators[-1] + (1 if last_my_action else 0)
        if last_total_cooperators == 0:
            self.has_collapsed = True
        if self.has_collapsed:
            return Action.D
        if current_round == self.desc.n_rounds - 1:
            success_count = 0
            for r in range(current_round):
                coop_count = history.opponent_cooperators[r] + (1 if history.my_actions[r] else 0)
                if coop_count >= self.desc.m:
                    success_count += 1
            if success_count > current_round / 2:
                return Action.C
            else:
                return Action.D
        if last_total_cooperators < self.desc.m:
            return Action.C
        if last_total_cooperators == self.desc.m:
            return Action.C
        if last_total_cooperators >= self.desc.m + 2:
            self.alternating_buffer_toggle = not self.alternating_buffer_toggle
            return Action.C if self.alternating_buffer_toggle else Action.D
        return Action.D

class Strategy_ALTRUISTIC_105(BaseStrategy):
    """
    Threshold-Conditional Reciprocal Altruism (TCRA).
    
    Fosters coordination toward the threshold 'm' by:
    1. Initializing with cooperation.
    2. Maintaining cooperation if the threshold was met.
    3. Punishing defection (switching to D if own contribution was C but threshold failed).
    4. Attempting 'rescue' (switching to C if threshold failed by only 1 and I was D).
    5. Applying a trend-based lookback in the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        prev_opponents_count = history.opponent_cooperators[-1]
        prev_total_coop = prev_opponents_count + (1 if my_prev_action else 0)
        if history.round_number == self.r - 1:
            total_history_coop = 0.0
            for i in range(history.round_number):
                opp_c = history.opponent_cooperators[i]
                me_c = 1 if history.my_actions[i] else 0
                total_history_coop += opp_c + me_c
            avg_coop = total_history_coop / history.round_number
            if avg_coop >= self.m / self.n:
                return Action.C
            else:
                return Action.D
        if prev_total_coop >= self.m:
            return Action.C
        if my_prev_action == Action.C:
            return Action.D
        deficit = self.m - prev_total_coop
        if deficit <= 1:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_106(BaseStrategy):
    """
    Implements a Conditional Tit-for-Tat with a Threshold-Trigger.
    - Seeds cooperation in the first round.
    - If threshold met: Tests for redundancy if contributing (probability 1/m), 
      otherwise continues defecting.
    - If threshold failed: Reverts to cooperation if necessary to reach m, 
      otherwise conserves resources.
    - Final round: Constrained altruism (cooperate only if necessary).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        my_last_action = Action.C if history.my_actions[-1] else Action.D
        others_cooperated = history.opponent_cooperators[-1]
        i_cooperated = 1 if my_last_action == Action.C else 0
        total_cooperators = others_cooperated + i_cooperated
        threshold_met = total_cooperators >= m
        if current_round == r - 1:
            if total_cooperators == m - 1:
                return Action.C
            return Action.D
        if threshold_met:
            if my_last_action == Action.C and total_cooperators == m:
                if random.random() < 1.0 / m:
                    return Action.D
                return Action.C
            return Action.D
        else:
            if total_cooperators == m - 1:
                return Action.C
            return Action.D

class Strategy_ALTRUISTIC_107(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that prioritizes group outcomes via conditional trust.
    
    Logic:
    - Round 1: Cooperate (Action.C).
    - Round > 1:
      - If the threshold (m) was met in the previous round, Cooperate (Action.C).
      - If the threshold was missed, Defect (Action.D) to recover losses, unless it's the final round where Defect is played regardless for utility maximization.
    - Robustness Logic:
      - Tracks consecutive successes (S).
      - If S > 1, enforces 'locked-in' cooperation (stays C even if the previous round failed due to a single vote).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_successes = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        my_last_action = int(history.my_actions[-1])
        last_total_cooperators = history.opponent_cooperators[-1] + my_last_action
        threshold_met = last_total_cooperators >= m
        if threshold_met:
            self.consecutive_successes += 1
        else:
            self.consecutive_successes = 0
        if self.consecutive_successes > 1:
            return Action.C
        if threshold_met:
            return Action.C
        if my_last_action == 1 and last_total_cooperators == m - 1:
            return Action.C
        if history.round_number == r - 1:
            return Action.D
        return Action.D

class Strategy_ALTRUISTIC_108(BaseStrategy):
    """
    Altruistic Threshold Reciprocator:
    Cooperates initially and when the group threshold is met. 
    If the group fails to meet the threshold, it defects unless the historical 
    cooperation average is sufficient, with periodic forced recovery attempts.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number + 1
        if current_round == 1:
            return Action.C
        last_cooperators = int(history.opponent_cooperators[-1])
        if current_round == self.r:
            return Action.C if last_cooperators >= self.m - 1 else Action.D
        if last_cooperators >= self.m:
            return Action.C
        if current_round % 5 == 0:
            return Action.C
        total_observed = np.sum(history.opponent_cooperators)
        expected_total = (current_round - 1) * self.m
        if total_observed < expected_total:
            return Action.D
        else:
            return Action.C

class Strategy_ALTRUISTIC_109(BaseStrategy):
    """
    A Tit-for-Tat with Threshold Sensitivity strategy. Maintains a state variable 'trust' (T)
    to regulate probabilistic cooperation. Adjusts T dynamically based on group 
    behavior relative to the critical threshold m.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.trust = 0.5
        self.is_low_trust_mode = False

    def __call__(self, history: PlayerHistory) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            if random.random() < 0.5:
                return Action.C
            return Action.D
        prev_my_action_bool = history.my_actions[-1]
        prev_c_obs = history.opponent_cooperators[-1]
        if self.trust < 0.2:
            self.is_low_trust_mode = True
            self.trust = 0.0
            my_contribution = 1 if prev_my_action_bool else 0
            if prev_c_obs + my_contribution >= self.game_description.m:
                self.trust = 0.3
                self.is_low_trust_mode = False
        else:
            self.is_low_trust_mode = False
        if not self.is_low_trust_mode:
            if prev_my_action_bool:
                if prev_c_obs >= self.game_description.m - 1:
                    self.trust = min(1.0, self.trust + 0.1)
                else:
                    self.trust = max(0.0, self.trust - 0.2)
            elif prev_c_obs >= self.game_description.m:
                self.trust = min(1.0, self.trust + 0.05)
            else:
                self.trust = max(0.0, self.trust - 0.1)
        if round_idx == self.game_description.n_rounds - 1:
            expected_others = (self.game_description.n_players - 1) * self.trust
            if expected_others >= self.game_description.m - 1:
                return Action.C
            else:
                return Action.D
        if self.is_low_trust_mode:
            return Action.D
        if random.random() < self.trust:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_110(BaseStrategy):
    """
    A strategy that uses a Conditional Threshold Trigger mechanism.
    - Initial phase: Cooperate.
    - Rounds 2 to r-1: Adjusts based on previous round's cooperation count C_{t-1}.
    - Terminal phase: Decides based on historical average of cooperation.
    - Adaptive Buffer: Maintains a 'Trust Index' to switch to permanent cooperation 
      or reset after consecutive failures.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.trust_index = 0
        self.consecutive_failures = 0
        self.is_unconditional_cooperator = False
        self.probing_mode = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        i_cooperated_last = 1 if history.my_actions[-1] else 0
        total_cooperators_last = history.opponent_cooperators[-1] + i_cooperated_last
        if total_cooperators_last > m:
            self.trust_index += 1
            self.consecutive_failures = 0
            self.probing_mode = False
        elif total_cooperators_last < m:
            self.consecutive_failures += 1
            if self.consecutive_failures >= 3:
                self.trust_index = 0
                self.probing_mode = True
        if self.trust_index >= r / 4:
            self.is_unconditional_cooperator = True
        if self.is_unconditional_cooperator:
            return Action.C
        if self.probing_mode:
            return Action.D
        if current_round == r - 1:
            my_history_arr = history.my_actions.astype(int)
            total_cooperators_history = history.opponent_cooperators + my_history_arr
            if np.mean(total_cooperators_history) >= m - 1:
                return Action.C
            else:
                return Action.D
        if total_cooperators_last >= m:
            return Action.C
        if total_cooperators_last == m - 1:
            prob = (m - 1) / n
            if random.random() < prob:
                return Action.C
            return Action.D
        return Action.D

class Strategy_ALTRUISTIC_111(BaseStrategy):
    """
    Implements a conditional cooperation strategy for the Collective Risk Dilemma.
    
    The strategy establishes a baseline of cooperation in the first round. 
    In subsequent rounds, it adapts to the group's performance: continuing 
    cooperation if the threshold is met or nearly met (gap <= 1), and 
    switching to defection if the collective effort fails significantly. 
    In the final round, it restricts cooperation to only those instances 
    where the previous round successfully met the threshold.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_opp_coop = history.opponent_cooperators[-1]
        my_prev_action_bool = history.my_actions[-1]
        c_prev = prev_opp_coop + (1 if my_prev_action_bool else 0)
        m = self.game_description.m
        r = self.game_description.n_rounds
        if history.round_number == r - 1:
            if c_prev >= m:
                return Action.C
            else:
                return Action.D
        if c_prev >= m:
            return Action.C
        else:
            gap = m - c_prev
            if gap <= 1:
                return Action.C
            else:
                return Action.D

class Strategy_ALTRUISTIC_112(BaseStrategy):
    """
    Threshold-Conditional Tit-for-Tat (TCTT)
    
    This strategy balances collective altruism with individual protection. It cooperates 
    when the collective goal is viable (or critical), and defects when the collective 
    effort is consistently failing or exploitation is detected.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.consecutive_failures = 0
        self.permanent_defection = False

    def __call__(self, history: PlayerHistory) -> Action:
        if self.permanent_defection:
            return Action.D
        if history.round_number == 0:
            return Action.C
        my_prev_action = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + my_prev_action
        if total_cooperators_prev < self.desc.m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 3:
            self.permanent_defection = True
            return Action.D
        if history.round_number == self.desc.n_rounds - 1:
            past_total_cooperators = history.opponent_cooperators + history.my_actions.astype(int)
            success_count = np.sum(past_total_cooperators >= self.desc.m)
            success_rate = success_count / history.round_number
            if success_rate > 0.5:
                return Action.C
            return Action.D
        if total_cooperators_prev >= self.desc.m:
            return Action.C
        elif self.desc.m - total_cooperators_prev == 1:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_113(BaseStrategy):
    """
    A strategy that starts by cooperating, then dynamically adjusts based on 
    the previous round's cooperation levels, incorporating a "Need Ratio" for recovery 
    and a persistent defection trigger for hostile environments.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.consecutive_failures = 0
        self.k_threshold = math.floor(self.desc.k)
        self.is_hostile = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        last_round_idx = history.round_number - 1
        last_cooperators = history.opponent_cooperators[last_round_idx]
        last_action = history.my_actions[last_round_idx]
        my_c_last = 1 if last_action else 0
        c_total_last = last_cooperators + my_c_last
        if c_total_last < self.desc.m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures >= self.k_threshold:
            self.is_hostile = True
        if self.is_hostile:
            return Action.D
        if history.round_number == self.desc.n_rounds - 1:
            if c_total_last >= self.desc.m:
                return Action.C
            else:
                return Action.D
        if c_total_last >= self.desc.m:
            return Action.C
        elif not last_action:
            return Action.D
        else:
            need_ratio = self.desc.m - c_total_last
            if need_ratio == 1:
                return Action.C if random.random() < 0.5 else Action.D
            else:
                return Action.D

class Strategy_ALTRUISTIC_114(BaseStrategy):
    """
    Conditional Threshold Reciprocity Strategy:
    Prioritizes the group outcome by maintaining cooperation as a baseline trust,
    dynamically adjusting to defect only when historical data indicates the group
    is consistently incapable of reaching the cooperation threshold m.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.nc = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            self.nc = 0
            return Action.C
        my_prev_action = int(history.my_actions[-1])
        total_cooperators_prev = history.opponent_cooperators[-1] + my_prev_action
        if total_cooperators_prev < m:
            self.nc += 1
        else:
            self.nc = 0
        if self.nc >= n:
            return Action.D
        if current_round == r - 1:
            total_history_c = np.sum(history.opponent_cooperators) + np.sum(history.my_actions)
            elapsed = current_round
            a_avg_n = total_history_c / elapsed
            if a_avg_n >= m - 1:
                return Action.C
            else:
                return Action.D
        if self.nc < 2:
            return Action.C
        total_history_c = np.sum(history.opponent_cooperators) + np.sum(history.my_actions)
        elapsed = current_round
        a_avg_n = total_history_c / elapsed
        if a_avg_n >= m:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_115(BaseStrategy):
    """
    Implements a Conditional Threshold Reciprocity strategy for the Collective Risk Dilemma.
    
    Logic summary:
    1. First round: Cooperate.
    2. Final round: Cooperate.
    3. Recovery Mode: If threshold was missed for the last two rounds, Cooperate for two rounds.
    4. Core Logic (otherwise):
       - If previous threshold met: Cooperate if I cooperated, Cooperate if I defected (signal commitment).
       - If previous threshold missed: Defect if I cooperated (punish group), Cooperate if I defected (incentivize).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.recovery_counter = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.C
        if history.round_number >= 2:
            last_round_missed = history.opponent_cooperators[-1] < self.game_description.m
            prev_round_missed = history.opponent_cooperators[-2] < self.game_description.m
            if last_round_missed and prev_round_missed:
                self.recovery_counter = 2
        if self.recovery_counter > 0:
            self.recovery_counter -= 1
            return Action.C
        last_round_cooperators = history.opponent_cooperators[-1]
        my_last_action = history.my_actions[-1]
        if last_round_cooperators >= self.game_description.m:
            return Action.C
        elif my_last_action:
            return Action.D
        else:
            return Action.C

class Strategy_ALTRUISTIC_116(BaseStrategy):
    """
    Threshold-Tit-for-Tat (TTFT): A conditional cooperation strategy that attempts 
    to coordinate reaching the threshold 'm' while punishing non-cooperative groups, 
    with a final round altruism check.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        previous_c = history.opponent_cooperators[-1]
        is_final_round = current_round == self.total_rounds - 1
        if previous_c >= self.m:
            return Action.C
        if previous_c == self.m - 1:
            return Action.C
        if previous_c < self.m - 1:
            if not is_final_round:
                return Action.D
            else:
                success_count = np.sum(history.opponent_cooperators >= self.m)
                success_rate = success_count / current_round
                if success_rate >= 0.5:
                    return Action.C
                else:
                    return Action.D
        return Action.D

class Strategy_ALTRUISTIC_117(BaseStrategy):
    """
    Threshold-Adaptive Reciprocity (TAR):
    A strategy that maintains a moving Trust Baseline (B_t) of collective cooperation.
    It adjusts contribution propensity (P_t) based on the group's ability to meet 
    the minimum cooperation threshold (m) and employs last-round safety logic.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.alpha = 0.1
        self.baseline = self.m / self.n

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_cooperators = int(history.opponent_cooperators[-1])
        if prev_cooperators == 0:
            self.baseline = 0.1
        else:
            self.baseline = (1.0 - self.alpha) * self.baseline + self.alpha * (prev_cooperators / self.n)
        is_last_round = history.round_number == self.r - 1
        if is_last_round:
            if self.baseline >= self.m / self.n:
                return Action.C
            else:
                return Action.D
        propensity = min(1.0, self.baseline * self.n / self.m)
        if random.random() <= propensity:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_118(BaseStrategy):
    """
    Threshold-Targeted Reciprocal Altruism: A strategy that balances individual 
    cost with the necessity of reaching threshold m. It behaves aggressively to 
    secure the collective benefit when the group is close to success, defects 
    when the group fails to coordinate, and maintains stable cooperation when 
    the reward is already being generated.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = self.game_description.n_players
        self.r = self.game_description.n_rounds
        self.m = self.game_description.m
        self.k = self.game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if self.m <= 1:
            return Action.C
        if history.round_number == 0:
            return Action.C if self.m > self.n / 2 else Action.D
        prev_idx = -1
        C_prev = int(history.opponent_cooperators[prev_idx])
        last_action_val = bool(history.my_actions[prev_idx])
        last_action = Action.C if last_action_val else Action.D
        t = history.round_number + 1
        if t == self.r:
            return Action.C if C_prev >= self.m - 1 else Action.D
        if C_prev >= self.m - 1:
            return Action.C
        if C_prev >= self.m and last_action == Action.C:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_119(BaseStrategy):
    """
    Threshold-Triggered Tit-for-Tat with Forgiving Reciprocity.
    
    Phased strategy:
    1. Initial Phase: Always cooperate.
    2. Operational Phase: Tit-for-tat based on threshold (m), with forgiveness if threshold met.
    3. Final Phase: Defect if the previous round failed the threshold, else cooperate.
    Includes logic for pivots and reward/cost evaluation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.is_punishing = False

    def __call__(self, history: PlayerHistory) -> Action:
        if self.desc.k < 1.0:
            return Action.D
        if history.round_number == 0:
            return Action.C
        n = self.desc.n_players
        m = self.desc.m
        r = self.desc.n_rounds
        my_prev_action = history.my_actions[-1]
        my_prev_c = 1 if my_prev_action == Action.C else 0
        s_prev = history.opponent_cooperators[-1] + my_prev_c
        round_idx = history.round_number
        is_final_round = round_idx == r - 1
        if is_final_round:
            if s_prev >= m:
                return Action.C
            else:
                return Action.D
        if self.is_punishing and s_prev >= m:
            self.is_punishing = False
            return Action.C
        if s_prev + 1 < m:
            self.is_punishing = True
            return Action.D
        if s_prev == m - 1 and my_prev_action == Action.D:
            self.is_punishing = False
            return Action.C
        if s_prev >= m:
            self.is_punishing = False
            return Action.C
        else:
            self.is_punishing = True
            return Action.D

class Strategy_ALTRUISTIC_120(BaseStrategy):
    """
    Implements a Conditional Tit-for-Tat with Threshold Sensitivity strategy.
    
    Logic:
    - Round 0: Cooperate (C) to signal intent.
    - Rounds 1 to r-2: 
        - If previous cooperation count >= m, Cooperate (C).
        - If previous cooperation count == m-1, Cooperate (C) to bridge the gap.
        - Otherwise, Defect (D) to conserve resources.
    - Final Round (r-1): Optimistic Finale.
        - If average historical cooperation >= (m + n) / 2, Cooperate (C).
        - Else, Defect (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        n = self.game_description.n_players
        if current_round == 0:
            return Action.C
        if current_round == total_rounds - 1:
            avg_coop = np.mean(history.opponent_cooperators)
            threshold = (m + n) / 2.0
            if avg_coop >= threshold:
                return Action.C
            else:
                return Action.D
        last_round_coop = history.opponent_cooperators[-1]
        if last_round_coop >= m:
            return Action.C
        elif last_round_coop == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_121(BaseStrategy):
    """
    Threshold-Tit-for-Tat (TTFT) Strategy:
    - Round 1: Always Cooperate.
    - Subsequent rounds:
        - If previous round met the threshold (N_c >= m), continue Cooperating.
        - If previous round failed (N_c < m), Defect, unless it is a 'recovery' round.
    - Recovery mechanism: Every floor(r/m) rounds, attempt to restart cooperation regardless of history.
    - Note: The pseudocode provided in requirements uses ceil(r/m), but the description says x = ceil(r/m). 
      We will use math.ceil as requested.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        rounds = self.game_description.n_rounds
        threshold = self.game_description.m
        self.restart_interval = max(1, math.ceil(rounds / threshold))

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_idx = history.round_number
        if current_round_idx == 0:
            return Action.C
        is_final_round = current_round_idx == self.game_description.n_rounds - 1
        if not is_final_round:
            if (current_round_idx + 1) % self.restart_interval == 0:
                return Action.C
        my_last_action = int(history.my_actions[-1])
        opponents_cooperated = history.opponent_cooperators[-1]
        total_cooperators_last_round = my_last_action + opponents_cooperated
        if total_cooperators_last_round >= self.game_description.m:
            return Action.C
        else:
            return Action.D

class Strategy_ALTRUISTIC_122(BaseStrategy):
    """
    Implements a Threshold Reciprocity with Forgiveness strategy.
    
    This strategy facilitates the collective success threshold (m) by:
    1. Signaling altruism in the first round.
    2. Maintaining cooperation if the group successfully met the threshold in the previous round.
    3. Acting as a "tipping point" player by cooperating if the group was exactly one short
       of the threshold in the previous round.
    4. Defecting otherwise to prevent exploitation.
    5. In the final round, prioritizing the potential for the final reward if the group 
       was close to success (m-1) in the penultimate round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number + 1
        my_last_action = history.my_actions[-1]
        my_last_contribution = 1 if my_last_action else 0
        last_total_cooperators = history.opponent_cooperators[-1] + my_last_contribution
        if current_round == r:
            if last_total_cooperators >= m - 1:
                return Action.C
            else:
                return Action.D
        if last_total_cooperators >= m:
            return Action.C
        if last_total_cooperators == m - 1:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_123(BaseStrategy):
    """
    Implements a strategy that cooperates by default but employs a recovery protocol 
    (one-round defect) if the cooperation threshold was not met in the previous round. 
    It ceases cooperation in the final round if the threshold was not met in the penultimate round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self._last_action = None

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_t = history.round_number + 1
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round_t == 1:
            action = Action.C
        elif current_round_t == total_rounds:
            previous_cooperators = history.opponent_cooperators[-1]
            my_prev_action_val = 1 if self._last_action == Action.C else 0
            total_previous_cooperators = previous_cooperators + my_prev_action_val
            if total_previous_cooperators >= m:
                action = Action.C
            else:
                action = Action.D
        else:
            previous_cooperators = history.opponent_cooperators[-1]
            my_prev_action_val = 1 if self._last_action == Action.C else 0
            total_previous_cooperators = previous_cooperators + my_prev_action_val
            if total_previous_cooperators >= m:
                action = Action.C
            elif self._last_action == Action.C:
                action = Action.D
            else:
                action = Action.C
        self._last_action = action
        return action

class Strategy_ALTRUISTIC_124(BaseStrategy):
    """
    A conditional contribution threshold strategy. 
    In the first round, it cooperates to signal willingness. 
    In subsequent rounds, it maintains cooperation if the threshold is met.
    If the threshold is missed, it adjusts based on whether it can marginally contribute to success.
    In the final round, it plays C if the threshold is within reach (m-1), otherwise D.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        current_round = history.round_number + 1
        total_rounds = self.desc.n_rounds
        m = self.desc.m
        my_prev_action = history.my_actions[-1]
        prev_my_c = 1 if my_prev_action == True else 0
        s_prev = prev_my_c + history.opponent_cooperators[-1]
        if current_round == total_rounds:
            if s_prev >= m - 1:
                return Action.C
            else:
                return Action.D
        if s_prev >= m:
            return Action.C
        if s_prev == m - 1:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_125(BaseStrategy):
    """
    Implements Conditional Threshold Reciprocity (CTR).
    
    Prioritizes achieving the cooperative threshold m by acting as a reliable 
    contributor, while safeguarding against exploitation through selective 
    conditional cooperation and periodic attempts to restart cooperation 
    if the group collapses.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.n = game_description.n_players
        self.m = game_description.m
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        last_obs = history.opponent_cooperators[-1]
        my_last_action = 1 if history.my_actions[-1] else 0
        total_cooperators_last_round = last_obs + my_last_action
        current_round = history.round_number
        if total_cooperators_last_round >= self.m:
            return Action.C
        if total_cooperators_last_round == self.m - 1:
            return Action.C
        if current_round % 5 == 0:
            return Action.C
        return Action.D

class Strategy_ALTRUISTIC_126(BaseStrategy):
    """
    Implements the Conditional Contribution Threshold (CCT) strategy.
    
    Logic:
    - Round 1: Always Cooperate (C).
    - Round R: Always Cooperate (C).
    - Intermediate Rounds:
        - If previous round threshold was met (total cooperators >= m), continue to Cooperate (C).
        - If previous round threshold failed (total cooperators < m), switch previous action:
            - If previously Cooperated, now Defect.
            - If previously Defected, now Cooperate.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n_players = self.game_description.n_players
        m = self.game_description.m
        total_rounds = self.game_description.n_rounds
        if current_round == 0:
            return Action.C
        if current_round == total_rounds - 1:
            return Action.C
        prev_round_index = -1
        c_self = 1 if history.my_actions[prev_round_index] else 0
        c_observed = int(history.opponent_cooperators[prev_round_index])
        total_cooperators = c_self + c_observed
        if total_cooperators >= m:
            return Action.C
        elif c_self == 1:
            return Action.D
        else:
            return Action.C

class Strategy_ALTRUISTIC_127(BaseStrategy):
    """
    A strategy that implements threshold-based conditional cooperation.
    It prioritizes initial cooperation, attempts to maintain threshold stability,
    utilizes a recovery mechanism for coordination errors, and adjusts behavior 
    based on the proximity to the payoff-triggering threshold 'm'.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.in_recovery_phase = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        k = self.game_description.k
        r = self.game_description.n_rounds
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        last_my_action = history.my_actions[-1]
        last_opponent_coops = history.opponent_cooperators[-1]
        last_total_coops = last_opponent_coops + (1 if last_my_action else 0)
        last_met_threshold = last_total_coops >= m
        if round_idx == r - 1:
            if last_total_coops >= m - 1:
                return Action.C
            return Action.D
        if round_idx > 1:
            prev_opp_coops = history.opponent_cooperators[-2]
            prev_my_action = history.my_actions[-2]
            prev_total_coops = prev_opp_coops + (1 if prev_my_action else 0)
            if prev_total_coops >= m and last_total_coops < m:
                self.in_recovery_phase = True
        if self.in_recovery_phase:
            self.in_recovery_phase = False
            return Action.C
        if k > 2.0 and last_total_coops >= m - 2:
            return Action.C
        if last_total_coops < m:
            if last_my_action:
                return Action.D
            else:
                if last_total_coops == m - 1:
                    return Action.C
                return Action.D
        elif last_my_action:
            return Action.C
        else:
            return Action.C

class Strategy_ALTRUISTIC_128(BaseStrategy):
    """
    Implements a conditional cooperation strategy based on the Collective Risk Dilemma threshold 'm'.
    Features include Tit-for-Tat inspired adjustments, probabilistic re-engagement, 
    swing-voter logic for near-threshold scenarios, and permanent defection upon 
    consistent total non-cooperation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_total_defect_rounds = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        last_round_idx = current_round - 1
        last_round_cooperators = history.opponent_cooperators[last_round_idx]
        my_last_action = history.my_actions[last_round_idx]
        if last_round_cooperators == 0:
            self.consecutive_total_defect_rounds += 1
        else:
            self.consecutive_total_defect_rounds = 0
        if self.consecutive_total_defect_rounds >= 2:
            return Action.D
        if last_round_cooperators == m - 1:
            return Action.C
        if current_round == r - 1:
            if last_round_cooperators >= m - 1:
                return Action.C
            else:
                return Action.D
        if last_round_cooperators >= m:
            return Action.C
        if last_round_cooperators < m:
            if my_last_action:
                punish_prob = (m - last_round_cooperators) / m
                if random.random() < punish_prob:
                    return Action.D
                else:
                    return Action.C
            else:
                rebuild_prob = last_round_cooperators / m
                if random.random() < rebuild_prob:
                    return Action.C
                else:
                    return Action.D
        return Action.D

class Strategy_BENEVOLENT_33(BaseStrategy):
    """
    Implements a strategy for the Collective Risk Dilemma that balances conditional
    cooperation, probabilistic risk-taking, and defection against persistent non-cooperators.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.persistent_defection_mode = False
        self.consecutive_zeros = 0

    def __call__(self, history: PlayerHistory) -> Action:
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        prev_s = history.opponent_cooperators[-1]
        if prev_s == 0:
            self.consecutive_zeros += 1
        else:
            self.consecutive_zeros = 0
            self.persistent_defection_mode = False
        if self.consecutive_zeros >= 2:
            self.persistent_defection_mode = True
        if self.persistent_defection_mode:
            return Action.D
        if prev_s >= m:
            return Action.C
        if current_round == r - 1:
            return Action.C
        p_t = min(1.0, float(prev_s) / float(m))
        if random.random() < p_t:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_34(BaseStrategy):
    """
    A strategy for Collective Risk Dilemma that transitions through three phases:
    1. Initial trust-building: Always C.
    2. Adaptive cooperation: C if collective cooperation history is above a threshold, else D.
    3. Final round: C if threshold met in >= 50% of previous rounds, else D.
    Includes specific edge case handling for near-misses, total collapse, and futility.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.cooperation_history = []
        self.my_history = []

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n = self.desc.n_players
        r = self.desc.n_rounds
        m = self.desc.m
        if current_round > 0:
            my_last_action = history.my_actions[-1]
            others_cooperated = history.opponent_cooperators[-1]
            total_cooperators = others_cooperated + (1 if my_last_action else 0)
            self.cooperation_history.append(total_cooperators)
            self.my_history.append(my_last_action)
        if current_round > 0 and self.cooperation_history[-1] == 0:
            return Action.D
        if current_round > 0 and current_round < r - 1:
            if self.cooperation_history[-1] == m - 1:
                return Action.C
        phase1_end = max(math.ceil(r / 4), 2)
        if current_round < phase1_end:
            return Action.C
        if current_round == r - 1:
            if not self.cooperation_history:
                return Action.D
            success_rounds = sum((1 for count in self.cooperation_history if count >= m))
            if success_rounds >= 0.5 * len(self.cooperation_history):
                return Action.C
            else:
                return Action.D
        avg_coop = sum(self.cooperation_history) / len(self.cooperation_history)
        threshold_rate = m / n
        if avg_coop >= threshold_rate * 0.8:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_35(BaseStrategy):
    """
    Implements a Threshold Tit-for-Tat strategy for the Collective Risk Dilemma.
    
    Logic:
    - t=0 (Round 1): Cooperate (C).
    - t=r-1 (Last Round): Cooperate if average cooperation rate was >= m/n, else Defect (D).
    - t > 0 and t < r-1: 
        - If previous round met threshold (>= m), defect with probability p = 1 - (m/C_prev), else Cooperate.
        - If previous round missed threshold, Cooperate.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n = self.desc.n_players
        m = self.desc.m
        r = self.desc.n_rounds
        if current_round == 0:
            return Action.C
        if current_round == r - 1:
            total_coop = np.sum(history.opponent_cooperators)
            avg_coop_rate = total_coop / current_round
            return Action.C if avg_coop_rate >= m / n else Action.D
        prev_coop = int(history.opponent_cooperators[-1])
        if prev_coop >= m:
            prob_defect = 1.0 - m / prev_coop
            if random.random() < prob_defect:
                return Action.D
            return Action.C
        return Action.C

class Strategy_BENEVOLENT_36(BaseStrategy):
    """
    A Tit-for-Tat based strategy with a probabilistic threshold response for the Collective Risk Dilemma.
    Prioritizes cooperation initially, uses probabilistic defect responses when the group threshold (m)
    is missed, and includes specific re-trust and 'almost' threshold logic.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_coop_count = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        total_coop_prev = prev_coop_count + (1 if my_prev_action else 0)
        if history.round_number >= 3:
            recent_hist = [history.opponent_cooperators[i] + (1 if history.my_actions[i] else 0) for i in range(-3, 0)]
            if all((count < self.m for count in recent_hist)):
                return Action.D
        if history.round_number == self.r - 1:
            total_rounds = history.round_number
            success_count = 0
            for i in range(total_rounds):
                c_i = history.opponent_cooperators[i] + (1 if history.my_actions[i] else 0)
                if c_i >= self.m:
                    success_count += 1
            if success_count / total_rounds >= 0.75:
                return Action.C
            return Action.D
        if total_coop_prev >= self.m and (not my_prev_action):
            return Action.C
        if total_coop_prev == self.m - 1 and (not my_prev_action):
            return Action.C
        if total_coop_prev >= self.m:
            return Action.C
        p_d = max(0.0, (self.m - total_coop_prev) / self.m)
        if random.random() < p_d:
            return Action.D
        return Action.C

class Strategy_BENEVOLENT_37(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that prioritizes conditional cooperation 
    to achieve the threshold m. It starts by cooperating. In subsequent rounds, 
    it attempts to sustain cooperation if the threshold was met, or attempts to 
    bridge the gap (cooperate) if the threshold was narrowly missed.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        last_round_idx = -1
        last_my_action = history.my_actions[last_round_idx]
        last_opp_cooperators = history.opponent_cooperators[last_round_idx]
        total_cooperators = last_opp_cooperators + (1 if last_my_action else 0)
        threshold_met = total_cooperators >= self.m
        if threshold_met:
            return Action.C
        elif total_cooperators >= self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_38(BaseStrategy):
    """
    A strategy that aims to maintain cooperation levels at exactly m.
    It cooperates in the first round, and subsequently tries to reach 
    the threshold m by cooperating if the group failed in the previous round, 
    but defects if the group is meeting or exceeding the threshold 
    (free-riding) or if it is the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.n = game_description.n_players
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.r - 1:
            return Action.D
        last_my_action = history.my_actions[-1]
        last_opponent_coop = history.opponent_cooperators[-1]
        c_prev = last_opponent_coop + (1 if last_my_action else 0)
        if c_prev < self.m:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_39(BaseStrategy):
    """
    Implements the Threshold-Targeted Reciprocity (TTR) strategy.
    
    TTR dynamically adjusts contributions to maintain the threshold m.
    It attempts to cooperate to reach m, but switches to defection if 
    sustained failure is detected or if over-contribution occurs.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.consecutive_failures = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_round = history.round_number - 1
        my_prev_action_val = 1 if history.my_actions[prev_round] else 0
        total_prev_c = history.opponent_cooperators[prev_round] + my_prev_action_val
        if total_prev_c < self.m - 1:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 2:
            return Action.D
        if history.round_number == self.r - 1:
            all_prev_c = history.opponent_cooperators + history.my_actions.astype(int)
            avg_c = np.mean(all_prev_c)
            if avg_c >= self.m - 1:
                return Action.C
            else:
                return Action.D
        if total_prev_c >= self.m:
            if total_prev_c - 1 >= self.m:
                return Action.D
            else:
                return Action.C
        else:
            return Action.C

class Strategy_BENEVOLENT_40(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that dynamically adjusts cooperation probability based 
    on group performance history, with a benevolent override for potential future gains and a
    last-round specific heuristic.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.p = 1.0
        self.coop_count_history = []

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        k = self.game_description.k
        current_round = history.round_number
        my_last_action = int(history.my_actions[-1])
        c_prev = history.opponent_cooperators[-1] + my_last_action
        self.coop_count_history.append(c_prev)
        total_cooperative_rounds = sum((1 for c in self.coop_count_history if c >= m))
        remaining_rounds = r - current_round
        if total_cooperative_rounds < current_round / 4 and k * remaining_rounds > 1.0:
            return Action.C
        if current_round == r - 1:
            if c_prev >= m - 1:
                return Action.C
            return Action.D
        if c_prev == m:
            self.p = min(1.0, self.p + 0.1)
        elif c_prev > m:
            pass
        elif c_prev < m:
            if c_prev < m - 1:
                self.p = max(0.0, self.p - 0.2)
        if current_round < 3 and self.p == 1.0:
            self.p = 0.5
        return Action.C if random.random() < self.p else Action.D

class Strategy_BENEVOLENT_41(BaseStrategy):
    """
    Implements an adaptive Tit-for-Tat style strategy for the Collective Risk Dilemma.
    - Round 0: Cooperate.
    - Post-Round 0: Tracks group cooperation threshold 'm'.
      - If threshold was met: Cooperate.
      - If threshold failed: Defect, unless probe logic dictates otherwise.
    - Recovery Mechanism: If the previous round failed (C < m), attempts a probe in the next round. If the probe fails, switches to permanent defection.
    - Terminal Boundary: On the final round, plays conservatively based on previous round success.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.permanently_defected = False
        self.in_recovery_probe = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        last_round = r - 1
        if current_round == 0:
            return Action.C
        prev_my_action = history.my_actions[-1]
        prev_opp_coop = history.opponent_cooperators[-1]
        prev_total_coop = prev_opp_coop + (1 if prev_my_action else 0)
        if current_round == last_round:
            return Action.C if prev_total_coop >= m else Action.D
        if self.permanently_defected:
            return Action.D
        if self.in_recovery_probe:
            if prev_total_coop >= m:
                self.in_recovery_probe = False
                return Action.C
            else:
                self.permanently_defected = True
                self.in_recovery_probe = False
                return Action.D
        if prev_total_coop >= m:
            return Action.C
        else:
            self.in_recovery_probe = True
            return Action.C

class Strategy_BENEVOLENT_42(BaseStrategy):
    """
    A Tit-for-Tat variant for threshold public goods. It initiates with cooperation,
    persists as long as the threshold 'm' is met, attempts to recover the threshold
    if it was missed by only one player, and occasionally uses a stochastic re-test
    mechanism if the project has stalled.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        prev_round_index = current_round - 1
        num_cooperators_prev = history.opponent_cooperators[prev_round_index]
        my_prev_action = history.my_actions[prev_round_index]
        total_cooperators_prev = num_cooperators_prev + (1 if my_prev_action else 0)
        if current_round == self.r - 1:
            if total_cooperators_prev >= self.m:
                return Action.C
            else:
                return Action.D
        if total_cooperators_prev >= self.m:
            return Action.C
        if total_cooperators_prev == self.m - 1:
            return Action.C
        remaining_rounds = self.r - current_round
        if remaining_rounds > 0 and random.random() < 1.0 / remaining_rounds:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_43(BaseStrategy):
    """
    Threshold-Conditional Tit-for-Tat strategy for the Collective Risk Dilemma.
    Maintains a 'Status' state ('Trusting' or 'Cautious') to navigate cooperative thresholds.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.status = 'Trusting'
        self.m = game_description.m
        self.target_t = self.m + 1
        self.n_total = game_description.n_players

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        last_my_action = history.my_actions[-1]
        last_opp_coop = history.opponent_cooperators[-1]
        total_cooperators_prev = last_opp_coop + (1 if last_my_action else 0)
        is_final_round = history.round_number == self.game_description.n_rounds - 1
        last_payoff = history.my_payoffs[-1]
        was_exploited = last_my_action and total_cooperators_prev == self.m
        if is_final_round:
            if total_cooperators_prev >= self.m:
                return Action.C
            else:
                return Action.D
        if was_exploited:
            self.status = 'Cautious'
            return Action.D
        if self.status == 'Trusting':
            if total_cooperators_prev < self.m:
                self.status = 'Cautious'
                return Action.D
            else:
                return Action.C
        elif self.status == 'Cautious':
            if total_cooperators_prev >= self.m:
                self.status = 'Trusting'
                return Action.C
            else:
                return Action.D
        return Action.C

class Strategy_BENEVOLENT_44(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that employs a mix of cooperative
    threshold maintenance, conditional cooperation, and desperation-based moves.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.n = self.desc.n_players
        self.m = self.desc.m
        self.r = self.desc.n_rounds
        self.k = self.desc.k
        self.alpha = 0.8
        self.p_hat = self.m / self.n
        self.consecutive_low_coop = 0
        self.buffer = math.floor((self.n - self.m) / self.n * self.r)

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        t = current_round + 1
        if t == 1:
            return Action.C
        last_others = history.opponent_cooperators[-1]
        last_my_action = int(history.my_actions[-1])
        N_last = last_others + last_my_action
        self.p_hat = self.alpha * self.p_hat + (1 - self.alpha) * (N_last / self.n)
        if N_last / self.n < self.m / self.n:
            self.consecutive_low_coop += 1
        else:
            self.consecutive_low_coop = 0
        is_desperate = False
        if t > self.r - 2:
            if current_round >= 2:
                prev_N = history.opponent_cooperators[-2] + int(history.my_actions[-2])
                if N_last < self.m and prev_N < self.m:
                    is_desperate = True
            elif current_round == 1:
                if N_last < self.m:
                    is_desperate = True
        if is_desperate:
            return Action.C
        if self.consecutive_low_coop >= 3:
            return Action.C if N_last >= self.m else Action.D
        if N_last >= self.m:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_45(BaseStrategy):
    """
    Implements a Conditional Threshold-Triggered Contribution strategy.
    
    This strategy focuses on sustaining cooperation when the group environment is
    supportive, while protecting the player from exploitation during chronic defection
    or terminal game stages.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_my_action = int(history.my_actions[-1])
        prev_opp_cooperators = history.opponent_cooperators[-1]
        prev_total_cooperators = prev_my_action + prev_opp_cooperators
        n_completed = history.round_number
        success_count = 0
        for r in range(n_completed):
            total_r = int(history.my_actions[r]) + history.opponent_cooperators[r]
            if total_r >= self.game_description.m:
                success_count += 1
        success_rate = success_count / n_completed
        if prev_total_cooperators >= self.game_description.m:
            return Action.C
        if n_completed == self.game_description.n_rounds:
            return Action.D
        if success_rate > 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_46(BaseStrategy):
    """
    Adaptive Threshold Trigger (ATT) Strategy:
    - Round 1: Cooperates with probability p = m/n.
    - Rounds 2 to r-1: Adapts based on the previous round's total cooperation.
      - If C_total >= m: Cooperate.
      - If C_total < m:
        - If deficit d == 1: Cooperate.
        - If d > 1: Defect.
    - Round r (Terminal): Cooperate if C_total >= m in >= 50% of history, else Defect.
    - Handles Edge Cases: Zero Cooperation -> Defect; Perfect Cooperation -> Cooperate.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            prob_cooperate = self.m / self.n
            if random.random() < prob_cooperate:
                return Action.C
            return Action.D
        my_last_action_val = 1 if history.my_actions[-1] else 0
        c_total_last = history.opponent_cooperators[-1] + my_last_action_val
        if c_total_last == self.n:
            return Action.C
        if c_total_last == 0:
            return Action.D
        if history.round_number == self.total_rounds - 1:
            my_action_history = history.my_actions.astype(int)
            total_history = history.opponent_cooperators + my_action_history
            successful_rounds = np.sum(total_history >= self.m)
            if successful_rounds / history.round_number >= 0.5:
                return Action.C
            return Action.D
        if c_total_last >= self.m:
            return Action.C
        else:
            deficit = self.m - c_total_last
            if deficit == 1:
                return Action.C
            else:
                return Action.D

class Strategy_BENEVOLENT_47(BaseStrategy):
    """
    Implements a trust-based adaptive strategy for the Collective Risk Dilemma.
    Adjusts cooperativeness based on historical threshold success, with specific 
    end-game behavior and benevolent triggers for near-threshold scenarios.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.trust_level = 1.0

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n = self.game_description.n_players
        m = self.game_description.m
        if current_round == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        my_prev_contribution = 1 if my_prev_action else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + my_prev_contribution
        threshold_met = total_cooperators_prev >= m
        if threshold_met:
            self.trust_level = min(1.0, self.trust_level + 0.1)
        else:
            self.trust_level = max(0.0, self.trust_level - 0.2)
        rounds_remaining = self.game_description.n_rounds - current_round
        if rounds_remaining <= 2:
            p_c = self.trust_level * 0.5
        else:
            p_c = self.trust_level
        if total_cooperators_prev == m - 1:
            p_c += 0.3
        p_c = max(0.0, min(1.0, p_c))
        if random.random() < p_c:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_48(BaseStrategy):
    """
    Threshold-Targeted Conditional Reciprocity strategy for the Collective Risk Dilemma.
    Maintains a target cooperative threshold (m) to maximize collective payoff.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self._role_idx = random.randint(1, self.game_description.n_players)
        self._consecutive_below_threshold = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C if self._role_idx <= m else Action.D
        my_prev_action = history.my_actions[-1]
        my_prev_val = 1 if my_prev_action == Action.C else 0
        prev_opponents = history.opponent_cooperators[-1]
        prev_total_coops = prev_opponents + my_prev_val
        if prev_total_coops < m:
            self._consecutive_below_threshold += 1
        else:
            self._consecutive_below_threshold = 0
        if self._consecutive_below_threshold >= 2:
            return Action.C
        if current_round == r - 1:
            if prev_total_coops >= m:
                return Action.D
            if prev_total_coops == m - 1:
                return Action.C
            return Action.D
        if prev_total_coops >= m:
            if my_prev_action == Action.C:
                return Action.D
            return Action.D
        if prev_total_coops < m:
            needed = m - prev_total_coops
            if needed <= 1:
                return Action.C
            gap = m - (prev_total_coops - my_prev_val)
            prob = min(1.0, gap / (n - 1))
            return Action.C if random.random() < prob else Action.D
        return Action.D

class Strategy_BENEVOLENT_49(BaseStrategy):
    """
    Implements a Tit-for-Tat with Threshold Sensitivity strategy.
    
    Logic:
    - Round 1: Cooperate.
    - Round t > 1:
        1. If previous round met threshold (>= m), maintain previous action.
        2. If previous round was m-1, cooperate (Threshold Boundary nudge).
        3. If failed significantly (< m-1), punish by defecting (unless consistently failing, then exit).
        4. Exploitation Protection: If I defected last round while threshold met (payoff=3), switch to C.
    - Final Round: If historical avg cooperation >= m/n, cooperate, else defect.
    - Persistent Defection: If failed 3 rounds in a row, defect for remainder.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.desc.n_players
        r = self.desc.n_rounds
        m = self.desc.m
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == r - 1:
            total_coop_counts = history.opponent_cooperators + history.my_actions.astype(int)
            avg_coop = np.mean(total_coop_counts) / n
            return Action.C if avg_coop >= m / n else Action.D
        last_total_C = history.opponent_cooperators[-1] + int(history.my_actions[-1])
        last_my_action = int(history.my_actions[-1])
        last_my_payoff = history.my_payoffs[-1]
        if len(history.opponent_cooperators) >= 3:
            recent_C = history.opponent_cooperators[-3:] + history.my_actions[-3:].astype(int)
            if all((c < m for c in recent_C)):
                return Action.D
        if last_my_action == 0 and last_total_C >= m:
            return Action.C
        if last_total_C >= m:
            return Action(last_my_action)
        if last_total_C == m - 1:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_50(BaseStrategy):
    """
    Threshold-Targeting Conditional Cooperation:
    A Tit-for-Tat variant designed to reach threshold m, while managing
    resources and penalizing non-contribution effectively.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.failure_streak = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            prob = self.m / self.n
            return Action.C if random.random() < prob else Action.D
        prev_round = history.round_number - 1
        my_prev_action = Action.C if history.my_actions[prev_round] else Action.D
        total_cooperators_prev = history.opponent_cooperators[prev_round] + (1 if my_prev_action == Action.C else 0)
        if total_cooperators_prev < self.m:
            self.failure_streak += 1
        else:
            self.failure_streak = 0
        if history.round_number > self.r / 2 and self.failure_streak > 0:
            return Action.D
        if self.failure_streak >= 2:
            self.failure_streak = 0
            return Action.C
        if history.round_number == self.r - 1:
            if my_prev_action == Action.C and total_cooperators_prev == self.m:
                return Action.C
            return Action.D
        if total_cooperators_prev >= self.m:
            if total_cooperators_prev > self.m:
                return Action.D
            return my_prev_action
        else:
            if my_prev_action == Action.C:
                return Action.D
            return Action.D

class Strategy_BENEVOLENT_51(BaseStrategy):
    """
    The Threshold-Responsive Trigger (TRT) strategy implements conditional cooperation.
    It prioritizes meeting the threshold 'm' for collective rewards.
    - Round 1: Always Cooperate (C).
    - Rounds 2 to r-1: 
        - If previous round N_c >= m, continue C.
        - If previous round N_c >= m-1, contribute C to try and reach threshold.
        - If previous round N_c < m-1, Defect (D) to conserve resources.
        - Includes an escape hatch: If failed to reach 'm' for 3 consecutive rounds, 
          switch to Defect until signals improve.
    - Terminal Round: Evaluates the historical success rate to decide whether to 
      make a final attempt at cooperation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            self.consecutive_failures = 0
            return Action.C
        my_prev_action_val = 1 if history.my_actions[-1] else 0
        n_c_prev = history.opponent_cooperators[-1] + my_prev_action_val
        m = self.game_description.m
        if n_c_prev < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if history.round_number == self.game_description.n_rounds - 1:
            all_n_c = history.opponent_cooperators + history.my_actions.astype(int)
            avg_success = np.mean(all_n_c >= m)
            if avg_success > 0.5:
                return Action.C
            return Action.D
        if self.consecutive_failures >= 3 and n_c_prev < m - 1:
            return Action.D
        if n_c_prev >= m:
            return Action.C
        elif n_c_prev >= m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_52(BaseStrategy):
    """
    A 'Conditional Trigger with Forgiveness' strategy for the Collective Risk Dilemma.
    Prioritizes maintaining the cooperation threshold 'm' to secure rewards,
    punishes defectors when the threshold is not met, but allows for forgiveness
    and recovery if the group is near the threshold or by random chance.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.p_restart = 0.1

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n_rounds = self.desc.n_rounds
        m = self.desc.m
        if current_round == 0:
            return Action.C
        if current_round == n_rounds - 1:
            prev_cooperators = history.opponent_cooperators[-1]
            my_prev_action_val = 1 if history.my_actions[-1] else 0
            total_C_prev = prev_cooperators + my_prev_action_val
            if total_C_prev >= m:
                return Action.C
            else:
                return Action.D
        prev_cooperators = history.opponent_cooperators[-1]
        my_prev_action_val = 1 if history.my_actions[-1] else 0
        total_C_prev = prev_cooperators + my_prev_action_val
        if total_C_prev >= m:
            return Action.C
        if total_C_prev >= m - 1 or random.random() < self.p_restart:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_53(BaseStrategy):
    """
    A sophisticated strategy for the Collective Risk Dilemma that balances 
    threshold maintenance (m), retaliation for poor cooperation (Tit-for-Tat),
    and adaptive generosity based on recent history to stabilize cooperation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_round = history.round_number - 1
        my_prev_action = history.my_actions[-1]
        n_c = int(history.opponent_cooperators[-1]) + (1 if my_prev_action else 0)
        if history.round_number == self.game.n_rounds - 1:
            if n_c >= self.m:
                return Action.C
            else:
                return Action.D
        if history.round_number >= 3:
            recent_counts = []
            for i in range(prev_round, prev_round - 3, -1):
                opp_c = int(history.opponent_cooperators[i])
                my_c = 1 if history.my_actions[i] else 0
                recent_counts.append(opp_c + my_c)
            if n_c == self.m:
                mean_counts = sum(recent_counts) / 3
                if abs(n_c - mean_counts) > 0.5:
                    return Action.C
            if n_c < self.m:
                prob = n_c / self.m
                if random.random() < prob:
                    return Action.C
                else:
                    return Action.D
            elif n_c >= self.m:
                return Action.C
        if n_c >= self.m:
            return Action.C
        if n_c == self.m or n_c == self.m + 1:
            return Action.C
        if n_c < self.m - 2:
            if history.round_number > 1:
                prev_n_c = int(history.opponent_cooperators[-2]) + (1 if history.my_actions[-2] else 0)
                if prev_n_c < self.m - 2:
                    return Action.C
            return Action.D
        return Action.D

class Strategy_BENEVOLENT_54(BaseStrategy):
    """
    Threshold-Adaptive Reciprocity (TAR):
    Prioritizes achieving threshold 'm' to maximize collective reward 'k'.
    Initiates with cooperation, then adapts based on the previous round's outcome:
    - If threshold met: maintains cooperation, but tests stability if exactly at threshold.
    - If threshold missed: pivots if pivotal, punishes if failure persists, or conserves if group effort is low.
    - Final round: prioritizes cooperation unless consistent failure is detected.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        m = self.game_description.m
        round_num = history.round_number
        if round_num == 0:
            return Action.C
        last_round_idx = round_num - 1
        last_c_count = history.opponent_cooperators[last_round_idx]
        my_last_action_val = 1 if history.my_actions[last_round_idx] else 0
        total_cooperators = last_c_count + my_last_action_val
        if round_num == r - 1:
            failures = 0
            for i in range(round_num):
                c_count = history.opponent_cooperators[i] + (1 if history.my_actions[i] else 0)
                if c_count < m:
                    failures += 1
            if failures >= r - 2 and r - 2 > 0:
                return Action.D
            return Action.C
        if total_cooperators >= m:
            if total_cooperators == m and my_last_action_val == 1:
                return Action.D
            return Action.C
        else:
            if total_cooperators < m - 1:
                return Action.D
            elif total_cooperators == m - 1:
                if my_last_action_val == 0:
                    return Action.C
                else:
                    return Action.D
            return Action.D

class Strategy_BENEVOLENT_55(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that acts as a Conditional Cooperator
    with a 'Recovery' trigger. 
    
    Logic:
    - Always cooperates on the first round.
    - On subsequent rounds:
        - If the previous round's total count of cooperators met or exceeded the 
          threshold (m), the strategy continues to cooperate.
        - If the threshold was not met, the strategy defects to protect its endowment.
        - If currently defecting, the strategy monitors if the threshold is met 
          by others (or spontaneously) and immediately reverts to cooperation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        last_c_count = int(history.opponent_cooperators[-1])
        if last_c_count >= self.m:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_56(BaseStrategy):
    """
    Implements a conditional threshold reciprocity strategy for the Collective Risk Dilemma.
    Prioritizes meeting the threshold m, adapts to failure by protecting utility, 
    and incorporates a 'gap of 1' recovery heuristic.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_round_idx = history.round_number - 1
        my_prev_action = history.my_actions[prev_round_idx]
        c_i_prev = 1 if my_prev_action else 0
        c_total_prev = history.opponent_cooperators[prev_round_idx] + c_i_prev
        m = self.game_description.m
        if c_total_prev < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 2:
            self.consecutive_failures = 0
            return Action.C
        if c_total_prev == m - 1:
            return Action.C
        if c_total_prev >= m:
            return Action.C
        else:
            if c_i_prev == 1 and m - c_total_prev > 1:
                return Action.D
            if c_i_prev == 0:
                return Action.D
            return Action.C

class Strategy_BENEVOLENT_57(BaseStrategy):
    """
    A threshold-seeking Tit-for-Tat variant that balances cooperation with 
    punishment/reset mechanisms based on group success signals (c_prev).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.n = game_description.n_players
        self.failure_streak = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            self.failure_streak = 0
            return Action.C
        c_prev_count = history.opponent_cooperators[-1]
        my_prev_action_val = 1 if history.my_actions[-1] else 0
        c_total_prev = c_prev_count + my_prev_action_val
        if c_total_prev < self.m:
            self.failure_streak += 1
        else:
            self.failure_streak = 0
        if history.round_number == self.r - 1:
            avg_coop = np.mean(history.opponent_cooperators + history.my_actions.astype(int))
            if avg_coop >= self.m:
                return Action.C
            return Action.D
        if self.failure_streak >= 3 and my_prev_action_val == 0:
            return Action.C
        if history.round_number >= 3:
            recent_counts = (history.opponent_cooperators + history.my_actions.astype(int))[-3:]
            is_volatile = np.all((recent_counts == self.m - 1) | (recent_counts == self.m + 1))
            if is_volatile:
                return Action.C
        if c_total_prev >= self.m:
            return Action.C
        elif my_prev_action_val == 1:
            return Action.D
        else:
            remaining = self.r - history.round_number
            p = 1.0 / remaining if remaining > 0 else 0
            if random.random() < p:
                return Action.C
            return Action.D

class Strategy_BENEVOLENT_58(BaseStrategy):
    """
    Implements a Threshold-seeking strategy for the Collective Risk Dilemma.
    Maintains an active cooperation status, attempts to meet the threshold 'm' 
    if deficit is 1, and defects if consistently exploited or if the threshold
    is deemed unreachable.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.cooperation_status = True
        self.consecutive_failed_cooperation = 0

    def __call__(self, history: PlayerHistory) -> Action:
        round_t = history.round_number
        m = self.game_description.m
        if round_t == 0:
            return Action.C
        last_n_cooperators = history.opponent_cooperators[-1] + int(history.my_actions[-1])
        if history.my_actions[-1] == True and last_n_cooperators < m:
            self.consecutive_failed_cooperation += 1
        else:
            self.consecutive_failed_cooperation = 0
        if self.consecutive_failed_cooperation >= 3:
            self.cooperation_status = False
        if round_t == self.game_description.n_rounds - 1:
            if last_n_cooperators >= m:
                return Action.C
            return Action.D
        if not self.cooperation_status:
            return Action.D
        if last_n_cooperators >= m:
            if history.my_actions[-1] == True or last_n_cooperators == m:
                return Action.C
            return Action.D
        deficit = m - last_n_cooperators
        if deficit == 1:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_59(BaseStrategy):
    """
    Implements Conditional Threshold Reciprocity.
    Balances contribution to a threshold m with defection when threshold is secure,
    including logic for threshold recovery and altruistic triggers.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.n = self.desc.n_players
        self.m = self.desc.m
        self.r = self.desc.n_rounds

    def _get_total_c(self, round_idx: int, history: PlayerHistory) -> int:
        c_i = 1 if history.my_actions[round_idx] else 0
        return history.opponent_cooperators[round_idx] + c_i

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        n = self.n
        m = self.m
        r = self.r
        if t == 0:
            prob = m / n
            if m / n >= 0.5:
                return Action.C
            return Action.C if random.random() < prob else Action.D
        total_cs = [self._get_total_c(i, history) for i in range(t)]
        avg_c = sum(total_cs) / t
        if t >= 2 and avg_c < m and (total_cs[-1] < m):
            return Action.C
        if avg_c > m + (n - m) / 2:
            return Action.D
        if t == r - 1:
            if avg_c < m:
                return Action.C
            return Action.D
        prev_c_total = total_cs[-1]
        if avg_c < m:
            return Action.C
        if avg_c >= m:
            if prev_c_total >= m:
                return Action.D
            else:
                return Action.C
        return Action.D

class Strategy_BENEVOLENT_60(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that utilizes a conditional 
    'Win-Stay, Lose-Shift' mechanism, adjusted for threshold-based public 
    goods provision. It focuses on maintaining the m-cooperator threshold, 
    probabilistically testing cooperation after failures, and cutting losses 
    if the group fails to cooperate.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_zero_rounds = 0

    def __call__(self, history: PlayerHistory) -> Action:
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        total_cooperators_prev = prev_cooperators + (1 if my_prev_action else 0)
        if total_cooperators_prev == 0:
            self.consecutive_zero_rounds += 1
        else:
            self.consecutive_zero_rounds = 0
        if self.consecutive_zero_rounds >= 2:
            return Action.D
        if current_round == r - 1:
            if len(history.my_actions) > 1:
                successes = 0
                for i in range(len(history.my_actions)):
                    opps = history.opponent_cooperators[i]
                    my_act = history.my_actions[i]
                    if opps + (1 if my_act else 0) >= m:
                        successes += 1
                if successes / len(history.my_actions) >= 0.5:
                    return Action.C
                else:
                    return Action.D
            return Action.C
        if total_cooperators_prev == m - 1:
            return Action.C
        success = total_cooperators_prev >= m
        if success:
            return Action.C
        elif not my_prev_action:
            return Action.D
        else:
            prob_defect = 1.0 - total_cooperators_prev / m if m > 0 else 1.0
            if random.random() < prob_defect:
                return Action.D
            else:
                return Action.C

class Strategy_BENEVOLENT_61(BaseStrategy):
    """
    Implements a Conditional Threshold strategy for the Collective Risk Dilemma.
    
    Logic Summary:
    1. Round 1: Always Cooperate (C).
    2. Rounds 2 to r-1: 
       - If previous round cooperators (C_{t-1}) >= m: Cooperate.
       - If C_{t-1} < m: Defect (D).
       - Edge Case (Nudge): If C_{t-1} == m-1, force C to help cross the threshold.
       - Edge Case (Reset): If previous outcome was m-1 (and we defected), force C to reset.
    3. Final Round: Always Cooperate (C).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.C
        m = self.game_description.m
        prev_cooperators = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        total_cooperators_prev = prev_cooperators + (1 if my_prev_action else 0)
        if total_cooperators_prev == m - 1:
            return Action.C
        if not my_prev_action and total_cooperators_prev == m - 1:
            return Action.C
        if total_cooperators_prev >= m:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_62(BaseStrategy):
    """
    Adaptive Threshold-Conditional Cooperation Strategy.

    Operates on a conditional contribution principle:
    - Round 0: Cooperate to signal intent.
    - Rounds 1 to (r-2): 
        - If previous count >= m, Cooperate.
        - If previous count == m-1, Cooperate to attempt threshold capture.
        - Otherwise, Defect to minimize losses.
    - Final Round (r-1): Cooperate if previous count was >= m-1, else Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        t = history.round_number
        if t == 0:
            return Action.C
        last_round_opponents_c = history.opponent_cooperators[-1]
        my_last_action = history.my_actions[-1]
        total_cooperators = last_round_opponents_c + (1 if my_last_action else 0)
        if t == r - 1:
            if total_cooperators >= m - 1:
                return Action.C
            else:
                return Action.D
        if total_cooperators >= m:
            return Action.C
        elif total_cooperators == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_63(BaseStrategy):
    """
    Threshold-Conditional Tit-for-Tat (TCTT):
    A strategy that cooperates if the threshold is met by others, includes a 'Benevolent Recovery' 
    forgiveness mechanism, and employs defensive termination in low-cooperation environments.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_zero_participation = 0
        self.permanent_defection = False

    def __call__(self, history: PlayerHistory) -> Action:
        if self.permanent_defection:
            return Action.D
        if history.round_number == 0:
            return Action.C
        m = self.game_description.m
        s_others_prev = history.opponent_cooperators[-1]
        c_self_prev = int(history.my_actions[-1])
        t_current = history.round_number + 1
        total_r = self.game_description.n_rounds
        if s_others_prev == 0:
            self.consecutive_zero_participation += 1
        else:
            self.consecutive_zero_participation = 0
        if self.consecutive_zero_participation >= 2:
            self.permanent_defection = True
            return Action.D
        if t_current == total_r:
            avg_cooperators = np.mean(history.opponent_cooperators + history.my_actions)
            if avg_cooperators >= m:
                return Action.C
            else:
                return Action.D
        if c_self_prev == 0 and s_others_prev >= m:
            return Action.C
        if s_others_prev >= m - 1:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_64(BaseStrategy):
    """
    Threshold-Conditional Reciprocity (TCR):
    - Round 1: Always Cooperate (C) to test the group.
    - Subsequent Rounds (t < r):
        - If last round's total cooperators >= m, play C to sustain reward.
        - If last round's total cooperators == m - 1, play C ("benevolent nudge").
        - Otherwise, play D (signal disappointment/save cost).
    - Final Round (t = r): Always Defect (D) to minimize personal loss.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_idx = history.round_number
        if current_round_idx == 0:
            return Action.C
        my_previous_contribution = 1 if history.my_actions[-1] else 0
        total_cooperators_last_round = history.opponent_cooperators[-1] + my_previous_contribution
        m = self.game_description.m
        r = self.game_description.n_rounds
        if current_round_idx == r - 1:
            return Action.D
        if total_cooperators_last_round >= m:
            return Action.C
        if total_cooperators_last_round == m - 1:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_65(BaseStrategy):
    """
    Implements a "Threshold-Targeted Reciprocity" strategy.
    
    The strategy attempts to reach the cooperation threshold (m) to secure reward (k)
    while avoiding exploitation. It starts with cooperation and adjusts based on
    previous rounds' outcomes (threshold attainment) and cumulative performance.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.r - 1:
            total_rounds = len(history.my_actions)
            successful_rounds = 0
            for i in range(total_rounds):
                contribution = 1 if history.my_actions[i] else 0
                total_cooperators = history.opponent_cooperators[i] + contribution
                if total_cooperators >= self.m:
                    successful_rounds += 1
            if successful_rounds / total_rounds > 0.5:
                return Action.C
            return Action.D
        c_self_prev = 1 if history.my_actions[-1] else 0
        s_prev = history.opponent_cooperators[-1] + c_self_prev
        if self.m / self.n > 0.8:
            if history.round_number >= 3:
                recent_three = history.opponent_cooperators[-3:]
                if all((val >= self.m - 1 for val in recent_three)):
                    return Action.C
            return Action.D
        if s_prev >= self.m:
            return Action.C if history.my_actions[-1] else Action.D
        if s_prev < self.m:
            if s_prev == self.m - 1:
                total_successes = 0
                for i in range(history.round_number):
                    my_act = 1 if history.my_actions[i] else 0
                    if history.opponent_cooperators[i] + my_act >= self.m:
                        total_successes += 1
                total_costs = np.sum(history.my_actions.astype(int))
                cumulative_gain = total_successes * self.k - total_costs
                if cumulative_gain > 0:
                    return Action.C
            if history.my_actions[-1]:
                return Action.D
            else:
                return Action.D
        return Action.D

class Strategy_BENEVOLENT_66(BaseStrategy):
    """
    Threshold-Targeting Reciprocity (TTR)
    
    This strategy attempts to reach the minimum cooperation threshold 'm' 
    efficiently by conditioning cooperation on previous rounds. It includes 
    an endgame push for cooperation and a "cut-loss" mechanism against 
    persistent defection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description
        self.consecutive_failed_thresholds = 0
        self.gave_up = False

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number + 1
        r = self.game.n_rounds
        m = self.game.m
        if self.gave_up:
            return Action.D
        if t == 1:
            return Action.C
        last_coop_count = history.opponent_cooperators[-1]
        my_last_action = history.my_actions[-1]
        total_cooperators_prev = last_coop_count + (1 if my_last_action else 0)
        if total_cooperators_prev < m:
            self.consecutive_failed_thresholds += 1
        else:
            self.consecutive_failed_thresholds = 0
        if self.consecutive_failed_thresholds >= 3:
            self.gave_up = True
            return Action.D
        if t >= r - 1:
            all_thresholds_met = True
            for i in range(history.round_number):
                opps = history.opponent_cooperators[i]
                mine = 1 if history.my_actions[i] else 0
                if opps + mine < m:
                    all_thresholds_met = False
                    break
            if not all_thresholds_met:
                return Action.C
        if total_cooperators_prev >= m:
            threshold_ratio = m / total_cooperators_prev
            if random.random() > threshold_ratio:
                return Action.D
            else:
                return Action.C
        else:
            return Action.C

class Strategy_BENEVOLENT_67(BaseStrategy):
    """
    A conditional threshold-based strategy for the Collective Risk Dilemma.
    Implements a risk-adjusted cooperation logic, tracking history to trigger
    cooperation when the threshold 'm' is reachable and defecting to avoid 
    exploitation when the group fails to coordinate. Includes a recovery mechanism
    and a final-round defection rule.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.is_defecting_due_to_failure = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.desc.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        n = self.desc.n_players
        m = self.desc.m
        k = self.desc.k
        my_last_action_val = 1 if history.my_actions[-1] else 0
        N_C_prev = my_last_action_val + history.opponent_cooperators[-1]
        if self.is_defecting_due_to_failure:
            probe_interval = math.floor(n / m) + 1
            if history.round_number % probe_interval == 0:
                self.is_defecting_due_to_failure = False
                return Action.C
            else:
                return Action.D
        if history.round_number >= 2:
            prev_1 = my_last_action_val + history.opponent_cooperators[-1]
            prev_2 = (1 if history.my_actions[-2] else 0) + history.opponent_cooperators[-2]
            if prev_1 < m and prev_2 < m:
                self.is_defecting_due_to_failure = True
                return Action.D
            if prev_1 >= m:
                prob = 1.0 - 1.0 / k
                return Action.C if random.random() < prob else Action.D
            if prev_1 == m - 1:
                return Action.C
        return Action.C

class Strategy_BENEVOLENT_68(BaseStrategy):
    """
    Implements a Conditional Threshold strategy for the Collective Risk Dilemma.
    1. Always cooperates in the first and final rounds.
    2. If the threshold was met previously, continues to cooperate.
    3. If the threshold was missed, uses a probabilistic nudge based on 
       previous cooperation levels.
    4. Switches to Defect (D) after 3 consecutive rounds of systemic failure 
       to prevent resource depletion.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.phi = 1.2

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == 0:
            return Action.C
        if current_round == total_rounds - 1:
            return Action.C
        my_prev_action = 1 if history.my_actions[-1] else 0
        c_prev = history.opponent_cooperators[-1] + my_prev_action
        if current_round >= 3:
            recent_c = []
            for i in range(-3, 0):
                opp_c = history.opponent_cooperators[i]
                my_c = 1 if history.my_actions[i] else 0
                recent_c.append(opp_c + my_c)
            if all((c < m for c in recent_c)):
                return Action.D
        if c_prev >= m:
            return Action.C
        if c_prev == 0:
            return Action.C
        p_t = min(1.0, m / (c_prev + 1) * self.phi)
        if random.random() < p_t:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_69(BaseStrategy):
    """
    Implements a Trigger-Based Threshold Reciprocity strategy for the Collective Risk Dilemma.
    It initiates cooperation, monitors threshold success (m), adapts using a confidence counter (S_t),
    and utilizes history-based decision making for the terminal round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.s_t = 1
        self.n = self.game_description.n_players
        self.m = self.game_description.m
        self.r = self.game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_last_action = history.my_actions[-1]
        opponents_last_action_count = history.opponent_cooperators[-1]
        n_t = (1 if my_last_action else 0) + opponents_last_action_count
        if history.round_number == self.r - 1:
            past_total_cooperators = []
            for i in range(len(history.my_actions)):
                past_total_cooperators.append((1 if history.my_actions[i] else 0) + history.opponent_cooperators[i])
            avg_n = sum(past_total_cooperators) / len(past_total_cooperators)
            if avg_n >= self.m - 1:
                return Action.C
            else:
                return Action.D
        if n_t >= self.m:
            self.s_t = 1
        else:
            self.s_t -= 1
        if n_t == self.m - 1:
            return Action.C
        if self.n == self.m:
            if n_t >= self.m:
                return Action.C
            else:
                return Action.D
        if self.s_t >= 1:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_70(BaseStrategy):
    """
    Adaptive Threshold Contribution:
    A strategy that balances altruistic coordination with resource preservation.
    It contributes if the threshold is met, if it can single-handedly meet the threshold,
    or if it's the final round and close to success. It implements safety mechanisms
    against persistent under-performance and sudden strategic collapses.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.under_performance_counter = 0

    def __call__(self, history: PlayerHistory) -> Action:
        desc = self.game_description
        if desc.k <= 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        last_cooperators = history.opponent_cooperators[-1]
        my_last_action = history.my_actions[-1]
        total_cooperators_last_round = last_cooperators + (1 if my_last_action else 0)
        if history.round_number >= 2:
            prev_cooperators = history.opponent_cooperators[-2]
            my_prev_action = history.my_actions[-2]
            total_prev_cooperators = prev_cooperators + (1 if my_prev_action else 0)
            if total_prev_cooperators >= desc.m and total_cooperators_last_round < desc.m - 1:
                return Action.D
        if total_cooperators_last_round < desc.m:
            self.under_performance_counter += 1
        else:
            self.under_performance_counter = 0
        if self.under_performance_counter >= 3 and desc.m - total_cooperators_last_round > 1:
            return Action.D
        if history.round_number == desc.n_rounds - 1:
            return Action.C if total_cooperators_last_round >= desc.m - 1 else Action.D
        if total_cooperators_last_round >= desc.m:
            return Action.C
        deficit = desc.m - total_cooperators_last_round
        if deficit == 1:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_71(BaseStrategy):
    """
    Implements a Tit-for-Tat inspired strategy based on running averages of 
    cooperation observed in the community. It cooperates if the historical 
    average of opponents' cooperation meets a threshold, but retaliates against 
    sudden drops in cooperation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.total_opponent_cooperations = 0
        self.last_observed_cooperators = 0
        self.in_punishment_phase = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        last_round_idx = history.round_number - 1
        last_opponents = history.opponent_cooperators[last_round_idx]
        self.total_opponent_cooperations += last_opponents
        self.last_observed_cooperators = last_opponents
        t = history.round_number
        avg_c = self.total_opponent_cooperations / t
        if self.in_punishment_phase:
            self.in_punishment_phase = False
            return Action.D
        if last_opponents < self.game_description.m and avg_c < self.game_description.m - 1:
            self.in_punishment_phase = True
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            if avg_c < self.game_description.m - 1:
                return Action.D
            return Action.C
        if avg_c >= self.game_description.m - 1:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_72(BaseStrategy):
    """
    Implements the Conditional Reciprocal Contribution (CRC) strategy.
    
    This strategy uses a "Testing" phase to establish cooperation and a 
    "Cooperative" phase to maintain it, provided the threshold 'm' is met. 
    It defaults to defection if 'm' is not met or if it is the final round
    without an established cooperative state.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self._state = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        m = self.game_description.m
        t = history.round_number + 1
        if t == 1:
            self._state = 0
            if m == 1:
                return Action.C
            if random.random() < m / n:
                return Action.C
            return Action.D
        my_prev_action = history.my_actions[-1]
        c_i = 1 if my_prev_action else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + c_i
        if t == r:
            if self._state == 1:
                return Action.C
            return Action.D
        if self._state == 0:
            if total_cooperators_prev >= m:
                self._state = 1
                return Action.C
            else:
                self._state = 0
                return Action.D
        elif total_cooperators_prev >= m:
            return Action.C
        else:
            self._state = 0
            return Action.D

class Strategy_BENEVOLENT_73(BaseStrategy):
    """
    Threshold-Triggered Reciprocity Strategy.
    
    Implements a conditional cooperation mechanism that attempts to hit the threshold m
    while dynamically adjusting cooperation based on past performance, stability, 
    and terminal round incentives.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        prev_round_idx = current_round - 1
        prev_cooperators = history.opponent_cooperators[prev_round_idx]
        my_prev_action = history.my_actions[prev_round_idx]
        my_prev_coop = 1 if my_prev_action else 0
        c_prev = prev_cooperators + my_prev_coop
        if current_round == self.r - 1:
            coop_history = [history.opponent_cooperators[i] + (1 if history.my_actions[i] else 0) >= self.m for i in range(current_round)]
            if sum(coop_history) > len(coop_history) / 2:
                return Action.C
            return Action.D
        rounds_to_fail = 3
        if current_round >= math.floor(self.r / 2):
            return Action.D
        if current_round >= rounds_to_fail:
            consecutive_failures = True
            for i in range(current_round - rounds_to_fail, current_round):
                if history.opponent_cooperators[i] + (1 if history.my_actions[i] else 0) >= self.m:
                    consecutive_failures = False
                    break
            if consecutive_failures:
                return Action.D
        if current_round >= 3:
            all_n = True
            for i in range(current_round - 3, current_round):
                if history.opponent_cooperators[i] + (1 if history.my_actions[i] else 0) != self.n:
                    all_n = False
                    break
            if all_n:
                prob = (self.m + 1) / self.n
                return Action.C if random.random() < prob else Action.D
        if c_prev >= self.m:
            if my_prev_action:
                if c_prev > self.m:
                    return Action.C
                else:
                    return Action.C if random.random() < self.m / self.n else Action.D
            else:
                return Action.C
        elif my_prev_action:
            return Action.D
        else:
            return Action.D

class Strategy_BENEVOLENT_74(BaseStrategy):
    """
    A triggered conditional cooperation strategy with a burn-in phase,
    relying on threshold monitoring (m) to decide between C and D.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.n = game_description.n_players
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_round_idx = -1
        prev_my_action = history.my_actions[prev_round_idx]
        my_c = 1 if prev_my_action else 0
        total_c_prev = history.opponent_cooperators[prev_round_idx] + my_c
        if history.round_number == self.r - 1:
            past_others = history.opponent_cooperators[:history.round_number]
            past_my = history.my_actions[:history.round_number].astype(int)
            total_past = past_others + past_my
            successful_rounds = np.sum(total_past >= self.m)
            if successful_rounds >= history.round_number / 2.0:
                return Action.C
            else:
                return Action.D
        if total_c_prev >= self.m:
            return Action.C
        else:
            if total_c_prev == self.m - 1:
                return Action.C
            return Action.D

class Strategy_BENEVOLENT_75(BaseStrategy):
    """
    Tit-for-Tat with Threshold Sensitivity Strategy.
    
    This strategy cooperates in the first round. In subsequent rounds, it adjusts 
    based on the previous round's cooperation count (C_prev). It includes a 
    'Benevolent Adaptation' that occasionally exploits full cooperation if 
    thresholds are met.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.target_count = game_description.m
        self.n_players = game_description.n_players
        self.total_rounds = game_description.n_rounds
        self.benevolent_cooldown = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        is_last_round = history.round_number == self.total_rounds - 1
        my_prev_action = history.my_actions[-1]
        opp_coop_count = history.opponent_cooperators[-1]
        C_prev = opp_coop_count + (1 if my_prev_action else 0)
        if not is_last_round and self.benevolent_cooldown == 0 and (C_prev == self.n_players):
            self.benevolent_cooldown = 1
            return Action.D
        if self.benevolent_cooldown > 0:
            self.benevolent_cooldown = 0
        if is_last_round:
            if C_prev >= self.target_count:
                return Action.C
            else:
                return Action.D
        if C_prev >= self.target_count:
            if my_prev_action:
                return Action.C
            else:
                if random.random() < 0.5:
                    return Action.C
                return Action.D
        elif C_prev == 0:
            return Action.D
        else:
            threshold_gap = self.target_count - C_prev
            if threshold_gap <= 1:
                return Action.C
            else:
                return Action.D

class Strategy_BENEVOLENT_76(BaseStrategy):
    """
    Implements the Triggered Threshold Coordination Strategy:
    - Starts with Cooperation (C).
    - If successful (C_last >= m), continues with C.
    - If on the cusp (C_last == m - 1), continues with C to attempt success.
    - If failure is significant (C_last < m - 1), defaults to Defection (D), 
      unless it is a "resurrection" round (every 3 rounds), where it tests with C.
    - Final round logic aligns with the cusp-check logic (C if cusp or better, else D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.resurrection_interval = 3

    def __call__(self, history: PlayerHistory) -> Action:
        round_t = history.round_number
        if round_t == 0:
            return Action.C
        last_my_action = history.my_actions[-1]
        my_c_last = 1 if last_my_action else 0
        total_c_last = history.opponent_cooperators[-1] + my_c_last
        m = self.game_description.m
        if round_t % self.resurrection_interval == 0:
            if total_c_last < m - 1:
                return Action.C
        if total_c_last >= m:
            return Action.C
        elif total_c_last == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_77(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that prioritizes cooperation, uses a "Benevolent Trigger"
    to address exploitation, and safeguards the final round against consistent non-cooperation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        prev_my_action = int(history.my_actions[-1])
        c_prev = history.opponent_cooperators[-1] + prev_my_action
        if current_round == self.r - 1:
            total_cooperators_per_round = history.opponent_cooperators + history.my_actions.astype(int)
            success_rounds = np.sum(total_cooperators_per_round >= self.m)
            success_rate = success_rounds / current_round
            if success_rate >= 0.5:
                return Action.C
            else:
                return Action.D
        x = min(3, current_round)
        recent_rounds = history.opponent_cooperators[-x:] + history.my_actions[-x:].astype(int)
        if np.mean(recent_rounds) == 0:
            if current_round % 2 == 0:
                return Action.D
            else:
                return Action.C
        if c_prev >= self.m:
            return Action.C
        else:
            return Action.C

class Strategy_BENEVOLENT_78(BaseStrategy):
    """
    Threshold-Tit-for-Tat strategy for the Collective Risk Dilemma.
    Initiates with cooperation, pivots to support the collective if the threshold
    is met or close, defects when the group fails to coordinate, with periodic
    probing to re-evaluate group behavior.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        round_idx = history.round_number
        current_round = round_idx + 1
        if current_round == 1:
            return Action.C
        if current_round == self.r:
            total_cooperators_per_round = history.opponent_cooperators + history.my_actions.astype(int)
            successful_rounds = np.sum(total_cooperators_per_round >= self.m)
            success_rate = successful_rounds / (self.r - 1)
            if success_rate > 0.5:
                return Action.C
            else:
                return Action.D
        last_round_idx = round_idx - 1
        last_total_cooperators = history.opponent_cooperators[last_round_idx] + int(history.my_actions[last_round_idx])
        if last_total_cooperators >= self.m - 1:
            return Action.C
        if current_round % 3 == 0:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_79(BaseStrategy):
    """
    Implements the Conditional Threshold-Trigger (CTT) strategy for the Collective Risk Dilemma.
    
    This strategy prioritizes achieving the collective reward threshold 'm' while minimizing individual 
    cost. It employs a conditional logic: Cooperate only if the group is one short of the threshold 
    (pivotal) or in the first round. It defects when the threshold is met or when the outcome 
    is deemed unreachable (too far below the threshold). It includes a specific check to 
    transition to cooperation if the previous attempt at defecting after success led to a failure 
    (the "Exploitation Check" mentioned in the specifications), and a terminal phase check.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.was_fragile_last_round = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        my_prev_action = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + my_prev_action
        if current_round == r - 1:
            total_history = np.sum(history.opponent_cooperators) + np.sum(history.my_actions)
            avg_cooperation = total_history / (r - 1)
            return Action.C if avg_cooperation >= m / n else Action.D
        if self.was_fragile_last_round:
            self.was_fragile_last_round = False
            return Action.C
        if total_cooperators_prev >= m:
            self.was_fragile_last_round = total_cooperators_prev == m
            return Action.D
        if total_cooperators_prev == m - 1:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_80(BaseStrategy):
    """
    A cooperative strategy that attempts to meet a threshold m of cooperators.
    It initiates with cooperation, continues to cooperate if the threshold is met or
    can be met by the player's contribution, and defects if the group is too far
    from the threshold. It employs a permanent defection switch if it detects
    exploitation and a final-round bailout clause.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.permanently_defected = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number > 1 and (not self.permanently_defected):
            for r in range(1, history.round_number - 1):
                my_action_r = 1 if history.my_actions[r] else 0
                total_c_r = history.opponent_cooperators[r] + my_action_r
                my_action_next = 1 if history.my_actions[r + 1] else 0
                total_c_next = history.opponent_cooperators[r + 1] + my_action_next
                if my_action_r == 1 and total_c_r > self.game_description.m and (total_c_next < self.game_description.m):
                    self.permanently_defected = True
                    break
        if self.permanently_defected:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            all_opp_coop = history.opponent_cooperators
            avg_o = np.mean(all_opp_coop)
            if avg_o < self.game_description.m - 2:
                return Action.D
        last_o = history.opponent_cooperators[-1]
        if last_o >= self.game_description.m - 1:
            return Action.C
        elif last_o == self.game_description.m - 2:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_81(BaseStrategy):
    """
    A conditional cooperation strategy for the Collective Risk Dilemma.
    It attempts to facilitate the group reward by cooperating in the first round,
    maintaining cooperation if the group is at or near the threshold (m-1),
    and switching to defection if the group consistently fails to reach the threshold,
    with a sensitivity to recovery signals.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.defecting_mode = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_my_action = int(history.my_actions[-1])
        prev_opp_coop = history.opponent_cooperators[-1]
        prev_total_coop = prev_opp_coop + prev_my_action
        recovery_signal = False
        if self.defecting_mode and history.round_number >= 2:
            prev_prev_my_action = int(history.my_actions[-2])
            prev_prev_opp_coop = history.opponent_cooperators[-2]
            prev_prev_total_coop = prev_prev_opp_coop + prev_prev_my_action
            if prev_total_coop > prev_prev_total_coop:
                recovery_signal = True
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == r - 1:
            if prev_total_coop >= m - 1:
                return Action.C
            else:
                return Action.D
        if prev_total_coop >= m:
            self.defecting_mode = False
            return Action.C
        if prev_total_coop == m - 1:
            self.defecting_mode = False
            return Action.C
        if recovery_signal:
            self.defecting_mode = False
            return Action.C
        self.defecting_mode = True
        return Action.D

class Strategy_BENEVOLENT_82(BaseStrategy):
    """
    Implements an Adaptive Reciprocity strategy for the Collective Risk Dilemma.
    - Phase 1 (S=1): Starts with cooperation.
    - Phase 2 (1 < S < r): Cooperates if previous round was successful (C_prev >= m) 
      or marginally successful (C_prev == m-1). Defects otherwise.
    - Phase 3 (S=r): Cooperates if historical success rate >= 75%, otherwise defects.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        current_round_index = history.round_number
        total_rounds = self.r
        my_last_action = history.my_actions[-1]
        last_round_cooperators = history.opponent_cooperators[-1] + (1 if my_last_action else 0)
        if current_round_index == total_rounds - 1:
            prev_round_coops = history.opponent_cooperators + history.my_actions.astype(int)
            threshold_met_count = np.sum(prev_round_coops >= self.m)
            if threshold_met_count / current_round_index >= 0.75:
                return Action.C
            else:
                return Action.D
        if last_round_cooperators >= self.m:
            return Action.C
        if last_round_cooperators == self.m - 1:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_83(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that attempts to meet the threshold m
    by probing cooperation early, transitioning to exploitation or maintenance based on 
    group behavior, and accounting for the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.patience_horizon = math.ceil(self.r / 2)
        self.consecutive_cooperation_failures = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        last_round_idx = history.round_number - 1
        last_coop_count = history.opponent_cooperators[last_round_idx]
        my_last_action = history.my_actions[last_round_idx]
        total_cooperation_last_round = last_coop_count + (1 if my_last_action else 0)
        if total_cooperation_last_round < self.m:
            self.consecutive_cooperation_failures += 1
        else:
            self.consecutive_cooperation_failures = 0
        if my_last_action == Action.C and last_coop_count == self.m - 1:
            if self.consecutive_cooperation_failures > 1:
                return Action.D
        if self.consecutive_cooperation_failures >= self.patience_horizon:
            return Action.D
        if history.round_number == self.r - 1:
            if total_cooperation_last_round == self.m - 1:
                return Action.C
            else:
                return Action.D
        if total_cooperation_last_round >= self.m:
            return Action.D
        return Action.C

class Strategy_BENEVOLENT_84(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that employs a conditional cooperation 
    approach. It starts by cooperating. In subsequent rounds (until the final one), 
    it monitors the number of cooperators from the previous round: if the count is 
    sufficient (>= m-1), it continues to cooperate. If the count is insufficient, 
    it employs a Tit-for-Tat forgiveness mechanic, defaulting to cooperation to 
    re-establish the social contract. In the final round, it defects to maximize 
    payoff, exploiting the end of the game's horizon.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        prev_round_cooperators = history.opponent_cooperators[-1]
        m = self.game_description.m
        if prev_round_cooperators >= m - 1:
            return Action.C
        else:
            last_action_was_cooperate = history.my_actions[-1]
            if last_action_was_cooperate:
                return Action.D
            else:
                return Action.C

class Strategy_BENEVOLENT_85(BaseStrategy):
    """
    Implements a conditional cooperation strategy for the Collective Risk Dilemma.
    - Round 1: Always Cooperate (C).
    - Round t (1 < t < r):
        - If previous round met threshold (C_prev >= m), Cooperate (C).
        - If previous round failed threshold (C_prev < m), Cooperate with probability p = m / n.
        - Special Case: If n == m, always Cooperate (absolute requirement).
        - Adaptation: If history shows consistent performance > m, use Tit-for-Tat (C if prev met threshold, else D).
    - Round r (Last Round):
        - If previous round met threshold (C_prev >= m), Cooperate (C).
        - If previous round failed threshold (C_prev < m), Defect (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.use_tft_adaptation = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if n == m:
            return Action.C
        if current_round == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        if not self.use_tft_adaptation and current_round > 1:
            all_successful = True
            for c_count in history.opponent_cooperators:
                if c_count < m:
                    all_successful = False
                    break
            if all_successful:
                self.use_tft_adaptation = True
        if current_round == r - 1:
            if prev_cooperators >= m:
                return Action.C
            else:
                return Action.D
        if self.use_tft_adaptation:
            if prev_cooperators >= m:
                return Action.C
            else:
                return Action.D
        if prev_cooperators >= m:
            return Action.C
        p_cooperate = m / n
        if random.random() < p_cooperate:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_86(BaseStrategy):
    """
    A threshold-based conditional cooperator that implements a "Trigger-Count"
    mechanism to maximize the likelihood of reaching the minimum cooperator threshold (m).
    
    Logic:
    - Round 0 (First round): Always cooperate to signal intent.
    - Rounds 1 to (r-2): If previous round cooperators >= m-1, cooperate; otherwise defect.
    - Final Round (r-1): If previous round cooperators >= m-1, cooperate to secure final reward; otherwise defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == 0:
            return Action.C
        my_last_action = history.my_actions[-1]
        last_round_cooperators = history.opponent_cooperators[-1] + (1 if my_last_action else 0)
        if current_round == total_rounds - 1:
            if last_round_cooperators >= m - 1:
                return Action.C
            else:
                return Action.D
        if last_round_cooperators >= m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_87(BaseStrategy):
    """
    A conditional cooperation strategy for the Collective Risk Dilemma.
    Implements threshold monitoring, signal-based punishment (deficit-based D),
    final-round altruism, and persistence checks.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.d_cooldown = 0
        self.failure_counter = 0
        self.last_was_test = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        m = self.game_description.m
        t = history.round_number
        if t == r - 1:
            return Action.C
        if t == 0:
            return Action.C
        i_cooperated_last = int(history.my_actions[-1])
        others_cooperated_last = history.opponent_cooperators[-1]
        total_cooperators_last = others_cooperated_last + i_cooperated_last
        if total_cooperators_last < m:
            self.failure_counter += 1
        else:
            self.failure_counter = 0
        if self.failure_counter >= 3:
            return Action.D
        if i_cooperated_last and total_cooperators_last > m + 2:
            self.last_was_test = True
            return Action.D
        if self.last_was_test:
            self.last_was_test = False
            return Action.C
        if self.d_cooldown > 0:
            self.d_cooldown -= 1
            return Action.D
        if total_cooperators_last >= m:
            return Action.C
        else:
            deficit = max(1, m - total_cooperators_last)
            self.d_cooldown = deficit - 1
            return Action.D

class Strategy_BENEVOLENT_88(BaseStrategy):
    """
    Implements a belief-based strategy for the Collective Risk Dilemma.
    Maintains a cooperative belief state S_t, adjusts based on thresholds,
    handles punishment cycles, and accounts for end-game conditions.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.s = 0.5
        self.d_counter = 0
        self.probe_next = False
        self.alpha = 0.7

    def __call__(self, history: PlayerHistory) -> Action:
        t_index = history.round_number
        t = t_index + 1
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        k = self.game_description.k
        if t_index > 0:
            last_n_cooperators = history.opponent_cooperators[-1] + (1 if history.my_actions[-1] else 0)
            self.s = self.alpha * self.s + (1 - self.alpha) * (last_n_cooperators / n)
            if last_n_cooperators < m:
                self.s = 0.0
                self.d_counter = 2
                self.probe_next = True
            else:
                self.probe_next = False
        if t == 1:
            return Action.C
        if t == r:
            if k < 1:
                return Action.D
            return Action.C
        if self.d_counter > 0:
            rounds_remaining = r - t + 1
            if rounds_remaining / r >= 0.25:
                pass
            self.d_counter -= 1
            return Action.D
        if self.probe_next:
            self.probe_next = False
            return Action.C
        theta = m / n * (1 - (t - 1) / r)
        if self.s >= theta:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_89(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that balances cooperative signaling,
    reciprocity, and risk-aversion. It uses probabilistic threshold targeting,
    conditional cooperation based on previous outcomes, and a small mutation
    (epsilon) probability to foster potential cooperation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.target_contribution_rate = self.m / self.n
        self.epsilon = 0.05
        self.giving_up = False

    def __call__(self, history: PlayerHistory) -> Action:
        round_t = history.round_number
        n_prev_coop = history.opponent_cooperators[-1] if round_t > 0 else 0
        last_my_action = history.my_actions[-1] if round_t > 0 else None
        chosen_action = Action.D
        if round_t == 0:
            chosen_action = Action.C if random.random() < self.target_contribution_rate else Action.D
        elif self.giving_up:
            chosen_action = Action.D
        else:
            my_c_last = 1 if last_my_action else 0
            c_total_last = n_prev_coop + my_c_last
            others_cooperated = n_prev_coop
            if c_total_last >= self.m:
                if last_my_action:
                    prob = self.m / max(1, others_cooperated)
                    chosen_action = Action.C if random.random() < prob else Action.D
                else:
                    chosen_action = Action.D
            elif last_my_action and others_cooperated == self.m - 1:
                chosen_action = Action.C
            elif others_cooperated < self.m / 2:
                self.giving_up = True
                chosen_action = Action.D
            else:
                chosen_action = Action.C
            if round_t == self.r - 1:
                if n_prev_coop >= self.m - 1:
                    chosen_action = Action.C
                else:
                    chosen_action = Action.D
        if chosen_action == Action.D:
            if random.random() < self.epsilon:
                chosen_action = Action.C
        return chosen_action

class Strategy_BENEVOLENT_90(BaseStrategy):
    """
    A conditional 'Triggered Tit-for-Tat' strategy for the Collective Risk Dilemma.
    
    Logic:
    - Round 0: Cooperate to signal intent.
    - Rounds t > 0:
      - If threshold (m) was met in previous round: Cooperate.
      - If threshold (m) was NOT met:
        - If we cooperated previously, defect (punitive).
        - If we defected previously, remain defecting until the threshold is met by the group.
    - Final round heuristic:
      - If last half of game showed consistent success (>= m), cooperate.
      - Otherwise, defect to maximize security.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        m = self.game.m
        total_rounds = self.game.n_rounds
        last_cooperators = history.opponent_cooperators[-1]
        my_last_action = history.my_actions[-1]
        if current_round == total_rounds - 1:
            check_depth = max(1, total_rounds // 2)
            start_index = max(0, current_round - check_depth)
            consistent_success = True
            for i in range(start_index, current_round):
                if history.opponent_cooperators[i] < m:
                    consistent_success = False
                    break
            if consistent_success:
                return Action.C
            return Action.D
        if last_cooperators >= m:
            return Action.C
        if my_last_action == Action.C:
            return Action.D
        return Action.D

class Strategy_BENEVOLENT_91(BaseStrategy):
    """
    A conditional 'Threshold-Trigger' strategy for Collective Risk Dilemmas.
    Uses three phases (Initiation, Stability, Dissolution) to balance 
    collective cooperation with individual endowment preservation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        m = self.game_description.m
        my_last_action_val = 1 if history.my_actions[-1] else 0
        total_cooperators_last = history.opponent_cooperators[-1] + my_last_action_val
        if history.round_number == r - 1:
            if total_cooperators_last == m - 1 and my_last_action_val == 1:
                return Action.C
            return Action.D
        if total_cooperators_last >= m:
            if my_last_action_val == 1 and total_cooperators_last > m:
                return Action.D
            return Action.C
        if total_cooperators_last >= m - 1:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_92(BaseStrategy):
    """
    Implements a Conditional Threshold Trigger strategy for the Collective Risk Dilemma.
    
    The strategy aims to foster cooperation while being resilient against persistent 
    non-cooperative groups. Key behaviors include:
    - Initial cooperation.
    - Conditional response to the previous round's outcome (threshold adherence).
    - Probabilistic cooperation if a single failure occurs.
    - Defection if the group proves consistently uncooperative (failure threshold criteria).
    - Final round exploitation if previous round failed.
    - Near-miss recovery: Always try to cooperate if the group was only 1 player 
      short of the threshold.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r_total = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        prev_c_count = history.opponent_cooperators[-1]
        my_prev_action = 1 if history.my_actions[-1] else 0
        c_total_prev = prev_c_count + my_prev_action
        if c_total_prev == m - 1:
            return Action.C
        if current_round >= 2:
            prev_prev_c_count = history.opponent_cooperators[-2]
            my_prev_prev_action = 1 if history.my_actions[-2] else 0
            c_total_prev_prev = prev_prev_c_count + my_prev_prev_action
            if c_total_prev < m and c_total_prev_prev < m:
                return Action.D
        if current_round == r_total - 1:
            if c_total_prev >= m:
                return Action.C
            else:
                return Action.D
        all_prev_opponent_counts = history.opponent_cooperators
        all_prev_my_actions = history.my_actions.astype(int)
        total_C_history = all_prev_opponent_counts + all_prev_my_actions
        if c_total_prev >= m:
            return Action.C
        else:
            failed_rounds = [t for t, count in enumerate(total_C_history) if count < m]
            if len(failed_rounds) == 1:
                if random.random() < m / n:
                    return Action.C
                else:
                    return Action.D
            elif len(failed_rounds) / current_round > 0.5:
                return Action.D
            else:
                return Action.C

class Strategy_BENEVOLENT_93(BaseStrategy):
    """
    Implements a threshold-sensitive conditional strategy for the Collective Risk Dilemma.
    
    Logic:
    - Round 1 (index 0): Always Cooperate (C).
    - Final Round (index r-1): Always Cooperate (C).
    - Other Rounds:
        - If previous round total cooperators (N_prev) >= m: Cooperate (C).
        - If N_prev == m - 1: Cooperate (C) (marginal failure, encourage group).
        - If N_prev < m - 1: Defect (D) (severe failure, protect endowment).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.m = game_description.m
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.n_rounds - 1:
            return Action.C
        my_prev_action = history.my_actions[-1]
        n_prev_cooperators = history.opponent_cooperators[-1] + (1 if my_prev_action else 0)
        if n_prev_cooperators >= self.m:
            return Action.C
        elif n_prev_cooperators == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_94(BaseStrategy):
    """
    Threshold-Responsive Tit-for-Tat (TR-TFT).
    
    Plays Cooperate (C) in round 1. In subsequent rounds, plays Cooperate (C) if the
    previous round resulted in >= m-1 total cooperators. Otherwise, plays Defect (D).
    This strategy encourages coordination by forgiving narrow misses (m-1) and
    re-engaging immediately if the collective successfully meets the threshold (m).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        opp_cooperators = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        my_contribution = 1 if my_prev_action else 0
        total_cooperators = opp_cooperators + my_contribution
        m = self.game_description.m
        if total_cooperators >= m - 1:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_95(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that manages trust dynamically.
    It cooperates based on a 'trust_level' which adjusts based on group behavior
    relative to the threshold 'm'. It includes specific recovery protocols,
    last-round behavior, and conditional cooperation logic.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.target_cooperators = game_description.m
        self.n_players = game_description.n_players
        self.trust_level = 1.0
        self.defect_counter = 0
        self.in_recovery = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            if self.trust_level > 0.8:
                return Action.C
            return Action.D
        c_prev_others = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        c_prev_total = c_prev_others + (1 if my_prev_action else 0)
        if c_prev_total <= self.target_cooperators / 2:
            self.trust_level = 0.0
            self.in_recovery = True
            self.defect_counter = 0
        if self.trust_level == 0.0:
            self.defect_counter += 1
            if self.defect_counter <= 2:
                return Action.D
            else:
                if c_prev_total >= self.target_cooperators:
                    self.trust_level = 0.5
                    self.in_recovery = False
                    self.defect_counter = 0
                    return Action.C
                return Action.C
        threshold_met = c_prev_total >= self.target_cooperators
        if threshold_met:
            self.trust_level = min(1.0, self.trust_level + 0.1)
        else:
            self.trust_level = max(0.0, self.trust_level - 0.2)
        if c_prev_others == self.target_cooperators - 1:
            return Action.C
        if random.random() < self.trust_level:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_96(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that employs a conditional cooperative approach:
    - Round 0: Always cooperates.
    - Rounds 1 to (r-2):
        - If the threshold (m) was met in the previous round, continues cooperating.
        - If the threshold was not met, defects for exactly one round to minimize loss,
          then returns to cooperating in the next round.
    - Final Round: Always cooperates to maximize potential collective reward.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self._defected_last_round = False

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == total_rounds - 1:
            self._defected_last_round = False
            return Action.C
        if current_round == 0:
            self._defected_last_round = False
            return Action.C
        my_prev_action = history.my_actions[-1]
        my_prev_val = 1 if my_prev_action else 0
        total_c_prev = history.opponent_cooperators[-1] + my_prev_val
        if self._defected_last_round:
            self._defected_last_round = False
            return Action.C
        if total_c_prev >= m:
            self._defected_last_round = False
            return Action.C
        else:
            self._defected_last_round = True
            return Action.D

class Strategy_BENEVOLENT_97(BaseStrategy):
    """
    A Tit-for-Tat variant strategy based on the "Contribution Floor".
    
    Logic:
    1. Always play C in the first round.
    2. In the final round, always play D to maximize payoff.
    3. If 0 < round < final:
       - If previous cooperators >= m, continue to play C.
       - If previous cooperators == m - 1 (and we defected), play C to bridge the gap.
       - Otherwise, play D to conserve endowment.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        m = self.game_description.m
        prev_cooperators = history.opponent_cooperators[-1]
        prev_my_action = history.my_actions[-1]
        if prev_cooperators >= m:
            return Action.C
        if prev_my_action == Action.D and prev_cooperators == m - 1:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_98(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that tracks global cooperation reputation,
    adjusts target thresholds based on group performance history, and modulates 
    contribution likelihood to optimize collective outcomes.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.target_cooperators = float(game_description.m)
        self.reputation_index = 0.5
        self.consecutive_low_cooperation = 0
        self.consecutive_high_cooperation = 0
        self.consecutive_zero_cooperation = 0
        self.forced_defect_round = False
        self.permanent_defect = False

    def __call__(self, history: PlayerHistory) -> Action:
        if self.permanent_defect:
            return Action.D
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        m = self.game_description.m
        k = self.game_description.k
        t = history.round_number + 1
        rounds_total = self.game_description.n_rounds
        prev_cooperators = history.opponent_cooperators[-1]
        if history.my_actions[-1]:
            prev_cooperators += 1
        observed_cooperation_rate = prev_cooperators / n
        self.reputation_index = self.reputation_index * 0.7 + observed_cooperation_rate * 0.3
        if prev_cooperators < m:
            self.consecutive_low_cooperation += 1
            self.consecutive_high_cooperation = 0
        else:
            self.consecutive_low_cooperation = 0
        if prev_cooperators >= m:
            self.consecutive_high_cooperation += 1
        else:
            self.consecutive_high_cooperation = 0
        if prev_cooperators == 0:
            self.consecutive_zero_cooperation += 1
        else:
            self.consecutive_zero_cooperation = 0
        if self.consecutive_low_cooperation >= 2:
            self.target_cooperators = min(n, self.target_cooperators + 1)
        elif self.consecutive_high_cooperation >= 3:
            self.target_cooperators = float(m)
        if self.consecutive_zero_cooperation >= 2:
            self.permanent_defect = True
            return Action.D
        if t == rounds_total:
            return Action.D
        if self.forced_defect_round:
            self.forced_defect_round = False
            return Action.D
        if prev_cooperators > m + 2:
            self.forced_defect_round = True
            return Action.C
        threshold_ratio = self.target_cooperators / n
        if self.reputation_index > threshold_ratio:
            return Action.C
        else:
            rho = random.random()
            if rho < self.reputation_index * (1 + k / n):
                return Action.C
            else:
                return Action.D

class Strategy_BENEVOLENT_99(BaseStrategy):
    """
    Implements a Threshold-Tit-for-Tat strategy for the Collective Risk Dilemma.
    It uses a conditional cooperation logic based on the threshold m, 
    with a 'trust-but-verify' mechanism, historical tracking for persistent defection, 
    and a specific final-round heuristic.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failed_rounds = 0
        self.reset_mode = False
        self.last_action = None

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            self.last_action = Action.C
            return Action.C
        prev_round = current_round - 1
        n_cooperators_prev = history.opponent_cooperators[prev_round]
        my_prev_action = history.my_actions[prev_round]
        total_cooperators = n_cooperators_prev + (1 if my_prev_action else 0)
        if current_round == r - 1:
            if self.last_action == Action.C:
                self.last_action = Action.C
                return Action.C
            elif total_cooperators + 1 >= m:
                self.last_action = Action.C
                return Action.C
            else:
                self.last_action = Action.D
                return Action.D
        if total_cooperators < m:
            self.consecutive_failed_rounds += 1
        else:
            self.consecutive_failed_rounds = 0
            self.reset_mode = False
        if self.consecutive_failed_rounds >= 3:
            self.consecutive_failed_rounds = 0
            self.reset_mode = True
            self.last_action = Action.C
            return Action.C
        if total_cooperators >= m:
            self.last_action = Action.C
            return Action.C
        if total_cooperators == m - 1 and self.last_action == Action.D:
            self.last_action = Action.C
            return Action.C
        if n_cooperators_prev >= m - 1:
            self.last_action = Action.C
            return Action.C
        else:
            self.last_action = Action.D
            return Action.D

class Strategy_BENEVOLENT_100(BaseStrategy):
    """
    Implements a threshold-based reciprocity strategy for the Collective Risk Dilemma.
    
    Logic:
    - Round 1: Cooperate.
    - If history is "non-cooperative" (< m):
        - Defect, but test for revival every (k+1) rounds by playing C.
    - If history is "cooperative" (>= m):
        - If exactly m cooperators, continue to cooperate.
        - If > m cooperators, defect to avoid over-contribution, 
          unless it's the last round where cooperative stability is prioritized
          via the logic provided in the specification.
    - Sensitivity: In early rounds (t < sqrt(r)), if the group fails to reach 
      m consistently, the agent switches to permanent defection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.given_up = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        r = self.desc.n_rounds
        m = self.desc.m
        k = int(self.desc.k)
        t_current = history.round_number + 1
        last_action_was_c = bool(history.my_actions[-1])
        s_prev = history.opponent_cooperators[-1] + (1 if last_action_was_c else 0)
        if not self.given_up and t_current < math.sqrt(r):
            all_previous_failed = np.all(history.opponent_cooperators + history.my_actions < m)
            if all_previous_failed:
                self.given_up = True
        if self.given_up:
            return Action.D
        if s_prev < m:
            if t_current % (k + 1) == 0:
                return Action.C
            else:
                return Action.D
        if s_prev == m:
            return Action.C
        if s_prev > m:
            if t_current == r:
                return Action.D
            if s_prev > m + 1:
                return Action.D
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_101(BaseStrategy):
    """
    Implements a threshold-based coordination strategy for the Collective Risk Dilemma.
    Coordinates based on player index (if available) or random probability, then adapts
    to the group's cooperation levels using a Tit-for-Tat inspired approach to maintain
    the threshold m while guarding against exploitation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.player_id = getattr(self, 'player_index', random.randint(1, self.desc.n_players))
        self.consecutive_failed_rounds = 0
        self.is_signaling_defection = False

    def __call__(self, history: PlayerHistory) -> Action:
        m = self.desc.m
        r = self.desc.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C if self.player_id <= m else Action.D
        last_action = Action.C if history.my_actions[-1] else Action.D
        last_opponents = history.opponent_cooperators[-1]
        total_cooperators = last_opponents + (1 if last_action == Action.C else 0)
        if current_round == r - 1:
            if history.round_number > 1:
                success_count = 0
                for i in range(history.round_number):
                    opp = history.opponent_cooperators[i]
                    my = 1 if history.my_actions[i] else 0
                    if opp + my >= m:
                        success_count += 1
                if success_count / history.round_number > 0.5:
                    return last_action
            return Action.D
        if self.is_signaling_defection:
            self.is_signaling_defection = False
            return Action.C
        if total_cooperators < m:
            self.consecutive_failed_rounds += 1
            if self.consecutive_failed_rounds >= 2 and last_action == Action.C:
                self.is_signaling_defection = True
                self.consecutive_failed_rounds = 0
                return Action.D
            return Action.C
        else:
            self.consecutive_failed_rounds = 0
            if total_cooperators == m:
                return last_action
            elif last_action == Action.C:
                return Action.C if random.random() > 0.05 else Action.D
            else:
                return Action.D

class Strategy_BENEVOLENT_102(BaseStrategy):
    """
    Implements a 'tit-for-tat with threshold-triggered altruism' strategy.
    
    Round 1: Always Cooperate.
    Subsequent (not final):
    - If threshold (m) met last round: Cooperate.
    - If threshold failed:
        - If previously C: Defect (warning).
        - If previously D: Cooperate if count >= m-1 (bridge gap), else Defect.
    Final Round:
    - If threshold met last round: Cooperate.
    - If threshold failed last round: Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        last_c_count = int(history.opponent_cooperators[-1])
        my_last_action_is_c = bool(history.my_actions[-1])
        if current_round == self.r - 1:
            if last_c_count >= self.m:
                return Action.C
            else:
                return Action.D
        if last_c_count >= self.m:
            return Action.C
        if my_last_action_is_c:
            return Action.D
        elif last_c_count >= self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_103(BaseStrategy):
    """
    A conditional, threshold-based cooperation strategy designed for Collective Risk Dilemmas.
    It initiates with cooperation, employs a 'punishment' trigger for failed thresholds,
    incorporates adaptive recovery when near-threshold, and defaults to cooperative play
    in the final round. It also includes safeguard logic for persistent defection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.persistent_defection_count = 0
        self.last_action_was_punishment = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.C
        prev_coop_count = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        total_prev_cooperators = prev_coop_count + (1 if my_prev_action else 0)
        m = self.game_description.m
        if total_prev_cooperators < m:
            self.persistent_defection_count += 1
        else:
            self.persistent_defection_count = 0
        if self.persistent_defection_count > 3:
            return Action.D
        if my_prev_action == Action.C and total_prev_cooperators == m:
            self.last_action_was_punishment = False
            return Action.C
        if total_prev_cooperators >= m:
            self.last_action_was_punishment = False
            return Action.C
        if total_prev_cooperators < m:
            if self.last_action_was_punishment:
                if total_prev_cooperators >= m - 1:
                    self.last_action_was_punishment = False
                    return Action.C
                else:
                    return Action.D
            else:
                self.last_action_was_punishment = True
                return Action.D
        return Action.C

class Strategy_BENEVOLENT_104(BaseStrategy):
    """
    Threshold-Responsive Tit-for-Tat: A strategy that adapts to collective success thresholds.
    It cooperates if the group meets or nears the minimum threshold (m), defects if the group
    fails significantly, and periodically attempts to re-engage cooperation to probe for
    better outcomes.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.is_defecting = False
        self.re_engagement_counter = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.game_description.m
        my_prev_action = history.my_actions[-1]
        s_prev = history.opponent_cooperators[-1] + (1 if my_prev_action else 0)
        if self.is_defecting:
            self.re_engagement_counter += 1
            if self.re_engagement_counter >= 3:
                self.re_engagement_counter = 0
                self.is_defecting = False
                return Action.C
        if s_prev >= m:
            self.is_defecting = False
            return Action.C
        if s_prev < m:
            if s_prev >= m - 1:
                self.is_defecting = False
                return Action.C
            else:
                self.is_defecting = True
                self.re_engagement_counter = 0
                return Action.D
        return Action.C

class Strategy_BENEVOLENT_105(BaseStrategy):
    """
    A conditional strategy for the Collective Risk Dilemma that employs a 
    'Trigger-Threshold' logic: incentivizes threshold cooperation, punishes 
    failures, attempts recovery, and provides benevolence in the final round 
    only if history justifies it. Includes logic for persistent failure and 
    near-threshold coordination.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failure_count = 0

    def __call__(self, history: PlayerHistory) -> Action:
        m = self.game_description.m
        n_rounds = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == n_rounds - 1:
            total_cooperators = history.opponent_cooperators + history.my_actions.astype(int)
            success_count = np.sum(total_cooperators >= m)
            if success_count > n_rounds / 2:
                return Action.C
            return Action.D
        last_opp_coop = history.opponent_cooperators[-1]
        last_my_action = history.my_actions[-1]
        total_coop_last = last_opp_coop + int(last_my_action)
        if total_coop_last < m:
            self.consecutive_failure_count += 1
        else:
            self.consecutive_failure_count = 0
        if self.consecutive_failure_count >= 3:
            return Action.D
        if total_coop_last == m - 1:
            return Action.C
        if total_coop_last >= m:
            return Action.C
        if last_my_action:
            return Action.D
        if current_round >= 2:
            prev_opp_coop = history.opponent_cooperators[-2]
            prev_my_action = history.my_actions[-2]
            total_coop_prev = prev_opp_coop + int(prev_my_action)
            if total_coop_last > total_coop_prev:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_BENEVOLENT_106(BaseStrategy):
    """
    Implements a Conditional Threshold Adaptation strategy for the Collective Risk Dilemma.
    
    This strategy starts with cooperation to build a baseline. In subsequent rounds:
    1. If the group met or exceeded the cooperation threshold (m) in the previous round, it cooperates.
    2. If the group was one player short of the threshold (m-1), it cooperates (the "Forgiveness" trigger).
    3. Otherwise, it defects to punish/maximize individual utility during failure.
    
    This logic applies consistently, including the final round, where the same rules dictate 
    the final action choice.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        opponents_prev_coop = history.opponent_cooperators[-1]
        last_C = int(opponents_prev_coop) + (1 if my_prev_action else 0)
        if last_C >= self.m:
            return Action.C
        elif last_C >= self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_107(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that maintains a reputation and 
    adaptively adjusts its willingness to cooperate based on group performance.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.my_reputation = 1.0
        self.cooperation_threshold = game_description.m
        self.delta = 1.0 / game_description.n_rounds
        self.gamma = 2.0 / game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_last_action = history.my_actions[-1]
        prev_opp_c = history.opponent_cooperators[-1]
        total_prev_cooperators = (1 if my_last_action else 0) + prev_opp_c
        if total_prev_cooperators >= self.game_description.m:
            self.my_reputation = min(1.0, self.my_reputation + self.delta)
        else:
            self.my_reputation = max(0.0, self.my_reputation - self.gamma)
        if total_prev_cooperators > self.game_description.m:
            self.cooperation_threshold = max(1, self.cooperation_threshold - 1)
        else:
            self.cooperation_threshold = self.game_description.m
        if history.round_number == self.game_description.n_rounds - 1:
            if total_prev_cooperators >= self.game_description.m:
                return Action.C
            else:
                return Action.D
        return Action.C if self.my_reputation >= 0.5 else Action.D

class Strategy_BENEVOLENT_108(BaseStrategy):
    """
    A strategic agent for the Collective Risk Dilemma that employs adaptive cooperation,
    punishment/rectification mechanisms, and termination defection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description
        self.cold_start_counter = 0
        self.failure_counter = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game.n_players
        m = self.game.m
        r = self.game.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        others_c = history.opponent_cooperators[-1]
        total_c_prev = others_c + (1 if my_prev_action else 0)
        if total_c_prev < m:
            self.failure_counter += 1
            if total_c_prev == 0:
                self.cold_start_counter += 1
            else:
                self.cold_start_counter = 0
        else:
            self.cold_start_counter = 0
        if self.failure_counter > r / 2:
            return Action.D
        if self.cold_start_counter >= 2:
            self.cold_start_counter = 0
            return Action.C
        if current_round == r - 1:
            if total_c_prev >= m:
                return Action.D
            else:
                return Action.C
        if total_c_prev >= m:
            if my_prev_action:
                return Action.C if random.random() < m / n else Action.D
            else:
                return Action.D
        else:
            return Action.C

class Strategy_BENEVOLENT_109(BaseStrategy):
    """
    Implements the target contribution adjustment strategy for the Collective Risk Dilemma.
    Adjusts target_contribution_count based on past success relative to the threshold m.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.target_contribution_count = self.m
        self.forced_cooperation = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        last_round_idx = history.round_number - 1
        my_last_action_val = 1 if history.my_actions[last_round_idx] else 0
        s_prev = history.opponent_cooperators[last_round_idx] + my_last_action_val
        if s_prev == 0:
            self.target_contribution_count = self.n
            self.forced_cooperation = True
        if history.round_number == self.r - 1:
            if s_prev >= self.m:
                return Action.D
            else:
                return Action.C
        if not self.forced_cooperation:
            if s_prev >= self.m:
                self.target_contribution_count = max(1, self.target_contribution_count - 1)
            elif s_prev < self.m:
                self.target_contribution_count = min(self.n, self.target_contribution_count + 1)
        s_other = history.opponent_cooperators[last_round_idx]
        if self.target_contribution_count > s_other:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_110(BaseStrategy):
    """
    A conditional, threshold-adaptive trigger strategy for the Collective Risk Dilemma.
    It initiates cooperation and continues as long as the threshold 'm' is met. 
    If the threshold is not met, it switches to a tit-for-tat variant to protect 
    resources, while attempting to recover the cooperative equilibrium if the 
    group is just one player short (m-1).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_idx = history.round_number
        is_first_round = current_round_idx == 0
        is_final_round = current_round_idx == self.r - 1
        if is_first_round:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        did_i_cooperate_prev = bool(history.my_actions[-1])
        if is_final_round:
            if prev_cooperators >= self.m:
                return Action.C
            else:
                return Action.D
        if prev_cooperators >= self.m:
            return Action.C
        elif did_i_cooperate_prev:
            return Action.D
        elif prev_cooperators == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_111(BaseStrategy):
    """
    A conditional, threshold-sensitive strategy for the Collective Risk Dilemma.
    It promotes cooperation when thresholds are met or nearly met (m-1),
    while defaulting to defection in failure scenarios or end-game games that 
    consistently underperformed.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        i_cooperated = 1 if history.my_actions[-1] else 0
        c_prev = history.opponent_cooperators[-1] + i_cooperated
        if history.round_number == self.r - 1:
            total_history = history.opponent_cooperators + history.my_actions.astype(int)
            meeting_threshold_count = np.sum(total_history >= self.m)
            failing_threshold_count = np.sum(total_history < self.m)
            if meeting_threshold_count >= failing_threshold_count:
                return Action.C
            else:
                return Action.D
        if c_prev == 0:
            return Action.D
        if c_prev == self.m:
            return Action.C
        if c_prev >= self.m:
            return Action.C
        if c_prev == self.m - 1:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_112(BaseStrategy):
    """
    Threshold-Targeting Reciprocity: A strategy that balances collective contribution requirements with 
    punishment/forgiveness dynamics. It maintains a reputation score based on whether the collective 
    contribution meets the minimum threshold (m-1) required for the reward.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.reputation = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_round_idx = history.round_number - 1
        o_prev = history.opponent_cooperators[prev_round_idx]
        threshold = self.game_description.m - 1
        self.reputation += o_prev - threshold
        if self.reputation < -2:
            self.reputation = 0
        if history.round_number == self.game_description.n_rounds - 1:
            if o_prev >= threshold:
                return Action.C
            else:
                return Action.D
        if self.reputation >= 0:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_113(BaseStrategy):
    """
    Implements a conditional cooperation strategy for the Collective Risk Dilemma.
    Starts with Cooperation. In subsequent rounds, it adjusts behavior based on 
    the observed cooperation rate: cooperating if the threshold is met, 
    probabilistically cooperating if the rate is between half-threshold and threshold, 
    and defecting otherwise, with a reset mechanism for sustained collective recovery.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.threshold_ratio = self.m / self.n

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        current_round = history.round_number + 1
        last_coop_count = history.opponent_cooperators[-1]
        my_last_action = history.my_actions[-1]
        total_cooperators = last_coop_count + (1 if my_last_action else 0)
        o_last = total_cooperators / self.n
        if current_round == self.r:
            if o_last >= self.threshold_ratio * 0.5:
                return Action.C
            else:
                return Action.D
        if o_last >= self.threshold_ratio:
            return Action.C
        elif o_last >= self.threshold_ratio * 0.5:
            probability = o_last / self.threshold_ratio
            if random.random() < probability:
                return Action.C
            else:
                return Action.D
        else:
            start_idx = max(0, len(history.my_actions) - 3)
            recent_my_actions = history.my_actions[start_idx:].astype(int)
            recent_opp_coops = history.opponent_cooperators[start_idx:]
            total_coops_recent = recent_my_actions + recent_opp_coops
            avg_3 = np.mean(total_coops_recent) / self.n
            if avg_3 >= self.threshold_ratio:
                return Action.C
            else:
                return Action.D

class Strategy_BENEVOLENT_114(BaseStrategy):
    """
    Implements a cooperative strategy for the Collective Risk Dilemma:
    - Round 1: Cooperates.
    - Round t > 1 (not final): 
        - If previous count >= m, Cooperates.
        - If previous count == m - 1, Cooperates (trying to push to threshold).
        - If previous count < m - 1, Defects (saving resources).
    - Final Round: Cooperates only if the threshold was already met (>= m).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number + 1
        n_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if t == 1:
            return Action.C
        my_prev_action = int(history.my_actions[-1])
        c_prev = my_prev_action + history.opponent_cooperators[-1]
        if t == n_rounds:
            if c_prev >= m:
                return Action.C
            else:
                return Action.D
        if c_prev >= m + 1:
            return Action.C
        s = c_prev - m
        if s >= 0:
            return Action.C
        elif s == -1:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_115(BaseStrategy):
    """
    Implements a Conditional Altruism strategy with a warm-up phase and a 
    robustness mechanism to protect against exploitation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.permanent_defection = False

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        my_prev_actions = history.my_actions.astype(int)
        total_cooperators_history = history.opponent_cooperators + my_prev_actions
        success_mask = total_cooperators_history >= self.m
        successful_rounds_count = np.sum(success_mask)
        if t > self.r / 4:
            if successful_rounds_count < 0.2 * t:
                self.permanent_defection = True
        if self.permanent_defection:
            return Action.D
        s_prev = total_cooperators_history[-1]
        if t == self.r - 1:
            if s_prev >= self.m:
                return Action.C
            else:
                return Action.D
        if s_prev >= self.m:
            return Action.C
        elif t < self.r / 2:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_116(BaseStrategy):
    """
    Implements a Generous Triggered Contribution strategy for Collective Risk Dilemma.
    Prioritizes cooperation while employing a 'generous' buffer (m-1) and response triggers
    to manage exploitation and persistence of failure.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.consecutive_failed_rounds = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.desc.n_players
        m = self.desc.m
        r = self.desc.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        i_cooperated_prev = history.my_actions[-1]
        s_prev = history.opponent_cooperators[-1] + (1 if i_cooperated_prev else 0)
        if s_prev < m:
            self.consecutive_failed_rounds += 1
        else:
            self.consecutive_failed_rounds = 0
        if n - s_prev < m:
            return Action.D
        if self.consecutive_failed_rounds >= 3:
            return Action.D
        if current_round == r - 1:
            if s_prev >= m - 1:
                return Action.C
            else:
                return Action.D
        if s_prev >= m:
            return Action.C
        if s_prev >= m - 1:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_117(BaseStrategy):
    """
    Adaptive Threshold-Matching (ATM) strategy for Collective Risk Dilemma.
    Tracks collective cooperation to calibrate contributions, prioritizes threshold
    achievement while employing defensive defection and re-engagement probes.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description
        self.critical_penalty_rounds_remaining = 0

    def _is_prime(self, n: int) -> bool:
        if n < 2:
            return False
        if n == 2 or n == 3:
            return True
        if n % 2 == 0 or n % 3 == 0:
            return False
        i = 5
        while i * i <= n:
            if n % i == 0 or n % (i + 2) == 0:
                return False
            i += 6
        return True

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game.n_players
        m = self.game.m
        r = self.game.n_rounds
        current_round_idx = history.round_number
        if current_round_idx == 0:
            return Action.C if m / n > 0.5 else Action.D
        prev_idx = current_round_idx - 1
        prev_my_action = Action.C if history.my_actions[prev_idx] else Action.D
        prev_cooperators = history.opponent_cooperators[prev_idx] + (1 if prev_my_action == Action.C else 0)
        if current_round_idx == r - 1:
            success_count = 0
            for i in range(current_round_idx):
                opps = history.opponent_cooperators[i]
                my_act = 1 if history.my_actions[i] else 0
                if opps + my_act >= m:
                    success_count += 1
            if success_count / current_round_idx > 0.5:
                return Action.C
            return Action.D
        if self.critical_penalty_rounds_remaining > 0:
            self.critical_penalty_rounds_remaining -= 1
        was_critical = prev_cooperators == m and prev_my_action == Action.C
        if was_critical and prev_cooperators < m:
            self.critical_penalty_rounds_remaining = 2
            return Action.D
        if prev_cooperators >= m:
            return Action.C
        else:
            round_number_1idx = current_round_idx + 1
            is_prime_round = self._is_prime(round_number_1idx)
            divisor = max(1, math.floor(n / m))
            is_mod_round = round_number_1idx % divisor == 0
            if is_prime_round or is_mod_round:
                return Action.C
            else:
                return Action.D

class Strategy_BENEVOLENT_118(BaseStrategy):
    """
    Implements a Conditional Threshold Reciprocity strategy.
    
    This strategy focuses on sustaining cooperation while monitoring the group's
    capacity to meet the threshold 'm'. It employs periodic "benevolent probes"
    to re-establish cooperation after failures and acts as a pivot when
    the group is close to success.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.last_action = None

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            self.last_action = Action.C
            return Action.C
        n = self.desc.n_players
        m = self.desc.m
        my_prev_action = history.my_actions[-1]
        prev_my_contribution = 1 if my_prev_action else 0
        opp_prev_coop = history.opponent_cooperators[-1]
        c_obs = opp_prev_coop + prev_my_contribution
        if history.round_number == self.desc.n_rounds - 1:
            past_successes = sum((1 for i in range(history.round_number) if history.opponent_cooperators[i] + (1 if history.my_actions[i] else 0) >= m))
            if past_successes / history.round_number >= 0.5:
                self.last_action = Action.C
                return Action.C
            else:
                self.last_action = Action.D
                return Action.D
        if self.last_action == Action.D and c_obs == m - 1:
            self.last_action = Action.C
            return Action.C
        if self.last_action == Action.D and c_obs >= m:
            self.last_action = Action.D
            return Action.D
        if c_obs >= m:
            self.last_action = Action.C
            return Action.C
        if c_obs >= m - 1:
            self.last_action = Action.C
            return Action.C
        self.last_action = Action.D
        return Action.D

class Strategy_BENEVOLENT_119(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that balances cooperation with 
    tit-for-tat retaliation and benevolent recovery. It cooperates in the first 
    round, continues cooperating if the threshold was met, and uses a recovery
    mechanism if cooperation is close to the target, while defaulting to 
    defection if the threshold is missed significantly.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        my_last_action = 1 if history.my_actions[-1] else 0
        total_cooperators_last_round = my_last_action + history.opponent_cooperators[-1]
        if current_round == r - 1:
            if total_cooperators_last_round >= m - 1:
                return Action.C
            else:
                return Action.D
        if total_cooperators_last_round >= m:
            return Action.C
        if total_cooperators_last_round >= math.floor(m / 2):
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_120(BaseStrategy):
    """
    Implements a threshold-conditional trigger strategy (Collective Risk Dilemma).
    Maintains cooperation while punishing persistent exploitation and using a 
    forgiveness mechanism to recover from deadlock cycles.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if round_idx == self.game_description.n_rounds - 1:
            successes = 0
            for t in range(round_idx):
                my_val = 1 if history.my_actions[t] else 0
                total_c = history.opponent_cooperators[t] + my_val
                if total_c >= self.game_description.m:
                    successes += 1
            if successes > self.game_description.n_rounds / 2:
                return Action.C
            return Action.D
        prev_idx = round_idx - 1
        prev_my_action = history.my_actions[prev_idx]
        prev_opp_coop = history.opponent_cooperators[prev_idx]
        my_prev_val = 1 if prev_my_action == Action.C else 0
        prev_total_coop = prev_opp_coop + my_prev_val
        prev_success = prev_total_coop >= self.game_description.m
        if prev_success:
            if prev_my_action == Action.C:
                return Action.C
            else:
                return Action.C if random.random() > 0.5 else Action.D
        else:
            if prev_my_action == Action.C:
                return Action.D
            is_recovery_time = False
            if round_idx >= 2:
                idx_prev_prev = round_idx - 2
                prev_prev_action = history.my_actions[idx_prev_prev]
                prev_prev_opp_coop = history.opponent_cooperators[idx_prev_prev]
                prev_prev_total = prev_prev_opp_coop + (1 if prev_prev_action == Action.C else 0)
                if prev_prev_action == Action.D and prev_prev_total < self.game_description.m:
                    is_recovery_time = True
            if is_recovery_time:
                return Action.C
            return Action.D

class Strategy_BENEVOLENT_121(BaseStrategy):
    """
    A conditional cooperation strategy for the Collective Risk Dilemma.
    
    Logic:
    - Round 1: Cooperate.
    - Round t (not last):
        - If previous cooperators >= m: Cooperate.
        - If previous cooperators < m:
            - If shortfall == 1: Cooperate.
            - If shortfall > 1: Defect (if previously cooperating).
    - Last Round (r):
        - Cooperate if success rate (historical proportion of rounds where cooperators >= m) > 0.5.
        - Otherwise, Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description
        self.m = self.game.m

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game.n_rounds - 1:
            success_count = 0
            for c_count in history.opponent_cooperators:
                if c_count >= self.m:
                    success_count += 1
            success_rate = success_count / history.round_number
            return Action.C if success_rate > 0.5 else Action.D
        c_prev = int(history.opponent_cooperators[-1])
        if c_prev >= self.m:
            return Action.C
        shortfall = self.m - c_prev
        if shortfall == 1:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_122(BaseStrategy):
    """
    Adaptive Threshold Tit-for-Tat (ATTT)
    
    This strategy behaves as a "Conditional Cooperator." It aims to coordinate 
    on the threshold `m`. It cooperates if the previous round reached the threshold 
    or came within one of it (the "rescue" move). If the group fails to meet the 
    threshold by more than one, it switches to defection to preserve resources 
    until the group signals willingness to cooperate.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        last_round_idx = history.round_number - 1
        i_cooperated = 1 if history.my_actions[last_round_idx] else 0
        total_cooperators_prev = history.opponent_cooperators[last_round_idx] + i_cooperated
        if history.round_number == self.total_rounds - 1:
            if total_cooperators_prev >= self.m - 1:
                return Action.C
            else:
                return Action.D
        if total_cooperators_prev >= self.m - 1:
            return Action.C
        return Action.D

class Strategy_BENEVOLENT_123(BaseStrategy):
    """
    Implements an adaptive threshold strategy for the Collective Risk Dilemma.
    Starts with cooperation to build a baseline, then adjusts contribution
    based on whether the group meets the threshold 'm'. It includes a buffer
    'delta' to identify and avoid over-contribution, while attempting to rescue
    cooperation if the group is just one player short of the threshold.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.delta = 0.1

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        last_cooperators = history.opponent_cooperators[-1]
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number + 1
        if current_round == r:
            if last_cooperators >= m:
                return Action.C
            else:
                return Action.D
        if last_cooperators >= m:
            if last_cooperators > m + self.delta * n:
                return Action.D
            return Action.C
        else:
            if last_cooperators == m - 1:
                return Action.C
            return Action.D

class Strategy_BENEVOLENT_124(BaseStrategy):
    """
    Threshold-Targeting Reciprocity: A conditional cooperation strategy that targets 
    the collective threshold (m). It signals willingness by starting with Cooperation, 
    follows the threshold for intermediate rounds, and applies specific termination 
    logic and patience signaling (re-entry) to avoid persistent exploitation or 
    unnecessary failures.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        last_round_idx = history.round_number - 1
        last_opp_c = history.opponent_cooperators[last_round_idx]
        last_my_c = 1 if history.my_actions[last_round_idx] else 0
        total_cooperators_prev = last_opp_c + last_my_c
        if history.round_number == self.total_rounds - 1:
            if total_cooperators_prev >= self.m:
                return Action.D
            elif total_cooperators_prev == self.m - 1:
                return Action.C
            else:
                return Action.D
        consecutive_failures = 0
        for i in range(last_round_idx, -1, -1):
            opp_c = history.opponent_cooperators[i]
            my_c = 1 if history.my_actions[i] else 0
            if opp_c + my_c < self.m:
                consecutive_failures += 1
            else:
                break
        if consecutive_failures > 2:
            return Action.C
        if total_cooperators_prev >= self.m:
            return Action.D
        return Action.C

class Strategy_BENEVOLENT_125(BaseStrategy):
    """
    Threshold-Adaptive Tit-for-Tat (TA-TFT):
    A strategy that maintains a cooperative stance as long as the group threshold 'm' 
    is met or almost met. It defects when the threshold is unreachable to prevent 
    resource waste (avoiding the sucker's payoff), but remains open to 
    re-establishing cooperation if the group shows promise in future rounds.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.m = game_description.m
        self.n_rounds = game_description.n_rounds
        self.trust_score = self.m

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        c_last = history.opponent_cooperators[-1]
        my_last_action = Action.C if history.my_actions[-1] else Action.D
        total_cooperators = c_last + (1 if my_last_action == Action.C else 0)
        if history.round_number == self.n_rounds - 1:
            return Action.C if total_cooperators >= self.m else Action.D
        if total_cooperators >= self.m:
            return Action.C
        elif total_cooperators == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_126(BaseStrategy):
    """
    Implements the Threshold-Adaptive Trigger (TAT) strategy.
    
    TAT balances individual payoff optimization with collective goal achievement (m).
    It uses reinforcement-style logic based on the success of previous rounds,
    detects critical contribution needs, and identifies 'near-miss' scenarios
    to attempt recovery.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.n = game_description.n_players

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        t = history.round_number
        last_round_idx = t - 1
        last_my_action = 1 if history.my_actions[last_round_idx] else 0
        c_prev = history.opponent_cooperators[last_round_idx] + last_my_action
        if t == self.game_description.n_rounds - 1:
            successes = 0
            for r in range(t):
                m_act = 1 if history.my_actions[r] else 0
                opp_c = history.opponent_cooperators[r]
                if m_act + opp_c >= self.m:
                    successes += 1
            success_ratio = successes / t
            return Action.C if success_ratio > 0.5 else Action.D
        if c_prev >= self.m:
            if last_my_action == 1:
                if c_prev == self.m:
                    return Action.C
                else:
                    return Action.D
            else:
                return Action.D
        else:
            if c_prev == self.m - 1:
                return Action.C
            return Action.D

class Strategy_BENEVOLENT_127(BaseStrategy):
    """
    A strategic implementation for the Collective Risk Dilemma where the player
    adjusts cooperation based on threshold dynamics, specific participant count,
    and the finality of the round, aimed at maximizing collective outcomes.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        my_last_action = int(history.my_actions[-1])
        c_prev = history.opponent_cooperators[-1] + my_last_action
        if n <= 3:
            return Action.C if c_prev >= m - 1 else Action.D
        if history.round_number == r - 1:
            if c_prev >= math.floor(m / 2):
                return Action.C
            else:
                return Action.D
        if c_prev >= m:
            probability = m / n
            return Action.C if random.random() < probability else Action.D
        elif c_prev >= math.floor(m / 2):
            return Action.C
        else:
            return Action.D

class Strategy_BENEVOLENT_128(BaseStrategy):
    """
    Threshold-Aware Adaptive Conditional Cooperation.
    This strategy dynamically adjusts cooperation based on group performance metrics,
    tracking both successful thresholds and persistent failure states to optimize
    individual outcomes in a Collective Risk Dilemma.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0
        self.sudden_drop_cooldown = 0
        self.successful_rounds = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        t = history.round_number
        if t == 0:
            return Action.C
        my_action_prev = bool(history.my_actions[-1])
        other_coop_prev = history.opponent_cooperators[-1]
        c_prev = other_coop_prev + int(my_action_prev)
        if c_prev >= m:
            self.successful_rounds += 1
            self.consecutive_failures = 0
        else:
            self.consecutive_failures += 1
        if self.sudden_drop_cooldown > 0:
            self.sudden_drop_cooldown -= 1
        if t >= r - 2:
            if self.successful_rounds / t > 0.5:
                return Action.C
            else:
                return Action.D
        if self.consecutive_failures >= 3:
            return Action.D
        if t > 1:
            prev_c_prev = history.opponent_cooperators[-2] + int(history.my_actions[-2])
            if prev_c_prev >= m and c_prev < m / 2:
                self.sudden_drop_cooldown = 1
                return Action.D
            if self.sudden_drop_cooldown > 0:
                return Action.C
        if c_prev >= m:
            return Action.C
        elif c_prev + 1 >= m:
            return Action.C
        elif m - c_prev < n / 2:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_33(BaseStrategy):
    """
    A conditional reciprocity strategy for the Collective Risk Dilemma.
    It initiates based on the probability of reaching the threshold and adjusts 
    subsequent moves based on whether the threshold was met in the previous round, 
    attempting to pivot only when necessary.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = self.game_description.n_players
        self.r = self.game_description.n_rounds
        self.m = self.game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_idx = history.round_number
        if current_round_idx == 0:
            if self.m / self.n <= 0.5:
                return Action.C
            return Action.D
        if current_round_idx == self.r - 1:
            return Action.D
        last_round_cooperators = history.opponent_cooperators[-1]
        i_cooperated_last = 1 if history.my_actions[-1] else 0
        total_cooperators_last = last_round_cooperators + i_cooperated_last
        if total_cooperators_last >= self.m:
            return Action.D
        if last_round_cooperators == self.m - 1:
            return Action.C
        return Action.D

class Strategy_SELFISH_34(BaseStrategy):
    """
    Implements a Threshold-seeking Conditional Contribution strategy:
    - Round 1: Always Cooperate (C).
    - Rounds 1 < t < r:
        - If previous round threshold m met (cooperators >= m), Defect (D).
        - If threshold m not met (cooperators < m):
            - If previously C, stay C.
            - If previously D, cooperate with probability p = 1 - (C_{t-1} / m).
    - Final Round r: Always Defect (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == n_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        last_round_idx = -1
        last_opponent_coop_count = history.opponent_cooperators[last_round_idx]
        last_my_action = history.my_actions[last_round_idx]
        my_prev_contrib = 1 if last_my_action else 0
        total_cooperators_prev = last_opponent_coop_count + my_prev_contrib
        if total_cooperators_prev >= m:
            return Action.D
        else:
            if last_my_action:
                return Action.C
            p = 1.0 - total_cooperators_prev / m
            if random.random() < p:
                return Action.C
            else:
                return Action.D

class Strategy_SELFISH_35(BaseStrategy):
    """
    Threshold-Dependent Adaptive Defection:
    A strategy that defaults to Defect. In rounds 1 < t < r, it cooperates only if the 
    previous round's cooperation count was exactly m-1, effectively bridging the gap 
    to trigger the threshold reward k. It ignores cooperation if the threshold is 
    already met (free riding) or if the gap is too large to close (minimizing loss).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        if t == 0:
            return Action.D
        if t == r - 1:
            return Action.D
        my_last_action = history.my_actions[-1]
        my_c_last = 1 if my_last_action else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + my_c_last
        if total_cooperators_prev >= m:
            self.consecutive_failures = 0
            return Action.D
        if total_cooperators_prev == m - 1:
            self.consecutive_failures = 0
            return Action.C
        self.consecutive_failures += 1
        if self.consecutive_failures >= 3:
            return Action.D
        return Action.D

class Strategy_SELFISH_36(BaseStrategy):
    """
    Collective Risk Dilemma strategy:
    - First round: D.
    - Last round: D.
    - If k <= 1: Always D.
    - If previous round threshold was met (cooperators >= m): D.
    - If previous round threshold was NOT met:
        - Check if own contributions in rolling window x = ceil(r/4)
          are less than failed threshold events. If so, C.
        - Otherwise, D.
    - Special: If consistent failure trend detected (C_{t-1} == m-1), trigger one round of C.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.x = math.ceil(self.game_description.n_rounds / 4)
        self.failed_threshold_events = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if self.game_description.k <= 1:
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.D
        my_prev_action = int(history.my_actions[-1])
        total_cooperators_prev = history.opponent_cooperators[-1] + my_prev_action
        prev_round_failed = total_cooperators_prev < self.game_description.m
        if prev_round_failed:
            self.failed_threshold_events += 1
        if total_cooperators_prev == self.game_description.m - 1:
            return Action.C
        if not prev_round_failed:
            return Action.D
        start_idx = max(0, history.round_number - self.x)
        recent_my_contributions = np.sum(history.my_actions[start_idx:])
        if recent_my_contributions < self.failed_threshold_events:
            return Action.C
        return Action.D

class Strategy_SELFISH_37(BaseStrategy):
    """
    Threshold-Triggered Conditional Cooperation Strategy.
    
    This strategy attempts to secure the collective reward 'k' by monitoring the
    cooperation levels of the opponent population. It pivots between conditional
    cooperation when necessary to meet the threshold 'm' and defection when the 
    threshold is either already met or impossible to reach. It also includes
    a "giving up" mechanism if the population appears consistently non-cooperative.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failed_thresholds = 0
        self.giving_up = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        k = self.game_description.k
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        if current_round == 0:
            if m / n <= 0.5:
                return Action.C
            else:
                return Action.D
        if self.giving_up:
            return Action.D
        my_last_action = history.my_actions[-1]
        my_last_contrib = 1 if my_last_action == Action.C else 0
        s_prev = history.opponent_cooperators[-1] + my_last_contrib
        if s_prev < m and my_last_action == Action.C:
            self.consecutive_failed_thresholds += 1
        else:
            self.consecutive_failed_thresholds = 0
        if self.consecutive_failed_thresholds >= 3:
            self.giving_up = True
            return Action.D
        high_reward_mode = k - 1 > 1
        if s_prev > m:
            return Action.D
        if s_prev == m:
            return Action.C
        if s_prev == m - 1 or (high_reward_mode and s_prev >= m - 1):
            return Action.C
        return Action.D

class Strategy_SELFISH_38(BaseStrategy):
    """
    Threshold-Dependent Conditional Defection:
    - First round: Always defect.
    - Last round: Always defect.
    - Success (prev_total_cooperators >= m): Defect to free-ride.
    - Failure (prev_total_cooperators < m): Cooperate only if pivotal (prev_total_cooperators == m - 1), otherwise defect.
    
    Logic assumes prev_total_cooperators accounts for all players.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.D
        m = self.game_description.m
        my_last_action_int = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + my_last_action_int
        if total_cooperators_prev >= m:
            return Action.D
        if total_cooperators_prev == m - 1:
            return Action.C
        return Action.D

class Strategy_SELFISH_39(BaseStrategy):
    """
    Threshold-Conditional Reciprocity (TCR):
    An adaptive strategy that initiates cooperation to test the group, then 
    dynamically adjusts between free-riding (when the reward is safe) and 
    contributing (when the threshold is at risk). It includes a patience 
    decay mechanism to break deadlocks by re-testing the group's willingness.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0
        self.init_prob = self.game_description.m / self.game_description.n_players

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            if random.random() < self.init_prob:
                return Action.C
            return Action.D
        prev_my_action = history.my_actions[-1]
        prev_opp_coop = history.opponent_cooperators[-1]
        prev_total_coop = prev_opp_coop + (1 if prev_my_action else 0)
        if prev_total_coop < self.game_description.m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures > 2:
            self.consecutive_failures = 0
            if random.random() < self.init_prob:
                return Action.C
            return Action.D
        if prev_total_coop > self.game_description.m:
            return Action.D
        if prev_total_coop == self.game_description.m:
            if prev_my_action:
                return Action.C
            else:
                return Action.D
        if prev_total_coop < self.game_description.m:
            return Action.D
        return Action.D

class Strategy_SELFISH_40(BaseStrategy):
    """
    Implements a Threshold-Targeted Conditional Defection strategy.
    
    This strategy seeks to maximize individual payoff by free-riding on the collective
    threshold 'm'. It attempts to ensure the threshold is met only when it acts as
    the marginal contributor, otherwise defaulting to defection (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        my_last_action = bool(history.my_actions[-1])
        others_contributed = int(history.opponent_cooperators[-1])
        total_cooperators_prev = (1 if my_last_action else 0) + others_contributed
        m = self.game_description.m
        if m <= 1:
            return Action.D
        if total_cooperators_prev >= m:
            return Action.D
        if others_contributed == m - 1:
            return Action.C
        return Action.D

class Strategy_SELFISH_41(BaseStrategy):
    """
    Threshold-Conditional Tit-for-Tat: A strategy that cooperates with probability m/n
    in the first round, and subsequently acts conditionally based on whether the
    group threshold 'm' was met in the previous round, attempting to minimize
    contributions while ensuring the reward 'k' is secured.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.group_ever_cooperated = False

    def __call__(self, history: PlayerHistory) -> Action:
        if self.desc.k <= 1.0:
            return Action.D
        if history.round_number == 0:
            if random.random() < self.desc.m / self.desc.n_players:
                return Action.C
            return Action.D
        prev_my_action = history.my_actions[-1]
        prev_opp_coop = history.opponent_cooperators[-1]
        my_contrib = 1 if prev_my_action else 0
        total_coop = prev_opp_coop + my_contrib
        if total_coop >= self.desc.m:
            self.group_ever_cooperated = True
        if not self.group_ever_cooperated:
            return Action.D
        if prev_my_action:
            if total_coop > self.desc.m:
                return Action.D
            elif total_coop == self.desc.m:
                return Action.C
            elif total_coop == self.desc.m - 1:
                return Action.C
            else:
                return Action.D
        elif total_coop >= self.desc.m:
            return Action.D
        elif total_coop == self.desc.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_42(BaseStrategy):
    """
    A threshold-aware strategy for the Collective Risk Dilemma.
    
    Logic:
    1. First round: Always Cooperate (C) to build trust/signal intent.
    2. Final round: Always Defect (D) to maximize terminal payoff.
    3. Intermediate rounds:
       - If previous threshold contributors >= m + 1: Defect (free-ride on surplus).
       - If previous threshold contributors == m: Cooperate (maintain threshold).
       - If previous threshold contributors < m:
         - If deficit is 1: Cooperate (attempt recovery).
         - If deficit > 1: Defect (cut losses).
    4. Adaptive Failure Mechanism: If the group consistently fails to reach the 
       threshold across rounds, the strategy permanently switches to Defect (D) 
       to preserve personal endowment.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.total_rounds = game_description.n_rounds
        self.has_abandoned_cooperation = False

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.total_rounds - 1:
            return Action.D
        if self.has_abandoned_cooperation:
            return Action.D
        my_prev_action = 1 if history.my_actions[-1] else 0
        total_prev_cooperators = history.opponent_cooperators[-1] + my_prev_action
        if total_prev_cooperators < self.m:
            recent_failures = 0
            for r_idx in range(current_round):
                prev_my = 1 if history.my_actions[r_idx] else 0
                prev_opp = history.opponent_cooperators[r_idx]
                if prev_my + prev_opp < self.m:
                    recent_failures += 1
            if recent_failures / current_round > 0.5:
                self.has_abandoned_cooperation = True
                return Action.D
        if total_prev_cooperators >= self.m + 1:
            return Action.D
        if total_prev_cooperators == self.m:
            return Action.C
        deficit = self.m - total_prev_cooperators
        if deficit <= 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_43(BaseStrategy):
    """
    Threshold-Sensitive Tit-for-Tat (TS-TFT).
    
    This strategy balances free-riding incentives against collective project requirements.
    - Round 1: Always Cooperate.
    - Final Round: Always Defect.
    - Ongoing Logic:
        - If previous count >= m: Defect (free-ride).
        - If previous count == m-1: Cooperate (help meet threshold).
        - If previous count < m-1: Defect (project already doomed).
    - Emergency Protocol: If failure (count < m-1) persists for 2 consecutive rounds,
      switch to permanent Defection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0
        self.locked_defect = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if self.locked_defect:
            return Action.D
        prev_count = history.opponent_cooperators[-1]
        m = self.game_description.m
        if prev_count < m - 1:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 2:
            self.locked_defect = True
            return Action.D
        if prev_count >= m:
            return Action.D
        if prev_count == m - 1:
            return Action.C
        return Action.D

class Strategy_SELFISH_44(BaseStrategy):
    """
    Implements a selfish strategy that aims to minimize contribution costs while maximizing rewards.
    The strategy cooperates only when it is the 'pivot' player (i.e., when n_cooperators == m-1)
    to secure the reward k. Otherwise, it defects to preserve its endowment.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if self.game_description.k <= 1:
            return Action.D
        current_round = history.round_number
        if current_round == self.game_description.n_rounds - 1:
            return Action.D
        if current_round == 0:
            if self.game_description.m == 1:
                return Action.C
            return Action.D
        prev_opponents = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        c_prev = prev_opponents + (1 if my_prev_action else 0)
        if c_prev >= self.game_description.m:
            return Action.D
        if c_prev == self.game_description.m - 1:
            return Action.C
        return Action.D

class Strategy_SELFISH_45(BaseStrategy):
    """
    Implements a conditional cooperation strategy for the Collective Risk Dilemma:
    - Round 0: Always Defect (D).
    - Subsequent rounds:
        - If O >= m: Defect (D) to free-ride.
        - If O == m - 1: Cooperate (C) to trigger the reward.
        - If O < m - 1: Defect (D) as cooperation cannot reach the threshold.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        O = int(history.opponent_cooperators[-1])
        if O >= self.m:
            return Action.D
        elif O == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_46(BaseStrategy):
    """
    Implements a Threshold-Targeting Tit-for-Tat strategy.
    
    This strategy attempts to reach the threshold `m` by only contributing when 
    the collective is exactly one short of the threshold (`m-1`), maximizing 
    payoffs by minimizing individual costs while securing the reward `k`.
    It defaults to defection in the first round and the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_idx = history.round_number
        if current_round_idx == self.r - 1:
            return Action.D
        if current_round_idx == 0:
            return Action.D
        prev_round_cooperators = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        my_prev_coop = 1 if my_prev_action == Action.C else 0
        total_cooperators = prev_round_cooperators + my_prev_coop
        if total_cooperators >= self.m:
            return Action.D
        elif total_cooperators == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_47(BaseStrategy):
    """
    Threshold-Adaptive Free-Rider strategy:
    Prioritizes personal gain while attempting to incentivize just enough 
    cooperation to trigger the collective reward k, adjusting dynamically 
    based on the previous round's performance and the player's own contribution.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        round_idx = history.round_number
        if round_idx == self.r - 1:
            return Action.D
        if round_idx == 0:
            return Action.D
        last_action_was_c = bool(history.my_actions[-1])
        opp_c = history.opponent_cooperators[-1]
        total_c = opp_c + (1 if last_action_was_c else 0)
        if not last_action_was_c:
            if total_c >= self.m:
                return Action.D
            elif total_c == self.m - 1:
                return Action.C
            else:
                return Action.D
        elif total_c > self.m:
            return Action.D
        elif total_c == self.m:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_48(BaseStrategy):
    """
    Implements a risk-aware strategy for the Collective Risk Dilemma.
    Strategy:
    - Round 0: Defect.
    - Subsequent rounds:
        - If last round: Defect.
        - If recent group performance (past 3 rounds) is sufficient to meet threshold 'm', Defect (free-ride).
        - If threshold gap is 1 and k > 1, Cooperate to secure the reward.
        - Otherwise, Defect.
        - Adjustment logic: If Cooperated last round and the threshold was not met, switch to Defect immediately.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.k = game_description.k
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        rounds_left = self.r - current_round
        if current_round == 0:
            return Action.D
        if rounds_left == 1:
            return Action.D
        prev_my_action = history.my_actions[-1]
        prev_opp_coops = history.opponent_cooperators[-1]
        c_i = 1 if prev_my_action else 0
        total_coops = prev_opp_coops + c_i
        if prev_my_action and total_coops < self.m:
            return Action.D
        start_idx = max(0, current_round - 3)
        recent_coops = history.opponent_cooperators[start_idx:] + history.my_actions[start_idx:].astype(int)
        if len(recent_coops) > 0:
            avg_coop = float(np.mean(recent_coops))
        else:
            avg_coop = 0.0
        if avg_coop >= self.m:
            return Action.D
        current_gap = self.m - total_coops
        if current_gap == 1 and self.k > 1:
            return Action.C
        return Action.D

class Strategy_SELFISH_49(BaseStrategy):
    """
    Threshold-Conditional Tit-for-Tat:
    Exploits the threshold mechanism by free-riding when the threshold is met,
    and attempting to bridge the gap (by contributing) only when missing the
    threshold by exactly one person.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if self.k <= 1:
            return Action.D
        if history.round_number == 0:
            return Action.D
        if history.round_number == self.r - 1:
            return Action.D
        prev_opp_coops = history.opponent_cooperators[-1]
        prev_my_action = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = prev_opp_coops + prev_my_action
        if total_cooperators_prev >= self.m + 1:
            return Action.D
        if total_cooperators_prev >= self.m:
            return Action.D
        gap = self.m - total_cooperators_prev
        if gap == 1:
            if random.random() < 1.0 / self.n:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_SELFISH_50(BaseStrategy):
    """
    Implements a Conditional Threshold Tracker strategy.
    
    1. Round 0: Always defects to observe baseline cooperation.
    2. Rounds 1 to r-2:
       - If previous cooperators >= m: Defect (Free-ride).
       - If previous cooperators == m - 1: Cooperate (Trigger reward).
       - Otherwise: Defect (Avoid wasted contribution).
    3. Round r-1 (Final round):
       - Same logic as intermediate rounds, as the incentive to cooperate 
         only exists if it triggers the reward (k > 1), and there is 
         no future penalty/reward structure defined beyond the threshold.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        n_c = history.opponent_cooperators[-1]
        if n_c >= self.m:
            return Action.D
        my_last_action = history.my_actions[-1]
        my_contribution = 1 if my_last_action == Action.C else 0
        total_cooperators = n_c + my_contribution
        if total_cooperators >= self.m:
            return Action.D
        elif total_cooperators == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_51(BaseStrategy):
    """
    A strategy that adopts a 'Conditional Threshold' approach to maximize individual payoff.
    It defects in the first round to test the environment. In subsequent rounds, it
    only cooperates if it acts as the 'pivotal' player (the m-th cooperator required to 
    unlock the reward k). If the reward k <= 1, it defaults to unconditional defection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.always_defect = self.game_description.k <= 1.0

    def __call__(self, history: PlayerHistory) -> Action:
        if self.always_defect:
            return Action.D
        if history.round_number == 0:
            return Action.D
        my_last_action = Action.C if history.my_actions[-1] else Action.D
        total_cooperators_last_round = history.opponent_cooperators[-1] + (1 if my_last_action == Action.C else 0)
        if total_cooperators_last_round >= self.game_description.m:
            return Action.D
        if history.opponent_cooperators[-1] == self.game_description.m - 1:
            return Action.C
        return Action.D

class Strategy_SELFISH_52(BaseStrategy):
    """
    Implements an Adaptive Threshold-Seeking Strategy.
    
    Logic:
    - Round 1: Defect (D).
    - If Threshold Met (N_c >= m): 
        - If N_c == m: Cooperate (C) to protect threshold.
        - Else: Defect (D) to free-ride.
    - If Threshold Not Met (N_c < m):
        - If Gap == 1: Cooperate (C) to trigger.
        - Else: Defect (D) to conserve resources.
    - Final Round Override:
        - If N_c == m - 1: Cooperate (C).
        - Else: Defect (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = self.desc.n_rounds
        m = self.desc.m
        if history.round_number == 0:
            return Action.D
        current_round = history.round_number + 1
        my_prev_action = history.my_actions[-1]
        opp_coop_prev = history.opponent_cooperators[-1]
        if my_prev_action == Action.C:
            n_c_prev = opp_coop_prev + 1
        else:
            n_c_prev = opp_coop_prev
        gap = m - n_c_prev
        if current_round == n_rounds:
            if n_c_prev == m - 1:
                return Action.C
            else:
                return Action.D
        if n_c_prev >= m:
            if n_c_prev == m:
                return Action.C
            else:
                return Action.D
        elif gap == 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_53(BaseStrategy):
    """
    Threshold-Adaptive Free-Riding strategy.
    
    This strategy aims to maximize cumulative payoff by minimizing personal contributions
    while free-riding on the group contribution whenever the threshold m is reached.
    
    Logic:
    1. Rounds 0 (Calibration): Always Defect.
    2. Terminal Round: Always Defect.
    3. Intermediate Rounds:
        - If previous cooperators >= m: Defect (Free-ride).
        - If previous cooperators == m - 1: Cooperate if reward k > 2 (net gain), else Defect.
        - Otherwise: Defect (Threshold unreachable).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        if history.round_number == self.game.n_rounds - 1:
            return Action.D
        previous_cooperators = history.opponent_cooperators[-1]
        if self.game.k <= 1:
            return Action.D
        if previous_cooperators >= self.game.m:
            return Action.D
        if previous_cooperators == self.game.m - 1:
            if self.game.k > 2:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_SELFISH_54(BaseStrategy):
    """
    A strategy that plays Defect in the first round. 
    In subsequent rounds, it observes the aggregate cooperation count ($N_c$) 
    from the previous round. It plays Defect if $N_c \\ge m$, or if the gap 
    to the threshold is not exactly one player. It plays Cooperate only 
    when the group is exactly one player short of the threshold ($N_c == m - 1$).
    If $k < 1$, it defaults to Defect for all rounds.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if self.k < 1.0:
            return Action.D
        if history.round_number == 0:
            return Action.D
        last_my_action = history.my_actions[-1]
        last_opponent_coop = history.opponent_cooperators[-1]
        n_c = last_opponent_coop + (1 if last_my_action else 0)
        if n_c >= self.m:
            return Action.D
        elif n_c == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_55(BaseStrategy):
    """
    Implements a conditional threshold strategy for the Collective Risk Dilemma.
    The strategy alternates between defecting to free-ride and conditionally 
    cooperating when it is necessary to meet the minimum threshold m. It features
    a failure-detection mechanism that switches to permanent defection if 
    the collective threshold consistently proves unattainable.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.cooperation_futile = False

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == n_rounds - 1:
            return Action.D
        if current_round == 0:
            if m == 1:
                return Action.D
            return Action.D
        prev_opp_cooperators = history.opponent_cooperators[-1]
        prev_my_action = history.my_actions[-1]
        c_prev = prev_opp_cooperators + (1 if prev_my_action == Action.C else 0)
        if c_prev < m:
            if prev_my_action == Action.C:
                self.cooperation_futile = True
        if self.cooperation_futile:
            return Action.D
        if m == 1:
            return Action.D
        if c_prev >= m + 1:
            return Action.D
        elif c_prev == m:
            return Action.D
        elif c_prev == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_56(BaseStrategy):
    """
    Implements a Conditional Free-Rider strategy.
    Prioritizes individual payoff maximization (Defect) by default.
    Maintains a role flag S to strategically contribute only when the 
    threshold (m) is one participant away, 'testing' the group's 
    willingness to cooperate before committing resources.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.s_flag = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number > 0:
            last_r = history.round_number - 1
            my_last_action = history.my_actions[last_r]
            c_last = history.opponent_cooperators[last_r] + (1 if my_last_action else 0)
            if not my_last_action:
                if c_last == self.game_description.m - 1:
                    self.s_flag = True
            elif c_last < self.game_description.m:
                self.s_flag = False
            else:
                self.s_flag = True
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.D
        last_r = history.round_number - 1
        c_prev = history.opponent_cooperators[last_r] + (1 if history.my_actions[last_r] else 0)
        if c_prev >= self.game_description.m:
            self.s_flag = False
            return Action.D
        if c_prev == self.game_description.m - 1:
            if self.s_flag:
                return Action.C
            else:
                return Action.D
        self.s_flag = False
        return Action.D

class Strategy_SELFISH_57(BaseStrategy):
    """
    Threshold-Sensitive Tit-for-Tat with Conditional Altruism.
    
    Strategies:
    - Initial Round: Always Cooperate.
    - Subsequent:
        - If Threshold Met (S >= m): Defect.
        - If Threshold Not Met (S < m):
            - Pivotal (D_d == 1): Cooperate.
            - Otherwise: Defect.
    - Overrides:
        - Last-Ditch (t=r): Cooperate if threshold was met in >= 50% of previous rounds AND D_d <= 1, else Defect.
        - Collapse: If S=0 for two consecutive rounds, Defect forever.
        - Greedy: If cumulative payoff > expected average, Defect (unless D_d == 1).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_zeros = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        k = self.game_description.k
        current_round_idx = history.round_number
        if current_round_idx == 0:
            return Action.C
        s_prev = int(history.opponent_cooperators[-1])
        if s_prev == 0:
            self.consecutive_zeros += 1
        else:
            self.consecutive_zeros = 0
        if self.consecutive_zeros >= 2:
            return Action.D
        successes = 0
        for i in range(current_round_idx):
            if history.opponent_cooperators[i] >= m:
                successes += 1
        expected_avg_return = k * (successes / r)
        cumulative_payoff = float(np.sum(history.my_payoffs))
        is_greedy = cumulative_payoff > expected_avg_return * current_round_idx + 1.0
        d_deficit = m - s_prev
        if is_greedy and d_deficit != 1:
            return Action.D
        if current_round_idx == r - 1:
            prev_rounds_count = current_round_idx
            if prev_rounds_count > 0:
                success_ratio = successes / prev_rounds_count
                if success_ratio >= 0.5 and d_deficit <= 1:
                    return Action.C
            return Action.D
        if s_prev >= m:
            return Action.D
        elif d_deficit == 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_58(BaseStrategy):
    """
    Implements a conditional threshold-triggered defection strategy for the Collective Risk Dilemma.
    
    Logic Summary:
    1. Initial Phase (Round 1): Always Defect.
    2. Observation/Mid-game Phase:
       - If the threshold (m) was met or exceeded in the previous round, Defect (free-ride).
       - If the group provided m-1 cooperators, Cooperate (marginal contribution).
       - If the group provided fewer than m-1, Defect (unreliable group).
    3. Final Phase (Round r):
       - Defect by default.
       - Exception: Cooperate only if the group has consistently provided exactly m-1 cooperators
         in at least 80% of previous rounds, and you are the marginal contributor.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_idx = history.round_number
        total_rounds = self.desc.n_rounds
        m = self.desc.m
        if current_round_idx == 0:
            return Action.D
        prev_my_actions = history.my_actions.astype(int)
        total_coops = history.opponent_cooperators + prev_my_actions
        prev_total_coops = total_coops[-1]
        if current_round_idx == total_rounds - 1:
            historical_m_minus_1_rate = np.mean(history.opponent_cooperators == m - 1)
            if historical_m_minus_1_rate >= 0.8 and history.opponent_cooperators[-1] == m - 1:
                return Action.C
            return Action.D
        if prev_total_coops >= m:
            return Action.D
        if prev_total_coops == m - 1:
            reliability_mask = history.opponent_cooperators == m - 1
            if np.mean(reliability_mask) > 0.5:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_SELFISH_59(BaseStrategy):
    """
    A strategic agent that dynamically adjusts cooperation based on threshold proximity
    and group history, aiming to secure reward 'k' only when pivotal.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description
        self.testing_pivotal = False
        self.testing_vulnerability = False
        self.override_cooperate_permanently = False
        self.override_defect_permanently = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        if history.round_number == self.game.n_rounds - 1:
            return Action.D
        my_prev_action = int(history.my_actions[-1])
        h_prev = history.opponent_cooperators[-1] + my_prev_action
        if self.override_defect_permanently:
            return Action.D
        if self.override_cooperate_permanently:
            return Action.C
        if h_prev == self.game.m and (not self.testing_vulnerability):
            if history.round_number >= 2 and history.opponent_cooperators[-2] + int(history.my_actions[-2]) == self.game.m:
                self.testing_vulnerability = True
                return Action.D
        if self.testing_vulnerability:
            if h_prev >= self.game.m:
                self.override_defect_permanently = True
                return Action.D
            elif h_prev == self.game.m - 1:
                self.testing_vulnerability = False
                return Action.C
            self.testing_vulnerability = False
        if h_prev == self.game.m - 1 and (not self.testing_pivotal):
            if history.round_number >= 2 and history.opponent_cooperators[-2] + int(history.my_actions[-2]) == self.game.m - 1:
                self.testing_pivotal = True
                return Action.D
        if self.testing_pivotal:
            if history.opponent_cooperators[-1] >= self.game.m:
                self.override_defect_permanently = True
                self.testing_pivotal = False
                return Action.D
            else:
                remaining_rounds = self.game.n_rounds - history.round_number
                if remaining_rounds * (self.game.k - 1) >= 0:
                    self.override_cooperate_permanently = True
                    return Action.C
                else:
                    self.override_defect_permanently = True
                    return Action.D
        if h_prev >= self.game.m:
            return Action.D
        elif h_prev == self.game.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_60(BaseStrategy):
    """
    Threshold-Conditional Cooperation:
    - Round 1: Defect.
    - Subsequent Rounds (2 to r-1): 
        - If previous C count >= m: Defect.
        - If previous C count == m - 1: Cooperate (with stochastic tie-breaking).
        - If previous C count < m - 1: Defect.
    - Final Round: Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self._tie_break_priority = random.random()

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == 0:
            return Action.D
        if current_round == total_rounds - 1:
            return Action.D
        my_prev_action = history.my_actions[-1]
        my_prev_c = 1 if my_prev_action else 0
        total_prev_c = history.opponent_cooperators[-1] + my_prev_c
        if total_prev_c >= m:
            return Action.D
        if total_prev_c == m - 1:
            if self._tie_break_priority > 0.5:
                return Action.C
            return Action.D
        return Action.D

class Strategy_SELFISH_61(BaseStrategy):
    """
    A threshold-matching strategy that defaults to Defection (D) but switches
    to Cooperation (C) only when the player's contribution is necessary to 
    reach the threshold 'm' and unlock the reward 'k'.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        last_round_i_cooperated = int(history.my_actions[-1])
        n_c = history.opponent_cooperators[-1] + last_round_i_cooperated
        if n_c >= self.game_description.m:
            return Action.D
        elif n_c == self.game_description.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_62(BaseStrategy):
    """
    Implements a Dynamic Threshold Conditional Cooperation strategy.
    
    Logic:
    - Round 1: Cooperate (C) to signal.
    - Subsequent (t > 1):
        - If previously C and success (C_prev >= m): Continue C.
        - If previously C and failure (C_prev < m): Switch to D and initiate 'Failure Recovery'
          (retry C every 3 rounds).
        - If previously D and success (C_prev >= m): Continue D (free-ride).
        - If previously D and threshold-adjacent (C_prev == m - 1): Switch to C.
        - Otherwise: D.
    - Terminal Round: Defect (D).
    - Threshold Marginality: If m is very close to n, default to D.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.recovery_countdown = 0
        self.failed_permanently = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.desc.n_players
        m = self.desc.m
        r = self.desc.n_rounds
        current_round = history.round_number
        if m >= n - 1:
            return Action.D
        if current_round == r - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        prev_my_action = history.my_actions[-1]
        prev_total_cooperators = history.opponent_cooperators[-1]
        total_coop_prev = (1 if prev_my_action else 0) + prev_total_cooperators
        if self.recovery_countdown > 0:
            self.recovery_countdown -= 1
        if self.failed_permanently:
            return Action.D
        if prev_my_action:
            if total_coop_prev >= m:
                self.recovery_countdown = 0
                return Action.C
            else:
                self.recovery_countdown = 3
                return Action.D
        elif self.recovery_countdown == 0:
            if total_coop_prev >= m:
                return Action.D
            elif total_coop_prev == m - 1:
                return Action.C
            else:
                return Action.D
        elif self.recovery_countdown == 1:
            self.recovery_countdown = 0
            if total_coop_prev < m:
                return Action.C
            return Action.C
        else:
            return Action.D
        return Action.D

class Strategy_SELFISH_63(BaseStrategy):
    """
    Implements a Conditional Threshold-Seeking Defection strategy.
    
    This strategy aims to secure the reward k by contributing only when necessary
    to meet the cooperation threshold m. It tests if the threshold can be met
    without the player's contribution, defecting whenever possible.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        prev_my_action = history.my_actions[-1]
        prev_opp_count = history.opponent_cooperators[-1]
        my_prev_contribution = 1 if prev_my_action else 0
        total_cooperators_prev = prev_opp_count + my_prev_contribution
        next_action = Action.D
        if prev_my_action == True:
            if total_cooperators_prev >= self.desc.m:
                next_action = Action.D
            else:
                next_action = Action.C
        elif total_cooperators_prev >= self.desc.m:
            next_action = Action.D
        elif total_cooperators_prev == self.desc.m - 1:
            next_action = Action.C
        else:
            next_action = Action.D
        if current_round == self.desc.n_rounds - 1:
            if self.desc.k <= 1:
                return Action.D
            if prev_opp_count == self.desc.m - 1:
                return Action.C
            else:
                return Action.D
        return next_action

class Strategy_SELFISH_64(BaseStrategy):
    """
    Implements a Threshold-Targeted Conditional Defection strategy.
    
    Logic:
    - Round 1: Always Defect.
    - Final Round: Always Defect.
    - Intermediate Rounds:
        - Calculate average cooperators (H) from history.
        - If previous round result was m (threshold met exactly) or H >= m: Defect (Free-riding).
        - If previous round result was m-1 (threshold missed by one) or (m-1 <= H < m): Cooperate (Tipping).
        - Otherwise: Defect (Ineffective contribution).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        round_idx = history.round_number
        if round_idx == 0:
            return Action.D
        if round_idx == r - 1:
            return Action.D
        last_round_idx = round_idx - 1
        my_last_action = int(history.my_actions[last_round_idx])
        opp_last_coops = history.opponent_cooperators[last_round_idx]
        total_coops_last = opp_last_coops + my_last_action
        if total_coops_last == m:
            return Action.D
        if total_coops_last == m - 1:
            return Action.C
        total_coops_array = history.opponent_cooperators + history.my_actions.astype(int)
        h = np.mean(total_coops_array)
        if h >= m:
            return Action.D
        elif m - 1 <= h < m:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_65(BaseStrategy):
    """
    Conditional Threshold Monitoring Strategy:
    - Round 1 (0): Always Defect.
    - Subsequent rounds:
        - If previous cooperation count >= m, Defect.
        - If previous cooperation count == m - 1, Cooperate to trigger the reward.
        - If previous cooperation count < m - 1, Defect.
    - Threshold Infeasibility: If the threshold has never been met in the past,
      never cooperate.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.has_threshold_ever_been_met = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        last_round_idx = history.round_number - 1
        last_cooperation_count = history.opponent_cooperators[last_round_idx]
        if history.my_actions[last_round_idx]:
            total_cooperators = last_cooperation_count + 1
        else:
            total_cooperators = last_cooperation_count
        if total_cooperators >= self.m:
            self.has_threshold_ever_been_met = True
        if not self.has_threshold_ever_been_met:
            return Action.D
        if total_cooperators >= self.m:
            return Action.D
        elif total_cooperators == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_66(BaseStrategy):
    """
    Implements a Threshold Tit-for-Tat with Conditional Defection strategy.
    
    Strategy logic:
    - Round 1: Always Cooperate (C) to establish willingness.
    - Final Round: Always Defect (D) as there is no future incentive.
    - Intermediate Rounds:
        - If previous round's cooperation count >= m: Threshold already met, Defect (D).
        - If previous round's cooperation count == m - 1:
            - If k > 1: Cooperate (C) to reach threshold.
            - Else: Defect (D) as it is not profitable.
        - Otherwise: Defect (D) because the threshold cannot be reached.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        prev_cooperators = history.opponent_cooperators[-1]
        my_prev_c = 1 if history.my_actions[-1] else 0
        total_prev_cooperators = prev_cooperators + my_prev_c
        m = self.game_description.m
        k = self.game_description.k
        if total_prev_cooperators == m - 1:
            if k > 1:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_SELFISH_67(BaseStrategy):
    """
    Implements a Threshold-Adaptive Trigger strategy for the Collective Risk Dilemma.
    It transitions through three phases: Probing (initial baseline establishment),
    Maintenance (pivotal contribution), and Terminal Defection, with additional
    mechanisms for decay monitoring and threshold recovery.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.is_punishing = False
        self.punishment_counter = 0
        self.coop_history = []

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.desc.n_players
        m = self.desc.m
        r = self.desc.n_rounds
        current_round = history.round_number
        if current_round == r - 1:
            last_opp_c = history.opponent_cooperators[-1]
            if last_opp_c == m - 1:
                return Action.C
            return Action.D
        if current_round > 0:
            self.coop_history.append(history.opponent_cooperators[-1])
        if self.is_punishing:
            self.punishment_counter -= 1
            if self.punishment_counter <= 0:
                self.is_punishing = False
            return Action.D
        if current_round == 0:
            return Action.D
        if current_round == 1:
            c1 = history.opponent_cooperators[0]
            if c1 >= m:
                return Action.D
            elif c1 == m - 1:
                return Action.C
            return Action.D
        if len(self.coop_history) >= 2:
            if self.coop_history[-1] < self.coop_history[-2]:
                self.is_punishing = True
                self.punishment_counter = 2
                return Action.D
        effective_c = history.opponent_cooperators[-1]
        if effective_c >= m:
            return Action.D
        elif effective_c == m - 1:
            return Action.C
        else:
            if len(self.coop_history) >= 2:
                if self.coop_history[-1] == m - 1 and self.coop_history[-2] == m - 1:
                    return Action.C
            return Action.D

class Strategy_SELFISH_68(BaseStrategy):
    """
    Conditional Threshold Thresholding (CTT) Strategy.
    
    Logic:
    1. Always defect in the first round.
    2. In subsequent rounds (up to the last):
       - If the threshold (m) was met in the previous round (by everyone, including self), 
         defect to maximize payoff.
       - If exactly m-1 players cooperated in the previous round, cooperate to trigger 
         the reward (k), provided k > 1.
       - Otherwise, defect.
    3. Always defect in the final round (r).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if self.desc.k <= 1:
            return Action.D
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round == self.desc.n_rounds - 1:
            return Action.D
        i_cooperated_last = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + i_cooperated_last
        if total_cooperators_prev >= self.desc.m:
            return Action.D
        elif total_cooperators_prev == self.desc.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_69(BaseStrategy):
    """
    A Conditional Opportunist strategy that free-rides (Defects) by default to 
    maximize private endowment, but pivots to Cooperate only when the collective 
    is exactly one person short of the threshold (m-1) to trigger the reward k.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        my_last_action = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = my_last_action + history.opponent_cooperators[-1]
        if total_cooperators_prev == self.game_description.m - 1:
            return Action.C
        return Action.D

class Strategy_SELFISH_70(BaseStrategy):
    """
    Implements a Conditional Threshold-Seeking strategy.
    
    This strategy minimizes contribution costs while maximizing the probability
    of meeting the threshold `m` by monitoring previous round outcomes and
    pivoting behavior based on the proximity of the threshold.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.n = game_description.n_players
        self.m = game_description.m
        self.k = game_description.k
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if self.k <= 1:
            return Action.D
        round_num = history.round_number
        if round_num == 0:
            prob_cooperate = self.m / self.n
            if random.random() < prob_cooperate:
                return Action.C
            return Action.D
        if round_num == self.r - 1:
            my_actions_int = history.my_actions.astype(int)
            total_cooperators_history = history.opponent_cooperators + my_actions_int
            if np.mean(total_cooperators_history) >= self.m - 1:
                return Action.C
            return Action.D
        my_prev_action = int(history.my_actions[-1])
        h_c_prev = history.opponent_cooperators[-1] + my_prev_action
        if h_c_prev >= self.m:
            return Action.D
        if h_c_prev == self.m - 1:
            return Action.C
        return Action.D

class Strategy_SELFISH_71(BaseStrategy):
    """
    A strategy that adapts cooperation based on threshold performance.
    It initiates with cooperation, pivots based on observed group success, 
    and incorporates a 'selfish trigger' to abandon cooperation if the 
    group consistently fails to reach the required threshold.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.defect_always = False
        self.consecutive_failures = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if self.defect_always:
            return Action.D
        if history.round_number == 0:
            return Action.C
        c_prev = history.opponent_cooperators[-1]
        my_last_action = history.my_actions[-1]
        if c_prev < self.m - 1:
            self.consecutive_failures += 1
            if self.consecutive_failures >= 2:
                self.defect_always = True
                return Action.D
        else:
            self.consecutive_failures = 0
        if history.round_number == self.game_description.n_rounds - 1:
            if c_prev >= self.m:
                return Action.C
            else:
                return Action.D
        if c_prev >= self.m:
            return Action.C
        if c_prev == self.m - 1:
            if my_last_action:
                return Action.D
            else:
                return Action.C
        if my_last_action:
            if c_prev >= self.m:
                return Action.C
            else:
                return Action.D
        elif c_prev + 1 >= self.m:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_72(BaseStrategy):
    """
    Threshold-Conditional Tit-for-Tat strategy.
    
    This strategy behaves as follows:
    1. Initial Round: Cooperates if k > 1.
    2. Subsequent Rounds: 
       - If the threshold m was met in the previous round, defect (free-ride).
       - If the threshold was narrowly missed (m-1), cooperate to signal coordination.
       - If the threshold was missed by a significant margin, defect.
    3. Final Round: Always defect.
    4. Safety: If k <= 1 or system appears uncooperative, default to defection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.k = game_description.k
        self.m = game_description.m
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if self.k <= 1:
            return Action.D
        if history.round_number == self.r - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if len(history.opponent_cooperators) == 0:
            return Action.D
        last_action_was_c = bool(history.my_actions[-1])
        last_opponents_c = int(history.opponent_cooperators[-1])
        total_c_last_round = last_opponents_c + (1 if last_action_was_c else 0)
        if total_c_last_round >= self.m:
            return Action.D
        elif total_c_last_round == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_73(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that follows a three-phase approach:
    1. Initial Calibration: Cooperates in the first round.
    2. Conditional Threshold: Adapts behavior based on whether the contribution was 
       marginal, redundant, or insufficient in the previous round.
    3. End-Game: Always defects in the final round to maximize immediate payoff.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number + 1
        if current_round == self.game_description.n_rounds:
            return Action.D
        if current_round == 1:
            return Action.C
        my_prev_action_bool = history.my_actions[-1]
        my_prev_c = 1 if my_prev_action_bool else 0
        prev_c_total = history.opponent_cooperators[-1] + my_prev_c
        m = self.game_description.m
        if my_prev_c == 1:
            if prev_c_total > m:
                return Action.D
            if prev_c_total == m:
                return Action.C
            return Action.D
        else:
            if prev_c_total >= m:
                return Action.D
            if prev_c_total + 1 >= m:
                return Action.C
            return Action.D

class Strategy_SELFISH_74(BaseStrategy):
    """
    A Tit-for-Tat variant conditioned on threshold satisfaction.
    Maximizes private gain by free-riding when the threshold is met,
    cooperating only when acting as the marginal player to reach the threshold,
    and defecting in the first and last rounds.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.n = game_description.n_players
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round == self.r - 1:
            return Action.D
        my_prev_action = 1 if history.my_actions[-1] else 0
        prev_total_cooperators = history.opponent_cooperators[-1] + my_prev_action
        if prev_total_cooperators >= self.m:
            return Action.D
        if prev_total_cooperators == self.m - 1:
            return Action.C
        return Action.D

class Strategy_SELFISH_75(BaseStrategy):
    """
    Conditional Threshold Exploitation Strategy.
    
    Operates on a "conditional defection" principle to maximize personal utility.
    - Free-rides (Defect) when the collective threshold is already met or being met.
    - Contributes (Cooperate) only at the critical "tipping point" (m-1 cooperators).
    - Defects on the final round and when group altruism is either non-existent or excessive.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if self.n == self.m:
            return Action.D
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round == self.r - 1:
            return Action.D
        if current_round > 0:
            avg_c = np.mean(history.opponent_cooperators)
        else:
            avg_c = 0.0
        if avg_c < 0.5 or avg_c >= self.m:
            return Action.D
        prev_opp_coops = history.opponent_cooperators[-1]
        prev_my_action = history.my_actions[-1]
        prev_total_coops = prev_opp_coops + (1 if prev_my_action else 0)
        if prev_total_coops == self.m - 1:
            return Action.C
        return Action.D

class Strategy_SELFISH_76(BaseStrategy):
    """
    A strategy that acts as a conditional pivot. It defaults to defection
    unless the previous round's cooperation count was exactly m-1, in which
    case it contributes to hit the threshold. It defects on the first and 
    final rounds regardless of history.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.D
        n_prev = history.opponent_cooperators[-1]
        my_prev_c = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = n_prev + my_prev_c
        if total_cooperators_prev == self.game_description.m - 1:
            return Action.C
        return Action.D

class Strategy_SELFISH_77(BaseStrategy):
    """
    Threshold-Conditional Reciprocity: Incentivizes the minimum necessary cooperation
    to meet the threshold while defecting when the threshold is safely exceeded, 
    unattainable, or in the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        if current_round == 0:
            if n - 1 >= m:
                return Action.C
            else:
                return Action.D
        prev_opp_coop = history.opponent_cooperators[-1]
        prev_self_val = int(history.my_actions[-1])
        prev_c_total = prev_opp_coop + prev_self_val
        if prev_c_total >= m + 1:
            return Action.D
        if prev_c_total == m:
            return Action.C if prev_self_val == 1 else Action.D
        if prev_c_total < m:
            if n >= m:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_SELFISH_78(BaseStrategy):
    """
    Implements a strategy that exploits the threshold 'm' for the Collective Risk Dilemma.
    It defects in the first and final rounds, and strategically cooperates only if
    such cooperation is the critical m-th contribution needed to trigger the reward 'k',
    provided 'k' is greater than the cost of cooperation (1). Otherwise, it free-rides.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.k = game_description.k
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if self.k <= 1:
            return Action.D
        if history.round_number == self.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.D
        last_round_cooperators = history.opponent_cooperators[-1]
        my_last_action = int(history.my_actions[-1])
        total_cooperators_last_round = last_round_cooperators + my_last_action
        if total_cooperators_last_round >= self.m:
            return Action.D
        elif last_round_cooperators == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_79(BaseStrategy):
    """
    Threshold-Sensitive Tit-for-Tat (TSTFT):
    1. Initial Round (0): Always Defect.
    2. Subsequent Rounds (t > 0):
       - If previous round's total cooperators (C_{t-1}) >= m: Play Defect.
       - If C_{t-1} < m:
         - If not final round: Play Cooperate.
         - If final round: Play Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        m = self.game_description.m
        total_rounds = self.game_description.n_rounds
        my_prev_action = int(history.my_actions[-1])
        c_prev = history.opponent_cooperators[-1] + my_prev_action
        if c_prev >= m:
            return Action.D
        is_final_round = current_round == total_rounds - 1
        if is_final_round:
            return Action.D
        else:
            return Action.C

class Strategy_SELFISH_80(BaseStrategy):
    """
    Threshold-Conditional Reciprocity: A strategy that cooperates to achieve the threshold m,
    free-rides when the threshold is met, but abandons efforts if the group consistently 
    fails to cooperate.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.failure_counter = 0
        self.persistent_failure_limit = 3

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        m = self.game_description.m
        c_prev = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        total_cooperators = c_prev + (1 if my_prev_action else 0)
        if total_cooperators < m:
            self.failure_counter += 1
        else:
            self.failure_counter = 0
        if self.failure_counter >= self.persistent_failure_limit:
            return Action.D
        if total_cooperators >= m:
            return Action.D
        else:
            return Action.C

class Strategy_SELFISH_81(BaseStrategy):
    """
    Implements Conditional Threshold Thresholding (CTT).
    Operates on the principle of minimal necessary contribution to secure reward k,
    acting as a free rider when possible and pivoting only when necessary.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_zeros = 0
        self.permanent_defect = False

    def __call__(self, history: PlayerHistory) -> Action:
        if self.permanent_defect:
            return Action.D
        m = self.game_description.m
        if history.round_number == 0:
            return Action.D
        prev_round = history.round_number - 1
        c_prev = int(history.opponent_cooperators[prev_round])
        my_prev_action = bool(history.my_actions[prev_round])
        total_cooperators_prev = c_prev + (1 if my_prev_action else 0)
        if total_cooperators_prev == 0:
            self.consecutive_zeros += 1
        else:
            self.consecutive_zeros = 0
        if self.consecutive_zeros >= 3:
            self.permanent_defect = True
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            if c_prev >= m - 1:
                return Action.C
            else:
                return Action.D
        if c_prev >= m:
            return Action.D
        if c_prev == m - 1:
            return Action.C
        if c_prev < m - 1:
            if my_prev_action:
                return Action.D
            return Action.D
        return Action.D

class Strategy_SELFISH_82(BaseStrategy):
    """
    Implements a Threshold-Targeting Conditional Tit-for-Tat strategy.
    
    This strategy focuses on pivoting cooperation to meet the minimum threshold 'm'.
    - If the threshold is already met or exceeded (even without this player), it defects to free-ride.
    - If the threshold is exactly one short, this player cooperates to pivot the outcome.
    - If the threshold is unreachable, it saves the endowment.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if round_idx == self.r - 1:
            total_observed_coops = np.sum(history.opponent_cooperators)
            total_possible_coops = round_idx * (self.n - 1)
            if total_possible_coops > 0:
                p = total_observed_coops / total_possible_coops
            else:
                p = 0.5
            if p * (self.n - 1) >= self.m - 1:
                return Action.C
            return Action.D
        prev_opp_coops = history.opponent_cooperators[-1]
        prev_my_action = 1 if history.my_actions[-1] else 0
        total_coop = prev_opp_coops + prev_my_action
        if total_coop >= self.m + 1:
            return Action.D
        elif total_coop == self.m:
            return Action.D
        elif total_coop == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_83(BaseStrategy):
    """
    A strategy that implements conditional threshold-matching.
    It defects in the first round. In subsequent rounds, it defects if the
    threshold `m` is already met by others, cooperates if its own contribution
    is necessary to trigger the reward `k`, and defects otherwise.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        prev_opponents_cooperated = history.opponent_cooperators[-1]
        if prev_opponents_cooperated >= self.m:
            return Action.D
        if prev_opponents_cooperated == self.m - 1:
            return Action.C
        return Action.D

class Strategy_SELFISH_84(BaseStrategy):
    """
    Implements a conditionally cooperative strategy for the Collective Risk Dilemma.
    
    Logic:
    - Round 1: Always Cooperate.
    - Rounds 2 to r-1: 
        - If previous round cooperators >= m: Defect (free-ride).
        - If previous round cooperators < m:
            - If deficit (m - cooperators) == 1: Cooperate (help meet threshold).
            - Otherwise: Defect.
    - Final Round (r):
        - If previous round cooperators >= m: Defect.
        - If previous round cooperators < m:
            - If deficit == 1 and k > 1: Cooperate.
            - Otherwise: Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.game_description.m
        k = self.game_description.k
        total_rounds = self.game_description.n_rounds
        current_round_index = history.round_number
        my_prev_action = 1 if history.my_actions[-1] else 0
        cooperators_prev_round = history.opponent_cooperators[-1] + my_prev_action
        is_final_round = current_round_index == total_rounds - 1
        if is_final_round:
            if cooperators_prev_round >= m:
                return Action.D
            else:
                deficit = m - cooperators_prev_round
                if deficit == 1 and k > 1:
                    return Action.C
                return Action.D
        elif cooperators_prev_round >= m:
            return Action.D
        else:
            deficit = m - cooperators_prev_round
            if deficit == 1:
                return Action.C
            return Action.D

class Strategy_SELFISH_85(BaseStrategy):
    """
    Conditional Threshold Tracker:
    - Phase 1: Cooperate in the first round to signal intent.
    - Phase 2: In subsequent rounds, monitor the number of cooperators from the previous round.
    - If the threshold m was met, Defect (free-ride).
    - If the threshold m was missed by exactly one, Cooperate (pivotal).
    - If the threshold m was missed by two or more, Defect (avoid wasting contribution).
    - In the final round, analyze historical contribution frequency to decide between cooperation or defection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        my_prev_action = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + my_prev_action
        if current_round == r - 1:
            threshold_met_history = [1 if c + (1 if a else 0) >= m else 0 for c, a in zip(history.opponent_cooperators, history.my_actions)]
            if np.mean(threshold_met_history) >= 0.5:
                return Action.D
            else:
                return Action.C
        if total_cooperators_prev >= m:
            return Action.D
        elif total_cooperators_prev == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_86(BaseStrategy):
    """
    A conditional cooperation strategy for the Collective Risk Dilemma.
    Prioritizes threshold maintenance by cooperating when the threshold is not met,
    but exploits the group by defecting if the threshold is already satisfied.
    Includes a 'Defect Trap' detection mechanism to cease cooperation if the
    group consistently fails to reach the threshold.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.is_in_defect_trap = False
        self.tried_stabilization = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        last_round_idx = history.round_number - 1
        last_my_action = int(history.my_actions[last_round_idx])
        last_opponent_coop_count = int(history.opponent_cooperators[last_round_idx])
        total_cooperators = last_opponent_coop_count + last_my_action
        m = self.game_description.m
        if total_cooperators < m:
            if last_my_action == 1:
                if self.tried_stabilization:
                    self.is_in_defect_trap = True
                else:
                    self.tried_stabilization = True
                    return Action.C
            else:
                pass
        else:
            self.is_in_defect_trap = False
            self.tried_stabilization = False
        if self.is_in_defect_trap:
            return Action.D
        if total_cooperators >= m + 1:
            return Action.D
        elif total_cooperators == m:
            return Action.D
        else:
            return Action.C

class Strategy_SELFISH_87(BaseStrategy):
    """
    Adaptive Threshold-Seeking (ATS): A strategy that minimizes personal cost while 
    maximizing the probability of triggering the threshold reward k. It probes in 
    the first round, then adjusts cooperation based on the previous round's 
    total cooperator count relative to the threshold m.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.failure_counter = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            p_coop = self.game_description.m / self.game_description.n_players
            return Action.C if random.random() < p_coop else Action.D
        n = self.game_description.n_players
        m = self.game_description.m
        my_last_action = Action.C if history.my_actions[-1] else Action.D
        n_t = history.opponent_cooperators[-1] + (1 if my_last_action == Action.C else 0)
        if n_t < m - 1:
            self.failure_counter += 1
        else:
            self.failure_counter = 0
        if self.failure_counter >= 3:
            return Action.D
        is_last_round = history.round_number == self.game_description.n_rounds - 1
        if is_last_round:
            if n_t == m - 1:
                return Action.C
            return Action.D
        if n_t >= m + 1:
            return Action.D
        if n_t == m:
            return Action.D
        if n_t == m - 1:
            return Action.C
        return Action.D

class Strategy_SELFISH_88(BaseStrategy):
    """
    Implements the Threshold-Targeted Conditional Defection (TTCD) strategy.
    
    This strategy focuses on free-riding while ensuring the collective threshold
    is met only when the reward is achievable by the player's contribution.
    - Round 1 and Final Round: Defect.
    - Intermediate Rounds:
        - If previous cooperators >= m: Defect (Free-ride).
        - If previous cooperators == m - 1: Cooperate (Pivot to trigger reward).
        - Otherwise: Defect (Threshold out of reach).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round == self.total_rounds - 1:
            return Action.D
        prev_opp_coop = history.opponent_cooperators[-1]
        i_cooperated_prev = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = prev_opp_coop + i_cooperated_prev
        if total_cooperators_prev >= self.m:
            return Action.D
        elif total_cooperators_prev == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_89(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that dynamically adjusts cooperation based on 
    previous rounds' cooperation counts, utilizing a threshold-based switching mechanism.
    
    Logic:
    - Round 1: Defect.
    - Final Round: Defect.
    - Persistent Failure (if < m for 3 consecutive rounds): Defect.
    - Otherwise:
        - If C_{t-1} > m: Defect (Surplus).
        - If C_{t-1} == m: Defect (Threshold met).
        - If C_{t-1} == m - 1 and last action was D: Cooperate (Attempt to trigger).
        - Else: Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0
        self.is_permanently_defecting = False

    def __call__(self, history: PlayerHistory) -> Action:
        if self.is_permanently_defecting:
            return Action.D
        current_round = history.round_number
        if current_round == self.game_description.n_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.D
        last_others_cooperated = history.opponent_cooperators[-1]
        my_last_action = Action.C if history.my_actions[-1] else Action.D
        last_total_cooperators = last_others_cooperated + (1 if my_last_action == Action.C else 0)
        if last_total_cooperators < self.game_description.m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 3:
            self.is_permanently_defecting = True
            return Action.D
        c_prev = last_total_cooperators
        m = self.game_description.m
        if c_prev > m:
            return Action.D
        if c_prev == m:
            return Action.D
        if c_prev == m - 1:
            if my_last_action == Action.D:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_SELFISH_90(BaseStrategy):
    """
    Implements the Conditional Threshold-Triggering (CTT) strategy.
    
    The strategy acts as a rational optimizer:
    1. First round: Defaults to Defection (D) to observe baseline.
    2. Subsequent rounds:
        - If the previous round's cooperator count (C_prev) matches exactly m-1, 
          play C to trigger the bonus k (since k > 1).
        - Otherwise, play D (either free-ride if threshold is met, or minimize 
          loss if threshold cannot be reached).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        last_my_action = history.my_actions[-1]
        c_prev = history.opponent_cooperators[-1] + (1 if last_my_action else 0)
        if history.opponent_cooperators[-1] == self.m - 1:
            return Action.C
        return Action.D

class Strategy_SELFISH_91(BaseStrategy):
    """
    Threshold-Dependent Conditional Reciprocity strategy for Collective Risk Dilemma.
    
    This strategy focuses on maximizing payoff by:
    1. Testing cooperation levels initially.
    2. Cooperating only if it is necessary to reach the threshold (pivotal) or if it's 
       needed to sustain a successful threshold state.
    3. Otherwise, defaulting to defect to maximize private payoff.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.last_action = None

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            self.last_action = Action.D
            return Action.D
        n = self.desc.n_players
        m = self.desc.m
        r = self.desc.n_rounds
        my_prev_action_bool = history.my_actions[-1]
        my_prev_action = Action.C if my_prev_action_bool else Action.D
        other_coop = history.opponent_cooperators[-1]
        c_prev = other_coop + (1 if my_prev_action == Action.C else 0)
        success = c_prev >= m
        if history.round_number == r - 1:
            if c_prev >= m - 1:
                self.last_action = Action.C
                return Action.C
            else:
                self.last_action = Action.D
                return Action.D
        if success:
            if my_prev_action == Action.C:
                if c_prev == m:
                    self.last_action = Action.C
                    return Action.C
                else:
                    self.last_action = Action.D
                    return Action.D
            else:
                self.last_action = Action.D
                return Action.D
        elif c_prev == m - 1:
            self.last_action = Action.C
            return Action.C
        else:
            self.last_action = Action.D
            return Action.D

class Strategy_SELFISH_92(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that acts as a pivot-conditional cooperator.
    
    Logic:
    - Round 1: Defect.
    - Rounds 2 to r-1: 
        - If previous count >= m: Defect (free-ride).
        - If previous count == m-1: Cooperate (pivot).
        - If previous count < m-1: Defect (conserve).
    - Last round: Defect.
    
    Exceptions:
    - Persistent Failure: If cooperation fails to reach threshold for 3 consecutive rounds, defect permanently.
    - Reward Trap: If we are the pivot (c_i=1, total=m), keep cooperating. 
      If total consistently == m (everyone free-riding/balanced), defect to force shift.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.failure_counter = 0
        self.persistent_failure_mode = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if self.persistent_failure_mode:
            return Action.D
        if history.round_number >= 3:
            recent_failures = 0
            for i in range(1, 4):
                my_last_action = 1 if history.my_actions[-i] else 0
                total_cooperators = history.opponent_cooperators[-i] + my_last_action
                if total_cooperators < self.game_description.m:
                    recent_failures += 1
            if recent_failures == 3:
                self.persistent_failure_mode = True
                return Action.D
        prev_opp_c = history.opponent_cooperators[-1]
        my_prev_c = 1 if history.my_actions[-1] else 0
        total_prev_c = prev_opp_c + my_prev_c
        if my_prev_c == 1 and total_prev_c == self.game_description.m:
            return Action.C
        if total_prev_c == self.game_description.m and prev_opp_c < self.game_description.m:
            return Action.D
        if prev_opp_c >= self.game_description.m:
            return Action.D
        elif prev_opp_c == self.game_description.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_93(BaseStrategy):
    """
    Implements a strategy for the Collective Risk Dilemma that utilizes greedy
    extraction when possible and conditional support to hit the threshold.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.D
        c_self_prev = int(history.my_actions[-1])
        c_others_prev = int(history.opponent_cooperators[-1])
        c_total_prev = c_self_prev + c_others_prev
        if c_others_prev >= self.m:
            return Action.D
        if c_others_prev == self.m - 1 and c_self_prev == 0:
            return Action.C
        if c_others_prev == self.m - 1 and c_self_prev == 1:
            if c_total_prev >= self.m:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_SELFISH_94(BaseStrategy):
    """
    A threshold-based conditional cooperator strategy for the Collective Risk Dilemma.
    Defaults to defection unless the player's contribution is critical to achieving
    the threshold m. Switches to 'Defect Always' if cooperation proves futile.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.is_futile = False
        self.consecutive_failed_rounds = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.desc.n_players
        r = self.desc.n_rounds
        m = self.desc.m
        k = self.desc.k
        t = history.round_number
        if k <= 1.0:
            return Action.D
        if t >= 3:
            last_three_counts = history.opponent_cooperators[t - 3:t]
            if all((c < m - 1 for c in last_three_counts)):
                self.is_futile = True
        if self.is_futile:
            return Action.D
        if t == 0:
            return Action.D
        if t == r - 1:
            return Action.D
        c_prev = history.opponent_cooperators[-1]
        if c_prev == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_95(BaseStrategy):
    """
    Implements a strategy for the Collective Risk Dilemma.
    
    Strategy:
    1. Round 1: Cooperate if k > 1, else Defect.
    2. Rounds 2 to r-1: 
       - If previous threshold met (c >= m), switch to/stay Defect.
       - If previous failed but within 1 (c == m-1), switch to/stay Cooperate.
       - Else (c < m-1), Defect.
    3. Final round: Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.k = self.desc.k
        self.m = self.desc.m
        self.n_rounds = self.desc.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == self.n_rounds - 1:
            return Action.D
        if current_round == 0:
            if self.k > 1:
                return Action.C
            return Action.D
        last_idx = current_round - 1
        my_last_c = 1 if history.my_actions[last_idx] else 0
        total_cooperators_last = history.opponent_cooperators[last_idx] + my_last_c
        if total_cooperators_last >= self.m:
            return Action.D
        elif total_cooperators_last == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_96(BaseStrategy):
    """
    Implements a Threshold Tit-for-Tat strategy for the Collective Risk Dilemma.
    
    The strategy follows these rules:
    - Round 1: Always Cooperate.
    - Cooperation Phase (Rounds 2 to r - floor(r/4)):
        - If previous cooperators >= m: Defect (Free-ride).
        - If previous cooperators == m - 1: Cooperate (Tipping point).
        - If previous cooperators < m - 1: Defect (Minimize loss).
    - Final Phase (Last floor(r/4) rounds): Always Defect.
    
    Special Cases:
    - If k <= 1: Always Defect.
    - If m == n: If round 1 fails to reach m, switch to permanent Defection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.final_phase_start = game_description.n_rounds - math.floor(game_description.n_rounds / 4)
        self.always_defect_k = game_description.k <= 1.0
        self.failed_to_coordinate = False

    def __call__(self, history: PlayerHistory) -> Action:
        if self.always_defect_k:
            return Action.D
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        prev_coop_count = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        total_cooperators_prev = prev_coop_count + (1 if my_prev_action else 0)
        if self.game_description.m == self.game_description.n_players:
            if total_cooperators_prev < self.game_description.m:
                self.failed_to_coordinate = True
            if self.failed_to_coordinate:
                return Action.D
        if current_round >= self.final_phase_start:
            return Action.D
        if total_cooperators_prev >= self.game_description.m:
            return Action.D
        elif total_cooperators_prev == self.game_description.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_97(BaseStrategy):
    """
    Implements an Adaptive Threshold Trigger Strategy for the Collective Risk Dilemma.

    The strategy behaves as follows:
    - Round 1: Always Defect (D).
    - Last Round (r): Always Defect (D).
    - Middle Rounds:
        - If last round's cooperators >= m: Defect (D) to free-ride.
        - If last round's cooperators == m - 1: Cooperate (C) to trigger the threshold.
        - If last round's cooperators < m - 1: Defect (D) to conserve resources.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == 0 or current_round == n_rounds - 1:
            return Action.D
        last_round_cooperators = history.opponent_cooperators[-1]
        if last_round_cooperators >= m:
            return Action.D
        elif last_round_cooperators == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_98(BaseStrategy):
    """
    Threshold-Conditional Opportunism Strategy:
    - Round 0: Cooperate to initiate contribution.
    - Rounds 1 to r-2:
        - If previous cooperators >= m: Defect (free-ride).
        - If previous cooperators == m - 1: Cooperate (pivotal move).
        - If previous cooperators < m - 1: Defect (failure inevitable).
    - Final round (r-1): Defect (no future incentives).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == 0:
            return Action.C
        if current_round == total_rounds - 1:
            return Action.D
        prev_cooperators = history.opponent_cooperators[-1]
        if prev_cooperators >= m:
            return Action.D
        elif prev_cooperators == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_99(BaseStrategy):
    """
    Implements a Conditional Threshold Exploitation strategy.
    
    This strategy defaults to Defection (D) to maximize private payoff. 
    It only switches to Cooperation (C) if:
    1. The reward factor (k) is greater than 1, making the collective project profitable 
       net of contribution costs.
    2. The player can be 'pivotal'—meaning their individual contribution would 
       cause the total number of cooperators to reach the threshold (m). 
       This is detected when the previous round had exactly m-1 cooperators.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if self.game_description.k <= 1:
            return Action.D
        if history.round_number == 0:
            return Action.D
        last_round_cooperators = history.opponent_cooperators[-1]
        target_cooperators = self.game_description.m - 1
        if last_round_cooperators == target_cooperators:
            return Action.C
        return Action.D

class Strategy_SELFISH_100(BaseStrategy):
    """
    Implements a conditional threshold-tracking strategy for the Collective Risk Dilemma.
    
    This strategy monitors the previous round's cooperation levels to adjust its own 
    cooperation. It attempts to free-ride if the group is successfully cooperating, 
    contributes only if its input is pivotal (the 'm-1' condition), and defects 
    on the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        h = history.round_number + 1
        if h == self.r:
            return Action.D
        if h == 1:
            return Action.C if self.k > 1 else Action.D
        prev_my_action = 1 if history.my_actions[-1] else 0
        total_prev_cooperators = history.opponent_cooperators[-1] + prev_my_action
        if total_prev_cooperators >= self.m:
            return Action.D
        elif total_prev_cooperators == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_101(BaseStrategy):
    """
    Implements the Conditional Threshold Anchoring strategy.
    
    This strategy acts as a defect-first exploiter that only contributes when 
    its own action is both necessary and sufficient to trigger the cooperation reward.
    It monitors the threshold history and abandons cooperation efforts if the group
    fails to coordinate for two consecutive rounds.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r_total = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        x_last = history.opponent_cooperators[-1]
        if current_round >= 2:
            x_prev = history.opponent_cooperators[-2]
            if x_last < m - 1 and x_prev < m - 1:
                self.consecutive_failures += 1
            else:
                self.consecutive_failures = 0
        if self.consecutive_failures >= 1:
            return Action.D
        if current_round < r_total - 1:
            if x_last >= m:
                return Action.D
            elif x_last == m - 1:
                return Action.C
            else:
                return Action.D
        elif x_last >= m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_102(BaseStrategy):
    """
    Adaptive Threshold Tit-for-Tat:
    - Round 1: Defect.
    - Rounds 2 to r-1:
        - If N_c >= m: Defect (Free-ride).
        - If N_c == m - 1 and last_action == D: Cooperate (Pivot to support).
        - Else: Defect.
    - Final round: Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == 0:
            return Action.D
        if current_round == n_rounds - 1:
            return Action.D
        last_my_action = history.my_actions[-1]
        n_opponents_c = history.opponent_cooperators[-1]
        total_c = n_opponents_c + (1 if last_my_action else 0)
        if total_c >= m:
            return Action.D
        elif total_c == m - 1 and (not last_my_action):
            return Action.C
        return Action.D

class Strategy_SELFISH_103(BaseStrategy):
    """
    A conditional cooperative strategy for the Collective Risk Dilemma.
    - Round 1: Cooperate.
    - Rounds 2 to r-1: 
        - If previous round had a surplus (c_prev > m), Defect (Greedy Override).
        - Else if threshold met (c_prev >= m), Cooperate.
        - Else (threshold failed), Defect.
    - Final round: Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        threshold = self.game_description.m
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        c_others = history.opponent_cooperators[-1]
        c_prev = c_others + (1 if my_prev_action else 0)
        if c_prev > threshold:
            return Action.D
        if c_prev >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_104(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that balances conditional cooperation,
    free-riding when thresholds are safely met, and cut-off points when cooperation
    seems futile.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.has_collapsed = False

    def __call__(self, history: PlayerHistory) -> Action:
        if self.game_description.k < 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        prev_my_action = history.my_actions[-1]
        prev_opp_cooperators = history.opponent_cooperators[-1]
        t_minus_1 = int(prev_my_action) + prev_opp_cooperators
        m = self.game_description.m
        if len(history.my_actions) > 1:
            prev_prev_opp_cooperators = history.opponent_cooperators[-2]
            prev_prev_my_action = history.my_actions[-2]
            t_minus_2 = int(prev_prev_my_action) + prev_prev_opp_cooperators
            if t_minus_2 >= m and t_minus_1 < m:
                self.has_collapsed = True
        if self.has_collapsed:
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if t_minus_1 >= m:
            if t_minus_1 > m:
                return Action.D
            else:
                return Action.C if prev_my_action else Action.D
        elif t_minus_1 == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_105(BaseStrategy):
    """
    Implements Conditional Reciprocal Participation (CRP).
    
    This strategy focuses on maximizing payoff by only contributing when 
    it is the deciding factor to trigger the threshold 'm' (reward k), 
    and avoiding contribution when the threshold is already met or 
    unattainable with a single contribution.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        last_round_idx = history.round_number - 1
        h_prev = history.opponent_cooperators[last_round_idx]
        if history.round_number == self.r - 1:
            return Action.D
        if h_prev >= self.m:
            return Action.D
        g = self.m - h_prev
        if g == 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_106(BaseStrategy):
    """
    Implements a decision-theoretic strategy for the Collective Risk Dilemma.
    It plays Defect in the first and last rounds. In intermediate rounds, it calculates the
    expected utility of contributing versus defecting based on the observed cooperators
    in the previous round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description

    def _nCr(self, n: int, r: int) -> float:
        """Helper to calculate binomial coefficient."""
        if r < 0 or r > n:
            return 0.0
        return math.comb(n, r)

    def _cdf_threshold(self, k_threshold: int, n_trials: int, p: float) -> float:
        """
        Calculates the probability that at least k_threshold successes occur
        in n_trials with probability p.
        P(X >= k) = sum_{j=k}^{n} binom(n, j) * p^j * (1-p)^(n-j)
        """
        prob = 0.0
        for j in range(k_threshold, n_trials + 1):
            term = self._nCr(n_trials, j) * p ** j * (1 - p) ** (n_trials - j)
            prob += term
        return prob

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.desc.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.D
        i_cooperated = int(history.my_actions[-1])
        n_prev_coop = history.opponent_cooperators[-1] + i_cooperated
        n_others = self.desc.n_players - 1
        if n_prev_coop >= self.desc.m:
            return Action.D
        p = n_prev_coop / n_others if n_others > 0 else 0.0
        prob_without_me = self._cdf_threshold(self.desc.m - 1, n_others, p)
        if prob_without_me >= 1.0 / self.desc.k:
            return Action.D
        prob_with_me = self._cdf_threshold(self.desc.m - 2, n_others, p)
        if self.desc.k * prob_with_me - 1 > self.desc.k * prob_without_me:
            return Action.C
        return Action.D

class Strategy_SELFISH_107(BaseStrategy):
    """
    Implements a threshold-based adaptive strategy for the Collective Risk Dilemma.
    It attempts to coordinate to meet the threshold m, acts as a free-rider when 
    the threshold is safely exceeded, and gives up on cooperation if persistent 
    failure occurs.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.consecutive_failures = 0

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == self.desc.n_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        opp_coop_count = history.opponent_cooperators[-1]
        my_prev_c = 1 if my_prev_action else 0
        total_c_prev = opp_coop_count + my_prev_c
        if total_c_prev < self.desc.m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 3:
            return Action.D
        threshold_met = total_c_prev >= self.desc.m
        if threshold_met:
            if my_prev_action == True:
                if total_c_prev > self.desc.m:
                    return Action.D
                else:
                    return Action.C
            else:
                return Action.D
        elif my_prev_action == False:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_108(BaseStrategy):
    """
    A strategy that plays Cooperate (C) in the first round, and subsequently decides
    to Cooperate or Defect based on the previous round's performance against the threshold m.
    
    Logic:
    - If k <= 1: Defect (D) always.
    - If m == n: Cooperate (C) unless the group failed to reach at least m-1 cooperators.
    - Otherwise (1 < m < n):
        - Final round: Defect (D).
        - If previous round threshold was met (C_prev >= m): Defect (D).
        - If previous round threshold not met (C_prev < m):
            - If I played C and C_prev == m - 1: Play C (critical contribution).
            - Otherwise: Defect (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if self.k <= 1.0:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if self.m == self.n:
            if history.round_number == self.r - 1:
                return Action.D
            last_my_c = 1 if history.my_actions[-1] else 0
            total_cooperators_prev = last_my_c + history.opponent_cooperators[-1]
            if total_cooperators_prev >= self.m - 1:
                return Action.C
            else:
                return Action.D
        if history.round_number == self.r - 1:
            return Action.D
        last_my_c = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = last_my_c + history.opponent_cooperators[-1]
        if total_cooperators_prev >= self.m:
            return Action.D
        if total_cooperators_prev == self.m - 1 and history.my_actions[-1] == True:
            return Action.C
        return Action.D

class Strategy_SELFISH_109(BaseStrategy):
    """
    Implements a strategic approach to the Collective Risk Dilemma based on estimated cooperation rates.
    It calculates the expected utility of cooperating versus defecting based on historical performance of opponents,
    using a binomial distribution to estimate the probability of hitting the success threshold.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == self.r - 1:
            return Action.D
        if t == 0:
            return Action.C
        total_opponents_cooperated = int(np.sum(history.opponent_cooperators))
        total_opportunities = t * (self.n - 1)
        avg_p = total_opponents_cooperated / total_opportunities if total_opportunities > 0 else 0.0
        n_opps = self.n - 1

        def get_prob_at_least(k_threshold: int, p: float, n_trials: int) -> float:
            if k_threshold <= 0:
                return 1.0
            if k_threshold > n_trials:
                return 0.0
            prob = 0.0
            for x in range(k_threshold, n_trials + 1):
                comb = math.comb(n_trials, x)
                prob += comb * p ** x * (1 - p) ** (n_trials - x)
            return prob
        p_a = get_prob_at_least(self.m - 1, avg_p, n_opps)
        p_b = get_prob_at_least(self.m, avg_p, n_opps)
        e_c = self.k * p_a - 1.0
        e_d = self.k * p_b
        if e_c > e_d:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_110(BaseStrategy):
    """
    Strategy: Threshold-Targeted Conditional Defection
    
    This strategy aims to optimize payoffs in a collective risk dilemma by:
    1. Signaling cooperation in the first round.
    2. Exploiting a 'buffer' or free-riding when the threshold is met, while
       reverting to cooperation only when the threshold is not met.
    3. Defecting in the final round.
    4. Handling non-cooperative group environments by switching permanently to defection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k
        self.is_permanently_defecting = False

    def __call__(self, history: PlayerHistory) -> Action:
        if self.m > self.n:
            return Action.D
        if self.is_permanently_defecting:
            return Action.D
        if history.round_number == self.r - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        total_cooperators_prev = history.opponent_cooperators[-1] + int(history.my_actions[-1])
        if history.my_actions[-1] and total_cooperators_prev < 1:
            self.is_permanently_defecting = True
            return Action.D
        consecutive_failures = 0
        for i in range(history.round_number - 1, -1, -1):
            coops = history.opponent_cooperators[i] + int(history.my_actions[i])
            if coops < self.m:
                consecutive_failures += 1
            else:
                break
        if consecutive_failures >= self.r - 1:
            self.is_permanently_defecting = True
            return Action.D
        C_prev = total_cooperators_prev
        if C_prev >= self.m + 1:
            return Action.D
        elif C_prev == self.m:
            return Action.D
        else:
            return Action.C

class Strategy_SELFISH_111(BaseStrategy):
    """
    Threshold-Responsive Tit-for-Tat:
    Maximizes utility by signalling cooperation in round 1, then dynamically switching
    between cooperation and free-riding (defection) based on the threshold (m) and
    the perceived viability of the collective action. It includes a fallback mechanism
    to stop contributing if cooperation efforts are futile.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.given_up = False
        self.consecutive_failed_attempts = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if self.given_up:
            return Action.D
        last_my_action = history.my_actions[-1]
        last_opponents = history.opponent_cooperators[-1]
        total_cooperators_last_round = last_opponents + (1 if last_my_action else 0)
        if total_cooperators_last_round < self.game_description.m:
            self.consecutive_failed_attempts += 1
        else:
            self.consecutive_failed_attempts = 0
        if self.consecutive_failed_attempts >= 2:
            self.given_up = True
            return Action.D
        threshold_met_without_me = last_opponents >= self.game_description.m
        if threshold_met_without_me:
            return Action.D
        if total_cooperators_last_round < self.game_description.m:
            return Action.C
        return Action.C

class Strategy_SELFISH_112(BaseStrategy):
    """
    A strategy that maximizes cumulative payoff by defecting in the first and last rounds
    and only cooperating when it is the pivot necessary to reach the cooperation threshold (m)
    based on the previous round's observations.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number + 1
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == 1:
            return Action.D
        if current_round == total_rounds:
            return Action.D
        last_my_action_int = 1 if history.my_actions[-1] else 0
        last_opp_cooperators = history.opponent_cooperators[-1]
        c_prev = last_my_action_int + last_opp_cooperators
        if c_prev >= m:
            return Action.D
        if c_prev == m - 1:
            return Action.C
        return Action.D

class Strategy_SELFISH_113(BaseStrategy):
    """
    Threshold-Conditional Reciprocity (TCR) Strategy.
    
    Maximizes individual cumulative payoff by minimizing personal contribution costs 
    while conditionally attempting to trigger the reward threshold 'm'.
    
    Decision Rules:
    1. Rounds 1 and r: Always Defect (D).
    2. Threshold Met (C_prev >= m): Defect (D) to free-ride.
    3. Gap Too Large (C_prev <= m - 2): Defect (D) as one contribution won't fix it.
    4. Make-or-Break (C_prev == m - 1): Cooperate (C) to trigger threshold.
    
    If reward factor k <= 1, defaults to pure Defect strategy.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.total_rounds = game_description.n_rounds
        self.is_reward_inefficient = game_description.k <= 1.0

    def __call__(self, history: PlayerHistory) -> Action:
        if self.is_reward_inefficient:
            return Action.D
        current_round_idx = history.round_number
        if current_round_idx == 0 or current_round_idx == self.total_rounds - 1:
            return Action.D
        prev_opp_coops = history.opponent_cooperators[-1]
        i_cooperated_prev = int(history.my_actions[-1])
        total_cooperators_prev = prev_opp_coops + i_cooperated_prev
        m = self.game_description.m
        if total_cooperators_prev >= m:
            return Action.D
        if total_cooperators_prev <= m - 2:
            return Action.D
        if total_cooperators_prev == m - 1:
            return Action.C
        return Action.D

class Strategy_SELFISH_114(BaseStrategy):
    """
    Implements Threshold-Targeted Conditional Defection.
    
    The strategy aims to maximize cumulative payoff by free-riding on the group 
    unless the marginal contribution of this player is necessary to trigger 
    the reward 'k'.
    
    - Round 1: Defect to observe baseline behavior.
    - Intermediate Rounds: 
        - If threshold met by others, Defect (free-ride).
        - If exactly m-1 cooperators, Cooperate (to trigger reward).
        - Otherwise, Defect.
    - Terminal Round: 
        - If m-1 or more cooperators observed previously, Cooperate.
        - Otherwise, Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        total_rounds = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        last_round_idx = current_round - 1
        my_last_action = history.my_actions[last_round_idx]
        prev_cooperators = history.opponent_cooperators[last_round_idx] + (1 if my_last_action else 0)
        if current_round == total_rounds - 1:
            if prev_cooperators >= m - 1:
                return Action.C
            return Action.D
        if prev_cooperators >= m:
            return Action.D
        if prev_cooperators == m - 1:
            return Action.C
        return Action.D

class Strategy_SELFISH_115(BaseStrategy):
    """
    Implements a strategic threshold-seeking approach for the Collective Risk Dilemma.
    Starts by defecting, then dynamically adjusts cooperation based on the threshold (m) 
    and recent group behavior, while accounting for the final round and specific edge cases.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.contribution_history = []
        self.given_up = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            self.contribution_history = []
            return Action.D
        my_prev_action = Action.C if history.my_actions[-1] else Action.D
        c_obs_total = history.opponent_cooperators[-1] + (1 if my_prev_action == Action.C else 0)
        self.contribution_history.append(c_obs_total)
        is_final_round = history.round_number == self.game_description.n_rounds - 1
        if is_final_round and c_obs_total >= self.game_description.m:
            return Action.D
        if self.given_up:
            return Action.D
        m = self.game_description.m
        if c_obs_total >= m + 1:
            return Action.D
        elif c_obs_total == m:
            return Action.C
        elif c_obs_total < m:
            if c_obs_total == m - 1:
                if my_prev_action == Action.C:
                    self.given_up = True
                    return Action.D
                else:
                    return Action.C
            elif my_prev_action == Action.D:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_SELFISH_116(BaseStrategy):
    """
    A conditional tit-for-tat strategy for the Collective Risk Dilemma.
    It attempts to minimize individual costs by defecting whenever possible, 
    but conditionally contributes (Cooperate) to meet the threshold 'm' 
    if the group is just one contribution short, ensuring the reward 'k' is triggered.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == 0:
            return Action.D
        total_cooperators = history.opponent_cooperators[-1]
        my_last_action = history.my_actions[-1]
        if my_last_action:
            others_cooperated = total_cooperators - 1
        else:
            others_cooperated = total_cooperators
        if current_round == r - 1:
            if others_cooperated == m - 1:
                return Action.C
            else:
                return Action.D
        if total_cooperators >= m:
            return Action.D
        elif total_cooperators == m - 1 and (not my_last_action):
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_117(BaseStrategy):
    """
    A strategy that aims to meet the cooperation threshold 'm'.
    It starts by cooperating, then dynamically switches between cooperating and
    defecting based on the previous round's total cooperation count to balance
    cost-sharing and threshold maintenance.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.T = game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.game_description.n_rounds - 1:
            if len(history.opponent_cooperators) > 0:
                avg_coop = np.mean(history.opponent_cooperators)
                if avg_coop >= self.T:
                    return Action.D
                else:
                    return Action.C
            return Action.C
        last_self_action = int(history.my_actions[-1])
        n_opponents_cooperating = int(history.opponent_cooperators[-1])
        total_cooperators_last_round = n_opponents_cooperating + last_self_action
        if total_cooperators_last_round >= self.T:
            return Action.D
        else:
            return Action.C

class Strategy_SELFISH_118(BaseStrategy):
    """
    A strategy that acts as a conditional free-rider. It starts by defecting.
    In subsequent rounds (excluding the last), it cooperates only if its contribution
    is the pivot point to reaching the threshold 'm'. It defects if the threshold
    is already met, impossible to meet, or if it is the last round.
    It also reverts to permanent defection if cooperation appears futile or
    if opponents seem to react negatively to cooperation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k
        self.permanent_defection = False

    def __call__(self, history: PlayerHistory) -> Action:
        if self.k <= 1:
            return Action.D
        if self.permanent_defection:
            return Action.D
        if history.round_number == 0:
            return Action.D
        if history.round_number == self.r - 1:
            return Action.D
        if np.any(history.opponent_cooperators + history.my_actions > self.m + 2):
            pass
        if history.round_number > 1:
            my_prev_action = int(history.my_actions[-2])
            prev_total_coop = history.opponent_cooperators[-2] + my_prev_action
            if my_prev_action == 1 and history.opponent_cooperators[-1] < self.m - 1:
                self.permanent_defection = True
                return Action.D
        c_prev = history.opponent_cooperators[-1] + int(history.my_actions[-1])
        if c_prev >= self.m:
            return Action.D
        if c_prev == self.m - 1:
            return Action.C
        return Action.D

class Strategy_SELFISH_119(BaseStrategy):
    """
    A Tit-for-Tat-Threshold (TFT-T) strategy.
    
    Logic:
    - Round 1: Always Cooperate (C).
    - Final Round (r-1): Always Defect (D).
    - Intermediate Rounds:
        - If the threshold (m) was met in the previous round (N_c >= m), continue Cooperating.
        - If the threshold was not met in the previous round:
            - If we defected, continue Defecting.
            - If we cooperated, switch to Defecting to punish/save endowment.
        - Correction: If we were Defecting, but the threshold was met anyway, switch back to Cooperating.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        last_my_action = bool(history.my_actions[-1])
        last_others_cooperators = history.opponent_cooperators[-1]
        my_contribution = 1 if last_my_action else 0
        total_cooperators = last_others_cooperators + my_contribution
        threshold = self.game_description.m
        threshold_met = total_cooperators >= threshold
        if threshold_met:
            return Action.C
        return Action.D

class Strategy_SELFISH_120(BaseStrategy):
    """
    A selfish strategy that attempts to free-ride on the collective threshold 'm'.
    - Round 1: Always defects to test the threshold.
    - Rounds 2 to r-1: Defects if threshold met or failing, cooperates only if pivotal (n_cooperators == m - 1).
    - Round r: Always defects regardless of history.
    - Edge cases: If k <= 1 or m > n, always defects.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k
        self.threshold_met_historically = False

    def __call__(self, history: PlayerHistory) -> Action:
        if self.k <= 1 or self.m > self.n:
            return Action.D
        round_idx = history.round_number
        if round_idx == 0:
            return Action.D
        last_self_action = int(history.my_actions[-1])
        total_cooperators_prev = history.opponent_cooperators[-1] + last_self_action
        if total_cooperators_prev >= self.m:
            self.threshold_met_historically = True
        if round_idx == self.r - 1:
            return Action.D
        if total_cooperators_prev >= self.m:
            return Action.D
        elif total_cooperators_prev == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_121(BaseStrategy):
    """
    Implements a conditional threshold-seeking strategy for the Collective Risk Dilemma.
    
    Logic:
    - Round 0: Always Defect (D) to establish baseline.
    - Last Round (r-1): If (Previous Cooperators == m - 1), Cooperate (C), else Defect (D).
    - Other Rounds:
        - If Previous Cooperators >= m: Defect (D) (Free riding/Optimization).
        - If Previous Cooperators == m - 1: Cooperate (C) (Marginal player triggering threshold).
        - Otherwise: Defect (D) (Inefficient to cooperate alone).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        last_round_idx = current_round - 1
        i_cooperated_last_round = 1 if history.my_actions[last_round_idx] else 0
        total_cooperators_last_round = history.opponent_cooperators[last_round_idx] + i_cooperated_last_round
        if current_round == self.r - 1:
            if total_cooperators_last_round == self.m - 1:
                return Action.C
            return Action.D
        if total_cooperators_last_round >= self.m:
            return Action.D
        deficit = self.m - total_cooperators_last_round
        if deficit == 1:
            return Action.C
        return Action.D

class Strategy_SELFISH_122(BaseStrategy):
    """
    Threshold-Conditional Tit-for-Tat:
    Maximizes individual payoff by targeting the minimum threshold (m) required to trigger the reward (k).
    It uses conditional cooperation (nudging) when necessary and exploits surplus cooperation
    or abandons cooperation if the group proves non-cooperative.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.failed_consecutive_count = 0
        self.cooperating_toggle = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.desc.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            n = self.desc.n_players
            m = self.desc.m

            def nCr(n, r):
                if r < 0 or r > n:
                    return 0
                return math.factorial(n) // (math.factorial(r) * math.factorial(n - r))
            n_trials = n - 1
            n_successes_needed = m - 1
            if n_successes_needed <= 0:
                return Action.C
            total_ways = 2 ** n_trials
            success_ways = sum((nCr(n_trials, i) for i in range(n_successes_needed, n_trials + 1)))
            prob_success = success_ways / total_ways
            if n <= 3 or prob_success > 0.5:
                return Action.C
            return Action.D
        my_prev_action = history.my_actions[-1]
        my_contribution = 1 if my_prev_action else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + my_contribution
        if total_cooperators_prev < self.desc.m:
            self.failed_consecutive_count += 1
        else:
            self.failed_consecutive_count = 0
        if self.failed_consecutive_count >= 3:
            return Action.D
        if total_cooperators_prev == self.desc.m and my_prev_action == True:
            self.cooperating_toggle = True
            return Action.D
        if self.cooperating_toggle:
            if total_cooperators_prev < self.desc.m:
                self.cooperating_toggle = False
                return Action.C
            else:
                self.cooperating_toggle = False
                return Action.D
        if total_cooperators_prev == self.desc.m - 1 and (not my_prev_action):
            return Action.C
        if total_cooperators_prev == self.desc.m and (not my_prev_action):
            return Action.C
        if total_cooperators_prev > self.desc.m:
            return Action.D
        if total_cooperators_prev < self.desc.m - 1:
            return Action.D
        return Action.D

class Strategy_SELFISH_123(BaseStrategy):
    """
    Implements a conditional cooperator strategy for the Collective Risk Dilemma.
    Prioritizes free-riding (Defect) to save costs, while attempting to meet the 
    threshold (m) only when one's own contribution can bridge the gap to success.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_idx = history.round_number
        t = current_round_idx + 1
        if t == 1:
            return Action.D
        prev_my_action = history.my_actions[-1]
        prev_opp_count = history.opponent_cooperators[-1]
        n_c_prev = int(prev_my_action) + prev_opp_count
        if t == self.r:
            if n_c_prev >= self.m - 1:
                return Action.C
            else:
                return Action.D
        if n_c_prev >= self.m:
            return Action.D
        elif n_c_prev == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_124(BaseStrategy):
    """
    Implements a conditional free-riding strategy.
    
    In Round 1, it defects.
    In intermediate rounds (1 < t < r), it cooperates only if the previous round
    had m-1 cooperators; otherwise, it defects.
    In the final round (t = r), it cooperates if the previous round had >= m-1
    cooperators; otherwise, it defects.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        last_round_my_action = history.my_actions[-1]
        c_prev = history.opponent_cooperators[-1] + (1 if last_round_my_action else 0)
        if current_round < r - 1:
            if c_prev >= m:
                return Action.D
            elif c_prev == m - 1:
                return Action.C
            else:
                return Action.D
        if current_round == r - 1:
            if c_prev >= m - 1:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_SELFISH_125(BaseStrategy):
    """
    Threshold-Targeted Conditional Defection Strategy.
    
    Logic:
    - Round 1: Cooperate with probability p = m / n.
    - Subsequent Rounds:
        - If previous round's total cooperators (opponent_cooperators + my last action) < m - 1: Defect.
        - If previous round's total cooperators == m - 1: Cooperate.
        - If previous round's total cooperators >= m: Defect.
    - Edge Cases:
        - Persistent Under-cooperation (3 consecutive rounds < m): Switch to permanent Defect.
        - Excessive Cooperation (2 consecutive rounds > m+1): Switch to permanent Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.persistent_defect_mode = False
        self.under_coop_counter = 0
        self.excessive_coop_counter = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if self.persistent_defect_mode:
            return Action.D
        round_idx = history.round_number
        n = self.game_description.n_players
        m = self.game_description.m
        if round_idx == 0:
            if random.random() < m / n:
                return Action.C
            return Action.D
        last_my_action = int(history.my_actions[-1])
        last_opponent_coops = int(history.opponent_cooperators[-1])
        c_total_prev = last_opponent_coops + last_my_action
        if c_total_prev < m:
            self.under_coop_counter += 1
            self.excessive_coop_counter = 0
        elif c_total_prev > m + 1:
            self.excessive_coop_counter += 1
            self.under_coop_counter = 0
        else:
            self.under_coop_counter = 0
            self.excessive_coop_counter = 0
        if self.under_coop_counter >= 3 or self.excessive_coop_counter >= 2:
            self.persistent_defect_mode = True
            return Action.D
        if round_idx == self.game_description.n_rounds - 1:
            if c_total_prev == m - 1:
                return Action.C
            return Action.D
        if c_total_prev < m - 1:
            return Action.D
        elif c_total_prev == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_126(BaseStrategy):
    """
    Implements a conditional threshold-based strategy for the Collective Risk Dilemma.
    
    Logic:
    - Round 0: Always Defect.
    - Rounds 1 to (r-2): 
        - If k <= 1, always Defect.
        - Otherwise, evaluate state based on effective cooperators (C_eff):
            - C_eff >= m: Success state, Defect (reward already secured).
            - C_eff == m-1: Pivotal state, Cooperate (needed to trigger reward).
            - C_eff < m-1: Failure state, Defect (contribution is wasted).
    - Final Round: Always Defect (no future consequences).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        k = self.game_description.k
        if current_round == 0:
            return Action.D
        if current_round == total_rounds - 1:
            return Action.D
        if k <= 1.0:
            return Action.D
        prev_round_idx = -1
        last_my_action = history.my_actions[prev_round_idx]
        last_opponent_coops = history.opponent_cooperators[prev_round_idx]
        s_i = 1 if last_my_action else 0
        c_eff = last_opponent_coops
        if c_eff >= m:
            return Action.D
        elif c_eff == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFISH_127(BaseStrategy):
    """
    Implements a Collective Risk Dilemma strategy with history-based thresholds,
    conditional reciprocity, and robustness testing.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.permanent_defect = False
        self.testing_mode = False
        self.test_counter = 0

    def _get_total_cooperators(self, history: PlayerHistory, round_idx: int) -> int:
        others = history.opponent_cooperators[round_idx]
        me = 1 if history.my_actions[round_idx] else 0
        return int(others + me)

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        round_num = history.round_number
        if round_num == r - 1:
            return Action.D
        if round_num >= 2:
            if self._get_total_cooperators(history, -1) == 0 and self._get_total_cooperators(history, -2) == 0:
                self.permanent_defect = True
        if self.permanent_defect:
            return Action.D
        if round_num == 0:
            return Action.C if random.random() < m / n else Action.D
        if round_num >= 3:
            if self._get_total_cooperators(history, -1) == n and self._get_total_cooperators(history, -2) == n and (self._get_total_cooperators(history, -3) == n):
                self.testing_mode = True
        if self.testing_mode:
            self.test_counter += 1
            return Action.D if self.test_counter % 3 == 0 else Action.C
        last_total = self._get_total_cooperators(history, -1)
        if last_total < m:
            return Action.D
        if last_total == m:
            return Action.D
        if history.my_actions[-1]:
            return Action.C
        else:
            return Action.C if random.random() < m / n else Action.D

class Strategy_SELFISH_128(BaseStrategy):
    """
    Implements a probabilistic strategy for the Collective Risk Dilemma.
    Adjusts contribution probability p_t based on past successes, failures,
    and threshold efficiency.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        n = float(self.game_description.n_players)
        m = float(self.game_description.m)
        self.p_t = min(1.0, m / n * 1.2)
        self.consecutive_zeros = 0
        self.is_permanently_defective = False

    def __call__(self, history: PlayerHistory) -> Action:
        if self.is_permanently_defective:
            return Action.D
        if history.round_number == 0:
            if random.random() < self.p_t:
                return Action.C
            return Action.D
        prev_round_idx = history.round_number - 1
        my_prev_action = 1 if history.my_actions[prev_round_idx] else 0
        total_cooperators = history.opponent_cooperators[prev_round_idx] + my_prev_action
        if total_cooperators == 0:
            self.consecutive_zeros += 1
        else:
            self.consecutive_zeros = 0
        if self.consecutive_zeros >= 2:
            self.is_permanently_defective = True
            return Action.D
        if total_cooperators > self.game_description.m:
            self.p_t = 0.0
        elif total_cooperators >= self.game_description.m:
            if my_prev_action == 0:
                pass
            else:
                self.p_t = max(0.0, self.p_t - 0.1)
        else:
            self.p_t = min(1.0, self.p_t + 0.2)
        if history.round_number == self.game_description.n_rounds - 1:
            lifetime_payoff = float(np.sum(history.my_payoffs))
            if lifetime_payoff > 1.0 + self.game_description.k:
                return Action.D
        if random.random() < self.p_t:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_33(BaseStrategy):
    """
    Implements a conditional reciprocal strategy for the Collective Risk Dilemma.
    
    Phase 1 (Round 1): Always cooperates to test group capability.
    Phase 2 (Intermediate Rounds): 
        - If previous round reached threshold m: Maintains cooperation to keep reward k.
        - If threshold not reached:
            - If own action was C: Switches to D (saving endowment).
            - If own action was D: 
                - If only 1 player missing (Gap=1): Switches to C to trigger collective reward.
                - If > 1 players missing: Remains D to preserve endowment.
    Phase 3 (Final Round):
        - If gap is 1 or less: Switches to C to capture final reward.
        - Otherwise: Remains D.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.game_description.m
        r = self.game_description.n_rounds
        last_round_idx = history.round_number - 1
        my_prev_action = Action.C if history.my_actions[last_round_idx] else Action.D
        my_prev_coop = 1 if my_prev_action == Action.C else 0
        total_cooperators_prev = history.opponent_cooperators[last_round_idx] + my_prev_coop
        gap = m - total_cooperators_prev
        if history.round_number == r - 1:
            if gap <= 1:
                return Action.C
            else:
                return Action.D
        if total_cooperators_prev >= m:
            return Action.C
        elif my_prev_action == Action.C:
            return Action.D
        elif gap == 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_34(BaseStrategy):
    """
    Threshold-Sensitive Tit-for-Tat with Probabilistic Defection.
    
    This strategy aims to sustain cooperation only when the collective threshold 
    is achievable and necessary. It avoids contributing when the threshold is 
    already secured or when the shortfall is too large to overcome, and switches 
    to defecting if the population proves unresponsive.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0
        self.is_unresponsive = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            threshold_ratio = self.game_description.m / self.game_description.n_players
            return Action.C if threshold_ratio <= 0.5 else Action.D
        last_round_idx = history.round_number - 1
        num_cooperators = history.opponent_cooperators[last_round_idx] + int(history.my_actions[last_round_idx])
        if history.my_actions[last_round_idx] and num_cooperators < self.game_description.m:
            self.consecutive_failures += 1
        elif num_cooperators >= self.game_description.m:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 3:
            self.is_unresponsive = True
        if self.is_unresponsive:
            return Action.D
        N_c = history.opponent_cooperators[-1] + int(history.my_actions[-1])
        self_c = int(history.my_actions[-1])
        if N_c >= self.game_description.m + 1:
            return Action.D
        if N_c == self.game_description.m:
            if self_c == 1:
                return Action.C
            else:
                return Action.D
        if N_c < self.game_description.m:
            shortfall = self.game_description.m - N_c
            if shortfall == 1:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_SELFINTERESTED_35(BaseStrategy):
    """
    Implements a Conditional Threshold Reciprocity strategy for the Collective Risk Dilemma.
    
    Logic:
    - Round 1: Always Cooperate (C) to establish a cooperative baseline.
    - Final Round: Always Defect (D) to maximize payoff.
    - Rounds 2 to r-1:
        - If previous round threshold was met (C_prev >= m) OR C_prev == m - 1: Play C.
        - Otherwise: Play D.
    - Adaptive Heuristic: If threshold (m) is missed for two consecutive rounds, permanently switch to Defect (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k
        self.consecutive_failures = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.r - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        my_prev_action = 1 if history.my_actions[-1] else 0
        c_prev = history.opponent_cooperators[-1] + my_prev_action
        if c_prev < self.m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 2:
            return Action.D
        if c_prev >= self.m:
            return Action.C
        if c_prev == self.m - 1:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_36(BaseStrategy):
    """
    Threshold-Adaptive Trigger (TAT): A strategy that probes for cooperation
    in the first round, maintains cooperative thresholds, exploits surplus
    cooperation, and abandons unviable groups.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.consecutive_failures = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if self.desc.k <= 1.0:
            return Action.D
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.desc.n_rounds - 1:
            return Action.D
        last_opponent_c = history.opponent_cooperators[-1]
        last_my_c = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = last_opponent_c + last_my_c
        if total_cooperators_prev < self.desc.m:
            is_within_one = last_opponent_c == self.desc.m - 1
            if not is_within_one:
                self.consecutive_failures += 1
            else:
                self.consecutive_failures = 0
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 3:
            return Action.D
        if total_cooperators_prev >= self.desc.m:
            if total_cooperators_prev > self.desc.m:
                return Action.D
            else:
                return Action.C
        elif last_opponent_c >= self.desc.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_37(BaseStrategy):
    """
    Threshold-Responsive Tit-for-Tat (TR-TFT).
    
    Initial Strategy: Cooperate in round 0.
    
    Subsequent Rounds:
    - If the last round was the final round, Defect.
    - If C_{t-1} >= m: Defect (Free-ride).
    - If C_{t-1} == m - 1: Cooperate (Pivotal contribution).
    - If C_{t-1} < m - 1:
        - Check for trend (increasing cooperation over last 3 rounds).
        - If trend is increasing, Cooperate (Testing).
        - Else, Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        m = self.game_description.m
        prev_my_action = 1 if history.my_actions[-1] else 0
        c_prev = history.opponent_cooperators[-1] + prev_my_action
        if c_prev >= m:
            return Action.D
        if c_prev == m - 1:
            return Action.C
        if history.round_number >= 3:

            def get_total_cooperators(round_idx):
                return history.opponent_cooperators[round_idx] + (1 if history.my_actions[round_idx] else 0)
            c_minus_1 = c_prev
            c_minus_2 = get_total_cooperators(-2)
            c_minus_3 = get_total_cooperators(-3)
            if c_minus_1 > c_minus_2 and c_minus_2 > c_minus_3:
                return Action.C
        return Action.D

class Strategy_SELFINTERESTED_38(BaseStrategy):
    """
    Threshold-Responsive Trigger (TRT) strategy for the Collective Risk Dilemma.
    
    Logic:
    - If k <= 1 or threshold n-1 < m: Always Defect.
    - Round 1: Cooperate.
    - Final Round: Defect.
    - If c_total_prev < m: Switch to/Continue Defect.
    - If c_total_prev == m: If I cooperated, continue Cooperate; else Defect.
    - If c_total_prev > m: Defect.
    - Reset Logic: If c_total_prev < m despite my cooperation, and I have previously 
      observed a successful threshold round, switch to permanent Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.ever_met_threshold = False
        self.punishing = False

    def __call__(self, history: PlayerHistory) -> Action:
        if self.game_description.k <= 1 or self.game_description.n_players - 1 < self.game_description.m:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        my_prev_action = history.my_actions[-1]
        my_prev_int = 1 if my_prev_action else 0
        c_total_prev = history.opponent_cooperators[-1] + my_prev_int
        was_met = c_total_prev >= self.game_description.m
        if was_met:
            self.ever_met_threshold = True
        if my_prev_action == Action.C and (not was_met) and self.ever_met_threshold:
            self.punishing = True
        if self.punishing:
            return Action.D
        if c_total_prev < self.game_description.m:
            return Action.D
        elif c_total_prev == self.game_description.m:
            if my_prev_action == Action.C:
                return Action.C
            else:
                return Action.D
        else:
            return Action.D

class Strategy_SELFINTERESTED_39(BaseStrategy):
    """
    Implements a conditional threshold-tracking strategy for the Collective Risk Dilemma.
    The strategy probes the cooperation of others, free-rides when possible, and
    acts as a pivotal player (cooperating) only when it makes the difference between
    reaching and missing the threshold m.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.state = 'Probing'

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            self.state = 'Probing'
            return Action.D
        last_my_action = history.my_actions[-1]
        c_prev = 1 if last_my_action else 0
        c_total = history.opponent_cooperators[-1] + c_prev
        m = self.game_description.m
        if self.state == 'Probing':
            deficit = m - c_total
            if deficit <= 0:
                self.state = 'FreeRiding'
        if history.round_number == self.game_description.n_rounds - 1:
            if self.state == 'FreeRiding':
                return Action.D
            deficit_last = m - c_total
            if deficit_last == 1:
                return Action.C
            return Action.D
        if self.state == 'FreeRiding':
            return Action.D
        deficit = m - c_total
        if deficit <= 0:
            self.state = 'FreeRiding'
            return Action.D
        if deficit == 1:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_40(BaseStrategy):
    """
    A conditional cooperator strategy for the Collective Risk Dilemma.
    Implements a "tit-for-tat with threshold adjustment" approach:
    1. Always cooperates in the first round (The Test).
    2. Adaptive Observation: For rounds t > 1, cooperates only if the previous round's 
       total cooperators (including self) met or exceeded the threshold 'm'.
    3. Exploitation Prevention: Prioritizes maintaining the threshold if it is achievable.
    4. Terminal logic: Switches to defection in the final round if the immediate history 
       has been unreliable (threshold not met in recent history).
    5. Fallback: If reward k <= 1, defaults to defection as contributing is net-negative.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.is_profitable = game_description.k > 1.0

    def __call__(self, history: PlayerHistory) -> Action:
        if not self.is_profitable:
            return Action.D
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        prev_my_action = 1 if history.my_actions[-1] else 0
        n_c_prev = history.opponent_cooperators[-1] + prev_my_action
        action = Action.C if n_c_prev >= self.m else Action.D
        if round_idx == self.r - 1:
            if round_idx >= 1:
                prev_prev_n_c = -1
                if round_idx >= 2:
                    prev_prev_my = 1 if history.my_actions[-2] else 0
                    prev_prev_n_c = history.opponent_cooperators[-2] + prev_prev_my
                if n_c_prev < self.m or (prev_prev_n_c != -1 and prev_prev_n_c < self.m):
                    return Action.D
        return action

class Strategy_SELFINTERESTED_41(BaseStrategy):
    """
    Threshold-Conditional Tit-for-Tat:
    - First round: Always defect to test threshold.
    - Last round: Always defect to maximize payoff.
    - Subsequent rounds: 
        - If threshold met in prev round: 
            - Cooperate if k > 1 and previous action was C, else Defect.
        - If threshold not met in prev round:
            - If own contribution was the missing piece to reach m, cooperate with probability k/(k+1).
    - Includes heuristics to stop cooperating if history shows repeated failure.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == self.r - 1:
            return Action.D
        if current_round == 0:
            return Action.D
        prev_round = current_round - 1
        prev_opp_coop = int(history.opponent_cooperators[prev_round])
        prev_my_action = bool(history.my_actions[prev_round])
        prev_total_coop = prev_opp_coop + (1 if prev_my_action else 0)
        total_cooperators_history = history.opponent_cooperators + history.my_actions.astype(np.int_)
        never_met_threshold = np.all(total_cooperators_history < self.m)
        if never_met_threshold and current_round > 1:
            return Action.D
        if prev_total_coop >= self.m:
            if prev_my_action:
                return Action.C if self.k > 1.0 else Action.D
            else:
                return Action.D
        else:
            if prev_total_coop == self.m - 1 and (not prev_my_action):
                prob = self.k / (self.k + 1.0)
                return Action.C if random.random() < prob else Action.D
            return Action.D

class Strategy_SELFINTERESTED_42(BaseStrategy):
    """
    Adaptive Threshold-Conditional Tit-for-Tat:
    1. Initial Round: Play C with probability p = m/n.
    2. Monitoring: Tracks successful threshold achievements.
    3. Rules:
       - If previous threshold (m) met: Reciprocate previous action.
       - If previous threshold not met: Provide marginal utility if 1 short of m; otherwise defect.
    4. Terminal Phase (last 2 rounds): Always defect.
    5. Edge Case: If 3 consecutive successful rounds, switch to 'Conditional Defector' (C only if exactly m or m+1).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.successful_streak = 0

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round >= self.r - 2:
            return Action.D
        if current_round == 0:
            p = self.m / self.n
            return Action.C if random.random() < p else Action.D
        my_prev_action = history.my_actions[-1]
        c_prev_total = history.opponent_cooperators[-1] + (1 if my_prev_action else 0)
        if c_prev_total >= self.m:
            self.successful_streak += 1
        else:
            self.successful_streak = 0
        if self.successful_streak >= 3:
            if c_prev_total == self.m or c_prev_total == self.m + 1:
                return Action.C
            else:
                return Action.D
        if c_prev_total >= self.m:
            if my_prev_action:
                return Action.C
            else:
                return Action.D
        elif c_prev_total == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_43(BaseStrategy):
    """
    Threshold-Adaptive Reciprocity Strategy:
    Adapts contribution probability based on a decaying moving average of observed cooperators.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.alpha = 0.2
        self.c_avg = 0.0
        self.consecutive_zero_rounds = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            prob_cooperate = self.m / self.n
            return Action.C if random.random() < prob_cooperate else Action.D
        n_opponents = self.n - 1
        my_prev_action = history.my_actions[-1]
        obs_cooperators_opponents = history.opponent_cooperators[-1]
        total_cooperators_last_round = obs_cooperators_opponents + (1 if my_prev_action else 0)
        self.c_avg = (1 - self.alpha) * self.c_avg + self.alpha * total_cooperators_last_round
        if total_cooperators_last_round < self.m - 2:
            self.c_avg = 0.0
        if total_cooperators_last_round == 0:
            self.consecutive_zero_rounds += 1
        else:
            self.consecutive_zero_rounds = 0
        if self.consecutive_zero_rounds >= 3:
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            if self.c_avg >= self.m - 1:
                contributed_recently = False
                if history.round_number >= 1 and history.my_actions[-1]:
                    contributed_recently = True
                if history.round_number >= 2 and history.my_actions[-2]:
                    contributed_recently = True
                return Action.C if contributed_recently else Action.D
            return Action.D
        if self.c_avg >= self.m:
            return Action.D
        gap = self.m - self.c_avg
        if total_cooperators_last_round == self.m - 1:
            return Action.C
        if gap <= 1:
            return Action.C
        elif gap <= 2:
            return Action.C if random.random() < 0.5 else Action.D
        else:
            return Action.D

class Strategy_SELFINTERESTED_44(BaseStrategy):
    """
    Threshold-Sensitive Tit-for-Tat with Defection Dampening.
    
    Strategy logic:
    - Round 1: Defect.
    - Subsequent rounds:
        - If threshold m was met last round:
            - If cooperators > m: Defect (redundant).
            - If cooperators == m: Cooperate (necessary for success).
        - If threshold m was NOT met last round:
            - If cooperators == m - 1: Cooperate (attempt to bridge).
            - If cooperators < m - 1: Defect (futile).
    - Endgame (final round):
        - Defect unless cooperators == m - 1 and k > 1.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        n = self.game_description.n_players
        m = self.game_description.m
        k = self.game_description.k
        r = self.game_description.n_rounds
        my_last_action = history.my_actions[-1]
        others_c = history.opponent_cooperators[-1]
        my_c = 1 if my_last_action else 0
        total_c = others_c + my_c
        if history.round_number == r - 1:
            if total_c == m - 1 and k > 1:
                return Action.C
            return Action.D
        if total_c >= m:
            if total_c > m:
                return Action.D
            else:
                return Action.C
        elif total_c == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_45(BaseStrategy):
    """
    Threshold-Dependent Conditional Cooperation (TDCC):
    - First round: Cooperate.
    - Subsequent rounds (non-final):
        - If C_{t-1} >= m: Defect (free-ride).
        - If C_{t-1} < m: Cooperate (needed to meet threshold).
    - Final round: Defect.
    - Exception: If k < 1, always Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if self.game_description.k < 1.0:
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        last_round_idx = history.round_number - 1
        opponents_cooperated = history.opponent_cooperators[last_round_idx]
        my_action_last_round = history.my_actions[last_round_idx]
        total_cooperators_prev = opponents_cooperated + (1 if my_action_last_round else 0)
        m = self.game_description.m
        if total_cooperators_prev >= m:
            return Action.D
        else:
            return Action.C

class Strategy_SELFINTERESTED_46(BaseStrategy):
    """
    Threshold-Conditional Reciprocity Strategy for Collective Risk Dilemma.
    
    Explores, signals, and adaptively chooses between a 'Grim-Trigger-Lite' 
    punishment phase or a 'Conditional Cooperation' phase based on 
    calculated historical success rates.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description
        self.exploration_limit = math.ceil(self.game.n_rounds / 5)
        self.grim_defection_counter = 0

    def __call__(self, history: PlayerHistory) -> Action:
        current_t = history.round_number
        n = self.game.n_players
        m = self.game.m
        k = self.game.k
        if k <= 1.0:
            return Action.D
        if current_t > 0:
            total_cooperators_prev = history.opponent_cooperators[-1] + (1 if history.my_actions[-1] else 0)
            if total_cooperators_prev == n:
                return Action.C
        if current_t < self.exploration_limit:
            if current_t == 0:
                return Action.C
            prev_total_coop = history.opponent_cooperators[-1] + (1 if history.my_actions[-1] else 0)
            if prev_total_coop >= m:
                return Action.C
            elif history.my_actions[-1] == False:
                return Action.C
            else:
                return Action.D
        if current_t < self.game.n_rounds - 1:
            successful_count = 0
            for r_idx in range(self.exploration_limit):
                total_coop_r = history.opponent_cooperators[r_idx] + (1 if history.my_actions[r_idx] else 0)
                if total_coop_r >= m:
                    successful_count += 1
            s_index = successful_count / self.exploration_limit
            if s_index < 0.5:
                if self.grim_defection_counter < 2:
                    self.grim_defection_counter += 1
                    return Action.D
                else:
                    self.grim_defection_counter = 0
                    return Action.C
            else:
                m_eff = m
                if history.opponent_cooperators[-1] >= m_eff:
                    return Action.C
                else:
                    return Action.D
        total_cooperators_prev = history.opponent_cooperators[-1] + (1 if history.my_actions[-1] else 0)
        if total_cooperators_prev >= m:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_47(BaseStrategy):
    """
    Threshold-Conditional Reciprocation:
    - Round 1: Cooperate with probability P = m/n.
    - Rounds 2 to r-1:
        - If previous threshold met (C_prev >= m): Repeat previous action.
        - If previous threshold failed (C_prev < m): 
            - If previously C: Switch to D (conserve).
            - If previously D: Attempt recovery with prob P_recovery = (m - C_prev) / (n - C_prev).
    - Terminal Phase (Round r): Always defect (D).
    - Stagnation: If C_prev was 0 for three consecutive rounds, switch to D permanently.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.consecutive_zeros = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.desc.n_players
        m = self.desc.m
        r = self.desc.n_rounds
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        if current_round > 0:
            c_prev = history.opponent_cooperators[-1]
            if c_prev == 0:
                self.consecutive_zeros += 1
            else:
                self.consecutive_zeros = 0
            if self.consecutive_zeros >= 3:
                return Action.D
        if current_round == 0:
            prob_c = m / n
            return Action.C if random.random() < prob_c else Action.D
        c_prev = history.opponent_cooperators[-1]
        my_prev_action = Action.C if history.my_actions[-1] else Action.D
        if c_prev >= m:
            return my_prev_action
        elif my_prev_action == Action.C:
            return Action.D
        else:
            needed = m - c_prev
            available = n - c_prev
            prob_recovery = needed / available
            return Action.C if random.random() < prob_recovery else Action.D

class Strategy_SELFINTERESTED_48(BaseStrategy):
    """
    Implements a Threshold-Sensitive Tit-for-Tat (TSTFT) strategy.
    
    This strategy adapts to the group's cooperative threshold by:
    1. Probing with Cooperation in the first round.
    2. Analyzing the previous round's cooperation count to determine if the player is 'pivotal'.
    3. Defecting if the threshold is met without the player, or if the threshold is impossible to reach.
    4. Cooperating if pivotal (m-1) or during the early-game 'reputation building' phase.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.n = game_description.n_players

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_round_idx = history.round_number - 1
        coop_count_history = history.opponent_cooperators[prev_round_idx]
        last_my_action = history.my_actions[prev_round_idx]
        c_self = 1 if last_my_action else 0
        e_others = coop_count_history - c_self
        if history.round_number == self.r - 1:
            if e_others >= self.m - 1:
                return Action.C
            return Action.D
        is_early_game = history.round_number <= self.r / 4
        if e_others >= self.m:
            return Action.D
        elif e_others == self.m - 1:
            return Action.C
        else:
            if is_early_game and e_others >= self.m - 2:
                return Action.C
            return Action.D

class Strategy_SELFINTERESTED_49(BaseStrategy):
    """
    Threshold-Conditional Tit-for-Tat with Defection-Risk Thresholding.
    
    This strategy implements:
    1. Initial Phase (Rounds 0-2): Cooperate to establish a baseline.
    2. Adaptive Phase (Rounds 3 to r-2):
       - If previous round met threshold (>= m): Defect if surplus (N_c > m), else Cooperate.
       - If previous round failed threshold (< m): Cooperate if within striking distance (N_c >= m - 1), else Defect.
    3. Endgame Phase (Final round): Defect to maximize utility.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_idx = history.round_number
        total_rounds = self.desc.n_rounds
        m = self.desc.m
        if current_round_idx == total_rounds - 1:
            return Action.D
        if current_round_idx < 3:
            return Action.C
        my_last_action_val = 1 if history.my_actions[-1] else 0
        last_total_cooperators = history.opponent_cooperators[-1] + my_last_action_val
        if last_total_cooperators >= m:
            if last_total_cooperators > m:
                return Action.D
            else:
                return Action.C
        elif last_total_cooperators >= m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_50(BaseStrategy):
    """
    Implements a Conditional Threshold strategy for the Collective Risk Dilemma.
    It balances cooperative pivot behavior with free-riding, incorporating a 
    signaling mechanism to break sub-optimal equilibria.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_stuck_rounds = 0
        self.signaled = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            if m / n > 0.5:
                return Action.C
            else:
                return Action.D
        if current_round == r - 1:
            return Action.D
        c_prev = history.opponent_cooperators[-1]
        i_prev = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = c_prev + i_prev
        if total_cooperators_prev == m - 1:
            self.consecutive_stuck_rounds += 1
        else:
            self.consecutive_stuck_rounds = 0
        if self.consecutive_stuck_rounds > 2 and (not self.signaled):
            self.signaled = True
            return Action.C
        if self.signaled and total_cooperators_prev < m:
            return Action.D
        if total_cooperators_prev >= m:
            return Action.D
        if total_cooperators_prev < m - 1:
            return Action.D
        if i_prev == 0:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_51(BaseStrategy):
    """
    Adaptive Threshold Trigger Strategy:
    - Initially probes cooperation.
    - Tracks threshold deficits.
    - Switches to defection if population proves uncooperative or if 
      threshold is already met.
    - Uses probabilistic cooperation when acting as the pivot.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.probe_rounds = min(3, max(1, math.ceil(self.game_description.n_rounds / 4)))
        self.threshold_met_history = []
        self.has_given_up = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        k = self.game_description.k
        r = self.game_description.n_rounds
        t = history.round_number
        if t >= 2:
            last_two_zero = history.opponent_cooperators[-1] == 0 and history.opponent_cooperators[-2] == 0
            if last_two_zero:
                self.has_given_up = True
                return Action.D
        if self.has_given_up:
            return Action.D
        if t == 0:
            return Action.C
        last_round_idx = t - 1
        my_last_action = int(history.my_actions[last_round_idx])
        total_cooperators_last = history.opponent_cooperators[last_round_idx] + my_last_action
        self.threshold_met_history.append(1 if total_cooperators_last >= m else 0)
        if t == r - 1:
            current_cooperators = history.opponent_cooperators[-1]
            deficit = m - (current_cooperators + 1)
            if deficit <= 0:
                return Action.C
            return Action.D
        current_opp_cooperators = history.opponent_cooperators[-1]
        deficit_if_i_defect = m - current_opp_cooperators
        if deficit_if_i_defect <= 0:
            return Action.D
        if deficit_if_i_defect == 1:
            if k > 1:
                prob = (k - 1) / k
                return Action.C if random.random() < prob else Action.D
            return Action.D
        if len(self.threshold_met_history) > 0:
            success_rate = sum(self.threshold_met_history) / len(self.threshold_met_history)
            if success_rate > 0.5:
                return Action.D
        if t < self.probe_rounds:
            return Action.C
        self.has_given_up = True
        return Action.D

class Strategy_SELFINTERESTED_52(BaseStrategy):
    """
    Implements a threshold-trigger tit-for-tat strategy for the Collective Risk Dilemma.
    
    Decisions are based on:
    1. The final round condition (Defect).
    2. Systemic failure detection (3 consecutive rounds of failure).
    3. Threshold-based reciprocity: Cooperate if the group meets the threshold required 
       to obtain reward k, factoring in whether self-contribution changes the outcome.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        last_round_idx = history.round_number - 1
        last_my_action = Action.C if history.my_actions[last_round_idx] else Action.D
        last_total_cooperators = history.opponent_cooperators[last_round_idx] + (1 if last_my_action == Action.C else 0)
        if last_total_cooperators < self.game_description.m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 3:
            return Action.D
        last_C_count = history.opponent_cooperators[-1]
        last_my_action = Action.C if history.my_actions[-1] else Action.D
        threshold_needed = self.game_description.m if last_my_action == Action.D else self.game_description.m - 1
        remaining_rounds = self.game_description.n_rounds - history.round_number
        if last_my_action == Action.D and last_C_count == self.game_description.m - 1 and (remaining_rounds >= 2):
            return Action.C
        if last_C_count >= threshold_needed:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_53(BaseStrategy):
    """
    Adaptive Threshold-Seeking Strategy:
    - Signals cooperation early based on target m/n.
    - Adapts probability of C based on current shortfall.
    - Transitions to Defect when the threshold is met, using probe factors.
    - Monitors for sustained failure to switch to permanent Defection.
    - Implements recovery logic after unexpected cooperation dips.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.consecutive_failures = 0
        self.recovery_mode = False
        self.recovery_timer = 0
        self.permanent_defection = False

    def __call__(self, history: PlayerHistory) -> Action:
        if self.permanent_defection:
            return Action.D
        round_idx = history.round_number
        n = self.desc.n_players
        m = self.desc.m
        if round_idx == 0:
            p = m / n
            return Action.C if random.random() < p else Action.D
        prev_round_idx = round_idx - 1
        my_prev_action = history.my_actions[prev_round_idx]
        c_prev = history.opponent_cooperators[prev_round_idx] + (1 if my_prev_action else 0)
        if c_prev < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
            self.recovery_mode = False
            self.recovery_timer = 0
        if self.consecutive_failures >= 3:
            self.permanent_defection = True
            return Action.D
        if round_idx == self.desc.n_rounds - 1:
            lookback = min(3, round_idx)
            avg_coop = np.mean(history.opponent_cooperators[-lookback:] + history.my_actions[-lookback:].astype(int))
            if avg_coop >= m:
                return Action.D
            has_success = np.any(history.opponent_cooperators + history.my_actions.astype(int) >= m)
            if has_success:
                return Action.C if random.random() < m / n else Action.D
            return Action.D
        if self.recovery_mode:
            self.recovery_timer += 1
            if self.recovery_timer > 2:
                self.permanent_defection = True
                return Action.D
            return Action.C
        if c_prev < m and any(history.opponent_cooperators + history.my_actions.astype(int) >= m):
            self.recovery_mode = True
            self.recovery_timer = 0
            return Action.C
        deficit = max(0, m - c_prev)
        if deficit > 0:
            p = min(1.0, deficit / (n - c_prev + 1))
            return Action.C if random.random() < p else Action.D
        else:
            epsilon = 0.1 if c_prev > m else 0.05
            return Action.D if random.random() < 1.0 - epsilon else Action.C

class Strategy_SELFINTERESTED_54(BaseStrategy):
    """
    A conditional cooperation strategy for the Collective Risk Dilemma.
    Implements threshold-based adjustments, defensive defecting, and 
    probabilistic efficiency corrections.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.permanent_defect = False

    def _get_total_cooperators(self, round_idx: int, history: PlayerHistory) -> int:
        """Helper to get total cooperators for a specific round index."""
        opps = history.opponent_cooperators[round_idx]
        mine = 1 if history.my_actions[round_idx] else 0
        return opps + mine

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if not self.permanent_defect and current_round >= 2:
            s_minus_1 = self._get_total_cooperators(current_round - 1, history)
            s_minus_2 = self._get_total_cooperators(current_round - 2, history)
            if s_minus_1 < m and s_minus_2 < m:
                self.permanent_defect = True
        if self.permanent_defect:
            return Action.D
        if current_round == 0:
            return Action.C if random.random() < m / n else Action.D
        s_prev = self._get_total_cooperators(current_round - 1, history)
        if current_round == r - 1:
            if s_prev >= m:
                return Action.C
            return Action.D
        if s_prev >= m:
            if s_prev > 1.5 * m:
                if random.random() < 0.5 * m / s_prev:
                    return Action.C
                return Action.D
            if s_prev > m:
                if random.random() < (s_prev - m) / s_prev:
                    return Action.D
                return Action.C
            else:
                return Action.C
        else:
            deficit = m - s_prev
            total_remaining = n - s_prev
            prob_next = min(1.0, deficit / total_remaining) if total_remaining > 0 else 0
            if random.random() < prob_next:
                return Action.C
            return Action.D

class Strategy_SELFINTERESTED_55(BaseStrategy):
    """
    Win-Stay, Lose-Shift strategy adapted for the Collective Risk Dilemma.
    
    Logic:
    - Round 0: Always Defect (D) to establish a baseline.
    - Subsequent Rounds:
        - If previous round threshold m was met (total cooperators >= m):
            - If we played Cooperate (C) and the total cooperators was exactly m, 
              we act as the critical contributor and must play C again to sustain the bonus.
            - Otherwise (we played C and total > m, OR we played D and total >= m),
              it is safe to Defect (D).
        - If previous round threshold m was not met:
            - Always Defect (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        m = self.game_description.m
        last_round_idx = -1
        my_last_action_is_c = history.my_actions[last_round_idx]
        opponents_cooperated = history.opponent_cooperators[last_round_idx]
        total_cooperators = opponents_cooperated + (1 if my_last_action_is_c else 0)
        bonus_secured = total_cooperators >= m
        if bonus_secured:
            if my_last_action_is_c and total_cooperators == m:
                return Action.C
            else:
                return Action.D
        else:
            return Action.D

class Strategy_SELFINTERESTED_56(BaseStrategy):
    """
    Implements the Adaptive Threshold-Trigger (ATT) strategy for the Collective Risk Dilemma.
    
    This strategy coordinates by attempting to reach the threshold 'm'. 
    It defaults to cooperation in the first round. In subsequent rounds, it 
    monitors the total number of cooperators (N_C) to decide:
    - If successful (N_C >= m): Maintain cooperation.
    - If a near-miss (N_C == m-1): Cooperate to bridge the gap.
    - If failing (N_C < m-1): Defect to protect endowment.
    
    In the final round, it cooperates only if the group was close to the threshold (>= m-1),
    otherwise it defaults to defection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.game_description.m
        r = self.game_description.n_rounds
        t = history.round_number + 1
        prev_my_action = 1 if history.my_actions[-1] else 0
        prev_opp_coop = history.opponent_cooperators[-1]
        prev_total_coop = prev_my_action + prev_opp_coop
        threshold_met = prev_total_coop >= m
        gap = m - prev_total_coop
        if t == r:
            return Action.C if prev_total_coop >= m - 1 else Action.D
        if threshold_met:
            return Action.C
        elif gap == 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_57(BaseStrategy):
    """
    Threshold Reciprocity with Contingent Defection.
    
    Phases:
    1. Calibration (Round 0): Cooperate if threshold relative to n > 0.5, else Defect.
    2. Conditional Reciprocity (Rounds 1 to r-2):
       - Calculate S = Average of past cooperator counts.
       - S >= m: Free-ride (D).
       - m-1 <= S < m: Pivot (C).
       - S < m-1: Defect (D) to minimize loss.
    3. Endgame (Round r-1): Always Defect (D).
    
    Includes Sucker Protection: If previous attempt at C did not meet threshold, switch to D.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.last_action_was_c = False
        self.sucker_protection_active = False

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        r = self.game_description.n_rounds
        m = self.game_description.m
        n = self.game_description.n_players
        if t == r - 1:
            return Action.D
        if t > 0:
            last_round_idx = t - 1
            last_i_cooperated = history.my_actions[last_round_idx]
            my_last_contribution = 1 if last_i_cooperated else 0
            total_cooperators_last_round = history.opponent_cooperators[last_round_idx] + my_last_contribution
            if last_i_cooperated and total_cooperators_last_round < m:
                self.sucker_protection_active = True
            else:
                self.sucker_protection_active = False
        if self.sucker_protection_active:
            return Action.D
        if t == 0:
            return Action.C if m / n > 0.5 else Action.D
        my_contribs = history.my_actions.astype(int)
        total_cooperators_history = history.opponent_cooperators + my_contribs
        avg_cooperators = np.mean(total_cooperators_history)
        if avg_cooperators >= m:
            return Action.D
        elif avg_cooperators >= m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_58(BaseStrategy):
    """
    Threshold-Adaptive Reciprocity (TAR) strategy for Collective Risk Dilemma.
    
    Logic:
    - If k <= 1: Always Defect (D).
    - Round 1: Defect (D).
    - Round t > 1:
        - If previous cooperators >= m: Defect (D) (Free-riding).
        - If previous cooperators == m - 1: Cooperate (C) (Threshold trigger).
        - If previous cooperators < m - 1: Defect (D) (Conservation).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if self.k <= 1.0:
            return Action.D
        if history.round_number == 0:
            return Action.D
        last_round_idx = history.round_number - 1
        my_last_action_val = 1 if history.my_actions[last_round_idx] else 0
        prev_total_cooperators = history.opponent_cooperators[last_round_idx] + my_last_action_val
        if prev_total_cooperators >= self.m:
            return Action.D
        elif prev_total_cooperators == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_59(BaseStrategy):
    """
    Threshold-Sensitive Tit-for-Tat (TSTFT) Strategy.
    
    This strategy conditionally cooperates to reach the threshold `m` only when
    cooperation is pivotal or when the group has already established a sustainable
    cooperative equilibrium. It prioritizes the threshold `m` as the pivot point
    for rational cooperation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_my_action_int = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + prev_my_action_int
        my_prev_action = Action.C if history.my_actions[-1] else Action.D
        current_round = history.round_number + 1
        if current_round == self.r:
            if total_cooperators_prev >= self.m - 1:
                return Action.C
            else:
                return Action.D
        if total_cooperators_prev >= self.m:
            return my_prev_action
        if total_cooperators_prev == self.m - 1:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_60(BaseStrategy):
    """
    Implements a Trigger-Adjusted Threshold Strategy.
    
    Phase 1: Cooperates on the first round.
    Phase 2: Uses a threshold-based adaptive logic. It monitors group cooperation. If the previous round met 
             the threshold, it maintains cooperation. If the threshold was narrowly missed, it attempts to 
             nudge the group. If the group is non-cooperative, it defects.
    Phase 3: Terminal Phase logic to secure the final reward if possible.
    Includes a "Free-Rider Pivot" to detect if the group threshold is met without the player's contribution,
    dynamically switching to defection if profitable.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.last_round_i_cooperated = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            self.last_round_i_cooperated = True
            return Action.C
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        prev_my_c = int(history.my_actions[-1])
        prev_opp_c = history.opponent_cooperators[-1]
        prev_total_c = prev_opp_c + prev_my_c
        if self.last_round_i_cooperated and (prev_total_c == m or prev_total_c == m + 1):
            if prev_opp_c >= m:
                self.last_round_i_cooperated = False
                return Action.D
        if history.round_number == r - 1:
            if prev_total_c >= m - 1:
                self.last_round_i_cooperated = True
                return Action.C
            else:
                self.last_round_i_cooperated = False
                return Action.D
        if prev_total_c >= m:
            self.last_round_i_cooperated = True
            return Action.C
        elif prev_total_c >= m - 1:
            self.last_round_i_cooperated = True
            return Action.C
        else:
            self.last_round_i_cooperated = False
            return Action.D

class Strategy_SELFINTERESTED_61(BaseStrategy):
    """
    Threshold-Targeted Tit-for-Tat (TTT) Strategy:
    - Round 1: Always Cooperate.
    - Rounds 1 < t < r:
        - If previous round threshold was met (C_prev >= m), continue Cooperate.
        - If previous round threshold was failed by exactly one (C_prev == m - 1), 
          signal by attempting to cooperate once. If that signal fails, defect.
        - Otherwise, Defect.
    - Final Round (t = r): Cooperate if the threshold was met in > 50% of 
      all previous rounds, otherwise Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.n = game_description.n_players
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_prev_action = int(history.my_actions[-1])
        c_prev_group = history.opponent_cooperators[-1] + my_prev_action
        if history.round_number == self.r - 1:
            all_prev_my_actions = history.my_actions.astype(int)
            all_prev_opponents = history.opponent_cooperators
            all_prev_totals = all_prev_opponents + all_prev_my_actions
            successes = np.sum(all_prev_totals >= self.m)
            total_past_rounds = len(all_prev_totals)
            if successes / total_past_rounds > 0.5:
                return Action.C
            return Action.D
        if c_prev_group >= self.m:
            return Action.C
        elif c_prev_group == self.m - 1:
            if my_prev_action == 0:
                return Action.C
            else:
                return Action.D
        else:
            return Action.D

class Strategy_SELFINTERESTED_62(BaseStrategy):
    """
    Implements a Threshold-Responsive Tit-for-Tat strategy for the Collective Risk Dilemma.
    Features:
    - Round 1: Stochastic cooperation with probability m/n.
    - Rounds 2 to r-1: Defection if threshold met/overshot or group failure is extreme; Cooperation if threshold is within reach (m-1).
    - Terminal: Always defect.
    - Adaptation: Permanent defection if threshold fails for 3 consecutive rounds; overshoot detection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.failure_streak = 0
        self.consecutive_overshoot = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            p = min(1.0, self.game_description.m / self.game_description.n_players)
            return Action.C if random.random() < p else Action.D
        prev_cooperators = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        total_prev_cooperators = prev_cooperators + (1 if my_prev_action else 0)
        if total_prev_cooperators < self.game_description.m:
            self.failure_streak += 1
        else:
            self.failure_streak = 0
        if total_prev_cooperators > self.game_description.m:
            self.consecutive_overshoot += 1
        else:
            self.consecutive_overshoot = 0
        if self.failure_streak >= 3:
            return Action.D
        if self.consecutive_overshoot >= 2:
            return Action.D
        if total_prev_cooperators >= self.game_description.m:
            return Action.D
        if total_prev_cooperators == self.game_description.m - 1:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_63(BaseStrategy):
    """
    Implements a Conditional Cooperation strategy with a 'Defect-Correction' 
    mechanism. It monitors the threshold m and adjusts cooperation based on 
    group outcomes, with a specific state machine for forced testing.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.mode = 0
        self.consecutive_defect_rounds = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        prev_my_action = history.my_actions[-1]
        prev_my_c = 1 if prev_my_action else 0
        n_prev_c = history.opponent_cooperators[-1] + prev_my_c
        if current_round == r - 1:
            if n_prev_c == m - 1:
                return Action.C
            else:
                return Action.D
        if self.mode > 0:
            self.mode -= 1
            if n_prev_c < m:
                self.consecutive_defect_rounds += 1
                if self.consecutive_defect_rounds >= 2:
                    self.mode = 0
                    self.consecutive_defect_rounds = 0
                    return Action.C
                return Action.D
            else:
                self.mode = 0
                self.consecutive_defect_rounds = 0
                return Action.D
        T = m - 1
        if prev_my_action:
            if n_prev_c > T:
                return Action.C
            else:
                self.mode = 2
                return Action.D
        elif n_prev_c >= m:
            return Action.D
        else:
            if n_prev_c == m - 1:
                return Action.C
            return Action.D

class Strategy_SELFINTERESTED_64(BaseStrategy):
    """
    A conditional cooperation strategy for the Collective Risk Dilemma:
    - Round 1: Defect.
    - Subsequent Rounds: 
        - If threshold m was met, Cooperate (unless in final 2 rounds).
        - If threshold m was missed, try 'swing' cooperation if only 1 more cooperator needed.
        - Otherwise, Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number + 1
        if current_round == 1:
            return Action.D
        prev_my_action = history.my_actions[-1]
        prev_opp_coop = history.opponent_cooperators[-1]
        prev_total_coop = prev_opp_coop + (1 if prev_my_action else 0)
        if prev_total_coop >= self.m:
            if current_round > self.r - 2:
                return Action.D
            else:
                return Action.C
        if prev_total_coop < self.m:
            if prev_total_coop == self.m - 1 and current_round < self.r:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_SELFINTERESTED_65(BaseStrategy):
    """
    Implements a threshold-conditional reciprocity strategy for the Collective Risk Dilemma.
    
    Phase 1: In the first round, cooperates if k > 1.
    Phase 2: In intermediate rounds, plays C if the previous round met the threshold (m), 
             otherwise plays D.
    Phase 3: In the final round, plays C if the threshold was met previously, otherwise D.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.k = game_description.k
        self.n = game_description.n_players
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C if self.k > 1 else Action.D
        last_round_idx = history.round_number - 1
        my_last_action = int(history.my_actions[last_round_idx])
        total_cooperators_prev = history.opponent_cooperators[last_round_idx] + my_last_action
        if history.round_number == self.r - 1:
            if total_cooperators_prev >= self.m:
                return Action.C
            else:
                return Action.D
        if self.k <= 1:
            return Action.D
        if total_cooperators_prev >= self.m:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_66(BaseStrategy):
    """
    Threshold-Adaptive Trigger (TAT)
    A strategy that balances reciprocity and threshold-efficiency. 
    It starts with cooperative exploration, adapts contributions based on threshold needs,
    and defects if the group proves unviable or when approaching the game's end.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.n = self.desc.n_players
        self.m = self.desc.m
        self.k = self.desc.k
        self.r = self.desc.n_rounds
        self.consecutive_failures = 0
        self.first_round_failure_cooldown = 0
        self.force_defect_mode = False

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if self.force_defect_mode:
            return Action.D
        if t > 0:
            last_round = t - 1
            last_c_count = history.opponent_cooperators[last_round] + int(history.my_actions[last_round])
            if last_c_count < self.m:
                self.consecutive_failures += 1
            else:
                self.consecutive_failures = 0
            if self.consecutive_failures >= 3:
                self.force_defect_mode = True
                return Action.D
        if t < 3:
            if t > 0 and self.first_round_failure_cooldown > 0:
                self.first_round_failure_cooldown -= 1
                return Action.D
            if t == 1:
                last_c_count = history.opponent_cooperators[0] + int(history.my_actions[0])
                if last_c_count < self.m:
                    self.first_round_failure_cooldown = 2
                    return Action.D
            return Action.C
        if t >= self.r - 1:
            total_contributions = np.sum(history.my_actions)
            total_rewards = np.sum([self.k if history.opponent_cooperators[i] + int(history.my_actions[i]) >= self.m else 0 for i in range(t)])
            if total_contributions > total_rewards or t == self.r - 1:
                return Action.D
            return Action.C
        last_round = t - 1
        last_c_count = history.opponent_cooperators[last_round] + int(history.my_actions[last_round])
        last_action = history.my_actions[last_round]
        if last_c_count > self.m + 1:
            return Action.D
        if last_c_count >= self.m:
            if not last_action:
                return Action.D
            else:
                others_c = history.opponent_cooperators[last_round]
                if others_c >= self.m:
                    return Action.D if random.random() < 1 - self.m / self.n else Action.C
                else:
                    return Action.C
        else:
            deficit = self.m - last_c_count
            if deficit == 1:
                return Action.C
            else:
                return Action.D

class Strategy_SELFINTERESTED_67(BaseStrategy):
    """
    Conditional Threshold-Trigger (CTT):
    - Round 1: Cooperate.
    - Subsequent Rounds (t < r):
        - Reciprocity: If opponents met or exceeded (m-1) cooperators last round, cooperate.
        - Defection: If opponents contributed fewer than (m-1) cooperators, defect.
        - Restoration: If playing D, calculate 'L' (consecutive D count) and test with probability P(L).
    - Final Round: If threshold met by others, defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.consecutive_defections = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        last_action = int(history.my_actions[-1])
        o_prev = int(history.opponent_cooperators[-1])
        is_final_round = history.round_number == self.r - 1
        if last_action == 0:
            self.consecutive_defections += 1
        else:
            self.consecutive_defections = 0
        if is_final_round:
            if o_prev >= self.m:
                return Action.D
            if o_prev == self.m - 1:
                return Action.C
            return Action.D
        if self.consecutive_defections > 0:
            p_test = min(self.consecutive_defections * 0.1, 0.5)
            if random.random() < p_test:
                return Action.C
        if o_prev >= self.m - 1:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_68(BaseStrategy):
    """
    Threshold-Adaptive Reciprocation (TAR) strategy for Collective Risk Dilemma.
    
    This strategy monitors collective cooperation and dynamically adjusts actions
    to maximize payoffs by being pivotal when needed and defecting when rewards
    are secured or impossible to reach. It includes drift protection logic to
    probe the population.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_defections_count = 0
        self.probed_last_round = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        k = self.game_description.k
        r = self.game_description.n_rounds
        round_idx = history.round_number
        if k <= 1:
            return Action.D
        if round_idx == 0:
            if m > 1:
                return Action.C
            else:
                return Action.D
        my_prev_action_bool = history.my_actions[-1]
        my_prev_contribution = 1 if my_prev_action_bool else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + my_prev_contribution
        if round_idx == r - 1:
            if total_cooperators_prev >= m - 1:
                return Action.D
        if not my_prev_action_bool:
            self.consecutive_defections_count += 1
        else:
            self.consecutive_defections_count = 0
            self.probed_last_round = False
        if self.consecutive_defections_count >= 3 and total_cooperators_prev < m - 1:
            if not self.probed_last_round:
                self.probed_last_round = True
                return Action.C
            else:
                return Action.D
        if total_cooperators_prev >= m:
            return Action.D
        if total_cooperators_prev == m - 1:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_69(BaseStrategy):
    """
    Threshold-Responsive Tit-for-Tat (TR-TFT)
    
    Optimizes for the minimum viable threshold:
    - Round 1: Cooperate if threshold/n > 0.5, else Defect.
    - Subsequent rounds:
        - If threshold met in previous round:
            - If we were necessary, keep cooperating.
            - Otherwise, defect.
        - If threshold missed in previous round:
            - If we can trigger it alone, cooperate.
            - Otherwise, conserve.
    - Punishment: If we are the sole swing voter for 3 consecutive rounds,
      punish for 2 rounds by defecting, then potentially revert or permanently defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.consecutive_swing_votes = 0
        self.punishment_rounds_remaining = 0
        self.permanently_defected = False

    def __call__(self, history: PlayerHistory) -> Action:
        if self.permanently_defected:
            return Action.D
        if self.punishment_rounds_remaining > 0:
            self.punishment_rounds_remaining -= 1
            return Action.D
        if history.round_number == 0:
            if self.desc.m / self.desc.n_players > 0.5:
                return Action.C
            return Action.D
        prev_my_c = bool(history.my_actions[-1])
        prev_opp_c = history.opponent_cooperators[-1]
        prev_total_c = prev_opp_c + (1 if prev_my_c else 0)
        is_swing_voter = prev_opp_c == self.desc.m - 1 and prev_my_c
        if is_swing_voter:
            self.consecutive_swing_votes += 1
            if self.consecutive_swing_votes >= 3:
                self.consecutive_swing_votes = 0
                self.punishment_rounds_remaining = 2
                return Action.D
        else:
            self.consecutive_swing_votes = 0
            if self.consecutive_swing_votes == 0 and prev_opp_c == 0 and prev_my_c and (self.desc.m > 1):
                self.permanently_defected = True
                return Action.D
        if prev_total_c >= self.desc.m:
            if prev_my_c and prev_opp_c >= self.desc.m:
                return Action.D
            elif not prev_my_c:
                return Action.D
            elif prev_my_c and prev_opp_c == self.desc.m - 1:
                return Action.C
            else:
                return Action.D
        elif prev_opp_c >= self.desc.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_70(BaseStrategy):
    """
    An adaptive conditional contribution strategy for the Collective Risk Dilemma.
    It utilizes a tiered response based on previous round cooperation, a terminal
    defection rule, and an 'over-contribution' pivot mechanism to optimize payoffs.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.consecutive_met_while_contributing = 0
        self.is_testing_pivot = False
        self.is_permanently_defecting = False

    def __call__(self, history: PlayerHistory) -> Action:
        if self.desc.k <= 1:
            return Action.D
        if history.round_number == self.desc.n_rounds - 1:
            return Action.D
        if self.desc.n_players == self.desc.m:
            return Action.C
        if history.round_number == 0:
            if self.desc.m / self.desc.n_players <= 0.5:
                return Action.C
            return Action.D
        prev_cooperators = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        total_cooperators = prev_cooperators + (1 if my_prev_action else 0)
        if total_cooperators >= self.desc.m and my_prev_action:
            self.consecutive_met_while_contributing += 1
        else:
            self.consecutive_met_while_contributing = 0
        if self.is_permanently_defecting:
            return Action.D
        if self.is_testing_pivot:
            if total_cooperators >= self.desc.m:
                self.is_permanently_defecting = True
                self.is_testing_pivot = False
                return Action.D
            else:
                self.is_testing_pivot = False
                return Action.C
        if self.consecutive_met_while_contributing >= 2:
            self.is_testing_pivot = True
            return Action.D
        if total_cooperators >= self.desc.m:
            return Action.C
        elif total_cooperators == self.desc.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_71(BaseStrategy):
    """
    Threshold-Adaptive Reciprocity (TAR):
    A strategy that contributes only when necessary to reach the collective
    threshold 'm', maximizing private gains by defecting when the threshold
    is either already met or unreachable by a single contribution.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        last_round_my_action = history.my_actions[-1]
        last_round_opponent_coops = history.opponent_cooperators[-1]
        c_prev = last_round_opponent_coops + (1 if last_round_my_action else 0)
        if t == self.r - 1:
            if c_prev >= self.m:
                return Action.D
            elif c_prev == self.m - 1:
                return Action.C
            else:
                return Action.D
        if c_prev >= self.m:
            return Action.D
        if c_prev == self.m - 1:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_72(BaseStrategy):
    """
    A conditional cooperation strategy that promotes the threshold 'm'.
    - Round 1: Always Cooperate (C).
    - Rounds 2 to r-1:
        - Reciprocates cooperation if the previous round met the threshold.
        - Defects (D) if the threshold was not met (signaling dissatisfaction).
        - Introduces a small noise factor epsilon=0.05 to test group robustness.
    - Endgame (last N rounds, N = min(3, r/4)):
        - Uses 'Tit-for-Tat' decay: If cooperation levels in the previous round fell below m-1, 
          defect regardless of threshold status to preempt collapse.
    - Final Round: Always Defect (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.epsilon = 0.05
        self.n_endgame = int(min(3, self.game_description.n_rounds / 4))

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        prev_my_action = history.my_actions[-1]
        prev_opponents_c = history.opponent_cooperators[-1]
        prev_total_c = (1 if prev_my_action else 0) + prev_opponents_c
        prev_threshold_met = prev_total_c >= m
        if current_round >= total_rounds - self.n_endgame:
            if prev_total_c < m - 1:
                return Action.D
        if not prev_threshold_met:
            return Action.D
        else:
            if random.random() < self.epsilon:
                return Action.D
            return Action.C

class Strategy_SELFINTERESTED_73(BaseStrategy):
    """
    Threshold-Sensitive Reciprocity (TSR):
    A strategy that aims to maximize payoff by ensuring the cooperation threshold (m) is met,
    while exploiting free-rider opportunities when the threshold is safely exceeded.
    It utilizes signaling and conditional cooperation after failures.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failure_count = 0
        self.signaling_mode = False
        self.gave_up_on_cooperation = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        round_idx = history.round_number
        if round_idx == r - 1:
            return Action.D
        if round_idx == 0:
            return Action.D
        last_round_idx = round_idx - 1
        my_last_action = history.my_actions[last_round_idx]
        total_cooperators = history.opponent_cooperators[last_round_idx] + (1 if my_last_action else 0)
        if self.gave_up_on_cooperation:
            return Action.D
        if total_cooperators < m:
            self.consecutive_failure_count += 1
            threshold = max(2, int(r * 0.1))
            if self.consecutive_failure_count >= threshold:
                if not self.signaling_mode:
                    self.signaling_mode = True
                    return Action.C
                else:
                    self.gave_up_on_cooperation = True
                    return Action.D
            else:
                return Action.D
        else:
            self.consecutive_failure_count = 0
            self.signaling_mode = False
            if my_last_action:
                if total_cooperators == m:
                    return Action.C
                else:
                    return Action.D
            else:
                return Action.D

class Strategy_SELFINTERESTED_74(BaseStrategy):
    """
    Implements the Adaptive Threshold Trigger (ATT) strategy:
    - Default: Defect (D) to secure private payoff.
    - Swing Voter: If previous round had exactly m-1 cooperators, Cooperate (C) to trigger reward.
    - Adaptive Signaling: If the group fails to meet the threshold for X consecutive rounds,
      perform a one-time test cooperation, then revert to defecting.
    - Endgame: In the final round, cooperate if the threshold is potentially reachable (m-1 cooperators).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.X = math.ceil(self.game_description.n_players / self.game_description.m)
        self.consecutive_failures = 0
        self.signaled = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        my_last_action = history.my_actions[-1]
        c_i_last = 1 if my_last_action else 0
        C_prev = history.opponent_cooperators[-1] + c_i_last
        if C_prev < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if current_round == r - 1:
            if C_prev >= m - 1:
                return Action.C
            else:
                return Action.D
        G = m - C_prev
        if G <= 0:
            return Action.D
        elif G == 1:
            return Action.C
        else:
            if not self.signaled and self.consecutive_failures >= self.X:
                self.signaled = True
                return Action.C
            return Action.D

class Strategy_SELFINTERESTED_75(BaseStrategy):
    """
    Threshold Tit-for-Tat with Probabilistic Exploitation:
    - Initially Cooperative.
    - Punishes group failures (C < m) by switching to Defective.
    - While Defective, occasionally attempts to "rescue" the group via probabilistic 
      cooperation, especially as the game nears its end.
    - Always "rescues" the group if they are exactly 1 short of the threshold.
    - Always defects on the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.state = 'Cooperative'

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        t = history.round_number
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        last_action_is_c = history.my_actions[-1]
        c_prev = history.opponent_cooperators[-1] + (1 if last_action_is_c else 0)
        if self.state == 'Cooperative' and c_prev < m:
            self.state = 'Defective'
        elif self.state == 'Defective':
            if last_action_is_c and c_prev >= m:
                self.state = 'Cooperative'
        if c_prev == m - 1:
            return Action.C
        if self.state == 'Cooperative':
            if c_prev >= m:
                return Action.C
            else:
                self.state = 'Defective'
                return Action.D
        else:
            p = (1.0 - t / r) ** 2
            if random.random() < p:
                return Action.C
            else:
                return Action.D

class Strategy_SELFINTERESTED_76(BaseStrategy):
    """
    Threshold-Adaptive Reciprocity (TAR) Strategy.
    
    Maintains cooperative threshold 'm' when evidence supports it.
    Defects if the threshold is met by others (free-riding) or if cooperation is futile.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k
        self.trust_score = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.r - 1:
            return Action.D
        last_round_idx = history.round_number - 1
        c_obs_total = history.opponent_cooperators[last_round_idx] + (1 if history.my_actions[last_round_idx] else 0)
        c_others = history.opponent_cooperators[last_round_idx]
        my_prev_action = 1 if history.my_actions[last_round_idx] else 0
        if c_obs_total >= self.m:
            self.trust_score += 1
        else:
            self.trust_score -= 1
        if self.trust_score < -self.m:
            self.trust_score = 0
        if c_others >= self.m:
            return Action.D
        if c_others == self.m - 1:
            if self.trust_score >= 0:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_SELFINTERESTED_77(BaseStrategy):
    """
    Threshold-Contingent Tit-for-Tat (TCTFT):
    A strategy that maintains the threshold m by free-riding (Defecting) whenever the
    threshold is met, and switching to contributing (Cooperate) only when the group 
    cooperation count is exactly m-1, thereby triggering the reward k.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_my_action = 1 if history.my_actions[-1] else 0
        prev_opp_coop = history.opponent_cooperators[-1]
        total_coop_prev = prev_opp_coop + prev_my_action
        m = self.game_description.m
        if total_coop_prev >= m:
            return Action.D
        if total_coop_prev == m - 1:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_78(BaseStrategy):
    """
    Implements the Threshold-Adaptive Reciprocity (TAR) strategy for Collective Risk Dilemmas.
    
    Strategy Principles:
    1.  Initialization: Always cooperate in the first round.
    2.  State-Based Logic: Maintains 'Active' (Cooperate) or 'Passive' (Defect) state
        based on previous round threshold performance.
    3.  Group Stability: If the group successfully cooperates (>= m cooperators)
        for three consecutive rounds, maintain Cooperation regardless of variance.
    4.  Terminal Defection: Always defect in the final round.
    5.  Reward Sensitivity: Defect immediately if the reward k <= 1.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if self.game.k <= 1:
            return Action.D
        if history.round_number == self.game.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        prev_my_action = history.my_actions[-1]
        prev_opp_coop = history.opponent_cooperators[-1]
        c_obs = prev_opp_coop + (1 if prev_my_action else 0)
        if history.round_number >= 3:
            recent_rounds = slice(-3, None)
            recent_my_actions = history.my_actions[recent_rounds].astype(int)
            recent_opp_coops = history.opponent_cooperators[recent_rounds]
            recent_totals = recent_my_actions + recent_opp_coops
            if np.all(recent_totals >= self.game.m):
                return Action.C
        was_active = bool(prev_my_action)
        if was_active:
            if c_obs >= self.game.m - 1:
                return Action.C
            else:
                return Action.D
        elif c_obs >= self.game.m:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_79(BaseStrategy):
    """
    Implements a conditional cooperation strategy for the Collective Risk Dilemma
    based on threshold monitoring and outcome history.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        is_terminal = history.round_number == self.game_description.n_rounds - 1
        s_opponents_last = int(history.opponent_cooperators[-1])
        my_last_action_bool = bool(history.my_actions[-1])
        s_total_last = s_opponents_last + (1 if my_last_action_bool else 0)
        if is_terminal:
            if s_total_last >= self.game_description.m:
                return Action.C
            return Action.D
        if my_last_action_bool:
            if s_total_last >= self.game_description.m:
                return Action.C
            else:
                return Action.D
        elif s_total_last >= self.game_description.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_80(BaseStrategy):
    """
    Implements Threshold-Conditional Reciprocity for the Collective Risk Dilemma.
    
    Strategy:
    1. Round 1: Cooperate if (m/n) <= (k-1)/k, else Defect.
    2. Rounds 2 to r-1:
       - If previous round >= m cooperators: Cooperate with probability 0.95 (noise).
       - If previous round == m-1 cooperators: Cooperate.
       - If previous round <= m-2 cooperators: Defect.
       - Adaptation: Every x-th round, Defect to test for free-riding (x = ceil((n+k)/k)).
    3. Final Round r: Always Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.epsilon = 0.05
        self.x = math.ceil((self.desc.n_players + self.desc.k) / self.desc.k)

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_idx = history.round_number
        n = self.desc.n_players
        m = self.desc.m
        k = self.desc.k
        r = self.desc.n_rounds
        if current_round_idx == 0:
            if m / n <= (k - 1) / k:
                return Action.C
            return Action.D
        if current_round_idx == r - 1:
            return Action.D
        if (current_round_idx + 1) % self.x == 0:
            return Action.D
        my_prev_action = 1 if history.my_actions[-1] else 0
        total_cooperators = history.opponent_cooperators[-1] + my_prev_action
        if total_cooperators >= m:
            if random.random() > self.epsilon:
                return Action.C
            return Action.D
        elif total_cooperators == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_81(BaseStrategy):
    """
    Threshold-Conditional Tit-for-Tat (TCTFT):
    A strategy that dynamically adjusts contribution based on whether the
    group threshold is met, employing free-riding, safety buffering,
    reciprocity, and punishment. Always defects on the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        c_prev_is_me = 1 if history.my_actions[-1] == True else 0
        c_prev_total = history.opponent_cooperators[-1] + c_prev_is_me
        i_prev = 1 if history.my_actions[-1] == True else 0
        m = self.game_description.m
        if c_prev_total >= m:
            if i_prev == 1 and c_prev_total == m:
                return Action.D
            elif i_prev == 1 and c_prev_total > m:
                return Action.C
            elif i_prev == 0:
                return Action.C
        else:
            return Action.D
        return Action.D

class Strategy_SELFINTERESTED_82(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that estimates opponent cooperation probability 
    based on historical data and decides to cooperate if the expected value of cooperation 
    exceeds the expected value of defection, provided the reward k justifies the risk.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.n_opponents = self.desc.n_players - 1
        self.always_defect = self.desc.k <= 1.0

    def _get_binomial_prob(self, n: int, k_val: int, p: float) -> float:
        if k_val < 0 or k_val > n:
            return 0.0
        comb = math.comb(n, k_val)
        return comb * p ** k_val * (1 - p) ** (n - k_val)

    def __call__(self, history: PlayerHistory) -> Action:
        if self.always_defect:
            return Action.D
        if history.round_number == 0:
            p_hat = 0.5
            val = self.desc.k * self._get_binomial_prob(self.n_opponents, self.desc.m - 1, p_hat)
            return Action.C if val > 1.0 else Action.D
        total_cooperators = np.sum(history.opponent_cooperators)
        total_observations = self.n_opponents * history.round_number
        p_hat = total_cooperators / total_observations if total_observations > 0 else 0.5
        expected_gain_condition = self.desc.k * self._get_binomial_prob(self.n_opponents, self.desc.m - 1, p_hat)
        if expected_gain_condition <= 1.0:
            return Action.D
        return Action.C

class Strategy_SELFINTERESTED_83(BaseStrategy):
    """
    A Threshold-Trigger strategy for the Collective Risk Dilemma.
    
    Logic Summary:
    - Round 1: Always Cooperate (C).
    - Rounds 2 to r-1: 
        - If previous cooperation count >= threshold M: Cooperate (C).
        - Else: Defect (D).
        - Resurrection: If previous count >= threshold M, switch back to C even if previously defecting.
        - Surplus Logic: If previous count > M, play D (unless C is required to maintain threshold).
    - Final Round (r): Always Defect (D), regardless of history.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_idx = history.round_number
        if current_round_idx == 0:
            return Action.C
        if current_round_idx == self.total_rounds - 1:
            return Action.D
        last_my_action = 1 if history.my_actions[-1] else 0
        last_total_cooperators = last_my_action + history.opponent_cooperators[-1]
        if last_total_cooperators >= self.m:
            if last_total_cooperators - 1 >= self.m:
                return Action.D
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_84(BaseStrategy):
    """
    Conditional Threshold Trigger (CTT) strategy:
    - Round 1: Defect.
    - Subsequent rounds:
        - If previous round total cooperators (T_c) >= m: Cooperate.
        - If T_c == m - 1: Cooperate (catalyst move).
        - Otherwise: Defect.
    - Includes sensitivity to exploitation: If T_c falls below m after I cooperated,
      I defect for one round to probe.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.probing = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        n = self.game_description.n_players
        m = self.game_description.m
        my_last_action = history.my_actions[-1]
        opp_c = history.opponent_cooperators[-1]
        t_c = opp_c + (1 if my_last_action else 0)
        if my_last_action and t_c < m:
            self.probing = True
            return Action.D
        if self.probing:
            if t_c >= m - 1:
                self.probing = False
            else:
                return Action.D
        if t_c >= m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_85(BaseStrategy):
    """
    Implements a risk-mitigation coordination strategy for the Collective Risk Dilemma.
    Uses probabilistic initialization, historical performance tracking, and 
    endgame resource optimization.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.epsilon = 0.05
        self.has_tested = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.desc.n_players
        m = self.desc.m
        r = self.desc.n_rounds
        current_round = history.round_number
        if current_round == 0:
            p = m / n * (1 + self.epsilon)
            p = min(p, 1.0)
            return Action.C if random.random() < p else Action.D
        if current_round > r - 3:
            successes = 0
            for i in range(current_round):
                total_coop = (1 if history.my_actions[i] else 0) + history.opponent_cooperators[i]
                if total_coop >= m:
                    successes += 1
            if successes / current_round < 0.5:
                return Action.D
        prev_my_action = history.my_actions[-1]
        prev_my_coop = 1 if prev_my_action else 0
        total_coop_prev = prev_my_coop + history.opponent_cooperators[-1]
        if total_coop_prev >= m:
            if not self.has_tested and total_coop_prev > m + (n - m) / 2:
                self.has_tested = True
                return Action.D
            if self.has_tested and total_coop_prev < m:
                self.has_tested = False
            return Action.C
        else:
            deficit = m - total_coop_prev
            if prev_my_action == Action.C:
                if deficit == 1:
                    return Action.C if random.random() < 0.75 else Action.D
                else:
                    return Action.D
            elif deficit == 1:
                return Action.C
            else:
                return Action.D

class Strategy_SELFINTERESTED_86(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that estimates opponent cooperation
    probability using a Bayesian-like update on reputation and makes decisions
    based on the expected utility of contributing vs. defecting.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k
        self.alpha = 0.1
        self.reputation = 1.0

    def _binomial_cdf_complement(self, n: int, p: float, k_threshold: int) -> float:
        """
        Calculates P(X >= k_threshold) where X ~ Binomial(n, p).
        Equivalent to 1 - P(X < k_threshold).
        """
        if k_threshold <= 0:
            return 1.0
        if k_threshold > n:
            return 0.0
        prob_success = 0.0
        for i in range(k_threshold, n + 1):
            comb = math.comb(n, i)
            prob = comb * p ** i * (1 - p) ** (n - i)
            prob_success += prob
        return min(1.0, max(0.0, prob_success))

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.r - 1:
            return Action.D
        if history.round_number > 0:
            last_s = history.opponent_cooperators[-1]
            self.reputation = (1 - self.alpha) * self.reputation + self.alpha * (last_s / (self.n - 1))
            p = (last_s + (self.n - 1) * self.reputation) / self.n
        else:
            p = 0.5
        p_success_if_c = self._binomial_cdf_complement(self.n - 1, p, self.m - 1)
        p_success_if_d = self._binomial_cdf_complement(self.n - 1, p, self.m)
        eu_c = p_success_if_c * self.k - 1.0
        eu_d = p_success_if_d * self.k
        if eu_c > eu_d:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_87(BaseStrategy):
    """
    Adaptive Threshold Trigger (ATT) Strategy:
    Cooperate initially. In subsequent rounds, cooperate only if pivotal (c_{t-1} = m-1),
    or if the trend is positive towards the threshold. Defect if the threshold is already met
    or if the collective effort is failing and likely to remain below the threshold.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.failed_streak = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.game_description.m
        k = self.game_description.k
        r = self.game_description.n_rounds
        t = history.round_number
        c_prev = history.opponent_cooperators[-1]
        if c_prev < m - 1:
            self.failed_streak += 1
        else:
            self.failed_streak = 0
        if self.failed_streak >= 3:
            return Action.D
        if t == r - 1:
            x = min(3, r - 1)
            recent_coops = history.opponent_cooperators[-x:]
            avg_coops = sum(recent_coops) / len(recent_coops)
            if avg_coops > m - 2:
                return Action.C
            return Action.D
        if k <= 1:
            return Action.D
        if c_prev >= m:
            return Action.D
        if c_prev == m - 1:
            return Action.C
        if t >= 2:
            c_prev_prev = history.opponent_cooperators[-2]
            delta = c_prev - c_prev_prev
            if delta > 0:
                return Action.C
        return Action.D

class Strategy_SELFINTERESTED_88(BaseStrategy):
    """
    Threshold-Conditional Reciprocity Strategy:
    - Phase 1: Cooperates on round 1.
    - Phase 2: Adjusts behavior based on whether the threshold was met in the previous round.
      - If threshold met: Cooperate (stabilize reward).
      - If threshold not met: Defect (save cost).
    - Phase 3: Terminal round defects unless pivoting.
    - Edge Cases: Pivotal rescue if previous round was m-1; defects if 3 consecutive failures.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description
        self.failure_counter = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_round = history.round_number - 1
        my_prev_action = int(history.my_actions[prev_round])
        total_cooperators_prev = history.opponent_cooperators[prev_round] + my_prev_action
        if total_cooperators_prev < self.game.m:
            self.failure_counter += 1
        else:
            self.failure_counter = 0
        if self.failure_counter >= 3:
            return Action.D
        if total_cooperators_prev == self.game.m - 1:
            return Action.C
        if history.round_number == self.game.n_rounds - 1:
            return Action.D
        if total_cooperators_prev >= self.game.m:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_89(BaseStrategy):
    """
    Threshold-Responsive Tit-for-Tat with Defection-on-Convergence:
    - Round 1: Always Cooperate (C).
    - Terminal Round: Always Defect (D).
    - Intermediate Rounds:
        - If previous cooperators >= m:
            - If I played C, probabilistically switch to D (to free-ride).
            - If I played D, stay D.
        - If previous cooperators < m:
            - If I played C, switch to D (avoiding waste).
            - If I played D, probabilistically play C (to rescue threshold).
    - Includes specific triggers for 'Rescue' (C if threshold imminent) and 
      'Free-Rider' (D if buffer exists).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.has_defected_previously = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.r - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        i_played_c_last = history.my_actions[-1]
        c_prev = history.opponent_cooperators[-1] + (1 if i_played_c_last else 0)
        if c_prev == self.m - 1:
            return Action.C
        if c_prev >= self.m:
            if i_played_c_last:
                prob_d = 1.0 / (self.n - self.m + 1)
                if self.game_description.m + 1 < c_prev:
                    prob_d = 0.8
                if random.random() < prob_d:
                    self.has_defected_previously = True
                    return Action.D
            return Action.D
        elif i_played_c_last:
            self.has_defected_previously = True
            return Action.D
        else:
            denom = self.n - c_prev
            if denom <= 0:
                prob_c = 0.0
            else:
                prob_c = (self.m - c_prev) / denom
            if random.random() < prob_c:
                return Action.C
            return Action.D

class Strategy_SELFINTERESTED_90(BaseStrategy):
    """
    Implements a phase-based adaptive strategy for the Collective Risk Dilemma.
    - Phase 1: Initiates with Cooperation.
    - Phase 2: Monitors previous success (c >= m). Cooperates if successful or 
      near-threshold (m-1), otherwise Defects to minimize loss.
    - Phase 3: Defects unless in 'Stable Cooperation' (success in last 3 rounds).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def _get_total_cooperators_last_round(self, history: PlayerHistory) -> int:
        """Helper to calculate total cooperators including self."""
        i_cooperated = int(history.my_actions[-1])
        return history.opponent_cooperators[-1] + i_cooperated

    def _is_stable_cooperation(self, history: PlayerHistory, window: int=3) -> bool:
        """
        Checks if the collective threshold (m) was met in each of the last 
        'window' rounds.
        """
        if history.round_number < window:
            return False
        for r in range(history.round_number - window, history.round_number):
            i_cooperated = int(history.my_actions[r])
            total_coop = history.opponent_cooperators[r] + i_cooperated
            if total_coop < self.game_description.m:
                return False
        return True

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            if self._is_stable_cooperation(history, window=3):
                return Action.C
            return Action.D
        prev_total = self._get_total_cooperators_last_round(history)
        if prev_total >= self.game_description.m:
            return Action.C
        if prev_total == self.game_description.m - 1:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_91(BaseStrategy):
    """
    Implements Conditional Reciprocity with Threshold Sensitivity:
    - Rounds 0-2 (first 3): Play Defect (D).
    - Rounds 3 to r-2: 
        - If previous N_C >= m: Defect (D) to free-ride.
        - If previous N_C == m-1: Cooperate (C) with prob (k-1)/k to hit threshold.
        - Otherwise: Defect (D).
    - Final round (r-1): Same logic as standard rounds but treats the immediate payoff as the priority.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.k = game_description.k
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number <= 2:
            return Action.D
        my_prev_action = history.my_actions[-1]
        others_prev_count = history.opponent_cooperators[-1]
        n_c_prev = (1 if my_prev_action else 0) + others_prev_count
        if n_c_prev >= self.m:
            return Action.D
        elif n_c_prev == self.m - 1:
            prob_c = (self.k - 1) / self.k
            if random.random() < prob_c:
                return Action.C
            else:
                return Action.D
        else:
            return Action.D

class Strategy_SELFINTERESTED_92(BaseStrategy):
    """
    Implements the Adaptive Threshold Strategy.
    
    This strategy monitors the previous round's outcome to determine the current state:
    - Recovery Phase: If the threshold was missed, cooperate to initiate collective effort.
    - Surplus Phase: If the threshold was met, defect to maximize individual payoff.
    - Precarious Phase: If the threshold was met exactly (by m cooperators), contribute
      to keep the system stable and prevent cascading failure.
    - Terminal Round: Finalizes with defection if the system is safe, or conditional
      cooperation if the threshold is within reach.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        m = self.game_description.m
        r = self.game_description.n_rounds
        n = self.game_description.n_players
        t = history.round_number
        if t == 0:
            return Action.C
        last_my_action_int = 1 if history.my_actions[-1] else 0
        last_opp_coop = int(history.opponent_cooperators[-1])
        last_total_C = last_my_action_int + last_opp_coop
        last_S = 1 if last_total_C >= m else 0
        if t == r - 1:
            if last_S == 1:
                return Action.D
            else:
                return Action.C if last_total_C >= m - 1 else Action.D
        if last_S == 0:
            return Action.C
        if last_total_C == m:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_93(BaseStrategy):
    """
    Threshold-Responsive Tit-for-Tat (TR-TFT):
    A strategy that switches between 'Cautious', 'Stable', and 'Defensive' states
    based on threshold attainment in previous rounds.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self._state = 'Cautious'

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            if n > m:
                return Action.C
            else:
                return Action.D
        last_my_action = 1 if history.my_actions[-1] else 0
        c_prev = history.opponent_cooperators[-1] + last_my_action
        r_rem = r - current_round
        if c_prev == n:
            self._state = 'Stable'
        elif self._state == 'Cautious' and c_prev >= m:
            self._state = 'Stable'
        elif c_prev < m:
            self._state = 'Defensive'
        elif self._state == 'Defensive' and c_prev >= m:
            self._state = 'Cautious'
        if r_rem == 1:
            if self._state == 'Stable' or self._state == 'Defensive':
                return Action.D
            elif self._state == 'Cautious':
                if c_prev == m - 1:
                    return Action.C
                else:
                    return Action.D
        if self._state == 'Stable':
            return Action.D
        elif self._state == 'Cautious':
            if c_prev < m + 1:
                return Action.C
            else:
                return Action.D
        elif self._state == 'Defensive':
            return Action.D
        return Action.D

class Strategy_SELFINTERESTED_94(BaseStrategy):
    """
    A strategy that balances cooperation and defection based on the threshold (m) and observed history.
    
    Logic:
    - Round 1: Random 50/50 cooperation.
    - Rounds 2 to r-1: 
        - If threshold was met with surplus: Defect.
        - If threshold was met exactly: Cooperate to maintain.
        - If threshold was not met: Defect (and stop cooperating permanently after 3 consecutive failures).
    - Round r (Final): Always Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0
        self.perm_defect = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C if random.random() < 0.5 else Action.D
        if self.perm_defect:
            return Action.D
        prev_my_action = 1 if history.my_actions[-1] else 0
        prev_opp_coop = history.opponent_cooperators[-1]
        c_prev_total = prev_opp_coop + prev_my_action
        m = self.game_description.m
        if c_prev_total >= m:
            self.consecutive_failures = 0
            if c_prev_total > m:
                return Action.D
            else:
                return Action.C
        else:
            self.consecutive_failures += 1
            if self.consecutive_failures >= 3:
                self.perm_defect = True
                return Action.D
            return Action.D

class Strategy_SELFINTERESTED_95(BaseStrategy):
    """
    Implements Dynamic Threshold Reciprocity.
    - Phase 1: Defect in Round 1.
    - Phase 2: Cooperate only if others meet the threshold requirement AND 
      the group succeeded in the previous round.
    - Phase 3: Terminal Horizon - Cooperate if reward is positive and group
      cooperation has been consistently high (>= m/n) over the last 3 rounds.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.k = game_description.k
        self.r = game_description.n_rounds
        self.threshold_ratio = self.m / self.n

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_index = history.round_number
        if current_round_index == 0:
            return Action.D
        if current_round_index == self.r - 1:
            if self.k > 1 and current_round_index >= 3:
                my_actions_int = history.my_actions.astype(int)
                total_cooperators_history = my_actions_int + history.opponent_cooperators
                recent_total = total_cooperators_history[-3:]
                avg_cooperation_rate = np.mean(recent_total) / self.n
                if avg_cooperation_rate >= self.threshold_ratio:
                    return Action.C
            return Action.D
        prev_round_idx = -1
        prev_opp_coop_count = history.opponent_cooperators[prev_round_idx]
        my_prev_action = history.my_actions[prev_round_idx]
        prev_total_coop = prev_opp_coop_count + (1 if my_prev_action else 0)
        threshold_met = prev_total_coop >= self.m
        n_others = self.n - 1
        others_rate = prev_opp_coop_count / n_others if n_others > 0 else 0
        if others_rate >= self.threshold_ratio and threshold_met:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_96(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that balances threshold maintenance
    with exploitative defection, including a mechanism to abandon cooperation
    if the collective consistently fails to meet the threshold.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.failed_consecutive_count = 0
        self.gave_up = False

    def __call__(self, history: PlayerHistory) -> Action:
        m = self.game_description.m
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        t = history.round_number
        if t == 0:
            if m / n <= 0.5:
                return Action.C
            else:
                return Action.D
        if self.gave_up:
            return Action.D
        if t == r - 1:
            return Action.D
        prev_my_action = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + prev_my_action
        if total_cooperators_prev < m - 1:
            self.failed_consecutive_count += 1
        else:
            self.failed_consecutive_count = 0
        if self.failed_consecutive_count >= 2:
            self.gave_up = True
            return Action.D
        if total_cooperators_prev >= m:
            return Action.D
        return Action.C

class Strategy_SELFINTERESTED_97(BaseStrategy):
    """
    Implements a Threshold-Sensitive Tit-for-Tat strategy for the Collective Risk Dilemma.
    It calibrates contributions based on threshold requirements, incorporates
    conditional cooperation, handles volatility via a generous defect/cooperate trigger,
    and defaults to defection in the final round or if the incentive structure is unfavorable.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description
        self.last_was_defect_due_to_failure = False

    def __call__(self, history: PlayerHistory) -> Action:
        if self.game.k < 1:
            return Action.D
        if history.round_number == self.game.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            try:
                prob = (self.game.m - 1) / (self.game.n_players - 1)
                return Action.C if random.random() < prob else Action.D
            except ZeroDivisionError:
                return Action.C
        prev_round_idx = history.round_number - 1
        my_prev_action = history.my_actions[prev_round_idx]
        opp_cooperators = history.opponent_cooperators[prev_round_idx]
        c_obs = opp_cooperators + (1 if my_prev_action else 0)
        if self.game.n_players - c_obs < self.game.m:
            self.last_was_defect_due_to_failure = False
            return Action.D
        if self.last_was_defect_due_to_failure and c_obs == self.game.m - 1:
            self.last_was_defect_due_to_failure = False
            return Action.C
        if c_obs >= self.game.m:
            self.last_was_defect_due_to_failure = False
            return Action.C
        else:
            sufficiency = c_obs / self.game.m
            if 0.8 <= sufficiency < 1.0:
                prev_payoff = history.my_payoffs[prev_round_idx]
                if prev_payoff >= 1.0:
                    return Action.C
            self.last_was_defect_due_to_failure = True
            return Action.D

class Strategy_SELFINTERESTED_98(BaseStrategy):
    """
    Implements the Collective Risk Dilemma strategy:
    - Round 1: Always Cooperate (C).
    - Rounds 2 to r-1:
        - If the threshold was met in the previous round:
            - Cooperate (C) only if the number of cooperators was exactly m (meaning my contribution was necessary).
            - Otherwise, Defect (D) to maximize personal payoff.
        - If the threshold was not met in the previous round:
            - Defect (D).
    - Round r: Always Defect (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        threshold = self.game_description.m
        if current_round == 0:
            return Action.C
        if current_round == total_rounds - 1:
            return Action.D
        prev_my_coop = bool(history.my_actions[-1])
        prev_opp_coop = history.opponent_cooperators[-1]
        total_coop_prev = (1 if prev_my_coop else 0) + prev_opp_coop
        if total_coop_prev >= threshold:
            if prev_my_coop:
                if total_coop_prev == threshold:
                    return Action.C
                else:
                    return Action.D
            else:
                return Action.D
        else:
            return Action.D

class Strategy_SELFINTERESTED_99(BaseStrategy):
    """
    Implements the Conditional Threshold Monitoring (CTM) strategy.
    
    Phase 1: Initial Rounds (t = 1 to 3): Always Cooperate.
    Phase 2: Adaptive Maintenance (t = 4 to r-1):
        - If previous round cooperators >= m: Defect (unless unstable).
        - If previous round cooperators == m - 1: Cooperate (pivot to trigger reward).
        - If previous round cooperators < m - 1: Defect (conserve resources).
    Phase 3: Terminal Round (t = r): Always Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.performance_history = []

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number + 1
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == total_rounds:
            return Action.D
        if current_round <= 3:
            return Action.C
        last_opponent_cooperators = history.opponent_cooperators[-1]
        my_last_action_val = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = last_opponent_cooperators + my_last_action_val
        self.performance_history.append(total_cooperators_prev)
        is_unstable = False
        if len(self.performance_history) >= 2:
            if self.performance_history[-1] < m and self.performance_history[-2] < m:
                is_unstable = True
        if total_cooperators_prev >= m:
            if is_unstable:
                return Action.C
            return Action.D
        elif total_cooperators_prev == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_100(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that employs adaptive threshold
    adjustment and endgame defection.

    Strategy Logic:
    1. Initial Round: Always starts with Action.C.
    2. Adaptive Threshold Adjustment:
       - Tracks success (C_prev >= S) vs failure (C_prev < S).
       - If failure, flips behavior (C -> D, D -> C).
       - If success, maintains behavior.
    3. Endgame Heuristic: In the final round, always defects.
    4. Defector Exploitation: If success occurs (C_prev >= m+1) for two consecutive rounds,
       attempts to defect to test if the group sustains the threshold. If C drops,
       reverts to C immediately.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.S = game_description.m
        self.consecutive_success_count = 0
        self.is_testing_exploitation = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        prev_round = history.round_number - 1
        my_prev_action_val = 1 if history.my_actions[prev_round] else 0
        c_prev = history.opponent_cooperators[prev_round] + my_prev_action_val
        my_prev_action = Action.C if history.my_actions[prev_round] else Action.D
        if self.is_testing_exploitation and c_prev < self.game_description.m:
            self.is_testing_exploitation = False
            self.consecutive_success_count = 0
            return Action.C
        if c_prev >= self.S:
            self.consecutive_success_count += 1
            if self.consecutive_success_count >= 2:
                self.is_testing_exploitation = True
                return Action.D
            return my_prev_action
        else:
            self.consecutive_success_count = 0
            self.is_testing_exploitation = False
            if my_prev_action == Action.C:
                return Action.D
            else:
                return Action.C

class Strategy_SELFINTERESTED_101(BaseStrategy):
    """
    Tit-for-Tat with Threshold Sensitivity strategy.
    
    Logic:
    - Round 1: Always Cooperate (C).
    - Last Round: Always Defect (D).
    - Intermediate Rounds: 
        1. Calculate if the threshold `m` is met including self.
        2. If C_{t-1} >= m and I defected, check if count dropped. If it did, revert to C.
        3. Otherwise, use threshold logic: if C_{t-1} (including my action) >= m, 
           free-ride if possible or maintain threshold.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.r - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        prev_my_action = history.my_actions[-1]
        prev_my_action_val = 1 if prev_my_action else 0
        prev_total_cooperators = history.opponent_cooperators[-1] + prev_my_action_val
        if history.round_number >= 2:
            prev_prev_my_action = 1 if history.my_actions[-2] else 0
            prev_prev_total_cooperators = history.opponent_cooperators[-2] + prev_prev_my_action
            if prev_prev_total_cooperators >= self.m and prev_prev_my_action == 0:
                if prev_total_cooperators < self.m:
                    return Action.C
        if prev_total_cooperators >= self.m:
            if prev_my_action:
                if history.opponent_cooperators[-1] >= self.m:
                    return Action.D
                else:
                    return Action.C
            return Action.D
        else:
            if prev_my_action:
                return Action.D
            return Action.D

class Strategy_SELFINTERESTED_102(BaseStrategy):
    """
    Threshold-Adaptive Reciprocity (TAR) Strategy:
    - Round 1: Cooperate if threshold/players <= 0.5, else Defect.
    - Rounds 2 to r-1:
        - If previous cooperators >= m: Cooperate.
        - If previous cooperators == m - 1: Cooperate with probability p = 1 - (m/n).
        - Otherwise: Defect.
    - Final round (r): Always Defect.
    - Edge Case: If total remaining potential payoff from cooperation is strictly
      less than total remaining potential payoff from defection, switch to permanent Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description
        self.permanent_defection = False

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.game.n_rounds
        n = self.game.n_players
        m = self.game.m
        k = self.game.k
        if self.permanent_defection:
            return Action.D
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            if m / n <= 0.5:
                return Action.C
            else:
                return Action.D
        remaining_rounds = total_rounds - current_round
        avg_past_cooperation = np.mean(history.opponent_cooperators) if current_round > 0 else 0
        if avg_past_cooperation < m - 1 and current_round > 2:
            self.permanent_defection = True
            return Action.D
        prev_cooperators = int(history.opponent_cooperators[-1])
        if prev_cooperators >= m:
            return Action.C
        elif prev_cooperators == m - 1:
            probability_c = 1.0 - m / n
            if random.random() < probability_c:
                return Action.C
            else:
                return Action.D
        else:
            return Action.D

class Strategy_SELFINTERESTED_103(BaseStrategy):
    """
    Threshold-Targeting Conditional Cooperation:
    This strategy attempts to ensure exactly m cooperators exist to trigger the reward k.
    It signals cooperation in the first round. In subsequent rounds, it adjusts its 
    contribution based on whether its participation is necessary to reach the threshold m.
    It includes a fallback to defecting if the group consistently fails to reach the threshold.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.failed_to_coordinate = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == 1:
            my_last_action = int(history.my_actions[-1])
            total_cooperators_round_1 = history.opponent_cooperators[-1] + my_last_action
            if total_cooperators_round_1 < self.game_description.m:
                self.failed_to_coordinate = True
        if self.failed_to_coordinate:
            return Action.D
        my_last_action = int(history.my_actions[-1])
        eff_cooperators = history.opponent_cooperators[-1]
        if eff_cooperators >= self.game_description.m:
            return Action.D
        elif eff_cooperators == self.game_description.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_104(BaseStrategy):
    """
    Implements a Threshold Reciprocity with Conditional Forgiveness strategy.
    
    The strategy attempts to maintain the minimum number of cooperators (m) 
    required to trigger the reward (k) by acting as the marginal contributor 
    when necessary, but defecting when the threshold is met or when the group 
    is too far from the threshold to make cooperation efficient. It also 
    includes a fallback mechanism for systemic defection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0
        self.systemic_defection_mode = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        t = history.round_number
        if t == 0:
            return Action.C
        if self.systemic_defection_mode:
            return Action.D
        prev_my_action = history.my_actions[-1]
        prev_C_total = history.opponent_cooperators[-1] + (1 if prev_my_action else 0)
        prev_threshold_met = prev_C_total >= m
        if prev_C_total < m - 1:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 3:
            self.systemic_defection_mode = True
            return Action.D
        if t == r - 1:
            if prev_threshold_met:
                return Action.D
            elif prev_C_total == m - 1:
                return Action.C
            else:
                return Action.D
        if t > 1:
            prev_prev_my_action = history.my_actions[-2]
            prev_prev_C_total = history.opponent_cooperators[-2] + (1 if prev_prev_my_action else 0)
            if prev_C_total < m - 1 and prev_prev_C_total >= m:
                return Action.C
        if prev_threshold_met:
            if prev_my_action and prev_C_total == m:
                return Action.D
            if prev_my_action and prev_C_total > m:
                return Action.D
            if not prev_my_action:
                return Action.D
            return Action.D
        if not prev_threshold_met:
            if prev_C_total == m - 1:
                return Action.C
            if prev_C_total < m - 1:
                return Action.D
        return Action.D

class Strategy_SELFINTERESTED_105(BaseStrategy):
    """
    Threshold-Adaptive Trigger (TAT) Strategy:
    A conditional cooperation strategy focused on meeting the threshold m at minimum personal cost.
    Uses adaptive rules based on previous round outcomes to balance contribution and free-riding.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.probe_counter = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if self.desc.k <= 1:
            return Action.D
        round_num = history.round_number
        n = self.desc.n_players
        m = self.desc.m
        if round_num == 0:
            return Action.C
        if round_num == self.desc.n_rounds - 1:
            last_opp_coop = history.opponent_cooperators[-1]
            last_my_action = history.my_actions[-1]
            total_coop_last = last_opp_coop + (1 if last_my_action else 0)
            if last_my_action or total_coop_last >= m - 1:
                return Action.C
            return Action.D
        last_opp_coop = history.opponent_cooperators[-1]
        last_my_action = history.my_actions[-1]
        total_coop_last = last_opp_coop + (1 if last_my_action else 0)
        self.probe_counter += 1
        if self.probe_counter >= 3:
            self.probe_counter = 0
            return Action.D
        if total_coop_last >= m:
            if last_my_action:
                if total_coop_last > m:
                    return Action.D
                return Action.C
            else:
                return Action.D
        else:
            if m - total_coop_last == 1:
                return Action.C
            return Action.D

class Strategy_SELFINTERESTED_106(BaseStrategy):
    """
    Adaptive Threshold Trigger (ATT):
    A strategy that calibrates in the first round, adapts to the previous round's 
    cooperation levels to maintain thresholds, and switches to a probability-based 
    heuristic in the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            prob = self.game_description.m / self.game_description.n_players
            return Action.C if random.random() < prob else Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            total_successes = 0
            for r in range(history.round_number):
                my_last_action = 1 if history.my_actions[r] else 0
                total_cooperators = my_last_action + history.opponent_cooperators[r]
                if total_cooperators >= self.game_description.m:
                    total_successes += 1
            success_rate = total_successes / history.round_number
            return Action.C if success_rate > 0.5 else Action.D
        my_prev_action = 1 if history.my_actions[-1] else 0
        last_C = my_prev_action + history.opponent_cooperators[-1]
        m = self.game_description.m
        if last_C >= m:
            return Action.C if last_C == m else Action.D
        else:
            return Action.C if last_C >= m - 1 else Action.D

class Strategy_SELFINTERESTED_107(BaseStrategy):
    """
    Threshold-Responsive Tit-for-Tat with Defection-Buffering.
    
    A dynamic strategy for the Collective Risk Dilemma that:
    1. Sets initial cooperation based on the threshold difficulty (m/n).
    2. Maintains cooperation if the threshold was met previously.
    3. Pivots to cooperation if the previous round was one short of the threshold (m-1).
    4. Punishes by defection if the threshold is significantly missed.
    5. Defects unconditionally on the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        m = self.game_description.m
        current_round = history.round_number
        is_last_round = current_round == r - 1
        if is_last_round:
            return Action.D
        if current_round == 0:
            if m / n <= 0.5:
                return Action.C
            else:
                return Action.D
        my_prev_action = history.my_actions[-1]
        opp_cooperators = history.opponent_cooperators[-1]
        s_prev = int(my_prev_action) + opp_cooperators
        if s_prev >= m:
            if not my_prev_action:
                return Action.D
            else:
                return Action.C
        elif s_prev == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_108(BaseStrategy):
    """
    Implements a risk-aware strategy for the Collective Risk Dilemma.
    Uses probabilistic calibration in the first round, adaptive threshold management
    in intermediate rounds with a 'near-miss' memory mechanism, and strict defection
    in the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.near_miss_count = 0
        self.tit_for_tat_mode = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        m = self.game_description.m
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        if current_round == 0:
            threshold_prob = (m - 1) / (n - 1)
            return Action.C if random.random() < threshold_prob else Action.D
        last_cooperators = history.opponent_cooperators[-1]
        if last_cooperators == m - 1:
            self.near_miss_count += 1
        else:
            self.near_miss_count = 0
        if self.near_miss_count >= 3:
            self.tit_for_tat_mode = True
        if self.tit_for_tat_mode:
            return Action.C if last_cooperators >= m - 1 else Action.D
        if last_cooperators >= m:
            return Action.D
        delta = m - last_cooperators
        if delta == 1:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_109(BaseStrategy):
    """
    A Threshold-Triggered Tit-for-Tat strategy for the Collective Risk Dilemma.
    
    Logic:
    1. First Round: Cooperate (C).
    2. Terminal Round (last round): Defect (D).
    3. Intermediate Rounds:
       - If previous total cooperators (including self) >= m: Defect (D).
       - If previous total cooperators (including self) == m-1: Cooperate (C).
       - If previous total cooperators (including self) < m-1: Defect (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.desc.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        prev_my_action = history.my_actions[-1]
        prev_opp_coop_count = history.opponent_cooperators[-1]
        total_cooperators_prev = (1 if prev_my_action else 0) + prev_opp_coop_count
        if total_cooperators_prev >= self.desc.m:
            return Action.D
        elif total_cooperators_prev == self.desc.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_110(BaseStrategy):
    """
    Conditional Threshold Tit-for-Tat (CT-TFT).
    A strategy designed for Collective Risk Dilemmas that adapts cooperation levels based on
    threshold attainment and individual contribution history to optimize personal payoff.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        r_total = self.game_description.n_rounds
        m = self.game_description.m
        if history.round_number == 0:
            return Action.C
        prev_round_idx = history.round_number - 1
        prev_my_action = Action.C if history.my_actions[prev_round_idx] else Action.D
        my_prev_contrib = 1 if prev_my_action == Action.C else 0
        n_coop = history.opponent_cooperators[prev_round_idx] + my_prev_contrib
        threshold_met = n_coop >= m
        if history.round_number == r_total - 1:
            if threshold_met:
                return Action.D
        if threshold_met and prev_my_action == Action.D:
            return Action.D
        if not threshold_met and prev_my_action == Action.C:
            return Action.D
        if not threshold_met and prev_my_action == Action.D:
            return Action.C
        if threshold_met and prev_my_action == Action.C:
            if n_coop == m:
                return Action.C
            if n_coop > m:
                return Action.D
        return Action.C

class Strategy_SELFINTERESTED_111(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that balances cooperation based on
    previous group success, exploiting successful thresholds and attempting to
    rescue near-failures, while defecting on the final round and during periods of
    clear coordination success.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.desc.n_rounds
        n = self.desc.n_players
        m = self.desc.m
        if current_round == 0:
            if m / n > 0.5:
                return Action.C
            return Action.D
        if current_round == total_rounds - 1:
            return Action.D
        last_opponent_coops = history.opponent_cooperators[-1]
        last_my_action = history.my_actions[-1]
        s_prev = last_opponent_coops + (1 if last_my_action else 0)
        if s_prev >= m:
            return Action.D
        if s_prev == m - 1:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_112(BaseStrategy):
    """
    Implements Threshold-Conditional Reciprocity:
    1. Initial round: Cooperate if k > 1.
    2. Core Rule: Reciprocate success; probabilistically reset after failure.
    3. Terminal Phase: Defect if history is poor; cooperate if reliable.
    4. Edge Case Handling: Maximize gain if persistent failure; nudge if near-threshold.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.persistent_failure_count = 0
        self.persistent_failure_mode = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        m = self.game_description.m
        k = self.game_description.k
        round_num = history.round_number
        if round_num == 0:
            return Action.C if k > 1 else Action.D
        my_last_action = int(history.my_actions[-1])
        c_prev = history.opponent_cooperators[-1] + my_last_action
        if c_prev < m:
            self.persistent_failure_count += 1
        else:
            self.persistent_failure_count = 0
        if self.persistent_failure_count >= 3:
            self.persistent_failure_mode = True
        if self.persistent_failure_mode:
            return Action.D
        if round_num == r - 1:
            if r > 5 and len(history.opponent_cooperators) >= 3:
                last_3_avg = np.mean(history.opponent_cooperators[-3:] + history.my_actions[-3:].astype(int))
                if last_3_avg < m - 1:
                    return Action.D
            return Action.C
        if c_prev == m - 1:
            return Action.C
        if c_prev >= m:
            return Action.C
        if m == 0 or c_prev == 0:
            return Action.D
        prob_reset = c_prev / m
        if random.random() < prob_reset:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_113(BaseStrategy):
    """
    Threshold Tit-for-Tat with Defection bias.
    
    Logic:
    - Round 1: Cooperate if m/n > 0.5, else Defect.
    - Subsequent rounds:
        - If previous round success (C_total >= m) AND own_prev=C: Cooperate with prob 1 - (m/n).
        - If previous round success (C_total >= m) AND own_prev=D: Cooperate.
        - If previous round fail (C_total < m): Defect, unless C_total == m-1, then 0.5 probability to cooperate.
    - Terminal round: Defect, unless C_prev == m-1, then Cooperate.
    - Adaptation: If avg_cooperation_last_3 < m/n, permanently Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.permanent_defection = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number >= 3:
            last_3_total_coops = []
            for r in range(history.round_number - 3, history.round_number):
                c_total = history.opponent_cooperators[r] + (1 if history.my_actions[r] else 0)
                last_3_total_coops.append(c_total / self.n)
            if np.mean(last_3_total_coops) < self.m / self.n:
                self.permanent_defection = True
        if self.permanent_defection:
            return Action.D
        if history.round_number == 0:
            return Action.C if self.m / self.n > 0.5 else Action.D
        prev_round_idx = history.round_number - 1
        prev_opp_coops = history.opponent_cooperators[prev_round_idx]
        prev_own_action = history.my_actions[prev_round_idx]
        prev_own_val = 1 if prev_own_action else 0
        prev_total_coops = prev_opp_coops + prev_own_val
        if history.round_number == self.r - 1:
            if prev_total_coops == self.m - 1:
                return Action.C
            return Action.D
        success = prev_total_coops >= self.m
        if success:
            if prev_own_action:
                prob_coop = 1.0 - self.m / self.n
                return Action.C if random.random() < prob_coop else Action.D
            else:
                return Action.C
        elif prev_total_coops == self.m - 1:
            return Action.C if random.random() < 0.5 else Action.D
        else:
            return Action.D

class Strategy_SELFINTERESTED_114(BaseStrategy):
    """
    Implements a 'Conditional Contribution based on Threshold Reliability' strategy.
    
    The strategy probes collective propensity in the first round. In subsequent rounds,
    it maintains a belief variable B about the probability of meeting the threshold,
    updated via an exponential moving average. Decisions are based on whether the
    expected utility of cooperation exceeds the cost of contribution (1).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.belief = 0.5
        self.alpha = 0.8
        self.theta = 1.0 / game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        k = self.game_description.k
        t = history.round_number
        if t == 0:
            if k > 1 and random.random() < m / n:
                return Action.C
            return Action.D
        if t == r - 1:
            total_cooperators = []
            for i in range(len(history.my_actions)):
                my_c = 1 if history.my_actions[i] else 0
                total_cooperators.append(history.opponent_cooperators[i] + my_c)
            matches_m_minus_1 = 0
            matches_m = 0
            for total_c in total_cooperators:
                if total_c >= m:
                    matches_m += 1
                if total_c >= m - 1:
                    matches_m_minus_1 += 1
            denom = len(total_cooperators)
            prob_hit_m = matches_m / denom
            prob_hit_m_minus_1 = matches_m_minus_1 / denom
            expected_gain_C = prob_hit_m_minus_1 * k - 1
            expected_gain_D = prob_hit_m * k
            return Action.C if expected_gain_C > expected_gain_D else Action.D
        my_prev_action = 1 if history.my_actions[-1] else 0
        prev_total = history.opponent_cooperators[-1] + my_prev_action
        indicator = 1.0 if prev_total >= m else 0.0
        self.belief = self.alpha * self.belief + (1.0 - self.alpha) * indicator
        if not history.my_actions[-1] and prev_total >= m:
            return Action.C
        if history.my_actions[-1] and prev_total < m:
            return Action.D
        if self.belief > self.theta:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_115(BaseStrategy):
    """
    Implements a Threshold-Conditional Reciprocity strategy for the Collective Risk Dilemma.
    It prioritizes initial cooperation, then employs conditional defection based on the
    previous round's cooperation levels to maximize utility. It includes a fallback to
    permanent defection if the group proves incapable of coordinating.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k
        self.consecutive_failures = 0
        self.permanent_defection = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_last_action = int(history.my_actions[-1])
        c_prev = history.opponent_cooperators[-1] + my_last_action
        if c_prev < self.m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 3:
            self.permanent_defection = True
        if self.permanent_defection:
            return Action.D
        if history.round_number == self.r - 1:
            return Action.D
        if c_prev > self.m:
            return Action.D
        elif c_prev == self.m:
            return Action.D
        elif c_prev == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_116(BaseStrategy):
    """
    Trigger-Threshold-Reciprocator strategy for the Collective Risk Dilemma.
    Implements conditional cooperation, defection penalties, re-entry attempts,
    last-round selfishness, and quit-thresholds for non-cooperative environments.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description
        self.consecutive_defect_count = 0
        self.permanent_defect = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game.n_players
        m = self.game.m
        r = self.game.n_rounds
        current_round = history.round_number
        last_round_idx = current_round - 1
        if current_round == r - 1:
            if current_round >= 5:
                recent_cooperation = [history.opponent_cooperators[i] >= m for i in range(current_round - 5, current_round)]
                if all(recent_cooperation):
                    return Action.C
            return Action.D
        if self.permanent_defect:
            return Action.D
        if m >= n - 1:
            if current_round >= 3:
                recent_failures = [history.opponent_cooperators[i] <= m - 2 for i in range(current_round - 3, current_round)]
                if all(recent_failures):
                    self.permanent_defect = True
                    return Action.D
        c_prev = history.opponent_cooperators[last_round_idx]
        my_prev_action = history.my_actions[last_round_idx]
        if c_prev >= m:
            self.consecutive_defect_count = 0
            if my_prev_action:
                return Action.C
            else:
                return Action.D
        if c_prev < m:
            self.consecutive_defect_count += 1
            if self.consecutive_defect_count >= 3:
                self.consecutive_defect_count = 0
                return Action.C
            if random.random() < 0.1:
                return Action.C
            if my_prev_action:
                return Action.D
            else:
                return Action.D
        return Action.D

class Strategy_SELFINTERESTED_117(BaseStrategy):
    """
    Implements an Adaptive Threshold-Tracking Strategy.
    
    This strategy behaves as a conditional cooperator:
    1. Probe: Always cooperates in the first round.
    2. Tracking: Maintains a weighted moving average of opponent cooperation to estimate
       the likelihood of hitting the threshold 'm'.
    3. Threshold Logic:
       - Defect if opponents contribute >= m (Free-riding).
       - Cooperate if opponents contribute == m-1 (Pivotal contribution).
       - Defect if opponents contribute < m-1 (Unattainable reward).
    4. Terminal Phase: Always defects in the last 3 rounds to prevent exploitation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.window_size = 5

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round >= total_rounds - 3:
            return Action.D
        if current_round == 0:
            return Action.C
        recent_history = history.opponent_cooperators[-self.window_size:]
        avg_opp_c = np.mean(recent_history)
        if avg_opp_c >= m:
            return Action.D
        if avg_opp_c >= m - 1 - 0.2:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_118(BaseStrategy):
    """
    Implements a Conditional Threshold Sensitivity (CTS) strategy.
    
    1. Calibration (Round 0): Always Defect.
    2. Adaptive Targeting (Rounds 1 to n_rounds-2):
        - If threshold met with surplus: Defect, unless previous defect caused failure.
        - If threshold barely met: Cooperate to maintain equilibrium.
        - If threshold not met: Defect (sunk cost logic).
        - Edge cases:
            - If threshold not met for 3 rounds: Probing (50/50 chance for one round).
            - If k is large: Strict equilibrium maintenance.
            - If C is consistently large: Permanent Defection.
    3. Terminal Phase (Last Round): Always Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description
        self.consecutive_failures = 0
        self.probing_active = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game.n_players
        m = self.game.m
        r = self.game.n_rounds
        k = self.game.k
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        if current_round == 0:
            return Action.D
        prev_round = current_round - 1
        c_prev_total = history.opponent_cooperators[prev_round]
        my_action_prev = history.my_actions[prev_round]
        total_c_prev = c_prev_total + (1 if my_action_prev else 0)
        if total_c_prev > m + (n - m) / 2:
            return Action.D
        if total_c_prev < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
            self.probing_active = False
        if self.consecutive_failures >= 3 and (not self.probing_active):
            self.probing_active = True
            return Action.C if random.random() < 0.5 else Action.D
        if k > 5.0:
            if total_c_prev == m:
                return Action.C
            if total_c_prev == m + 1:
                return Action.D
            return Action.D if total_c_prev > m else Action.D
        if total_c_prev >= m:
            if total_c_prev > m:
                if my_action_prev and total_c_prev - 1 < m:
                    return Action.C
                return Action.D
            else:
                return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_119(BaseStrategy):
    """
    A conditional trigger strategy for the Collective Risk Dilemma.
    
    Strategy Logic:
    - Round 1: Cooperate (C).
    - Round r (Final): Defect (D).
    - Rounds 2 to r-1:
        - If previous round cooperators (c_{t-1}) >= m: Defect (D).
        - If previous round cooperators (c_{t-1}) == m-1: Cooperate (C).
        - If previous round cooperators (c_{t-1}) < m-1: Defect (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C
        if round_idx == self.n_rounds - 1:
            return Action.D
        my_prev_action = Action.C if history.my_actions[round_idx - 1] else Action.D
        opp_coop_count = history.opponent_cooperators[round_idx - 1]
        total_prev_c = opp_coop_count + (1 if my_prev_action == Action.C else 0)
        if total_prev_c >= self.m:
            return Action.D
        if total_prev_c == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_120(BaseStrategy):
    """
    Implements a Conditional Threshold Cooperation strategy.
    
    Phases:
    1. Threshold Testing: Defect in round 1, test viability in round 2.
    2. Adaptive Cooperation: Cooperate if observed cooperation history meets a threshold, 
       otherwise defect. Uses a safety buffer strategy to free-ride if the threshold
       is already met by others.
    3. Terminal Phase: Cooperate if the contribution will tip the scale to meet m in the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.n = self.desc.n_players
        self.m = self.desc.m
        self.r = self.desc.n_rounds
        self.target_ratio = self.m / self.n

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round > 0:
            last_my_action = history.my_actions[-1]
            total_cooperators_last_round = history.opponent_cooperators[-1] + (1 if last_my_action else 0)
            if total_cooperators_last_round >= self.m:
                return Action.D
        if current_round == 0:
            return Action.D
        if current_round == 1:
            prev_cooperators = history.opponent_cooperators[0]
            if prev_cooperators >= self.m - 1:
                return Action.C
            return Action.D
        if current_round == self.r - 1:
            total_c_history = np.sum(history.opponent_cooperators) + np.sum(history.my_actions)
            if (total_c_history + self.n - 1) / ((current_round + 1) * self.n) >= self.target_ratio:
                return Action.C
            return Action.D
        total_c_history = np.sum(history.opponent_cooperators) + np.sum(history.my_actions)
        observed_ratio = total_c_history / (current_round * self.n)
        if observed_ratio >= self.target_ratio * 0.8:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_121(BaseStrategy):
    """
    A conditional strategy for the Collective Risk Dilemma.
    Implements a threshold-based cooperation logic with adaptive memory and
    terminal-phase exploitation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.window_size = max(1, self.game_description.n_rounds // 4)
        self.is_permanently_defecting = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number >= self.window_size:
            recent_coop = history.opponent_cooperators[-self.window_size:]
            avg_coop = np.mean(recent_coop)
            if avg_coop < self.game_description.m - 1:
                self.is_permanently_defecting = True
            elif avg_coop >= self.game_description.m - 1:
                self.is_permanently_defecting = False
        if self.is_permanently_defecting:
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            success_count = np.sum(history.opponent_cooperators >= self.game_description.m)
            prob_success = success_count / history.round_number if history.round_number > 0 else 0
            if prob_success > 0.5:
                return Action.D
            else:
                pass
        my_prev_action = int(history.my_actions[-1])
        c_prev = history.opponent_cooperators[-1] + my_prev_action
        if c_prev >= self.game_description.m:
            return Action.C
        elif c_prev == self.game_description.m - 1:
            p = c_prev / self.game_description.m
            return Action.C if random.random() < p else Action.D
        else:
            return Action.D

class Strategy_SELFINTERESTED_122(BaseStrategy):
    """
    Threshold-Sensitive Tit-for-Tat with Defection Bias.
    
    This strategy behaves as follows:
    - Round 1: Cooperates if threshold ratio m/n <= 0.5, else defects.
    - Subsequent Rounds (not final):
        - Cooperate (C) if:
            1. (C_{t-1} >= m) AND (previously played D) [Testing group]
            2. (C_{t-1} == m-1) [Pivotal agent]
        - Defect (D) if:
            1. (C_{t-1} >= m) AND (previously played C) [Exploitation]
            2. (C_{t-1} < m-1) [Sunk cost avoidance]
            3. (C_{t-1} > m) [Already exceeding threshold]
    - Final Round: Always defects.
    - Persistent Failure (C_{t-1} < m for two consecutive rounds): Force Defect for remaining.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.persistent_failure = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        if current_round == 0:
            if m / n <= 0.5:
                return Action.C
            return Action.D
        if current_round >= 2:
            last_failed = history.opponent_cooperators[-1] < m
            prev_failed = history.opponent_cooperators[-2] < m
            if last_failed and prev_failed:
                self.persistent_failure = True
        if self.persistent_failure:
            return Action.D
        c_prev = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        total_cooperators = c_prev + (1 if my_prev_action else 0)
        if total_cooperators > m + 1:
            return Action.D
        if c_prev >= m and (not my_prev_action):
            return Action.C
        if c_prev == m - 1:
            return Action.C
        if c_prev >= m and my_prev_action:
            return Action.D
        if c_prev < m - 1:
            return Action.D
        return Action.D

class Strategy_SELFINTERESTED_123(BaseStrategy):
    """
    Adaptive Threshold Trigger (ATT) Strategy:
    Attempts to coordinate with the minimum number of cooperators (m) required to trigger 
    the reward (k), defecting when the threshold is met without personal contribution, 
    or when coordination is impossible.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.prev_cooperator_count = None

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.desc.n_players
        m = self.desc.m
        total_rounds = self.desc.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        opp_c_count = history.opponent_cooperators[-1]
        prev_total_c = opp_c_count + (1 if my_prev_action else 0)
        if self.prev_cooperator_count is not None:
            if self.prev_cooperator_count < m - 1 and prev_total_c >= m:
                self.prev_cooperator_count = prev_total_c
                return Action.D
        self.prev_cooperator_count = prev_total_c
        if current_round == total_rounds - 1:
            if prev_total_c >= m:
                return Action.D
            if prev_total_c == m - 1:
                return Action.C
            return Action.D
        if prev_total_c >= m:
            if prev_total_c == m:
                return Action.C
            else:
                return Action.D
        elif not my_prev_action:
            return Action.C
        elif prev_total_c >= m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_124(BaseStrategy):
    """
    Threshold-Sensitive Tit-for-Tat (TS-TFT).
    
    This strategy adapts dynamically to group behavior in the Collective Risk Dilemma.
    It begins with cooperation to test the group. In subsequent rounds:
    - If the threshold was met, it tries to free-ride (switch to/stay in D).
    - If the threshold was missed, it acts as a pivot if only 1 away from the goal, otherwise it defects.
    - It includes a terminal round adjustment and a 'Defection Trap' detector (3 rounds of failure)
      to switch to permanent defection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0
        self.target = self.game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        r_total = self.game_description.n_rounds
        m = self.target
        last_my_c = int(history.my_actions[-1])
        s_prev = history.opponent_cooperators[-1] + last_my_c
        if s_prev < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 3:
            return Action.D
        if history.round_number == r_total - 1:
            if s_prev + (1 - last_my_c) == m:
                return Action.C
            return Action.D
        if s_prev >= m:
            if last_my_c == 1 and s_prev == m:
                return Action.C
            return Action.D
        else:
            if s_prev == m - 1:
                return Action.C
            return Action.D

class Strategy_SELFINTERESTED_125(BaseStrategy):
    """
    Implements Dynamic Threshold Reciprocity:
    - Round 1: Stochastic cooperation based on threshold ratio m/n.
    - Rounds 2 to r-1: Conditional adaptation:
        - If threshold failed, signal cooperation.
        - If threshold met and self was C: Defect if N=m (test), Cooperate if N>m (buffer).
        - If threshold met and self was D: Continue defecting.
    - Final round: Unconditional Defection.
    - Failure detection: Switch to permanent Defection if cooperation is consistently absent.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.consecutive_failures = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.desc.n_players
        m = self.desc.m
        r = self.desc.n_rounds
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        if current_round == 0:
            p = m / n
            return Action.C if random.random() < p else Action.D
        my_prev_action = history.my_actions[-1]
        others_prev = history.opponent_cooperators[-1]
        n_prev = others_prev + (1 if my_prev_action else 0)
        if n_prev < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 2 or (n_prev == 0 and self.consecutive_failures >= 1):
            return Action.D
        if n_prev < m:
            return Action.C
        if my_prev_action:
            if n_prev == m:
                return Action.D
            else:
                return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_126(BaseStrategy):
    """
    A conditional threshold-trigger strategy for the Collective Risk Dilemma.
    
    Logic Summary:
    - Round 1: Always Cooperate (C) to establish baseline.
    - Subsequent Rounds (t=2 to r):
        - If previous cooperation count == m: Cooperate (C) to maintain stability.
        - If previous cooperation count == m - 1: Cooperate (C) to trigger reward.
        - Otherwise: Defect (D) to minimize loss/maximize gain.
    - Final Round: Same logic as subsequent rounds (C if m-1, else D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        opp_coop_count = history.opponent_cooperators[-1]
        total_cooperators = opp_coop_count + (1 if my_prev_action else 0)
        if total_cooperators == self.m:
            return Action.C
        if total_cooperators == self.m - 1:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_127(BaseStrategy):
    """
    Threshold-Triggered Adaptive Defection:
    - Starts with C.
    - If round > 1, acts based on the previous round's cooperator count (N_c).
    - If N_c >= m: Defect (capture reward + private gain).
    - If N_c == m - 1: Cooperate (contribute to secure reward).
    - If N_c < m - 1: Defect (maximize private gain, reward unreachable).
    - Terminal round (last): Cooperate if N_c >= m - 1, else Defect.
    - Instability: If volatility is detected (switching between N_c < m-1 and N_c >= m), switch to pure Defection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.volatility_detected = False
        self.last_state_type = None

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        last_my_action = 1 if history.my_actions[-1] else 0
        n_c_prev = history.opponent_cooperators[-1] + last_my_action
        current_state = 1 if n_c_prev >= m - 1 else 0
        if self.last_state_type is not None and self.last_state_type != current_state:
            self.volatility_detected = True
        self.last_state_type = current_state
        if self.volatility_detected:
            return Action.D
        if current_round == r - 1:
            if n_c_prev >= m - 1:
                return Action.C
            return Action.D
        if n_c_prev >= m:
            return Action.D
        elif n_c_prev == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_128(BaseStrategy):
    """
    Threshold-Adaptive Reciprocity (TAR):
    - Round 1: Always Cooperate (C).
    - Rounds 2 to r-1:
        - If previous round cooperator count < m: Cooperate (C) to help meet threshold.
        - If previous round cooperator count == m: Defect (D) to maximize payoff.
        - If previous round cooperator count > m: Defect (D) to maximize payoff.
        - Observation Trigger: If in the last 3 rounds, the threshold was failed in 2+ instances, permanent Defect (D).
        - Edge Case: If history consistently shows < m cooperators, default to Defect (D) to avoid wasting resources.
    - Final Round (r): Always Defect (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.permanent_defect = False

    def __call__(self, history: PlayerHistory) -> Action:
        m = self.game_description.m
        total_rounds = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        if not self.permanent_defect:
            past_my_actions = history.my_actions.astype(int)
            past_total_coops = past_my_actions + history.opponent_cooperators
            last_3_rounds = past_total_coops[-3:]
            failed_rounds = [count for count in last_3_rounds if count < m]
            if len(failed_rounds) >= 2:
                self.permanent_defect = True
        if self.permanent_defect:
            return Action.D
        prev_total_coops = int(history.my_actions[-1]) + int(history.opponent_cooperators[-1])
        if len(past_total_coops) >= 3 and all((c < m for c in past_total_coops[-3:])):
            return Action.D
        if prev_total_coops < m:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_33(BaseStrategy):
    """
    Opportunistic Threshold Tracking (OTT)
    
    A conditional strategy that maximizes individual payoff by oscillating between 
    cooperation to meet collective thresholds and defection to capture the 
    maximum payoff (1+k) when the threshold is secured by others.
    
    Phase 1: Cooperate (Round 1)
    Phase 2: If threshold not met, Cooperate. If threshold met, Defect.
    Phase 3: Defect (Last Round)
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == self.game_description.n_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        i_cooperated_prev = int(history.my_actions[-1])
        c_prev = history.opponent_cooperators[-1] + i_cooperated_prev
        if c_prev < self.game_description.m:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_34(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that employs adaptive cooperation:
    - Round 1: Always Cooperate to test the field.
    - Rounds 2 to r-1: 
        - If previous round threshold was met (C_prev >= m), Defect.
        - If previous round threshold was NOT met (C_prev < m), Cooperate to signal/attempt to reach threshold.
    - Final Round (Round r):
        - If C_prev >= m, Defect.
        - If C_prev == m - 1 (meaning the player's single contribution completes the set), Cooperate.
        - Otherwise, Defect (as cooperation cannot reach the threshold).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        c_prev_total = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        total_cooperators_prev = c_prev_total + (1 if my_prev_action else 0)
        if history.round_number == self.r - 1:
            if total_cooperators_prev >= self.m:
                return Action.D
            if total_cooperators_prev + 1 >= self.m:
                return Action.C
            return Action.D
        if total_cooperators_prev >= self.m:
            return Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_35(BaseStrategy):
    """
    Strategy: Threshold-Responsive Opportunism.
    Plays C in the first round. In subsequent rounds, it dynamically adjusts 
    based on the previous round's cooperation levels, targeting the threshold m.
    It defects in the final round and permanently defects if it detects 
    an unexpected threshold collapse (N_c == 0).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.collapsed = False

    def __call__(self, history: PlayerHistory) -> Action:
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        total_prev_cooperators = prev_cooperators + (1 if my_prev_action else 0)
        if total_prev_cooperators == 0:
            self.collapsed = True
        if self.collapsed:
            return Action.D
        if total_prev_cooperators >= m + 1:
            return Action.D
        elif total_prev_cooperators == m:
            return Action.D
        elif total_prev_cooperators == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_36(BaseStrategy):
    """
    A strategy that exploits the threshold mechanics of the Collective Risk Dilemma.
    - Round 1: Cooperates if threshold ratio is <= 0.5, else defects.
    - Rounds 2 to r-1:
        - Free-Rider: Defects if the threshold was met in the previous round.
        - Threshold Trigger: Cooperates if the threshold was missed by exactly one person.
        - Hopeless: Defects if the threshold was missed significantly and the game is ending.
        - Recalibrate: Cooperates with probability proportional to the cooperation deficit.
    - Final Round: Always defects.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = self.game_description.n_players
        self.m = self.game_description.m
        self.r = self.game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number + 1
        if current_round == self.r:
            return Action.D
        if current_round == 1:
            return Action.C if self.m / self.n <= 0.5 else Action.D
        my_previous_action = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + my_previous_action
        if total_cooperators_prev >= self.m:
            return Action.D
        if total_cooperators_prev == self.m - 1:
            return Action.C
        if total_cooperators_prev < self.m - 1 and current_round > self.r - 2:
            return Action.D
        deficit = self.m - total_cooperators_prev
        threshold_prob = deficit / self.n
        threshold_prob = max(0.0, min(1.0, threshold_prob))
        if random.random() < threshold_prob:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_37(BaseStrategy):
    """
    A threshold-sensitive strategy that signals cooperation in the first round,
    then pivotally contributes only when the threshold is within reach (m-1),
    and exploits cooperation when the threshold is secure (>= m).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.is_viable = self.game_description.k > 1 and self.game_description.m > 1

    def __call__(self, history: PlayerHistory) -> Action:
        if not self.is_viable:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if np.all(history.opponent_cooperators == 0):
            return Action.D
        s_prev = history.opponent_cooperators[-1]
        m = self.game_description.m
        if s_prev >= m:
            return Action.D
        if s_prev == m - 1:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_38(BaseStrategy):
    """
    Implements the Adaptive Threshold Anchoring strategy for the Collective Risk Dilemma.
    Uses adaptive logic to balance contribution against threshold requirements, 
    exploits surplus cooperation, and accounts for group failure signals.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description
        self.n = self.game.n_players
        self.r = self.game.n_rounds
        self.m = self.game.m
        self.k = self.game.k
        self.trust_score = 0
        self.consecutive_failed_rounds = 0
        self.testing_mode = False
        self.testing_round_count = 0

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        my_prev_action = 1 if history.my_actions[-1] else 0
        c_prev = history.opponent_cooperators[-1] + my_prev_action
        if c_prev < self.m:
            self.consecutive_failed_rounds += 1
            self.trust_score -= 1
        else:
            self.consecutive_failed_rounds = 0
        if self.consecutive_failed_rounds > self.r / 3:
            return Action.D
        if current_round > 1:
            prev_prev_action = 1 if history.my_actions[-2] else 0
            c_prev_prev = history.opponent_cooperators[-2] + prev_prev_action
            if c_prev_prev - c_prev > 2:
                return Action.D
        if current_round == self.r - 1:
            recent_success = False
            for i in range(1, min(4, current_round + 1)):
                if history.opponent_cooperators[-i] + (1 if history.my_actions[-i] else 0) >= self.m:
                    recent_success = True
                    break
            if c_prev >= self.m:
                return Action.D
            elif c_prev < self.m and recent_success:
                return Action.C
            else:
                return Action.D
        threshold_n = math.floor(self.n / 2)
        if self.trust_score > threshold_n and (not self.testing_mode):
            if current_round >= 3:
                condition_met = True
                for i in range(1, 4):
                    if history.opponent_cooperators[-i] + (1 if history.my_actions[-i] else 0) <= self.m:
                        condition_met = False
                if condition_met:
                    self.testing_mode = True
                    self.testing_round_count = 0
        if self.testing_mode:
            self.testing_round_count += 1
            if self.testing_round_count == 1:
                return Action.D
            if c_prev < self.m:
                self.testing_mode = False
                return Action.C
            return Action.D
        if c_prev >= self.m + 1:
            return Action.D
        if c_prev == self.m:
            return Action.C
        if c_prev < self.m:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_39(BaseStrategy):
    """
    A 'Wait-and-See' conditional strategy for the Collective Risk Dilemma.
    1. First round: Always Defects to minimize endowment loss.
    2. Subsequent rounds:
        - If threshold met last round, Defect.
        - If goal mathematically impossible, Defect.
        - Opportunistic: If threshold reachable only if I contribute (N=1), Cooperate. Otherwise, Defect.
    3. Last round:
        - If current progress is exactly m-1, 'Last-ditch' Cooperate to secure payoff.
        - Otherwise Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.D
        my_last_action = history.my_actions[-1]
        last_c_count = history.opponent_cooperators[-1] + (1 if my_last_action else 0)
        all_my_actions = history.my_actions
        all_opp_counts = history.opponent_cooperators
        successful_rounds_count = 0
        for i in range(t):
            total_c_in_round = all_opp_counts[i] + (1 if all_my_actions[i] else 0)
            if total_c_in_round >= self.m:
                successful_rounds_count += 1
        if t == self.r - 1:
            if successful_rounds_count >= self.m:
                return Action.D
            if last_c_count == self.m - 1:
                return Action.C
            return Action.D
        if last_c_count >= self.m:
            return Action.D
        if successful_rounds_count + (self.r - t) < self.m:
            return Action.D
        if last_c_count + (self.r - t) >= self.m:
            need_index = self.m - last_c_count
            if need_index == 1:
                return Action.C
            return Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_40(BaseStrategy):
    """
    Implements a Conditional Threshold Anchoring strategy for the Collective Risk Dilemma.
    
    Logic Summary:
    - Round 1: Cooperate (C) to establish baseline.
    - Rounds 2 to r-1: 
        - If previous cooperators >= m: Defect (D) (free-riding).
        - If previous cooperators == m - 1: Cooperate (C) (critical contribution).
        - If previous cooperators < m - 1: Defect (D) (contribution futile).
    - Round r: Defect (D) unconditionally to maximize final payoff.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == self.total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        last_action_bool = history.my_actions[-1]
        last_opp_coop = history.opponent_cooperators[-1]
        c_prev = last_opp_coop + (1 if last_action_bool else 0)
        if c_prev >= self.m:
            return Action.D
        elif c_prev == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_41(BaseStrategy):
    """
    Implements a threshold-enforcement strategy for the Collective Risk Dilemma.
    
    Strategy:
    - Phase 1: Always Cooperate in the first round.
    - Phase 2: In intermediate rounds, monitor the previous round's cooperation count (N_prev).
        - If N_prev >= m, Defect.
        - If N_prev < m:
            - If exactly m - 1 people cooperated (deficit of 1), Cooperate to reach the threshold.
            - If deficit > 1, Defect (conserve endowment).
    - Phase 3: Always Defect in the final round as there is no future incentive.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.r - 1:
            return Action.D
        prev_opponents = history.opponent_cooperators[-1]
        i_cooperated = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = prev_opponents + i_cooperated
        if total_cooperators_prev >= self.m:
            return Action.D
        deficit = self.m - total_cooperators_prev
        if deficit == 1:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_42(BaseStrategy):
    """
    A Tit-for-Tat based strategy with opportunistic bias.
    - Round 1: Defect (D).
    - Rounds 2 to r-1: 
        - If previous threshold met (C_total >= m), repeat previous action.
        - If previous threshold missed (C_total < m):
            - If I was D and (C_total == m-1), switch to C.
            - Otherwise, switch to D.
    - Final Round: Defect (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == 0:
            return Action.D
        if current_round == total_rounds - 1:
            return Action.D
        my_prev_action_bool = history.my_actions[-1]
        my_prev_action_is_c = 1 if my_prev_action_bool else 0
        c_prev = history.opponent_cooperators[-1] + my_prev_action_is_c
        if c_prev >= m:
            return Action.C if my_prev_action_bool else Action.D
        else:
            if not my_prev_action_bool and c_prev == m - 1:
                return Action.C
            return Action.D

class Strategy_OPPORTUNISTIC_43(BaseStrategy):
    """
    A conditional cooperator strategy for the Collective Risk Dilemma.
    
    Strategy logic:
    - Round 0: Cooperate with probability m/n.
    - Last round: Always Defect.
    - If threshold was met previously: Defect (test for free-riding).
    - If threshold was not met:
        - If decisive (cooperators == m-1), Cooperate.
        - Otherwise, Defect.
    - State tracking: After observing failures to meet the threshold for 
      w = ceil(total_rounds / 4) rounds, switch to Permanent Defector.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.w = math.ceil(self.r / 4)
        self.failed_attempts = 0
        self.my_last_action = Action.D

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == self.r - 1:
            return Action.D
        if current_round == 0:
            prob = self.m / self.n
            action = Action.C if random.random() < prob else Action.D
            self.my_last_action = action
            return action
        my_prev_coop = 1 if history.my_actions[-1] else 0
        total_cooperators_last = history.opponent_cooperators[-1] + my_prev_coop
        threshold_met_last = total_cooperators_last >= self.m
        if not threshold_met_last:
            self.failed_attempts += 1
        if self.failed_attempts > self.w:
            return Action.D
        action = Action.D
        if threshold_met_last:
            action = Action.D
        elif total_cooperators_last == self.m - 1:
            action = Action.C
        else:
            action = Action.D
        self.my_last_action = action
        return action

class Strategy_OPPORTUNISTIC_44(BaseStrategy):
    """
    A strategy that acts as a 'Conditional Threshold-Seeker'. 
    It defaults to defection (D) to save resources but acts as the 'pivotal player' 
    (cooperating to trigger the reward) if the previous round was exactly one 
    cooperator short of the threshold (m-1). It always defects in the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.desc.n_rounds
        m = self.desc.m
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.D
        last_my_action = history.my_actions[-1]
        last_opponents = history.opponent_cooperators[-1]
        total_cooperators_last_round = last_opponents + (1 if last_my_action else 0)
        if total_cooperators_last_round == m - 1:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_45(BaseStrategy):
    """
    Implements a Threshold-Dependent Tit-for-Tat strategy with conditional free-riding.
    It balances collective goals by aiming for threshold m while minimizing 
    personal cost, utilizing history to determine contribution necessity.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            prob_c = self.m / self.n
            return Action.C if random.random() < prob_c else Action.D
        prev_round_idx = current_round - 1
        my_prev_action = history.my_actions[prev_round_idx]
        my_prev_c = 1 if my_prev_action else 0
        c_prev_total = my_prev_c + history.opponent_cooperators[prev_round_idx]
        if current_round == self.r - 1:
            all_prev_coops = np.concatenate([[(1 if a else 0) + o for a, o in zip(history.my_actions, history.opponent_cooperators)]])
            success_count = np.sum(all_prev_coops >= self.m)
            success_rate = success_count / current_round
            if success_rate < 0.5 and c_prev_total == self.m - 1:
                return Action.C
            else:
                return Action.D
        if c_prev_total >= self.m:
            return Action.D
        if c_prev_total == self.m - 1:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_46(BaseStrategy):
    """
    Opportunistic Threshold-Targeting Strategy.
    
    This strategy defaults to defecting (D) to maximize private gains. It monitors the 
    collective cooperation level from the previous round. It only pivots to cooperate (C) 
    if the threshold 'm' is within reach by exactly one additional cooperator (m-1), 
    thereby minimizing individual contribution costs while attempting to secure 
    the reward 'k'. It avoids cooperation in the final round as it yields no future 
    incentive for continued cooperation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.p = 1.0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        our_last_action = history.my_actions[-1]
        prev_opp_coop = history.opponent_cooperators[-1]
        c_prev = prev_opp_coop + (1 if our_last_action else 0)
        if current_round == r - 1:
            return Action.D
        if c_prev >= m:
            return Action.D
        if c_prev < m - 1:
            return Action.D
        if c_prev == m - 1:
            return Action.C if random.random() < self.p else Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_47(BaseStrategy):
    """
    Implements Threshold-Responsive Opportunism in the Collective Risk Dilemma.
    The strategy balances cooperation to meet thresholds with opportunistic defection
    to maximize payoffs, while accounting for last-round conditions, oscillations,
    and population responsiveness.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failed_attempts = 0
        self.permanently_defected = False

    def __call__(self, history: PlayerHistory) -> Action:
        r = self.game_description.n_rounds
        t = history.round_number
        m = self.game_description.m
        if self.permanently_defected:
            return Action.D
        if t == 0:
            return Action.C
        prev_my_action = history.my_actions[-1]
        prev_opp_coop = history.opponent_cooperators[-1]
        c_prev = int(prev_my_action)
        c_total_prev = prev_opp_coop + c_prev
        if c_total_prev < m:
            self.consecutive_failed_attempts += 1
            if self.consecutive_failed_attempts >= 3:
                self.permanently_defected = True
                return Action.D
        else:
            self.consecutive_failed_attempts = 0
        if t == r - 1:
            if c_total_prev >= m:
                return Action.D
            elif c_total_prev == m - 1:
                return Action.C
            else:
                return Action.D
        if c_total_prev >= m:
            if prev_my_action == Action.C:
                return Action.D
            else:
                return Action.D
        elif prev_my_action == Action.D:
            return Action.C
        elif c_total_prev == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_48(BaseStrategy):
    """
    Implements a threshold-seeking conditional strategy. 
    In Round 1, it contributes with probability m/n. 
    In subsequent rounds, it free-rides if the threshold was met, 
    attempts to trigger the threshold if only one more cooperator is needed,
    and defects otherwise. In the terminal round, it evaluates accumulated payoff 
    to decide if the final contribution is worth the cost.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        m = self.game.m
        n = self.game.n_players
        r = self.game.n_rounds
        round_idx = history.round_number
        if round_idx == 0:
            return Action.C if random.random() < m / n else Action.D
        prev_my_action = 1 if history.my_actions[-1] else 0
        c_prev_opponents = history.opponent_cooperators[-1]
        c_prev_total = c_prev_opponents + prev_my_action
        if round_idx == r - 1:
            total_payoff = np.sum(history.my_payoffs)
            if total_payoff < r:
                return Action.D
            else:
                gap = m - c_prev_total
                return Action.C if gap == 1 else Action.D
        if c_prev_total >= m:
            return Action.D
        gap = m - c_prev_total
        if gap == 1:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_49(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that transitions through initialization,
    calibration/assessment, and endgame phases. It focuses on being the marginal
    contributor when necessary, testing for free-riders, and protecting against
    consistent exploitation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.last_round_i_contributed = False
        self.has_locked_to_defect = False

    def __call__(self, history: PlayerHistory) -> Action:
        if self.has_locked_to_defect:
            return Action.D
        round_num = history.round_number
        n = self.game_description.n_players
        m = self.game_description.m
        total_rounds = self.game_description.n_rounds
        if round_num == 0:
            self.last_round_i_contributed = True
            return Action.C
        opp_c = history.opponent_cooperators[-1]
        c_prev = opp_c + (1 if self.last_round_i_contributed else 0)
        if round_num >= 3:
            total_coop_history = history.opponent_cooperators + history.my_actions.astype(int)
            if np.all(total_coop_history < m):
                self.has_locked_to_defect = True
                return Action.D
        if round_num == total_rounds - 1:
            avg_coop = np.mean(history.opponent_cooperators + history.my_actions.astype(int))
            self.last_round_i_contributed = False
            return Action.D
        if self.last_round_i_contributed and c_prev == m:
            if opp_c < m:
                self.last_round_i_contributed = True
                return Action.C
            else:
                self.last_round_i_contributed = False
                return Action.D
        if c_prev >= m + 1:
            self.last_round_i_contributed = False
            return Action.D
        elif c_prev == m:
            self.last_round_i_contributed = False
            return Action.D
        elif c_prev == m - 1:
            self.last_round_i_contributed = True
            return Action.C
        else:
            self.last_round_i_contributed = False
            return Action.D

class Strategy_OPPORTUNISTIC_50(BaseStrategy):
    """
    A Conditional Trigger strategy for the Collective Risk Dilemma.
    
    Logic:
    - Phase 1: Always Cooperate in the first round.
    - Phase 2: If the group is at or over the threshold (m), Defect to free-ride. 
               If the group fails to meet the threshold, Cooperate.
    - End Game: Always Defect in the final round (t=r).
    - Edge Cases: If the group fails to meet the threshold for 3 consecutive rounds
      despite self-cooperation, switch to permanent Defection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.total_rounds = game_description.n_rounds
        self.fail_streak = 0
        self.perma_defect = False

    def __call__(self, history: PlayerHistory) -> Action:
        if self.perma_defect:
            return Action.D
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.total_rounds - 1:
            return Action.D
        prev_my_action = 1 if history.my_actions[-1] else 0
        s_prev = history.opponent_cooperators[-1] + prev_my_action
        if s_prev < self.m:
            self.fail_streak += 1
        else:
            self.fail_streak = 0
        if self.fail_streak >= 3:
            self.perma_defect = True
            return Action.D
        if s_prev >= self.m:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_51(BaseStrategy):
    """
    Implements a Conditional Trigger with Defection Bias strategy.
    
    Logic Summary:
    1. Always defect in round 1.
    2. Always defect in the final round (round r).
    3. In intermediate rounds, analyze the previous round's outcome:
       - If opponents alone reached the threshold (M_prev >= m), defect to save endowment.
       - If opponents were exactly one short of the threshold (M_prev == m - 1), 
         cooperate to trigger the reward k.
       - Otherwise, defect, as cooperating is insufficient to trigger the reward.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.r - 1:
            return Action.D
        if history.round_number == 0:
            return Action.D
        prev_round_idx = history.round_number - 1
        m_prev = history.opponent_cooperators[prev_round_idx]
        if m_prev >= self.m:
            return Action.D
        elif m_prev == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_52(BaseStrategy):
    """
    Implements a responsive, conditional cooperation strategy for the Collective Risk Dilemma.
    
    Logic:
    - Round 0: Cooperate to signal willingness.
    - Subsequent rounds:
        - If the group has never achieved the threshold m (all history < m), Defect (give up on coordination).
        - If the previous round met or exceeded the threshold m (>= m), Defect (free-ride).
        - If the previous round missed the threshold (< m), Cooperate (rescue/restore).
        - Last round special case: If the history shows persistent failure, Defect (sunk cost).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        i_cooperated = int(history.my_actions[-1])
        total_cooperators_prev = history.opponent_cooperators[-1] + i_cooperated
        past_my_actions = [int(a) for a in history.my_actions]
        past_opponent_coops = [int(c) for c in history.opponent_cooperators]
        full_history_coops = [past_my_actions[t] + past_opponent_coops[t] for t in range(len(past_my_actions))]
        has_ever_succeeded = any((count >= self.m for count in full_history_coops))
        if not has_ever_succeeded:
            return Action.D
        if history.round_number == self.n_rounds - 1:
            if total_cooperators_prev < self.m:
                return Action.D
        if total_cooperators_prev >= self.m:
            return Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_53(BaseStrategy):
    """
    A strategy that defaults to Defection in the first and final rounds.
    In intermediate rounds, it mimics a 'Threshold Tit-for-Tat':
    If the threshold 'm' was met in the previous round, it cooperates to
    capture the reward 'k'. If the threshold was missed, it defects.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == self.game_description.n_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.D
        prev_my_action = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + prev_my_action
        if total_cooperators_prev >= self.game_description.m:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_54(BaseStrategy):
    """
    A conditional free-riding strategy that oscillates between cooperation to
    secure the collective threshold and defection to maximize personal gains.
    It tracks persistent failure to cooperate and defaults to permanent
    defection in the terminal round or if the collective proves unresponsive.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0
        self.given_up = False

    def __call__(self, history: PlayerHistory) -> Action:
        if self.given_up:
            return Action.D
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == 0:
            return Action.C
        if current_round == total_rounds - 1:
            return Action.D
        last_my_action = history.my_actions[-1]
        last_opponent_coops = history.opponent_cooperators[-1]
        total_cooperators = last_opponent_coops + (1 if last_my_action else 0)
        if total_cooperators < m:
            if last_my_action == Action.C:
                self.consecutive_failures += 1
            else:
                self.consecutive_failures = 0
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 2:
            self.given_up = True
            return Action.D
        if total_cooperators < m:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_55(BaseStrategy):
    """
    Strategy: Threshold-Conditional Reciprocal Cooperation
    
    This strategy attempts to achieve the threshold 'm' for cooperation while
    minimizing personal costs through free-riding whenever possible. It adapts
    dynamically based on observed collective behavior, pivoting to support
    the threshold only when necessary or when it can guarantee the reward.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_coop_failures = 0
        self.last_action_was_c = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            self.last_action_was_c = True
            return Action.C
        n = self.game_description.n_players
        m = self.game_description.m
        c_total_prev = history.opponent_cooperators[-1] + (1 if self.last_action_was_c else 0)
        if self.last_action_was_c and c_total_prev < m:
            self.consecutive_coop_failures += 1
        else:
            self.consecutive_coop_failures = 0
        if self.consecutive_coop_failures >= 2:
            self.last_action_was_c = False
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            if c_total_prev >= m:
                self.last_action_was_c = False
                return Action.D
            elif c_total_prev + 1 >= m:
                self.last_action_was_c = True
                return Action.C
            else:
                self.last_action_was_c = False
                return Action.D
        if c_total_prev > m:
            self.last_action_was_c = False
            return Action.D
        if c_total_prev >= m:
            self.last_action_was_c = False
            return Action.D
        elif c_total_prev + 1 >= m:
            self.last_action_was_c = True
            return Action.C
        else:
            self.last_action_was_c = False
            return Action.D

class Strategy_OPPORTUNISTIC_56(BaseStrategy):
    """
    A conditional Tit-for-Tat strategy for the Collective Risk Dilemma.
    Transitions through phases: Observation, Adaptive Maintenance, and Terminal Exploitation.
    Implements a 'critical correction' mechanism and a fail-safe against chronic non-cooperation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0
        self.is_terminal_exhausted = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if not self.is_terminal_exhausted:
            lookback = min(3, history.round_number)
            recent_opponent_coop = history.opponent_cooperators[-lookback:]
            my_actions_int = history.my_actions.astype(int)
            total_cooperators = history.opponent_cooperators + my_actions_int
            recent_totals = total_cooperators[-lookback:]
            failures = [1 for x in recent_totals if x < self.game_description.m - 1]
            if len(failures) == 3:
                self.is_terminal_exhausted = True
        if self.is_terminal_exhausted:
            return Action.D
        prev_my_action = int(history.my_actions[-1])
        prev_opp_coop = history.opponent_cooperators[-1]
        c_prev = prev_opp_coop + prev_my_action
        m = self.game_description.m
        if c_prev >= m:
            return Action.C
        if c_prev == m - 1 and prev_my_action == 0:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_57(BaseStrategy):
    """
    Adaptive threshold-seeking strategy.
    
    Logic:
    - Round 1: Test group commitment based on (m / n) ratio.
    - Intermediate Rounds:
        - If avg_cooperators >= m, use probability p = min(1, (avg_cooperators / n) * k) to cooperate,
          while actively employing "freeloader" logic (defect if previous contribution wasn't strictly necessary).
        - If avg_cooperators < m, only contribute if the group is close (threshold - 1), otherwise defect.
    - Final Round: Defect unconditionally.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        k = self.game_description.k
        last_round_idx = self.game_description.n_rounds - 1
        current_round = history.round_number
        if current_round == last_round_idx:
            return Action.D
        if current_round == 0:
            return Action.C if m / n < 0.7 else Action.D
        my_prev_action = history.my_actions[-1]
        c_i_prev = 1 if my_prev_action else 0
        opp_c_prev = history.opponent_cooperators[-1]
        total_c_prev = opp_c_prev + c_i_prev
        total_cooperators_history = history.opponent_cooperators + history.my_actions.astype(int)
        avg_c = np.mean(total_cooperators_history)
        if avg_c >= m:
            if my_prev_action == Action.C and opp_c_prev >= m:
                return Action.D
            p = min(1.0, avg_c / n * k)
            return Action.C if random.random() < p else Action.D
        elif opp_c_prev >= m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_58(BaseStrategy):
    """
    A strategy that transitions through phases: Initialization (C), Monitoring (Dynamic response to 
    cooperator counts, including threshold testing and failure recovery), and Terminal (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0
        self.recovery_mode_counter = 0
        self.permanently_defected = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        if self.permanently_defected:
            return Action.D
        prev_round_idx = current_round - 1
        c_prev = history.opponent_cooperators[prev_round_idx]
        my_prev_action = history.my_actions[prev_round_idx]
        total_cooperators = c_prev + (1 if my_prev_action else 0)
        if total_cooperators < m:
            self.consecutive_failures += 1
            self.recovery_mode_counter += 1
        else:
            self.consecutive_failures = 0
            self.recovery_mode_counter = 0
        if self.consecutive_failures >= 3:
            self.permanently_defected = True
            return Action.D
        if self.recovery_mode_counter == 2:
            self.recovery_mode_counter = 0
            return Action.D
        if total_cooperators >= m + 1:
            return Action.D
        elif total_cooperators == m:
            return Action.C
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_59(BaseStrategy):
    """
    An adaptive collective risk strategy:
    - Round 1: Probabilistic cooperation based on threshold ratio m/n.
    - Intermediate rounds: Tit-for-tat-like adaptation based on whether the previous threshold was met.
      Free-riding when successful, targeted cooperation when close to success.
    - Final round: Cost-benefit analysis based on whether the threshold is within reach.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if self.m / self.n > 1 or self.k <= 1:
            return Action.D
        round_idx = history.round_number
        if round_idx == 0:
            prob_c = self.m / self.n
            return Action.C if random.random() < prob_c else Action.D
        my_last_action = Action.C if history.my_actions[-1] else Action.D
        s_opponents = history.opponent_cooperators[-1]
        s_total = s_opponents + (1 if my_last_action == Action.C else 0)
        if round_idx == self.r - 1:
            if s_total >= self.m - 1:
                return Action.C
            else:
                return Action.D
        if s_total >= self.m:
            return Action.D
        elif my_last_action == Action.C:
            if s_total == self.m - 1:
                return Action.C
            else:
                return Action.D
        else:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_60(BaseStrategy):
    """
    Implements the Threshold-Driven Reciprocator strategy for the Collective Risk Dilemma.
    
    This strategy focuses on maximizing payoff by balancing the cost of contribution with the 
    collective reward (k). It tests the group in the first round by cooperating, then adjusts 
    based on the observed cooperation levels of opponents to maintain the minimum threshold (m) 
    only when necessary.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        my_last_action = 1 if history.my_actions[-1] else 0
        s_prev = history.opponent_cooperators[-1] + my_last_action
        m_threshold = self.game_description.m
        if s_prev >= m_threshold:
            return Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_61(BaseStrategy):
    """
    Adaptive Opportunism strategy for the Collective Risk Dilemma.
    
    Strategy:
    - Round 0: Cooperate (C) to establish baseline.
    - Subsequent Rounds:
        - If previous round cooperators (c_{t-1}) >= m: Defect (D) to free-ride.
        - If previous round cooperators (c_{t-1}) == m - 1: Cooperate (C) to meet threshold.
        - If previous round cooperators (c_{t-1}) < m - 1: Defect (D) as individual contribution is ineffective.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_c = history.opponent_cooperators[-1]
        if prev_c >= self.game_description.m:
            return Action.D
        elif prev_c == self.game_description.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_62(BaseStrategy):
    """
    Adaptive strategy for the Collective Risk Dilemma.
    Maintains internal state (Testing, Cooperative, Defective) and adjusts behavior
    based on the observed frequency of cooperation from opponents relative to the threshold m.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.state = 'Testing'
        self.consecutive_successes = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        last_round_my_action = 1 if history.my_actions[-1] else 0
        last_C = history.opponent_cooperators[-1] + last_round_my_action
        m = self.game_description.m
        if last_C < m:
            self.state = 'Defective'
            self.consecutive_successes = 0
        elif self.state == 'Defective':
            self.state = 'Testing'
            self.consecutive_successes = 1
        elif self.state == 'Testing':
            self.consecutive_successes += 1
            if self.consecutive_successes >= 2:
                self.state = 'Cooperative'
        if self.state == 'Defective':
            return Action.D
        elif self.state == 'Cooperative':
            if last_C <= m:
                self.state = 'Testing'
                self.consecutive_successes = 0
                return Action.C
            p_defect = (last_C - m) / last_C
            if random.random() < p_defect:
                return Action.D
            else:
                return Action.C
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_63(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that employs a conditional
    trigger mechanism based on observed cooperation counts.
    
    Logic:
    - Round 1: Always Defect.
    - Subsequent Rounds:
        - If k <= 1, always Defect (the cost of C is 1, reward k is not worth it).
        - If the previous round's total cooperators (S_{t-1}) >= m, Defect.
        - If S_{t-1} == m-1, Cooperate (to push the group over the threshold).
        - If S_{t-1} < m-1, Defect (insufficient effort from others).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if self.k <= 1.0:
            return Action.D
        if history.round_number == 0:
            return Action.D
        previous_my_action = history.my_actions[-1]
        previous_opp_count = history.opponent_cooperators[-1]
        total_cooperators_prev = previous_opp_count + (1 if previous_my_action else 0)
        if total_cooperators_prev >= self.m:
            return Action.D
        if total_cooperators_prev == self.m - 1:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_64(BaseStrategy):
    """
    Threshold-Sensitive Tit-for-Tat with Defection Bias.
    
    This strategy monitors the previous round's cooperation count (C_prev).
    - Round 1: Always cooperates.
    - Final Round: Always defects.
    - Intermediate Rounds: 
        - If previous cooperation met or exceeded threshold (m), it defects to exploit the group payoff.
        - Otherwise, it cooperates to help the group reach the threshold.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        prev_my_action = history.my_actions[-1]
        prev_opponents_c = history.opponent_cooperators[-1]
        total_c_prev = prev_opponents_c + (1 if prev_my_action else 0)
        if total_c_prev >= self.game_description.m:
            return Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_65(BaseStrategy):
    """
    Implements a "Conditional Trigger with Threshold Anticipation" strategy.
    
    Logic:
    - Round 0: Always Defect (Baseline measurement).
    - If 'cynical_mode' is active: Defect.
    - If threshold met in previous round: Defect.
    - If threshold met with one missing contributor: Cooperate.
    - Otherwise: Defect (Sunk cost avoidance).
    
    Cynical mode is triggered if the group fails to reach m-1 cooperators for 2 consecutive rounds.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.cynical_mode = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        if self.cynical_mode:
            return Action.D
        m = self.game_description.m
        prev_cooperators = history.opponent_cooperators[-1]
        if history.round_number >= 2:
            prev_1 = history.opponent_cooperators[-1]
            prev_2 = history.opponent_cooperators[-2]
            if prev_1 < m - 1 and prev_2 < m - 1:
                self.cynical_mode = True
                return Action.D
        if prev_cooperators >= m:
            return Action.D
        elif prev_cooperators == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_66(BaseStrategy):
    """
    Implements a Conditional Threshold Trigger (CTT) strategy:
    - Round 1: Cooperate (C) to establish baseline.
    - Rounds 2 to r-1:
        - If previous cooperators < m - 1: Defect (D) to minimize loss.
        - If previous cooperators >= m: Defect (D) to free-ride.
        - If previous cooperators == m - 1: Cooperate (C) to pivot threshold success.
    - Last Round (r): Always Defect (D) as there is no future incentive.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_zero_indexed = history.round_number
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round_zero_indexed == total_rounds - 1:
            return Action.D
        if current_round_zero_indexed == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        total_prev_cooperators = prev_cooperators + (1 if my_prev_action else 0)
        if total_prev_cooperators >= m:
            return Action.D
        elif total_prev_cooperators == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_67(BaseStrategy):
    """
    Implements the Threshold-Sensitive Tit-for-Tat (TS-TFT) strategy.
    
    This strategy prioritizes free-riding (Defecting) unless the player is 
    pivotal to reaching the cooperation threshold 'm'. Specifically:
    - Round 1: Defect (D) to observe baseline behavior.
    - Subsequent Rounds:
        - If previous round cooperators < m - 1: Defect (D) (threshold unreachable/too low).
        - If previous round cooperators == m - 1: Cooperate (C) (pivotal for reward).
        - If previous round cooperators >= m: Defect (D) (free-ride).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        last_o = history.opponent_cooperators[-1]
        m = self.game_description.m
        if last_o == m - 1:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_68(BaseStrategy):
    """
    Threshold-Sensitive Tit-for-Tat (TSTFT):
    A strategy that maintains a threshold buffer to encourage group cooperation 
    while opportunistically defecting in the final round and during marginal 
    cooperation states.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number + 1
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == total_rounds:
            return Action.D
        if current_round == 1:
            return Action.C
        my_prev_action = 1 if history.my_actions[-1] else 0
        total_prev_cooperators = history.opponent_cooperators[-1] + my_prev_action
        if total_prev_cooperators >= m:
            if total_prev_cooperators == m:
                return Action.D if random.random() < 0.5 else Action.C
            return Action.C
        else:
            if total_prev_cooperators == m - 1:
                return Action.C
            return Action.D

class Strategy_OPPORTUNISTIC_69(BaseStrategy):
    """
    A Threshold-Targeting strategy for the Collective Risk Dilemma.
    Prioritizes free-riding by defecting when the threshold is met,
    conditionally signaling cooperation when the deficit is small,
    and attempting a periodic trigger if the group consistently fails.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description
        self.failure_counter = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.game.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.D
        prev_my_action = int(history.my_actions[-1])
        prev_opponent_coops = history.opponent_cooperators[-1]
        c_prev = prev_opponent_coops + prev_my_action
        if c_prev < self.game.m:
            self.failure_counter += 1
        else:
            self.failure_counter = 0
        if self.failure_counter >= 3:
            self.failure_counter = 0
            return Action.C
        if c_prev >= self.game.m:
            return Action.D
        else:
            deficit = self.game.m - c_prev
            if deficit == 1:
                if random.random() < 0.5:
                    return Action.C
                return Action.D
            else:
                return Action.D

class Strategy_OPPORTUNISTIC_70(BaseStrategy):
    """
    Conditional Threshold-Maintenance (CTM): A tit-for-tat style mechanism enforcing 
    collective cooperation. It maintains exactly m cooperators to avoid the 
    sucker's payoff while ensuring reward k. Includes a failure-reversion 
    mechanism to cut losses if the group fails to cooperate.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.giving_up = False
        self.consecutive_failures = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if self.game_description.k <= 1.0:
            return Action.D
        if self.game_description.m == 1:
            if history.round_number == 0:
                return Action.C
            return Action.D
        if self.giving_up:
            return Action.D
        if history.round_number == 0:
            if self.game_description.n_players == self.game_description.m:
                return Action.C
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        prev_opp_coop = history.opponent_cooperators[-1]
        prev_my_action = history.my_actions[-1]
        total_coop_prev = prev_opp_coop + (1 if prev_my_action else 0)
        threshold_met_prev = total_coop_prev >= self.game_description.m
        if not threshold_met_prev:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 2:
            self.giving_up = True
            return Action.D
        if not threshold_met_prev:
            return Action.C
        else:
            surplus = total_coop_prev - self.game_description.m
            if prev_my_action:
                if surplus > 0:
                    return Action.D
                else:
                    return Action.C
            else:
                return Action.C

class Strategy_OPPORTUNISTIC_71(BaseStrategy):
    """
    A conditional cooperator strategy for the Collective Risk Dilemma.
    It tracks a 'trust score' based on the success of previous rounds
    relative to the threshold `m` and adapts contribution levels accordingly.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.trust_score = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        prev_coop_count = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        total_prev_cooperators = prev_coop_count + (1 if my_prev_action else 0)
        m = self.game_description.m
        if total_prev_cooperators >= m:
            self.trust_score += 1
        else:
            self.trust_score -= 1
        if total_prev_cooperators >= m + 1:
            self.trust_score -= 1
            return Action.D
        if total_prev_cooperators == m:
            if self.trust_score > 0:
                return Action.D
            else:
                return Action.C
        if total_prev_cooperators < m:
            if self.trust_score < -1:
                return Action.D
            else:
                return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_72(BaseStrategy):
    """
    Implements a Conditional Tit-for-Tat with Threshold Sensitivity.
    
    Logic:
    1. Initial Phase: Always Cooperate (C) in the first round to signal intent.
    2. Maintenance Phase (Rounds 2 to r-1):
       - If previous cooperators > m: Defect (D) to maximize profit.
       - If previous cooperators == m: Cooperate (C) to maintain threshold.
       - If previous cooperators < m: Cooperate (C) to push toward threshold.
    3. Terminal Phase: Always Defect (D) as there is no future incentive.
    4. Edge Cases: If threshold is impossible (n-1 < m) or reward k <= 1, always Defect (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.always_defect = self.game_description.n_players - 1 < self.game_description.m or self.game_description.k <= 1.0

    def __call__(self, history: PlayerHistory) -> Action:
        if self.always_defect:
            return Action.D
        round_idx = history.round_number
        n_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if round_idx == n_rounds - 1:
            return Action.D
        if round_idx == 0:
            return Action.C
        prev_my_action = 1 if history.my_actions[-1] else 0
        prev_opp_coop = int(history.opponent_cooperators[-1])
        total_cooperators_prev = prev_opp_coop + prev_my_action
        if total_cooperators_prev > m:
            return Action.D
        elif total_cooperators_prev == m:
            return Action.C
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_73(BaseStrategy):
    """
    A threshold-seeking tit-for-tat strategy. Prioritizes free-riding (D) when the threshold is met,
    cooperates (C) only when acting as the decisive marginal voter to reach the threshold,
    and abandons hopeless group efforts by reverting to defection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.previously_cooperated = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            if m / n <= 0.5:
                self.previously_cooperated = True
                return Action.C
            else:
                self.previously_cooperated = False
                return Action.D
        is_terminal = current_round == r - 1
        my_prev_action = history.my_actions[-1]
        my_prev_coop = 1 if my_prev_action == Action.C else 0
        c_prev = history.opponent_cooperators[-1] + my_prev_coop
        if is_terminal:
            if c_prev >= m:
                return Action.D
            elif m - c_prev == 1:
                return Action.C
            else:
                return Action.D
        elif c_prev >= m:
            self.previously_cooperated = False
            return Action.D
        else:
            deficit = m - c_prev
            if deficit == 1:
                self.previously_cooperated = True
                return Action.C
            elif deficit > 1:
                if self.previously_cooperated:
                    self.previously_cooperated = False
                    return Action.D
                else:
                    return Action.D
            return Action.D

class Strategy_OPPORTUNISTIC_74(BaseStrategy):
    """
    Implements an Opportunistic Threshold-Seeking Strategy.
    
    This strategy aims to ensure the cooperative threshold m is met while minimizing 
    personal contribution costs. It operates as follows:
    - Round 1: Cooperate.
    - Final Round (r): Defect.
    - Intermediate Rounds:
        - If last round's cooperators >= m (Surplus): Defect (Free-ride).
        - If last round's cooperators == m - 1 (Pivot): Cooperate (Ensure threshold).
        - If last round's cooperators < m - 1 (Deficit): Defect (Avoid wasted effort).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == 0:
            return Action.C
        if current_round == n_rounds - 1:
            return Action.D
        my_prev_action = 1 if history.my_actions[-1] else 0
        last_total_cooperators = history.opponent_cooperators[-1] + my_prev_action
        if last_total_cooperators >= m:
            return Action.D
        elif last_total_cooperators == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_75(BaseStrategy):
    """
    Implements the Conditional Reciprocal Trigger (CRT) strategy.
    
    This strategy focuses on maximizing payoffs by incentivizing the collective 
    threshold (m) while minimizing exploitation. It uses state-based logic to 
    transition between cooperation (to meet thresholds) and defection (to free-ride 
    or avoid waste). It features a "recovery signal" mechanism to attempt to 
    re-engage cooperation after a period of failure.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.t_c = game_description.m - 1

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        previous_my_action = history.my_actions[-1]
        c_i_prev = 1 if previous_my_action == Action.C else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + c_i_prev
        if total_cooperators_prev >= self.game_description.m:
            if previous_my_action == Action.C:
                return Action.C
            else:
                return Action.D
        else:
            if c_i_prev == 1 and total_cooperators_prev >= self.t_c:
                return Action.C
            if total_cooperators_prev >= self.t_c:
                return Action.C
            return Action.D

class Strategy_OPPORTUNISTIC_76(BaseStrategy):
    """
    Opportunistic Threshold-Targeting Strategy:
    Prioritizes defecting to free-ride, but selectively cooperates when
    the player's contribution is critical to hitting the threshold 'm'.
    Includes a "prodding" mechanism if progress stalls.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0
        self.is_prodding = False
        self.prodding_round = -1

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        m = self.game_description.m
        prev_my_action = history.my_actions[-1]
        c_prev = history.opponent_cooperators[-1] + (1 if prev_my_action else 0)
        if c_prev < m - 1:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
            self.is_prodding = False
        if self.consecutive_failures >= 3 and (not self.is_prodding):
            self.is_prodding = True
            self.prodding_round = history.round_number
            return Action.C
        if self.is_prodding:
            if history.round_number - 1 == self.prodding_round:
                if c_prev < m - 1:
                    self.consecutive_failures = 999
                    return Action.D
            return Action.C
        if c_prev >= m:
            return Action.D
        if c_prev == m - 1:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_77(BaseStrategy):
    """
    Implements a Threshold-Sensitive Tit-for-Tat (TSTFT) strategy.
    
    The strategy cooperates if its contribution is critical or if the group shows 
    cooperative potential. It includes an "Inertia Reset" mechanism to punish 
    consistent defectors and transitions behavior in the final round to avoid
    unnecessary losses.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        last_my_action = history.my_actions[-1]
        last_opp_coop = history.opponent_cooperators[-1]
        s_prev = last_opp_coop + (1 if last_my_action else 0)
        if history.round_number >= 2:
            s_prev_minus_1 = history.opponent_cooperators[-2] + (1 if history.my_actions[-2] else 0)
            if s_prev < self.m and s_prev_minus_1 < self.m:
                return Action.D
        if history.round_number == self.r - 1:
            if s_prev < self.m - 1:
                return Action.D
            else:
                return Action.C
        if s_prev >= self.m:
            return Action.C
        elif s_prev == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_78(BaseStrategy):
    """
    Threshold-Targeting Opportunism strategy.
    
    Operates by attempting to ensure the threshold m is met while minimizing 
    individual contribution. 
    1. First round: Probabilistically cooperates to signal and test group.
    2. Intermediate rounds: Cooperates if the group failed the threshold in the 
       previous round, otherwise defects to free-ride.
    3. Terminal round: Always defects.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            probability = self.game_description.m / self.game_description.n_players
            if random.random() <= probability:
                return Action.C
            return Action.D
        if current_round == self.game_description.n_rounds - 1:
            return Action.D
        last_round_opponents_c = history.opponent_cooperators[-1]
        last_round_my_action = history.my_actions[-1]
        total_cooperators_prev = last_round_opponents_c + (1 if last_round_my_action else 0)
        if total_cooperators_prev < self.game_description.m:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_79(BaseStrategy):
    """
    Implements the Threshold-Sensitive Opportunism (TSO) strategy.
    
    This strategy prioritizes securing the reward `k` by contributing only when the
    player's action is critical (the "swing vote"), while free-riding (defecting) 
    whenever the group can achieve the threshold without the player's help.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        t_index = history.round_number
        t = t_index + 1
        r = self.game_description.n_rounds
        m = self.game_description.m
        if t == 1:
            return Action.C
        n_c_prev = history.opponent_cooperators[-1]
        if t < r:
            if n_c_prev >= m:
                return Action.D
            elif n_c_prev == m - 1:
                return Action.C
            else:
                return Action.D
        if t == r:
            if n_c_prev >= m - 1:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_80(BaseStrategy):
    """
    A strategy that pursues the collective reward (k) by cooperating only when necessary
    to meet the threshold (m), while defecting (free-riding) when the threshold is 
    already secured. It includes a patience mechanism: if cooperation fails to trigger 
    the threshold for three consecutive rounds, it stops cooperating.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failed_cooperation_attempts = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        c_prev_count = history.opponent_cooperators[-1] + (1 if my_prev_action else 0)
        if not my_prev_action and c_prev_count < self.game_description.m:
            pass
        elif my_prev_action and c_prev_count < self.game_description.m:
            self.consecutive_failed_cooperation_attempts += 1
        else:
            self.consecutive_failed_cooperation_attempts = 0
        if self.consecutive_failed_cooperation_attempts >= 3:
            return Action.D
        if c_prev_count >= self.game_description.m:
            return Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_81(BaseStrategy):
    """
    A strategy that starts with cooperation, then adapts based on whether the 
    cooperation threshold (m) was met in the previous round. If the threshold 
    was met, the player exploits the situation by defecting. If not, the player 
    contributes to attempt to hit the threshold. Regardless of state, the 
    player always defects in the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        my_prev_action = 1 if history.my_actions[-1] else 0
        total_prev_cooperators = history.opponent_cooperators[-1] + my_prev_action
        if total_prev_cooperators >= self.game_description.m:
            return Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_82(BaseStrategy):
    """
    Implements a conditional contribution strategy for the Collective Risk Dilemma.
    
    Logic:
    1. First Round: Cooperate if the threshold 'm' is achievable (<= n/2), 
       otherwise defect.
    2. Intermediate Rounds (1 to r-2):
       - If previous threshold was met (C_t-1 >= m): Defect (Free-ride).
       - If previous threshold narrowly missed (C_t-1 == m-1): Cooperate (Nudge).
       - Otherwise: Defect (Cut losses).
    3. Final Round: Always Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n = self.desc.n_players
        m = self.desc.m
        r = self.desc.n_rounds
        if current_round == r - 1:
            return Action.D
        if current_round == 0:
            if m <= n / 2:
                return Action.C
            else:
                return Action.D
        last_round_cooperators = history.opponent_cooperators[-1]
        if history.my_actions[-1]:
            last_round_cooperators += 1
        if last_round_cooperators >= m:
            return Action.D
        elif last_round_cooperators == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_83(BaseStrategy):
    """
    Conditional Threshold-Triggered Opportunism (CTTO):
    Maintains a minimum contribution threshold to secure reward 'k' while minimizing costs.
    1. First round: Cooperate.
    2. Intermediate rounds: Defect if threshold is being met or exceeded; Cooperate if not.
    3. Final round: Always Defect.
    4. Adaptive mechanics: Give up on cooperation if consecutive failures occur.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0
        self.give_up_threshold_reached = False

    def __call__(self, history: PlayerHistory) -> Action:
        if self.game_description.n_rounds < 3:
            return Action.D
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if self.give_up_threshold_reached:
            return Action.D
        my_last_action = int(history.my_actions[-1])
        last_round_cooperators = int(history.opponent_cooperators[-1])
        total_cooperators = last_round_cooperators + my_last_action
        m = self.game_description.m
        if my_last_action == 1 and total_cooperators < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 2:
            self.give_up_threshold_reached = True
            return Action.D
        if current_round == self.game_description.n_rounds - 1:
            return Action.D
        if total_cooperators >= m:
            return Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_84(BaseStrategy):
    """
    Implements a conditional, threshold-sensitive cooperation strategy for the 
    Collective Risk Dilemma. Features adaptive opportunism, phase-based 
    decision making, and stability refinements (Defector Trap escape and 
    Free-Rider ceiling).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failure_while_defecting = 0
        self.consecutive_success_while_cooperating = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            p = self.game_description.m / self.game_description.n_players
            return Action.C if random.random() < p else Action.D
        prev_round = history.round_number - 1
        my_prev_action = history.my_actions[prev_round]
        opp_coop = history.opponent_cooperators[prev_round]
        total_coop = opp_coop + (1 if my_prev_action else 0)
        if not my_prev_action and total_coop < self.game_description.m:
            self.consecutive_failure_while_defecting += 1
        else:
            self.consecutive_failure_while_defecting = 0
        if my_prev_action and total_coop > self.game_description.m:
            self.consecutive_success_while_cooperating += 1
        else:
            self.consecutive_success_while_cooperating = 0
        if self.consecutive_failure_while_defecting >= 2:
            return Action.C
        if self.consecutive_success_while_cooperating >= 2:
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            if total_coop >= self.game_description.m:
                return Action.D
            else:
                return Action.C
        if total_coop >= self.game_description.m:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_85(BaseStrategy):
    """
    Conditional Threshold Tracker strategy.
    
    This strategy employs 'Threshold Elasticity' to maximize individual payoffs:
    - Initially cooperates to signal commitment.
    - Exploits successful groups by defecting when the threshold is met.
    - Pivots (contributes) only when critical to reaching the threshold.
    - Abandons cooperation if the group proves structurally unable to coordinate.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.is_non_cooperative = False
        self.consecutive_failures = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        t = history.round_number
        last_round_idx = -1
        my_prev_action = 1 if history.my_actions[last_round_idx] else 0
        total_cooperators_prev = history.opponent_cooperators[last_round_idx] + my_prev_action
        if total_cooperators_prev < self.m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 3:
            self.is_non_cooperative = True
        if self.is_non_cooperative:
            return Action.D
        if t == self.r - 1:
            if total_cooperators_prev >= self.m:
                return Action.D
            elif total_cooperators_prev >= self.m - 1:
                return Action.C
            else:
                return Action.D
        if total_cooperators_prev >= self.m:
            return Action.D
        if total_cooperators_prev == self.m - 1 and my_prev_action == 0:
            return Action.C
        if total_cooperators_prev == self.m - 1 and my_prev_action == 1:
            return Action.D
        if total_cooperators_prev < self.m - 1:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_86(BaseStrategy):
    """
    Implements a Conditional Threshold-Triggered Maximization strategy.
    
    This strategy attempts to free-ride on cooperative outcomes when the threshold is met,
    contributes when the group is exactly one short of the threshold, and defects 
    when the group fails to reach the threshold or in the terminal round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        threshold_m = self.game_description.m
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        my_prev_action = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = prev_cooperators + my_prev_action
        if total_cooperators_prev >= threshold_m:
            return Action.D
        elif total_cooperators_prev == threshold_m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_87(BaseStrategy):
    """
    Implements Conditional Threshold-Triggered Opportunism.
    Starts with Defection, then adaptively switches to Cooperation only when the 
    collective is exactly one player away from meeting the threshold (m-1),
    unless coordination has proven persistently impossible.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.coordination_failed = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        m = self.game_description.m
        last_my_action = int(history.my_actions[-1])
        s_prev = history.opponent_cooperators[-1] + last_my_action
        if last_my_action == 1 and s_prev < m:
            self.coordination_failed = True
        if self.coordination_failed:
            return Action.D
        if s_prev >= m:
            return Action.D
        elif s_prev == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_88(BaseStrategy):
    """
    Implements Threshold-Targeting Adaptive Opportunism.
    Strategies adapt based on historical success rates, the necessity of personal
    contributions to hit the threshold 'm', and specific end-game defection logic.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.rotation_counter = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        m = self.game_description.m
        n = self.game_description.n_players
        prev_my_action = history.my_actions[-1]
        prev_opp_coop = history.opponent_cooperators[-1]
        c_prev = prev_opp_coop + (1 if prev_my_action else 0)
        s_prev = 1 if c_prev >= m else 0
        total_successes = 0
        for i in range(history.round_number):
            c_i = history.opponent_cooperators[i] + (1 if history.my_actions[i] else 0)
            if c_i >= m:
                total_successes += 1
        h_ratio = total_successes / history.round_number
        if c_prev == m:
            action = [Action.C, Action.C, Action.D][self.rotation_counter % 3]
            self.rotation_counter += 1
            if action == Action.D and s_prev == 0:
                return Action.C
            return action
        if s_prev == 1:
            if prev_my_action and c_prev > m or (not prev_my_action and c_prev >= m):
                return Action.D
            if h_ratio >= 0.8:
                return Action.D
        if s_prev == 0:
            return Action.C
        if s_prev == 1 and prev_my_action and (c_prev == m):
            return Action.C
        if h_ratio < 0.2:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_89(BaseStrategy):
    """
    Implements a Threshold-Matching strategy for the Collective Risk Dilemma.
    
    Logic:
    - Round 0: Always Defect.
    - Round > 0:
        - If previous round met the threshold (C_t-1 >= m): Play Defect (Opportunistic Free-Riding).
        - If previous round was one short of threshold (C_t-1 == m - 1): 
            - In the terminal round: Play Cooperate only if reward k > 1, else Defect.
            - Otherwise: Play Cooperate to bridge the gap.
        - Otherwise: Play Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        my_last_action = history.my_actions[-1]
        opp_last_count = history.opponent_cooperators[-1]
        last_total_coop = opp_last_count + (1 if my_last_action else 0)
        m = self.game_description.m
        k = self.game_description.k
        current_round_idx = history.round_number
        last_round_idx = self.game_description.n_rounds - 1
        if last_total_coop >= m:
            return Action.D
        if last_total_coop == m - 1:
            if current_round_idx == last_round_idx:
                return Action.C if k > 1 else Action.D
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_90(BaseStrategy):
    """
    Implements a conditional 'Tit-for-Tat with a Threshold-Seeker' framework.
    Balances the exploitation of free-riders with the necessity of reaching the cooperation 
    threshold (m) to unlock the reward (k), with logic for persistent failure detection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.persistent_failure_count = 0
        self.give_up_on_threshold = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        last_three_rounds = history.opponent_cooperators[-3:]
        if len(last_three_rounds) == 3:
            if all(history.my_actions[-3:]):
                total_coops = [opp + 1 for opp in last_three_rounds]
                if all((c < self.game_description.m for c in total_coops)):
                    self.give_up_on_threshold = True
        if self.give_up_on_threshold:
            return Action.D
        previous_my_action_val = 1 if history.my_actions[-1] else 0
        total_cooperators_previous_round = history.opponent_cooperators[-1] + previous_my_action_val
        if total_cooperators_previous_round >= self.game_description.m:
            return Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_91(BaseStrategy):
    """
    Implements an Opportunistic Threshold-Stabilization Strategy.
    
    The strategy aims to maintain exactly m cooperators to trigger the reward k.
    It initiates cooperation, then modulates based on previous round feedback, 
    with safeguards against persistent failure (the "sucker" scenario) and 
    inefficient reward structures.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k
        self.failure_counter = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if self.k <= 1.0:
            return Action.D
        current_round = history.round_number
        if current_round == self.r - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        last_my_action = history.my_actions[-1]
        last_opponents_coop = history.opponent_cooperators[-1]
        total_cooperators = last_opponents_coop + (1 if last_my_action else 0)
        if last_my_action and total_cooperators < self.m:
            self.failure_counter += 1
        else:
            self.failure_counter = 0
        if self.failure_counter >= 2:
            return Action.D
        if total_cooperators >= self.m:
            return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_92(BaseStrategy):
    """
    A strategy that implements threshold-monitoring Tit-for-Tat.
    It cooperates to reach the threshold m, then exploits if the threshold is safe,
    while tracking persistent failure to detect uncooperative groups.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.persistent_failure_counter = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_my_action_int = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + prev_my_action_int
        m = self.game_description.m
        if total_cooperators_prev < m:
            self.persistent_failure_counter += 1
        else:
            self.persistent_failure_counter = 0
        if self.persistent_failure_counter >= 3:
            return Action.D
        if total_cooperators_prev >= m + 1:
            return Action.D
        if total_cooperators_prev == m:
            return Action.D
        if total_cooperators_prev < m:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_93(BaseStrategy):
    """
    Opportunistic Threshold-Targeting Strategy for Collective Risk Dilemma.
    
    Phases:
    1. Initiation: Cooperate in round 0.
    2. Adaptive Execution (rounds 1 to r-2):
       - If previous threshold met (C >= m):
         - If we were Cooperating and C == m, continue C to maintain threshold.
         - Otherwise, Defect to exploit.
       - If previous threshold missed (C < m):
         - If trend improved (C_t-1 > C_t-2), try C again.
         - Else, Defect permanently.
    3. Terminal Round (round r-1): Always Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.has_abandoned_cooperation = False

    def __call__(self, history: PlayerHistory) -> Action:
        r = self.desc.n_rounds
        t = history.round_number
        m = self.desc.m
        if t == 0:
            return Action.C
        if t == r - 1:
            return Action.D
        prev_my_action = history.my_actions[-1]
        c_prev = history.opponent_cooperators[-1]
        total_cooperators_prev = int(prev_my_action) + c_prev
        if self.has_abandoned_cooperation:
            return Action.D
        if total_cooperators_prev >= m:
            if prev_my_action == Action.C and total_cooperators_prev == m:
                return Action.C
            else:
                return Action.D
        elif t > 1:
            c_prev_prev = history.opponent_cooperators[-2]
            prev_my_action_prev = history.my_actions[-2]
            total_cooperators_prev_prev = int(prev_my_action_prev) + c_prev_prev
            if total_cooperators_prev > total_cooperators_prev_prev:
                return Action.C
            else:
                self.has_abandoned_cooperation = True
                return Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_94(BaseStrategy):
    """
    Threshold-Adaptive Tit-for-Tat (TA-TFT):
    Optimizes payoffs by only contributing (Cooperating) when the group is exactly
    one cooperator away from the threshold `m`. If the threshold is met, it defects
    to exploit the cooperative effort of others. If the threshold is far from reach
    (less than m-1), it defects to preserve private payoff.
    Always defects in the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = self.game_description.n_players
        self.r = self.game_description.n_rounds
        self.m = self.game_description.m
        self.k = self.game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.r
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        prev_my_action = 1 if history.my_actions[-1] else 0
        prev_opp_coop = history.opponent_cooperators[-1]
        prev_total_cooperators = prev_my_action + prev_opp_coop
        if self.m == self.n:
            if prev_total_cooperators < self.n:
                return Action.D
            return Action.D
        if prev_total_cooperators >= self.m:
            return Action.D
        elif prev_total_cooperators == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_95(BaseStrategy):
    """
    Threshold-seeking conditional cooperation strategy.
    
    This strategy attempts to secure the collective reward by contributing
    only when pivotally necessary. It calibrates in the first round based
    on the relative threshold, opportunistically exploits the group when 
    the threshold is already met, and defects during the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        m = self.game_description.m
        current_round = history.round_number
        if current_round == r - 1:
            return Action.D
        if current_round == 0:
            return Action.C if m / n <= 0.5 else Action.D
        prev_round_idx = current_round - 1
        my_prev_action = history.my_actions[prev_round_idx]
        opp_coop_count = history.opponent_cooperators[prev_round_idx]
        c_prev = opp_coop_count + (1 if my_prev_action else 0)
        if c_prev >= m:
            return Action.D
        elif c_prev == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_96(BaseStrategy):
    """
    Conditional Threshold Strategy:
    Maximizes personal gain by conditionally contributing to the threshold 'm'
    only when beneficial or necessary, while defecting when the threshold
    is met or the goal is deemed unreachable.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.desc.n_rounds
        n = self.desc.n_players
        m = self.desc.m
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            if m < n / 2:
                return Action.C
            return Action.D
        prev_my_action_is_c = history.my_actions[-1]
        prev_opp_coop_count = history.opponent_cooperators[-1]
        prev_total_coop = (1 if prev_my_action_is_c else 0) + prev_opp_coop_count
        if prev_total_coop >= m:
            return Action.D
        elif not prev_my_action_is_c:
            return Action.C
        else:
            if current_round > 1:
                prev_prev_my_c = history.my_actions[-2]
                prev_prev_opp_c = history.opponent_cooperators[-2]
                prev_prev_total = (1 if prev_prev_my_c else 0) + prev_prev_opp_c
                if prev_prev_total < m:
                    return Action.D
            return Action.C

class Strategy_OPPORTUNISTIC_97(BaseStrategy):
    """
    Implements the Threshold-Follower Conditional Opportunist strategy.
    
    Logic:
    1. First round: Contribute with probability m/n.
    2. Subsequent rounds:
       - If previous threshold met (C_prev >= m): Defect to maximize personal gain.
       - If previous threshold not met (C_prev < m):
         - If cusp (C_prev == m - 1): Contribute to attempt reward trigger.
         - If far from threshold (C_prev < m - 1): Defect to conserve resources.
    3. Last round: Only cooperate if exactly on the cusp.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.k = game_description.k
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if self.m > self.n or self.k <= 1:
            return Action.D
        if history.round_number == 0:
            if self.m == 1:
                return Action.C
            if random.random() < self.m / self.n:
                return Action.C
            return Action.D
        my_last_action_idx = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + my_last_action_idx
        is_last_round = history.round_number == self.r - 1
        if total_cooperators_prev >= self.m:
            return Action.D
        is_on_cusp = history.opponent_cooperators[-1] == self.m - 1
        if is_on_cusp:
            return Action.C
        if is_last_round:
            return Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_98(BaseStrategy):
    """
    An adaptive strategy for the Collective Risk Dilemma that balances 
    cooperation to meet threshold requirements with strategic free-riding.
    
    Logic:
    - Round 1: Always Cooperate to establish a positive signal.
    - Final Round: Defect, as there is no future incentive for others to maintain 
      cooperation and the payoff is determined.
    - Intermediate Rounds:
        - If previous cooperators > m: Defect (free-ride on excess).
        - If previous cooperators == m: Cooperate (maintain threshold).
        - If previous cooperators < m: Cooperate (attempt to correct the deficit).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == self.total_rounds - 1:
            return Action.D
        prev_cooperators = history.opponent_cooperators[-1]
        if prev_cooperators > self.m:
            return Action.D
        elif prev_cooperators == self.m:
            return Action.C
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_99(BaseStrategy):
    """
    A strategy that behaves as a conditional cooperator based on a target threshold (m).
    
    Decision Logic:
    1. Round 1: Always Cooperate (C).
    2. Rounds 2 to r-1: 
       - If the previous round's number of cooperators was >= m: Defect (D).
       - If the previous round's number of cooperators was < m: Cooperate (C).
    3. Last Round (r): Always Defect (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.threshold = game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        if current_round_idx == 0:
            return Action.C
        if current_round_idx == total_rounds - 1:
            return Action.D
        prev_my_action = history.my_actions[-1]
        prev_opp_cooperators = history.opponent_cooperators[-1]
        total_cooperators_prev = (1 if prev_my_action else 0) + prev_opp_cooperators
        if total_cooperators_prev >= self.threshold:
            return Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_100(BaseStrategy):
    """
    Opportunistic Threshold Triggering strategy.
    
    This strategy minimizes individual contribution by defecting in the first round to test 
    the group, then acts as a 'conditional pivot': it free-rides (defects) if the group 
    is already meeting the threshold, and cooperates only when that action is the 
    single necessary step to reach the required threshold 'm'.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        last_action_was_coop = bool(history.my_actions[-1])
        opponents_coop_last_round = int(history.opponent_cooperators[-1])
        total_coop_last_round = opponents_coop_last_round + (1 if last_action_was_coop else 0)
        m = self.game_description.m
        if total_coop_last_round >= m:
            return Action.D
        if opponents_coop_last_round == m - 1:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_101(BaseStrategy):
    """
    A conditional, threshold-tracking strategy for the Collective Risk Dilemma.
    
    The strategy employs a probing phase, a threshold-tracking phase, and a 
    terminal phase, while including an adaptive mechanism to abandon cooperation
    if the collective consistently fails to meet the threshold m.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.abandon_threshold_round = math.ceil(self.game_description.n_rounds / 2)

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        prev_my_c = 1 if my_prev_action else 0
        N_prev = prev_my_c + history.opponent_cooperators[-1]
        threshold_ever_met = False
        for t in range(min(current_round, self.abandon_threshold_round)):
            c_me = 1 if history.my_actions[t] else 0
            n_ops = history.opponent_cooperators[t]
            if c_me + n_ops >= m:
                threshold_ever_met = True
                break
        if current_round >= self.abandon_threshold_round and (not threshold_ever_met):
            return Action.D
        if current_round < r - 1:
            if N_prev >= m:
                return Action.D
            else:
                return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_102(BaseStrategy):
    """
    Conditional Threshold Reciprocity (CTR): A strategy for the Collective Risk Dilemma 
    that balances contribution based on threshold status, marginal utility, and 
    opportunistic defection checks.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.defection_probe_rounds_left = 0
        self.is_probing = False

    def _get_my_contribution(self, my_last_action: bool) -> int:
        return 1 if my_last_action else 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.desc.n_players
        m = self.desc.m
        r = self.desc.n_rounds
        current_round = history.round_number
        if current_round >= 5:
            last_5_payoffs = history.my_payoffs[-5:]
            avg_payoff = np.mean(last_5_payoffs)
            if avg_payoff < 0.95:
                self.is_probing = True
                self.defection_probe_rounds_left = 3
        if self.is_probing:
            if current_round > 0:
                prev_opp_c = history.opponent_cooperators[-1]
                prev_my_c = self._get_my_contribution(history.my_actions[-1])
                if prev_opp_c + prev_my_c >= m:
                    if self.defection_probe_rounds_left > 0:
                        self.defection_probe_rounds_left -= 1
                        return Action.D
                    else:
                        return Action.D
                else:
                    self.is_probing = False
                    self.defection_probe_rounds_left = 0
            else:
                pass
        if current_round == 0:
            if n < 5:
                return Action.C if m / n >= 0.5 else Action.D
            else:
                prob = m / n
                return Action.C if random.random() < prob else Action.D
        prev_opp_c = history.opponent_cooperators[-1]
        prev_my_c = self._get_my_contribution(history.my_actions[-1])
        total_prev_c = prev_opp_c + prev_my_c
        if current_round == r - 1:
            if total_prev_c >= m - 1:
                return Action.C
            else:
                return Action.D
        if total_prev_c >= m:
            if total_prev_c > m:
                return Action.D
            else:
                return Action.C
        elif total_prev_c >= m - 1:
            return Action.C
        else:
            return Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_103(BaseStrategy):
    """
    Opportunistic Trigger-Threshold Strategy (OTTS).
    
    Operates on Conditional Minimum Thresholding:
    - Phase 1 (Round 0): Defect unless the threshold requires everyone to cooperate.
    - Phase 2 & 3 (Subsequent):
        - If previous cooperators >= m: Defect (free-ride).
        - If previous cooperators == m - 1: Cooperate (trigger threshold).
        - Otherwise: Defect (threshold unattainable).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            if self.game_description.n_players == self.game_description.m:
                return Action.C
            return Action.D
        prev_opp_coop = int(history.opponent_cooperators[-1])
        i_cooperated = int(history.my_actions[-1])
        c_prev = prev_opp_coop + i_cooperated
        m = self.game_description.m
        if c_prev >= m:
            return Action.D
        elif c_prev == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_104(BaseStrategy):
    """
    Opportunistic Threshold-Trigger Strategy (OTTS)
    
    A conditional parasitism strategy that balances maximizing individual payoffs 
    (free-riding) with the necessity of reaching the threshold 'm' to secure the 
    collective reward 'k'.
    
    Decision Rules:
    1. Always Defect (D) in the first round and the final round.
    2. Monitor total cooperation (self + others).
    3. If previous round was a Failure (total < m), Cooperate (C).
    4. If previous round was a Success (total >= m):
       - If total > m, Defect (D) to free-ride.
       - If total == m, Cooperate (C) to maintain the threshold.
    5. Includes persistence logic for boundary conditions (e.g., oscillating success/failure).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.persistence_counter = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.D
        prev_my_action = 1 if history.my_actions[-1] else 0
        prev_opp_coop = history.opponent_cooperators[-1]
        total_coop_prev = prev_opp_coop + prev_my_action
        prev_success = total_coop_prev >= self.game_description.m
        if prev_my_action == 1 and (not prev_success):
            self.persistence_counter = 1
        if self.persistence_counter > 0:
            self.persistence_counter -= 1
            return Action.C
        if prev_success:
            if total_coop_prev > self.game_description.m:
                return Action.D
            else:
                return Action.C
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_105(BaseStrategy):
    """
    A Conditional Threshold-Seeking Tit-for-Tat strategy.
    
    This strategy behaves as a free-rider, defecting in the first and last rounds. 
    In intermediate rounds, it monitors the previous round's cooperation count:
    - If the threshold was met without this player, it continues to defect.
    - If exactly m-1 players cooperated, it cooperates to trigger the reward.
    - If fewer than m-1 players cooperated, it defects, as its single contribution cannot change the outcome.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == 0:
            return Action.D
        if current_round == n_rounds - 1:
            return Action.D
        prev_coop_count = history.opponent_cooperators[-1]
        my_last_action = history.my_actions[-1]
        total_cooperators_last_round = prev_coop_count + (1 if my_last_action else 0)
        if total_cooperators_last_round >= m:
            return Action.D
        elif total_cooperators_last_round == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_106(BaseStrategy):
    """
    A strategy that implements threshold-sensitive conditional cooperation in the Collective Risk Dilemma.
    It signals cooperation initially, then dynamically adjusts based on group success, 
    including a 'Defector's Trap' detector and a long-term failure exit condition.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0
        self.in_trap_recovery = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            if self.game_description.m < self.game_description.n_players and self.game_description.k > 1:
                return Action.C
            return Action.D
        t_minus_1 = history.round_number - 1
        c_prev = history.opponent_cooperators[t_minus_1]
        my_prev_action = Action.C if history.my_actions[t_minus_1] else Action.D
        total_coop = c_prev + (1 if my_prev_action == Action.C else 0)
        if total_coop < self.game_description.m and my_prev_action == Action.C:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 3:
            return Action.D
        if my_prev_action == Action.D and c_prev == self.game_description.m - 1:
            self.in_trap_recovery = True
            return Action.C
        if self.in_trap_recovery:
            self.in_trap_recovery = False
        if total_coop >= self.game_description.m:
            return Action.D
        if total_coop < self.game_description.m:
            if my_prev_action == Action.C:
                return Action.D
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_107(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that balances cooperative signaling
    with free-riding opportunities based on previous round outcomes.
    
    Logic:
    - Round 0: Always Cooperate (C).
    - If last round was C:
        - If C_prev >= m + 1: Defect (D) to free-ride.
        - Otherwise: Cooperate (C).
    - If last round was D:
        - If C_prev >= m: Defect (D) to free-ride.
        - If C_prev < m: Cooperate (C) to rescue.
    - Final Round: Always Defect (D) regardless of strategy.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        m = self.game_description.m
        r_total = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == r_total - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        my_last_action = history.my_actions[-1]
        opp_cooperators = history.opponent_cooperators[-1]
        c_i = 1 if my_last_action else 0
        c_prev = opp_cooperators + c_i
        if my_last_action == Action.C:
            if c_prev >= m + 1:
                return Action.D
            else:
                return Action.C
        elif c_prev >= m:
            return Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_108(BaseStrategy):
    """
    Threshold-Conditional Opportunistic (TCO) strategy:
    A threshold-based tit-for-tat mechanism that attempts to trigger the reward
    by contributing when the group is failing, while exploiting the surplus
    contribution when the threshold is already exceeded.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_idx = history.round_number
        n_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round_idx == 0:
            return Action.C
        if current_round_idx == n_rounds - 1:
            return Action.D
        prev_my_action_is_c = history.my_actions[-1]
        prev_opponent_coops = history.opponent_cooperators[-1]
        total_cooperators_prev = prev_opponent_coops + (1 if prev_my_action_is_c else 0)
        if total_cooperators_prev > m:
            return Action.D
        elif total_cooperators_prev == m:
            return Action.C if prev_my_action_is_c else Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_109(BaseStrategy):
    """
    Implements Conditional Threshold-Triggered Opportunism (CTTO).
    
    This strategy acts as a 'conditional pivot':
    - Always defects in the first round.
    - If the previous round's cooperation count (by others) was exactly m-1, 
      it cooperates to trigger the collective reward.
    - If the threshold m is already met by others, it defects to free-ride.
    - If the threshold is unreachable (less than m-1 cooperators), it defects to save endowment.
    - Includes a 'sucker trap' check: if it previously cooperated as a pivot but the 
      threshold was still not met, it assumes instability and defaults to defection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.sucker_trap_triggered = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        if self.sucker_trap_triggered:
            return Action.D
        last_round_idx = history.round_number - 1
        last_opponents = history.opponent_cooperators[last_round_idx]
        my_last_action = history.my_actions[last_round_idx]
        m_total = last_opponents + (1 if my_last_action else 0)
        if my_last_action and m_total < self.game_description.m:
            self.sucker_trap_triggered = True
            return Action.D
        if last_opponents >= self.game_description.m:
            return Action.D
        elif last_opponents == self.game_description.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_110(BaseStrategy):
    """
    Implements Conditional Threshold Optimism:
    Starts by cooperating (t=1). In subsequent rounds, it monitors the number of 
    cooperators. It aims to maximize payoff by free-riding (playing D) when the 
    threshold is safely exceeded (> m), but immediately switches to cooperation 
    (C) when the threshold is exactly met (= m) or threatened (< m) to ensure 
    the collective reward is secured. In the final round, it defects if the 
    threshold was previously met, otherwise it cooperates.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.n = game_description.n_players
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        previous_my_action = int(history.my_actions[-1])
        c_previous = history.opponent_cooperators[-1] + previous_my_action
        if history.round_number == self.r - 1:
            if c_previous >= self.m:
                return Action.D
            else:
                return Action.C
        if c_previous > self.m:
            return Action.D
        elif c_previous == self.m:
            return Action.C
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_111(BaseStrategy):
    """
    Implements a Threshold Trigger Strategy with Opportunistic Exploitation.
    
    The strategy aims to secure the collective threshold reward (k) while defecting
    whenever the threshold is met or unreachable. It uses a "swing vote" logic:
    contributing only if it directly causes the threshold (m) to be met.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number + 1
        total_rounds = self.game.n_rounds
        m = self.game.m
        if current_round == 1:
            return Action.C
        if current_round == total_rounds:
            return Action.D
        last_round_idx = history.round_number - 1
        last_my_action = 1 if history.my_actions[last_round_idx] else 0
        last_opponent_count = history.opponent_cooperators[last_round_idx]
        total_cooperators_last_round = last_opponent_count + last_my_action
        if total_cooperators_last_round >= m:
            return Action.D
        if total_cooperators_last_round == m - 1:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_112(BaseStrategy):
    """
    Threshold-Seeking Opportunism strategy:
    Focuses on clinching the threshold (m) only when necessary, while defecting
    when the goal is already met by others or unreachable. Includes logic to
    identify non-cooperative groups and opportunistic free-riding.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failed_cooperation_attempts = 0
        self.consecutive_free_rider_rounds = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r_total = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            if m / n > 0.5:
                return Action.C
            return Action.D
        my_prev_action = int(history.my_actions[-1])
        nc_prev = history.opponent_cooperators[-1] + my_prev_action
        if current_round == r_total - 1:
            return Action.D
        if my_prev_action == 1 and nc_prev < m:
            self.consecutive_failed_cooperation_attempts += 1
        else:
            self.consecutive_failed_cooperation_attempts = 0
        if my_prev_action == 0 and nc_prev >= m:
            self.consecutive_free_rider_rounds += 1
        else:
            self.consecutive_free_rider_rounds = 0
        if self.consecutive_failed_cooperation_attempts >= 3:
            return Action.D
        if nc_prev >= m and self.consecutive_free_rider_rounds >= 2:
            return Action.D
        if nc_prev >= m:
            return Action.D
        if nc_prev < m - 1:
            return Action.D
        if nc_prev == m - 1:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_113(BaseStrategy):
    """
    Conditional Threshold Monitoring (CTM):
    A strategy that treats cooperation as a conditional investment. 
    It cooperates on the first round, defects on the last round, and 
    dynamically adjusts to provide marginal cooperation only when 
    the collective threshold is one shy of being met. Otherwise, 
    it defects to maximize individual payoff.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.last_action: Action = Action.D

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == 0:
            self.last_action = Action.C
            return Action.C
        if current_round == total_rounds - 1:
            self.last_action = Action.D
            return Action.D
        prev_cooperators = history.opponent_cooperators[-1]
        if self.last_action == Action.C:
            total_cooperators = prev_cooperators + 1
        else:
            total_cooperators = prev_cooperators
        if total_cooperators >= m:
            self.last_action = Action.D
            return Action.D
        elif total_cooperators == m - 1:
            self.last_action = Action.C
            return Action.C
        else:
            self.last_action = Action.D
            return Action.D

class Strategy_OPPORTUNISTIC_114(BaseStrategy):
    """
    Implements a conditional threshold-tracking strategy.
    
    Logic:
    - Round 0: Defect (D).
    - Rounds t > 0:
        - If previous C_count >= m: Defect (D).
        - If previous C_count == m - 1: Cooperate (C).
        - If previous C_count < m - 1: 
            - Check for static state (if static for 3 rounds, test with C for one round).
            - Otherwise: Defect (D).
    - If 'Shake-up' (C test) fails, revert to Defect for the remainder of the game.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.reverting_to_permanent_defect = False
        self.static_rounds_count = 0
        self.shake_up_active = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        if self.reverting_to_permanent_defect:
            return Action.D
        prev_my_action = history.my_actions[-1]
        prev_opp_coop = history.opponent_cooperators[-1]
        c_prev = prev_opp_coop + (1 if prev_my_action else 0)
        m = self.game_description.m
        if self.shake_up_active:
            if c_prev <= prev_opp_coop:
                self.reverting_to_permanent_defect = True
                self.shake_up_active = False
                return Action.D
            else:
                self.shake_up_active = False
                self.static_rounds_count = 0
                return Action.D
        if c_prev < m - 1:
            self.static_rounds_count += 1
        else:
            self.static_rounds_count = 0
        if c_prev >= m:
            return Action.D
        elif c_prev == m - 1:
            return Action.C
        else:
            if self.static_rounds_count >= 3:
                self.shake_up_active = True
                return Action.C
            return Action.D

class Strategy_OPPORTUNISTIC_115(BaseStrategy):
    """
    A strategy that adapts to the Collective Risk Dilemma by attempting to initiate cooperation
    probabilistically in the first round, and then dynamically adjusting based on whether the
    group threshold (m) is met. It exploits the group by defecting when the threshold is 
    already satisfied (S >= m) and attempts to restore cooperation if the threshold was missed 
    (S < m) while ensuring it does not waste costs in the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = self.game_description.n_players
        self.m = self.game_description.m
        self.r = self.game_description.n_rounds
        self.last_action = None

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            threshold_prob = self.m / self.n
            if random.random() < threshold_prob:
                self.last_action = Action.C
                return Action.C
            else:
                self.last_action = Action.D
                return Action.D
        prev_my_action_int = 1 if self.last_action == Action.C else 0
        s_prev = history.opponent_cooperators[-1] + prev_my_action_int
        if current_round >= self.r:
            self.last_action = Action.D
            return Action.D
        if s_prev >= self.m:
            self.last_action = Action.D
            return Action.D
        if s_prev < self.m:
            if current_round < self.r - 1:
                self.last_action = Action.C
                return Action.C
            else:
                self.last_action = Action.D
                return Action.D
        self.last_action = Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_116(BaseStrategy):
    """
    Implements a Tit-for-Tat strategy with opportunistic defection for the Collective Risk Dilemma.
    - Cooperates on the first round.
    - Defects on the final round.
    - If the threshold was met, attempts to free-ride (defect) if safe, otherwise cooperates.
    - If the threshold was not met, retaliates by defecting.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_idx = history.round_number
        if current_round_idx == self.total_rounds - 1:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        my_prev_action = Action.C if history.my_actions[-1] else Action.D
        my_prev_count = 1 if my_prev_action == Action.C else 0
        prev_cooperators = history.opponent_cooperators[-1] + my_prev_count
        if prev_cooperators < self.m:
            return Action.D
        else:
            if prev_cooperators > self.m and my_prev_action == Action.C:
                return Action.D
            if prev_cooperators == self.m and my_prev_action == Action.C:
                if prev_cooperators - 1 < self.m:
                    return Action.C
                else:
                    return Action.D
            return Action.C

class Strategy_OPPORTUNISTIC_117(BaseStrategy):
    """
    Strategy: Threshold-Targeting Opportunism
    Implements a conditional threshold satisfaction logic:
    - Minimizes contribution while ensuring the threshold m is met.
    - Round 0: Tests the waters.
    - Standard Rounds: Opportunistically fills the gap if m-1 opponents cooperated, otherwise defects.
    - Final Round: Pure defect, except when acting as the sole swing vote.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number + 1
        if current_round == 1:
            return Action.C if m / n > 0.5 else Action.D
        prev_cooperators = history.opponent_cooperators[-1]
        if current_round == r:
            if prev_cooperators == m - 1:
                return Action.C
            return Action.D
        if prev_cooperators >= m:
            return Action.D
        elif prev_cooperators == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_118(BaseStrategy):
    """
    Threshold-Adaptive Tit-for-Tat (TA-TFT).

    Strategy logic:
    1. First round (round 0): Always Cooperate (C).
    2. Final round (round r-1): Always Defect (D).
    3. Intermediate rounds: Cooperate (C) if the number of cooperators in the 
       previous round was >= m, otherwise Defect (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == 0:
            return Action.C
        if current_round == total_rounds - 1:
            return Action.D
        prev_cooperators = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        total_cooperators_prev = (1 if my_prev_action else 0) + prev_cooperators
        if total_cooperators_prev >= m:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_119(BaseStrategy):
    """
    Implements Threshold-Targeted Reciprocity (TTR).
    
    This strategy focuses on maintaining the threshold 'm' for cooperation. 
    It cooperates in the first round to establish a baseline. In subsequent rounds, 
    it monitors the number of cooperators from the previous round. If the threshold 
    was not met or barely met, it cooperates to ensure stability. If the threshold 
    was exceeded, it defects to exploit the surplus, unless it is the final round, 
    where it prioritizes defecting if the threshold is safe or cooperating if it is at risk.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = self.game_description.m
        self.total_rounds = self.game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        others_cooperated = history.opponent_cooperators[-1]
        total_cooperators_prev = others_cooperated + (1 if my_prev_action else 0)
        if current_round == self.total_rounds - 1:
            if total_cooperators_prev > self.m:
                return Action.D
            else:
                return Action.C
        if total_cooperators_prev < self.m:
            return Action.C
        elif total_cooperators_prev == self.m:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_120(BaseStrategy):
    """
    Threshold-Conditional Opportunism (TCO):
    A strategy that estimates the probability of others cooperating based on history
    and acts only when the agent's contribution is critical to hitting the threshold 'm'.
    Adjusts beliefs based on observed threshold sensitivity.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        if self.desc.n_players > 1:
            self.q_hat = (self.desc.m - 1) / (self.desc.n_players - 1)
        else:
            self.q_hat = 0.0
        self.threshold_met_count = 0

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_idx = history.round_number
        if current_round_idx == 0:
            return Action.D
        last_round_opp_coop = history.opponent_cooperators[-1]
        last_round_my_action = history.my_actions[-1]
        total_cooperators = last_round_opp_coop + (1 if last_round_my_action else 0)
        if total_cooperators >= self.desc.m:
            self.threshold_met_count += 1
        if total_cooperators == self.desc.m - 1 and (not last_round_my_action):
            self.q_hat = min(1.0, self.q_hat * 1.1)
        if last_round_my_action and total_cooperators >= self.desc.m + 1:
            self.q_hat = max(0.0, self.q_hat * 0.9)
        if current_round_idx == self.desc.n_rounds - 1:
            return Action.D
        sum_total_coop = 0
        for i in range(current_round_idx):
            my_c = 1 if history.my_actions[i] else 0
            sum_total_coop += history.opponent_cooperators[i] + my_c
        self.q_hat = sum_total_coop / (self.desc.n_players * current_round_idx)
        num_opponents = self.desc.n_players - 1
        if num_opponents == 0:
            expected_others = 0
        else:
            expected_others = self.q_hat * num_opponents
        if (m_float := float(self.desc.m)):
            if expected_others >= m_float:
                return Action.D
            elif expected_others < m_float - 1:
                return Action.D
            else:
                return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_121(BaseStrategy):
    """
    Threshold-Seeking Opportunism strategy:
    1. Initializes by cooperating to test the waters.
    2. In subsequent rounds, if the threshold was met previously, defects to exploit the reward.
    3. If the threshold was almost met (m-1), cooperates to become pivotal.
    4. Otherwise, defects to conserve endowment.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_prev_action_val = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + my_prev_action_val
        m = self.game_description.m
        if total_cooperators_prev >= m:
            return Action.D
        if total_cooperators_prev == m - 1:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_122(BaseStrategy):
    """
    Implements a Threshold-Triggered Conditional Cooperation strategy.
    
    Operates on a greedy principle:
    - Round 0: Cooperates to probe the group.
    - Subsequent rounds:
        - If the group met the threshold without my help (S >= m): Defect.
        - If the group needs exactly my contribution to meet the threshold (S == m - 1): Cooperate.
        - Otherwise (S < m - 1): Defect (Despair).
    - Terminal round:
        - If group history suggests threshold is reachable (S >= m - 1): Cooperate.
        - Else: Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        m = self.game_description.m
        r_total = self.game_description.n_rounds
        current_round = history.round_number
        s_prev = history.opponent_cooperators[-1]
        if current_round == r_total - 1:
            if s_prev >= m - 1:
                return Action.C
            else:
                return Action.D
        if s_prev >= m:
            return Action.D
        elif s_prev == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_123(BaseStrategy):
    """
    Implements a conditional threshold strategy for the Collective Risk Dilemma.
    The player cooperates in the first round to signal intent. In subsequent 
    rounds, the player acts as a 'pivot': defecting when the group succeeds 
    without them, cooperating when their contribution is necessary to reach 
    the threshold m, and defecting when the threshold is unreachable.
    In the final round, the player biases towards cooperation if success 
    is within reach (m-1).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.n = game_description.n_players
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        current_round = history.round_number + 1
        last_round_my_action = 1 if history.my_actions[-1] else 0
        last_round_opponents_coop = history.opponent_cooperators[-1]
        last_round_total_coop = last_round_opponents_coop + last_round_my_action
        if current_round == self.r:
            if last_round_total_coop >= self.m - 1:
                return Action.C
            else:
                return Action.D
        if last_round_total_coop >= self.m:
            return Action.D
        if last_round_total_coop == self.m - 1:
            return Action.C
        if last_round_total_coop < self.m - 1:
            return Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_124(BaseStrategy):
    """
    Opportunistic Tipping Point Strategy for Collective Risk Dilemma.
    In the first round, it defects. In subsequent rounds, it monitors the
    previous round's cooperation count (Nc). It defects if Nc >= m, 
    cooperates if Nc == m - 1 (to trigger the reward), and defects if 
    Nc < m - 1.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        my_prev_action = history.my_actions[-1]
        if my_prev_action:
            n_c = history.opponent_cooperators[-1] + 1
        else:
            n_c = history.opponent_cooperators[-1]
        m = self.game_description.m
        if n_c >= m:
            return Action.D
        elif n_c == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_125(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that implements:
    1. Initial cooperation.
    2. Opportunistic logic: if previous cooperation > m, defect (free-ride).
    3. Threshold maintenance: if previous cooperation <= m, cooperate.
    4. Terminal logic: defect in final rounds unless cooperation is crucial and effective.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        prev_my_action = int(history.my_actions[-1])
        prev_others_coop = history.opponent_cooperators[-1]
        prev_total_coop = prev_others_coop + prev_my_action
        if current_round == self.total_rounds - 1:
            return Action.D
        if current_round == self.total_rounds - 2:
            if prev_total_coop >= self.m:
                return Action.D
            if prev_others_coop + 1 >= self.m:
                return Action.C
            else:
                return Action.D
        if prev_total_coop > self.m:
            return Action.D
        if prev_total_coop <= self.m:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_126(BaseStrategy):
    """
    Threshold-Conditional Tit-for-Tat:
    - Round 1: Cooperate if m/n <= 0.5, else Defect.
    - Subsequent Rounds (t < r):
      - If last_cooperators >= m: Defect (free-riding).
      - Else if last_cooperators >= m - 1: Cooperate (recovery).
      - Else: Defect (failure).
    - Final Round (t = r): Always Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = self.game_description.n_players
        self.r = self.game_description.n_rounds
        self.m = self.game_description.m
        self.initial_action = Action.C if self.m / self.n <= 0.5 else Action.D

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.r - 1:
            return Action.D
        if history.round_number == 0:
            return self.initial_action
        my_last_action_val = 1 if history.my_actions[-1] else 0
        total_cooperators_last_round = history.opponent_cooperators[-1] + my_last_action_val
        if total_cooperators_last_round >= self.m:
            return Action.D
        if total_cooperators_last_round >= self.m - 1:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_127(BaseStrategy):
    """
    A Tit-for-Tat with a Threshold-Trigger strategy. 
    Defects by default to maintain endowment, only switches to Cooperate (C) 
    in Round 2 to R-1 if the group is exactly one player away from the 
    threshold (m - 1), otherwise defects. Always defects in the final round.
    Defaults to Defect if the reward (k) is <= 1 (cost of cooperation).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.is_profitable = self.game_description.k > 1.0

    def __call__(self, history: PlayerHistory) -> Action:
        if not self.is_profitable:
            return Action.D
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.D
        prev_round_cooperators = history.opponent_cooperators[-1]
        if prev_round_cooperators == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_OPPORTUNISTIC_128(BaseStrategy):
    """
    Adaptive Opportunism Strategy for Collective Risk Dilemma:
    - Starts with cooperation.
    - Exploits successful collective outcomes (previous cooperators >= m) by defecting.
    - Switches back to cooperation if the threshold was missed, to enforce/restore the reward.
    - Always defects in the final round.
    - Adjusts to high-stakes scenarios (m very close to n) by prioritizing cooperation if constant failure is observed.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        prev_cooperators = int(history.opponent_cooperators[-1])
        i_cooperated_prev = bool(history.my_actions[-1])
        total_cooperators_prev = prev_cooperators + (1 if i_cooperated_prev else 0)
        if total_cooperators_prev < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if m >= n * 0.9 and self.consecutive_failures >= 2:
            return Action.C
        if current_round == r - 1:
            return Action.D
        if total_cooperators_prev >= m:
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_33(BaseStrategy):
    """
    Threshold-Tit-for-Tat with Variable Thresholding (TTFT-VT).
    
    1. First round: Cooperate (C).
    2. Threshold Condition (t > 1):
        - If N_c(t-1) < m: Revert to C to restart efforts.
        - If N_c(t-1) == m: Must play C to ensure threshold is maintained.
        - If N_c(t-1) > m: Switch to D to maximize gain, unless last round rules apply.
    3. Defector Correction: If N_c < m for two consecutive rounds, switch to D forever.
    4. Final Round (t = r):
        - If N_c(r-1) >= m and consistently played D: D.
        - If N_c(r-1) < m and consistently played C: C if prob > m/n else D.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.consecutive_failures = 0
        self.defector_correction_active = False
        self.played_c_consistently = True

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_my_action = history.my_actions[-1]
        prev_my_c = 1 if prev_my_action else 0
        prev_total_c = prev_my_c + history.opponent_cooperators[-1]
        if not prev_my_action:
            self.played_c_consistently = False
        if self.defector_correction_active:
            return Action.D
        if history.round_number >= 2:
            prev_total_c_minus_2 = (1 if history.my_actions[-2] else 0) + history.opponent_cooperators[-2]
            if prev_total_c < self.desc.m and prev_total_c_minus_2 < self.desc.m:
                self.defector_correction_active = True
                return Action.D
        if history.round_number == self.desc.n_rounds - 1:
            if prev_total_c >= self.desc.m and (not self.played_c_consistently):
                return Action.D
            elif prev_total_c < self.desc.m and self.played_c_consistently:
                if len(history.opponent_cooperators) > 0:
                    prob_others = np.mean(history.opponent_cooperators) / (self.desc.n_players - 1)
                else:
                    prob_others = 0.5
                threshold_prob = self.desc.m / self.desc.n_players
                return Action.C if prob_others >= threshold_prob else Action.D
            return Action.D
        if prev_total_c < self.desc.m:
            return Action.C
        elif prev_total_c == self.desc.m:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_34(BaseStrategy):
    """
    Implements the Adaptive Threshold Strategy (ATS).
    
    This strategy utilizes a dynamic threshold mechanism based on recent history to 
    optimize cooperation. It plays D in the first round to establish a baseline, 
    then evaluates recent contribution trends to decide whether to pivot to C 
    (to trigger the threshold) or remain at D (to free-ride or avoid wasted effort).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.D
        m = self.game_description.m
        r = self.game_description.n_rounds
        if t == r - 1:
            last_round_cooperators = history.opponent_cooperators[-1]
            my_last_action = int(history.my_actions[-1])
            total_cooperators_last_round = history.opponent_cooperators[-1] + my_last_action
            if total_cooperators_last_round == m - 1:
                return Action.C
            else:
                return Action.D
        start_idx = max(0, t - 3)
        relevant_history = history.opponent_cooperators[start_idx:t]
        my_actions_int = history.my_actions.astype(int)
        relevant_my_actions = my_actions_int[start_idx:t]
        total_cooperators_series = relevant_history + relevant_my_actions
        H = np.mean(total_cooperators_series)
        if H >= m + 1:
            return Action.D
        elif m - 1 <= H < m:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_35(BaseStrategy):
    """
    A strategy that observes the population's cooperation propensity in the first round 
    and thereafter acts only when the player's contribution is pivotal (i.e., when the
    cooperator count is exactly m-1), effectively maximizing payoffs by free-riding 
    when the threshold is already met or impossible to reach.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        m = self.game_description.m
        last_round_cooperators = history.opponent_cooperators[-1]
        my_last_action_is_cooperate = bool(history.my_actions[-1])
        total_cooperators_prev = last_round_cooperators + (1 if my_last_action_is_cooperate else 0)
        if total_cooperators_prev == m - 1:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_36(BaseStrategy):
    """
    Implements a strategic approach to the Collective Risk Dilemma using 
    probabilistic utility calculations and reactive triggers.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.n = self.desc.n_players
        self.m = self.desc.m
        self.k = self.desc.k
        self.r = self.desc.n_rounds
        self.p_est = self.m / self.n
        self.consecutive_failure_count = 0
        self.testing_mode = False
        self.testing_cooperated_last = False

    def _nCr(self, n, r):
        if r < 0 or r > n:
            return 0
        return math.comb(n, r)

    def _binomial_prob_cumulative(self, trials, k_successes, p):
        prob = 0.0
        for j in range(k_successes, trials + 1):
            prob += self._nCr(trials, j) * p ** j * (1 - p) ** (trials - j)
        return prob

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            if self.m > self.n / 2:
                return Action.C
            return Action.D
        prev_opp_coop = history.opponent_cooperators[-1]
        prev_opp_total = self.n - 1
        observed_fraction = prev_opp_coop / prev_opp_total if prev_opp_total > 0 else 0
        self.p_est = (self.p_est + observed_fraction) / 2
        if prev_opp_coop + (1 if history.my_actions[-1] else 0) < self.m:
            self.consecutive_failure_count += 1
        else:
            self.consecutive_failure_count = 0
        if self.consecutive_failure_count >= 2:
            return Action.D
        if prev_opp_coop + (1 if history.my_actions[-1] else 0) >= self.m + 2:
            self.testing_mode = True
            return Action.D
        if self.testing_mode:
            threshold_met = prev_opp_coop >= self.m
            if threshold_met:
                return Action.D
            else:
                self.testing_mode = False
                return Action.C
        p_success_c = self._binomial_prob_cumulative(self.n - 1, self.m - 1, self.p_est)
        eu_c = self.k * p_success_c - 1
        p_success_d = self._binomial_prob_cumulative(self.n - 1, self.m, self.p_est)
        eu_d = self.k * p_success_d
        if t == self.r - 1:
            if eu_c < eu_d:
                return Action.D
            return Action.C
        if eu_c >= eu_d:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_37(BaseStrategy):
    """
    Threshold-conditional tit-for-tat strategy.
    
    This strategy prioritizes securing the collective reward 'k' by monitoring the 
    previous round's cooperation count. It acts as a "swing vote" collaborator:
    - Round 1: Probes for cooperation by playing C.
    - Final Round: Always plays D (Endgame Effect).
    - Intermediate Rounds:
        - If previous C count >= m: Free-ride by playing D.
        - If previous C count == m-1: Provide critical swing contribution by playing C.
        - If previous C count < m-1: Conserve endowment by playing D (unreachable threshold).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        if t == self.r - 1:
            return Action.D
        prev_my_action = history.my_actions[-1]
        prev_opp_coop = history.opponent_cooperators[-1]
        total_cooperators_prev = prev_opp_coop + (1 if prev_my_action else 0)
        if total_cooperators_prev >= self.m:
            return Action.D
        elif total_cooperators_prev == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_38(BaseStrategy):
    """
    Threshold-Adaptive Conditional Cooperation Strategy:
    - Round 1: Always Cooperate (C).
    - Terminal Round: Always Defect (D).
    - Adaptive Rule (Intermediate Rounds):
      Let S_{t-1} be the number of cooperators observed in the previous round.
      1. If S_{t-1} >= m: Defect (Threshold met without personal contribution).
      2. If S_{t-1} == m - 1: Cooperate (One short of threshold; trigger reward).
      3. If S_{t-1} < m - 1: Defect (Too few to hit threshold).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.r - 1:
            return Action.D
        s_prev = history.opponent_cooperators[-1]
        if s_prev >= self.m:
            return Action.D
        elif s_prev == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_39(BaseStrategy):
    """
    A Tit-for-Tat based strategy for the Collective Risk Dilemma.
    
    Logic:
    1. Round 0: Defect (D).
    2. Last Round (r-1): Defect (D).
    3. Failure Recovery: If the last 3 rounds showed < m cooperators, probe with Cooperate (C).
    4. Normal rounds: Cooperate (C) if previous round had >= m cooperators, else Defect (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round == self.total_rounds - 1:
            return Action.D
        observed = history.opponent_cooperators
        if len(observed) >= 3:
            if all((obs < self.m for obs in observed[-3:])):
                return Action.C
        last_round_cooperators = observed[-1]
        if last_round_cooperators >= self.m:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_40(BaseStrategy):
    """
    Implements a conditional cooperation strategy for the Collective Risk Dilemma.
    
    The strategy attempts to meet the threshold 'm' by cooperating when necessary. 
    It incorporates:
    1. First round cooperation to signal intent.
    2. Threshold monitoring: Defects if the previous round met or exceeded 'm'.
    3. Adaptive logic: Monitors for "population incompetence" (3 consecutive rounds below 'm') 
       and potential free-riding opportunities.
    4. End-game: Defects in the final round as the future shadow disappears.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.permanent_defect = False
        self.testing_free_ride = False

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        m = self.game_description.m
        total_rounds = self.game_description.n_rounds
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        if current_round >= 3 and (not self.permanent_defect):
            coop_during_failure = True
            for i in range(-3, 0):
                if not history.my_actions[i]:
                    coop_during_failure = False
                    break
                total_c = history.opponent_cooperators[i] + int(history.my_actions[i])
                if total_c >= m:
                    coop_during_failure = False
                    break
            if coop_during_failure:
                self.permanent_defect = True
        if self.permanent_defect:
            return Action.D
        last_coop_count = history.opponent_cooperators[-1] + int(history.my_actions[-1])
        last_action = history.my_actions[-1]
        if last_coop_count >= m:
            return Action.D
        elif last_action == True:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_41(BaseStrategy):
    """
    Threshold-Sensitive Reciprocal Cooperation
    
    This strategy uses conditional cooperation based on group threshold dynamics. 
    It initiates with cooperation, maintains a probing phase for the first 3 rounds, 
    and then switches to a responsive monitoring strategy. It defects in the final 
    round and when group coordination collapses.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.n = game_description.n_players
        self.total_rounds = game_description.n_rounds
        self.s_counter = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.total_rounds - 1:
            return Action.D
        prev_round_idx = history.round_number - 1
        c_prev = history.opponent_cooperators[prev_round_idx]
        my_prev_action = 1 if history.my_actions[prev_round_idx] else 0
        total_cooperators_prev = c_prev + my_prev_action
        if total_cooperators_prev >= self.m:
            self.s_counter += 1
        C_prev = total_cooperators_prev
        T = history.round_number + 1
        is_probing = T <= 3
        if is_probing:
            all_prev_coop_counts = history.opponent_cooperators + history.my_actions.astype(int)
            if np.all(all_prev_coop_counts >= self.n / 2):
                return Action.C
        if C_prev >= self.m:
            return Action.C
        if C_prev == self.m - 1:
            return Action.C
        if C_prev < self.m - 1:
            return Action.D
        return Action.D

class Strategy_INDIVIDUALISTIC_42(BaseStrategy):
    """
    A conditional, threshold-based strategy for the Collective Risk Dilemma.
    
    Logic:
    - Round 0: Always Defect.
    - Rounds 1 to r-2: 
        - If previous cooperators >= m: Defect (threshold is met).
        - If previous cooperators == m - 1: Cooperate (bridge the gap).
        - Otherwise: Defect (too far to bridge).
    - Final Round:
        - If previous cooperators >= m - 1: Cooperate (secure the reward).
        - Otherwise: Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        m = self.game_description.m
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        my_prev_action = 1 if history.my_actions[-1] else 0
        s_prev = my_prev_action + history.opponent_cooperators[-1]
        if current_round == r - 1:
            if s_prev >= m - 1:
                return Action.C
            else:
                return Action.D
        if s_prev >= m:
            return Action.D
        elif s_prev == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_43(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that balances cooperative threshold 
    maintenance with conditional risk mitigation based on historical group behavior.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.k = game_description.k
        self.always_defect_mode = False

    def __call__(self, history: PlayerHistory) -> Action:
        if self.m / self.n > 0.75:
            if history.round_number > 0:
                cooperation_met_count = np.sum(history.opponent_cooperators >= self.m)
                if cooperation_met_count / history.round_number < 0.5:
                    return Action.D
        if history.round_number >= 3:
            last_three_rounds = history.opponent_cooperators[-3:]
            if np.all(last_three_rounds == 0):
                self.always_defect_mode = True
        if self.always_defect_mode:
            return Action.D
        if history.round_number == 0:
            return Action.C
        t = history.round_number
        last_coop_count = int(history.opponent_cooperators[-1])
        last_action = bool(history.my_actions[-1])
        if t == self.r - 1:
            near_miss = last_coop_count >= self.m - 1
            successful_rounds_count = np.sum(history.opponent_cooperators >= self.m)
            if successful_rounds_count >= t / 2 and near_miss:
                return Action.C
            return Action.D
        threshold_met_last = last_coop_count >= self.m
        if threshold_met_last:
            if last_action:
                return Action.C if random.random() < 0.9 else Action.D
            else:
                return Action.D
        elif last_coop_count >= self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_44(BaseStrategy):
    """
    Implements a Conditional Threshold Tracker strategy for the Collective Risk Dilemma.
    It calibrates in the first round, exploits success in subsequent rounds, 
    attempts recovery if the project is viable, and defects in the final round.
    It also accounts for high-reward scenarios by overriding defection if recent 
    collective performance is high.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.k = game_description.k
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if self.m > self.n:
            return Action.D
        if current_round == 0:
            return Action.C if self.k > 1 else Action.D
        if current_round == self.r - 1:
            return Action.D
        all_round_cooperators = []
        for i in range(current_round):
            my_contribution = 1 if history.my_actions[i] else 0
            total_c = history.opponent_cooperators[i] + my_contribution
            all_round_cooperators.append(total_c)
        if self.k > 1:
            recent_rounds = all_round_cooperators[-3:]
            success_count = sum((1 for c in recent_rounds if c >= self.m))
            if len(recent_rounds) >= 3 and success_count / len(recent_rounds) < 0.25:
                return Action.C
        prev_my_action = 1 if history.my_actions[-1] else 0
        prev_opp_count = history.opponent_cooperators[-1]
        prev_total_cooperators = prev_opp_count + prev_my_action
        if prev_total_cooperators >= self.m:
            return Action.D
        if any((h >= self.m - 1 for h in history.opponent_cooperators)):
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_45(BaseStrategy):
    """
    A strategy that aims to maximize personal utility by contributing to a public good
    threshold when necessary, defecting when the threshold is safe, and giving up 
    cooperation if the group fails to organize consistently.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_zeros = 0

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round_idx == total_rounds - 1:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        last_coop_count = history.opponent_cooperators[-1]
        if last_coop_count == 0:
            self.consecutive_zeros += 1
        else:
            self.consecutive_zeros = 0
        if self.consecutive_zeros >= 2:
            return Action.D
        if last_coop_count > m:
            return Action.D
        elif last_coop_count == m:
            if random.random() < 1.0 / m:
                return Action.C
            else:
                return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_46(BaseStrategy):
    """
    Implements Threshold-Adaptive Conditional Cooperation for the Collective Risk Dilemma.
    
    This strategy decides to cooperate (C) or defect (D) based on observed cooperation counts
    from previous rounds relative to the threshold m required to trigger the reward k.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        t = history.round_number + 1
        if t == 1:
            prob_success = (m - 1) / n if n > 0 else 0
            return Action.C if prob_success >= 0.5 else Action.D
        my_prev_action = history.my_actions[-1]
        others_prev = history.opponent_cooperators[-1]
        c_prev_total = int(my_prev_action) + others_prev
        if t == r:
            return Action.C if c_prev_total == m - 1 else Action.D
        if c_prev_total > m:
            return Action.D
        elif c_prev_total == m:
            return Action.C
        elif c_prev_total == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_47(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that transitions through three phases:
    1. Threshold Discovery (Round 0): Always Cooperate (C).
    2. Adaptive Response (Rounds 1 to r-2): Cooperate if previous round cooperators < m, otherwise Defect.
    3. Terminal Phase (Last Round): Always Defect (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == self.total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        prev_my_action = 1 if history.my_actions[-1] else 0
        prev_opponent_count = history.opponent_cooperators[-1]
        c_prev = prev_opponent_count + prev_my_action
        if c_prev >= self.m:
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_48(BaseStrategy):
    """
    Threshold-Conditional Tit-for-Tat (TCTT).
    
    A state-based strategy that prioritizes individual payoff maximization.
    - Initial round: Cooperates to signal willingness to coordinate.
    - Terminal round: Always defects.
    - During play:
      - Tracks the previous round's outcome (C_{t-1}).
      - If threshold m was met: Tests the group by switching to D (if currently C) or maintains D.
      - If threshold m was not met: Switches to C (if currently D) to re-coordinate or maintains D (if currently C) to prevent exploitation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.total_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        last_round_idx = history.round_number - 1
        my_last_action = Action.C if history.my_actions[last_round_idx] else Action.D
        opponents_cooperated = history.opponent_cooperators[last_round_idx]
        my_contribution = 1 if my_last_action == Action.C else 0
        total_cooperators = opponents_cooperated + my_contribution
        threshold_met = total_cooperators >= self.m
        if threshold_met:
            return Action.D
        elif my_last_action == Action.D:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_49(BaseStrategy):
    """
    Threshold-Responsive Trigger (TRT) strategy for the Collective Risk Dilemma.
    
    This strategy uses a threshold-based logic to determine cooperation:
    - Round 1: Always cooperates.
    - Rounds 2 to r-1:
        - If previous round total cooperators (C_prev) >= m: Cooperate (C).
        - If m-1 <= C_prev < m: Defect (D).
        - If C_prev < m-1: Defect (D).
    - Terminal Round (r):
        - If C_prev (from r-1) >= m: Cooperate (C).
        - Otherwise: Defect (D).
    
    Note: The 'opponent_cooperators' in history does not include self,
    so we adjust calculations to represent the total cooperation count.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_prev_action = int(history.my_actions[-1])
        c_prev_total = history.opponent_cooperators[-1] + my_prev_action
        m = self.game_description.m
        is_terminal_round = history.round_number == self.game_description.n_rounds - 1
        if is_terminal_round:
            if c_prev_total >= m:
                return Action.C
            else:
                return Action.D
        if c_prev_total >= m:
            return Action.C
        elif m - 1 <= c_prev_total < m:
            return Action.D
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_50(BaseStrategy):
    """
    A strategy that cooperates in the first round and subsequently triggers
    cooperation only if the group is exactly one person short of the
    required threshold (m-1 cooperators). It defects in the final round
    regardless of previous outcomes to maximize free-riding.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.total_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.total_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        o_prev = history.opponent_cooperators[-1]
        if o_prev == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_51(BaseStrategy):
    """
    Threshold-Dependent Tit-for-Tat (TDTFT).
    Prioritizes collective reward (k) while protecting against defection.
    Includes probe mechanisms and free-rider detection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.probe_interval = 3

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_my_action = 1 if history.my_actions[-1] else 0
        prev_opp_coop = int(history.opponent_cooperators[-1])
        c_prev = prev_opp_coop + prev_my_action
        if history.round_number == self.r - 1:
            if c_prev < self.m:
                return Action.D
            if c_prev > self.m:
                return Action.D
            return Action.C
        if c_prev > self.m:
            return Action.D
        if c_prev >= self.m:
            return Action.C
        current_t = history.round_number + 1
        if current_t % self.probe_interval == 0:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_52(BaseStrategy):
    """
    A Bayesian-updating strategy for the Collective Risk Dilemma.
    Maintains a sliding window estimate of opponent cooperation probabilities to
    calculate the expected utility of cooperation vs. defection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description
        self.window_size = 5
        self.n_opponents = self.game.n_players - 1

    def _get_probability_of_at_least_k(self, k: int, history: PlayerHistory) -> float:
        """
        Estimates the probability that at least k opponents cooperate,
        based on recent history.
        """
        if history.round_number == 0:
            prob = 0.0
            p = 0.5
            comb = 1.0
            for i in range(self.n_opponents + 1):
                pass
            total_subsets = 2 ** self.n_opponents
            favorable_subsets = 0
            for i in range(k, self.n_opponents + 1):
                favorable_subsets += math.comb(self.n_opponents, i)
            return favorable_subsets / total_subsets
        recent_opponents = history.opponent_cooperators[-self.window_size:]
        n_rounds = len(recent_opponents)
        successes = sum((1 for count in recent_opponents if count >= k))
        return successes / n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        if history.round_number == self.game.n_rounds - 1:
            return Action.D
        p_m_minus_1 = self._get_probability_of_at_least_k(self.game.m - 1, history)
        p_m = self._get_probability_of_at_least_k(self.game.m, history)
        avg_coop = np.mean(history.opponent_cooperators[-self.window_size:])
        if avg_coop > self.game.m + 1:
            return Action.D
        if p_m == 0:
            return Action.D
        eu_d = 1.0 + self.game.k * p_m_minus_1
        eu_c = 0.0 + self.game.k * p_m
        if eu_c > eu_d:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_53(BaseStrategy):
    """
    Implements a Conditional Threshold Strategy for the Collective Risk Dilemma.
    
    Logic:
    - Round 1: Cooperate (C).
    - Final Round: Defect (D).
    - If total cooperation in previous round (C_{t-1}) was 0: Defect for the remainder of the game.
    - If C_{t-1} >= m: Defect (Threshold met without my contribution).
    - If C_{t-1} == m - 1: Cooperate (Critical threshold rescue).
    - If C_{t-1} < m - 1: Defect (Inefficient to contribute).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.defected_permanently = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if self.defected_permanently:
            return Action.D
        prev_cooperators = history.opponent_cooperators[-1]
        my_prev_action = int(history.my_actions[-1])
        total_cooperators_prev = prev_cooperators + my_prev_action
        if total_cooperators_prev == 0:
            self.defected_permanently = True
            return Action.D
        if total_cooperators_prev >= self.game_description.m:
            return Action.D
        if total_cooperators_prev == self.game_description.m - 1:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_54(BaseStrategy):
    """
    A threshold-conditional trigger strategy for the Collective Risk Dilemma.
    
    Logic:
    - Round 0: Always Cooperate (C).
    - Round > 0:
        - If previous round's total cooperators (C_{t-1}) >= m: Defect (D) to maximize individual gain.
        - If previous round's total cooperators (C_{t-1}) == m - 1: Cooperate (C) to act as the pivotal player.
        - If previous round's total cooperators (C_{t-1}) < m - 1: Defect (D) as the threshold is unreachable.
        
    Note on 'opponent_cooperators' in history:
    - The history provides `opponent_cooperators`, which is the count of *other* players who cooperated.
    - To get the total number of cooperators ($C_t$), we must add this player's own contribution from that round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_opponent_count = history.opponent_cooperators[-1]
        prev_my_action = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = prev_opponent_count + prev_my_action
        m = self.game_description.m
        if total_cooperators_prev >= m:
            return Action.D
        elif total_cooperators_prev == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_55(BaseStrategy):
    """
    Conditional Tit-for-Tat with Threshold Sensitivity strategy.
    
    Logic:
    1. First round: Always cooperate to initiate coordination.
    2. Final round: If the threshold was safely met in the previous round (c_t-1 >= m+1),
       defect to exploit the collective. Otherwise, apply standard logic.
    3. Intermediate rounds:
       - If the threshold was met in the previous round, cooperate to secure the reward.
       - If my action contributes to hitting the threshold (others >= m-1), cooperate.
       - Otherwise, defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_prev_action = Action.C if history.my_actions[-1] else Action.D
        my_contrib = 1 if my_prev_action == Action.C else 0
        total_cooperators_last = history.opponent_cooperators[-1] + my_contrib
        if history.round_number == self.game.n_rounds - 1:
            if total_cooperators_last >= self.game.m + 1:
                return Action.D
        if total_cooperators_last >= self.game.m:
            return Action.C
        others_cooperated = history.opponent_cooperators[-1]
        if others_cooperated >= self.game.m - 1:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_56(BaseStrategy):
    """
    A threshold-conditional trigger strategy for the Collective Risk Dilemma.
    It monitors collective cooperation, probes for recovery after failure,
    and abandons cooperative efforts if the group remains persistently
    non-cooperative or if the threshold is safely exceeded.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.failed_rounds_count = 0
        self.max_allowable_failures = 0.25 * game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C if self.game_description.k > 1.0 else Action.D
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        r_remaining = r - current_round
        my_prev_action = 1 if history.my_actions[-1] else 0
        c_prev = history.opponent_cooperators[-1] + my_prev_action
        if c_prev < m:
            self.failed_rounds_count += 1
        if self.failed_rounds_count > self.max_allowable_failures:
            return Action.D
        if c_prev > m + 1:
            return Action.D
        if current_round == r - 1:
            return Action.C if c_prev >= m - 1 else Action.D
        if c_prev >= m:
            return Action.C
        else:
            prob_probe = (m - c_prev) / n
            if random.random() < prob_probe:
                return Action.C
            else:
                return Action.D

class Strategy_INDIVIDUALISTIC_57(BaseStrategy):
    """
    Trigger-Based Threshold Adaptation (TBTA):
    A strategy that plays D in the first and last rounds. In intermediate rounds,
    it exploits successful outcomes, attempts to tip near-failures into success,
    and abandons cooperation when insufficient support exists.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == self.r - 1:
            return Action.D
        if current_round == 0:
            return Action.D
        my_prev_action = int(history.my_actions[-1])
        c_prev = history.opponent_cooperators[-1] + my_prev_action
        if c_prev >= self.m:
            return Action.D
        if c_prev == self.m - 1:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_58(BaseStrategy):
    """
    Implements a Collective Risk Dilemma strategy that balances 
    threshold maintenance with individual payoff maximization.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        m = self.game.m
        r = self.game.n_rounds
        if current_round == 0:
            return Action.C
        if current_round == r - 1:
            return Action.D
        my_prev_action = 1 if history.my_actions[-1] else 0
        others_cooperated = history.opponent_cooperators[-1]
        total_cooperated = others_cooperated + my_prev_action
        if current_round >= 3:
            last_3_coop = history.opponent_cooperators[-3:] + np.array(history.my_actions[-3:], dtype=np.int_)
            if np.all(last_3_coop < m):
                return Action.D
        if total_cooperated > m:
            return Action.D
        if total_cooperated < m:
            return Action.C
        return Action.C

class Strategy_INDIVIDUALISTIC_59(BaseStrategy):
    """
    Implements a pivotal-cooperation strategy for the Collective Risk Dilemma.
    It defaults to Defect in the first round and the last round. In intervening
    rounds, it cooperates only if its contribution is the pivot needed to meet
    the cooperation threshold (m) and the reward (k) is greater than 1.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.r - 1:
            return Action.D
        if history.round_number == 0:
            return Action.D
        prev_my_action = int(history.my_actions[-1])
        c_obs_prev = history.opponent_cooperators[-1] + prev_my_action
        threshold_met = c_obs_prev >= self.m
        if threshold_met:
            return Action.D
        if c_obs_prev < self.m - 1:
            return Action.D
        if c_obs_prev == self.m - 1:
            if self.k > 1:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_INDIVIDUALISTIC_60(BaseStrategy):
    """
    Implements a Threshold-Targeted Conditional Reciprocity strategy for the 
    Collective Risk Dilemma.
    
    The strategy prioritizes:
    1. Parameter sensitivity (always defect if k <= 1).
    2. Threshold maintenance (contributing only if essential).
    3. Free-riding when safe (defecting if surplus cooperators exist).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        g = self.game_description
        if g.k <= 1:
            return Action.D
        if history.round_number == 0:
            if g.m / g.n_players >= 0.5:
                return Action.C
            return Action.D
        prev_my_action = 1 if history.my_actions[-1] else 0
        prev_opp_coop = int(history.opponent_cooperators[-1])
        prev_total_coop = prev_opp_coop + prev_my_action
        if history.round_number == g.n_rounds - 1:
            if prev_total_coop == g.m or prev_total_coop == g.m + 1:
                return Action.C
            return Action.D
        if prev_total_coop < g.m:
            return Action.D
        if prev_total_coop == g.m or prev_total_coop == g.m + 1:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_61(BaseStrategy):
    """
    Implements a Threshold-Targeting Trigger strategy for the Collective Risk Dilemma.
    - Plays Defect in the first round.
    - Subsequent rounds: conditional coordination based on previous cooperators count.
    - Includes Pivot Clause for threshold stability.
    - Includes End-Game Protocol based on recent performance.
    - Handles edge cases for low rewards (k <= 1) and tight thresholds (n-m <= 1).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if self.k <= 1.0:
            return Action.D
        round_idx = history.round_number
        if round_idx == 0:
            return Action.D
        prev_coop_count = int(history.opponent_cooperators[-1])
        prev_my_action = Action.C if history.my_actions[-1] else Action.D
        total_prev_coop = prev_coop_count + (1 if prev_my_action == Action.C else 0)
        if self.n - self.m <= 1:
            if total_prev_coop >= self.m - 1:
                return Action.C
        if round_idx == self.r - 1:
            lookback = min(3, round_idx)
            success_count = 0
            for i in range(1, lookback + 1):
                hist_idx = round_idx - i
                c_opp = int(history.opponent_cooperators[hist_idx])
                c_mine = 1 if history.my_actions[hist_idx] else 0
                if c_opp + c_mine >= self.m:
                    success_count += 1
            success_rate = success_count / lookback if lookback > 0 else 0
            if success_rate > 0.5:
                return Action.C
            else:
                return Action.D
        if total_prev_coop == self.m - 1:
            return Action.C
        if total_prev_coop >= self.m:
            if prev_my_action == Action.C:
                return Action.C
            else:
                return Action.C if random.random() < 0.5 else Action.D
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_62(BaseStrategy):
    """
    A conditional tit-for-tat strategy for the Collective Risk Dilemma.
    
    1. Initial Phase: Cooperate with probability m/n.
    2. Monitoring Phase:
       - If the threshold was met in the previous round, switch to or stay on Defect (D) to exploit.
       - If the threshold was not met, pivot: Cooperate only if that contribution pushes 
         the group over the threshold (m). Otherwise, Defect (D).
    3. Terminal Phase: Always Defect (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.p_c_initial = self.game_description.m / self.game_description.n_players

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C if random.random() < self.p_c_initial else Action.D
        my_last_action = history.my_actions[-1]
        last_round_coop_others = history.opponent_cooperators[-1]
        total_cooperators_last_round = last_round_coop_others + (1 if my_last_action else 0)
        if total_cooperators_last_round >= m:
            return Action.D
        if last_round_coop_others + 1 >= m:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_63(BaseStrategy):
    """
    Threshold-Dependent Reciprocity (TDR) strategy:
    Operates on conditional cooperation. Initially cooperates to test the waters.
    If the threshold is met, defects to freeride.
    If the threshold is missed but within one of the target (m-1), it persists in cooperation 
    to try and reach the target. Otherwise, it defects to conserve resources.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_index = history.round_number
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round_index == 0:
            return Action.C
        if current_round_index == total_rounds - 1:
            return Action.D
        prev_cooperators = history.opponent_cooperators[-1]
        prev_action = history.my_actions[-1]
        total_c_prev = prev_cooperators + (1 if prev_action else 0)
        if total_c_prev >= m:
            return Action.D
        if prev_action:
            if total_c_prev == m - 1:
                return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_INDIVIDUALISTIC_64(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that employs a threshold-sensitive
    conditional cooperation logic.

    Phase 1 (Round 0): Cooperates with probability m/n.
    Phase 2 (Rounds 1 to r-2):
        - If previous round's cooperation count C_prev >= m: Defect (redundant).
        - If C_prev == m - 1: Cooperate (threshold critical).
        - Otherwise (C_prev < m - 1): Defect (insufficient).
    Phase 3 (Round r-1):
        - If C_prev == m - 1: Cooperate.
        - Otherwise: Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            prob_c = self.m / self.n
            return Action.C if random.random() < prob_c else Action.D
        last_round_my_action = history.my_actions[-1]
        last_round_opponents_c = history.opponent_cooperators[-1]
        c_prev = last_round_opponents_c + (1 if last_round_my_action else 0)
        if current_round < self.r - 1:
            if c_prev >= self.m:
                return Action.D
            elif c_prev == self.m - 1:
                return Action.C
            else:
                return Action.D
        elif c_prev == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_65(BaseStrategy):
    """
    Threshold-Adaptive Trigger (TAT): A conditional strategy that cooperates initially,
    continues cooperation if the threshold is met, and exploits successful outcomes 
    when others carry the threshold, while attempting to be pivotal only when 
    a contribution guarantees success. Defection is used in the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        last_action = Action.C if history.my_actions[-1] else Action.D
        last_n_cooperators = history.opponent_cooperators[-1]
        total_c = last_n_cooperators + (1 if last_action == Action.C else 0)
        m = self.game_description.m
        if last_action == Action.C:
            if total_c >= m:
                return Action.C
            else:
                return Action.D
        elif total_c >= m:
            return Action.D
        elif total_c == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_66(BaseStrategy):
    """
    Implements a threshold-conditional trigger strategy for the Collective Risk Dilemma.
    
    Strategy:
    - Round 0 (1st round): Always defects.
    - Subsequent rounds:
        - If previous total cooperators >= m: Defect (free-ride).
        - If previous total cooperators == m - 1: Cooperate (tipping point).
        - If previous total cooperators < m - 1: Defect (conserve resources).
        
    Note on interpretation: The pseudocode and strategy description provided 
    specify 'previous_round_cooperators' as the metric. This variable is 
    provided in PlayerHistory as the count of *other* cooperators, but 
    the strategy logic depends on the *total* number of cooperators. 
    The logic below adjusts for the player's own contribution status.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        m = self.game_description.m
        last_opponent_coops = history.opponent_cooperators[-1]
        my_last_action = history.my_actions[-1]
        total_cooperators = last_opponent_coops + (1 if my_last_action else 0)
        if total_cooperators >= m:
            return Action.D
        elif total_cooperators == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_67(BaseStrategy):
    """
    Implements a Conditional Threshold-Triggered Tit-for-Tat strategy.
    
    Logic:
    - If k <= 1: Always Defect (D).
    - If round == r: Always Defect (D).
    - If round == 1: Cooperate (C) if k > 1.
    - Safety Override (Frustration): If consecutive_failures >= 2, Defect (D) for one round, then reset.
    - Primary Rule: 
        - If m=n: If any previous round was C < n, permanent Defect (D).
        - If m=1: Cooperate (C) only if previous was C == 0.
        - Otherwise: If previous round C >= m, Defect (D); else Cooperate (C).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failures = 0
        self.frustration_override = False
        self.impossible_threshold_reached = False

    def __call__(self, history: PlayerHistory) -> Action:
        if self.game_description.k <= 1:
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        my_prev_action = int(history.my_actions[-1])
        total_cooperators_prev = my_prev_action + history.opponent_cooperators[-1]
        if total_cooperators_prev < self.game_description.m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.frustration_override:
            self.frustration_override = False
            return Action.C
        if self.consecutive_failures >= 2:
            self.consecutive_failures = 0
            self.frustration_override = True
            return Action.D
        if self.game_description.m == self.game_description.n_players:
            if total_cooperators_prev < self.game_description.n_players:
                self.impossible_threshold_reached = True
            if self.impossible_threshold_reached:
                return Action.D
        if self.game_description.m == 1:
            if total_cooperators_prev >= 1:
                return Action.D
            else:
                return Action.C
        if total_cooperators_prev >= self.game_description.m:
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_68(BaseStrategy):
    """
    Tit-for-Tat with a Threshold strategy.
    Maintains cooperation as long as the threshold m is met, 
    with a status-based mechanism for probing and recovery.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.is_cooperative = True
        self.probe_interval = max(1, game_description.n_rounds // 4)

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        prev_opp_coop = history.opponent_cooperators[-1]
        prev_total = prev_opp_coop + (1 if my_prev_action else 0)
        if not self.is_cooperative:
            if history.round_number % self.probe_interval == 0:
                if prev_total >= self.game_description.m:
                    self.is_cooperative = True
        if self.is_cooperative:
            if prev_total < self.game_description.m:
                self.is_cooperative = False
                return Action.D
            if history.round_number == self.game_description.n_rounds - 1:
                return Action.C if prev_total > self.game_description.m else Action.D
            return Action.C
        if (history.round_number + 1) % self.probe_interval == 0:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_69(BaseStrategy):
    """
    Implements Conditional Threshold Tit-for-Tat (CT-TFT).
    Prioritizes the collective reward 'k' by coordinating contributions around
    the threshold 'm', while exploiting overshoot and defecting in the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        m = self.game_description.m
        total_rounds = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round == total_rounds - 1:
            return Action.D
        my_last_action = int(history.my_actions[-1])
        prev_cooperators = history.opponent_cooperators[-1] + my_last_action
        if prev_cooperators < m:
            return Action.D
        if prev_cooperators == m or prev_cooperators == m + 1:
            return Action.C
        if prev_cooperators >= m + 2:
            return Action.D
        return Action.D

class Strategy_INDIVIDUALISTIC_70(BaseStrategy):
    """
    A conditional tit-for-tat strategy for the Collective Risk Dilemma.
    
    The strategy cycles between 'contributive' and 'exploitative' states based on the threshold `m`.
    - Initial round: Cooperates to gauge group willingness.
    - Subsequent rounds:
        - If previous round failed (cooperators < m): Cooperate to restore success.
        - If previous round succeeded (cooperators >= m):
            - If previously Cooperated: If threshold was exactly met, Defect (to test stability); otherwise, Cooperate (safe).
            - If previously Defected: Continue Defecting (free-riding).
    - Terminal round: Always Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == n_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        my_last_action = history.my_actions[-1]
        n_my_last_coop = 1 if my_last_action else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + n_my_last_coop
        if total_cooperators_prev < m:
            return Action.C
        if my_last_action == Action.D:
            return Action.D
        if total_cooperators_prev == m:
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_71(BaseStrategy):
    """
    A threshold-conditional tit-for-tat strategy with signal testing and final round defection.
    
    Logic:
    1. Risk Assessment: If k <= 1, cooperation is net-negative; always defect.
    2. Final Round: Always defect.
    3. First Round: Always cooperate to signal intent.
    4. Intermediate Rounds: Cooperate if the previous round's total cooperation 
       met or exceeded the threshold 'm'; otherwise, defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.is_cooperation_viable = game_description.k > 1.0

    def __call__(self, history: PlayerHistory) -> Action:
        if not self.is_cooperation_viable:
            return Action.D
        round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if round_idx == total_rounds - 1:
            return Action.D
        if round_idx == 0:
            return Action.C
        my_prev_action = history.my_actions[-1]
        my_prev_contrib = 1 if my_prev_action else 0
        prev_total_cooperators = history.opponent_cooperators[-1] + my_prev_contrib
        if prev_total_cooperators >= m:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_72(BaseStrategy):
    """
    A strategy based on a dynamic threshold of reciprocated investment.
    Cooperates in the first round. In subsequent rounds, it acts based on whether
    the previous round's cooperation count met the threshold `m`.
    If the threshold was met, it cooperates to maintain the reward. If not, it
    defects to minimize individual loss.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_my_action = history.my_actions[-1]
        prev_coop_count = history.opponent_cooperators[-1]
        s_prev = prev_coop_count + (1 if prev_my_action else 0)
        if s_prev >= self.game_description.m:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_73(BaseStrategy):
    """
    Implements a strategy based on Collective Risk Dilemma decision rules:
    - Initial belief B=0.5, updated via a rolling window.
    - Decides based on Expected Value (EV) comparisons of cooperation vs. defection.
    - Incorporates Tit-for-Tat triggers based on previous threshold success.
    - Includes edge case handling for risk-aversion.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.b_estimate = 0.5
        self.n = game_description.n_players
        self.m = game_description.m
        self.k = game_description.k
        self.n_opponents = self.n - 1

    def _get_prob_threshold_met(self, cooperators_needed: int, b_estimate: float) -> float:
        """
        Calculates the probability that at least 'cooperators_needed' 
        others cooperate, assuming each follows probability b_estimate.
        Using Binomial CDF approximation (1 - CDF).
        """
        if cooperators_needed <= 0:
            return 1.0
        if cooperators_needed > self.n_opponents:
            return 0.0
        prob = 0.0
        for i in range(cooperators_needed, self.n_opponents + 1):
            ncr = math.comb(self.n_opponents, i)
            prob += ncr * b_estimate ** i * (1 - b_estimate) ** (self.n_opponents - i)
        return prob

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t > 0:
            window_size = 3
            recent_rounds = history.opponent_cooperators[-window_size:]
            avg_coop_rate = np.mean(recent_rounds) / self.n_opponents
            last_outcome = history.opponent_cooperators[-1] / self.n_opponents
            self.b_estimate = avg_coop_rate * 0.7 + last_outcome * 0.3
            self.b_estimate = max(0.0, min(1.0, self.b_estimate))
        if t == 0:
            if self.n_opponents * self.b_estimate >= self.m - 1:
                return Action.C
            return Action.D
        if t == self.game_description.n_rounds - 1:
            return Action.D
        prob_if_c = self._get_prob_threshold_met(self.m - 1, self.b_estimate)
        if prob_if_c < 1.0 / self.k:
            return Action.D
        prob_c = self._get_prob_threshold_met(self.m - 1, self.b_estimate)
        prob_d = self._get_prob_threshold_met(self.m, self.b_estimate)
        ev_c = prob_c * self.k - 1
        ev_d = prob_d * self.k + 1
        prev_others_coop = history.opponent_cooperators[-1]
        prev_my_action = history.my_actions[-1]
        threshold_met_prev = prev_others_coop + (1 if prev_my_action else 0) >= self.m
        override_action = None
        if not threshold_met_prev and prev_my_action:
            override_action = Action.D
        elif threshold_met_prev and (not prev_my_action):
            override_action = Action.C
        if override_action is not None:
            return override_action
        if ev_c > ev_d:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_74(BaseStrategy):
    """
    A conditional threshold strategy that alternates between cooperative enforcement 
    and defection optimization based on the previous round's outcome, 
    with a safeguard against the "Sucker Trap".
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.sucker_trap_count = 0
        self.permanent_defection = False

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round_idx == 0:
            return Action.C
        if current_round_idx == total_rounds - 1:
            return Action.D
        if self.permanent_defection:
            return Action.D
        last_round_idx = current_round_idx - 1
        opponents_cooperating = history.opponent_cooperators[last_round_idx]
        my_last_action = history.my_actions[last_round_idx]
        total_cooperators = opponents_cooperating + (1 if my_last_action else 0)
        if my_last_action and total_cooperators < m:
            self.sucker_trap_count += 1
        else:
            self.sucker_trap_count = 0
        if self.sucker_trap_count >= 3:
            self.permanent_defection = True
            return Action.D
        if total_cooperators >= m:
            return Action.D
        gap = m - total_cooperators
        if gap == 1:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_75(BaseStrategy):
    """
    Threshold-Sensitive Tit-for-Tat with Defection-to-Threshold (TS-TFT).
    
    Logic:
    - Round 1: Always Cooperate (C) if k > 1.
    - Final Round: Always Defect (D).
    - Middle Rounds:
      - If cumulative average of cooperators < m/2: Shift to unconditional Defect (D).
      - Else:
        - If previous round cooperators >= m: Defect (D).
        - If previous round cooperators == 0: Defect (D).
        - If previous round cooperators < m (but > 0): Cooperate (C).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.r = game_description.n_rounds
        self.k = game_description.k
        self.abandoned_cooperation = False

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            if self.k > 1:
                return Action.C
            return Action.D
        if current_round == self.r - 1:
            return Action.D
        if not self.abandoned_cooperation:
            total_cooperators_history = []
            for t in range(current_round):
                my_action_val = 1 if history.my_actions[t] else 0
                total_cooperators = history.opponent_cooperators[t] + my_action_val
                total_cooperators_history.append(total_cooperators)
            avg_cooperators = sum(total_cooperators_history) / len(total_cooperators_history)
            if avg_cooperators < self.m / 2:
                self.abandoned_cooperation = True
        if self.abandoned_cooperation:
            return Action.D
        my_prev_action = 1 if history.my_actions[-1] else 0
        c_obs_prev = history.opponent_cooperators[-1] + my_prev_action
        if c_obs_prev == 0:
            return Action.D
        if c_obs_prev >= self.m:
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_76(BaseStrategy):
    """
    Implements a Threshold Trigger-Contingent Cooperation strategy.
    
    The strategy maximizes personal payoff by defecting (free-riding) whenever possible
    and only contributing (Cooperating) when the reward threshold 'm' is reachable 
    strictly by adding one's own contribution to the existing pool of cooperators.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if self.k <= 1.0:
            return Action.D
        if history.round_number == 0:
            return Action.D
        last_coop_count = history.opponent_cooperators[-1]
        if last_coop_count >= self.m:
            return Action.D
        elif last_coop_count == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_77(BaseStrategy):
    """
    Implements a Conditional Tit-for-Tat with Threshold Sensitivity.
    Prioritizes individual payoff maximization by attempting to coordinate only when necessary 
    to trigger the threshold 'm', and defecting otherwise to exploit or preserve private resources.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.D
        prev_S = history.opponent_cooperators[-1]
        prev_my_action = Action.C if history.my_actions[-1] else Action.D
        my_contrib = 1 if prev_my_action == Action.C else 0
        total_S = prev_S + my_contrib
        if total_S >= self.game_description.m:
            if prev_my_action == Action.C:
                p = self.game_description.m / total_S
                return Action.C if random.random() < p else Action.D
            else:
                return Action.D
        else:
            if prev_my_action == Action.D and total_S == self.game_description.m - 1:
                return Action.C
            return Action.D

class Strategy_INDIVIDUALISTIC_78(BaseStrategy):
    """
    Threshold-Targeting Reciprocity: A conditional cooperator strategy.
    
    1. Plays C in the first round.
    2. Monitors the previous round's cooperation count.
    3. Triggers permanent defection if the previous round's cooperation count < m.
    4. Only cooperates if k > 1.
    5. Implements end-game adjustments to protect against exploitation when the 
       threshold is exactly met.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.failed_threshold = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_coop_count = history.opponent_cooperators[-1]
        my_prev_action = 1 if history.my_actions[-1] else 0
        total_prev_coop = prev_coop_count + my_prev_action
        if total_prev_coop < self.game_description.m:
            self.failed_threshold = True
        if self.failed_threshold:
            return Action.D
        if self.game_description.k <= 1.0:
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            if total_prev_coop == self.game_description.m:
                return Action.D
            return Action.C
        return Action.C

class Strategy_INDIVIDUALISTIC_79(BaseStrategy):
    """
    Implements a Conditional Trigger strategy for the Collective Risk Dilemma.
    
    Logic summary:
    1. Round 0: Always Defect (D).
    2. Round t > 0:
       - If previous round (t-1) threshold reached (Nc >= m):
         - If we played C, continue C.
         - If we played D, continue D (Free-ride).
       - If previous round (t-1) threshold not reached:
         - If Nc == m - 1, Pivot (C) to meet threshold.
         - Otherwise, Defect (D).
    3. Final Round: Apply dominant-strategy subgame logic (D if possible, otherwise C if profitable).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.k = game_description.k
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        prev_my_action = 1 if history.my_actions[-1] else 0
        prev_opp_cooperators = history.opponent_cooperators[-1]
        prev_total_cooperators = prev_opp_cooperators + prev_my_action
        if current_round == self.n_rounds - 1:
            if prev_total_cooperators >= self.m:
                return Action.D
            elif prev_total_cooperators == self.m - 1:
                return Action.C
            else:
                return Action.D
        if prev_total_cooperators >= self.m:
            if prev_my_action == 1:
                return Action.C
            else:
                return Action.D
        elif prev_total_cooperators == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_80(BaseStrategy):
    """
    Implements a Conditional Threshold Tit-for-Tat strategy.
    
    Logic:
    - Round 1: Cooperate.
    - Last Round: Defect.
    - If failed to reach threshold (m cooperators) for 3 consecutive rounds: Defect permanently.
    - Otherwise:
        - If previous round met threshold (>= m): Defect.
        - If previous round failed threshold (< m): Cooperate.
        
    Note: The 'opponent_cooperators' array in PlayerHistory counts *only* the opponents.
    The total number of cooperators is opponent_cooperators + (1 if I played C else 0).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.desc.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        prev_round_idx = history.round_number - 1
        my_prev_action = history.my_actions[prev_round_idx]
        prev_total_cooperators = history.opponent_cooperators[prev_round_idx] + (1 if my_prev_action else 0)
        if history.round_number >= 3:
            failed_counts = []
            for i in range(1, 4):
                idx = history.round_number - i
                my_act = history.my_actions[idx]
                opp_act = history.opponent_cooperators[idx]
                total = opp_act + (1 if my_act else 0)
                failed_counts.append(total < self.desc.m)
            if all(failed_counts):
                return Action.D
        if prev_total_cooperators >= self.desc.m:
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_81(BaseStrategy):
    """
    Implements Threshold-Conditional Reciprocity.
    
    The strategy acts as a conditional cooperator, serving as a 'swing voter' 
    to ensure the collective threshold 'm' is met while minimizing personal 
    contribution costs.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        my_prev_action = 1 if history.my_actions[-1] else 0
        opp_prev_count = history.opponent_cooperators[-1]
        prev_total_cooperators = opp_prev_count + my_prev_action
        m = self.game_description.m
        if prev_total_cooperators >= m:
            return Action.D
        if prev_total_cooperators + 1 >= m:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_82(BaseStrategy):
    """
    A Tit-for-Tat with Threshold Sensitivity strategy for the Collective Risk Dilemma.
    It cooperates to probe, maintains support if the threshold is met, pushes if
    near-threshold, and defects if the group is unlikely to succeed. Includes
    logic to reset once if cooperation collapses, and defects on the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.consecutive_failed_rounds = 0
        self.has_reset_once = False
        self.defecting_mode = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        n = self.game_description.n_players
        m = self.game_description.m
        my_last_action = history.my_actions[-1]
        last_opponents = history.opponent_cooperators[-1]
        c_t_minus_1 = (1 if my_last_action else 0) + last_opponents
        if c_t_minus_1 < m:
            self.consecutive_failed_rounds += 1
        else:
            self.consecutive_failed_rounds = 0
        if not self.defecting_mode and self.consecutive_failed_rounds >= 2:
            if not self.has_reset_once:
                self.has_reset_once = True
                self.consecutive_failed_rounds = 0
                return Action.C
            else:
                self.defecting_mode = True
        if self.defecting_mode:
            return Action.D
        if c_t_minus_1 >= m:
            return Action.C
        if c_t_minus_1 == m - 1:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_83(BaseStrategy):
    """
    Threshold-Adaptive Trigger (TAT) strategy.
    
    Dynamically adjusts cooperation based on the collective behavior of the group.
    - Round 1: Cooperates if k > 1.
    - Mid-game: Cooperates if the group is at the tipping point (m-1) to trigger the reward, 
      defects if the goal is met or the group is too far from the goal.
    - Final round: Cooperates if the goal is attainable (m-1), defects otherwise.
    - Persistence: If coordination consistently fails (never reaching m in the past), 
      switches to permanent defection.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.n = game_description.n_players
        self.k = game_description.k
        self.n_rounds = game_description.n_rounds
        self.has_ever_met_threshold = False

    def __call__(self, history: PlayerHistory) -> Action:
        if self.k <= 1:
            return Action.D
        round_idx = history.round_number
        if round_idx > 0:
            my_last_action_val = 1 if history.my_actions[-1] else 0
            prev_total_cooperators = my_last_action_val + history.opponent_cooperators[-1]
            if prev_total_cooperators >= self.m:
                self.has_ever_met_threshold = True
        if round_idx == 0:
            return Action.C
        if not self.has_ever_met_threshold and round_idx > 1:
            return Action.D
        c_prev = history.opponent_cooperators[-1]
        my_prev_action = 1 if history.my_actions[-1] else 0
        c_prev_total = c_prev + my_prev_action
        if round_idx == self.n_rounds - 1:
            if c_prev_total >= self.m - 1:
                return Action.C
            else:
                return Action.D
        if c_prev_total >= self.m:
            return Action.D
        elif c_prev_total == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_84(BaseStrategy):
    """
    Implements a strategic approach for the Collective Risk Dilemma.
    Decisions are based on threshold compliance, adaptive cooperation based on recent trends,
    and a final-round utility maximization check.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            if (self.n - 1) / 2 >= self.m:
                return Action.C
            return Action.D
        last_round_idx = history.round_number - 1
        i_last_played_c = int(history.my_actions[last_round_idx])
        total_cooperators_last = history.opponent_cooperators[last_round_idx] + i_last_played_c
        if total_cooperators_last < self.m:
            return Action.D
        lookback = min(3, history.round_number)
        recent_total_cooperators = []
        for r_idx in range(history.round_number - lookback, history.round_number):
            c_val = int(history.my_actions[r_idx])
            opp_val = history.opponent_cooperators[r_idx]
            recent_total_cooperators.append(opp_val + c_val)
        avg_cooperators = sum(recent_total_cooperators) / len(recent_total_cooperators)
        if avg_cooperators > self.m:
            return Action.D
        elif avg_cooperators == self.m:
            return Action.C
        else:
            return Action.C
        if history.round_number == self.r - 1:
            all_total_coops = [history.opponent_cooperators[i] + int(history.my_actions[i]) for i in range(history.round_number)]
            hist_avg = sum(all_total_coops) / len(all_total_coops)
            if hist_avg >= self.m:
                return Action.D
            else:
                if history.opponent_cooperators[-1] + 1 >= self.m:
                    return Action.C
                return Action.D

class Strategy_INDIVIDUALISTIC_85(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that monitors the collective threshold.
    
    Logic summary:
    1. First round: Cooperate.
    2. Last round: Cooperate if threshold was met in previous round, else Defect.
    3. Intermediate rounds:
       - If goal met previously, maintain cooperation.
       - If goal missed:
         - Calculate gap. If gap == 1 and we cooperated, test with 50% probability.
         - Else, Defect.
       - Edge cases:
         - "Persistent Defection": If cooperation failed for 3 consecutive rounds, switch to Defect.
         - "Threshold Excess": If excess cooperation observed, maximize gain by Defecting (though this logic is secondary to maintaining the threshold, implemented as an optional optimization).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game = game_description
        self.consecutive_failures = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        n = self.game.n_players
        m = self.game.m
        r = self.game.n_rounds
        my_prev_action_val = 1 if history.my_actions[-1] else 0
        total_cooperators_prev = history.opponent_cooperators[-1] + my_prev_action_val
        if total_cooperators_prev < m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 3:
            return Action.D
        if history.round_number == r - 1:
            return Action.C if total_cooperators_prev >= m else Action.D
        if total_cooperators_prev >= m:
            if total_cooperators_prev > m:
                return Action.D
            return Action.C
        if not history.my_actions[-1]:
            return Action.D
        gap = m - total_cooperators_prev
        if gap == 1:
            return Action.C if random.random() < 0.5 else Action.D
        return Action.D

class Strategy_INDIVIDUALISTIC_86(BaseStrategy):
    """
    Implements a Conditional Threshold Tracker strategy for the Collective Risk Dilemma.
    
    Logic:
    - Round 1: Always Cooperate (C).
    - Rounds 2 to r-1: 
        - If C_prev >= m: Defect (D) to test/exploit threshold.
        - If C_prev < m: Cooperate (C) to restore threshold.
    - Round r: Always Defect (D).
    - Edge Cases:
        - If k <= 1, always Defect.
        - If C_prev was 0 for two consecutive rounds, switch to always Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.k = game_description.k
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.zero_streak_count = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if self.k <= 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        my_last_action = 1 if history.my_actions[-1] else 0
        c_prev = history.opponent_cooperators[-1] + my_last_action
        if c_prev == 0:
            self.zero_streak_count += 1
        else:
            self.zero_streak_count = 0
        if self.zero_streak_count >= 2:
            return Action.D
        current_round_idx = history.round_number
        is_final_round = current_round_idx == self.r - 1
        if is_final_round:
            return Action.D
        if c_prev >= self.m:
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_87(BaseStrategy):
    """
    Implements a Threshold-Conditioned Tit-for-Tat with Defection-Trigger.
    - Round 1: Defects.
    - Subsequent Rounds:
        - If previous project was failed (< m cooperators): Defect.
        - If previous project was exactly at threshold (== m): Cooperate to sustain the project.
        - If previous project was successful (> m): Defect to free-ride.
    - Terminal Phase: The strategy logic naturally handles the terminal phase through the previous round evaluation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        my_prev_action = int(history.my_actions[-1])
        other_prev_cooperators = int(history.opponent_cooperators[-1])
        total_prev_cooperators = my_prev_action + other_prev_cooperators
        if total_prev_cooperators < self.m:
            return Action.D
        if total_prev_cooperators == self.m:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_88(BaseStrategy):
    """
    Threshold-Conditional Tit-for-Tat with Defection-Risk Thresholding.
    
    Operates on conditional cooperation: 
    - Cooperates in the first round.
    - If threshold met in previous round: probabilistic defection to test for free-riding.
    - If threshold missed: punishes if contributed but count too low (< m-1), else attempts to bridge gap.
    - Always defects in the last round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_idx = history.round_number
        last_round_idx = self.game_description.n_rounds - 1
        if current_round_idx == last_round_idx:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        my_last_action = Action.C if history.my_actions[-1] else Action.D
        c_last = history.opponent_cooperators[-1] + (1 if my_last_action == Action.C else 0)
        m = self.game_description.m
        n = self.game_description.n_players
        if c_last >= m:
            prob_defect = 1.0 / (n - m + 1)
            if random.random() < prob_defect:
                return Action.D
            else:
                return Action.C
        else:
            if my_last_action == Action.D:
                return Action.C
            if c_last >= m - 1:
                return Action.C
            else:
                return Action.D

class Strategy_INDIVIDUALISTIC_89(BaseStrategy):
    """
    Threshold-Responsive Trigger (TRT) Strategy.
    
    1. First round: Cooperate.
    2. Last round: Defect.
    3. Zero Cooperation Clause: If zero total cooperators in previous round, Defect forever.
    4. Excessive Cooperation/Payoff Clause: If k < 2 (meaning payoff for Cooperating is less than Defecting), Defect forever.
    5. Success Condition: If threshold m met in prev round, Defect.
    6. Failure Condition: If threshold m not met in prev round, Cooperate.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.permanent_defect = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        if self.permanent_defect:
            return Action.D
        my_prev_action = 1 if history.my_actions[-1] else 0
        opp_prev_coop = history.opponent_cooperators[-1]
        total_cooperators_prev = opp_prev_coop + my_prev_action
        if total_cooperators_prev == 0:
            self.permanent_defect = True
            return Action.D
        if self.game_description.k < 2:
            self.permanent_defect = True
            return Action.D
        if total_cooperators_prev >= self.game_description.m:
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_90(BaseStrategy):
    """
    Implements a Collective Risk Dilemma strategy with state-dependent behavior.
    Tracks success thresholds to transition between Neutral, Cooperative, and Exploited states.
    Includes persistence checks and end-of-game logic.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.state = 'Neutral'
        self.consecutive_failure_count = 0

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        prev_idx = t - 1
        my_prev_action = Action.C if history.my_actions[prev_idx] else Action.D
        my_prev_val = 1 if my_prev_action == Action.C else 0
        c_prev = history.opponent_cooperators[prev_idx] + my_prev_val
        m = self.game_description.m
        if c_prev < m:
            self.consecutive_failure_count += 1
        else:
            self.consecutive_failure_count = 0
        if self.consecutive_failure_count >= 3:
            return Action.D
        if t == self.game_description.n_rounds - 1:
            return Action.D if c_prev >= m else Action.C
        if c_prev >= m:
            if my_prev_action == Action.C and c_prev > m:
                self.state = 'Cooperative'
            elif my_prev_action == Action.D and c_prev >= m:
                self.state = 'Exploited'
            else:
                self.state = 'Neutral'
        else:
            self.state = 'Neutral'
        if self.state == 'Cooperative':
            return Action.C if random.random() < 0.9 else Action.D
        else:
            return Action.C if c_prev < m else Action.D

class Strategy_INDIVIDUALISTIC_91(BaseStrategy):
    """
    A conditional threshold-matching strategy for the Collective Risk Dilemma.
    
    Logic:
    - Round 1: Always Cooperate (C).
    - If Last Round >= m: Cooperate (C) if I cooperated last, else Defect (D).
    - If Last Round < m: Cooperate (C) to try and meet threshold, unless market failure detected.
    - Market Failure: If N_c(1) < m and N_c(2) < m, switch to Defect (D) permanently.
    - Last Round (r): Always Defect (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.market_failed = False

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_idx = history.round_number
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round_idx == total_rounds - 1:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        last_cooperators = history.opponent_cooperators[-1]
        my_last_action_val = 1 if history.my_actions[-1] else 0
        total_cooperators = last_cooperators + my_last_action_val
        if current_round_idx > 1 and (not self.market_failed):
            r0_c = history.opponent_cooperators[0] + (1 if history.my_actions[0] else 0)
            r1_c = history.opponent_cooperators[1] + (1 if history.my_actions[1] else 0)
            if r0_c < m and r1_c < m:
                self.market_failed = True
        if self.market_failed:
            return Action.D
        if total_cooperators >= m:
            if history.my_actions[-1]:
                return Action.C
            else:
                return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_92(BaseStrategy):
    """
    Dynamic Threshold Conditional Cooperation (DTCC).
    This strategy implements a Conditional Tit-for-Tat approach with a greedy exit:
    - Cooperates in the first round.
    - Defects in the last round.
    - If the threshold was comfortably met (>= m+1) in the previous round, it defects to save costs.
    - If the threshold was exactly met (= m), it cooperates to maintain stability.
    - If the group fails to reach the threshold (< m), it defects, unless a 'panic' trigger
      is met (3 consecutive defections + consistent total failure), at which point it 
      attempts to signal cooperation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        my_prev_action = 1 if history.my_actions[-1] else 0
        h_prev = history.opponent_cooperators[-1] + my_prev_action
        m = self.game_description.m
        if h_prev >= m + 1:
            return Action.D
        if h_prev == m:
            return Action.C
        if h_prev < m:
            consecutive_d_rounds = 0
            for action in reversed(history.my_actions):
                if action == False:
                    consecutive_d_rounds += 1
                else:
                    break
            consistent_failure = False
            if history.round_number >= 3:
                c_minus_1 = history.opponent_cooperators[-1] + (1 if history.my_actions[-1] else 0)
                c_minus_2 = history.opponent_cooperators[-2] + (1 if history.my_actions[-2] else 0)
                c_minus_3 = history.opponent_cooperators[-3] + (1 if history.my_actions[-3] else 0)
                if c_minus_1 == 0 and c_minus_2 == 0 and (c_minus_3 == 0):
                    consistent_failure = True
            if consecutive_d_rounds >= 3 and consistent_failure:
                return Action.C
            return Action.D
        return Action.D

class Strategy_INDIVIDUALISTIC_93(BaseStrategy):
    """
    Implements a Conditional Threshold Strategy.
    - Round 1: Cooperate (Probe).
    - Rounds 2 to r-1:
        - Sustainable (N_c >= m): Cooperate.
        - Marginal (N_c == m-1): Cooperate.
        - Failed (N_c < m-1): Defect.
        - Special 'Betrayal Pivot': If exactly m cooperators for 3 consecutive rounds, test Defection.
    - Endgame (Round r): Always Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.betrayal_mode = False

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.desc.n_rounds
        m = self.desc.m
        if current_round == 0:
            return Action.C
        if current_round == total_rounds - 1:
            return Action.D
        last_my_action = history.my_actions[-1]
        last_opp_c = history.opponent_cooperators[-1]
        n_c_last = last_opp_c + (1 if last_my_action else 0)
        history_n_c = []
        for i in range(len(history.my_actions)):
            c_count = history.opponent_cooperators[i] + (1 if history.my_actions[i] else 0)
            history_n_c.append(c_count)
        if len(history_n_c) >= 3 and all((h == m for h in history_n_c[-3:])):
            self.betrayal_mode = True
        if self.betrayal_mode:
            if n_c_last == m - 1:
                return Action.D
            elif n_c_last < m - 1:
                self.betrayal_mode = False
                return Action.C
            else:
                return Action.D
        if n_c_last >= m:
            return Action.C
        if n_c_last == m - 1:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_94(BaseStrategy):
    """
    A strategy that implements a sliding window conditional trigger.
    Defects in the first and last rounds.
    In intermediate rounds:
    - Defects if the threshold was met in the previous round.
    - Cooperates if only one more contributor is needed to reach the threshold.
    - Defects otherwise.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        is_first_round = current_round == 0
        is_last_round = current_round == self.game_description.n_rounds - 1
        if is_first_round or is_last_round:
            return Action.D
        previous_opp_count = history.opponent_cooperators[-1]
        self_was_cooperator = int(history.my_actions[-1])
        total_cooperators = previous_opp_count + self_was_cooperator
        m = self.game_description.m
        if total_cooperators >= m:
            return Action.D
        if m - total_cooperators == 1:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_95(BaseStrategy):
    """
    Trigger-Threshold Adaptation (TTA) Strategy:
    A conditional cooperation mechanism that adapts to the number of cooperators observed.
    It cooperates in the first round, maintains cooperation if the threshold m is met, 
    attempts probabilistic recovery on near-misses (m-1), and defaults to defection 
    after persistent failure.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.m = game_description.m
        self.total_rounds = game_description.n_rounds
        self.consecutive_failures = 0

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        last_my_action = history.my_actions[-1]
        c_prev = history.opponent_cooperators[-1] + (1 if last_my_action else 0)
        if c_prev < self.m:
            self.consecutive_failures += 1
        else:
            self.consecutive_failures = 0
        if self.consecutive_failures >= 2 and c_prev < self.m - 1:
            return Action.D
        if current_round == self.total_rounds - 1:
            return Action.C if c_prev >= self.m else Action.D
        if c_prev >= self.m:
            return Action.C
        elif c_prev == self.m - 1:
            if random.random() < self.m / self.n:
                return Action.C
            return Action.D
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_96(BaseStrategy):
    """
    Threshold-Contingent Trigger with Probabilistic Forgiveness.
    
    This strategy uses a conditional Tit-for-Tat approach to achieve the collective
    threshold 'm' while minimizing individual losses. It includes state-tracking
    for successful rounds and consecutive failures to determine adaptive behavior.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.history_threshold_met_count = 0
        self.consecutive_zeros = 0
        self.last_self_action = Action.C

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            self.last_self_action = Action.C
            return Action.C
        prev_obs = int(history.opponent_cooperators[-1])
        my_prev_action = self.last_self_action
        total_cooperators = prev_obs + (1 if my_prev_action == Action.C else 0)
        if total_cooperators >= self.game_description.m:
            self.history_threshold_met_count += 1
            self.consecutive_zeros = 0
        elif total_cooperators == 0:
            self.consecutive_zeros += 1
        else:
            self.consecutive_zeros = 0
        if history.round_number == self.game_description.n_rounds - 1:
            threshold_ratio = self.history_threshold_met_count / history.round_number
            if threshold_ratio >= 0.5:
                action = Action.C
            else:
                action = Action.D
            self.last_self_action = action
            return action
        action = Action.D
        if total_cooperators >= self.game_description.m:
            if my_prev_action == Action.C:
                action = Action.C
            else:
                action = Action.C if random.random() < 0.5 else Action.D
        elif my_prev_action == Action.C and prev_obs == self.game_description.m - 1:
            action = Action.C
        elif self.consecutive_zeros >= 2 and random.random() < 0.2:
            action = Action.C
        else:
            action = Action.D
        self.last_self_action = action
        return action

class Strategy_INDIVIDUALISTIC_97(BaseStrategy):
    """
    Implements a conditional contribution strategy for the Collective Risk Dilemma.
    Rules:
    - Round 1: Defect (D).
    - Rounds t > 1:
        - If C_prev >= m: Maintain status (if C then C, if D then D).
        - If C_prev < m:
            - If deficit d = m - C_prev:
                - If C and d == 1: Maintain C.
                - If D and d > 1: Maintain D.
                - If C and d == 0 (redundant logic handled by C_prev >= m clause, but implies success): Switch D.
                - If D and d == 1: Switch C.
        - Redundancy check: If C_prev > m, switch to D.
        - Restoration check: If C_prev dropped from m to m-1, switch to C.
    - Last Round: Defect (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        if history.round_number == self.r - 1:
            return Action.D
        prev_round = history.round_number - 1
        my_prev_action = 1 if history.my_actions[prev_round] else 0
        c_prev_total = history.opponent_cooperators[prev_round] + my_prev_action
        status_prev = my_prev_action
        if c_prev_total > self.m:
            return Action.D
        if history.round_number > 1:
            prev_prev_round = history.round_number - 2
            my_prev_prev_action = 1 if history.my_actions[(prev_prev_prev_action := prev_prev_round)] else 0
            c_prev_prev_total = history.opponent_cooperators[prev_prev_round] + my_prev_prev_action
            if c_prev_prev_total == self.m and c_prev_total == self.m - 1:
                return Action.C
        if self.k > 1:
            if c_prev_total >= self.m:
                return Action.C if status_prev == 1 else Action.D
            else:
                deficit = self.m - c_prev_total
                if status_prev == 1:
                    if deficit == 1:
                        return Action.C
                    else:
                        return Action.D
                elif deficit > 1:
                    return Action.D
                elif deficit == 1:
                    return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_98(BaseStrategy):
    """
    Implements a threshold-seeking conditional probabilistic strategy.
    
    The strategy attempts to coordinate on the minimum threshold 'm' needed to 
    maximize individual payoffs. It starts with cooperation, probes for efficiency 
    by defecting with probability when excess cooperators exist, attempts recovery 
    when the threshold fails, and abandons cooperation if the collective proves 
    unreliable. It also features terminal defection in the final round and 
    anchoring behavior to stabilize volatile thresholds.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.failed_trigger_count = 0
        self.anchor_rounds_remaining = 0
        self.has_abandoned = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.desc.n_players
        m = self.desc.m
        k = self.desc.k
        r = self.desc.n_rounds
        if k <= 1.0:
            return Action.D
        if history.round_number == r - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        prev_round = history.round_number - 1
        prev_my_action = 1 if history.my_actions[prev_round] else 0
        total_cooperators = history.opponent_cooperators[prev_round] + prev_my_action
        if total_cooperators < m:
            self.failed_trigger_count += 1
        else:
            self.failed_trigger_count = 0
        if self.failed_trigger_count >= 3:
            self.has_abandoned = True
            return Action.D
        if self.has_abandoned:
            return Action.D
        if history.round_number > 1:
            curr_val = total_cooperators
            prev_val = history.opponent_cooperators[prev_round - 1] + (1 if history.my_actions[prev_round - 1] else 0)
            if abs(curr_val - prev_val) >= math.sqrt(n):
                self.anchor_rounds_remaining = 2
        if self.anchor_rounds_remaining > 0:
            self.anchor_rounds_remaining -= 1
            return Action.C
        if total_cooperators >= m:
            excess = total_cooperators - m
            if excess == 0:
                return Action.C
            else:
                p = 1.0 - m / total_cooperators
                if random.random() < p:
                    return Action.D
                return Action.C
        else:
            if total_cooperators == m - 1:
                return Action.C
            return Action.C

class Strategy_INDIVIDUALISTIC_99(BaseStrategy):
    """
    Implements a Conditional Threshold Commitment strategy.
    
    This strategy monitors the community's cooperation level relative to the threshold m.
    It defects by default, cooperates only when pivotal (m-1 cooperators detected),
    and punishes the collective by defecting if a cooperative effort (C) failed to 
    meet the threshold.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        m = self.game_description.m
        prev_opp_coop = int(history.opponent_cooperators[-1])
        prev_my_action = bool(history.my_actions[-1])
        my_contribution = 1 if prev_my_action else 0
        total_cooperators = prev_opp_coop + my_contribution
        if total_cooperators >= m:
            return Action.D
        if prev_my_action:
            return Action.D
        if total_cooperators == m - 1:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_100(BaseStrategy):
    """
    Conditional Threshold Thresholding (CTT) Strategy:
    - Round 1: Cooperate with probability m/n.
    - Rounds 2 to r-1:
        - If previous round cooperators >= m: Defect (exploit).
        - If previous round cooperators == m-1: Cooperate (clinch threshold).
        - If previous round cooperators < m-1: Defect (conserve).
        - Systemic Failure Rule: If the threshold (m) is not met for 3 consecutive rounds,
          switch to permanent Defection.
    - Final Round: Defect to capture final endowment, unless trailing in payoff.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.failure_counter = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            prob_coop = m / n
            return Action.C if random.random() < prob_coop else Action.D
        my_prev_action = history.my_actions[-1]
        last_total_cooperators = history.opponent_cooperators[-1] + (1 if my_prev_action else 0)
        if last_total_cooperators < m:
            self.failure_counter += 1
        else:
            self.failure_counter = 0
        if self.failure_counter >= 3:
            return Action.D
        if current_round == r - 1:
            my_total_payoff = np.sum(history.my_payoffs)
            avg_payoff = np.mean(history.my_payoffs)
            if my_total_payoff >= avg_payoff:
                return Action.D
            else:
                return Action.C if history.opponent_cooperators[-1] == m - 1 else Action.D
        last_s = history.opponent_cooperators[-1]
        if last_s >= m:
            return Action.D
        elif last_s == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_101(BaseStrategy):
    """
    Threshold-Contingent Trigger Strategy:
    - Round 0: Always Cooperate (C) to test group reliability.
    - Rounds 1 to n-1: If the previous round's cooperation count (by all players) 
      met or exceeded the threshold 'm', Cooperate (C). Otherwise, Defect (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        last_round_idx = current_round - 1
        opponents_cooperated = history.opponent_cooperators[last_round_idx]
        my_last_action = history.my_actions[last_round_idx]
        total_cooperators_last_round = opponents_cooperated + (1 if my_last_action else 0)
        if total_cooperators_last_round >= self.game_description.m:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_102(BaseStrategy):
    """
    Threshold-Dependent Conditional Cooperation strategy.
    
    In the first round, cooperates.
    In subsequent rounds, analyzes the previous round's cooperative count (O_{t-1}).
    - If O_{t-1} is exactly m - 1 (pivotal), it cooperates to trigger the reward.
    - Otherwise, it defects to save costs.
    If the reward factor k <= 1, it defects in all rounds.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if self.game_description.k <= 1.0:
            return Action.D
        if history.round_number == 0:
            return Action.C
        previous_my_action = history.my_actions[-1]
        previous_opponent_cooperators = history.opponent_cooperators[-1]
        o_prev = int(previous_my_action) + previous_opponent_cooperators
        if o_prev == self.game_description.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_103(BaseStrategy):
    """
    A conditional trigger-based strategy for the Collective Risk Dilemma.
    It optimizes individual returns by defecting when the threshold is met,
    conditionally cooperating to restore coordination, and switching to 
    a permanent defection or mixed strategy based on history stability.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.persistent_defection_mode = False
        self.failed_threshold_count = 0
        self.volatility_counter = 0
        self.last_was_coop = False
        self.mixed_strategy_mode = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            self.last_was_coop = True
            return Action.C
        if self.persistent_defection_mode:
            return Action.D
        prev_my_action = int(self.last_was_coop)
        prev_opp_coop = history.opponent_cooperators[-1]
        S = prev_opp_coop + prev_my_action
        threshold_met = S >= self.game_description.m
        if not threshold_met:
            self.failed_threshold_count += 1
            self.volatility_counter = 0
        else:
            self.failed_threshold_count = 0
            if abs(S - self.game_description.m) <= 1:
                self.volatility_counter += 1
            else:
                self.volatility_counter = 0
        if self.failed_threshold_count >= 3:
            self.persistent_defection_mode = True
            self.last_was_coop = False
            return Action.D
        if self.volatility_counter > 5:
            self.mixed_strategy_mode = True
        if self.mixed_strategy_mode:
            p = self.game_description.m / (self.game_description.n_players - 1)
            action = Action.C if random.random() < p else Action.D
            self.last_was_coop = action == Action.C
            return action
        if S >= self.game_description.m + prev_my_action:
            self.last_was_coop = False
            return Action.D
        if S < self.game_description.m:
            self.last_was_coop = True
            return Action.C
        if S == self.game_description.m:
            if prev_my_action == 1:
                self.last_was_coop = True
                return Action.C
            else:
                self.last_was_coop = False
                return Action.D
        self.last_was_coop = False
        return Action.D

class Strategy_INDIVIDUALISTIC_104(BaseStrategy):
    """
    Implements the "Conditional Threshold Vigilance" strategy.
    
    This strategy monitors the number of other cooperators to determine if the 
    threshold 'm' can be met. It attempts to cooperate when necessary to reach 
    the threshold, free-rides when the threshold is already met, and stops 
    cooperating if the group consistently fails to reach the threshold.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.always_defect_mode = False
        self.consecutive_failed_rounds = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if self.game_description.k <= 1:
            return Action.D
        if self.always_defect_mode:
            return Action.D
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        o_prev = history.opponent_cooperators[-1]
        m = self.game_description.m
        if o_prev >= m:
            self.consecutive_failed_rounds = 0
            return Action.D
        elif o_prev == m - 1:
            self.consecutive_failed_rounds = 0
            return Action.C
        else:
            self.consecutive_failed_rounds += 1
            if self.consecutive_failed_rounds >= 3:
                self.always_defect_mode = True
            return Action.D

class Strategy_INDIVIDUALISTIC_105(BaseStrategy):
    """
    A strategy for the Collective Risk Dilemma that employs a probabilistic 'Trust Level' 
    (TL) based on past group coordination. It attempts to foster cooperation by 
    rewarding successful threshold hitting while defensively defecting when group 
    trust erodes or the game reaches its final stage.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.trust_level = 1.0
        self.unconditional_defection = False

    def __call__(self, history: PlayerHistory) -> Action:
        if self.unconditional_defection:
            return Action.D
        if history.round_number == 0:
            return Action.C
        last_my_action = history.my_actions[-1]
        last_opponent_coops = history.opponent_cooperators[-1]
        total_cooperators = int(last_my_action) + last_opponent_coops
        cr = total_cooperators / self.game_description.n_players
        threshold_rate = self.game_description.m / self.game_description.n_players
        if cr >= threshold_rate:
            self.trust_level = min(1.0, self.trust_level + 0.1)
        else:
            self.trust_level = max(0.0, self.trust_level - 0.2)
        if self.trust_level <= 0.0:
            self.unconditional_defection = True
            return Action.D
        rounds_remaining = self.game_description.n_rounds - history.round_number
        if rounds_remaining == 1:
            if self.trust_level >= 0.8:
                return Action.C
            else:
                return Action.D
        p = random.random()
        if p < self.trust_level:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_106(BaseStrategy):
    """
    A conditional cooperation strategy for the Collective Risk Dilemma.
    
    Strategy Overview:
    - Round 1: Cooperate (C) to test the population baseline.
    - Subsequent Rounds (t < r):
        - If the group successfully hit the target 'm' in the previous round:
            - If the group would have hit 'm' without my contribution (others_c >= m), Defect (D).
            - Otherwise, Cooperate (C) to maintain the threshold.
        - If the group failed to hit the target 'm' in the previous round:
            - If no one else cooperated (others_c == 0), Defect (D) to avoid wasted cost.
            - Otherwise, Cooperate (C) to signal commitment and attempt to reach the threshold.
    - Terminal Round (Round r): Defect (D) unconditionally.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_idx = history.round_number
        n_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round_idx == n_rounds - 1:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        others_c = history.opponent_cooperators[-1]
        i_cooperated = bool(history.my_actions[-1])
        total_c_prev = others_c + (1 if i_cooperated else 0)
        if total_c_prev >= m:
            if others_c >= m:
                return Action.D
            else:
                return Action.C
        elif others_c == 0:
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_107(BaseStrategy):
    """
    Implements a conditional tit-for-tat strategy for the Collective Risk Dilemma.
    Decisions are based on threshold maintenance and historical performance,
    optimizing for reward k when possible, while defecting in the final round
    and when rewards are insufficient.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        if self.desc.n_players > 1:
            self.p = (self.desc.m - 1) / (self.desc.n_players - 1)
        else:
            self.p = 0.0

    def __call__(self, history: PlayerHistory) -> Action:
        if self.desc.k <= 1:
            return Action.D
        round_idx = history.round_number
        if round_idx == self.desc.n_rounds - 1:
            return Action.D
        if round_idx == 0:
            return Action.C if random.random() < self.p else Action.D
        i_last_played = Action.C if history.my_actions[-1] else Action.D
        c_prev = history.opponent_cooperators[-1] + (1 if i_last_played == Action.C else 0)
        if c_prev >= self.desc.m:
            return Action.D
        if i_last_played == Action.C:
            return Action.D
        deficit = self.desc.m - c_prev
        if deficit == 1:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_108(BaseStrategy):
    """
    Conditional Threshold Tit-for-Tat (CTTFT):
    1. Round 1: Cooperate.
    2. Final Round: Always Defect to maximize payoff.
    3. Intermediate Rounds (t > 1):
       - If previous round's cooperation count >= threshold (m): Defect.
       - If previous round's cooperation count < threshold (m): Cooperate.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.r = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_idx = history.round_number
        if current_round_idx == self.r - 1:
            return Action.D
        if current_round_idx == 0:
            return Action.C
        last_round_cooperators = history.opponent_cooperators[-1]
        i_contributed_last = history.my_actions[-1]
        total_cooperators_last = last_round_cooperators + (1 if i_contributed_last else 0)
        if total_cooperators_last >= self.m:
            return Action.D
        else:
            return Action.C

class Strategy_INDIVIDUALISTIC_109(BaseStrategy):
    """
    Implements a risk-aware strategy for the Collective Risk Dilemma:
    - Round 1: Defect to test the waters.
    - Subsequent rounds:
      - If threshold was met: Continue current behavior (cooperate if already cooperating, defect if already free-riding).
      - If threshold was not met: Cooperate only if exactly one more cooperator is needed to reach the threshold 'm'.
      - Special logic for the final round: If the threshold wasn't met in the previous round, defect, unless exactly one more cooperator is needed, in which case cooperate.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        last_action_was_c = bool(history.my_actions[-1])
        total_c_last_round = (1 if last_action_was_c else 0) + history.opponent_cooperators[-1]
        is_last_round = current_round == self.game_description.n_rounds - 1
        m = self.game_description.m
        if is_last_round:
            if total_c_last_round < m and m - total_c_last_round == 1:
                return Action.C
            return Action.D
        if total_c_last_round >= m:
            if last_action_was_c:
                return Action.C
            else:
                return Action.D
        needed = m - total_c_last_round
        if needed == 1:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_110(BaseStrategy):
    """
    Threshold-Adaptive Trigger (TAT) Strategy.
    
    This strategy implements conditional cooperation with a defensive adjustment.
    - First round: Always Cooperate.
    - Last round: Always Defect.
    - If previous round failed (X_{t-1} < m): Permanently Defect.
    - If previous round barely met threshold (X_{t-1} == m): Defect to protect against risk.
    - If previous round exceeded threshold (X_{t-1} > m): Cooperate to maintain buffer.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.collaboration_broken = False

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == self.game_description.n_rounds - 1:
            return Action.D
        if t == 0:
            return Action.C
        prev_opp_coop = history.opponent_cooperators[-1]
        my_prev_action = history.my_actions[-1]
        total_prev_coop = prev_opp_coop + (1 if my_prev_action else 0)
        m = self.game_description.m
        if self.collaboration_broken or total_prev_coop < m:
            self.collaboration_broken = True
            return Action.D
        if total_prev_coop == m:
            return Action.D
        if total_prev_coop > m:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_111(BaseStrategy):
    """
    A reactive strategy for the Collective Risk Dilemma that monitors the 
    collective threshold. 
    
    Logic:
    - Round 0: Always Cooperate (C).
    - Subsequent rounds (1 to r-2):
        - If previous count of cooperators C_{t-1} >= m:
            - If we played C, switch to D (free-riding).
            - If we played D, continue D.
        - If previous count C_{t-1} < m:
            - If C_{t-1} == m-1, switch to C (be the marginal contributor).
            - Otherwise, play D (if the gap is too large, cost of C exceeds benefit).
    - Final round (r-1):
        - Defect, unless the game has consistently hovered around the threshold 
          (specifically, if C_{t-1} == m-1), in which case play C to secure the reward.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        prev_cooperators = history.opponent_cooperators[-1]
        total_cooperators_prev = prev_cooperators + (1 if history.my_actions[-1] else 0)
        is_final_round = history.round_number == self.n_rounds - 1
        if is_final_round:
            if total_cooperators_prev == self.m - 1:
                return Action.C
            return Action.D
        if total_cooperators_prev >= self.m:
            return Action.D
        elif total_cooperators_prev == self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_112(BaseStrategy):
    """
    A strategy that maintains a cooperation threshold 'm' for a collective risk dilemma.
    It cooperates if the previous round's cooperation count was insufficient but recoverable,
    free-rides if a surplus exists, and defects in the final round.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.target_c = self.game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        last_my_action = 1 if history.my_actions[-1] else 0
        last_opponent_coops = history.opponent_cooperators[-1]
        observed_c_prev = last_my_action + last_opponent_coops
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if self.target_c == self.game_description.n_players:
            if observed_c_prev == self.game_description.n_players:
                return Action.C
            else:
                return Action.D
        if observed_c_prev >= self.target_c:
            if observed_c_prev == self.target_c:
                return Action.C
            else:
                return Action.D
        elif observed_c_prev == self.target_c - 1:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_113(BaseStrategy):
    """
    Implements a phase-based strategy for the Collective Risk Dilemma.
    Phase 1: Cooperation baseline.
    Phase 2: Adaptive testing of the threshold (switching between C and D based on previous outcomes).
    Phase 3: Termination based on history.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.cooperation_threshold_met_count = 0
        self.my_last_action = Action.C

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        m = self.game_description.m
        k = self.game_description.k
        if current_round == 0:
            self.my_last_action = Action.C
            return Action.C
        prev_round_idx = current_round - 1
        prev_my_action = Action.C if history.my_actions[prev_round_idx] else Action.D
        my_prev_contribution = 1 if prev_my_action == Action.C else 0
        total_cooperators_prev = history.opponent_cooperators[prev_round_idx] + my_prev_contribution
        if total_cooperators_prev >= m:
            self.cooperation_threshold_met_count += 1
        if current_round == r - 1:
            success_ratio = self.cooperation_threshold_met_count / current_round
            if success_ratio > 0.5:
                self.my_last_action = Action.C
                return Action.C
            else:
                self.my_last_action = Action.D
                return Action.D
        if current_round < r / 4:
            self.my_last_action = Action.C
            return Action.C
        if total_cooperators_prev >= m:
            if prev_my_action == Action.C and total_cooperators_prev == m:
                self.my_last_action = Action.D
                return Action.D
            elif prev_my_action == Action.D and total_cooperators_prev > m:
                self.my_last_action = Action.D
                return Action.D
            elif prev_my_action == Action.D and total_cooperators_prev == m:
                self.my_last_action = Action.C
                return Action.C
        elif prev_my_action == Action.C:
            self.my_last_action = Action.D
            return Action.D
        else:
            cooperators_others = history.opponent_cooperators[prev_round_idx]
            n_others = n - 1
            prob_others = cooperators_others / n_others if n_others > 0 else 0
            if prob_others > 1 / k:
                self.my_last_action = Action.C
                return Action.C
            else:
                self.my_last_action = Action.D
                return Action.D
        return Action.D

class Strategy_INDIVIDUALISTIC_114(BaseStrategy):
    """
    Implements a Threshold-Adaptive Contribution strategy.
    
    Logic:
    1. Rounds 0 and (total_rounds - 1): Play Defect (D).
    2. Other rounds:
       - If last round's cooperation count (N_c) was >= m: Defect (D).
       - If last round's cooperation count (N_c) == m - 1: Cooperate (C) to pivot.
       - Otherwise: Defect (D).
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.D
        last_round_idx = current_round - 1
        others_who_cooperated = history.opponent_cooperators[last_round_idx]
        my_previous_action = history.my_actions[last_round_idx]
        n_c = others_who_cooperated + (1 if my_previous_action else 0)
        gap = m - n_c
        if gap <= 0:
            return Action.D
        elif gap == 1:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_115(BaseStrategy):
    """
    Threshold-Triggered Tit-for-Tat (TTT-T).
    
    Operates on conditional provision:
    - Round 1: Always Cooperate (C) to test for reciprocation.
    - Rounds 2 to r-1: 
        - If previous round met threshold (>= m) and self cooperated, continue (C).
        - If previous round failed but was only 1 short (== m-1) and self defected, re-engage (C).
        - Otherwise, defect (D) to preserve endowment.
    - Last Round (r): Always Defect (D) to maximize terminal payoff.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if current_round == 0:
            return Action.C
        if current_round == total_rounds - 1:
            return Action.D
        my_last_action_int = 1 if history.my_actions[-1] else 0
        total_prev_cooperators = history.opponent_cooperators[-1] + my_last_action_int
        if total_prev_cooperators >= m:
            if history.my_actions[-1]:
                return Action.C
            else:
                return Action.D
        else:
            if total_prev_cooperators == m - 1:
                return Action.C
            return Action.D

class Strategy_INDIVIDUALISTIC_116(BaseStrategy):
    """
    Threshold-Targeting Reciprocity (TTR)
    
    This strategy maximizes cumulative payoff by ensuring the group threshold m is met 
    only when necessary, minimizing the 'sucker's payoff' while testing the stability 
    of cooperation.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.game_description.n_rounds
        threshold = self.game_description.m
        if current_round == total_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        last_opponent_count = history.opponent_cooperators[-1]
        last_my_action = history.my_actions[-1]
        last_my_contrib = 1 if last_my_action == Action.C else 0
        total_cooperators_prev = last_opponent_count + last_my_contrib
        if total_cooperators_prev >= threshold:
            if last_my_action == Action.C:
                if total_cooperators_prev > threshold:
                    return Action.C
                else:
                    return Action.D
            return Action.D
        else:
            if total_cooperators_prev == threshold - 1:
                return Action.C
            return Action.D

class Strategy_INDIVIDUALISTIC_117(BaseStrategy):
    """
    Adaptive Threshold-Conditional Cooperation:
    A strategy that dynamically adjusts cooperation based on the collective threshold (m)
    to maximize personal utility by either facilitating the reward or exploiting it.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_idx = history.round_number
        n = self.game_description.n_players
        m = self.game_description.m
        r = self.game_description.n_rounds
        if current_round_idx == 0:
            return Action.C
        if current_round_idx == r - 1:
            return Action.D
        my_prev_action = int(history.my_actions[-1])
        opp_prev_coops = int(history.opponent_cooperators[-1])
        last_N = my_prev_action + opp_prev_coops
        if last_N >= m:
            if my_prev_action == 1 and last_N > m:
                return Action.D
            elif my_prev_action == 1 and last_N == m:
                return Action.C
            else:
                return Action.D
        elif last_N == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_118(BaseStrategy):
    """
    Implements a risk-aware, adaptive collective strategy.
    
    Phases:
    1. Initial Calibration: Cooperates in round 1.
    2. Adaptive Threshold: Uses historical cooperation to decide whether to contribute or defect based on necessity and redundancy.
    3. Terminal Defection: Always defects in the final round.
    
    Includes heuristics for:
    - Permanent defection if redundant for 3+ rounds.
    - Defensive defection if cooperation rates crash (below T/2).
    - Always defecting if (k-1) < 1.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description
        self.consecutive_redundant_rounds = 0
        self.n_opponents = self.desc.n_players - 1

    def __call__(self, history: PlayerHistory) -> Action:
        if self.desc.k - 1 < 1:
            return Action.D
        if history.round_number == self.desc.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            return Action.C
        last_my_action = 1 if history.my_actions[-1] else 0
        s_prev = history.opponent_cooperators[-1] + last_my_action
        t = self.desc.m - 1
        if s_prev > t + 1:
            self.consecutive_redundant_rounds += 1
        else:
            self.consecutive_redundant_rounds = 0
        if self.consecutive_redundant_rounds >= 3:
            return Action.D
        if s_prev < t / 2:
            return Action.D
        if s_prev >= t + 1:
            if s_prev > t + 1:
                return Action.D
            else:
                return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_119(BaseStrategy):
    """
    A conditional tit-for-tat strategy for the Collective Risk Dilemma.
    
    Logic:
    - Phase 1 (Round 1): Defect.
    - Phase 2 (Rounds 2 to r-1): Adapt based on previous round's cooperation. 
      If threshold met, defect. If threshold not met but (m-1) cooperators, cooperate. Otherwise, defect.
    - Phase 3 (Final Round): If cumulative average cooperation >= m-1, cooperate, else defect.
    - Edge cases: If m == n or k <= 1, always defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if self.game_description.m == self.game_description.n_players or self.game_description.k <= 1.0:
            return Action.D
        round_idx = history.round_number
        n_rounds = self.game_description.n_rounds
        m = self.game_description.m
        if round_idx == 0:
            return Action.D
        if round_idx == n_rounds - 1:
            my_actions_int = history.my_actions.astype(int)
            total_cooperators_history = history.opponent_cooperators + my_actions_int
            avg_c = np.mean(total_cooperators_history)
            if avg_c >= m - 1:
                return Action.C
            else:
                return Action.D
        prev_my_action = int(history.my_actions[-1])
        c_prev = history.opponent_cooperators[-1] + prev_my_action
        if c_prev >= m:
            return Action.D
        elif c_prev == m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_120(BaseStrategy):
    """
    Implements a conditional threshold-trigger strategy based on the 'Contribution-to-Benefit' ratio.
    The strategy coordinates to meet threshold 'm' and reverts to defection if the threshold is not met.
    It includes specific logic for final-round defection and robustness against free-riding.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.s_i = 0

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == self.game_description.n_rounds - 1:
            return Action.D
        if history.round_number == 0:
            threshold_ratio = 1.0 / self.game_description.m
            if self.game_description.k - 1.0 > threshold_ratio:
                return Action.C
            else:
                return Action.D
        prev_my_action = 1 if history.my_actions[-1] else 0
        prev_c_total = history.opponent_cooperators[-1] + prev_my_action
        if prev_c_total >= self.game_description.m:
            self.s_i = 1
        else:
            self.s_i = 0
        if self.s_i == 0:
            if prev_c_total >= self.game_description.m:
                return Action.C
            else:
                return Action.D
        elif prev_c_total >= self.game_description.m:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_121(BaseStrategy):
    """
    Implements a conditional commitment strategy:
    1. Trust Period: Cooperates in the first 10% of rounds.
    2. Conditional Cooperation: Cooperates if the threshold for the collective 
       reward 'k' is met or can be met by this player's contribution.
    3. Failure Detection: Defects permanently if the group fails to meet the 
       threshold 'm' for two consecutive rounds.
    4. Last Round: Always defects.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k
        self.trust_rounds = math.ceil(self.r * 0.1)

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == self.r - 1:
            return Action.D
        if current_round < self.trust_rounds:
            return Action.C
        consecutive_failures = 0
        for i in range(len(history.my_actions) - 1, -1, -1):
            my_action_val = 1 if history.my_actions[i] else 0
            total_C = history.opponent_cooperators[i] + my_action_val
            if total_C < self.m:
                consecutive_failures += 1
            else:
                break
        if consecutive_failures >= 2:
            return Action.D
        prev_opp_C = history.opponent_cooperators[-1]
        if prev_opp_C >= self.m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_122(BaseStrategy):
    """
    Implements a conditional threshold-triggered cooperation strategy.
    
    Logic:
    1. Round 1: Defect.
    2. Last Round: Defect.
    3. Cooperation Collapse: If two consecutive rounds fail to reach threshold (m), permanently Defect.
    4. Exploitation Defense: If I cooperated but others met threshold > m, switch to permanent Defect.
    5. Conditional Trigger: 
       - If previous round (m-1) cooperators + 1 == m, Cooperate (Pivotal).
       - Otherwise, Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.permanent_defect = False
        self.exploitation_detected = False

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == self.r - 1:
            return Action.D
        if current_round == 0:
            return Action.D
        prev_opp_coop = history.opponent_cooperators[-1]
        prev_my_coop = history.my_actions[-1]
        prev_total_coop = prev_opp_coop + (1 if prev_my_coop else 0)
        if current_round >= 2:
            prev_prev_opp_coop = history.opponent_cooperators[-2]
            prev_prev_my_coop = history.my_actions[-2]
            prev_prev_total_coop = prev_prev_opp_coop + (1 if prev_prev_my_coop else 0)
            if prev_total_coop < self.m and prev_prev_total_coop < self.m:
                self.permanent_defect = True
        if prev_my_coop and prev_opp_coop > self.m:
            self.exploitation_detected = True
        if self.permanent_defect or self.exploitation_detected:
            return Action.D
        is_pivotal = prev_opp_coop + 1 == self.m
        surplus_cooperation = prev_opp_coop > self.m
        if is_pivotal:
            return Action.C
        elif surplus_cooperation:
            return Action.D
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_123(BaseStrategy):
    """
    Implements a strategic approach to the Collective Risk Dilemma based on 
    moving averages of total cooperation and conditional reciprocity.
    - Defects on round 1 and the last round.
    - Uses a moving average of cooperators to assess if the threshold 'm' 
      is consistently met to trigger cooperation.
    - Employs 'sucker' avoidance by switching to defect if cooperation 
      fails despite the player contributing.
    - Employs 'recovery' by switching to cooperate if the threshold is met.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self._last_action = None

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        m = self.game_description.m
        t = history.round_number
        if t == 0:
            self._last_action = Action.D
            return Action.D
        if t == r - 1:
            self._last_action = Action.D
            return Action.D
        c_prev = history.opponent_cooperators[-1]
        if t == 1:
            avg_cooperators = float(c_prev)
        else:
            avg_cooperators = np.mean(history.opponent_cooperators[:t])
        next_action = Action.D
        if c_prev >= m:
            next_action = Action.C
        elif avg_cooperators >= m:
            next_action = Action.C
        else:
            next_action = Action.D
        if c_prev < m and self._last_action == Action.C:
            next_action = Action.D
        self._last_action = next_action
        return next_action

class Strategy_INDIVIDUALISTIC_124(BaseStrategy):
    """
    Threshold-Conditional Trigger (TCT)
    
    A strategy that aims to secure the collective reward 'k' while minimizing individual losses.
    It defects in the first round to gather data. In subsequent rounds, it only cooperates 
    if it can act as the 'pivot' (the difference between the group failing and succeeding), 
    effectively forcing others to do the heavy lifting when possible.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.m = game_description.m
        self.k = game_description.k

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        last_round_idx = current_round - 1
        opponents_cooperating = history.opponent_cooperators[last_round_idx]
        my_previous_action = int(history.my_actions[last_round_idx])
        total_cooperators = opponents_cooperating + my_previous_action
        if total_cooperators >= self.m:
            return Action.D
        if total_cooperators == self.m - 1:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_125(BaseStrategy):
    """
    Adaptive Threshold-Matching strategy for the Collective Risk Dilemma.
    
    This strategy dynamically adjusts behavior based on the observed number of 
    cooperators in the previous round to balance personal payoff (via defection) 
    against the potential reward k (via conditional cooperation).
    
    Strategy Logic:
    1. Initial Round: Always play C to initiate.
    2. Adaptive Phase (Rounds 2 to r-1):
       - If previous round cooperators C_{t-1} >= m-1: Play C.
       - If previous round cooperators C_{t-1} < m-1: Play D.
    3. Terminal Phase (Round r):
       - If previous round cooperators C_{r-1} >= m-1: Play C.
       - If previous round cooperators C_{r-1} < m-1: Play D.
    
    The logic covers the "Failure Recovery" heuristic implicitly by checking 
    the most recent history index (C_{t-1}) before deciding, allowing the 
    agent to switch back to C if cooperation levels rise.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description
        self.m = game_description.m

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.m
        total_rounds = self.game_description.n_rounds
        current_round = history.round_number
        my_prev_action = int(history.my_actions[-1])
        c_prev = history.opponent_cooperators[-1] + my_prev_action
        if current_round == total_rounds - 1:
            if c_prev >= m - 1:
                return Action.C
            else:
                return Action.D
        if c_prev >= m - 1:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_126(BaseStrategy):
    """
    Implements a conditional cooperation strategy for the Collective Risk Dilemma.
    
    Logic:
    1. Always Cooperate in the first round.
    2. In subsequent rounds:
        - If the previous round met the threshold (N_c >= m), continue Cooperating.
        - If the threshold was missed:
            - Punish by Defecting, unless the group was just one player short of the
              threshold (Recovery Signal: N_c == m - 1), in which case transition back to Cooperate.
    3. Last Round Handling:
        - If the previous action was Cooperate, continue to Cooperate to preserve the reward.
        - If the previous action was Defect, continue to Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        m = self.game_description.m
        total_rounds = self.game_description.n_rounds
        last_round_idx = history.round_number - 1
        my_last_action = Action.C if history.my_actions[last_round_idx] else Action.D
        n_c_last = history.opponent_cooperators[last_round_idx] + (1 if my_last_action == Action.C else 0)
        if history.round_number == total_rounds:
            return my_last_action
        if n_c_last >= m:
            return Action.C
        if n_c_last >= m - 1:
            return Action.C
        else:
            return Action.D

class Strategy_INDIVIDUALISTIC_127(BaseStrategy):
    """
    Implements a Threshold-Tracking Trigger (TTT) strategy for the Collective Risk Dilemma.
    
    The strategy follows these rules:
    - Round 0 (1st round): Defect.
    - Final round (last round): Defect.
    - Intermediate rounds:
        - Free-ride (Defect) if the threshold m was met in the previous round.
        - Act as a pivot (Cooperate) if exactly m-1 players cooperated in the previous round.
        - Otherwise, Defect.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.desc = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        total_rounds = self.desc.n_rounds
        m = self.desc.m
        if current_round == 0 or current_round == total_rounds - 1:
            return Action.D
        if m == 1:
            if history.opponent_cooperators[-1] < m:
                return Action.C
            else:
                return Action.D
        prev_cooperators = int(history.opponent_cooperators[-1])
        if prev_cooperators >= m:
            return Action.D
        if prev_cooperators == m - 1:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_128(BaseStrategy):
    """
    Implements a trigger-based, threshold-aware strategy for the Collective Risk Dilemma.
    It cooperates initially, maintains cooperation if average opponent cooperation
    is sufficient, defects on the last round, and switches to defect if opponent
    cooperation surplus is detected.
    """

    def __init__(self, game_description: CollectiveRiskDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        t_index = history.round_number
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        m = self.game_description.m
        if t_index == r - 1:
            return Action.D
        if t_index == 0:
            return Action.C
        my_previous_actions = history.my_actions.astype(int)
        total_cooperators_per_round = history.opponent_cooperators + my_previous_actions
        s_total = np.sum(total_cooperators_per_round)
        denominator = t_index * (n - 1)
        avg_opponent_c = np.sum(history.opponent_cooperators) / denominator if denominator > 0 else 0
        threshold_rate = (m - 1) / (n - 1)
        last_round_idx = t_index - 1
        last_outcome = total_cooperators_per_round[last_round_idx]
        last_action = my_previous_actions[last_round_idx]
        if last_outcome >= m:
            if last_action == 0:
                return Action.D
            elif last_action == 1:
                if last_outcome > m:
                    return Action.D
                return Action.C
        if avg_opponent_c >= threshold_rate:
            return Action.C
        else:
            return Action.D